# F2-NY-NOR-BUY with WR >50% and positive AvgR. Clamp the hard-disable WR threshold to
# <=45 so borderline/profitable lanes stay WATCH or KEEP.
SETUP_COMBO_POLICY_DISABLE_WR = min(float(os.environ.get("SETUP_COMBO_POLICY_DISABLE_WR", "45") or 45), 45.0)
SETUP_COMBO_POLICY_DISABLE_AVG_R = float(os.environ.get("SETUP_COMBO_POLICY_DISABLE_AVG_R", "0.00") or 0.00)
SETUP_COMBO_POLICY_WATCH_WR = float(os.environ.get("SETUP_COMBO_POLICY_WATCH_WR", "50") or 50)
SETUP_COMBO_POLICY_PROMOTE_AVG_R = float(os.environ.get("SETUP_COMBO_POLICY_PROMOTE_AVG_R", "0.35") or 0.35)
# yver21: Ramin rule — any lane with decided WR >49% is KEEP, regardless of sample/payoff.
SETUP_COMBO_POLICY_FORCE_KEEP_WR = float(os.environ.get("SETUP_COMBO_POLICY_FORCE_KEEP_WR", "49") or 49)


def _setup_combo_force_keep_by_wr(decided: int, wr: float) -> bool:
    try:
        return int(decided or 0) > 0 and float(wr or 0.0) > float(globals().get('SETUP_COMBO_POLICY_FORCE_KEEP_WR', 49.0) or 49.0)
    except Exception:
        return False


def _setup_combo_current_wr_blocks_keep(decided: int, wr: float) -> bool:
    """True when current decided evidence exists but no longer qualifies for KEEP.

    Owner rule: only WR > SETUP_COMBO_POLICY_FORCE_KEEP_WR is KEEP.
    Therefore any decided row at or below the threshold must not retain an old
    stored KEEP status, even if the latest score snapshot is not keyed exactly and
    the values are only available through setup_combo_policy.last_* columns.
    """
    try:
        return int(decided or 0) > 0 and float(wr or 0.0) <= float(globals().get('SETUP_COMBO_POLICY_FORCE_KEEP_WR', 49.0) or 49.0)
    except Exception:
        return False


def _setup_combo_has_current_score(score: dict) -> bool:
    """True when a latest setup_combo_scores row exists for this exact/fallback lane.

    yver26 fix: the visible/source-of-truth policy must follow the current WR.
    If the score exists and WR is no longer >49, an old stored KEEP policy must
    not keep the lane as KEEP.
    """
    try:
        if not isinstance(score, dict) or not score:
            return False
        return any(k in score for k in ('setups', 'decided', 'win_rate', 'wr', 'avg_r', 'action'))
    except Exception:
        return False


# yver22: /setup_matrix policy already displays WR>49 lanes as KEEP.  Runtime
# gates must use the same rule immediately, without waiting for the scheduled
# policy table writer.  This cache reads the latest setup_combo_scores snapshot
# and lets the policy lookup override stale DISABLE/OFF rows when the exact lane
# now has decided WR > SETUP_COMBO_POLICY_FORCE_KEEP_WR.
_SETUP_COMBO_FORCE_KEEP_SCORE_CACHE = {'ts': 0.0, 'user_id': 0, 'run_id': '', 'rows': {}}


def _setup_combo_latest_score_rows_for_runtime(user_id: int = 0, ttl_sec: int = 60) -> dict:
    try:
        owner_uid = int(globals().get('AUTOTRADE_OWNER_UID', 0) or 0)
        uid = int(user_id or owner_uid or 0)
        cache = globals().setdefault('_SETUP_COMBO_FORCE_KEEP_SCORE_CACHE', {'ts': 0.0, 'user_id': 0, 'run_id': '', 'rows': {}})
        now = float(time.time())
        if cache.get('rows') and int(cache.get('user_id') or 0) == uid and (now - float(cache.get('ts') or 0.0)) <= max(5, int(ttl_sec or 60)):
            return dict(cache.get('rows') or {})
        rows_by_combo = {}
        try:
            with sqlite3.connect(DB_PATH) as conn:
                conn.row_factory = sqlite3.Row
                cur = conn.cursor()
                ids = [x for x in [uid, 0] if int(x or 0) >= 0]
                ids = list(dict.fromkeys([int(x) for x in ids])) or [0]
                qmarks = ','.join(['?'] * len(ids))
                latest = cur.execute(
                    f"SELECT run_id FROM setup_combo_scores WHERE user_id IN ({qmarks}) ORDER BY evaluated_ts DESC LIMIT 1",
                    tuple(ids),
                ).fetchone()
                run_id = str(latest['run_id'] if latest else '' or '')
                if run_id:
                    for sr in cur.execute("SELECT * FROM setup_combo_scores WHERE run_id=?", (run_id,)).fetchall() or []:
                        d = dict(sr)
                        fam = str(d.get('family') or '').upper().strip()
                        sess = str(d.get('session') or '').upper().strip()
                        strat = _setup_strategy_suffix(value=str(d.get('strategy') or 'NOR'))
                        side = _setup_side_suffix(value=str(d.get('side') or 'BOTH'))
                        combo = str(d.get('combo') or '').upper().strip()
                        if not combo and fam and sess:
                            combo = _setup_combo_strategy_side_key(fam, sess, strat, side) if side in {'BUY','SELL'} else _setup_combo_strategy_key(fam, sess, strat)
                        if combo:
                            rows_by_combo[combo] = d
                        if fam and sess and strat:
                            rows_by_combo.setdefault(_setup_combo_strategy_key(fam, sess, strat), d)
                        if fam and sess:
                            rows_by_combo.setdefault(f'{fam}-{sess}', d)
                cache.update({'ts': now, 'user_id': uid, 'run_id': run_id, 'rows': dict(rows_by_combo)})
        except Exception:
            cache.update({'ts': now, 'user_id': uid, 'run_id': '', 'rows': {}})
        return dict(rows_by_combo)
    except Exception:
        return {}


def _setup_combo_force_keep_override_for_lane(family: str, session: str, strategy: str = 'NOR', side: str = 'BOTH', user_id: int = 0) -> dict:
    """Return a KEEP override dict when the latest evidence has decided WR >49%."""
    try:
        fam = str(family or '').upper().strip()
        sess = str(session or '').upper().strip()
        strat = _setup_strategy_suffix(value=str(strategy or 'NOR'))
        side_u = _setup_side_suffix(value=str(side or 'BOTH'))
        if not fam or not sess or fam in {'-', 'F0'} or sess in {'-', 'NONE'}:
            return {}
        rows = _setup_combo_latest_score_rows_for_runtime(int(user_id or 0))
        keys = []
        if side_u in {'BUY','SELL'}:
            keys.append(_setup_combo_strategy_side_key(fam, sess, strat, side_u))
        keys.append(_setup_combo_strategy_key(fam, sess, strat))
        keys.append(f'{fam}-{sess}')
        for key in keys:
            st = dict(rows.get(str(key or '').upper().strip()) or {})
            if not st:
                continue
            decided = int(st.get('decided') or st.get('last_decided') or 0)
            wr = float(st.get('win_rate') if st.get('win_rate') is not None else (st.get('wr') if st.get('wr') is not None else (st.get('last_win_rate') or 0.0)))
            if _setup_combo_force_keep_by_wr(decided, wr):
                return {
                    'combo': str(key),
                    'decided': int(decided),
                    'win_rate': float(wr),
                    'avg_r': float(st.get('avg_r') if st.get('avg_r') is not None else (st.get('last_avg_r') or 0.0)),
                    'setups': int(st.get('setups') or st.get('last_setups') or 0),
                    'source': 'latest_setup_combo_scores',
                    'reason': f'force_keep_wr_gt_{float(globals().get("SETUP_COMBO_POLICY_FORCE_KEEP_WR", 49.0) or 49.0):.0f}',
                }
        return {}
    except Exception:
        return {}


# yver24: /setup_matrix policy is the source of truth for lane Policy.
# /setup_audit must display this exact Policy state, not a separate actionability
# result, and KEEP rows must not be silently re-blocked by later policy/context
# gates before /screen, setup email, or AutoTrade selection.  Structural checks
# such as valid SL/TP, min volume, cooldowns, duplicate guards, risk sizing and
# exchange safety still run in their existing downstream locations.
_SETUP_MATRIX_POLICY_SOURCE_CACHE = {'ts': 0.0, 'user_id': 0, 'data': {}}


def _setup_matrix_policy_source_maps(user_id: int = 0, ttl_sec: int = 60) -> dict:
    """Return the same backing maps used by /setup_matrix policy display."""
    try:
        owner_uid = int(globals().get('AUTOTRADE_OWNER_UID', 0) or 0)
        uid = int(user_id or owner_uid or 0)
        cache = globals().setdefault('_SETUP_MATRIX_POLICY_SOURCE_CACHE', {'ts': 0.0, 'user_id': 0, 'data': {}})
        now = float(time.time())
        if int(cache.get('user_id') or 0) == uid and dict(cache.get('data') or {}) and (now - float(cache.get('ts') or 0.0)) <= max(5, int(ttl_sec or 60)):
            return dict(cache.get('data') or {})

        rows = []
        try:
            _setup_combo_policy_migrate()
            with sqlite3.connect(DB_PATH) as conn:
                conn.row_factory = sqlite3.Row
                cur = conn.cursor()
                rows = [dict(r) for r in cur.execute(
                    "SELECT * FROM setup_combo_policy WHERE user_id IN (?,0) ORDER BY enabled DESC, last_score DESC, family, session, strategy, side",
                    (int(uid),)
                ).fetchall() or []]
        except Exception:
            rows = []
        try:
            if bool(globals().get('SETUP_POLICY_CLEAN_START_ALL_ENABLED', True)):
                rows = [r for r in rows if not _setup_policy_row_is_clean_start_legacy(r)]
        except Exception:
            pass

        try:
            latest_scores = _setup_combo_latest_score_rows_for_runtime(int(uid), ttl_sec=max(5, int(ttl_sec or 60)))
        except Exception:
            latest_scores = {}
        try:
            policy_by_combo = _setup_combo_enforceable_policy_lookup(int(uid))
        except Exception:
            policy_by_combo = {}

        rows_by_combo = {}
        for r in rows:
            try:
                fam_r = str(r.get('family') or '').upper().strip()
                sess_r = str(r.get('session') or '').upper().strip()
                strat_r = str(r.get('strategy') or 'ALL').upper().strip() or 'ALL'
                side_r = str(r.get('side') or 'BOTH').upper().strip() or 'BOTH'
                if side_r not in {'BUY', 'SELL'}:
                    side_r = 'BOTH'
                if strat_r in {'NOR', 'REV'} and side_r in {'BUY', 'SELL'}:
                    combo = _setup_combo_strategy_side_key(fam_r, sess_r, strat_r, side_r)
                elif strat_r in {'NOR', 'REV'}:
                    combo = _setup_combo_strategy_key(fam_r, sess_r, strat_r)
                else:
                    combo = f'{fam_r}-{sess_r}'
                if combo and combo != '-':
                    old_r = rows_by_combo.get(combo)
                    if old_r is None or (int(r.get('user_id') or 0) != 0 and int(old_r.get('user_id') or 0) == 0):
                        rows_by_combo[combo] = dict(r)
            except Exception:
                continue

        try:
            guard_data = _setup_edge_guard_build(
                int(uid),
                hours=_overall_report_effective_hours(globals().get('SETUP_EDGE_GUARD_WINDOW_HOURS', 168)),
                force=False,
            )
            side_blocks = set(str(x or '').upper().strip() for x in ((guard_data or {}).get('combo_strategy_side_block') or (guard_data or {}).get('combo_side_block') or {}).keys())
            legacy_side_blocks = set(str(x or '').upper().strip() for x in ((guard_data or {}).get('legacy_combo_side_block') or {}).keys())
        except Exception:
            side_blocks = set(); legacy_side_blocks = set()

        data = {
            'policy_by_combo': dict(policy_by_combo or {}),
            'rows_by_combo': dict(rows_by_combo or {}),
            'latest_scores': dict(latest_scores or {}),
            'side_blocks': set(side_blocks or set()),
            'legacy_side_blocks': set(legacy_side_blocks or set()),
        }
        cache.update({'ts': now, 'user_id': uid, 'data': data})
        return dict(data)
    except Exception:
        return {}


def _setup_matrix_policy_source_state_for_lane(family: str, session: str, strategy: str = 'NOR', side: str = 'BOTH', user_id: int = 0) -> dict:
    """Return the exact ExecNow/Policy state that /setup_matrix policy would show for a lane."""
    out = {'execnow': 'GATE', 'policy': 'WATCH', 'reco': 'WATCH', 'combo': '', 'setups': 0, 'decided': 0, 'wr': 0.0, 'avg_r': 0.0, 'source': 'setup_matrix_policy'}
    try:
        fam = str(family or '').upper().strip()
        sess = str(session or '').upper().strip()
        strat = _setup_strategy_suffix(value=str(strategy or 'NOR'))
        side_u = _setup_side_suffix(value=str(side or 'BOTH'))
        if side_u not in {'BUY', 'SELL'}:
            side_u = 'BOTH'
        if not fam or not sess or fam in {'-', 'F0'} or sess in {'-', 'NONE'}:
            out.update({'execnow': 'OFF', 'policy': 'DISABLE', 'reco': 'DISABLE'})
            return out
        full_combo = _setup_combo_strategy_side_key(fam, sess, strat, side_u) if side_u in {'BUY', 'SELL'} else _setup_combo_strategy_key(fam, sess, strat)
        strat_combo = _setup_combo_strategy_key(fam, sess, strat)
        base_combo = f'{fam}-{sess}'
        out['combo'] = full_combo
        maps = _setup_matrix_policy_source_maps(int(user_id or 0)) or {}
        policy_by_combo = dict(maps.get('policy_by_combo') or {})
        rows_by_combo = dict(maps.get('rows_by_combo') or {})
        latest_scores = dict(maps.get('latest_scores') or {})
        side_blocks = set(maps.get('side_blocks') or set())
        legacy_side_blocks = set(maps.get('legacy_side_blocks') or set())

        pol = dict(policy_by_combo.get(full_combo) or policy_by_combo.get(strat_combo) or policy_by_combo.get(base_combo) or {})
        raw_pol = dict(rows_by_combo.get(full_combo) or rows_by_combo.get(strat_combo) or rows_by_combo.get(base_combo) or {})
        score = dict(latest_scores.get(full_combo) or latest_scores.get(strat_combo) or latest_scores.get(base_combo) or {})

        set_v = int(score.get('setups') if score.get('setups') is not None else (pol.get('last_setups') or raw_pol.get('last_setups') or 0))
        dec_v = int(score.get('decided') if score.get('decided') is not None else (pol.get('last_decided') or raw_pol.get('last_decided') or 0))
        wr_v = float(score.get('win_rate') if score.get('win_rate') is not None else (pol.get('last_win_rate') or raw_pol.get('last_win_rate') or 0.0))
        avg_v = float(score.get('avg_r') if score.get('avg_r') is not None else (pol.get('last_avg_r') or raw_pol.get('last_avg_r') or 0.0))
        adv = str(score.get('action') or '-').upper().strip() or '-'
        has_current_score = _setup_combo_has_current_score(score)
        force_keep = _setup_combo_force_keep_by_wr(dec_v, wr_v)
        wr_blocks_keep = _setup_combo_current_wr_blocks_keep(dec_v, wr_v)
        # yver27 fix: the current displayed WR is authoritative even when it comes
        # from setup_combo_policy.last_* instead of a directly matched score row.
        # If WR is <=49, stale stored KEEP must be demoted everywhere.
        if wr_blocks_keep and adv == 'KEEP':
            adv = 'WATCH'

        full_disabled = False
        if pol:
            st = str(pol.get('status') or '').upper().strip()
            full_disabled = st in {'DISABLE', 'BLOCK', 'PAUSE', 'OFF'} or int(pol.get('enabled') or 0) == 0
        elif raw_pol:
            full_disabled = False

        side_block = False
        try:
            side_block = (full_combo in side_blocks) or (strat == 'NOR' and side_u in {'BUY','SELL'} and f'{base_combo}-{side_u}' in legacy_side_blocks)
        except Exception:
            side_block = False

        if force_keep:
            exec_state = 'KEEP'; live_state = 'KEEP'; adv = 'KEEP'
        elif full_disabled:
            exec_state = 'OFF'; live_state = 'DISABLE'
        elif side_block:
            exec_state = 'PART'; live_state = 'TIGHTEN'
        else:
            pol_status = str((pol or raw_pol or {}).get('status') or '').upper().strip()
            adv_status = str(adv or score.get('action') or '').upper().strip()
            if wr_blocks_keep:
                # Current WR <=49 has decided evidence, so old/stored KEEP cannot survive.
                if bool(globals().get('SETUP_COMBO_WATCH_STRICT_QUALITY_GATE', True)):
                    exec_state = 'GATE'; live_state = 'WATCH'
                else:
                    exec_state = 'ON'; live_state = 'WATCH'
            elif has_current_score:
                # Current score is the source of truth. Only current WR>49 can be KEEP.
                if adv_status == 'KEEP' and _setup_combo_force_keep_by_wr(dec_v, wr_v):
                    exec_state = 'KEEP'; live_state = 'KEEP'
                elif bool(globals().get('SETUP_COMBO_WATCH_STRICT_QUALITY_GATE', True)):
                    exec_state = 'GATE'; live_state = 'WATCH'
                else:
                    exec_state = 'ON'; live_state = 'WATCH'
            elif pol_status == 'KEEP':
                exec_state = 'KEEP'; live_state = 'KEEP'
            elif bool(globals().get('SETUP_COMBO_WATCH_STRICT_QUALITY_GATE', True)):
                exec_state = 'GATE'; live_state = 'WATCH'
            else:
                exec_state = 'ON'; live_state = 'WATCH'

        out.update({'execnow': exec_state, 'policy': live_state, 'reco': adv, 'setups': set_v, 'decided': dec_v, 'wr': wr_v, 'avg_r': avg_v, 'force_keep': bool(force_keep)})
        return out
    except Exception as exc:
        out.update({'execnow': 'OFF', 'policy': 'DISABLE', 'reco': 'DISABLE', 'error': f'{type(exc).__name__}: {exc}'})
        return out


def _setup_matrix_policy_source_state_for_setup(setup_or_row, session_name: str = '', user_id: int = 0) -> dict:
    """Return /setup_matrix policy source-of-truth state for a setup/audit row."""
    try:
        fam, sess2 = _setup_combo_family_session_from_obj(setup_or_row, session_name=session_name)
        sess = str(session_name or sess2 or _autotrade_setup_attr(setup_or_row, 'session', '') or _autotrade_setup_attr(setup_or_row, 'source_session', '') or '').upper().strip()
        strat = _setup_strategy_suffix(setup_or_row)
        side = _setup_side_suffix(setup_or_row)
        if side not in {'BUY', 'SELL'}:
            side = str(_autotrade_setup_attr(setup_or_row, 'side', '') or '').upper().strip()
        return _setup_matrix_policy_source_state_for_lane(fam, sess, strat, side, user_id=int(user_id or 0))
    except Exception as exc:
        return {'execnow': 'OFF', 'policy': 'DISABLE', 'reco': 'DISABLE', 'combo': '', 'error': f'{type(exc).__name__}: {exc}', 'source': 'setup_matrix_policy'}


def _setup_matrix_policy_is_keep_for_setup(setup_or_row, session_name: str = '', user_id: int = 0) -> bool:
    try:
        return str((_setup_matrix_policy_source_state_for_setup(setup_or_row, session_name=session_name, user_id=int(user_id or 0)) or {}).get('policy') or '').upper().strip() == 'KEEP'
    except Exception:
        return False

def _setup_matrix_policy_current_lane_sets(user_id: int = 0) -> dict:
    """Return current lane sets using the exact /setup_matrix policy source-of-truth.

    yver28: summary commands such as /setup_audit_keep must not read the older
    persisted setup_combo_policy table directly.  /setup_matrix policy combines
    latest score rows, clean-start filtering, WR>49 promotion, WR<=49 demotion,
    side tightening and stored policy rows.  This helper walks the same full lane
    universe and asks _setup_matrix_policy_source_state_for_lane for each lane, so
    KEEP/WATCH counts and row filtering match the table the owner sees.
    """
    try:
        owner_uid = int(globals().get('AUTOTRADE_OWNER_UID', 0) or 0)
        uid = int(user_id or owner_uid or 0)
    except Exception:
        uid = int(user_id or 0)

    keep_combos: set[str] = set()
    watch_combos: set[str] = set()
    tighten_combos: set[str] = set()
    disable_combos: set[str] = set()
    all_combos: set[str] = set()

    families = set()
    sessions = set()
    try:
        cfg = load_strategy_config(force=False)
    except Exception:
        cfg = {}
    try:
        for f in ((cfg or {}).get('active_family_codes') or []):
            ff = str(f or '').upper().strip()
            if re.fullmatch(r'F\d+', ff):
                families.add(ff)
    except Exception:
        pass
    for f in [f'F{i}' for i in range(1, 10)]:
        families.add(f)
    try:
        for s in _strategy_cfg_execution_sessions_allowed(cfg):
            ss = str(s or '').upper().strip()
            if ss:
                sessions.add(ss)
    except Exception:
        pass
    try:
        for s in _autotrade_get_sessions():
            ss = str(s or '').upper().strip()
            if ss:
                sessions.add(ss)
    except Exception:
        pass
    if not sessions:
        sessions.update(['ASIA', 'LON', 'NY'])

    # Include any families/sessions that exist only in stored policy or latest score rows.
    try:
        maps = _setup_matrix_policy_source_maps(int(uid)) or {}
        keys = list((maps.get('policy_by_combo') or {}).keys()) + list((maps.get('rows_by_combo') or {}).keys()) + list((maps.get('latest_scores') or {}).keys())
        for c in keys:
            parts = str(c or '').upper().split('-')
            if len(parts) >= 2:
                if parts[0]:
                    families.add(parts[0])
                if parts[1]:
                    sessions.add(parts[1])
    except Exception:
        pass

    try:
        lanes = list(_setup_combo_full_universe(families, sessions))
    except Exception:
        lanes = []
    for fam, sess, strat, side, full_combo in lanes:
        try:
            combo_u = str(full_combo or '').upper().strip()
            if not combo_u:
                continue
            st = _setup_matrix_policy_source_state_for_lane(fam, sess, strat, side, user_id=int(uid)) or {}
            pol = str(st.get('policy') or '').upper().strip()
            all_combos.add(combo_u)
            if pol == 'KEEP':
                keep_combos.add(combo_u)
            elif pol in {'WATCH', 'GATE', 'ON'}:
                watch_combos.add(combo_u)
            elif pol in {'TIGHTEN', 'PART'}:
                tighten_combos.add(combo_u)
                watch_combos.add(combo_u)
            elif pol in {'DISABLE', 'OFF', 'BLOCK', 'PAUSE'}:
                disable_combos.add(combo_u)
        except Exception:
            continue
    return {
        'keep': keep_combos,
        'watch': watch_combos,
        'tighten': tighten_combos,
        'disable': disable_combos,
        'allowed': set(keep_combos) | set(watch_combos) | set(tighten_combos),
        'all': all_combos,
        'source': 'setup_matrix_policy',
    }
    
    # unreachable fallback, kept for defensive readability
    return {'keep': set(), 'watch': set(), 'tighten': set(), 'disable': set(), 'allowed': set(), 'all': set(), 'source': 'setup_matrix_policy'}

# 13May edge-quality micro guard: family/session policy is useful, but the latest
# matrix showed the losing edge was concentrated by side and symbol (e.g. F1-ASIA-BUY,
# F1-LON-BUY, GIGA/H/B) while the opposite side was still profitable.  This guard
# sits after the family/session policy and before persistence/email/autotrade so the
# bot can block bad directions/symbols without killing the whole family/session.
SETUP_EDGE_MICRO_GUARD_ENABLED = env_bool("SETUP_EDGE_MICRO_GUARD_ENABLED", True)
SETUP_EDGE_GUARD_WINDOW_HOURS = int(os.environ.get("SETUP_EDGE_GUARD_WINDOW_HOURS", "168") or 168)
SETUP_EDGE_GUARD_CACHE_SEC = int(os.environ.get("SETUP_EDGE_GUARD_CACHE_SEC", "900") or 900)
SETUP_EDGE_GUARD_SIDE_MIN_DECIDED = int(os.environ.get("SETUP_EDGE_GUARD_SIDE_MIN_DECIDED", "5") or 5)
SETUP_EDGE_GUARD_SIDE_WR_MAX = float(os.environ.get("SETUP_EDGE_GUARD_SIDE_WR_MAX", "30") or 30)
