async def _run_in_executor(executor, fn, *args, timeout: int | None = None, **kwargs):
    loop = asyncio.get_running_loop()
    call = _functools.partial(fn, *args, **kwargs)
    fut = loop.run_in_executor(executor, call)
    return await asyncio.wait_for(fut, timeout=timeout) if timeout else await fut

async def to_thread_fast(fn, *args, timeout: int | None = None, **kwargs):
    return await _run_in_executor(_FAST_EXECUTOR, fn, *args, timeout=timeout, **kwargs)

async def to_thread_heavy(fn, *args, timeout: int | None = None, **kwargs):
    return await _run_in_executor(_HEAVY_EXECUTOR, fn, *args, timeout=timeout, **kwargs)

async def to_thread_screen(fn, *args, timeout: int | None = None, **kwargs):
    return await _run_in_executor(_SCREEN_EXECUTOR, fn, *args, timeout=timeout, **kwargs)

async def to_thread_email(fn, *args, timeout: int | None = None, **kwargs):
    return await _run_in_executor(_EMAIL_EXECUTOR, fn, *args, timeout=timeout, **kwargs)

async def to_thread_autotrade(fn, *args, timeout: int | None = None, **kwargs):
    return await _run_in_executor(_AUTOTRADE_EXECUTOR, fn, *args, timeout=timeout, **kwargs)

async def to_thread_bg(fn, *args, timeout: int | None = None, **kwargs):
    return await _run_in_executor(_BACKGROUND_EXECUTOR, fn, *args, timeout=timeout, **kwargs)


def _safe_task_done(task: asyncio.Task, label: str = "background") -> None:
    """Consume exceptions from fire-and-forget tasks so asyncio never logs
    Task exception was never retrieved. Background refresh failures are recorded
    but they must never pollute Render logs or delay Telegram commands.
    """
    try:
        task.result()
    except asyncio.CancelledError:
        pass
    except TimeoutError as e:
        try:
            logger.warning("background task %s timed out: %s", label, e)
        except Exception:
            pass
    except Exception as e:
        try:
            logger.warning("background task %s failed: %s: %s", label, type(e).__name__, e)
        except Exception:
            pass


def _safe_create_task(coro, label: str = "background"):
    try:
        task = asyncio.create_task(coro, name=str(label or "background"))
        task.add_done_callback(lambda t, _label=str(label or "background"): _safe_task_done(t, _label))
        return task
    except Exception:
        return None


def _run_async_in_new_loop(coro_fn, *args, **kwargs):
    """Run an async callable inside its own event loop from a worker thread.

    This is used when background schedulers need to execute async orchestration without
    blocking the main Telegram event loop. It keeps slow scan/build logic off the loop
    that serves user commands.
    """
    try:
        return asyncio.run(coro_fn(*args, **kwargs))
    except RuntimeError:
        loop = asyncio.new_event_loop()
        try:
            asyncio.set_event_loop(loop)
            return loop.run_until_complete(coro_fn(*args, **kwargs))
        finally:
            try:
                loop.close()
            except Exception:
                pass
            try:
                asyncio.set_event_loop(None)
            except Exception:
                pass

# Fast-command activity hint so background jobs can yield briefly to user-facing commands.
_USER_ACTIVITY_TS = 0.0
USER_ACTIVITY_COOLDOWN_SEC = int(os.getenv("USER_ACTIVITY_COOLDOWN_SEC", "60") or 60)
FAST_ADMIN_SNAPSHOT_TTL_SEC = int(os.getenv("FAST_ADMIN_SNAPSHOT_TTL_SEC", "20") or 20)
FAST_ADMIN_METRICS_TTL_SEC = int(os.getenv("FAST_ADMIN_METRICS_TTL_SEC", "20") or 20)
FAST_ADMIN_COMMAND_TIMEOUT_SEC = int(os.getenv("FAST_ADMIN_COMMAND_TIMEOUT_SEC", "4") or 4)

def _mark_user_activity() -> None:
    global _USER_ACTIVITY_TS
    try:
        _USER_ACTIVITY_TS = float(time.time())
    except Exception:
        _USER_ACTIVITY_TS = 0.0

def _recent_user_activity(window_sec: int | None = None) -> bool:
    try:
        win = int(window_sec if window_sec is not None else USER_ACTIVITY_COOLDOWN_SEC)
        return (float(time.time()) - float(_USER_ACTIVITY_TS or 0.0)) <= max(1, win)
    except Exception:
        return False


def _goal_profile_quiet_window_ok(now_ts: float | None = None) -> bool:
    """Allow scheduled goal-profile work mainly during quiet local hours.

    Manual /goal_run remains available any time; this only affects background scheduling so it does
    not steal OHLCV bandwidth from live setup generation during the trading day.
    """
    try:
        ts = float(now_ts if now_ts is not None else time.time())
        tz_local = ZoneInfo(str(globals().get('TIMEZONE') or os.environ.get('TIMEZONE') or 'Australia/Melbourne'))
        dt_local = datetime.fromtimestamp(ts, tz=timezone.utc).astimezone(tz_local)
        start_h = int(os.getenv('GOAL_PROFILE_QUIET_START_HOUR', '1') or 1)
        end_h = int(os.getenv('GOAL_PROFILE_QUIET_END_HOUR', '6') or 6)
        hour = int(dt_local.hour)
        if start_h <= end_h:
            return start_h <= hour < end_h
        return hour >= start_h or hour < end_h
    except Exception:
        return False


def _heavy_background_window_ok(now_ts: float | None = None) -> bool:
    """Run paged OHLCV / backtest style background jobs only during quiet local hours."""
    try:
        ts = float(now_ts if now_ts is not None else time.time())
        tz_local = ZoneInfo(str(globals().get('TIMEZONE') or os.environ.get('TIMEZONE') or 'Australia/Melbourne'))
        dt_local = datetime.fromtimestamp(ts, tz=timezone.utc).astimezone(tz_local)
        start_h = int(os.getenv('HEAVY_BACKGROUND_START_HOUR', os.getenv('GOAL_PROFILE_QUIET_START_HOUR', '1')) or 1)
        end_h = int(os.getenv('HEAVY_BACKGROUND_END_HOUR', os.getenv('GOAL_PROFILE_QUIET_END_HOUR', '6')) or 6)
        hour = int(dt_local.hour)
        if start_h <= end_h:
            return start_h <= hour < end_h
        return hour >= start_h or hour < end_h
    except Exception:
        return False


def _heavy_background_defer(reason_only: bool = False) -> bool | str:
    """Shared defer gate for heavy background jobs so simple commands stay responsive."""
    try:
        if _recent_user_activity(int(HEAVY_USER_ACTIVITY_DEFER_SEC)):
            return 'recent_user_activity' if reason_only else True
        if ALERT_LOCK.locked() or SCAN_LOCK.locked() or _SCREEN_LOCK.locked():
            return 'interactive_runtime_busy' if reason_only else True
        try:
            if _MARKET_ADAPTIVE_LOCK.locked():
                return 'market_adaptive_running' if reason_only else True
        except Exception:
            pass
        try:
            if _SELF_OPT_STATE.get('stop_event') is not None:
                return 'autonomous_optimizer_running' if reason_only else True
        except Exception:
            pass
        if _backtest_runtime_busy() or _goal_profile_is_running():
            return 'backtest_or_goal_running' if reason_only else True
        if not _heavy_background_window_ok():
            return 'outside_quiet_window' if reason_only else True
        return '' if reason_only else False
    except Exception:
        return 'defer_guard_error' if reason_only else True


import re
import sqlite3

TXID_REGEX = re.compile(r"^[A-Fa-f0-9]{64}$")


