def _resolve_single_tp(entry: float, sl: float, tp=None, alt_target_a=None, alt_target_b=None, side: str = '') -> float:
    """Resolve the bot's single take-profit target.

    Compatibility rules:
    - prefer tp when present (single-TP model stores the only target there)
    - otherwise fall back to alt_target_a, then alt_target_b
    - validate direction against entry when possible
    """
    try:
        e = float(entry or 0.0)
    except Exception:
        e = 0.0
    side_u = str(side or '').upper().strip()
    raw = []
    for v in (tp, alt_target_a, alt_target_b):
        try:
            fv = float(v or 0.0)
        except Exception:
            fv = 0.0
        if fv > 0:
            raw.append(fv)
    if not raw:
        return 0.0
    for cand in raw:
        if e <= 0:
            return float(cand)
        if side_u == 'SELL' and cand < e:
            return float(cand)
        if side_u != 'SELL' and cand > e:
            return float(cand)
    return float(raw[0])

def _ensure_three_tps(entry: float, sl: float, alt_target_b: float, tp, alt_target_a, side: str):
    """Backward-compatible single-TP resolver.

    The bot now uses exactly one TP. For old code paths that still expect a 3-value
    tuple we mirror the same resolved target into all three positions so downstream
    calculations stay stable without creating extra targets.
    """
    tp = _resolve_single_tp(entry, sl, tp=tp, alt_target_a=alt_target_a, alt_target_b=alt_target_b, side=side)
    return float(tp or 0.0), float(tp or 0.0), float(tp or 0.0)


def _setup_target_tp(obj, default: float = 0.0) -> float:
    """Canonical single-TP accessor for Setup objects / dict rows.

    New setups store the only real target in tp and leave alt_target_a/alt_target_b empty.
    Older rows may still carry alt_target_a/alt_target_b, so we resolve defensively.
    """
    try:
        if isinstance(obj, dict):
            entry = float(obj.get('entry') or 0.0)
            sl = float(obj.get('sl') or 0.0)
            return float(_resolve_single_tp(entry, sl, obj.get('tp'), obj.get('alt_target_a'), obj.get('alt_target_b'), str(obj.get('side') or '')) or default)
        entry = float(getattr(obj, 'entry', 0.0) or 0.0)
        sl = float(getattr(obj, 'sl', 0.0) or 0.0)
        return float(_resolve_single_tp(entry, sl, getattr(obj, 'tp', None), getattr(obj, 'alt_target_a', None), getattr(obj, 'alt_target_b', None), str(getattr(obj, 'side', '') or '')) or default)
    except Exception:
        return float(default or 0.0)

# =========================================================
# VER37 ADAPTIVE STRATEGY ROUTER (NORMAL / REVERSE)
# =========================================================
def _setup_strategy_db_migrate() -> None:
    """Add strategy metadata columns used by ver37 reporting and execution routing."""
    try:
        with sqlite3.connect(DB_PATH) as conn:
            cur = conn.cursor()
            table_cols = {
                'signals': {
                    'setup_strategy': "TEXT NOT NULL DEFAULT 'NORMAL'",
                    'original_setup_id': "TEXT NOT NULL DEFAULT ''",
                    'original_side': "TEXT NOT NULL DEFAULT ''",
                    'strategy_reason': "TEXT NOT NULL DEFAULT ''",
                },
                'generated_setups': {
                    'setup_strategy': "TEXT NOT NULL DEFAULT 'NORMAL'",
                    'original_setup_id': "TEXT NOT NULL DEFAULT ''",
                    'original_side': "TEXT NOT NULL DEFAULT ''",
                    'strategy_reason': "TEXT NOT NULL DEFAULT ''",
                },
                'executable_setups': {
                    'setup_strategy': "TEXT NOT NULL DEFAULT 'NORMAL'",
                    'original_setup_id': "TEXT NOT NULL DEFAULT ''",
                    'original_side': "TEXT NOT NULL DEFAULT ''",
                    'strategy_reason': "TEXT NOT NULL DEFAULT ''",
                },
                'autotrade_trades': {
                    'setup_strategy': "TEXT NOT NULL DEFAULT 'NORMAL'",
                    'original_setup_id': "TEXT NOT NULL DEFAULT ''",
                    'original_side': "TEXT NOT NULL DEFAULT ''",
                    'strategy_reason': "TEXT NOT NULL DEFAULT ''",
                },
            }
            for table, cols in table_cols.items():
                try:
                    existing = {r[1] for r in cur.execute(f"PRAGMA table_info({table})").fetchall()}
                    if not existing:
                        continue
                    for col, ddl in cols.items():
                        if col not in existing:
                            cur.execute(f"ALTER TABLE {table} ADD COLUMN {col} {ddl}")
                            existing.add(col)
                except Exception:
                    continue
            conn.commit()
    except Exception:
        pass


def _setup_strategy_normalize(value: str = '') -> str:
    try:
        v = str(value or '').strip().upper().replace('-', '_')
        if v in {'REV', 'REVERSE', 'INVERSE', 'RV'}:
            return 'REVERSE'
        # Ver53: MON/MONITOR/TIGHTEN/DISABLE/BLOCK are policy/advisory states,
        # not executable strategy identities.  Combo keys must be NOR or REV only.
        if v in {'N', 'NORMAL', 'ORIGINAL', 'BASE', 'NOR', 'MON', 'MONITOR', 'TIGHTEN', 'DISABLE', 'BLOCK'}:
            return 'NORMAL'
    except Exception:
        pass
    return 'NORMAL'


def _setup_strategy_attr(setup_or_row, name: str, default=None):
    try:
        if isinstance(setup_or_row, dict):
            if name in setup_or_row:
                return setup_or_row.get(name, default)
            dj = setup_or_row.get('details_json')
            if dj:
                try:
                    obj = json.loads(str(dj or '{}'))
                    if isinstance(obj, dict) and name in obj:
                        return obj.get(name, default)
                except Exception:
                    pass
            return default
        return getattr(setup_or_row, name, default)
    except Exception:
        return default


def _setup_strategy_set_attr(setup_or_row, name: str, value) -> None:
    try:
        if isinstance(setup_or_row, dict):
            setup_or_row[name] = value
        else:
            setattr(setup_or_row, name, value)
    except Exception:
        pass


def _setup_delivery_lane_locked(setup_or_row=None, source_kind: str = '') -> bool:
    """True when a setup has already become an authoritative delivery/execution lane.

    yver71: NOR→REV routing must happen once, before email/executable persistence.
    After a setup is emailed or written into the owner executable queue, AutoTrade
    must execute that exact lane (same setup_id/side/SL/TP/strategy) instead of
    re-routing it again after a later policy update.
    """
    try:
        src = str(source_kind or _setup_strategy_attr(setup_or_row, 'source_kind', '') or '').lower().strip()
        if src in {
            'emailed_setups', 'setup_email', 'recent_email_cache',
            'email_autotrade_immediate', 'bigmove_email_autotrade_immediate',
            'email_sent_immediate', 'setup_delivery',
        }:
            return True
        if bool(_setup_strategy_attr(setup_or_row, 'delivery_lane_locked', False)):
            return True
    except Exception:
        pass
    return False


def _setup_route_unless_delivery_locked(setup, session_name: str = '', user_id: int = 0, source_kind: str = ''):
    try:
        if _setup_delivery_lane_locked(setup, source_kind=source_kind):
            sess = str(session_name or '').upper().strip()
            if sess:
                _setup_strategy_set_attr(setup, 'source_session', sess)
                if not _setup_strategy_attr(setup, 'session', ''):
                    _setup_strategy_set_attr(setup, 'session', sess)
            if not float(_setup_strategy_attr(setup, 'created_ts', 0.0) or 0.0):
                _setup_strategy_set_attr(setup, 'created_ts', float(time.time()))
            return setup
    except Exception:
        pass
    return _setup_route_candidate_for_executable_lane(setup, session_name=session_name, user_id=int(user_id or 0))


def _setup_strategy_label(setup_or_row) -> str:
    try:
        raw = _setup_strategy_attr(setup_or_row, 'setup_strategy', '') or _setup_strategy_attr(setup_or_row, 'strategy', '') or _setup_strategy_attr(setup_or_row, 'strategy_mode', '')
        if raw:
            return _setup_strategy_normalize(str(raw))
        sid = str(_setup_strategy_attr(setup_or_row, 'setup_id', '') or _setup_strategy_attr(setup_or_row, 'id', '') or '').upper().strip()
        suffix = str(globals().get('SETUP_ADAPTIVE_REVERSE_SUFFIX', 'RV') or 'RV').upper().strip()
        if sid.endswith('-' + suffix) or sid.endswith('_' + suffix):
            return 'REVERSE'
    except Exception:
        pass
    return 'NORMAL'


def _setup_strategy_short_label(setup_or_row) -> str:
    return 'REV' if _setup_strategy_label(setup_or_row) == 'REVERSE' else 'NOR'


def _setup_strategy_full_label_from_short(value: str = '') -> str:
    try:
        v = str(value or '').upper().strip()
        if v in {'REV', 'REVERSE', 'RV', 'INVERSE'}:
            return 'REVERSE'
        if v in {'NOR', 'NORMAL', 'N', 'ORIGINAL', 'BASE'}:
            return 'NORMAL'
        if v in {'MON', 'MONITOR'}:
            return 'NORMAL'
    except Exception:
        pass
    return 'NORMAL'


def _setup_strategy_suffix(setup_or_row=None, value: str | None = None) -> str:
    """Compact executable strategy suffix for combo identity: NOR / REV only."""
    try:
        if value is not None:
            vv = str(value or '').upper().strip()
            if vv in {'REV', 'REVERSE', 'RV', 'INVERSE'}:
                return 'REV'
            if vv in {'MON', 'MONITOR'}:
                return 'NOR'
            if vv in {'NOR', 'NORMAL', 'N', 'ORIGINAL', 'BASE'}:
                return 'NOR'
        return 'REV' if _setup_strategy_label(setup_or_row) == 'REVERSE' else 'NOR'
    except Exception:
        return 'NOR'


def _setup_combo_strategy_key(family: str = '', session: str = '', strategy=None) -> str:
    """Canonical decision combo key: Family-Session-Strategy, e.g. F8-NY-REV."""
    try:
        fam = str(family or 'F0').upper().strip() or 'F0'
        sess = str(session or '-').upper().strip() or '-'
        if isinstance(strategy, dict) or not isinstance(strategy, str):
            strat = _setup_strategy_suffix(strategy)
        else:
            strat = _setup_strategy_suffix(value=strategy)
        return f'{fam}-{sess}-{strat}'
    except Exception:
        return 'F0-UNK-NOR'


def _setup_combo_strategy_key_for_row(row: dict, session_name: str = '') -> str:
    try:
        fam = _setup_audit_family_code(row) if isinstance(row, dict) else _setup_family_id_to_code(str(getattr(row, 'family_id', '') or getattr(row, 'family', '') or 'F0'))
        sess = str(session_name or (row or {}).get('session') or (row or {}).get('source_session') or '-').upper().strip() if isinstance(row, dict) else str(session_name or getattr(row, 'session', '') or '-').upper().strip()
        return _setup_combo_strategy_key(fam, sess, row)
    except Exception:
        return 'F0-UNK-NOR'



def _setup_side_suffix(setup_or_row=None, value: str | None = None) -> str:
    """Compact side suffix for reporting keys: BUY / SELL / BOTH.

    yver59: the analytical identity is Family-Session-Strategy-Side so the bot can
    compare NOR-BUY, NOR-SELL, REV-BUY and REV-SELL separately while the older
    family/session policy table remains a coarse safety layer.
    """
    try:
        raw = value if value is not None else _setup_strategy_attr(setup_or_row, 'side', '')
        side = str(raw or '').upper().strip()
        if side in {'LONG', 'BULL', 'BULLISH'}:
            side = 'BUY'
        elif side in {'SHORT', 'BEAR', 'BEARISH'}:
            side = 'SELL'
        if side in {'BUY', 'SELL'}:
            return side
        if side in {'BOTH', 'ALL', '*'}:
            return 'BOTH'
    except Exception:
        pass
    return 'BOTH'


def _setup_combo_strategy_side_key(family: str = '', session: str = '', strategy=None, side=None) -> str:
    """Canonical granular learning key: Family-Session-Strategy-Side.

    Example: F3-ASIA-NOR-BUY or F8-NY-REV-SELL.
    """
    try:
        base = _setup_combo_strategy_key(family, session, strategy)
        s = _setup_side_suffix(value=side) if isinstance(side, str) else _setup_side_suffix(side)
        if s == 'BOTH':
            return base
        return f'{base}-{s}'
    except Exception:
        return 'F0-UNK-NOR-BOTH'




def _setup_reverse_target_lane_for_combo(combo: str = '') -> str:
    """Return the exact REV lane that a weak/disabled NOR lane routes into.

    Important direction rule:
    - NOR-BUY weakness means the original BUY signal is faded as REV-SELL.
    - NOR-SELL weakness means the original SELL signal is faded as REV-BUY.
    REV lanes are never auto-marked weak from NOR evidence; they need their own
    decided REV evidence before being tightened/disabled.
    """
    try:
        c = str(combo or '').upper().strip()
        parts = [x for x in c.split('-') if x]
        if len(parts) < 4:
            return '-'
        fam, sess, strat, side = parts[0], parts[1], parts[2], parts[3]
        if strat != 'NOR' or side not in {'BUY', 'SELL'}:
            return '-'
        rev_side = 'SELL' if side == 'BUY' else 'BUY'
        return _setup_combo_strategy_side_key(fam, sess, 'REV', rev_side)
    except Exception:
        return '-'


def _setup_nor_rev_router_note(uid: int = 0, rows: list[dict] | None = None) -> str:
    """Compact operator-facing explanation of the active NOR->REV router state."""
    try:
        active = []
        seen = set()
        # Enforceable policy disables: hard live route candidates.
        try:
            policy_by_combo = _setup_combo_enforceable_policy_lookup(int(uid or 0))
            for combo, pol in sorted((policy_by_combo or {}).items()):
                c = str(combo or '').upper().strip()
                tgt = _setup_reverse_target_lane_for_combo(c)
                if tgt == '-':
                    continue
                st = str((pol or {}).get('status') or '').upper().strip()
                en = int((pol or {}).get('enabled') or 0) == 1
                if st in {'DISABLE', 'BLOCK', 'PAUSE', 'OFF'} or not en:
                    txt = f'{c}->{tgt} (policy)'
                    if txt not in seen:
                        active.append(txt); seen.add(txt)
        except Exception:
            pass
        # Micro-edge tightened lanes: soft/strict quality route candidates.
        try:
            gd = _setup_edge_guard_build(int(uid or 0), hours=_overall_report_effective_hours(hours) if fixed_start_ts > 0 else int(globals().get('SETUP_EDGE_GUARD_WINDOW_HOURS', 168) or 168), force=False)
            for combo in sorted(((gd or {}).get('combo_strategy_side_block') or (gd or {}).get('combo_side_block') or {}).keys()):
                c = str(combo or '').upper().strip()
                tgt = _setup_reverse_target_lane_for_combo(c)
                if tgt == '-':
                    continue
                txt = f'{c}->{tgt} (tighten)'
                if txt not in seen:
                    active.append(txt); seen.add(txt)
        except Exception:
            pass
        # Advisory rows from the currently selected /setup_matrix window.
        try:
            for r in list(rows or []):
                c = str((r or {}).get('combo') or '').upper().strip()
                tgt = _setup_reverse_target_lane_for_combo(c)
                if tgt == '-':
                    continue
                act = str((r or {}).get('action') or (r or {}).get('advisory_action') or '').upper().strip()
                if act in {'DISABLE', 'BLOCK', 'PAUSE', 'OFF'}:
                    txt = f'{c}->{tgt} (reco)'
                    if txt not in seen:
                        active.append(txt); seen.add(txt)
        except Exception:
            pass
        route_txt = ', '.join(active[:8]) if active else '-'
        more = f' (+{len(active)-8} more)' if len(active) > 8 else ''
        return (
            'NOR→REV router: weak/disabled NOR-BUY routes future raw BUY candidates to REV-SELL; '
            'weak/disabled NOR-SELL routes future raw SELL candidates to REV-BUY. '
            f'Active route candidates now: {route_txt}{more}. REV rows appear only after a fresh raw NOR candidate is generated, flipped, and passes the shared final executable gate.'
        )
    except Exception:
        return 'NOR→REV router: unavailable'

def _setup_combo_strategy_side_key_for_row(row: dict, session_name: str = '') -> str:
    try:
        fam = _setup_audit_family_code(row) if isinstance(row, dict) else _setup_family_id_to_code(str(getattr(row, 'family_id', '') or getattr(row, 'family', '') or 'F0'))
        sess = str(session_name or (row or {}).get('session') or (row or {}).get('source_session') or '-').upper().strip() if isinstance(row, dict) else str(session_name or getattr(row, 'session', '') or '-').upper().strip()
        side = str((row or {}).get('side') or '').upper().strip() if isinstance(row, dict) else str(getattr(row, 'side', '') or '').upper().strip()
        return _setup_combo_strategy_side_key(fam, sess, row, side)
    except Exception:
        return 'F0-UNK-NOR-BOTH'


def _setup_combo_full_universe(families=None, sessions=None) -> list[tuple[str, str, str, str, str]]:
    """Return the full configured Family-Session-Strategy-Side universe for policy views."""
    try:
        fams = [str(f or '').upper().strip() for f in (families or []) if str(f or '').strip()]
        sesses = [str(s or '').upper().strip() for s in (sessions or []) if str(s or '').strip()]
        if not fams:
            fams = [f'F{i}' for i in range(1, 10)]
        if not sesses:
            sesses = ['ASIA', 'LON', 'NY']
        fams = sorted(set(fams), key=lambda x: (int(x[1:]) if re.fullmatch(r'F\d+', x) else 99, x))
        order = ['ASIA', 'LON', 'NY']
        sesses = sorted(set(sesses), key=lambda x: (order.index(x) if x in order else 99, x))
        out = []
        for fam in fams:
            for sess in sesses:
                for strat in ('NOR', 'REV'):
                    for side in ('BUY', 'SELL'):
                        out.append((fam, sess, strat, side, _setup_combo_strategy_side_key(fam, sess, strat, side)))
        return out
    except Exception:
        return []


def _setup_volume_bucket_from_usd(vol_usd: float) -> str:
    try:
        v = float(vol_usd or 0.0)
        if v >= 1_000_000_000:
            return 'V1B+'
        if v >= 250_000_000:
            return 'V250M+'
        if v >= 100_000_000:
            return 'V100M+'
        if v >= 50_000_000:
            return 'V50M+'
        if v >= 15_000_000:
            return 'V15M+'
        return 'VLOW'
    except Exception:
        return 'VUNK'


def _setup_decision_profile_key(row: dict, include_hour: bool = True) -> str:
    """Higher-resolution learning key for future router/optimizer use.

    Format includes combo strategy + side + volume bucket (+ Melbourne hour).
    This prevents the bot from treating F8-NY-NOR and F8-NY-REV as the same edge.
    """
    try:
        combo = _setup_combo_strategy_key_for_row(row)
        side = str((row or {}).get('side') or '-').upper().strip() or '-'
        vol_b = _setup_volume_bucket_from_usd(float((row or {}).get('fut_vol_usd') or (row or {}).get('volume_usd') or (row or {}).get('vol_usd') or 0.0))
        if include_hour:
            ts = _setup_audit_row_ts(row)
            hr = datetime.fromtimestamp(float(ts), tz=timezone.utc).astimezone(MEL_TZ).strftime('%H:00') if float(ts or 0.0) > 0 else 'HUNK'
            return f'{combo}-{side}-{vol_b}-{hr}'
        return f'{combo}-{side}-{vol_b}'
    except Exception:
        return 'F0-UNK-NOR-UNK-VUNK'


def _setup_policy_effective_status(status: str = '', found: bool = False) -> str:
    """Normalize policy statuses for the executable lane.

    Ver44 hard rule:
    - DISABLE/BLOCK/PAUSE/OFF remain hard policy states.
    - KEEP remains preferred.
    - WATCH/unknown/new strategy keys (for example F8-NY-REV before a policy row
      exists) are treated as WATCH probation. They must still pass the strict
      quality/risk/SL/TP gate before reaching email or AutoTrade, but they must
      not be killed as UNKNOWN.

    This deliberately ignores any stale runtime/config value that could set
    SETUP_FINAL_UNKNOWN_AS_WATCH=false, because that was starving the executable
    lane after Family-Session-Strategy combo keys were introduced.
    """
    try:
        st = str(status or '').upper().strip()
        if st in {'DISABLE', 'BLOCK', 'PAUSE', 'OFF'}:
            return st
        if st in {'KEEP', 'ACTIVE', 'ON'}:
            return 'KEEP'
        if st in {'WATCH', 'WARN', 'CAUTION'}:
            return 'WATCH'
        if st in {'', 'UNKNOWN', 'UNSET', 'NONE', 'NULL', '-', 'MON', 'MONITOR', 'PROBATION', 'GATE'}:
            return 'WATCH'
        # Any unrecognised policy string should be probationary, not fatal.
        return 'WATCH'
    except Exception:
        return 'WATCH'


def _setup_policy_status_is_unknownish(status: str = '') -> bool:
    try:
        return str(status or '').upper().strip() in {'', 'UNKNOWN', 'UNSET', 'NONE', 'NULL', '-', 'MON', 'MONITOR', 'PROBATION', 'GATE'}
    except Exception:
        return True


def _setup_strategy_combo_metrics(setup_or_row, session_name: str = '', user_id: int = 0) -> dict:
    """Return current family/session/strategy evidence used to choose NORMAL vs REVERSE."""
    out = {
        'combo': '', 'combo_strategy': '', 'combo_strategy_side': '', 'family': '', 'session': '', 'strategy': _setup_strategy_short_label(setup_or_row), 'side': _setup_side_suffix(setup_or_row),
        'decided': 0, 'tp': 0, 'sl': 0, 'wr': 0.0, 'avg_r': 0.0, 'score': 0.0,
        'policy_status': '', 'policy_enabled': 1, 'policy_found': False,
        'strategy_decided': 0, 'strategy_wr': 0.0, 'strategy_avg_r': 0.0, 'strategy_score': 0.0,
    }
    try:
        fam, sess2 = _setup_combo_family_session_from_obj(setup_or_row, session_name=session_name)
        sess = str(session_name or sess2 or _setup_strategy_attr(setup_or_row, 'session', '') or _setup_strategy_attr(setup_or_row, 'source_session', '') or '').upper().strip()
        fam_s = str(fam or 'F0').upper().strip()
        sess_s = str(sess or '-').upper().strip()
        strat_s = _setup_strategy_short_label(setup_or_row)
        combo = f"{fam_s}-{sess_s}"
        side_s = _setup_side_suffix(setup_or_row)
        combo_strategy = _setup_combo_strategy_key(fam_s, sess_s, strat_s)
        combo_strategy_side = _setup_combo_strategy_side_key(fam_s, sess_s, strat_s, side_s)
        out.update({'family': fam_s, 'session': sess_s, 'combo': combo, 'combo_strategy': combo_strategy, 'combo_strategy_side': combo_strategy_side, 'strategy': strat_s, 'side': side_s})
        try:
            info = _setup_combo_policy_lookup_for_setup(setup_or_row, session_name=sess_s, user_id=int(user_id or 0)) or {}
            out['policy_found'] = bool(info.get('found'))
            _raw_policy_status = str(info.get('status') or '').upper().strip()
            out['policy_status_raw'] = _raw_policy_status or ('UNKNOWN' if not info.get('found') else '')
            out['policy_status'] = _setup_policy_effective_status(_raw_policy_status, found=bool(info.get('found')))
            out['policy_enabled'] = 1 if int(info.get('enabled') or (1 if not info.get('found') else 0)) == 1 else 0
            pol = dict(info.get('policy') or {})
            if pol:
                out['decided'] = int(pol.get('last_decided') or out['decided'])
                out['wr'] = float(pol.get('last_win_rate') or out['wr'])
                out['avg_r'] = float(pol.get('last_avg_r') or out['avg_r'])
                out['score'] = float(pol.get('last_score') or out['score'])
        except Exception:
            pass
        try:
            data = _setup_edge_guard_build(int(user_id or 0), hours=int(globals().get('SETUP_EDGE_GUARD_WINDOW_HOURS', 168) or 168), force=False) or {}
            cm_legacy = dict((data.get('combo_metrics') or {}).get(combo) or {})
            cm_strategy = dict((data.get('combo_strategy_metrics') or {}).get(combo_strategy) or {})
            cm_strategy_side = dict((data.get('combo_strategy_side_metrics') or {}).get(combo_strategy_side) or {})
            cm = cm_strategy_side or cm_strategy or cm_legacy
            if cm:
                out['decided'] = int(cm.get('decided') or out['decided'])
                out['tp'] = int(cm.get('tp') or out.get('tp') or 0)
                out['sl'] = int(cm.get('sl') or out.get('sl') or 0)
                out['wr'] = float(cm.get('wr') or out['wr'])
                out['avg_r'] = float(cm.get('avg_r') or out['avg_r'])
                out['score'] = float(cm.get('score') or out['score'])
            if cm_strategy_side:
                out['strategy_decided'] = int(cm_strategy_side.get('decided') or 0)
                out['strategy_wr'] = float(cm_strategy_side.get('wr') or 0.0)
                out['strategy_avg_r'] = float(cm_strategy_side.get('avg_r') or 0.0)
                out['strategy_score'] = float(cm_strategy_side.get('score') or 0.0)
            elif cm_strategy:
                out['strategy_decided'] = int(cm_strategy.get('decided') or 0)
                out['strategy_wr'] = float(cm_strategy.get('wr') or 0.0)
                out['strategy_avg_r'] = float(cm_strategy.get('avg_r') or 0.0)
                out['strategy_score'] = float(cm_strategy.get('score') or 0.0)
        except Exception:
            pass
    except Exception:
        pass
    return out


def _setup_strategy_metrics_for_key(family: str, session: str, strategy: str, user_id: int = 0, side: str = '') -> dict:
    """Fetch evidence for a Family-Session-Strategy-Side key, falling back to strategy level."""
    try:
        combo_strategy = _setup_combo_strategy_key(family, session, strategy)
        combo_strategy_side = _setup_combo_strategy_side_key(family, session, strategy, side) if str(side or '').strip() else ''
        data = _setup_edge_guard_build(int(user_id or 0), hours=int(globals().get('SETUP_EDGE_GUARD_WINDOW_HOURS', 168) or 168), force=False) or {}
        if combo_strategy_side:
            m = dict((data.get('combo_strategy_side_metrics') or {}).get(combo_strategy_side) or {})
            if m:
                return m
        return dict((data.get('combo_strategy_metrics') or {}).get(combo_strategy) or {})
    except Exception:
        return {}


def _setup_strategy_decision_for_setup(setup_or_row, session_name: str = '', user_id: int = 0) -> tuple[str, str, dict]:
    """Choose NORMAL for strong edges, REVERSE for weak edges, and block both if reverse is proven weak."""
    meta = _setup_strategy_combo_metrics(setup_or_row, session_name=session_name, user_id=int(user_id or 0))
    try:
        if not bool(globals().get('SETUP_ADAPTIVE_STRATEGY_ROUTER_ENABLED', True)):
            return 'NORMAL', 'strategy_router_disabled', meta
        status = str(meta.get('policy_status') or '').upper().strip()
        enabled = int(meta.get('policy_enabled') or 0) == 1
        decided = int(meta.get('decided') or 0)
        tp = int(meta.get('tp') or 0)
        sl = int(meta.get('sl') or 0)
        wr = float(meta.get('wr') or 0.0)
        avg_r = float(meta.get('avg_r') or 0.0)
        score = float(meta.get('score') or 0.0)
        strong_min = max(1, int(globals().get('SETUP_ADAPTIVE_STRONG_MIN_DECIDED', 2) or 2))
        weak_min = max(1, int(globals().get('SETUP_ADAPTIVE_WEAK_MIN_DECIDED', 2) or 2))
        strong_wr = float(globals().get('SETUP_ADAPTIVE_STRONG_WR', 55) or 55)
        strong_avg = float(globals().get('SETUP_ADAPTIVE_STRONG_AVG_R', 0.05) or 0.05)
        reverse_wr = float(globals().get('SETUP_ADAPTIVE_REVERSE_WR_MAX', 50) or 50)
        reverse_avg = float(globals().get('SETUP_ADAPTIVE_REVERSE_AVG_R_MAX', 0.05) or 0.05)
        fam = str(meta.get('family') or 'F0')
        sess = str(meta.get('session') or '-')
        rev_side = 'SELL' if str(meta.get('side') or '').upper().strip() == 'BUY' else ('BUY' if str(meta.get('side') or '').upper().strip() == 'SELL' else '')
        rev_m = _setup_strategy_metrics_for_key(fam, sess, 'REV', user_id=int(user_id or 0), side=rev_side)
        rev_dec = int(rev_m.get('decided') or 0)
        rev_wr = float(rev_m.get('wr') or 0.0)
        rev_avg = float(rev_m.get('avg_r') or 0.0)
        rev_sl = int(rev_m.get('sl') or 0)
        rev_tp = int(rev_m.get('tp') or 0)
        meta.update({'reverse_decided': rev_dec, 'reverse_wr': rev_wr, 'reverse_avg_r': rev_avg, 'reverse_tp': rev_tp, 'reverse_sl': rev_sl})
        rev_bad_enough = rev_dec >= int(globals().get('SETUP_ADAPTIVE_TIGHTEN_REVERSE_MIN_DECIDED', 4) or 4) and (rev_wr <= float(globals().get('SETUP_ADAPTIVE_TIGHTEN_REVERSE_WR_MAX', 45) or 55) or rev_avg <= 0.0 or rev_sl > rev_tp)

        # yver70: policy-disabled NORMAL lanes must be routed before the strong-KEEP
        # shortcut.  Otherwise a disabled but historically decent NOR lane could stay
        # NORMAL and then be rejected by final_combo_disabled, starving the REV lane.
        needs_reverse = False
        reverse_reason = ''
        if (status in {'DISABLE', 'BLOCK', 'PAUSE', 'OFF'} or not enabled) and bool(globals().get('SETUP_ADAPTIVE_REVERSE_FOR_DISABLED', True)):
            needs_reverse = True
            reverse_reason = f"disabled_combo_route_reverse:{meta.get('combo','-')}"
        elif decided >= strong_min and wr >= strong_wr and avg_r >= strong_avg and tp >= sl:
            return 'NORMAL', f"strong_combo_keep_normal:{meta.get('combo_strategy','-')}:WR{wr:.1f}:AvgR{avg_r:+.2f}:n{decided}", meta
        elif decided >= weak_min and (wr < reverse_wr or avg_r <= reverse_avg or score <= 0.0 or sl > tp):
            needs_reverse = True
            reverse_reason = f"weak_combo_route_reverse:{meta.get('combo','-')}:WR{wr:.1f}:AvgR{avg_r:+.2f}:n{decided}"

        if needs_reverse:
            if rev_bad_enough:
                return 'NORMAL', f"reverse_also_weak_block:{_setup_combo_strategy_key(fam, sess, 'REV')}:WR{rev_wr:.1f}:AvgR{rev_avg:+.2f}:n{rev_dec}", meta
            return 'REVERSE', reverse_reason, meta

        if status == 'KEEP':
            return 'NORMAL', f"policy_keep_normal:{meta.get('combo_strategy','-')}", meta
        return 'NORMAL', f"monitor_normal_until_decided:{meta.get('combo_strategy','-')}:n{decided}", meta
    except Exception as exc:
        meta['error'] = f'{type(exc).__name__}: {exc}'
        return 'NORMAL', 'strategy_router_error_normal', meta


def _setup_strategy_reverse_setup(setup, session_name: str = '', user_id: int = 0, reason: str = '', meta: dict | None = None):
    """Return a reversed copy of a setup: BUY->SELL / SELL->BUY with valid REV RR.

    yver70: Do NOT simply swap old TP and old SL.  A normal setup with RR 1.55
    would become a reverse setup with RR 0.65 and would almost always be rejected
    by the shared executable RR gate.  Instead, the old NORMAL stop becomes the
    reverse target, and the reverse protective stop is calculated from
    SETUP_REVERSE_TARGET_RR so the flipped lane can actually forward-test.
    """
    try:
        side = str(_setup_strategy_attr(setup, 'side', '') or '').upper().strip()
        entry = float(_setup_strategy_attr(setup, 'entry', 0.0) or 0.0)
        old_sl = float(_setup_strategy_attr(setup, 'sl', 0.0) or 0.0)
        old_tp = float(_setup_target_tp(setup, 0.0) or 0.0)
        if side not in {'BUY', 'SELL'} or entry <= 0 or old_sl <= 0 or old_tp <= 0:
            _setup_strategy_set_attr(setup, 'setup_strategy', 'NORMAL')
            _setup_strategy_set_attr(setup, 'strategy_reason', 'reverse_not_possible_bad_levels')
            return setup
        if side == 'BUY' and not (old_sl < entry < old_tp):
            _setup_strategy_set_attr(setup, 'setup_strategy', 'NORMAL')
            _setup_strategy_set_attr(setup, 'strategy_reason', 'reverse_not_possible_bad_normal_buy_geometry')
            return setup
        if side == 'SELL' and not (old_tp < entry < old_sl):
            _setup_strategy_set_attr(setup, 'setup_strategy', 'NORMAL')
            _setup_strategy_set_attr(setup, 'strategy_reason', 'reverse_not_possible_bad_normal_sell_geometry')
            return setup

        new_side = 'SELL' if side == 'BUY' else 'BUY'
        target_rr = float(globals().get('SETUP_REVERSE_TARGET_RR', 1.50) or 1.50)
        target_rr = float(clamp(target_rr, 1.05, 2.50))
        # The old normal SL is the first proof point that the normal idea failed;
        # use it as the reverse TP and calculate a closer stop from target RR.
        if side == 'BUY':
            new_tp = old_sl
            reward_dist = float(entry - new_tp)
            if reward_dist <= 0:
                _setup_strategy_set_attr(setup, 'setup_strategy', 'NORMAL')
                _setup_strategy_set_attr(setup, 'strategy_reason', 'reverse_invalid_sell_reward')
                return setup
            new_sl = entry + (reward_dist / target_rr)
        else:
            new_tp = old_sl
            reward_dist = float(new_tp - entry)
            if reward_dist <= 0:
                _setup_strategy_set_attr(setup, 'setup_strategy', 'NORMAL')
                _setup_strategy_set_attr(setup, 'strategy_reason', 'reverse_invalid_buy_reward')
                return setup
            new_sl = entry - (reward_dist / target_rr)

        if new_side == 'BUY' and not (new_sl < entry < new_tp):
            _setup_strategy_set_attr(setup, 'setup_strategy', 'NORMAL')
            _setup_strategy_set_attr(setup, 'strategy_reason', 'reverse_invalid_buy_geometry')
            return setup
        if new_side == 'SELL' and not (new_tp < entry < new_sl):
            _setup_strategy_set_attr(setup, 'setup_strategy', 'NORMAL')
            _setup_strategy_set_attr(setup, 'strategy_reason', 'reverse_invalid_sell_geometry')
            return setup
        try:
            rev = copy.copy(setup)
        except Exception:
            try:
                rev = dict(setup)
            except Exception:
                rev = setup
        old_sid = str(_setup_strategy_attr(setup, 'setup_id', '') or _setup_strategy_attr(setup, 'id', '') or make_setup_id(str(_setup_strategy_attr(setup, 'symbol', '') or ''), new_side)).strip()
        suffix = str(globals().get('SETUP_ADAPTIVE_REVERSE_SUFFIX', 'RV') or 'RV').strip().upper()
        new_sid = old_sid if old_sid.upper().endswith('-' + suffix) else f"{old_sid}-{suffix}"
        for name, value in {
            'setup_id': new_sid,
            'id': new_sid,
            'side': new_side,
            'sl': float(new_sl),
            'tp': float(new_tp),
            'alt_target_a': 0.0,
            'alt_target_b': 0.0,
            'setup_strategy': 'REVERSE',
            'strategy': 'REVERSE',
            'strategy_mode': 'REVERSE',
            'strategy_reason': str(reason or 'weak_combo_reverse'),
            'original_setup_id': old_sid,
            'original_side': side,
            'original_sl': float(old_sl),
            'original_tp': float(old_tp),
            'normal_signal_side': side,
            'reverse_target_rr': float(target_rr),
            'reverse_reward_dist': float(abs(float(entry) - float(new_tp))),
            'reverse_risk_dist': float(abs(float(new_sl) - float(entry))),
            'strategy_meta_json': json.dumps(dict(meta or {}), separators=(',', ':'), ensure_ascii=False)[:1500],
        }.items():
            _setup_strategy_set_attr(rev, name, value)
        try:
            setattr(rev, 'trend', 'BULLISH' if new_side == 'BUY' else 'BEARISH')
            setattr(rev, 'structure', getattr(rev, 'trend'))
        except Exception:
            pass
        return rev
    except Exception:
        try:
            _setup_strategy_set_attr(setup, 'setup_strategy', 'NORMAL')
            _setup_strategy_set_attr(setup, 'strategy_reason', 'reverse_exception_fallback_normal')
        except Exception:
            pass
        return setup


def _setup_adaptive_strategy_route_setup(setup, session_name: str = '', user_id: int = 0):
    """Apply ver37 NORMAL/REVERSE router to an individual setup object."""
    try:
        if _setup_strategy_label(setup) == 'REVERSE':
            return setup
        decision, reason, meta = _setup_strategy_decision_for_setup(setup, session_name=session_name, user_id=int(user_id or 0))
        if decision == 'REVERSE':
            rev = _setup_strategy_reverse_setup(setup, session_name=session_name, user_id=int(user_id or 0), reason=reason, meta=meta)
            try:
                if _setup_strategy_label(rev) == 'REVERSE':
                    db_log_setup_pipeline_event(
                        int(user_id or 0),
                        stage='nor_to_rev_router',
                        status='routed',
                        session=str(session_name or ''),
                        mode='setup_generation',
                        setup_id=str(_setup_strategy_attr(rev, 'setup_id', '') or ''),
                        symbol=str(_setup_strategy_attr(rev, 'symbol', '') or ''),
                        side=str(_setup_strategy_attr(rev, 'side', '') or ''),
                        details={
                            'reason': str(reason or ''),
                            'from_side': str(_setup_strategy_attr(rev, 'original_side', '') or ''),
                            'to_side': str(_setup_strategy_attr(rev, 'side', '') or ''),
                            'reverse_target_rr': float(_setup_strategy_attr(rev, 'reverse_target_rr', 0.0) or 0.0),
                            'source_combo': str((meta or {}).get('combo_strategy_side') or (meta or {}).get('combo_strategy') or (meta or {}).get('combo') or ''),
                        },
                    )
            except Exception:
                pass
            return rev
        _setup_strategy_set_attr(setup, 'setup_strategy', 'NORMAL')
        _setup_strategy_set_attr(setup, 'strategy', 'NORMAL')
        _setup_strategy_set_attr(setup, 'strategy_mode', 'NORMAL')
        _setup_strategy_set_attr(setup, 'strategy_reason', reason)
        return setup
    except Exception:
        return setup


def _setup_route_candidate_for_executable_lane(setup, session_name: str = '', user_id: int = 0):
    """Route a raw generated candidate into its executable strategy before gating.

    Ver42 fix: raw generated setups must be passed through the adaptive NORMAL/REVERSE
    router before `is_executable_setup_eligible()` is called.  Earlier builds checked
    the raw NORMAL setup first, so weak NORMAL combos were rejected before they could
    be converted into their intended REVERSE test lane.
    """
    try:
        routed = _setup_adaptive_strategy_route_setup(setup, session_name=session_name, user_id=int(user_id or 0))
    except Exception:
        routed = setup
    try:
        sess = str(session_name or '').upper().strip()
        if sess:
            _setup_strategy_set_attr(routed, 'source_session', sess)
            # Keep an explicit session marker for downstream report joins; do not
            # overwrite if a setup already carries a specific source session.
            if not _setup_strategy_attr(routed, 'session', ''):
                _setup_strategy_set_attr(routed, 'session', sess)
        if not float(_setup_strategy_attr(routed, 'created_ts', 0.0) or 0.0):
            _setup_strategy_set_attr(routed, 'created_ts', float(time.time()))
    except Exception:
        pass
    return routed


def _setup_strategy_for_combo_metrics(setups: int = 0, decided: int = 0, tp: int = 0, sl: int = 0, wr: float = 0.0, avg_r: float = 0.0, status: str = 'WATCH', enabled: int = 1) -> str:
    try:
        status_u = str(status or '').upper().strip()
        if bool(globals().get('SETUP_ADAPTIVE_REVERSE_FOR_DISABLED', True)) and (status_u in {'DISABLE','BLOCK','PAUSE','OFF'} or int(enabled or 0) == 0):
            return 'REV'
        if int(decided or 0) >= int(globals().get('SETUP_ADAPTIVE_STRONG_MIN_DECIDED', 2) or 2) and float(wr or 0.0) >= float(globals().get('SETUP_ADAPTIVE_STRONG_WR', 55) or 55) and float(avg_r or 0.0) >= float(globals().get('SETUP_ADAPTIVE_STRONG_AVG_R', 0.05) or 0.05) and int(tp or 0) >= int(sl or 0):
            return 'NOR'
        if int(decided or 0) >= int(globals().get('SETUP_ADAPTIVE_WEAK_MIN_DECIDED', 2) or 2) and (float(wr or 0.0) < float(globals().get('SETUP_ADAPTIVE_REVERSE_WR_MAX', 50) or 50) or float(avg_r or 0.0) <= float(globals().get('SETUP_ADAPTIVE_REVERSE_AVG_R_MAX', 0.05) or 0.05) or int(sl or 0) > int(tp or 0)):
            return 'REV'
        return 'NOR'
    except Exception:
        return 'NOR'


_LAST_SCAN_UNIVERSE = []
_LAST_SCAN_UNIVERSE = []  # bases used for setups in last scan (for /why + filtering)

def is_valid_txid(txid: str) -> bool:
    return bool(TXID_REGEX.match(txid))

def usdt_txid_exists(txid: str) -> bool:
    conn = sqlite3.connect(DB_PATH)
    cur = conn.cursor()
    cur.execute("SELECT 1 FROM usdt_payments WHERE txid = ?", (txid,))
    exists = cur.fetchone() is not None
    conn.close()
    return exists

def save_usdt_payment(user_id, username, txid, plan):
    conn = sqlite3.connect(DB_PATH)
    cur = conn.cursor()
    cur.execute("""
        INSERT INTO usdt_payments (telegram_id, username, txid, plan, status)
        VALUES (?, ?, ?, ?, 'PENDING')
    """, (user_id, username, txid, plan))
    conn.commit()
    conn.close()



