def _autotrade_daily_realized_loss_stop_allows(uid: int) -> tuple[bool, str]:
    """Hard real-money brake: do not open new AutoTrades after a bad Melbourne day."""
    try:
        if not _autotrade_daily_realized_loss_stop_enabled():
            return True, 'daily_loss_stop_disabled'
        user = _autotrade_user_settings(int(uid))
        equity = float(_effective_equity_for_risk(user, prefer_live=(str(_autotrade_runtime_mode()).lower() == 'live')) or 0.0)
        if equity <= 0:
            return True, 'daily_loss_stop_no_equity'
        pct = max(0.0, float(_autotrade_daily_realized_loss_stop_pct() or 0.0))
        if pct <= 0:
            return True, 'daily_loss_stop_pct_zero'
        m = _autotrade_day_risk_metrics_cached(int(uid), equity, ttl=10, force_refresh=False) or {}
        realised = float(m.get('realized_pnl_today') if m.get('realized_pnl_today') is not None else m.get('pnl_today') or 0.0)
        stop_usd = float(equity) * pct / 100.0
        if realised <= -stop_usd:
            return False, f'autotrade_daily_loss_stop:{realised:+.2f}<=-{stop_usd:.2f} ({pct:.1f}% equity)'
        return True, f'daily_loss_ok:{realised:+.2f}/-{stop_usd:.2f}'
    except Exception as exc:
        return True, f'daily_loss_stop_error_allowed:{type(exc).__name__}'


def _autotrade_setup_exact_combo_key(setup_or_row, session_name: str = '') -> str:
    try:
        fam, sess = _setup_combo_family_session_from_obj(setup_or_row, session_name=session_name)
        side = _setup_side_suffix(setup_or_row)
        if side not in {'BUY', 'SELL'}:
            side = _setup_side_suffix(value=str(_autotrade_setup_attr(setup_or_row, 'side', '') or ''))
        return _setup_combo_strategy_side_key(fam, sess, _setup_strategy_suffix(setup_or_row), side)
    except Exception:
        return ''


def _autotrade_realized_combo_edge_metrics(owner_uid: int) -> dict:
    """Closed real AutoTrade performance from the fixed 15-May baseline, keyed by exact lane."""
    try:
        owner_uid = int(owner_uid or 0)
        if owner_uid <= 0:
            return {}
        now_ts = float(time.time())
        start_ts = float(_overall_report_start_ts() or 0.0)
        cache = globals().setdefault('_AUTOTRADE_REALIZED_COMBO_EDGE_CACHE', {'uid': 0, 'ts': 0.0, 'data': {}})
        if int(cache.get('uid') or 0) == owner_uid and now_ts - float(cache.get('ts') or 0.0) < 180:
            return dict(cache.get('data') or {})
        rows = _autotrade_closed_report_rows_for_fixed_overall(owner_uid, start_ts, now_ts) if start_ts > 0 else []
        prepared = []
        for r in list(rows or []):
            try:
                row = _setup_audit_merge_trade_setup_row(dict(r or {}))
                fam = _setup_audit_family_display(row, compact=True)
                if not fam or fam == '-':
                    fam = _setup_audit_family_code(row)
                sess = _autotrade_report_row_session(row)
                side = str(row.get('side') or r.get('side') or '').upper().strip()
                strat = _setup_strategy_short_label(row)
                pnl = float(row.get('pnl_usdt') if row.get('pnl_usdt') is not None else row.get('pnl') or r.get('pnl_usdt') or r.get('pnl') or 0.0)
                prepared.append({
                    'family': fam or 'F0', 'session': sess or 'UNK', 'side': side or '-',
                    'setup_strategy': strat, 'strategy': strat, 'state': 'CLOSED',
                    'closed_kind': str(row.get('closed_kind') or r.get('closed_kind') or ''),
                    'result_label': str(row.get('result_label') or r.get('result_label') or ''),
                    'close_reason': str(row.get('close_reason') or r.get('close_reason') or ''),
                    'note': str(row.get('note') or r.get('note') or ''),
                    'pnl': pnl, 'pnl_usdt': pnl,
                    'setup_id': str(row.get('setup_id') or r.get('setup_id') or ''),
                    'trade_id': str(row.get('trade_id') or r.get('trade_id') or ''),
                    'opened_ts': float(row.get('opened_ts') or r.get('opened_ts') or 0.0),
                    'closed_ts': float(row.get('closed_ts') or r.get('closed_ts') or 0.0),
                    'parts': int(row.get('parts') or r.get('parts') or 1),
                })
            except Exception:
                continue
        try:
            merged = _autotrade_merge_position_report_rows(prepared)
        except Exception:
            merged = prepared
        buckets: dict[str, dict] = {}
        for r in list(merged or []):
            try:
                fam = str(r.get('family') or 'F0').upper().strip() or 'F0'
                sess = str(r.get('session') or _autotrade_report_row_session(r) or 'UNK').upper().strip() or 'UNK'
                strat = _setup_strategy_short_label(r)
                side = _setup_side_suffix(value=str(r.get('side') or ''))
                if side not in {'BUY', 'SELL'}:
                    continue
                key = _setup_combo_strategy_side_key(fam, sess, strat, side)
                b = buckets.setdefault(key, {'tp': 0, 'sl': 0, 'other': 0, 'pnl': 0.0, 'decided': 0, 'wr': 0.0})
                kind = str(r.get('closed_kind') or _autotrade_report_closed_kind(r)).upper().strip()
                pnl = float(r.get('pnl_usdt') if r.get('pnl_usdt') is not None else r.get('pnl') or 0.0)
                b['pnl'] += pnl
                if kind == 'TP':
                    b['tp'] += 1
                elif kind == 'SL':
                    b['sl'] += 1
                else:
                    b['other'] += 1
            except Exception:
                continue
        for b in buckets.values():
            d = int(b.get('tp') or 0) + int(b.get('sl') or 0)
            b['decided'] = d
            b['wr'] = (float(b.get('tp') or 0) / float(d) * 100.0) if d > 0 else 0.0
        cache.update({'uid': owner_uid, 'ts': now_ts, 'data': buckets})
        return dict(buckets)
    except Exception:
        return {}


def _autotrade_exact_lane_is_strong_from_setup_audit(data: dict, combo: str, *, for_session_escape: bool = False) -> bool:
    try:
        m = dict(((data or {}).get('combo_strategy_side_metrics') or {}).get(str(combo or '').upper().strip()) or {})
        if not m:
            return False
        dec = int(m.get('decided') or 0)
        wr = float(m.get('wr') or 0.0)
        avg = float(m.get('avg_r') or 0.0)
        if for_session_escape:
            return dec >= int(globals().get('AUTOTRADE_CONTEXT_SESSION_ESCAPE_MIN_DECIDED', 5) or 5) and wr >= float(globals().get('AUTOTRADE_CONTEXT_SESSION_ESCAPE_WR', 55.0) or 55.0) and avg >= float(globals().get('AUTOTRADE_CONTEXT_SESSION_ESCAPE_AVGR', 0.35) or 0.35)
        return dec >= int(globals().get('AUTOTRADE_CONTEXT_STRONG_ESCAPE_MIN_DECIDED', 8) or 8) and wr >= float(globals().get('AUTOTRADE_CONTEXT_STRONG_ESCAPE_WR', 65.0) or 65.0) and avg >= float(globals().get('AUTOTRADE_CONTEXT_STRONG_ESCAPE_AVGR', 0.50) or 0.50)
    except Exception:
        return False


def _autotrade_exact_lane_watch_escape_from_setup_audit(data: dict, combo: str) -> tuple[bool, str]:
    """Allow a WATCH lane to escape broad side/session/hour weakness when the exact
    family-session-strategy-side lane already has enough positive setup-audit evidence.
    This keeps strong niche lanes such as F5-NY-REV-SELL alive while preventing weak
    broad contexts from leaking into /screen, setup emails or AutoTrade.
    """
    try:
        key = str(combo or '').upper().strip()
        m = dict(((data or {}).get('combo_strategy_side_metrics') or {}).get(key) or {})
        if not m:
            return False, 'no_exact_lane_metrics'
        dec = int(m.get('decided') or 0)
        tp = int(m.get('tp') or 0)
        sl = int(m.get('sl') or 0)
        wr = float(m.get('wr') or 0.0)
        avg = float(m.get('avg_r') or 0.0)
        min_dec = int(globals().get('AUTOTRADE_CONTEXT_WATCH_EXACT_ESCAPE_MIN_DECIDED', 3) or 3)
        min_wr = float(globals().get('AUTOTRADE_CONTEXT_WATCH_EXACT_ESCAPE_WR', 55.0) or 55.0)
        min_avg = float(globals().get('AUTOTRADE_CONTEXT_WATCH_EXACT_ESCAPE_AVGR', 0.25) or 0.25)
        if dec >= min_dec and wr >= min_wr and avg >= min_avg:
            return True, f'exact_watch_escape:{key}:WR{wr:.1f}:AvgR{avg:+.2f}:n{dec}'
        # Small perfect samples remain probationary but may escape broad side/session blocks.
        if dec >= min_dec and sl == 0 and tp >= min_dec and avg > 0:
            return True, f'exact_watch_escape_perfect_sample:{key}:TP{tp}:SL0:n{dec}'
        return False, f'exact_watch_not_strong:{key}:WR{wr:.1f}:AvgR{avg:+.2f}:n{dec}'
    except Exception as exc:
        return False, f'exact_watch_escape_error:{type(exc).__name__}'

def _autotrade_policy_context_execution_allows(setup_or_row, session_name: str = '', user_id: int = 0) -> tuple[bool, str]:
    """Final real-money filter: policy KEEP + realised AutoTrade edge + setup-audit context."""
    try:
        if not _autotrade_context_feed_guard_enabled() and not _autotrade_require_realized_combo_edge():
            return True, 'autotrade_context_guard_disabled'
        owner_uid = int(globals().get('AUTOTRADE_OWNER_UID', 0) or user_id or 0)
        sess = str(session_name or _autotrade_setup_attr(setup_or_row, 'session', '') or _autotrade_setup_attr(setup_or_row, 'source_session', '') or '').upper().strip()
        combo = _autotrade_setup_exact_combo_key(setup_or_row, sess)
        pstatus_exec = ''
        # yver72: /setup_matrix KEEP is still required, but it must not bypass
        # real-money strict edge controls.  The 18-Jun review showed account PnL
        # falling while matrix KEEP hovered around ~50% WR, so AutoTrade now treats
        # matrix KEEP as the first gate and continues through strict live edge,
        # realised-combo and context guards before placing money on the trade.
        try:
            _matrix_state = _setup_matrix_policy_source_state_for_setup(setup_or_row, session_name=sess, user_id=owner_uid) or {}
            if str(_matrix_state.get('policy') or '').upper().strip() == 'KEEP':
                pstatus_exec = 'KEEP'
                try:
                    _setup_quality_gate_set_attr(setup_or_row, 'yver72_matrix_keep_seen', True)
                except Exception:
                    pass
        except Exception:
            pass
        try:
            _pinfo_exec = _setup_combo_policy_lookup_for_setup(setup_or_row, session_name=sess, user_id=owner_uid)
            pstatus_exec = _setup_policy_effective_status(
                str((_pinfo_exec or {}).get('status') or '').upper().strip(),
                found=bool((_pinfo_exec or {}).get('found'))
            )
        except Exception:
            pstatus_exec = ''
        fam, sess_k, side, sym, hour = _setup_edge_guard_setup_key(setup_or_row, session_name=sess)
        side = str(side or '').upper().strip()
        # 1) Exact real AutoTrade combo performance must not be losing once it has enough samples.
        if _autotrade_require_realized_combo_edge() and combo:
            rm = dict((_autotrade_realized_combo_edge_metrics(owner_uid) or {}).get(combo) or {})
            dec = int(rm.get('decided') or 0)
            wr = float(rm.get('wr') or 0.0)
            pnl = float(rm.get('pnl') or 0.0)
            min_dec = int(globals().get('AUTOTRADE_REALIZED_COMBO_MIN_DECIDED', 3) or 3)
            if dec >= min_dec and (wr < float(globals().get('AUTOTRADE_REALIZED_COMBO_MIN_WR', 50.0) or 50.0) or pnl < float(globals().get('AUTOTRADE_REALIZED_COMBO_MIN_PNL', 0.0) or 0.0)):
                return False, f'autotrade_realized_combo_block:{combo}:WR{wr:.1f}:PnL{pnl:+.2f}:n{dec}'
        if not _autotrade_context_feed_guard_enabled():
            return True, 'autotrade_realized_combo_ok'
        hours = _overall_report_effective_hours(int(globals().get('SETUP_EDGE_GUARD_WINDOW_HOURS', 168) or 168))
        data = _setup_edge_guard_build(owner_uid, hours=hours, force=False) or {}

        # yver147: real-money AutoTrade should not use every KEEP lane while the
        # target WR is >50%.  A lane can be KEEP because of broader/older policy,
        # but live entries now require the exact lane evidence to remain strong.
        # Default: decided>=5, WR>=60%, AvgR>=+0.25. This blocks recent weak KEEP
        # lanes such as F1-LON-NOR-BUY/F2-NY-NOR-BUY while keeping stronger lanes
        # like F2-ASIA-NOR-BUY and F1-LON-REV-BUY.
        try:
            # yver23: Ramin's explicit rule is that any exact combo/lane with
            # decided WR >49% is KEEP.  yver22 correctly forced that in the
            # policy lookup, but this later strict-KEEP edge guard could still
            # re-block the same lane using a different rolling/micro dataset
            # (seen as email_autotrade_strict_keep_edge_block for
            # F8-ASIA-REV-BUY while /setup_matrix policy showed KEEP).
            # When the policy lookup was force-kept from latest setup_combo_scores,
            # do not let this secondary guard override it. Symbol/hour/directional
            # safety checks below still remain active.
            _force_keep_policy = False
            try:
                _force_keep_policy = bool((_pinfo_exec or {}).get('force_keep')) or bool((_pinfo_exec or {}).get('force_keep_info'))
            except Exception:
                _force_keep_policy = False
            _allow_force_keep_bypass = env_bool('AUTOTRADE_ALLOW_MATRIX_KEEP_STRICT_BYPASS', False)
            if pstatus_exec == 'KEEP' and _autotrade_strict_keep_edge_enabled() and ((not _force_keep_policy) or (not _allow_force_keep_bypass)):
                m = dict(((data or {}).get('combo_strategy_side_metrics') or {}).get(str(combo or '').upper().strip()) or {})
                dec = int(m.get('decided') or 0)
                wr = float(m.get('wr') or 0.0)
                avg = float(m.get('avg_r') or 0.0)
                min_dec = int(_autotrade_strict_keep_edge_min_decided())
                min_wr = float(_autotrade_strict_keep_edge_min_wr())
                min_avg = float(_autotrade_strict_keep_edge_min_avgr())
                if dec < min_dec or wr < min_wr or avg < min_avg:
                    return False, f'autotrade_strict_keep_edge_block:{combo}:WR{wr:.1f}:AvgR{avg:+.2f}:n{dec}'
            elif pstatus_exec == 'KEEP' and _force_keep_policy and _allow_force_keep_bypass:
                try:
                    _setup_quality_gate_set_attr(setup_or_row, 'yver24_matrix_keep_bypassed_strict_edge', True)
                except Exception:
                    pass
        except Exception as _strict_exc:
            return False, f'autotrade_strict_keep_edge_error:{type(_strict_exc).__name__}'

        # 2) Existing micro-edge symbols/hours are hard execution blockers.
        if sym and sym in dict((data or {}).get('symbol_block') or {}):
            return False, f'autotrade_symbol_block:{sym}'
        if hour in dict((data or {}).get('hour_watch') or {}):
            return False, f'autotrade_weak_hour_block:{hour}'

        # yver117: Apply Setup Deep Analysis lessons to WATCH rows. KEEP rows are
        # already proven by exact lane evidence; WATCH rows are probationary and must
        # survive side/session/hour context. This same function also controls /screen
        # and setup emails, so subscribers only see the cleaner subset.
        if pstatus_exec == 'WATCH' and bool(globals().get('AUTOTRADE_CONTEXT_WATCH_DEEP_GUARD_ENABLED', True)):
            exact_escape, exact_escape_reason = _autotrade_exact_lane_watch_escape_from_setup_audit(data, combo)
            if not exact_escape:
                try:
                    m = dict(((data or {}).get('combo_strategy_side_metrics') or {}).get(str(combo or '').upper().strip()) or {})
                    dec = int(m.get('decided') or 0)
                    conf = float(_autotrade_setup_attr(setup_or_row, 'conf', 0.0) or 0.0)
                    dyn = float(_autotrade_setup_attr(setup_or_row, 'quality_score', 0.0) or 0.0)
                    if dyn <= 0:
                        dyn = float(_autotrade_setup_attr(setup_or_row, 'dynamic_risk_score', 0.0) or 0.0)
                    if dec < 2 and (conf < int(globals().get('AUTOTRADE_CONTEXT_WATCH_LOW_SAMPLE_MIN_CONF', 87) or 87) or dyn < float(globals().get('AUTOTRADE_CONTEXT_WATCH_LOW_SAMPLE_MIN_DYNAMIC', 75) or 75)):
                        return False, f'autotrade_watch_low_sample_block:{combo}:Conf{conf:.0f}:Dyn{dyn:.0f}:n{dec}'
                except Exception:
                    pass
                if side in {'BUY', 'SELL'}:
                    sm = dict(((data or {}).get('side_metrics') or {}).get(side) or {})
                    if int(sm.get('decided') or 0) >= int(globals().get('AUTOTRADE_CONTEXT_WATCH_SIDE_MIN_DECIDED', 100) or 100):
                        swr = float(sm.get('wr') or 0.0); savg = float(sm.get('avg_r') or 0.0)
                        if swr <= float(globals().get('AUTOTRADE_CONTEXT_WATCH_SIDE_WR_MAX', 35.0) or 35.0) and savg <= float(globals().get('AUTOTRADE_CONTEXT_WATCH_SIDE_AVGR_MAX', 0.0) or 0.0):
                            return False, f'autotrade_watch_side_context_block:{side}:WR{swr:.1f}:AvgR{savg:+.2f}:{exact_escape_reason}'
                if sess_k in {'ASIA', 'LON', 'NY'}:
                    ss = dict(((data or {}).get('session_metrics') or {}).get(sess_k) or {})
                    if int(ss.get('decided') or 0) >= int(globals().get('AUTOTRADE_CONTEXT_WATCH_SESSION_MIN_DECIDED', 100) or 100):
                        wrs = float(ss.get('wr') or 0.0); avgs = float(ss.get('avg_r') or 0.0)
                        if wrs <= float(globals().get('AUTOTRADE_CONTEXT_WATCH_SESSION_WR_MAX', 40.0) or 40.0) and avgs <= float(globals().get('AUTOTRADE_CONTEXT_WATCH_SESSION_AVGR_MAX', 0.05) or 0.05):
                            return False, f'autotrade_watch_session_context_block:{sess_k}:WR{wrs:.1f}:AvgR{avgs:+.2f}:{exact_escape_reason}'
                hm = dict(((data or {}).get('hour_metrics') or {}).get(hour) or {})
                if int(hm.get('decided') or 0) >= int(globals().get('AUTOTRADE_CONTEXT_WATCH_HOUR_MIN_DECIDED', 10) or 10):
                    hwr = float(hm.get('wr') or 0.0); havg = float(hm.get('avg_r') or 0.0)
                    if hwr <= float(globals().get('AUTOTRADE_CONTEXT_WATCH_HOUR_WR_MAX', 35.0) or 35.0) and havg <= float(globals().get('AUTOTRADE_CONTEXT_WATCH_HOUR_AVGR_MAX', 0.0) or 0.0):
                        return False, f'autotrade_watch_hour_context_block:{hour}:WR{hwr:.1f}:AvgR{havg:+.2f}:{exact_escape_reason}'
        # 3) Feed broad side/session evidence into AutoTrade. Setup emails can still show them.
        # yver108: broad BUY/SELL weakness is advisory for exact KEEP/WATCH lanes.
        # Exact lane policy + symbol/hour blocks are more precise. Do not let global BUY
        # weakness hide an allowed F1-LON-REV-BUY/F5-LON-REV-SELL style lane.
        if side in {'BUY', 'SELL'} and pstatus_exec not in _autotrade_allowed_policy_statuses() and bool(globals().get('AUTOTRADE_BLOCK_WEAK_SIDE_CONTEXT', True)):
            sm = dict(((data or {}).get('side_metrics') or {}).get(side) or {})
            if int(sm.get('decided') or 0) >= int(globals().get('AUTOTRADE_CONTEXT_SIDE_MIN_DECIDED', 40) or 40):
                if float(sm.get('wr') or 0.0) <= float(globals().get('AUTOTRADE_CONTEXT_SIDE_WR_MAX', 40.0) or 40.0) and float(sm.get('avg_r') or 0.0) < 0:
                    if not _autotrade_exact_lane_is_strong_from_setup_audit(data, combo, for_session_escape=False):
                        return False, f'autotrade_weak_side_block:{side}:WR{float(sm.get("wr") or 0.0):.1f}:AvgR{float(sm.get("avg_r") or 0.0):+.2f}'
        if sess_k in {'ASIA', 'LON', 'NY'} and pstatus_exec not in _autotrade_allowed_policy_statuses() and bool(globals().get('AUTOTRADE_BLOCK_WEAK_SESSION_CONTEXT', True)):
            ss = dict(((data or {}).get('session_metrics') or {}).get(sess_k) or {})
            if int(ss.get('decided') or 0) >= int(globals().get('AUTOTRADE_CONTEXT_SESSION_MIN_DECIDED', 50) or 50):
                if float(ss.get('wr') or 0.0) <= float(globals().get('AUTOTRADE_CONTEXT_SESSION_WR_MAX', 38.0) or 38.0) and float(ss.get('avg_r') or 0.0) < 0:
                    if not _autotrade_exact_lane_is_strong_from_setup_audit(data, combo, for_session_escape=True):
                        return False, f'autotrade_weak_session_block:{sess_k}:WR{float(ss.get("wr") or 0.0):.1f}:AvgR{float(ss.get("avg_r") or 0.0):+.2f}'
        return True, 'autotrade_policy_context_ok'
    except Exception as exc:
        return True, f'autotrade_context_guard_error_allowed:{type(exc).__name__}'


