def _strategy_config_migrate():
    """Ensure strategy_config table exists."""
    try:
        with sqlite3.connect(DB_PATH) as conn:
            c = conn.cursor()
            c.execute("""CREATE TABLE IF NOT EXISTS strategy_config (
                key TEXT PRIMARY KEY,
                value TEXT NOT NULL,
                updated_ts REAL
            )""")
            conn.commit()
    except Exception:
        pass

