def _strategy_config_apply_ver08_quality_patch() -> None:
    """Ver09/Ver10 balanced quality patch from 04 May audit results.

    Ver08 was intentionally very strict (LON/NY + Engine A only). After reviewing
    the next command outputs, that was too narrow and it also risked blocking the
    newly-added Big-Move engine. Ver09 keeps Big-Move/F8 active, keeps Engine B
    available, removes only the weakest current executor (F3/Engine C), and uses
    higher volume/quality/RR gates to reduce bad setups without killing flow.
    """
    try:
        cfg = load_strategy_config(force=True)
        cfg['ver09_quality_patch_applied'] = True
        cfg['ver09_quality_patch_ts'] = float(time.time())
        # Balanced, not F1-only. Keep all sessions available, but make ASIA stricter.
        cfg['high_win_mode'] = False
        cfg['execution_sessions_allowed'] = ['ASIA', 'LON', 'NY']
        # Ver14: discovery mode. Keep all eight setup families active so we can
        # collect enough real samples before prioritising winners. F1/F2/F3 are
        # represented by engines A/B/C; F4-F7 are research-family overlays; F8 is BigMove.
        cfg['execution_engines_allowed'] = ['A', 'B', 'C', 'F4', 'F5', 'F6', 'F7', 'F8', 'F9']
        cfg['active_family_codes'] = ['F1', 'F2', 'F3', 'F4', 'F5', 'F6', 'F7', 'F8', 'F9']
        cfg['execution_asia_enabled'] = True
        cfg['execution_asia_user_override'] = False
        cfg['execution_engine_b_email_enabled'] = True
        cfg['goal_profile_allow_asia'] = True
        cfg['goal_profile_allow_engine_b'] = True
        cfg['goal_profile_active_profile'] = 'ALL_FAMILIES_DISCOVERY_VER14'
        cfg['family_allocator_shadow_mode'] = True
        cfg['family_allocator_enforce_live'] = False

        # Quality floors: reduce raw noise, but avoid the too-tight Ver08 1-3/day profile.
        cfg['min_fut_vol_usd'] = 10_000_000.0
        cfg['quality_score_min_screen'] = max(63.0, float(cfg.get('quality_score_min_screen', 0) or 0.0))
        cfg['quality_score_min_email'] = 70.0
        cfg['min_rr_tp'] = 1.35
        cfg['tf_align_1h_min_abs'] = max(0.70, float(cfg.get('tf_align_1h_min_abs', 0) or 0.0))
        cfg['tf_align_4h_min_abs'] = max(0.60, float(cfg.get('tf_align_4h_min_abs', 0) or 0.0))
        cfg['atr_min_pct'] = max(0.95, float(cfg.get('atr_min_pct', 0) or 0.0))

        # Session weighting: LON/NY are preferred, ASIA can still produce only strong setups.
        cfg['session_weights'] = {'NY': 0.45, 'LON': 0.45, 'ASIA': 0.10}
        cfg['session_exec_overrides'] = {
            'NY': {'quality_add': 1.0, 'conf_add': 1, 'rr_add': 0.06},
            'LON': {'quality_add': 0.5, 'conf_add': 1, 'rr_add': 0.04},
            'ASIA': {'quality_add': 4.0, 'conf_add': 3, 'rr_add': 0.22},
        }

        # Commercial target: enough signals to learn from, but not the raw 100+/day noise.
        cfg['target_setups_per_day_lo'] = 4.0
        cfg['target_setups_per_day_hi'] = 8.0
        cfg['governor_target_lo'] = 4.0
        cfg['governor_target_hi'] = 8.0
        cfg['goal_profile_target_setups_per_day_lo'] = 4.0
        cfg['goal_profile_target_setups_per_day_hi'] = 8.0
        cfg['goal_profile_target_win_rate'] = 52.0
        cfg['goal_profile_target_avg_r'] = 0.10
        save_strategy_config(cfg)
        apply_strategy_config(cfg)
    except Exception:
        pass

def apply_strategy_config(cfg: dict) -> None:
    """Apply StrategyConfig into global tunables used throughout the bot."""
    global MIN_FUT_VOL_USD, EMAIL_MIN_FUT_VOL_USD, MIN_RR_TP
    global QUALITY_SCORE_MIN_SCREEN, QUALITY_SCORE_MIN_EMAIL
    global TF_ALIGN_ENABLED, TF_ALIGN_1H_MIN_ABS, TF_ALIGN_4H_MIN_ABS
    global ATR_MIN_PCT, ATR_MAX_PCT
    global _QUALITY_W

    if not isinstance(cfg, dict):
        return

    # Liquidity + RR
    try:
        # yver30: keep live setup/email/audit floor at 10M even if old StrategyConfig stored 15M.
        MIN_FUT_VOL_USD = 10_000_000.0
        EMAIL_MIN_FUT_VOL_USD = 10_000_000.0
        try:
            cfg["min_fut_vol_usd"] = 10_000_000.0
        except Exception:
            pass
    except Exception:
        pass
    try:
        MIN_RR_TP = float(cfg.get("min_rr_tp", cfg.get("min_rr_tp", MIN_RR_TP)))
    except Exception:
        pass

    # Score floors
    try:
        QUALITY_SCORE_MIN_SCREEN = float(cfg.get("quality_score_min_screen", QUALITY_SCORE_MIN_SCREEN))
    except Exception:
        pass
    try:
        QUALITY_SCORE_MIN_EMAIL = float(cfg.get("quality_score_min_email", QUALITY_SCORE_MIN_EMAIL))
    except Exception:
        pass

    # Alignment / ATR
    try:
        TF_ALIGN_ENABLED = bool(cfg.get("tf_align_enabled", TF_ALIGN_ENABLED))
    except Exception:
        pass
    try:
        TF_ALIGN_1H_MIN_ABS = float(cfg.get("tf_align_1h_min_abs", TF_ALIGN_1H_MIN_ABS))
        TF_ALIGN_4H_MIN_ABS = float(cfg.get("tf_align_4h_min_abs", TF_ALIGN_4H_MIN_ABS))
    except Exception:
        pass
    try:
        ATR_MIN_PCT = float(cfg.get("atr_min_pct", ATR_MIN_PCT))
        ATR_MAX_PCT = float(cfg.get("atr_max_pct", ATR_MAX_PCT))
    except Exception:
        pass

    # Scoring weights (kept in one dict for compute_setup_quality_score)
    _QUALITY_W = {
        "conf": float(cfg.get("score_w_conf", 0.45)),
        "regime": float(cfg.get("score_w_regime", 0.12)),
        "align": float(cfg.get("score_w_align", 0.10)),
        "rr": float(cfg.get("score_w_rr", 0.10)),
        "vol": float(cfg.get("score_w_vol", 0.08)),
        "atr": float(cfg.get("score_w_atr", 0.06)),
        "ema_clean": float(cfg.get("score_w_ema_clean", 0.04)),
        "stop_sane": float(cfg.get("score_w_stop_sane", 0.04)),
        "sweep": float(cfg.get("score_w_sweep", 0.03)),
        "smf": float(cfg.get("score_w_smf", 0.01)),
    }

# Initialize config on boot
try:
    apply_strategy_config(load_strategy_config(force=True))
    _strategy_config_bootstrap_recommendations()
    _strategy_config_apply_ver08_quality_patch()
    try:
        _research_seed_family_registry()
        _research_activate_all_families_runtime()
        _ver14_all_family_profile_bootstrap()
    except Exception:
        pass
except Exception:
    pass

def _parse_param_value(s: str):
    """Parse param values for /params_set. Supports bool/int/float/json/raw string."""
    v = (s or "").strip()
    if v.lower() in ("true","yes","on","1"): return True
    if v.lower() in ("false","no","off","0"): return False
    # Try numeric
    try:
        if re.fullmatch(r"[-+]?\d+", v):
            return int(v)
        if re.fullmatch(r"[-+]?\d*\.\d+", v):
            return float(v)
    except Exception:
        pass
    # Try JSON
    try:
        if (v.startswith("{") and v.endswith("}")) or (v.startswith("[") and v.endswith("]")):
            return json.loads(v)
    except Exception:
        pass
    return v

async def cmd_params_show(update: Update, context: ContextTypes.DEFAULT_TYPE):
    cfg = load_strategy_config(force=False)
    pretty = json.dumps(cfg, indent=2, ensure_ascii=False, sort_keys=True)
    await send_long_message(update, f"⚙️ Strategy Params (active)\n{HDR}\n```\n{pretty}\n```", parse_mode=ParseMode.MARKDOWN)

async def cmd_params_reset(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if not is_admin_user(update.effective_user.id):
        await update.message.reply_text("⛔ Admin only.")
        return
    cfg = _strategy_config_defaults()
    save_strategy_config(cfg)
    apply_strategy_config(cfg)
    await update.message.reply_text("✅ Strategy params reset to defaults.")

async def cmd_params_set(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if not is_admin_user(update.effective_user.id):
        await update.message.reply_text("⛔ Admin only.")
        return
    args = context.args or []
    if len(args) < 2:
        await update.message.reply_text("Usage: /params_set <key> <value>\nExample: /params_set quality_score_min_screen 58")
        return
    key = str(args[0]).strip()
    val_raw = " ".join(args[1:]).strip()
    val = _parse_param_value(val_raw)
    cfg = load_strategy_config(force=True)

    # Support dot paths into nested dict (e.g. opt_bounds.quality_score_min_screen)
    if "." in key:
        parts = key.split(".")
        cur = cfg
        for p in parts[:-1]:
            if p not in cur or not isinstance(cur[p], dict):
                cur[p] = {}
            cur = cur[p]
        cur[parts[-1]] = val
    else:
        cfg[key] = val

    if key == 'execution_asia_enabled':
        cfg['execution_asia_user_override'] = True

    save_strategy_config(cfg)
    apply_strategy_config(cfg)
    await update.message.reply_text(f"✅ Updated: {key} = {val_raw}")


