# =========================================================
# 🤖 AUTOTRADE — Bybit V5 helpers + DB
# =========================================================
import hmac
import hashlib
import uuid

def _bybit_base_url() -> str:
    return "https://api-testnet.bybit.com" if BYBIT_TESTNET else "https://api.bybit.com"

def _bybit_v5_sign(ts_ms: str, body: str) -> str:
    """
    Bybit V5 signature:
      sign = HMAC_SHA256(secret, timestamp + api_key + recv_window + body)
    """
    msg = f"{ts_ms}{BYBIT_API_KEY}{BYBIT_RECV_WINDOW}{body}".encode("utf-8")
    return hmac.new(BYBIT_API_SECRET.encode("utf-8"), msg, hashlib.sha256).hexdigest()

def _bybit_v5_request(method: str, path: str, payload: dict | None = None) -> dict:
    import requests
    from urllib.parse import urlencode

    method = (method or "GET").upper().strip()
    payload = payload or {}

    base = _bybit_base_url()
    url = base + path

    ts_ms = str(int(time.time() * 1000))

    # For V5 signing:
    # - GET requests must be signed with the *query string* (not the body),
    #   and the query must actually be sent to Bybit.
    # - POST requests are signed with the JSON body.
    body = ""
    query_str = ""

    if method == "GET":
        # Support callers that pass params in payload (recommended).
        # If path already has '?', keep it and append any payload params.
        if "?" in url:
            url_base, url_q = url.split("?", 1)
            url = url_base
            query_str = url_q
        if payload:
            extra = urlencode(payload, doseq=True)
            query_str = f"{query_str}&{extra}" if (query_str and extra) else (query_str or extra)

        if query_str:
            url = f"{url}?{query_str}"

        sign_payload = query_str
    else:
        body = json.dumps(payload, separators=(",", ":"), ensure_ascii=False)
        sign_payload = body

    sign = _bybit_v5_sign(ts_ms, sign_payload) if (BYBIT_API_KEY and BYBIT_API_SECRET) else ""

    headers = {
        "Content-Type": "application/json",
        "X-BAPI-API-KEY": BYBIT_API_KEY,
        "X-BAPI-TIMESTAMP": ts_ms,
        "X-BAPI-RECV-WINDOW": BYBIT_RECV_WINDOW,
        "X-BAPI-SIGN": sign,
    }

    try:
        try:
            http_timeout = float(os.getenv("BYBIT_HTTP_TIMEOUT_SEC", "7") or 7)
        except Exception:
            http_timeout = 7.0
        http_timeout = max(2.0, min(15.0, float(http_timeout)))
        if method == "GET":
            r = requests.get(url, headers=headers, timeout=http_timeout)
        else:
            r = requests.post(url, headers=headers, data=body.encode("utf-8"), timeout=http_timeout)
        return r.json()
    except Exception as e:
        return {"retCode": -1, "retMsg": f"{type(e).__name__}: {e}", "result": None}
def _autotrade_liq_before_sl(side: str, liq_price: float, sl_price: float) -> bool:
    """True when exchange liquidation would happen before/at the stop loss."""
    try:
        side_u = str(side or '').upper().strip()
        liq = float(liq_price or 0.0)
        sl = float(sl_price or 0.0)
        if liq <= 0 or sl <= 0:
            return False
        if side_u == 'BUY':
            return liq >= sl
        if side_u == 'SELL':
            return liq <= sl
    except Exception:
        pass
    return False



def _autotrade_liq_has_required_buffer(side: str, liq_price: float, sl_price: float, entry_price: float, buffer_pct: float | None = None) -> bool:
    """True when liquidation is beyond SL by the configured safety buffer."""
    try:
        side_u = str(side or '').upper().strip()
        liq = float(liq_price or 0.0)
        sl = float(sl_price or 0.0)
        entry = float(entry_price or 0.0)
        raw_buf = float(buffer_pct if buffer_pct is not None else _autotrade_runtime_liq_buffer_pct())
        try:
            raw_buf = max(raw_buf, float(AUTOTRADE_LIQ_GUARD_MIN_BUFFER_PCT))
        except Exception:
            raw_buf = max(raw_buf, 3.0)
        buf = entry * max(0.0, min(25.0, raw_buf)) / 100.0
        if liq <= 0 or sl <= 0 or entry <= 0 or side_u not in {'BUY', 'SELL'}:
            return True  # no reliable liq price reported; do not force-close purely on missing data
        if side_u == 'BUY':
            return bool(liq < (sl - buf))
        return bool(liq > (sl + buf))
    except Exception:
        return True


def _autotrade_live_liq_guard_ok(side: str, liq_price: float, sl_price: float, entry_price: float, buffer_pct: float | None = None) -> bool:
    """Final live check: liquidation must not be before SL and must keep buffer."""
    try:
        if _autotrade_liq_before_sl(side, liq_price, sl_price):
            return False
        return _autotrade_liq_has_required_buffer(side, liq_price, sl_price, entry_price, buffer_pct)
    except Exception:
        return False

def _autotrade_liq_safety_plan(entry: float, sl: float, side: str, configured_leverage: int | float, buffer_pct: float | None = None) -> dict:
    """Plan a per-symbol leverage that keeps liquidation beyond the stop-loss.

    Conservative isolated-linear approximation:
      long  liq ≈ entry * (1 - 1/leverage)
      short liq ≈ entry * (1 + 1/leverage)

    We require the approximate liquidation point to sit beyond SL by buffer_pct of
    entry. If configured leverage is too high for a wide SL, the bot automatically
    lowers leverage for this symbol before opening the trade.
    """
    out = {
        'ok': False,
        'reason': 'liq_plan_not_computed',
        'configured_leverage': int(float(configured_leverage or 1) or 1),
        'safe_leverage': int(float(configured_leverage or 1) or 1),
        'stop_distance_pct': 0.0,
        'buffer_pct': float(buffer_pct if buffer_pct is not None else 0.0),
        'estimated_liq_price': 0.0,
    }
    try:
        e = float(entry or 0.0)
        st = float(sl or 0.0)
        side_u = str(side or '').upper().strip()
        cfg_lev = max(1, int(float(configured_leverage or 1)))
        raw_buf_pct = float(buffer_pct if buffer_pct is not None else _autotrade_runtime_liq_buffer_pct())
        # Apply a hard internal minimum buffer so liquidation is not merely beyond
        # the SL by a tiny amount. User-facing config can still be lower, but live
        # execution stays safer.
        try:
            min_buf = float(AUTOTRADE_LIQ_GUARD_MIN_BUFFER_PCT)
        except Exception:
            min_buf = 3.0
        buf_pct = max(0.0, min(25.0, max(float(raw_buf_pct), float(min_buf))))
        out['configured_leverage'] = cfg_lev
        out['buffer_pct'] = float(buf_pct)
        if e <= 0 or st <= 0 or side_u not in {'BUY', 'SELL'}:
            out['reason'] = 'bad_liq_inputs'
            return out
        if side_u == 'BUY' and st >= e:
            out['reason'] = 'bad_buy_sl_for_liq_guard'
            return out
        if side_u == 'SELL' and st <= e:
            out['reason'] = 'bad_sell_sl_for_liq_guard'
            return out
        stop_frac = abs(e - st) / e
        buf_frac = float(buf_pct) / 100.0
        # Use a conservative factor instead of 1.00 to leave room for maintenance
        # margin, fees, risk-limit tiers and mark-price slippage. This intentionally
        # chooses a lower leverage so the Bybit liquidation line sits beyond SL.
        try:
            safety_factor = max(0.50, min(0.94, float(AUTOTRADE_LIQ_GUARD_SAFETY_FACTOR)))
        except Exception:
            safety_factor = 0.72
        out['safety_factor'] = float(safety_factor)
        denom = max(1e-9, stop_frac + buf_frac)
        max_safe_lev = int(math.floor(float(safety_factor) / denom))
        safe_lev = max(1, min(cfg_lev, max_safe_lev if max_safe_lev > 0 else 1))
        if safe_lev <= 0:
            safe_lev = 1
        liq_distance_frac = 1.0 / float(safe_lev)
        est_liq = e * (1.0 - liq_distance_frac) if side_u == 'BUY' else e * (1.0 + liq_distance_frac)
        out.update({
            'safe_leverage': int(safe_lev),
            'stop_distance_pct': float(stop_frac * 100.0),
            'estimated_liq_price': float(est_liq),
            'reason': 'ok',
        })
        # Estimated liquidation must be beyond the buffered stop level.
        if side_u == 'BUY':
            out['ok'] = bool(est_liq < (st - e * buf_frac))
        else:
            out['ok'] = bool(est_liq > (st + e * buf_frac))
        if not out['ok'] and safe_lev == 1:
            out['reason'] = 'stop_too_wide_for_liq_buffer_even_1x'
        elif not out['ok']:
            out['reason'] = 'liq_plan_failed'
        return out
    except Exception as exc:
        out['reason'] = f'liq_plan_error:{type(exc).__name__}'
        return out


def _autotrade_set_symbol_leverage_safe(symbol: str, leverage: int | float) -> tuple[bool, str, dict]:
    """Best-effort Bybit V5 leverage setter. Accepts 'not modified' as OK.

    Ver53: Bybit can reject a liquidation-safe downgrade when the requested
    leverage is still above the symbol/risk-tier maximum, for example:
    `cannot set leverage [700] gt maxLeverage [500] by risk limit`.
    The numbers are Bybit's 100x leverage units, so [700]=7x and [500]=5x.
    In that case retry once at the exchange maximum instead of skipping the setup.
    Lower leverage is safer for liquidation distance, so this preserves the liq guard.
    """
    def _lev_x_from_bybit_units(raw) -> int:
        try:
            v = float(raw)
            if v >= 100:
                return max(1, int(math.floor(v / 100.0)))
            return max(1, int(math.floor(v)))
        except Exception:
            return 0

    def _post(lev_x: int):
        payload = {
            'category': 'linear',
            'symbol': sym,
            'buyLeverage': str(int(max(1, lev_x))),
            'sellLeverage': str(int(max(1, lev_x))),
        }
        return _bybit_v5_request('POST', '/v5/position/set-leverage', payload)

    try:
        sym = _bybit_linear_symbol(symbol)
        lev = max(1, int(float(leverage or 1)))
        res = _post(lev)
        code = int((res or {}).get('retCode', -1))
        msg = str((res or {}).get('retMsg') or '')
        low = msg.lower()
        if code == 0 or 'not modified' in low or 'same leverage' in low:
            return True, msg or 'ok', (res or {})

        retry_lev = 0
        try:
            nums = re.findall(r'\[(\d+(?:\.\d+)?)\]', msg)
            # Usually [requested_units] then [max_units].  Use the last bracket as max.
            if nums and ('maxleverage' in low or 'risk limit' in low or code == 110013):
                retry_lev = _lev_x_from_bybit_units(nums[-1])
        except Exception:
            retry_lev = 0
        if retry_lev > 0 and retry_lev < lev:
            res2 = _post(retry_lev)
            code2 = int((res2 or {}).get('retCode', -1))
            msg2 = str((res2 or {}).get('retMsg') or '')
            low2 = msg2.lower()
            if code2 == 0 or 'not modified' in low2 or 'same leverage' in low2:
                try:
                    if isinstance(res2, dict):
                        res2.setdefault('_ver53_actual_leverage', int(retry_lev))
                        res2.setdefault('_ver53_retry_from_leverage', int(lev))
                except Exception:
                    pass
                return True, f'exchange_max_downgrade_{lev}x_to_{retry_lev}x: {msg2 or "ok"}', (res2 or {})
            return False, f'{code2} {msg2} after_exchange_max_retry_{retry_lev}x'.strip(), (res2 or {})

        return False, f'{code} {msg}'.strip(), (res or {})
    except Exception as exc:
        return False, f'{type(exc).__name__}: {exc}', {}



def _autotrade_adjust_live_liq_beyond_sl(symbol: str, side: str, sl_price: float, entry_price: float, start_leverage: int | float, uid: int | None = None) -> dict:
    """Try to move Bybit liquidation price beyond SL by lowering live leverage.

    If Bybit reports a liquidation price that would be hit before SL, do not close
    immediately. First reduce leverage step-by-step down to 1x and re-check the
    exchange-reported liq price. Only the caller decides whether to close if this
    still fails.
    """
    out = {'ok': False, 'reason': 'not_attempted', 'attempts': []}
    try:
        sym = _bybit_linear_symbol(symbol)
        side_u = str(side or '').upper().strip()
        start = max(1, int(float(start_leverage or _autotrade_runtime_leverage() or 1)))
        buffer_pct = _autotrade_runtime_liq_buffer_pct()
        last_pos = None
        for lev in range(start, 0, -1):
            lev_ok, lev_msg, lev_res = _autotrade_set_symbol_leverage_safe(sym, lev)
            try:
                time.sleep(0.35)
            except Exception:
                pass
            pos = _autotrade_wait_live_position(sym, side=side_u, wait_sec=2.0, step_sec=0.25) or _autotrade_find_live_position(sym, side=side_u)
            last_pos = pos or last_pos
            liq = float(_pos_liq_price(pos) if pos else 0.0)
            entry_live = float(_pos_entry(pos) if pos else entry_price or 0.0) or float(entry_price or 0.0)
            ok_now = bool(lev_ok) and _autotrade_live_liq_guard_ok(side_u, liq, sl_price, entry_live, buffer_pct)
            out['attempts'].append({'lev': int(lev), 'set_ok': bool(lev_ok), 'msg': str(lev_msg), 'liq': float(liq), 'entry': float(entry_live), 'ok': bool(ok_now)})
            if ok_now:
                out.update({'ok': True, 'reason': 'adjusted', 'leverage': int(lev), 'liq_price': float(liq), 'entry': float(entry_live), 'position': pos})
                return out
        out.update({'ok': False, 'reason': 'unable_to_move_liq_beyond_sl', 'position': last_pos})
        return out
    except Exception as exc:
        out.update({'ok': False, 'reason': f'{type(exc).__name__}: {exc}'})
        return out

def _bybit_get_instr_filters(symbol: str) -> dict:
    """Return best-effort Bybit linear instrument filters.

    Keys returned as strings when available:
    - minQty
    - qtyStep
    - minNotional
    - contractSize
    - tickSize
    """
    sym = _bybit_linear_symbol(symbol)
    if sym in _INSTR_FILTER_CACHE:
        return _INSTR_FILTER_CACHE[sym]
    out = {"minQty": None, "qtyStep": None, "minNotional": None, "contractSize": None, "tickSize": None}
    try:
        res = _bybit_v5_request("GET", "/v5/market/instruments-info", {"category": "linear", "symbol": sym})
        items = (((res or {}).get("result") or {}).get("list") or [])
        if items:
            info = items[0] or {}
            lot = info.get("lotSizeFilter") or {}
            price_filter = info.get("priceFilter") or {}

            if lot.get("minOrderQty") is not None:
                out["minQty"] = str(lot.get("minOrderQty"))
            if lot.get("qtyStep") is not None:
                out["qtyStep"] = str(lot.get("qtyStep"))
            # Current Bybit V5 field for linear min notional is lotSizeFilter.minNotionalValue
            min_notional = lot.get("minNotionalValue")
            if min_notional is None:
                nf = info.get("notionalFilter") or {}
                min_notional = nf.get("minNotional")
            if min_notional is not None:
                out["minNotional"] = str(min_notional)
            if info.get('contractSize') is not None:
                out['contractSize'] = str(info.get('contractSize'))
            if price_filter.get('tickSize') is not None:
                out['tickSize'] = str(price_filter.get('tickSize'))
    except Exception:
        pass
    _INSTR_FILTER_CACHE[sym] = out
    return out



def _fmt_qty(qty: float, step) -> str:
    """Format qty as Bybit-safe decimal string aligned to qtyStep.

    Safety rule (critical): never round UP quantities, because that can increase
    the true $ risk beyond the intended risk-per-trade. We therefore round DOWN
    to the nearest qtyStep multiple.
    """
    try:
        if qty is None:
            return "0"
        dqty = Decimal(str(qty))

        if step is None:
            return format(dqty, "f")

        dstep = Decimal(str(step))
        if dstep <= 0:
            return format(dqty, "f")

        mult = (dqty / dstep).to_integral_value(rounding=ROUND_DOWN)
        dq = (mult * dstep).quantize(dstep)  # keeps correct decimals
        if dq <= 0:
            return "0"
        return format(dq, "f")
    except Exception:
        try:
            return format(Decimal(str(qty)), "f")
        except Exception:
            return str(qty)


def _round_qty_down(symbol: str, qty: float, entry_price: float) -> tuple[float | None, str | None]:
    """Decimal-safe rounding DOWN to Bybit qtyStep and safety-checking minQty/minNotional.

    CRITICAL SAFETY:
    - We never round UP qty to satisfy minNotional/minQty because that can increase
      the true $ risk beyond the user's /riskmode.
    - If, after rounding DOWN, qty does not meet exchange minimums, we SKIP the trade.
    """
    try:
        if qty is None or float(qty) <= 0:
            return (None, "qty<=0")

        f = _bybit_get_instr_filters(symbol)
        step_s = f.get("qtyStep")
        min_qty_s = f.get("minQty")
        min_not_s = f.get("minNotional")
        cs_s = f.get("contractSize")

        dqty = Decimal(str(qty))
        dentry = Decimal(str(entry_price)) if entry_price and entry_price > 0 else None

        def _d(x):
            if x is None:
                return None
            try:
                return Decimal(str(x))
            except Exception:
                return None

        dstep = _d(step_s)
        dmin = _d(min_qty_s)
        dmin_not = _d(min_not_s)
        dcs = _d(cs_s) or Decimal('1')

        # Round DOWN to step
        if dstep and dstep > 0:
            mult = (dqty / dstep).to_integral_value(rounding=ROUND_DOWN)
            dqty = (mult * dstep).quantize(dstep)

        if dqty <= 0:
            return (None, "qty_rounds_to_0")

        # Enforce minQty without rounding up
        if dmin and dqty < dmin:
            return (None, "below_minQty_after_round_down")

        # Enforce minNotional without rounding up
        if dmin_not and dentry and dentry > 0:
            notional = dqty * dentry * dcs
            if notional < dmin_not:
                return (None, "below_minNotional_after_round_down")

        return (float(dqty), None)

    except Exception as e:
        return (None, f"qty_round_fail:{type(e).__name__}")




def _round_price_to_tick(symbol: str, price: float, rounding=ROUND_DOWN) -> float:
    """Round a price to Bybit tick size. Best-effort only."""
    try:
        if price is None:
            return 0.0
        f = _bybit_get_instr_filters(symbol)
        tick_s = f.get("tickSize")
        if not tick_s:
            return float(price)
        dprice = Decimal(str(price))
        dtick = Decimal(str(tick_s))
        if dtick <= 0:
            return float(price)
        mult = (dprice / dtick).to_integral_value(rounding=rounding)
        out = (mult * dtick).quantize(dtick)
        return float(out)
    except Exception:
        try:
            return float(price)
        except Exception:
            return 0.0


def _effective_equity_for_risk(user: dict | None = None, prefer_live: bool = True) -> float:
    """Single source of truth for risk-based equity.

    LIVE mode prefers Bybit-reported equity; otherwise falls back to user-stored equity.
    """
    eq = 0.0
    try:
        if isinstance(user, dict):
            eq = float(user.get("equity", 0.0) or 0.0)
    except Exception:
        eq = 0.0
    if prefer_live:
        try:
            live_eq = _live_equity_usdt_cached(ttl=FAST_ADMIN_SNAPSHOT_TTL_SEC)
            if live_eq is not None and float(live_eq) > 0:
                return float(live_eq)
        except Exception:
            pass
    return max(0.0, float(eq or 0.0))


def _risk_amount_from_pct(equity: float, risk_pct: float) -> float:
    try:
        if float(equity) <= 0:
            return 0.0
        return max(0.0, float(equity) * (float(risk_pct) / 100.0))
    except Exception:
        return 0.0


def _risk_pct_from_amount(equity: float, risk_usd: float) -> float:
    try:
        if float(equity) <= 0:
            return 0.0
        return max(0.0, (float(risk_usd) / float(equity)) * 100.0)
    except Exception:
        return 0.0


def _autotrade_live_reference_price(symbol: str, fallback_entry: float = 0.0) -> float:
    """Best-effort executable reference price for live sizing.

    We use a current market reference instead of a potentially stale setup entry so market-order
    sizing stays aligned with real stop distance.
    """
    sym = _bybit_linear_symbol(symbol)
    try:
        res = _bybit_v5_request("GET", "/v5/market/tickers", {"category": "linear", "symbol": sym})
        items = (((res or {}).get("result") or {}).get("list") or [])
        if items:
            t = items[0] or {}
            for k in ("markPrice", "lastPrice", "indexPrice"):
                try:
                    px = float(t.get(k) or 0.0)
                    if px > 0:
                        return px
                except Exception:
                    pass
    except Exception:
        pass

    try:
        best = get_cached_futures_tickers() or {}
        base = sym[:-4] if sym.endswith("USDT") else sym
        mv = best.get(base)
        if mv:
            px = float(getattr(mv, "last", 0.0) or 0.0)
            if px > 0:
                return px
    except Exception:
        pass
    try:
        return float(fallback_entry or 0.0)
    except Exception:
        return 0.0


def _autotrade_true_risk_usd(entry_price: float, stop_price: float, qty_contracts: float, contract_size: float = 1.0) -> float:
    try:
        return abs(float(entry_price) - float(stop_price)) * abs(float(qty_contracts)) * abs(float(contract_size or 1.0))
    except Exception:
        return 0.0



def _autotrade_live_position_risk_detail(p: dict) -> dict:
    '''Return current live position risk based on detected exchange SL.'''
    try:
        sym = _pos_symbol(p)
        side = _pos_side_text(p)
        entry = float(_pos_entry(p) or 0.0)
        sl = float(_pos_stop(p) or 0.0)
        qty = abs(float(_pos_size(p) or 0.0))
        try:
            cs = float((_bybit_get_instr_filters(sym) or {}).get('contractSize') or 1.0)
        except Exception:
            cs = 1.0
        risk = _autotrade_true_risk_usd(entry, sl, qty, cs) if entry > 0 and sl > 0 and qty > 0 else 0.0
        return {'symbol': sym, 'side': side, 'entry': entry, 'sl': sl, 'qty': qty, 'contract_size': cs, 'risk_usd': float(risk), 'leverage': float(_pos_leverage(p) or 0.0)}
    except Exception as exc:
        return {'risk_usd': 0.0, 'error': f'{type(exc).__name__}: {exc}'}


def _autotrade_reduce_live_position_to_risk_cap(symbol: str, side: str, risk_cap_usd: float, reason: str = 'risk_cap', live_pos: dict | None = None) -> dict:
    '''Reduce or close a live position until detected SL risk is within cap.'''
    out = {'ok': False, 'action': 'none', 'reason': str(reason or 'risk_cap'), 'cap_usd': float(risk_cap_usd or 0.0)}
    try:
        sym = _bybit_linear_symbol(symbol)
        side_u = str(side or '').upper().strip()
        p = live_pos or _autotrade_find_live_position(sym, side=side_u)
        if not p:
            out.update({'ok': True, 'action': 'no_position'})
            return out
        detail = _autotrade_live_position_risk_detail(p)
        out['before'] = detail
        risk_now = float(detail.get('risk_usd') or 0.0)
        cap = float(risk_cap_usd or 0.0)
        if cap <= 0 or risk_now <= cap * 1.0005:
            out.update({'ok': True, 'action': 'within_cap'})
            return out
        entry = float(detail.get('entry') or 0.0)
        sl = float(detail.get('sl') or 0.0)
        qty = float(detail.get('qty') or 0.0)
        cs = float(detail.get('contract_size') or 1.0)
        if entry <= 0 or sl <= 0 or qty <= 0:
            close_res = _autotrade_force_close_live_position(sym, side_u, qty=qty)
            out.update({'action': 'closed_missing_risk_inputs', 'close_res': close_res, 'ok': int((close_res or {}).get('retCode', -1)) == 0})
            return out
        allowed_qty = _autotrade_qty_from_risk(entry, sl, 0.0, risk_usd=cap, contract_size=cs)
        allowed_qty, allowed_reason = _round_qty_down(sym, allowed_qty, entry)
        reduce_qty = qty - float(allowed_qty or 0.0) if allowed_qty and allowed_qty > 0 else qty
        reduce_qty, reduce_reason = _round_qty_down(sym, reduce_qty, entry)
        if reduce_qty is None or reduce_qty <= 0:
            close_res = _autotrade_force_close_live_position(sym, side_u, qty=qty)
            out.update({'action': 'closed_unreducible', 'allowed_reason': allowed_reason, 'reduce_reason': reduce_reason, 'close_res': close_res, 'ok': int((close_res or {}).get('retCode', -1)) == 0})
            return out
        payload = {
            'category': 'linear',
            'symbol': sym,
            'side': 'Sell' if side_u == 'BUY' else 'Buy',
            'orderType': 'Market',
            'qty': _fmt_qty(float(reduce_qty), (_bybit_get_instr_filters(sym) or {}).get('qtyStep')),
            'timeInForce': 'IOC',
            'reduceOnly': True,
            'closeOnTrigger': True,
        }
        res = _bybit_v5_request('POST', '/v5/order/create', payload)
        out.update({'action': 'reduced', 'reduce_qty': float(reduce_qty), 'payload': payload, 'res': res, 'ok': int((res or {}).get('retCode', -1)) == 0})
        p2 = _autotrade_wait_live_position(sym, side=side_u, wait_sec=3.0, step_sec=0.25) or _autotrade_find_live_position(sym, side=side_u)
        if p2:
            out['after'] = _autotrade_live_position_risk_detail(p2)
            if float((out.get('after') or {}).get('risk_usd') or 0.0) > cap * 1.05:
                close_res = _autotrade_force_close_live_position(sym, side_u, qty=float(_pos_size(p2) or 0.0))
                out.update({'action': 'closed_after_reduce_still_over_cap', 'close_res': close_res, 'ok': int((close_res or {}).get('retCode', -1)) == 0})
        return out
    except Exception as exc:
        out.update({'ok': False, 'action': 'error', 'error': f'{type(exc).__name__}: {exc}'})
        return out


def _autotrade_find_live_position(symbol: str, side: str | None = None) -> dict | None:
    sym = _bybit_linear_symbol(symbol)
    side_u = str(side or "").upper().strip()
    try:
        for p in _bybit_get_open_positions_linear():
            psym = _pos_symbol(p)
            if psym != sym:
                continue
            if side_u:
                pside = _pos_side_text(p)
                if pside != side_u:
                    continue
            return p
    except Exception:
        return None
    return None
def _autotrade_ready() -> bool:
    # Infrastructure readiness. New-entry ON/OFF is checked separately by
    # _autotrade_entry_enabled() so guardian/report/flat controls still work.
    if not AUTOTRADE_ENABLED:
        return False
    if AUTOTRADE_OWNER_UID <= 0:
        return False
    mode = str(_autotrade_runtime_mode()).lower()
    if mode not in ("paper", "live"):
        return False
    if mode == "live" and (not BYBIT_API_KEY or not BYBIT_API_SECRET):
        return False
    return True

def _bybit_get_equity_usdt() -> float:
    """Returns account equity (USDT) from Bybit V5 wallet-balance.

    Tries common account types (UNIFIED, CONTRACT) and returns the first positive equity found.
    """
    def _extract_equity(res: dict) -> float:
        try:
            if int(res.get("retCode", -1)) != 0:
                return 0.0
            lst = ((res.get("result") or {}).get("list") or [])
            if not lst:
                return 0.0
            # V5 response: result.list[].coin[] contains entries like {"coin":"USDT","equity":"..."}
            coins = ((lst[0] or {}).get("coin") or [])
            usdt = None
            for c in coins:
                if str((c or {}).get("coin", "")).upper() == "USDT":
                    usdt = c or {}
                    break
            if not usdt and coins:
                usdt = coins[0] or {}
            eq = float(usdt.get("equity") or usdt.get("walletBalance") or usdt.get("availableToWithdraw") or 0.0)
            return max(0.0, eq)
        except Exception:
            return 0.0

    for acct in ("UNIFIED", "CONTRACT"):
        res = _bybit_v5_request("GET", f"/v5/account/wallet-balance?accountType={acct}&coin=USDT")
        eq = _extract_equity(res)
        if eq > 0:
            return eq
    return 0.0


def _live_equity_usdt() -> float | None:
    """LIVE mode equity source. Returns None if unavailable.

    Uses Bybit V5 wallet-balance (UNIFIED, USDT) and falls back to None on failure.
    """
    try:
        if not AUTOTRADE_ENABLED:
            return None
        if str(_autotrade_runtime_mode()).lower() != "live":
            return None
        if not BYBIT_API_KEY or not BYBIT_API_SECRET:
            return None
        eq = float(_bybit_get_equity_usdt() or 0.0)
        return eq if eq > 0 else None
    except Exception:
        return None


def _live_equity_usdt_cached(ttl: int | None = None, force_refresh: bool = False) -> float | None:
    """Short cache for live equity so fast admin commands do not hit Bybit every time."""
    try:
        cache_key = 'live_equity_usdt'
        ttl_i = max(2, int(ttl if ttl is not None else FAST_ADMIN_SNAPSHOT_TTL_SEC))
        if (not force_refresh) and cache_valid(cache_key, ttl_i):
            val = cache_get(cache_key)
            if val is None:
                return None
            try:
                return float(val)
            except Exception:
                return None
        eq = _live_equity_usdt()
        if eq is not None and float(eq) > 0:
            cache_set(cache_key, float(eq))
            return float(eq)
        stale = cache_get(cache_key)
        if stale is None:
            return None
        return float(stale)
    except Exception:
        try:
            stale = cache_get('live_equity_usdt')
            return float(stale) if stale is not None else None
        except Exception:
            return None



def _tz_melbourne():
    try:
        return ZoneInfo("Australia/Melbourne")
    except Exception:
        return timezone.utc

MEL_TZ = _tz_melbourne()

def _parse_iso_utcish(iso_s: str) -> Optional[datetime]:
    """Parse ISO text and treat naive timestamps as UTC."""
    if not iso_s:
        return None
    try:
        dt = datetime.fromisoformat(str(iso_s).replace("Z", "+00:00"))
        if dt.tzinfo is None:
            dt = dt.replace(tzinfo=timezone.utc)
        return dt
    except Exception:
        return None


def _dt_local(dt: datetime) -> datetime:
    try:
        if getattr(dt, "tzinfo", None) is None:
            dt = dt.replace(tzinfo=timezone.utc)
        return dt.astimezone(_tz_melbourne())
    except Exception:
        return dt


def _fmt_dt_local(dt: datetime, fmt: str = "%Y-%m-%d %H:%M:%S") -> str:
    try:
        return _dt_local(dt).strftime(fmt)
    except Exception:
        try:
            return dt.isoformat(timespec="seconds")
        except Exception:
            return str(dt)


def _fmt_iso_to_local(iso_s: str) -> str:
    """Convert ISO string (UTC or with tz) to Melbourne local display."""
    if not iso_s:
        return ""
    dt = _parse_iso_utcish(str(iso_s))
    if dt is None:
        return str(iso_s)
    return _fmt_dt_local(dt)

def _ms_to_local_str(ms: int | str | None) -> str:
    try:
        if ms is None:
            return ""
        ms_i = int(float(ms))
        dt = datetime.fromtimestamp(ms_i/1000.0, tz=timezone.utc)
        return _fmt_dt_local(dt)
    except Exception:
        return ""

def _bybit_get_open_positions_linear() -> list[dict]:
    """Return cached open linear USDT positions (Bybit V5).

    Short cache keeps status/report/autotrade commands responsive and avoids repeated
    position-list hits within the same second burst.
    """
    cache_key = 'bybit_open_positions_linear'
    try:
        ttl = max(1, int(BYBIT_OPEN_POSITIONS_CACHE_TTL_SEC or 6))
        if cache_valid(cache_key, ttl):
            cached = cache_get(cache_key)
            return list(cached or []) if isinstance(cached, list) else []
    except Exception:
        pass
    try:
        if not BYBIT_API_KEY or not BYBIT_API_SECRET:
            return []
        res = _bybit_v5_request("GET", "/v5/position/list", {
            "category": "linear",
            "settleCoin": "USDT",
            "limit": 200,
        })
        if int(res.get("retCode", -1)) != 0:
            return []
        lst = ((res.get("result") or {}).get("list") or [])
        out = []
        for p in lst:
            try:
                size = float(p.get("size") or 0.0)
            except Exception:
                size = 0.0
            if size == 0:
                continue
            out.append(p)
        try:
            cache_set(cache_key, list(out))
        except Exception:
            pass
        return out
    except Exception:
        stale = cache_get(cache_key)
        return list(stale or []) if isinstance(stale, list) else []

def _norm_trade_side(side: str) -> str:
    try:
        s = str(side or '').strip().upper()
        if s in ('BUY', 'LONG'):
            return 'BUY'
        if s in ('SELL', 'SHORT'):
            return 'SELL'
        return s
    except Exception:
        return ''

def _pos_side_text(p: dict) -> str:
    try:
        s = str(p.get("side") or "").upper()
        return "BUY" if s == "BUY" else "SELL" if s == "SELL" else s
    except Exception:
        return ""

def _pos_symbol(p: dict) -> str:
    try:
        return _bybit_linear_symbol(str(p.get("symbol") or ""))
    except Exception:
        return str(p.get("symbol") or "")

def _pos_unreal_pnl(p: dict) -> float:
    try:
        return float(p.get("unrealisedPnl") or p.get("unrealizedPnl") or 0.0)
    except Exception:
        return 0.0

def _pos_mark(p: dict) -> float:
    try:
        return float(p.get("markPrice") or 0.0)
    except Exception:
        return 0.0

def _pos_entry(p: dict) -> float:
    try:
        return float(p.get("avgPrice") or p.get("entryPrice") or 0.0)
    except Exception:
        return 0.0

def _pos_liq_price(p: dict) -> float:
    try:
        return float(p.get("liqPrice") or p.get("liquidationPrice") or 0.0)
    except Exception:
        return 0.0


def _pos_leverage(p: dict) -> float:
    try:
        return float((p or {}).get('leverage') or (p or {}).get('positionLeverage') or 0.0)
    except Exception:
        return 0.0

def _bybit_exit_close_side_for_position_side(side: str | None) -> str:
    try:
        s = str(side or '').upper().strip()
        if s == 'BUY':
            return 'SELL'
        if s == 'SELL':
            return 'BUY'
    except Exception:
        pass
    return ''


def _bybit_order_close_side(order: dict) -> str:
    """Best-effort close-side for Bybit exit orders.

    For TP/SL orders Bybit may not always expose a normal side field consistently,
    so we also infer from text like 'close short' / 'close long'.
    Returned value is the exchange order side that would close the position: BUY or SELL.
    """
    try:
        s = str((order or {}).get('side') or '').upper().strip()
        if s in {'BUY', 'SELL'}:
            return s
    except Exception:
        pass
    try:
        txt = _bybit_order_kind_text(order)
        if 'close short' in txt:
            return 'BUY'
        if 'close long' in txt:
            return 'SELL'
    except Exception:
        pass
    return ''


def _bybit_order_matches_close_side(order: dict, want_close_side: str | None = None) -> bool:
    try:
        want = str(want_close_side or '').upper().strip()
        if not want:
            return True
        got = _bybit_order_close_side(order)
        if not got:
            # Do not reject an otherwise valid TP/SL order just because Bybit omitted side.
            return True
        return got == want
    except Exception:
        return False


def _bybit_detect_open_sl_price(symbol: str, side: str | None = None) -> float:
    """Detect the effective SL price from active exchange TP/SL orders.

    This is needed because Bybit partial TP/SL pairs do not always populate the
    position-level stopLoss field, even though the SL is real and active.
    """
    sym = _bybit_linear_symbol(symbol)
    if not sym:
        return 0.0
    want_close_side = _bybit_exit_close_side_for_position_side(side)
    buckets: list[dict] = []
    try:
        for o in (_bybit_get_open_orders_linear(sym) or []):
            try:
                if _bybit_linear_symbol(str((o or {}).get('symbol') or '')) != sym:
                    continue
                if not _bybit_order_matches_close_side(o, want_close_side):
                    continue
                if not _bybit_is_sl_exit_order(o):
                    continue
                px = float(_bybit_order_sl_price(o) or _bybit_order_working_price(o) or 0.0)
                if px <= 0:
                    continue
                qty = abs(float(_bybit_order_filled_qty(o) or 0.0))
                if qty <= 0:
                    qty = 1.0
                matched = False
                for b in buckets:
                    if _price_close_enough(float(b.get('price') or 0.0), px, rel_tol=0.0010):
                        b['qty'] = float(b.get('qty') or 0.0) + qty
                        b['count'] = int(b.get('count') or 0) + 1
                        matched = True
                        break
                if not matched:
                    buckets.append({'price': float(px), 'qty': float(qty), 'count': 1})
            except Exception:
                continue
    except Exception:
        return 0.0
    if not buckets:
        return 0.0
    buckets.sort(key=lambda x: (float(x.get('qty') or 0.0), int(x.get('count') or 0), float(x.get('price') or 0.0)), reverse=True)
    try:
        return float((buckets[0] or {}).get('price') or 0.0)
    except Exception:
        return 0.0


def _pos_stop(p: dict) -> float:
    try:
        raw = float(p.get("stopLoss") or 0.0)
        if raw > 0:
            return raw
    except Exception:
        pass
    try:
        return float(_bybit_detect_open_sl_price(_pos_symbol(p), _pos_side_text(p)) or 0.0)
    except Exception:
        return 0.0

def _pos_size(p: dict) -> float:
    try:
        return float(p.get("size") or 0.0)
    except Exception:
        return 0.0

def _estimate_position_risk_usd(p: dict) -> float:
    """Estimate exchange risk using live entry, detected SL and instrument size."""
    try:
        entry = _pos_entry(p)
        sl = _pos_stop(p)
        size = abs(_pos_size(p))
        if entry <= 0 or sl <= 0 or size <= 0:
            return 0.0
        try:
            cs = float((_bybit_get_instr_filters(_pos_symbol(p)) or {}).get('contractSize') or 1.0)
        except Exception:
            cs = 1.0
        return _autotrade_true_risk_usd(entry, sl, size, cs)
    except Exception:
        return 0.0


def _estimate_position_tp_usd(p: dict) -> float:
    """Estimate full-position TP reward using live entry, native TP and instrument size."""
    try:
        entry = _pos_entry(p)
        tp = _pos_take_profit(p)
        size = abs(_pos_size(p))
        if entry <= 0 or tp <= 0 or size <= 0:
            return 0.0
        try:
            cs = float((_bybit_get_instr_filters(_pos_symbol(p)) or {}).get('contractSize') or 1.0)
        except Exception:
            cs = 1.0
        return abs(float(tp) - float(entry)) * float(size) * abs(float(cs or 1.0))
    except Exception:
        return 0.0

def _pos_take_profit(p: dict) -> float:
    try:
        return float(p.get("takeProfit") or 0.0)
    except Exception:
        return 0.0


def _pos_native_stop_loss(p: dict) -> float:
    """Position-level Bybit stopLoss only; does not accept standalone Conditional SL orders."""
    try:
        return float((p or {}).get("stopLoss") or 0.0)
    except Exception:
        return 0.0


def _pos_native_take_profit(p: dict) -> float:
    """Position-level Bybit takeProfit only; does not accept standalone Conditional TP orders."""
    try:
        return float((p or {}).get("takeProfit") or 0.0)
    except Exception:
        return 0.0


def _price_close_enough(a: float, b: float, rel_tol: float = 0.002, abs_tol: float = 1e-8) -> bool:
    try:
        a = float(a or 0.0)
        b = float(b or 0.0)
        if a <= 0 or b <= 0:
            return False
        return abs(a - b) <= max(abs_tol, max(abs(a), abs(b)) * float(rel_tol))
    except Exception:
        return False


def _dedupe_price_targets(values: list[float], rel_tol: float = 0.0005) -> list[float]:
    """Return ordered positive targets with near-duplicates removed."""
    out: list[float] = []
    try:
        for raw in (values or []):
            try:
                px = float(raw or 0.0)
            except Exception:
                px = 0.0
            if px <= 0:
                continue
            if any(_price_close_enough(px, seen, rel_tol=rel_tol) for seen in out):
                continue
            out.append(float(px))
    except Exception:
        return [float(x) for x in (values or []) if float(x or 0.0) > 0]
    return out


def _be_min_quality_for_session(session_name: str) -> float:
    sess = str(session_name or '').upper().strip()
    if sess == 'NY':
        return max(float(AUTOTRADE_BE_AFTER_TP_MIN_QUALITY), 80.0)
    if sess == 'LON':
        return max(float(AUTOTRADE_BE_AFTER_TP_MIN_QUALITY), 76.0)
    if sess == 'ASIA':
        return max(float(AUTOTRADE_BE_AFTER_TP_MIN_QUALITY), 82.0)
    return float(AUTOTRADE_BE_AFTER_TP_MIN_QUALITY)


def _backtest_should_move_sl_to_be_after_tp(setup: "Setup", session_name: str) -> bool:
    """Single-TP model: no break-even step is used."""
    return False

def _autotrade_live_exit_plan_from_targets(entry: float, sl: float, tp, alt_target_a, alt_target_b, side: str) -> dict:
    tp = _resolve_single_tp(entry, sl, tp=tp, alt_target_a=alt_target_a, alt_target_b=alt_target_b, side=side)
    return {
        'partial_tp': 0.0,
        'final_tp': float(tp or 0.0),
        'partial_fraction': 1.0,
        'effective_tp': float(tp or 0.0),
        'effective_alt_target_a': 0.0,
        'effective_alt_target_b': 0.0,
    }


def _autotrade_live_exit_plan_for_trade(trade_or_setup) -> dict:
    return _autotrade_live_exit_plan_from_targets(
        float(getattr(trade_or_setup, 'entry', 0.0) if hasattr(trade_or_setup, 'entry') else (trade_or_setup.get('entry') if isinstance(trade_or_setup, dict) else 0.0) or 0.0),
        float(getattr(trade_or_setup, 'sl', 0.0) if hasattr(trade_or_setup, 'sl') else (trade_or_setup.get('sl') if isinstance(trade_or_setup, dict) else 0.0) or 0.0),
        getattr(trade_or_setup, 'tp', None) if hasattr(trade_or_setup, 'tp') else (trade_or_setup.get('tp') if isinstance(trade_or_setup, dict) else None),
        getattr(trade_or_setup, 'alt_target_a', None) if hasattr(trade_or_setup, 'alt_target_a') else (trade_or_setup.get('alt_target_a') if isinstance(trade_or_setup, dict) else None),
        getattr(trade_or_setup, 'alt_target_b', None) if hasattr(trade_or_setup, 'alt_target_b') else (trade_or_setup.get('alt_target_b') if isinstance(trade_or_setup, dict) else None),
        getattr(trade_or_setup, 'side', '') if hasattr(trade_or_setup, 'side') else (trade_or_setup.get('side') if isinstance(trade_or_setup, dict) else ''),
    )


def _bybit_order_active(order: dict) -> bool:
    try:
        status = str(order.get('orderStatus') or '').upper().strip()
        return status not in {'FILLED', 'CANCELLED', 'REJECTED', 'DEACTIVATED'}
    except Exception:
        return False


def _bybit_order_working_price(order: dict) -> float:
    try:
        for key in ('triggerPrice', 'trigger_price', 'stopOrderPrice', 'stop_order_price', 'price'):
            v = float(order.get(key) or 0.0)
            if v > 0:
                return v
    except Exception:
        pass
    return 0.0


def _bybit_order_tp_price(order: dict) -> float:
    try:
        for key in ('takeProfit', 'take_profit', 'tpTriggerPrice', 'tp_trigger_price', 'tpLimitPrice', 'tp_limit_price', 'tpPrice', 'tp_price'):
            v = float((order or {}).get(key) or 0.0)
            if v > 0:
                return v
    except Exception:
        pass
    try:
        txt = _bybit_order_kind_text(order)
        if 'takeprofit' in txt or 'partialtakeprofit' in txt or 'pf_tp' in txt:
            v = float(_bybit_order_working_price(order) or 0.0)
            if v > 0:
                return v
    except Exception:
        pass
    return 0.0


def _bybit_order_sl_price(order: dict) -> float:
    try:
        for key in ('stopLoss', 'stop_loss', 'slTriggerPrice', 'sl_trigger_price', 'slLimitPrice', 'sl_limit_price', 'slPrice', 'sl_price'):
            v = float((order or {}).get(key) or 0.0)
            if v > 0:
                return v
    except Exception:
        pass
    try:
        txt = _bybit_order_kind_text(order)
        if 'stoploss' in txt or 'pf_sl' in txt:
            v = float(_bybit_order_working_price(order) or 0.0)
            if v > 0:
                return v
    except Exception:
        pass
    return 0.0

def _bybit_order_kind_text(order: dict) -> str:
    try:
        bits = [
            str(order.get('orderType') or ''),
            str(order.get('stopOrderType') or ''),
            str(order.get('stop_order_type') or ''),
            str(order.get('createType') or ''),
            str(order.get('create_type') or ''),
            str(order.get('orderLinkId') or ''),
        ]
        return ' '.join([b for b in bits if b]).lower()
    except Exception:
        return ''


def _bybit_is_tp_exit_order(order: dict) -> bool:
    try:
        if not _bybit_order_active(order):
            return False
        if not _bybit_order_reduce_only(order):
            return False
        if float(_bybit_order_tp_price(order) or 0.0) > 0:
            return True
        txt = _bybit_order_kind_text(order)
        if 'stoploss' in txt and 'takeprofit' not in txt and 'partialtakeprofit' not in txt:
            return False
        if 'partialtakeprofit' in txt or 'takeprofit' in txt or 'pf_tp' in txt:
            return True
        order_type = str(order.get('orderType') or '').upper().strip()
        trig = float(order.get('triggerPrice') or order.get('trigger_price') or 0.0)
        if order_type == 'MARKET' and trig > 0:
            return True
        if order_type == 'LIMIT':
            return True
    except Exception:
        pass
    return False


def _bybit_is_sl_exit_order(order: dict) -> bool:
    try:
        if not _bybit_order_active(order):
            return False
        if not _bybit_order_reduce_only(order):
            return False
        if float(_bybit_order_sl_price(order) or 0.0) > 0:
            return True
        txt = _bybit_order_kind_text(order)
        if 'partialtakeprofit' in txt or 'takeprofit' in txt or 'pf_tp' in txt:
            return False
        if 'stoploss' in txt or 'pf_sl' in txt:
            return True
        trig = float(order.get('triggerPrice') or order.get('trigger_price') or 0.0)
        order_type = str(order.get('orderType') or '').upper().strip()
        return bool(order_type == 'MARKET' and trig > 0)
    except Exception:
        return False


def _bybit_has_matching_tp_exit(symbol: str, close_side: str, tp_price: float) -> bool:
    sym = _bybit_linear_symbol(symbol)
    want_side = str(close_side or '').upper().strip()
    for o in _bybit_get_open_orders_linear(sym):
        try:
            if _bybit_linear_symbol(str(o.get('symbol') or '')) != sym:
                continue
            if not _bybit_order_matches_close_side(o, want_side):
                continue
            if not _bybit_is_tp_exit_order(o):
                continue
            px = float(_bybit_order_tp_price(o) or _bybit_order_working_price(o) or 0.0)
            if _price_close_enough(px, tp_price, rel_tol=0.0010):
                return True
        except Exception:
            continue
    return False


def _bybit_has_open_tp_order_at(symbol: str, tp_price: float, side: str | None = None) -> bool:
    sym = _bybit_linear_symbol(symbol)
    side_u = str(side or '').upper().strip()
    close_side = ''
    if side_u == 'BUY':
        close_side = 'SELL'
    elif side_u == 'SELL':
        close_side = 'BUY'
    return _bybit_has_matching_tp_exit(sym, close_side, float(tp_price or 0.0))


def _bybit_has_matching_sl_exit(symbol: str, close_side: str, sl_price: float) -> bool:
    sym = _bybit_linear_symbol(symbol)
    want_side = str(close_side or '').upper().strip()
    for o in _bybit_get_open_orders_linear(sym):
        try:
            if _bybit_linear_symbol(str(o.get('symbol') or '')) != sym:
                continue
            if not _bybit_order_matches_close_side(o, want_side):
                continue
            if not _bybit_is_sl_exit_order(o):
                continue
            px = float(_bybit_order_sl_price(o) or _bybit_order_working_price(o) or 0.0)
            if _price_close_enough(px, sl_price, rel_tol=0.0010):
                return True
        except Exception:
            continue
    return False


def _bybit_has_open_sl_order_at(symbol: str, sl_price: float, side: str | None = None) -> bool:
    sym = _bybit_linear_symbol(symbol)
    side_u = str(side or '').upper().strip()
    close_side = ''
    if side_u == 'BUY':
        close_side = 'SELL'
    elif side_u == 'SELL':
        close_side = 'BUY'
    return _bybit_has_matching_sl_exit(sym, close_side, float(sl_price or 0.0))


def _bybit_sum_open_exit_qty_at(symbol: str, trigger_price: float, side: str | None = None, kind: str = 'tp') -> float:
    sym = _bybit_linear_symbol(symbol)
    side_u = str(side or '').upper().strip()
    close_side = ''
    if side_u == 'BUY':
        close_side = 'SELL'
    elif side_u == 'SELL':
        close_side = 'BUY'
    want_kind = str(kind or 'tp').lower().strip()
    total = 0.0
    for o in _bybit_get_open_orders_linear(sym):
        try:
            if _bybit_linear_symbol(str(o.get('symbol') or '')) != sym:
                continue
            if not _bybit_order_matches_close_side(o, close_side):
                continue
            is_match = _bybit_is_sl_exit_order(o) if want_kind == 'sl' else _bybit_is_tp_exit_order(o)
            if not is_match:
                continue
            px = float((_bybit_order_sl_price(o) if want_kind == 'sl' else _bybit_order_tp_price(o)) or _bybit_order_working_price(o) or 0.0)
            if not _price_close_enough(px, float(trigger_price or 0.0), rel_tol=0.0010):
                continue
            total += abs(float(_bybit_order_filled_qty(o) or 0.0))
        except Exception:
            continue
    return float(total)


def _autotrade_min_child_exit_qty(symbol: str, trigger_price: float) -> float:
    """Minimum child-order quantity needed for one TP slice on Bybit."""
    try:
        sym = _bybit_linear_symbol(symbol)
        filt = _bybit_get_instr_filters(sym)
        step_s = filt.get('qtyStep')
        min_qty_s = filt.get('minQty')
        min_not_s = filt.get('minNotional')
        cs_s = filt.get('contractSize')

        dstep = Decimal(str(step_s)) if step_s not in (None, '', 0, '0') else Decimal('0.00000001')
        if dstep <= 0:
            dstep = Decimal('0.00000001')
        dmin_qty = Decimal(str(min_qty_s)) if min_qty_s not in (None, '', 0, '0') else Decimal('0')
        dmin_not = Decimal(str(min_not_s)) if min_not_s not in (None, '', 0, '0') else Decimal('0')
        dcs = Decimal(str(cs_s)) if cs_s not in (None, '', 0, '0') else Decimal('1')
        dpx = Decimal(str(trigger_price)) if float(trigger_price or 0.0) > 0 else Decimal('0')

        need = dmin_qty
        if dmin_not > 0 and dpx > 0 and dcs > 0:
            need = max(need, (dmin_not / (dpx * dcs)))
        if need <= 0:
            need = dstep
        steps = (need / dstep).to_integral_value(rounding=ROUND_UP)
        return float((steps * dstep).quantize(dstep))
    except Exception:
        return 0.0


def _autotrade_build_tp_order_slices(symbol: str, tp_targets: list[float], base_qty: float, tp_fraction: float | None = None) -> list[dict]:
    """Build TP slices that satisfy Bybit qtyStep/minQty/minNotional constraints."""
    out: list[dict] = []
    try:
        sym = _bybit_linear_symbol(symbol)
        tp_targets = _dedupe_price_targets([float(x or 0.0) for x in (tp_targets or [])])
        total_qty = float(base_qty or 0.0)
        if not tp_targets or total_qty <= 0:
            return []

        if len(tp_targets) == 1:
            qty_i, qreason = _round_qty_down(sym, total_qty, tp_targets[0])
            if not qty_i or qty_i <= 0:
                return [{'idx': 1, 'tp': float(tp_targets[0]), 'qty': 0.0, 'ok': False, 'reason': str(qreason or 'qty_invalid')}]
            return [{'idx': 1, 'tp': float(tp_targets[0]), 'qty': float(qty_i), 'ok': True, 'reason': ''}]

        tp_targets = list(tp_targets[:2])
        filt = _bybit_get_instr_filters(sym)
        step_s = filt.get('qtyStep')
        dstep = Decimal(str(step_s)) if step_s not in (None, '', 0, '0') else Decimal('0.00000001')
        if dstep <= 0:
            dstep = Decimal('0.00000001')
        dtotal_steps = (Decimal(str(total_qty)) / dstep).to_integral_value(rounding=ROUND_DOWN)
        if dtotal_steps <= 0:
            return [{'idx': 0, 'tp': 0.0, 'qty': 0.0, 'ok': False, 'reason': 'qty_rounds_to_0'}]

        min1 = Decimal(str(_autotrade_min_child_exit_qty(sym, tp_targets[0]) or 0.0))
        min2 = Decimal(str(_autotrade_min_child_exit_qty(sym, tp_targets[1]) or 0.0))
        min1_steps = (min1 / dstep).to_integral_value(rounding=ROUND_UP) if min1 > 0 else Decimal('1')
        min2_steps = (min2 / dstep).to_integral_value(rounding=ROUND_UP) if min2 > 0 else Decimal('1')

        if dtotal_steps < (min1_steps + min2_steps):
            short_qty = float(((min1_steps + min2_steps - dtotal_steps) * dstep).quantize(dstep))
            return [
                {'idx': 1, 'tp': float(tp_targets[0]), 'qty': 0.0, 'ok': False, 'reason': f'tp_child_qty_below_exchange_min(shortfall={short_qty:g})'},
                {'idx': 2, 'tp': float(tp_targets[1]), 'qty': 0.0, 'ok': False, 'reason': f'tp_child_qty_below_exchange_min(shortfall={short_qty:g})'},
            ]

        first = float(tp_fraction if tp_fraction is not None else AUTOTRADE_LIVE_TP_FRACTION)
        first = max(0.10, min(0.90, first))
        want1_steps = (Decimal(str(total_qty * first)) / dstep).to_integral_value(rounding=ROUND_DOWN)
        alloc1_steps = max(min1_steps, min(want1_steps, dtotal_steps - min2_steps))
        alloc2_steps = dtotal_steps - alloc1_steps

        q1 = float((alloc1_steps * dstep).quantize(dstep))
        q2 = float((alloc2_steps * dstep).quantize(dstep))
        q1, r1 = _round_qty_down(sym, q1, tp_targets[0])
        q2, r2 = _round_qty_down(sym, q2, tp_targets[1])
        if not q1 or q1 <= 0 or not q2 or q2 <= 0:
            return [
                {'idx': 1, 'tp': float(tp_targets[0]), 'qty': float(q1 or 0.0), 'ok': bool(q1 and q1 > 0), 'reason': str(r1 or 'qty_invalid')},
                {'idx': 2, 'tp': float(tp_targets[1]), 'qty': float(q2 or 0.0), 'ok': bool(q2 and q2 > 0), 'reason': str(r2 or 'qty_invalid')},
            ]

        return [
            {'idx': 1, 'tp': float(tp_targets[0]), 'qty': float(q1), 'ok': True, 'reason': ''},
            {'idx': 2, 'tp': float(tp_targets[1]), 'qty': float(q2), 'ok': True, 'reason': ''},
        ]
    except Exception as e:
        return [{'idx': 0, 'tp': 0.0, 'qty': 0.0, 'ok': False, 'reason': f'{type(e).__name__}: {e}'}]


def _autotrade_place_reduce_only_tp_order_slice(symbol: str, side: str, idx: int, tp_price: float, qty_i: float) -> dict:
    """DISABLED for AutoTrade exit protection.

    Older builds used /v5/order/create reduce-only trigger orders for TP. Bybit shows
    those rows as standalone ``Conditional`` orders with TP/SL = --/--, which created
    the 14-orders-for-5-positions problem. AutoTrade exits must now be attached only
    through /v5/position/trading-stop in Full mode so every position has native
    position-level TP/SL protection.
    """
    try:
        sym = _bybit_linear_symbol(symbol)
        return {
            'idx': int(idx or 0),
            'tp': float(tp_price or 0.0),
            'qty': float(qty_i or 0.0),
            'ok': False,
            'retCode': 0,
            'retMsg': 'disabled_full_position_tpsl_only_no_conditional_orders',
            'symbol': sym,
            'placement': 'disabled_conditional_tp',
        }
    except Exception as e:
        return {'idx': int(idx or 0), 'tp': float(tp_price or 0.0), 'qty': float(qty_i or 0.0), 'ok': False, 'retMsg': f'{type(e).__name__}: {e}', 'placement': 'disabled_conditional_tp'}


def _autotrade_place_reduce_only_tp_orders(symbol: str, side: str, tp_targets: list[float], base_qty: float, tp_fraction: float | None = None) -> list[dict]:
    """Place exactly two native close-trigger TP orders, not book limit orders."""
    results = []
    try:
        slices = _autotrade_build_tp_order_slices(symbol, tp_targets, base_qty, tp_fraction=tp_fraction)
        for item in (slices or []):
            idx = int(item.get('idx') or 0)
            tp = float(item.get('tp') or 0.0)
            qty_i = float(item.get('qty') or 0.0)
            if not item.get('ok'):
                results.append({'idx': idx, 'tp': tp, 'qty': qty_i, 'ok': False, 'retMsg': str(item.get('reason') or 'qty_invalid')})
                continue
            results.append(_autotrade_place_reduce_only_tp_order_slice(symbol, side, idx, tp, qty_i))
        return results
    except Exception as e:
        return [{'idx': 0, 'tp': 0.0, 'qty': 0.0, 'ok': False, 'retMsg': f'{type(e).__name__}: {e}'}]


def _autotrade_confirm_tp_targets_present(symbol: str, side: str, tp_targets: list[float], wait_sec: float | None = None, step_sec: float | None = None) -> tuple[bool, list[float]]:
    want = _dedupe_price_targets([float(x or 0.0) for x in (tp_targets or []) if float(x or 0.0) > 0])
    if not want:
        return False, []
    deadline = time.time() + float(wait_sec if wait_sec is not None else AUTOTRADE_TP_CONFIRM_WAIT_SEC)
    step = max(0.10, float(step_sec if step_sec is not None else AUTOTRADE_TP_CONFIRM_STEP_SEC))
    missing = list(want)
    while True:
        try:
            missing = [px for px in want if not _bybit_has_open_tp_order_at(symbol, px, side=side)]
        except Exception:
            missing = list(want)
        if not missing:
            return True, []
        if time.time() >= deadline:
            return False, missing
        time.sleep(step)


def _autotrade_place_partial_tpsl_pair_slice(symbol: str, side: str, idx: int, tp_price: float, stop_loss: float, qty_i: float, live_pos: dict | None = None) -> dict:
    try:
        sym = _bybit_linear_symbol(symbol)
        side_u = str(side or '').upper().strip()
        if side_u not in {'BUY', 'SELL'}:
            return {'idx': int(idx or 0), 'tp': float(tp_price or 0.0), 'qty': float(qty_i or 0.0), 'ok': False, 'retMsg': 'bad_side', 'placement': 'partial_pair'}
        tp_px = _round_price_to_tick(sym, float(tp_price or 0.0), rounding=ROUND_HALF_UP)
        sl_px = _round_price_to_tick(sym, float(stop_loss or 0.0), rounding=ROUND_HALF_UP)
        if tp_px <= 0 or sl_px <= 0:
            return {'idx': int(idx or 0), 'tp': float(tp_price or 0.0), 'qty': float(qty_i or 0.0), 'ok': False, 'retMsg': 'bad_tp_or_sl', 'placement': 'partial_pair'}
        filt = _bybit_get_instr_filters(sym)
        qty_step = filt.get('qtyStep')
        best = {'retCode': -1, 'retMsg': 'partial_pair_not_attempted'}
        for pos_idx in _bybit_position_idx_candidates(side=side_u, live_pos=live_pos):
            payload = {
                'category': 'linear',
                'symbol': sym,
                'tpslMode': 'Partial',
                'positionIdx': int(pos_idx),
                'takeProfit': str(float(tp_px)),
                'stopLoss': str(float(sl_px)),
                'tpTriggerBy': str(AUTOTRADE_LIVE_TP_TRIGGER_BY),
                'slTriggerBy': str(AUTOTRADE_LIVE_TP_TRIGGER_BY),
                'tpOrderType': 'Market',
                'slOrderType': 'Market',
                'tpSize': _fmt_qty(float(qty_i or 0.0), qty_step),
                'slSize': _fmt_qty(float(qty_i or 0.0), qty_step),
            }
            res = _bybit_v5_request('POST', '/v5/position/trading-stop', payload)
            ok = int((res or {}).get('retCode', -1)) == 0
            if ok:
                return {
                    'idx': int(idx or 0),
                    'tp': float(tp_px),
                    'qty': float(qty_i or 0.0),
                    'ok': True,
                    'retCode': (res or {}).get('retCode'),
                    'retMsg': (res or {}).get('retMsg'),
                    'order_payload': payload,
                    'placement': 'partial_pair',
                    'positionIdx_used': int(pos_idx),
                }
            best = dict(res or {})
            try:
                best['positionIdx_used'] = int(pos_idx)
                best['request_payload'] = payload
            except Exception:
                pass
        return {
            'idx': int(idx or 0),
            'tp': float(tp_px),
            'qty': float(qty_i or 0.0),
            'ok': False,
            'retCode': best.get('retCode'),
            'retMsg': best.get('retMsg'),
            'order_payload': best.get('request_payload'),
            'placement': 'partial_pair',
            'positionIdx_used': best.get('positionIdx_used'),
        }
    except Exception as e:
        return {'idx': int(idx or 0), 'tp': float(tp_price or 0.0), 'qty': float(qty_i or 0.0), 'ok': False, 'retMsg': f'{type(e).__name__}: {e}', 'placement': 'partial_pair'}


def _autotrade_place_confirmed_tp_orders(symbol: str, side: str, tp_targets: list[float], base_qty: float, stop_loss: float, tp_fraction: float | None = None) -> list[dict]:
    """Single-TP live exit attach policy: Full-position TP/SL only.

    PulseFutures now keeps all live exits as Bybit position-level TP/SL rows.
    It must NOT create standalone reduce-only Conditional orders for AutoTrade exits,
    because those show as separate Conditional rows in Bybit and create confusing extra
    orders. One open position should have exactly one TP and one SL attached to the
    entire position.
    """
    try:
        want = _dedupe_price_targets([float(x or 0.0) for x in (tp_targets or []) if float(x or 0.0) > 0])
        tp = float((want[-1] if want else 0.0) or 0.0)
        if tp <= 0 or float(stop_loss or 0.0) <= 0:
            return [{'idx': 1, 'tp': float(tp or 0.0), 'qty': float(base_qty or 0.0), 'ok': False, 'retMsg': 'invalid_full_position_tpsl'}]
        res = _autotrade_apply_position_tp_sl(symbol, float(stop_loss or 0.0), tp, side=side)
        ok, detail = _autotrade_confirm_position_full_tpsl(symbol, side, float(stop_loss or 0.0), tp, wait_sec=max(AUTOTRADE_TP_CONFIRM_WAIT_SEC, 3.0))
        cleanup = _autotrade_cancel_legacy_conditional_exit_orders(symbol, side=side)
        return [{
            'idx': 1,
            'tp': float(tp),
            'qty': float(base_qty or 0.0),
            'ok': bool(ok),
            'retCode': (res or {}).get('retCode'),
            'retMsg': (res or {}).get('retMsg'),
            'placement': 'position_full_tpsl',
            'confirm': detail,
            'legacy_conditional_cancelled': int(cleanup or 0),
        }]
    except Exception as e:
        return [{'idx': 1, 'tp': 0.0, 'qty': float(base_qty or 0.0), 'ok': False, 'retMsg': f'{type(e).__name__}: {e}', 'placement': 'position_full_tpsl'}]


def _autotrade_cancel_reduce_only_tp_orders(symbol: str, side: str | None = None, keep_stop_price: float | None = None) -> int:
    count = 0
    sym = _bybit_linear_symbol(symbol)
    close_side = ''
    side_u = str(side or '').upper().strip()
    if side_u == 'BUY':
        close_side = 'SELL'
    elif side_u == 'SELL':
        close_side = 'BUY'
    keep_sl = float(keep_stop_price or 0.0)
    for o in _bybit_get_open_orders_linear(sym):
        try:
            if _bybit_linear_symbol(str(o.get('symbol') or '')) != sym:
                continue
            if not _bybit_order_matches_close_side(o, close_side):
                continue
            if not _bybit_order_reduce_only(o):
                continue
            if not _bybit_order_active(o):
                continue
            px = _bybit_order_working_price(o)
            if keep_sl > 0 and _bybit_is_sl_exit_order(o) and _price_close_enough(px, keep_sl, rel_tol=0.0010):
                continue
            if not _bybit_is_tp_exit_order(o):
                continue
            oid = str(o.get('orderId') or '')
            if not oid:
                continue
            res = _bybit_v5_request('POST', '/v5/order/cancel', {'category': 'linear', 'symbol': sym, 'orderId': oid})
            if int((res or {}).get('retCode', -1)) == 0:
                count += 1
        except Exception:
            continue
    return count




def _bybit_invalidate_live_order_position_cache(symbol: str | None = None) -> None:
    """Drop short Bybit open-order/position caches after exit-order mutations."""
    try:
        sym = _bybit_linear_symbol(symbol) if symbol else ''
        keys = [
            'bybit_open_positions_linear',
            'bybit_open_orders_linear:ALL',
        ]
        if sym:
            keys.append(f'bybit_open_orders_linear:{sym}')
        for k in keys:
            try:
                cache_delete(k)
            except Exception:
                try:
                    _CACHE.pop(str(k), None)
                except Exception:
                    pass
    except Exception:
        pass


def _autotrade_order_is_legacy_conditional_exit(order: dict) -> bool:
    """True only for standalone Conditional exit orders created by older bot builds.

    We intentionally do NOT cancel native Bybit TP/SL rows (stopOrderType
    TakeProfit/StopLoss/tpsl), because the user wants those. The main target is
    the old pf_tp_* reduce-only trigger order that appears in Bybit as
    'Conditional' with TP/SL shown as --/--.
    """
    try:
        if not _bybit_order_active(order):
            return False
        if not _bybit_order_reduce_only(order):
            return False
        link = str((order or {}).get('orderLinkId') or '').lower().strip()
        if link.startswith(('pf_tp_', 'pf_sl_', 'pf_cond_', 'pf_exit_')):
            return True
        txt = _bybit_order_kind_text(order)
        # Native/position-level protection orders must remain.
        native_words = ('takeprofit', 'stoploss', 'partialtakeprofit', 'partialstoploss', 'tpsl', 'tp/sl')
        if any(w in txt for w in native_words):
            return False
        trig = float((order or {}).get('triggerPrice') or (order or {}).get('trigger_price') or (order or {}).get('stopOrderPrice') or 0.0)
        if trig <= 0:
            return False
        # If it is a reduce-only triggered market/conditional close without native
        # TP/SL metadata, it is a legacy standalone Conditional exit.
        order_type = str((order or {}).get('orderType') or '').upper().strip()
        return order_type in {'MARKET', 'LIMIT', ''}
    except Exception:
        return False


def _autotrade_cancel_legacy_conditional_exit_orders(symbol: str, side: str | None = None) -> int:
    """Cancel old standalone Conditional exit rows for a symbol/side.

    This is the cleanup that converts the account back to the desired shape:
    only position-level TP/SL rows, no separate Conditional close orders.
    """
    count = 0
    sym = _bybit_linear_symbol(symbol)
    close_side = ''
    side_u = str(side or '').upper().strip()
    if side_u == 'BUY':
        close_side = 'SELL'
    elif side_u == 'SELL':
        close_side = 'BUY'
    try:
        for o in list(_bybit_get_open_orders_linear(sym) or []):
            try:
                if _bybit_linear_symbol(str((o or {}).get('symbol') or '')) != sym:
                    continue
                if not _bybit_order_matches_close_side(o, close_side):
                    continue
                if not _autotrade_order_is_legacy_conditional_exit(o):
                    continue
                oid = str((o or {}).get('orderId') or '')
                if not oid:
                    continue
                res = _bybit_v5_request('POST', '/v5/order/cancel', {'category': 'linear', 'symbol': sym, 'orderId': oid})
                if int((res or {}).get('retCode', -1)) == 0:
                    count += 1
            except Exception:
                continue
    except Exception:
        pass
    if count:
        _bybit_invalidate_live_order_position_cache(sym)
    return int(count)






def _autotrade_order_is_partial_tpsl_exit(order: dict) -> bool:
    """True for native Partial TP/SL children that can split one position close into many rows.

    Ver06 keeps the desired account shape strict: one live position must have one native
    Full-position TP and one native Full-position SL. Old Partial TP/SL children from older
    builds are cleaned before a fresh Full TP/SL attach so future closes should not fragment
    into many tiny PnL rows such as BLEND/ZEREBRO dust lines.
    """
    try:
        if not _bybit_order_active(order):
            return False
        txt = _bybit_order_kind_text(order)
        if 'partialtakeprofit' in txt or 'partialstoploss' in txt:
            return True
        mode = str((order or {}).get('tpslMode') or (order or {}).get('tpSlMode') or '').lower().strip()
        if mode == 'partial' and ('takeprofit' in txt or 'stoploss' in txt):
            return True
        return False
    except Exception:
        return False


def _autotrade_cancel_partial_tpsl_exit_orders(symbol: str, side: str | None = None) -> int:
    """Cancel old native Partial TP/SL children for this symbol/side.

    This deliberately does not cancel Full-position TP/SL rows. It only targets Partial
    TakeProfit/StopLoss children, because those are the common cause of one position being
    reported as several tiny close-PnL fragments.
    """
    if not AUTOTRADE_CANCEL_PARTIAL_TPSL_BEFORE_FULL_ATTACH:
        return 0
    count = 0
    sym = _bybit_linear_symbol(symbol)
    close_side = ''
    side_u = str(side or '').upper().strip()
    if side_u == 'BUY':
        close_side = 'SELL'
    elif side_u == 'SELL':
        close_side = 'BUY'
    try:
        for o in list(_bybit_get_open_orders_linear(sym) or []):
            try:
                if _bybit_linear_symbol(str((o or {}).get('symbol') or '')) != sym:
                    continue
                if not _bybit_order_matches_close_side(o, close_side):
                    continue
                if not _autotrade_order_is_partial_tpsl_exit(o):
                    continue
                oid = str((o or {}).get('orderId') or '')
                if not oid:
                    continue
                res = _bybit_v5_request('POST', '/v5/order/cancel', {'category': 'linear', 'symbol': sym, 'orderId': oid})
                if int((res or {}).get('retCode', -1)) == 0:
                    count += 1
            except Exception:
                continue
    except Exception:
        pass
    if count:
        _bybit_invalidate_live_order_position_cache(sym)
    return int(count)

def _autotrade_cancel_all_legacy_conditional_exit_orders(max_items: int = 80, max_cancel: int | None = None) -> int:
    """Cancel old bot-created standalone Conditional exit orders across the account.

    These are the rows shown by Bybit as ``Conditional`` with TP/SL = --/--.
    Native position-level TP/SL rows are explicitly excluded by
    _autotrade_order_is_legacy_conditional_exit().
    """
    count = 0
    try:
        max_n = max(1, int(max_cancel if max_cancel is not None else (max_items or 80)))
    except Exception:
        max_n = 80
    try:
        for o in list(_bybit_get_open_orders_linear(None) or []):
            if count >= max_n:
                break
            try:
                if not _autotrade_order_is_legacy_conditional_exit(o):
                    continue
                sym = _bybit_linear_symbol(str((o or {}).get('symbol') or ''))
                oid = str((o or {}).get('orderId') or '')
                if not sym or not oid:
                    continue
                res = _bybit_v5_request('POST', '/v5/order/cancel', {'category': 'linear', 'symbol': sym, 'orderId': oid})
                if int((res or {}).get('retCode', -1)) == 0:
                    count += 1
            except Exception:
                continue
    except Exception:
        pass
    if count:
        _bybit_invalidate_live_order_position_cache(None)
    return int(count)


def _autotrade_confirm_position_full_tpsl(symbol: str, side: str, stop_loss: float, take_profit: float, wait_sec: float = 3.0, step_sec: float = 0.30) -> tuple[bool, dict]:
    """Confirm Full-position TP/SL from the live position fields, not standalone orders."""
    sym = _bybit_linear_symbol(symbol)
    side_u = str(side or '').upper().strip()
    sl_target = float(stop_loss or 0.0)
    tp_target = float(take_profit or 0.0)
    detail = {'symbol': sym, 'side': side_u, 'want_sl': sl_target, 'want_tp': tp_target, 'live_sl': 0.0, 'live_tp': 0.0}
    try:
        deadline = time.time() + max(0.2, float(wait_sec or 0.0))
        while True:
            _bybit_invalidate_live_order_position_cache(sym)
            p = _autotrade_find_live_position(sym, side=side_u)
            # Confirm ONLY native position-level TP/SL. Do not allow standalone
            # Conditional orders to satisfy this check.
            live_sl = float(_pos_native_stop_loss(p) or 0.0) if p else 0.0
            live_tp = float(_pos_native_take_profit(p) or 0.0) if p else 0.0
            detail.update({'live_sl': float(live_sl), 'live_tp': float(live_tp), 'position_found': bool(p)})
            sl_ok = bool(sl_target > 0 and live_sl > 0 and _price_close_enough(live_sl, sl_target, rel_tol=0.0020))
            tp_ok = bool(tp_target > 0 and live_tp > 0 and _price_close_enough(live_tp, tp_target, rel_tol=0.0020))
            if sl_ok and tp_ok:
                detail.update({'sl_ok': True, 'tp_ok': True})
                return True, detail
            if time.time() >= deadline:
                detail.update({'sl_ok': bool(sl_ok), 'tp_ok': bool(tp_ok)})
                return False, detail
            time.sleep(max(0.05, float(step_sec or 0.2)))
    except Exception as exc:
        detail.update({'error': f'{type(exc).__name__}: {exc}', 'sl_ok': False, 'tp_ok': False})
        return False, detail


def _autotrade_attach_position_full_tpsl_and_cleanup(symbol: str, side: str, stop_loss: float, take_profit: float, live_pos: dict | None = None) -> dict:
    """Authoritative live exit attach path: Full-position TP/SL + legacy conditional cleanup."""
    out = {
        'symbol': _bybit_linear_symbol(symbol),
        'side': str(side or '').upper().strip(),
        'placement': 'position_full_tpsl',
        'apply_res': {},
        'confirm': {},
        'legacy_conditional_cancelled': 0,
        'ok': False,
    }
    try:
        # First remove old standalone pf_tp/pf_cond rows so the Bybit Orders page
        # does not show extra Conditional exits. Then apply the wanted native TP/SL.
        out['legacy_conditional_cancelled_before'] = _autotrade_cancel_legacy_conditional_exit_orders(symbol, side=side)
        out['partial_tpsl_cancelled_before'] = _autotrade_cancel_partial_tpsl_exit_orders(symbol, side=side)
        res = _autotrade_apply_position_tp_sl(symbol, float(stop_loss or 0.0), float(take_profit or 0.0), side=side, live_pos=live_pos)
        out['apply_res'] = res or {}
        _bybit_invalidate_live_order_position_cache(symbol)
        ok, detail = _autotrade_confirm_position_full_tpsl(symbol, side, float(stop_loss or 0.0), float(take_profit or 0.0), wait_sec=max(AUTOTRADE_TP_CONFIRM_WAIT_SEC, 8.0))
        out['confirm'] = detail or {}
        # Clean again after attach in case older code left an order hidden behind cache.
        out['legacy_conditional_cancelled_after'] = _autotrade_cancel_legacy_conditional_exit_orders(symbol, side=side)
        out['partial_tpsl_cancelled_after'] = _autotrade_cancel_partial_tpsl_exit_orders(symbol, side=side)
        out['legacy_conditional_cancelled'] = int(out.get('legacy_conditional_cancelled_before') or 0) + int(out.get('legacy_conditional_cancelled_after') or 0)
        out['partial_tpsl_cancelled'] = int(out.get('partial_tpsl_cancelled_before') or 0) + int(out.get('partial_tpsl_cancelled_after') or 0)
        # Reconfirm after cleanup to ensure we did not disturb the native TP/SL.
        ok2, detail2 = _autotrade_confirm_position_full_tpsl(symbol, side, float(stop_loss or 0.0), float(take_profit or 0.0), wait_sec=4.0)
        out['confirm_after_cleanup'] = detail2 or {}
        out['ok'] = bool(ok and ok2)
        return out
    except Exception as exc:
        out['error'] = f'{type(exc).__name__}: {exc}'
        out['ok'] = False
        return out

def _autotrade_wait_live_position(symbol: str, side: str, wait_sec: float = 4.0, step_sec: float = 0.35):
    deadline = time.time() + max(0.2, float(wait_sec or 0.0))
    last_pos = None
    while time.time() < deadline:
        last_pos = _autotrade_find_live_position(symbol, side=side)
        if last_pos and abs(float(_pos_size(last_pos) or 0.0)) > 0:
            return last_pos
        time.sleep(max(0.05, float(step_sec or 0.2)))
    return last_pos


def _autotrade_wait_live_entry_confirmation(symbol: str, side: str, order_id: str = '', order_link_id: str = '', wait_sec: float = 9.0, step_sec: float = 0.4) -> dict:
    """Wait for position visibility, but fall back to order-state proof when Bybit lags."""
    sym = _bybit_linear_symbol(symbol)
    side_u = str(side or '').upper().strip()
    deadline = time.time() + max(0.5, float(wait_sec or 0.0))
    last_state = {}
    while time.time() < deadline:
        pos = _autotrade_find_live_position(sym, side=side_u)
        if pos and abs(float(_pos_size(pos) or 0.0)) > 0:
            return {
                'position': pos,
                'filled_confirmed': True,
                'filled_qty': abs(float(_pos_size(pos) or 0.0)),
                'avg_price': float(_pos_entry(pos) or 0.0),
                'reason': 'position_visible',
                'order_state': last_state,
            }
        state = _bybit_get_order_linear_state(sym, order_id=order_id, order_link_id=order_link_id)
        if state:
            last_state = state
            status = str((state or {}).get('orderStatus') or '').upper().strip()
            filled_qty = float(_bybit_order_filled_qty(state) or 0.0)
            if status in {'CANCELLED', 'REJECTED', 'DEACTIVATED'} and filled_qty <= 0:
                return {
                    'position': None,
                    'filled_confirmed': False,
                    'filled_qty': 0.0,
                    'avg_price': 0.0,
                    'reason': f'order_{status.lower()}',
                    'order_state': last_state,
                }
        time.sleep(max(0.05, float(step_sec or 0.2)))

    filled_qty = float(_bybit_order_filled_qty(last_state) or 0.0)
    status = str((last_state or {}).get('orderStatus') or '').upper().strip()
    return {
        'position': None,
        'filled_confirmed': bool(filled_qty > 0 and status in {'FILLED', 'PARTIALLYFILLED', 'PARTIALLY_FILLED'}),
        'filled_qty': filled_qty,
        'avg_price': float(_bybit_order_avg_price(last_state) or 0.0),
        'reason': ('fill_confirmed_visibility_pending' if (filled_qty > 0 and status in {'FILLED', 'PARTIALLYFILLED', 'PARTIALLY_FILLED'}) else ('order_status_' + status.lower() if status else 'live_entry_fill_not_confirmed')),
        'order_state': last_state,
    }


def _autotrade_force_close_live_position(symbol: str, side: str, qty: float | None = None) -> dict:
    try:
        sym = _bybit_linear_symbol(symbol)
        side_u = str(side or '').upper().strip()
        if side_u not in {'BUY', 'SELL'}:
            return {'retCode': -1, 'retMsg': 'bad_side'}
        live_pos = _autotrade_find_live_position(sym, side=side_u)
        live_qty = abs(float(qty or (_pos_size(live_pos) if live_pos else 0.0) or 0.0))
        if live_qty <= 0:
            return {'retCode': 0, 'retMsg': 'no_live_qty'}
        qty_i, qreason = _round_qty_down(sym, live_qty, float(_pos_entry(live_pos) if live_pos else 0.0))
        if not qty_i or qty_i <= 0:
            return {'retCode': -1, 'retMsg': f'close_qty_invalid:{qreason}'}
        filt = _bybit_get_instr_filters(sym)
        payload = {
            'category': 'linear',
            'symbol': sym,
            'side': 'Sell' if side_u == 'BUY' else 'Buy',
            'orderType': 'Market',
            'qty': _fmt_qty(qty_i, filt.get('qtyStep')),
            'timeInForce': 'IOC',
            'reduceOnly': True,
            'positionIdx': 0,
            'orderLinkId': f"pf_fc_{sym}_{int(time.time()*1000)%100000000}_{uuid.uuid4().hex[:6]}"[:36],
        }
        return _bybit_v5_request('POST', '/v5/order/create', payload)
    except Exception as e:
        return {'retCode': -1, 'retMsg': f'{type(e).__name__}: {e}'}





def _local_hhmm_in_window(hhmm: str, window: str) -> bool:
    try:
        cur_h, cur_m = [int(x) for x in str(hhmm).split(':')[:2]]
        start_s, end_s = str(window or '').split('-', 1)
        pa = _parse_blackout_endpoint(start_s.strip())
        pb = _parse_blackout_endpoint(end_s.strip())
        if not pa or not pb or pa[0] is not None or pb[0] is not None:
            return False
        cur = cur_h * 60 + cur_m
        start = int(pa[1])
        end = int(pb[1])
        if start <= end:
            return start <= cur < end
        return cur >= start or cur < end
    except Exception:
        return False


def _local_dt_in_blackout_window(dt, window: str) -> bool:
    """Return True when a Melbourne datetime is inside a daily or day-aware window."""
    try:
        w = str(window or '').strip()
        if '-' not in w:
            return False
        start_s, end_s = [x.strip() for x in w.split('-', 1)]
        pa = _parse_blackout_endpoint(start_s)
        pb = _parse_blackout_endpoint(end_s)
        if not pa or not pb:
            return False
        sd, sm, _ = pa
        ed, em, _ = pb
        if sd is None and ed is None:
            return _local_hhmm_in_window(dt.strftime('%H:%M'), w)
        if sd is None and ed is not None:
            sd = ed
            if sm > em:
                sd = (ed - 1) % 7
        if ed is None and sd is not None:
            ed = sd if em > sm else (sd + 1) % 7
        if sd is None or ed is None:
            return False
        week = 7 * 24 * 60
        cur = int(dt.weekday()) * 1440 + int(dt.hour) * 60 + int(dt.minute)
        start = int(sd) * 1440 + int(sm)
        end = int(ed) * 1440 + int(em)
        if end <= start:
            end += week
            if cur < start:
                cur += week
        return start <= cur < end
    except Exception:
        return False


def _blackout_now_from_windows(enabled: bool, windows_value, reason_prefix: str, now_ts: float | None = None) -> tuple[bool, str]:
    try:
        if not bool(enabled):
            return False, ''
        ts = float(now_ts if now_ts is not None else time.time())
        dt = datetime.fromtimestamp(ts, tz=timezone.utc).astimezone(MEL_TZ)
        for w in _split_blackout_windows(windows_value):
            if _local_dt_in_blackout_window(dt, str(w)):
                return True, f'{reason_prefix}_{w}_melbourne'
        return False, ''
    except Exception:
        return False, ''


def _autotrade_entry_blackout_now(now_ts: float | None = None) -> tuple[bool, str]:
    return _blackout_now_from_windows(
        bool(_autotrade_entry_blackout_enabled()),
        _autotrade_entry_blackout_windows(),
        'entry_blackout',
        now_ts=now_ts,
    )


def _setup_generation_blackout_now(now_ts: float | None = None) -> tuple[bool, str]:
    return _blackout_now_from_windows(
        bool(_setup_generation_blackout_enabled()),
        _setup_generation_blackout_windows(),
        'setup_generation_blackout',
        now_ts=now_ts,
    )



def _autotrade_close_carried_live_positions_after_reset(uid: int, reason: str = 'post_asia_flat_carryover_guard') -> dict:
    """Close bot-owned live positions that existed before the configured ASIA flat cutoff.

    Ver69: the previous guard used the trading-day reset boundary. In current runtime
    the trading-day reset can be 00:00 Melbourne, which caused repeated "carryover flat
    after ASIA reset" messages before the intended 09:55 ASIA flat. The zero-carryover
    guard must be tied to AUTOTRADE_FLAT_BEFORE_ASIA_TIME instead:
      - before today's configured flat cutoff: do nothing;
      - after the cutoff: close only bot-owned positions opened before the cutoff;
      - leave current-day positions opened after the cutoff untouched.
    """
    out = {'ok': True, 'reason': str(reason or 'post_asia_flat_carryover_guard'), 'closed': [], 'skipped': [], 'errors': []}
    try:
        uid_i = int(uid or 0)
        if uid_i <= 0:
            out['ok'] = False
            out['errors'].append('missing_owner_uid')
            return out
        if not bool(_autotrade_flat_before_asia_enabled()):
            out['skipped'].append({'reason': 'flat_before_asia_disabled'})
            return out

        now_dt = datetime.now(MEL_TZ)
        cutoff_dt, cutoff_date_s = _autotrade_flat_before_asia_local_cutoff(now_dt)
        now_ts = float(now_dt.timestamp())
        cutoff_ts = float(cutoff_dt.timestamp())

        # Do not perform carryover flattening before the configured ASIA flat time.
        # This prevents midnight/day-reset cleanup messages before 09:55 Melbourne.
        if now_dt < cutoff_dt:
            out['skipped'].append({
                'reason': 'before_flat_before_asia_cutoff',
                'cutoff_local': cutoff_dt.strftime('%Y-%m-%d %H:%M'),
                'now_local': now_dt.strftime('%Y-%m-%d %H:%M'),
            })
            return out

        live_positions = list(_bybit_get_open_positions_linear() or [])
        journal_open = list(_autotrade_db_open_trades(uid_i) or [])
        bot_positions, external_positions, _jr = _autotrade_collect_live_position_rows(
            uid_i,
            positions=live_positions,
            journal_open=journal_open,
            fallback_unmatched_as_owned=bool(globals().get('AUTOTRADE_FLAT_FALLBACK_UNMATCHED_AS_OWNED', True)),
        )
        for p, tr in (bot_positions or []):
            try:
                sym = _pos_symbol(p)
                side = _pos_side_text(p)
                try:
                    info = _autotrade_resolve_live_position_open_info(uid_i, p, journal_open=[tr] if tr else journal_open)
                except Exception:
                    info = {}
                opened_ts = float((info or {}).get('opened_ts') or (tr or {}).get('opened_ts') or (tr or {}).get('created_ts') or 0.0)
                if opened_ts <= 0:
                    out['skipped'].append({'symbol': sym, 'side': side, 'reason': 'open_time_unknown'})
                    continue
                if opened_ts >= cutoff_ts:
                    out['skipped'].append({'symbol': sym, 'side': side, 'reason': 'opened_after_flat_cutoff', 'opened_ts': opened_ts, 'cutoff_ts': cutoff_ts})
                    continue
                qty = abs(float(_pos_size(p) or 0.0))
                if qty <= 0:
                    out['skipped'].append({'symbol': sym, 'side': side, 'reason': 'zero_qty'})
                    continue
                res = _autotrade_force_close_live_position(sym, side, qty=qty)
                row = {
                    'symbol': sym,
                    'side': side,
                    'qty': qty,
                    'retCode': (res or {}).get('retCode'),
                    'retMsg': (res or {}).get('retMsg'),
                    'opened_ts': opened_ts,
                    'cutoff_ts': cutoff_ts,
                    'cutoff_local_date': cutoff_date_s,
                }
                out['closed'].append(row)
                try:
                    if tr and str((tr or {}).get('trade_id') or ''):
                        _autotrade_db_close_trade(str(tr.get('trade_id')), time.time(), 0.0, 'CARRYOVER_FLAT', str(reason or 'post_asia_flat_carryover_guard'))
                except Exception:
                    pass
            except Exception as exc:
                out['errors'].append(f'{type(exc).__name__}: {exc}')
        if external_positions:
            for p in external_positions[:12]:
                try:
                    out['skipped'].append({'symbol': _pos_symbol(p), 'side': _pos_side_text(p), 'reason': 'external_or_manual_position'})
                except Exception:
                    pass
        try:
            _autotrade_cancel_all_legacy_conditional_exit_orders(max_items=80)
        except Exception:
            pass
        if out['errors']:
            out['ok'] = False
        return out
    except Exception as exc:
        return {'ok': False, 'reason': str(reason or 'post_asia_flat_carryover_guard'), 'closed': [], 'skipped': [], 'errors': [f'{type(exc).__name__}: {exc}']}

def _autotrade_close_owned_live_positions(uid: int, reason: str = 'scheduled_flat', max_opened_before_ts: float | None = None) -> dict:
    """Close AutoTrade-owned live positions.

    Ver15 hardening:
    - Uses the same owner classification as /open_trades and /autotrade_debug, including
      synthetic fallback for live Bybit positions when the journal was reset/cleared.
    - Optional max_opened_before_ts is used by the catch-up flat so positions opened after
      the 09:55 cutoff are not closed by a late catch-up run.
    """
    out = {'ok': True, 'reason': str(reason or 'scheduled_flat'), 'closed': [], 'skipped': [], 'errors': []}
    try:
        uid_i = int(uid or 0)
        live_positions = list(_bybit_get_open_positions_linear() or [])
        journal_open = list(_autotrade_db_open_trades(uid_i) or [])
        try:
            bot_positions, external_positions, _jr = _autotrade_collect_live_position_rows(
                uid_i,
                positions=live_positions,
                journal_open=journal_open,
                fallback_unmatched_as_owned=bool(globals().get('AUTOTRADE_FLAT_FALLBACK_UNMATCHED_AS_OWNED', True)),
            )
        except Exception:
            bot_positions, external_positions = [], []
            for p in live_positions:
                tr = _autotrade_find_open_trade_for_live_position(uid_i, p, journal_open=journal_open)
                if not tr and bool(globals().get('AUTOTRADE_FLAT_CLOSE_ALL_LIVE', False)):
                    tr = _autotrade_synthetic_live_trade_row(uid_i, p)
                if tr:
                    bot_positions.append((p, dict(tr)))
                else:
                    external_positions.append(p)

        cutoff = float(max_opened_before_ts or 0.0)
        for p, tr in (bot_positions or []):
            try:
                sym = _pos_symbol(p)
                side = _pos_side_text(p)
                if cutoff > 0:
                    try:
                        info = _autotrade_resolve_live_position_open_info(uid_i, p, journal_open=journal_open)
                    except Exception:
                        info = {}
                    opened_ts = float((info or {}).get('opened_ts') or tr.get('opened_ts') or tr.get('created_ts') or 0.0)
                    if opened_ts > cutoff:
                        out['skipped'].append({'symbol': sym, 'side': side, 'reason': 'opened_after_flat_cutoff', 'opened_ts': opened_ts, 'cutoff_ts': cutoff})
                        continue
                    if opened_ts <= 0:
                        out['skipped'].append({'symbol': sym, 'side': side, 'reason': 'open_time_unknown_for_catchup'})
                        continue
                qty = abs(float(_pos_size(p) or 0.0))
                if qty <= 0:
                    out['skipped'].append({'symbol': sym, 'side': side, 'reason': 'zero_qty'})
                    continue
                res = _autotrade_force_close_live_position(sym, side, qty=qty)
                row = {'symbol': sym, 'side': side, 'qty': qty, 'retCode': (res or {}).get('retCode'), 'retMsg': (res or {}).get('retMsg')}
                out['closed'].append(row)
                try:
                    if tr and str(tr.get('trade_id') or ''):
                        _autotrade_db_close_trade(str(tr.get('trade_id')), time.time(), 0.0, 'SCHEDULED_FLAT', str(reason or 'scheduled_flat'))
                except Exception:
                    pass
            except Exception as exc:
                out['errors'].append(f'{type(exc).__name__}: {exc}')
        if external_positions:
            for p in external_positions[:12]:
                try:
                    out['skipped'].append({'symbol': _pos_symbol(p), 'side': _pos_side_text(p), 'reason': 'external_or_manual_position'})
                except Exception:
                    pass
        try:
            _autotrade_cancel_all_legacy_conditional_exit_orders(max_items=80)
        except Exception:
            pass
        if out['errors']:
            out['ok'] = False
        return out
    except Exception as exc:
        return {'ok': False, 'reason': str(reason or 'scheduled_flat'), 'closed': [], 'skipped': [], 'errors': [f'{type(exc).__name__}: {exc}']}


async def autotrade_flat_before_asia_job(context: ContextTypes.DEFAULT_TYPE):
    try:
        if not bool(_autotrade_flat_before_asia_enabled()):
            return
        if not _autotrade_ready() or str(_autotrade_runtime_mode()).lower() != 'live':
            return
        uid = int(AUTOTRADE_OWNER_UID or 0)
        if uid <= 0:
            return
        res = await to_thread_autotrade(_autotrade_close_owned_live_positions, uid, f'scheduled_flat_before_asia_{_autotrade_flat_before_asia_hour():02d}_{_autotrade_flat_before_asia_minute():02d}_melbourne', timeout=60)
        try:
            _autotrade_config_set(AUTOTRADE_CFG_FLAT_BEFORE_ASIA_LAST_DATE_KEY, datetime.now(MEL_TZ).strftime('%Y-%m-%d'))
        except Exception:
            pass
        try:
            cd_reset = _autotrade_clear_execution_cooldowns(uid, 'scheduled_flat_before_asia')
        except Exception:
            cd_reset = {}
        closed = list((res or {}).get('closed') or [])
        if closed or cd_reset:
            try:
                msg = '🧹 AutoTrade scheduled flat before ASIA\n' + f"Closed positions: {len(closed)}"
                if cd_reset:
                    msg += f"\nCooldown reset: cleared {int((cd_reset or {}).get('deleted_emailed_symbols') or 0)} email/setup cooldown rows"
                if closed:
                    msg += '\n' + '\n'.join([f"• {x.get('symbol')} {x.get('side')} ret={x.get('retCode')}" for x in closed[:12]])
                await context.bot.send_message(chat_id=uid, text=msg)
            except Exception:
                pass
    except Exception as exc:
        try:
            _hb_touch('autotrade_flat_before_asia', ok=False, error=f'{type(exc).__name__}: {exc}', details='flat_job_error')
        except Exception:
            pass



def _autotrade_flat_before_asia_local_cutoff(now_dt: datetime | None = None) -> tuple[datetime, str]:
    """Return today's configured Melbourne flat cutoff and local date string."""
    try:
        dt = now_dt or datetime.now(MEL_TZ)
        if dt.tzinfo is None:
            dt = dt.replace(tzinfo=MEL_TZ)
        h = int(_autotrade_flat_before_asia_hour())
        m = int(_autotrade_flat_before_asia_minute())
        cutoff = dt.replace(hour=h, minute=m, second=0, microsecond=0)
        return cutoff, dt.strftime('%Y-%m-%d')
    except Exception:
        dt = datetime.now(MEL_TZ)
        return dt.replace(hour=9, minute=45, second=0, microsecond=0), dt.strftime('%Y-%m-%d')


def _autotrade_flat_before_asia_catchup_due(now_dt: datetime | None = None) -> tuple[bool, datetime, str, str]:
    """Return whether the missed 09:55 Melbourne flat should be caught up now."""
    try:
        if not bool(_autotrade_flat_before_asia_enabled()):
            return False, datetime.now(MEL_TZ), '', 'disabled'
        if not bool(_autotrade_flat_before_asia_catchup_enabled()):
            return False, datetime.now(MEL_TZ), '', 'catchup_disabled'
        now = now_dt or datetime.now(MEL_TZ)
        cutoff, date_s = _autotrade_flat_before_asia_local_cutoff(now)
        if now < cutoff:
            return False, cutoff, date_s, 'before_flat_time'
        grace_h = max(1.0, float(globals().get('AUTOTRADE_FLAT_BEFORE_ASIA_CATCHUP_GRACE_HOURS', 18) or 18))
        if now > cutoff + timedelta(hours=grace_h):
            return False, cutoff, date_s, 'outside_catchup_grace'
        last = str(_autotrade_config_get(AUTOTRADE_CFG_FLAT_BEFORE_ASIA_LAST_DATE_KEY, '') or '').strip()
        if last == date_s:
            return False, cutoff, date_s, 'already_flat_today'
        return True, cutoff, date_s, 'due'
    except Exception as exc:
        try:
            return False, datetime.now(MEL_TZ), '', f'catchup_due_error:{type(exc).__name__}'
        except Exception:
            return False, datetime.now(timezone.utc), '', 'catchup_due_error'


async def autotrade_flat_before_asia_catchup_job(context: ContextTypes.DEFAULT_TYPE):
    """Repeating safety net for missed 09:55 Melbourne scheduled flat.

    Render restarts/sleeps or job-queue misfires can miss an exact run_daily event. This
    guardian checks repeatedly after 09:55 and runs the flat once per Melbourne date. It
    only closes positions opened before the configured cutoff, so a late catch-up does not
    close legitimate new ASIA trades opened after the blackout window.
    """
    try:
        if not _autotrade_ready() or str(_autotrade_runtime_mode()).lower() != 'live':
            return
        uid = int(AUTOTRADE_OWNER_UID or 0)
        if uid <= 0:
            return
        # Ver69: zero-carryover is a once-per-day post-09:55 safety pass.
        # Do not run it at midnight/day-reset, and do not spam the owner every catch-up tick.
        try:
            now_local = datetime.now(MEL_TZ)
            carry_cutoff, carry_date_s = _autotrade_flat_before_asia_local_cutoff(now_local)
            last_carry_date = str(_autotrade_config_get(AUTOTRADE_CFG_CARRYOVER_FLAT_LAST_DATE_KEY, '') or '').strip()
            if now_local >= carry_cutoff and last_carry_date != carry_date_s:
                carry_res = await to_thread_autotrade(_autotrade_close_carried_live_positions_after_reset, uid, f'carryover_flat_after_asia_cutoff_{carry_date_s}', timeout=60)
                carry_closed = list((carry_res or {}).get('closed') or [])
                carry_errors = list((carry_res or {}).get('errors') or [])
                if carry_closed:
                    try:
                        cd_reset2 = _autotrade_clear_execution_cooldowns(uid, f'carryover_flat_after_asia_cutoff_{carry_date_s}')
                    except Exception:
                        cd_reset2 = {}
                    try:
                        _autotrade_config_set(AUTOTRADE_CFG_CARRYOVER_FLAT_LAST_DATE_KEY, carry_date_s)
                    except Exception:
                        pass
                    msg2 = '🧹 AutoTrade carryover flat after ASIA cutoff\n' + f"Cutoff: {carry_cutoff.strftime('%H:%M')} Melbourne | Closed carried positions: {len(carry_closed)}"
                    if cd_reset2:
                        msg2 += f"\nCooldown reset: cleared {int((cd_reset2 or {}).get('deleted_emailed_symbols') or 0)} email/setup cooldown rows"
                    msg2 += '\n' + '\n'.join([f"• {x.get('symbol')} {x.get('side')} ret={x.get('retCode')}" for x in carry_closed[:12]])
                    await context.bot.send_message(chat_id=uid, text=msg2)
                elif not carry_errors:
                    # Nothing carried across the cutoff. Mark today done so the 5-minute
                    # catch-up guardian remains quiet until tomorrow.
                    try:
                        _autotrade_config_set(AUTOTRADE_CFG_CARRYOVER_FLAT_LAST_DATE_KEY, carry_date_s)
                    except Exception:
                        pass
        except Exception:
            pass

        due, cutoff, date_s, reason = _autotrade_flat_before_asia_catchup_due()
        if not due:
            return
        cutoff_ts = cutoff.timestamp()
        res = await to_thread_autotrade(_autotrade_close_owned_live_positions, uid, f'catchup_flat_before_asia_{date_s}', cutoff_ts, timeout=90)
        try:
            _autotrade_config_set(AUTOTRADE_CFG_FLAT_BEFORE_ASIA_LAST_DATE_KEY, date_s)
        except Exception:
            pass
        try:
            cd_reset = _autotrade_clear_execution_cooldowns(uid, f'catchup_flat_before_asia_{date_s}')
        except Exception:
            cd_reset = {}
        closed = list((res or {}).get('closed') or [])
        skipped = list((res or {}).get('skipped') or [])
        try:
            msg = '🧹 AutoTrade 09:55 flat catch-up\n' + f"Date: {date_s} | Cutoff: {cutoff.strftime('%H:%M')} Melbourne\nClosed positions: {len(closed)}"
            if cd_reset:
                msg += f"\nCooldown reset: cleared {int((cd_reset or {}).get('deleted_emailed_symbols') or 0)} email/setup cooldown rows"
            if skipped:
                msg += f"\nSkipped: {len(skipped)}"
            if closed:
                msg += '\n' + '\n'.join([f"• {x.get('symbol')} {x.get('side')} ret={x.get('retCode')}" for x in closed[:12]])
            await context.bot.send_message(chat_id=uid, text=msg)
        except Exception:
            pass
    except Exception as exc:
        try:
            _hb_touch('autotrade_flat_before_asia_catchup', ok=False, error=f'{type(exc).__name__}: {exc}', details='flat_catchup_error')
        except Exception:
            pass


def _autotrade_close_stale_owned_live_positions(uid: int, max_age_hours: float | None = None, reason: str = 'max_position_age') -> dict:
    """Close AutoTrade-owned live positions whose resolved open age exceeds max_age_hours."""
    hours = float(max_age_hours if max_age_hours is not None else _autotrade_max_position_hours())
    out = {'ok': True, 'reason': str(reason or 'max_position_age'), 'max_age_hours': hours, 'closed': [], 'skipped': [], 'errors': []}
    try:
        if not bool(_autotrade_max_position_hours_enabled()):
            out['skipped'].append({'reason': 'max_position_hours_disabled'})
            return out
        uid_i = int(uid or 0)
        if uid_i <= 0:
            out['ok'] = False
            out['errors'].append('missing_owner_uid')
            return out
        now_ts = time.time()
        live_positions = list(_bybit_get_open_positions_linear() or [])
        journal_open = list(_autotrade_db_open_trades(uid_i) or [])
        # Ver17: use the same fallback ownership classification as /open_trades and
        # /autotrade_debug. This lets max-hold close old live AutoTrade positions even
        # after journal/test data was reset.
        try:
            bot_positions, external_positions, _jr = _autotrade_collect_live_position_rows(
                uid_i,
                positions=live_positions,
                journal_open=journal_open,
                fallback_unmatched_as_owned=bool(globals().get('AUTOTRADE_FLAT_FALLBACK_UNMATCHED_AS_OWNED', True)),
            )
        except Exception:
            bot_positions = []
            external_positions = []
            for _p in live_positions:
                _tr = _autotrade_find_open_trade_for_live_position(uid_i, _p, journal_open=journal_open)
                if not _tr and bool(globals().get('AUTOTRADE_FLAT_CLOSE_ALL_LIVE', False)):
                    _tr = _autotrade_synthetic_live_trade_row(uid_i, _p)
                if _tr:
                    bot_positions.append((_p, dict(_tr)))
                else:
                    external_positions.append(_p)
        for p, tr in list(bot_positions or []):
            try:
                sym = _pos_symbol(p)
                side = _pos_side_text(p)
                info = _autotrade_resolve_live_position_open_info(uid_i, p, journal_open=journal_open)
                opened_ts = float((info or {}).get('opened_ts') or tr.get('opened_ts') or tr.get('created_ts') or 0.0)
                if opened_ts <= 0:
                    out['skipped'].append({'symbol': sym, 'side': side, 'reason': 'open_time_unknown'})
                    continue
                age_h = max(0.0, (now_ts - opened_ts) / 3600.0)
                if age_h < hours:
                    out['skipped'].append({'symbol': sym, 'side': side, 'reason': 'not_old_enough', 'age_h': round(age_h, 2)})
                    continue
                qty = abs(float(_pos_size(p) or 0.0))
                res = _autotrade_force_close_live_position(sym, side, qty=qty)
                row = {'symbol': sym, 'side': side, 'qty': qty, 'age_h': round(age_h, 2), 'retCode': (res or {}).get('retCode'), 'retMsg': (res or {}).get('retMsg')}
                out['closed'].append(row)
                try:
                    if tr and str(tr.get('trade_id') or ''):
                        _autotrade_db_close_trade(str(tr.get('trade_id')), now_ts, 0.0, 'MAX_HOLD_TIME_EXIT', str(reason or 'max_position_age'))
                except Exception:
                    pass
            except Exception as exc:
                out['errors'].append(f'{type(exc).__name__}: {exc}')
        try:
            for _p in list(locals().get('external_positions', []) or [])[:12]:
                out['skipped'].append({'symbol': _pos_symbol(_p), 'side': _pos_side_text(_p), 'reason': 'external_or_manual_position'})
        except Exception:
            pass
        if out['errors']:
            out['ok'] = False
        return out
    except Exception as exc:
        return {'ok': False, 'reason': str(reason or 'max_position_age'), 'max_age_hours': hours, 'closed': [], 'skipped': [], 'errors': [f'{type(exc).__name__}: {exc}']}


async def autotrade_max_position_age_job(context: ContextTypes.DEFAULT_TYPE):
    """Periodic 8h max-hold guardian for AutoTrade-owned live positions."""
    try:
        if not bool(_autotrade_max_position_hours_enabled()):
            return
        if not _autotrade_ready() or str(_autotrade_runtime_mode()).lower() != 'live':
            return
        uid = int(AUTOTRADE_OWNER_UID or 0)
        if uid <= 0:
            return
        hours = float(_autotrade_max_position_hours())
        res = await to_thread_autotrade(_autotrade_close_stale_owned_live_positions, uid, hours, f'max_hold_{hours:.2f}h', timeout=60)
        closed = list((res or {}).get('closed') or [])
        if closed:
            try:
                msg = '⏱️ AutoTrade max-hold exit\n' + f"Max hold: {hours:.2f}h | Closed: {len(closed)}\n" + '\n'.join([f"• {x.get('symbol')} {x.get('side')} age={x.get('age_h')}h ret={x.get('retCode')}" for x in closed[:12]])
                await context.bot.send_message(chat_id=uid, text=msg)
            except Exception:
                pass
    except Exception as exc:
        try:
            _hb_touch('autotrade_max_position_age', ok=False, error=f'{type(exc).__name__}: {exc}', details='max_age_job_error')
        except Exception:
            pass


async def autotrade_flat_now_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Manually close AutoTrade-owned live positions now."""
    uid_req = int(update.effective_user.id)
    if not is_admin_user(uid_req) and int(uid_req) != int(AUTOTRADE_OWNER_UID or 0):
        await update.message.reply_text("⛔ Owner/admin only.")
        return
    if not _autotrade_ready() or str(_autotrade_runtime_mode()).lower() != 'live':
        await update.message.reply_text("AutoTrade is not live/ready.")
        return
    owner = int(AUTOTRADE_OWNER_UID or uid_req)
    try:
        res = await to_thread_autotrade(_autotrade_close_owned_live_positions, owner, 'manual_autotrade_flat_now', timeout=60)
        closed = list((res or {}).get('closed') or [])
        skipped = list((res or {}).get('skipped') or [])
        errs = list((res or {}).get('errors') or [])
        try:
            cd_reset = _autotrade_clear_execution_cooldowns(owner, 'manual_autotrade_flat_now')
        except Exception:
            cd_reset = {}
        lines = ["🧹 AutoTrade flat now", HDR, f"Closed attempts: {len(closed)} | Skipped: {len(skipped)} | Errors: {len(errs)}"]
        if cd_reset:
            lines.append(f"Cooldown reset: cleared {int((cd_reset or {}).get('deleted_emailed_symbols') or 0)} email/setup cooldown rows")
        for x in closed[:15]:
            lines.append(f"• {x.get('symbol')} {x.get('side')} qty={x.get('qty')} ret={x.get('retCode')} {x.get('retMsg') or ''}")
        if errs:
            lines.append("Errors: " + "; ".join([str(e) for e in errs[:3]]))
        await update.message.reply_text("\n".join(lines))
    except Exception as exc:
        await update.message.reply_text(f"❌ /autotrade_flat_now failed: {type(exc).__name__}: {exc}")

# Ver12: strict TP/SL-only lifecycle. AutoTrade should not close or partially
# reduce a live position at market in the middle of a trade. A position should
# normally finish only via native Bybit position TP or SL. Manual /autotrade_flat_now and configured time exits
# remain available as explicit owner-approved exceptions.
AUTOTRADE_STRICT_TPSL_ONLY = env_bool('AUTOTRADE_STRICT_TPSL_ONLY', True)
AUTOTRADE_IMMUTABLE_TPSL_AFTER_ENTRY = env_bool('AUTOTRADE_IMMUTABLE_TPSL_AFTER_ENTRY', True)
AUTOTRADE_MARKET_REDUCE_ON_RISK_BREACH = env_bool('AUTOTRADE_MARKET_REDUCE_ON_RISK_BREACH', False)
AUTOTRADE_MARKET_CLOSE_ON_EXIT_ATTACH_FAIL = env_bool('AUTOTRADE_MARKET_CLOSE_ON_EXIT_ATTACH_FAIL', False)
try:
    AUTOTRADE_STRICT_TPSL_ONLY = bool(_autotrade_bool_cfg(AUTOTRADE_CFG_STRICT_TPSL_ONLY_KEY, 'AUTOTRADE_STRICT_TPSL_ONLY', True))
    AUTOTRADE_IMMUTABLE_TPSL_AFTER_ENTRY = bool(_autotrade_immutable_tpsl_after_entry())
    AUTOTRADE_MARKET_REDUCE_ON_RISK_BREACH = bool(_autotrade_bool_cfg(AUTOTRADE_CFG_MARKET_REDUCE_ON_RISK_BREACH_KEY, 'AUTOTRADE_MARKET_REDUCE_ON_RISK_BREACH', False))
    AUTOTRADE_MARKET_CLOSE_ON_EXIT_ATTACH_FAIL = bool(_autotrade_bool_cfg(AUTOTRADE_CFG_MARKET_CLOSE_ON_EXIT_ATTACH_FAIL_KEY, 'AUTOTRADE_MARKET_CLOSE_ON_EXIT_ATTACH_FAIL', False))
    AUTOTRADE_REPORT_REQUIRE_VERIFIED_TPSL = bool(_autotrade_bool_cfg(AUTOTRADE_CFG_REPORT_REQUIRE_VERIFIED_TPSL_KEY, 'AUTOTRADE_REPORT_REQUIRE_VERIFIED_TPSL', True))
    AUTOTRADE_REPORT_INCLUDE_EXCHANGE_ONLY_FALLBACK = bool(_autotrade_bool_cfg(AUTOTRADE_CFG_REPORT_INCLUDE_EXCHANGE_ONLY_FALLBACK_KEY, 'AUTOTRADE_REPORT_INCLUDE_EXCHANGE_ONLY_FALLBACK', True))
except Exception:
    pass
AUTOTRADE_PREFILL_RISK_BUFFER_MULT = float(os.environ.get('AUTOTRADE_PREFILL_RISK_BUFFER_MULT', '0.92') or 0.92)
AUTOTRADE_F8_CLOSE_OPPOSITE_ENABLED = env_bool('AUTOTRADE_F8_CLOSE_OPPOSITE_ENABLED', False)
AUTOTRADE_F8_CLOSE_EXTERNAL_OPPOSITE = env_bool('AUTOTRADE_F8_CLOSE_EXTERNAL_OPPOSITE', False)


def _autotrade_setup_family_code(setup: Any) -> str:
    try:
        fam = str(getattr(setup, 'family_id', '') or '').strip()
        if fam:
            return _setup_family_id_to_code(fam)
    except Exception:
        pass
    try:
        return _setup_family_id_to_code(_family_id_from_engine(str(getattr(setup, 'engine', '') or ''), setup))
    except Exception:
        return ''


def _autotrade_f8_close_opposite_position_if_needed(uid: int, setup: Any, symbol: str, side: str) -> tuple[bool, str, dict]:
    """For F8 BigMove only: handle same-symbol opposite live exposure.

    Ver12 strict TP/SL-only policy: do not flatten the existing exposure just
    because a new opposite setup appears. If an opposite position is already open,
    the new setup is skipped and the existing position must finish by its native
    Bybit TP or SL, unless the owner manually runs /autotrade_flat_now.
    """
    detail = {'checked': False, 'action': 'none'}
    try:
        if not AUTOTRADE_F8_CLOSE_OPPOSITE_ENABLED:
            return (True, 'disabled', detail)
        if str(_autotrade_runtime_mode()).lower() != 'live':
            return (True, 'paper_or_not_live', detail)
        fam_code = _autotrade_setup_family_code(setup)
        if fam_code != 'F8':
            return (True, 'not_f8', detail)
        sym = _bybit_linear_symbol(symbol)
        sd = str(side or '').upper().strip()
        if sd not in {'BUY', 'SELL'}:
            return (False, 'bad_side_for_f8_opposite_close', detail)
        conflict = _autotrade_live_symbol_conflict(int(uid), sym, side=sd) or {}
        detail.update({'checked': True, 'conflict': conflict})
        if not bool(conflict.get('has_conflict')):
            return (True, 'no_conflict', detail)
        pos_side = str(conflict.get('position_side') or '').upper().strip()
        if pos_side == sd:
            return (False, 'f8_same_side_position_already_open', detail)
        if pos_side not in {'BUY', 'SELL'}:
            return (False, 'f8_unknown_existing_position_side', detail)
        owner_kind = str(conflict.get('owner_kind') or '').lower().strip()
        if owner_kind != 'bot' and not AUTOTRADE_F8_CLOSE_EXTERNAL_OPPOSITE:
            return (False, 'f8_opposite_external_position_not_closed', detail)
        if bool(globals().get('AUTOTRADE_STRICT_TPSL_ONLY', True)):
            detail.update({'action': 'blocked_new_f8_opposite_kept_existing_until_tp_sl', 'existing_side': pos_side})
            return (False, 'opposite_position_open_wait_for_existing_tp_sl', detail)

        qty = float(conflict.get('position_qty') or 0.0)
        close_res = _autotrade_force_close_live_position(sym, pos_side, qty=qty)
        detail.update({'action': 'closed_opposite', 'close_res': close_res, 'closed_side': pos_side, 'closed_qty': qty})
        if int((close_res or {}).get('retCode', -1)) != 0:
            return (False, f"f8_opposite_close_failed:{(close_res or {}).get('retMsg')}", detail)

        # Mark matching bot journal row closed so local duplicate gates do not block the new F8 setup.
        try:
            trade_id = str(conflict.get('trade_id') or '').strip()
            if trade_id:
                _autotrade_db_close_trade(trade_id, float(time.time()), 0.0, 'OPPOSITE_F8_CLOSE', 'closed_by_opposite_f8_bigmove_setup')
        except Exception:
            pass
        try:
            _autotrade_cancel_legacy_conditional_exit_orders(sym, side=pos_side)
            _bybit_invalidate_live_order_position_cache(sym)
        except Exception:
            pass
        time.sleep(1.2)
        return (True, 'opposite_position_closed_for_f8', detail)
    except Exception as exc:
        detail['error'] = f'{type(exc).__name__}: {exc}'
        return (False, 'f8_opposite_close_exception', detail)

def _bybit_position_idx_candidates(side: str | None = None, live_pos: dict | None = None) -> list[int]:
    vals: list[int] = []
    try:
        if live_pos:
            raw = live_pos.get('positionIdx')
            if raw is not None and str(raw).strip() != '':
                vals.append(int(float(raw)))
    except Exception:
        pass
    side_u = str(side or '').upper().strip()
    if side_u == 'BUY':
        vals.extend([1, 0, 2])
    elif side_u == 'SELL':
        vals.extend([2, 0, 1])
    else:
        vals.extend([0, 1, 2])
    out: list[int] = []
    for v in vals:
        try:
            iv = int(v)
        except Exception:
            continue
        if iv not in out:
            out.append(iv)
    return out or [0, 1, 2]


def _autotrade_apply_position_tp_sl(symbol: str, stop_loss: float, take_profit: float, side: str | None = None, live_pos: dict | None = None) -> dict:
    try:
        sym = _bybit_linear_symbol(symbol)
        best = {'retCode': -1, 'retMsg': 'tp_sl_not_attempted'}
        for pos_idx in _bybit_position_idx_candidates(side=side, live_pos=live_pos):
            payload = {
                'category': 'linear',
                'symbol': sym,
                'tpslMode': 'Full',
                'positionIdx': int(pos_idx),
                'tpOrderType': 'Market',
                'slOrderType': 'Market',
                'tpTriggerBy': str(AUTOTRADE_LIVE_TP_TRIGGER_BY),
                'slTriggerBy': str(AUTOTRADE_LIVE_TP_TRIGGER_BY),
                'stopLoss': str(float(stop_loss or 0.0)) if float(stop_loss or 0.0) > 0 else '0',
                'takeProfit': str(float(take_profit or 0.0)) if float(take_profit or 0.0) > 0 else '0',
            }
            res = _bybit_v5_request('POST', '/v5/position/trading-stop', payload)
            if int((res or {}).get('retCode', -1)) == 0:
                out = dict(res or {})
                try:
                    out['positionIdx_used'] = int(pos_idx)
                    out['request_payload'] = payload
                    out['placement'] = 'position_full_tpsl'
                except Exception:
                    pass
                try:
                    _bybit_invalidate_live_order_position_cache(sym)
                except Exception:
                    pass
                return out
            best = dict(res or {})
            try:
                best['positionIdx_used'] = int(pos_idx)
                best['request_payload'] = payload
            except Exception:
                pass
        return best
    except Exception as e:
        return {'retCode': -1, 'retMsg': f'{type(e).__name__}: {e}'}


def _autotrade_clear_position_full_tp_sl(symbol: str, side: str | None = None, live_pos: dict | None = None) -> dict:
    try:
        sym = _bybit_linear_symbol(symbol)
        best = {'retCode': -1, 'retMsg': 'clear_tp_sl_not_attempted'}
        for pos_idx in _bybit_position_idx_candidates(side=side, live_pos=live_pos):
            payload = {
                'category': 'linear',
                'symbol': sym,
                'takeProfit': '0',
                'stopLoss': '0',
                'tpslMode': 'Full',
                'positionIdx': int(pos_idx),
            }
            res = _bybit_v5_request('POST', '/v5/position/trading-stop', payload)
            if int((res or {}).get('retCode', -1)) == 0:
                out = dict(res or {})
                try:
                    out['positionIdx_used'] = int(pos_idx)
                    out['request_payload'] = payload
                except Exception:
                    pass
                return out
            best = dict(res or {})
            try:
                best['positionIdx_used'] = int(pos_idx)
                best['request_payload'] = payload
            except Exception:
                pass
        return best
    except Exception as e:
        return {'retCode': -1, 'retMsg': f'{type(e).__name__}: {e}'}



def _autotrade_exact_setup_exit_targets(trade_row: dict, side: str = '', fallback_entry: float = 0.0) -> dict:
    """Return immutable setup SL/TP for a live AutoTrade row.

    Critical safety rule: once a setup is emailed/executed, live TP/SL must stay
    based on that setup's stored prices, not on a later scan, live mark price,
    trailing recalculation, or another open row for the same symbol.
    """
    out = {'entry': 0.0, 'sl': 0.0, 'tp': 0.0, 'source': 'none'}
    try:
        row = dict(trade_row or {})
    except Exception:
        row = {}
    side_u = str(side or row.get('side') or '').upper().strip()

    def _valid(e, sl, tp):
        try:
            e = float(e or 0.0); sl = float(sl or 0.0); tp = float(tp or 0.0)
            if e <= 0 or sl <= 0 or tp <= 0:
                return False
            if side_u == 'SELL':
                return bool(sl > e and tp < e)
            return bool(sl < e and tp > e)
        except Exception:
            return False

    # yver72: the journal row is the immutable contract after entry. It is
    # written with the rounded live TP/SL that were sent to Bybit. Do not prefer
    # the original setup payload here because that can be an older/unrounded cache
    # or later-hydrated payload and would make the guardian move live TP/SL.
    try:
        e = float(row.get('entry') or fallback_entry or 0.0)
        sl = float(row.get('sl') or 0.0)
        tp = float(_resolve_single_tp(e, sl, row.get('tp'), row.get('alt_target_a'), row.get('alt_target_b'), side_u) or 0.0)
        if _valid(e, sl, tp):
            out.update({'entry': e, 'sl': sl, 'tp': tp, 'source': 'trade_row_immutable'})
            return out
    except Exception:
        pass

    # Fallback only for adopted/orphan rows that have no valid stored TP/SL.
    setup_id = str(row.get('setup_id') or '').strip()
    if setup_id:
        try:
            payload = _signal_setup_eval_payload(setup_id) or {}
            e = float(payload.get('entry') or row.get('entry') or fallback_entry or 0.0)
            sl = float(payload.get('sl') or 0.0)
            tp = float(_resolve_single_tp(e, sl, payload.get('tp'), payload.get('alt_target_a'), payload.get('alt_target_b'), side_u) or 0.0)
            if _valid(e, sl, tp):
                out.update({'entry': e, 'sl': sl, 'tp': tp, 'source': 'setup_payload_fallback_missing_row_targets'})
                return out
        except Exception:
            pass
    return out


def _autotrade_rr_value(entry: float, sl: float, tp: float, side: str) -> float:
    try:
        e = float(entry or 0.0); s = float(sl or 0.0); t = float(tp or 0.0)
        risk = abs(e - s)
        reward = abs(t - e)
        if e <= 0 or s <= 0 or t <= 0 or risk <= 0:
            return 0.0
        side_u = str(side or '').upper().strip()
        if side_u == 'SELL' and not (s > e and t < e):
            return 0.0
        if side_u != 'SELL' and not (s < e and t > e):
            return 0.0
        return float(reward / risk)
    except Exception:
        return 0.0


def _autotrade_cap_tp_to_rr(symbol: str, entry: float, sl: float, tp: float, side: str, max_rr: float) -> tuple[float, bool, float, float]:
    """Cap TP distance by live RR while preserving the existing SL risk geometry.

    Returns (new_tp, capped, old_rr, new_rr). This is used only before creating a new
    AutoTrade TP/SL order. It does not automatically rewrite already-open positions.
    """
    try:
        e = float(entry or 0.0); s = float(sl or 0.0); t = float(tp or 0.0)
        side_u = str(side or '').upper().strip()
        cap = float(max_rr or 0.0)
        old_rr = _autotrade_rr_value(e, s, t, side_u)
        if e <= 0 or s <= 0 or t <= 0 or cap <= 0 or old_rr <= cap:
            return float(t), False, float(old_rr or 0.0), float(old_rr or 0.0)
        risk = abs(e - s)
        if side_u == 'SELL':
            raw_tp = e - risk * cap
            rounding = ROUND_DOWN
        else:
            raw_tp = e + risk * cap
            rounding = ROUND_UP
        try:
            new_tp = _round_price_to_tick(str(symbol or ''), float(raw_tp), rounding=rounding)
        except Exception:
            new_tp = float(raw_tp)
        new_rr = _autotrade_rr_value(e, s, new_tp, side_u)
        if new_tp <= 0 or new_rr <= 0:
            return float(t), False, float(old_rr or 0.0), float(old_rr or 0.0)
        return float(new_tp), True, float(old_rr or 0.0), float(new_rr or 0.0)
    except Exception:
        return float(tp or 0.0), False, 0.0, 0.0

def _autotrade_repair_live_exit_protection(uid: int, trade_row: dict, live_pos: dict | None = None) -> dict:
    """Repair AutoTrade exits using native Full-position TP/SL only.

    This intentionally does NOT create or accept standalone Conditional reduce-only
    orders. If an old pf_tp/pf_cond conditional row exists, it is cancelled after the
    position-level TP/SL is attached/confirmed.
    """
    result = {
        'checked': False,
        'sl_fixed': False,
        'tp_fixed': False,
        'tp_order_fixed': False,
        'be_applied': False,
        'symbol': '',
        'side': '',
        'placement': 'position_full_tpsl',
        'legacy_conditional_cancelled': 0,
    }
    try:
        if str(_autotrade_runtime_mode()).lower() != 'live':
            return result
        if not trade_row:
            return result
        sym = _bybit_linear_symbol(str(trade_row.get('symbol') or ''))
        side = str(trade_row.get('side') or '').upper().strip()
        result['symbol'] = sym
        result['side'] = side
        if side not in {'BUY', 'SELL'} or not sym:
            return result
        pos = live_pos or _autotrade_find_live_position(sym, side=side)
        if not pos:
            return result
        result['checked'] = True

        entry = float(_pos_entry(pos) or trade_row.get('entry') or 0.0)
        fixed_targets = _autotrade_exact_setup_exit_targets(trade_row, side=side, fallback_entry=entry)
        target_sl = float((fixed_targets or {}).get('sl') or 0.0)
        target_tp = float((fixed_targets or {}).get('tp') or 0.0)
        result['target_source'] = str((fixed_targets or {}).get('source') or '')
        if target_sl <= 0 or target_tp <= 0:
            result['pending_missing'] = ['SL' if target_sl <= 0 else '', 'TP' if target_tp <= 0 else '']
            result['pending_missing'] = [x for x in result['pending_missing'] if x]
            return result
        # Never repair a live position using inverted/low-RR targets. This prevents
        # the guardian from changing a clean setup into a poor RR or unsafe SL.
        live_rr_for_targets = _autotrade_rr_value(entry, target_sl, target_tp, side)
        result['wanted_rr_live'] = float(live_rr_for_targets or 0.0)
        if live_rr_for_targets < 1.0:
            result['error'] = f'fixed_targets_rr_below_1 entry={entry:g} sl={target_sl:g} tp={target_tp:g}'
            return result

        native_sl = float(_pos_native_stop_loss(pos) or 0.0)
        native_tp = float(_pos_native_take_profit(pos) or 0.0)
        native_sl_ok = bool(native_sl > 0 and _price_close_enough(native_sl, target_sl, rel_tol=0.0020))
        native_tp_ok = bool(native_tp > 0 and _price_close_enough(native_tp, target_tp, rel_tol=0.0020))
        result.update({
            'wanted_sl': float(target_sl),
            'wanted_tp': float(target_tp),
            'native_sl_before': float(native_sl or 0.0),
            'native_tp_before': float(native_tp or 0.0),
            'native_sl_ok_before': bool(native_sl_ok),
            'native_tp_ok_before': bool(native_tp_ok),
        })

        # yver72 immutable TP/SL rule: once Bybit already has both native Full
        # position TP and SL, never move them in the background guardian. A live
        # position can only have one Full TP/SL in one-way mode; changing it later
        # is exactly the behaviour the forward test must avoid. The guardian still
        # fixes missing TP/SL and still cleans legacy standalone Conditional exits.
        if bool(_autotrade_immutable_tpsl_after_entry()) and native_sl > 0 and native_tp > 0 and not (native_sl_ok and native_tp_ok):
            immutable_liq_detail = {}
            try:
                # Keep the fixed exchange SL/TP, but still allow leverage-only safety
                # repair if liquidation would sit before the existing native SL.
                liq_px = float(_pos_liq_price(pos) or 0.0)
                entry_for_liq = float(_pos_entry(pos) or entry or 0.0)
                if liq_px > 0 and not _autotrade_live_liq_guard_ok(side, liq_px, native_sl, entry_for_liq, _autotrade_runtime_liq_buffer_pct()):
                    lev_start = int(float((pos or {}).get('leverage') or _autotrade_runtime_leverage() or 1))
                    immutable_liq_detail = _autotrade_adjust_live_liq_beyond_sl(sym, side, native_sl, entry_for_liq, lev_start) or {}
            except Exception as _immut_liq_exc:
                immutable_liq_detail = {'error': f'{type(_immut_liq_exc).__name__}: {_immut_liq_exc}'}
            cancelled_before = _autotrade_cancel_legacy_conditional_exit_orders(sym, side=side)
            partial_cancelled_before = _autotrade_cancel_partial_tpsl_exit_orders(sym, side=side)
            result.update({
                'immutable_existing_tpsl_kept': True,
                'sl_fixed': False,
                'tp_fixed': False,
                'pending_missing': [],
                'legacy_conditional_cancelled': int(cancelled_before or 0),
                'partial_tpsl_cancelled': int(partial_cancelled_before or 0),
                'native_sl_after': float(native_sl or 0.0),
                'native_tp_after': float(native_tp or 0.0),
                'immutable_liq_repair': immutable_liq_detail,
                'reason': 'existing_native_tpsl_not_moved_after_entry',
            })
            return result

        # Liquidation must stay beyond the setup SL. If leverage is unsafe, lower it
        # before applying/repairing TP/SL. If it cannot be made safe, flatten rather
        # than leaving a position where liquidation can happen before stop-loss.
        try:
            liq_px = float(_pos_liq_price(pos) or 0.0)
            if liq_px > 0 and not _autotrade_live_liq_guard_ok(side, liq_px, target_sl, entry, _autotrade_runtime_liq_buffer_pct()):
                lev_start = int(float((pos or {}).get('leverage') or _autotrade_runtime_leverage() or 1))
                adj = _autotrade_adjust_live_liq_beyond_sl(sym, side, target_sl, entry, lev_start)
                result['liq_repair'] = adj
                if not bool((adj or {}).get('ok')):
                    if bool(globals().get('AUTOTRADE_STRICT_TPSL_ONLY', True)) and not bool(globals().get('AUTOTRADE_MARKET_CLOSE_ON_EXIT_ATTACH_FAIL', False)):
                        result['liq_unsafe_not_closed_strict_tpsl_only'] = True
                        result['error'] = f'liq_before_sl_unfixable_no_market_close liq={liq_px:g} sl={target_sl:g}'
                        # Continue to re-apply native TP/SL; no intermediate market close.
                    else:
                        qty_to_close = abs(float(_pos_size(pos) or 0.0))
                        close_res = _autotrade_force_close_live_position(sym, side, qty=qty_to_close)
                        result['liq_unsafe_force_close'] = close_res
                        result['error'] = f'liq_before_sl_unfixable liq={liq_px:g} sl={target_sl:g}'
                        return result
                pos = (adj or {}).get('position') or _autotrade_find_live_position(sym, side=side) or pos
                entry = float(_pos_entry(pos) or entry or 0.0)
        except Exception as _liq_exc:
            result['liq_guard_error'] = f'{type(_liq_exc).__name__}: {_liq_exc}'

        # Always cleanup legacy standalone Conditional exits for this symbol/side.
        # If native TP/SL is already correct, this still reduces Orders count.
        cancelled_before = _autotrade_cancel_legacy_conditional_exit_orders(sym, side=side)
        partial_cancelled_before = _autotrade_cancel_partial_tpsl_exit_orders(sym, side=side)

        attach_res = {}
        if not (native_sl_ok and native_tp_ok):
            attach_res = _autotrade_attach_position_full_tpsl_and_cleanup(sym, side, target_sl, target_tp, live_pos=pos)
        else:
            attach_res = {
                'ok': True,
                'placement': 'position_full_tpsl',
                'reason': 'native_full_tpsl_already_correct',
                'legacy_conditional_cancelled_before': int(cancelled_before or 0),
                'partial_tpsl_cancelled_before': int(partial_cancelled_before or 0),
            }
            # Run one more cleanup after a fresh order snapshot in case cache hid old rows.
            attach_res['legacy_conditional_cancelled_after'] = _autotrade_cancel_legacy_conditional_exit_orders(sym, side=side)
            attach_res['partial_tpsl_cancelled_after'] = _autotrade_cancel_partial_tpsl_exit_orders(sym, side=side)
            attach_res['legacy_conditional_cancelled'] = int(attach_res.get('legacy_conditional_cancelled_before') or 0) + int(attach_res.get('legacy_conditional_cancelled_after') or 0)
            attach_res['partial_tpsl_cancelled'] = int(attach_res.get('partial_tpsl_cancelled_before') or 0) + int(attach_res.get('partial_tpsl_cancelled_after') or 0)

        result['attach_res'] = attach_res
        result['legacy_conditional_cancelled'] = int(cancelled_before or 0) + int((attach_res or {}).get('legacy_conditional_cancelled') or 0)
        result['partial_tpsl_cancelled'] = int(partial_cancelled_before or 0) + int((attach_res or {}).get('partial_tpsl_cancelled') or 0)
        ok, confirm = _autotrade_confirm_position_full_tpsl(sym, side, target_sl, target_tp, wait_sec=1.5)
        result['confirm'] = confirm or {}
        result['sl_fixed'] = bool(ok and (confirm or {}).get('sl_ok'))
        result['tp_fixed'] = bool(ok and (confirm or {}).get('tp_ok'))
        result['tp_order_fixed'] = False
        result['pending_missing'] = [name for name, flag in (('SL', not result['sl_fixed']), ('TP', not result['tp_fixed'])) if bool(flag)]
        return result
    except Exception as exc:
        result['error'] = f'{type(exc).__name__}: {exc}'
        return result

def _ts_seconds_from_any(value) -> float:
    try:
        if value in (None, "", 0, "0"):
            return 0.0
        v = float(value)
        if v <= 0:
            return 0.0
        return (v / 1000.0) if v > 10_000_000_000 else v
    except Exception:
        return 0.0


def _bybit_order_reduce_only(order: dict) -> bool:
    try:
        for key in ('reduceOnly', 'reduce_only', 'closeOnTrigger', 'close_on_trigger'):
            val = order.get(key)
            if isinstance(val, bool) and val:
                return True
            sval = str(val or '').strip().lower()
            if sval in {'true', '1', 'yes', 'y'}:
                return True
    except Exception:
        pass
    return False


def _bybit_order_filled_time_ts(order: dict) -> float:
    try:
        for key in ('updatedTime', 'updated_time', 'createdTime', 'created_time', 'orderTime', 'execTime', 'transactTime'):
            ts = _ts_seconds_from_any(order.get(key))
            if ts > 0:
                return ts
    except Exception:
        pass
    return 0.0


def _bybit_order_avg_price(order: dict) -> float:
    try:
        for key in ('avgPrice', 'avg_price', 'price', 'triggerPrice', 'trigger_price'):
            v = float(order.get(key) or 0.0)
            if v > 0:
                return v
    except Exception:
        pass
    return 0.0


def _bybit_order_filled_qty(order: dict) -> float:
    try:
        for key in ('cumExecQty', 'cum_exec_qty', 'cumFilledQty', 'filledQty', 'qty'):
            v = float(order.get(key) or 0.0)
            if v > 0:
                return abs(v)
    except Exception:
        pass
    return 0.0


def _bybit_get_recent_filled_orders_linear(symbol: str, lookback_hours: int = 168, limit: int = 200) -> list[dict]:
    """Recent filled order history for one linear symbol.

    We use this for live-position attribution only. The result is cached briefly because
    /status and /autotrade_debug may be called back-to-back.
    """
    sym = _bybit_linear_symbol(symbol)
    cache_key = f"bybit_order_history:{sym}:{int(lookback_hours)}:{int(limit)}"
    try:
        if cache_valid(cache_key, 30):
            return list(cache_get(cache_key) or [])
    except Exception:
        pass

    end_ms = int(time.time() * 1000)
    start_ms = int((time.time() - max(1, int(lookback_hours)) * 3600.0) * 1000)
    payload = {
        'category': 'linear',
        'symbol': sym,
        'startTime': start_ms,
        'endTime': end_ms,
        'limit': int(max(20, min(int(limit), 200))),
    }
    out = []
    try:
        res = _bybit_v5_request('GET', '/v5/order/history', payload)
        if int((res or {}).get('retCode', -1)) == 0:
            out = (((res or {}).get('result') or {}).get('list') or [])
    except Exception:
        out = []

    try:
        cache_set(cache_key, list(out or []))
    except Exception:
        pass
    return list(out or [])


def _autotrade_resolve_live_position_open_info(uid: int, p: dict, journal_open: Optional[list[dict]] = None) -> dict:
    """Resolve the authoritative open timestamp for one live Bybit position.

    Evidence priority:
    1) Matching autotrade journal OPEN row (authoritative for the bot's anchored trading-day accounting).
    2) Bybit filled order history for the same symbol/side and same-position characteristics.
    3) Bybit live position createdTime.

    Why journal-first:
    - Bybit aggregate positions can be updated or scaled in later, which can make exchange-side
      timestamps look newer than the real open for today's /dayreset bucket.
    - The bot's own open-trade journal is the most reliable source for deciding whether a live
      position is carried from a prior anchored day or opened today.
    """
    sym = _pos_symbol(p)
    side = _pos_side_text(p)
    entry = float(_pos_entry(p) or 0.0)
    size = abs(float(_pos_size(p) or 0.0))
    position_created_ts = _ts_seconds_from_any(p.get('createdTime') or p.get('created_time'))
    position_updated_ts = _ts_seconds_from_any(p.get('updatedTime') or p.get('updated_time'))

    info = {
        'symbol': sym,
        'side': side,
        'opened_ts': 0.0,
        'source': 'unknown',
        'position_created_ts': float(position_created_ts or 0.0),
        'position_updated_ts': float(position_updated_ts or 0.0),
        'journal_ts': 0.0,
        'journal_trade_id': '',
        'exchange_order_ts': 0.0,
        'exchange_order_id': '',
        'exchange_order_price': 0.0,
        'exchange_order_qty': 0.0,
        'notes': '',
    }

    def _entry_rel_diff(a: float, b: float) -> float:
        try:
            a = float(a or 0.0)
            b = float(b or 0.0)
            if a <= 0 or b <= 0:
                return 999.0
            return abs(a - b) / max(abs(a), abs(b), 1e-9)
        except Exception:
            return 999.0

    def _qty_rel_diff(a: float, b: float) -> float:
        try:
            a = abs(float(a or 0.0))
            b = abs(float(b or 0.0))
            if a <= 0 or b <= 0:
                return 999.0
            return abs(a - b) / max(a, b, 1e-9)
        except Exception:
            return 999.0

    journal_matches = []
    for t in (journal_open or []):
        try:
            if str(t.get('symbol') or '').upper() != str(sym).upper():
                continue
            if str(t.get('side') or '').upper() != str(side).upper():
                continue
            j_entry = float(t.get('entry') or 0.0)
            j_qty = abs(float(t.get('qty') or 0.0))
            entry_rel = _entry_rel_diff(j_entry, entry)
            qty_rel = _qty_rel_diff(j_qty, size)
            if entry_rel <= 0.0075 or qty_rel <= 0.35:
                journal_matches.append((entry_rel, qty_rel, -float(t.get('opened_ts') or 0.0), t))
        except Exception:
            continue
    if journal_matches:
        best_journal = sorted(journal_matches, key=lambda x: (x[0], x[1], x[2]))[0][3]
        try:
            info['journal_ts'] = float(best_journal.get('opened_ts') or 0.0)
            info['journal_trade_id'] = str(best_journal.get('trade_id') or '')
        except Exception:
            pass

    order_candidates = []
    try:
        for o in _bybit_get_recent_filled_orders_linear(sym, lookback_hours=168, limit=200):
            try:
                if _bybit_linear_symbol(str(o.get('symbol') or '')) != sym:
                    continue
                o_side = str(o.get('side') or '').upper().strip()
                if o_side != side:
                    continue
                if _bybit_order_reduce_only(o):
                    continue
                o_status = str(o.get('orderStatus') or '').upper().strip()
                o_qty = _bybit_order_filled_qty(o)
                if o_status not in {'FILLED', 'PARTIALLYFILLED', 'PARTIALLY_FILLED', ''} and o_qty <= 0:
                    continue
                ts = _bybit_order_filled_time_ts(o)
                if ts <= 0:
                    continue
                o_price = _bybit_order_avg_price(o)
                entry_rel = _entry_rel_diff(o_price, entry)
                qty_rel = _qty_rel_diff(o_qty, size)
                if entry_rel <= 0.0075 or qty_rel <= 0.35:
                    order_candidates.append((entry_rel, qty_rel, ts, o))
            except Exception:
                continue
    except Exception:
        order_candidates = []

    if order_candidates:
        best_entry_rel = min(x[0] for x in order_candidates)
        shortlist = [x for x in order_candidates if x[0] <= max(best_entry_rel + 0.0015, 0.0080)]
        best_order = sorted(shortlist, key=lambda x: (x[2], x[0], x[1]))[0][3]
        info['exchange_order_ts'] = _bybit_order_filled_time_ts(best_order)
        info['exchange_order_id'] = str(best_order.get('orderId') or best_order.get('orderLinkId') or '')
        info['exchange_order_price'] = float(_bybit_order_avg_price(best_order) or 0.0)
        info['exchange_order_qty'] = float(_bybit_order_filled_qty(best_order) or 0.0)

    exchange_ts = float(info.get('exchange_order_ts') or 0.0)
    journal_ts = float(info.get('journal_ts') or 0.0)
    created_ts = float(info.get('position_created_ts') or 0.0)

    if journal_ts > 0:
        info['opened_ts'] = journal_ts
        info['source'] = 'autotrade_journal'
        if exchange_ts > 0 and abs(exchange_ts - journal_ts) > 3600.0:
            info['notes'] = 'exchange_ts_ignored_for_day_bucket'
    elif exchange_ts > 0:
        info['opened_ts'] = exchange_ts
        info['source'] = 'bybit_order_history'
    elif created_ts > 0:
        info['opened_ts'] = created_ts
        info['source'] = 'bybit_position_created'
    else:
        info['opened_ts'] = 0.0
        info['source'] = 'unknown'

    return info


def _autotrade_realized_pnl_today(uid: int, now_utc: Optional[datetime] = None) -> float:
    """Realized PnL for autotrade journal rows closed inside the active trading-day window."""
    try:
        user = _autotrade_user_settings(int(uid))
        start_utc, end_utc = _admin_today_window_utc(now_utc, uid=int(uid), user=user)
        start_ts = int(start_utc.timestamp())
        end_ts = int(end_utc.timestamp())
        with sqlite3.connect(DB_PATH) as conn:
            cur = conn.cursor()
            cur.execute(
                "SELECT COALESCE(SUM(pnl_usdt), 0) FROM autotrade_trades WHERE uid=? AND closed_ts IS NOT NULL AND closed_ts>=? AND closed_ts<?",
                (int(uid), start_ts, end_ts),
            )
            row = cur.fetchone()
            return float((row[0] if row else 0.0) or 0.0)
    except Exception:
        return 0.0




def _bybit_closed_pnl_event_ts(row: dict) -> float:
    try:
        for key in ('updatedTime', 'updated_time', 'createdTime', 'created_time', 'execTime', 'fillTime'):
            ts = _ts_seconds_from_any((row or {}).get(key))
            if ts > 0:
                return ts
    except Exception:
        pass
    return 0.0


def _bybit_closed_pnl_event_qty(row: dict) -> float:
    try:
        for key in ('closedSize', 'closed_size', 'qty', 'size', 'closedQty', 'execQty'):
            v = float((row or {}).get(key) or 0.0)
            if v > 0:
                return abs(v)
    except Exception:
        pass
    return 0.0


def _opposite_side_text(side: str) -> str:
    s = str(side or '').upper().strip()
    if s == 'BUY':
        return 'SELL'
    if s == 'SELL':
        return 'BUY'
    return s


def _bybit_closed_pnl_event_side_candidates(row: dict) -> set[str]:
    """Return possible open-side labels that may correspond to a closed-pnl row.

    Bybit payloads are inconsistent across endpoints / environments: some rows expose the
    original position side, while others can look like the closing execution side. We accept
    both the raw side and its opposite when reconciling journal rows so close-sync and
    performance reporting remain robust.
    """
    raw = str((row or {}).get('side') or '').upper().strip()
    out = set()
    if raw:
        out.add(raw)
        opp = _opposite_side_text(raw)
        if opp:
            out.add(opp)
    return out or {'BUY', 'SELL'}




def _bybit_closed_pnl_position_side(row: dict) -> str:
    """Infer the original position side for a Bybit Closed-PnL row.

    Bybit Closed P&L can expose the closing execution side, not the original
    position side. For reporting/reconciliation we need the original position
    side so SELL winners such as 1000PEPE are matched to SELL setup rows instead
    of being shown as BUY/NO_SETUP. Use entry/exit prices + realised PnL when
    available; fall back to the exchange side only when inference is impossible.
    """
    raw = str((row or {}).get('side') or '').upper().strip()
    if raw not in {'BUY', 'SELL'}:
        raw = ''
    def _num(keys):
        for k in keys:
            try:
                v = (row or {}).get(k)
                if v not in (None, ''):
                    x = abs(float(v or 0.0))
                    if x > 0:
                        return x
            except Exception:
                pass
        return 0.0
    try:
        entry = _num(('avgEntryPrice', 'avg_entry_price', 'entryPrice', 'entry_price', 'createdPrice', 'openPrice'))
        exitp = _num(('avgExitPrice', 'avg_exit_price', 'exitPrice', 'exit_price', 'orderPrice', 'price', 'closedPrice'))
        pnl = float((row or {}).get('closedPnl') if (row or {}).get('closedPnl') is not None else (row or {}).get('closed_pnl') if (row or {}).get('closed_pnl') is not None else (row or {}).get('pnl') or 0.0)
        if entry > 0 and exitp > 0 and abs(exitp - entry) > max(entry * 1e-7, 1e-12) and abs(pnl) >= 0.05:
            if pnl > 0:
                return 'BUY' if exitp > entry else 'SELL'
            if pnl < 0:
                return 'BUY' if exitp < entry else 'SELL'
    except Exception:
        pass
    return raw or ''


def _bybit_closed_pnl_original_side_candidates(row: dict) -> set[str]:
    """Candidate original position sides, preferring price/PnL inference."""
    try:
        inferred = _bybit_closed_pnl_position_side(row)
        if inferred in {'BUY', 'SELL'}:
            return {inferred}
    except Exception:
        pass
    return _bybit_closed_pnl_event_side_candidates(row)

def _bybit_get_closed_pnl_linear(start_ts: float, end_ts: float, symbol: str | None = None, limit: int = 200) -> list[dict]:
    """Fetch Bybit closed-PnL rows for the requested window.

    Best-effort pagination is used because the exchange may return a cursor.
    """
    if str(_autotrade_runtime_mode()).lower() != 'live' or not BYBIT_API_KEY or not BYBIT_API_SECRET:
        return []
    start_ms = int(max(0.0, float(start_ts or 0.0)) * 1000)
    end_ms = int(max(float(end_ts or 0.0), float(start_ts or 0.0)) * 1000)
    sym = _bybit_linear_symbol(symbol) if symbol else None
    out = []
    cursor = None
    seen = set()
    for _ in range(8):
        payload = {
            'category': 'linear',
            'startTime': start_ms,
            'endTime': end_ms,
            'limit': int(max(20, min(int(limit or 200), 200))),
        }
        if sym:
            payload['symbol'] = sym
        if cursor:
            payload['cursor'] = cursor
        try:
            res = _bybit_v5_request('GET', '/v5/position/closed-pnl', payload)
            if int((res or {}).get('retCode', -1)) != 0:
                break
            result = (res or {}).get('result') or {}
            rows = result.get('list') or []
            if not rows:
                break
            added = 0
            for r in rows:
                try:
                    key = (
                        _bybit_linear_symbol(str((r or {}).get('symbol') or '')),
                        str((r or {}).get('side') or '').upper().strip(),
                        int(_bybit_closed_pnl_event_ts(r) or 0),
                        str((r or {}).get('orderId') or (r or {}).get('execId') or ''),
                        float((r or {}).get('closedPnl') or 0.0),
                    )
                    if key in seen:
                        continue
                    seen.add(key)
                    out.append(r)
                    added += 1
                except Exception:
                    continue
            cursor = str(result.get('nextPageCursor') or result.get('nextPageToken') or '').strip()
            if not cursor or added <= 0:
                break
        except Exception:
            break
    return list(out)


def _bybit_closed_pnl_summary(start_ts: float, end_ts: float, symbol: str | None = None) -> dict:
    """Summarize Bybit closed-PnL rows inside a UTC window.

    Returns exchange-truth totals for the anchored trading day so /status and
    /autotrade_debug can reflect live realized results even before journal
    reconciliation finishes.
    """
    rows = _bybit_get_closed_pnl_linear(start_ts, end_ts, symbol=symbol, limit=200) or []
    net_pnl = 0.0
    realized_loss = 0.0
    count = 0
    normalized_rows = []
    for r in rows:
        try:
            ts = float(_bybit_closed_pnl_event_ts(r) or 0.0)
            if ts <= 0 or ts < float(start_ts) or ts >= float(end_ts):
                continue
            pnl = float((r or {}).get('closedPnl') or (r or {}).get('closed_pnl') or 0.0)
            net_pnl += pnl
            if pnl < 0:
                realized_loss += abs(pnl)
            count += 1
            normalized_rows.append(r)
        except Exception:
            continue
    return {
        'rows': normalized_rows,
        'count': int(count),
        'net_pnl': float(net_pnl),
        'realized_loss': float(realized_loss),
    }


def _autotrade_db_close_trade(trade_id: str, closed_ts: float, pnl_usdt: float, outcome: str, note_append: str = '') -> None:
    try:
        with sqlite3.connect(DB_PATH) as conn:
            cur = conn.cursor()
            row = cur.execute("SELECT note, symbol, side FROM autotrade_trades WHERE trade_id=?", (str(trade_id),)).fetchone()
            old_note = str((row[0] if row else '') or '')
            old_symbol = str((row[1] if row else '') or '')
            old_side = str((row[2] if row else '') or '')
            note_parts = [old_note.strip()] if old_note and old_note.strip() else []
            extra = str(note_append or '').strip()
            if extra and extra not in note_parts:
                note_parts.append(extra)
            merged_note = ' | '.join([x for x in note_parts if x])
            cur.execute(
                """UPDATE autotrade_trades
                   SET status='CLOSED', closed_ts=?, pnl_usdt=?, outcome=?, note=?
                   WHERE trade_id=?""",
                (int(float(closed_ts or 0.0)), float(pnl_usdt or 0.0), str(outcome or '').upper().strip(), merged_note, str(trade_id)),
            )
            conn.commit()
            try:
                life = cur.execute("SELECT setup_id FROM admin_setup_lifecycle WHERE trade_id=? LIMIT 1", (str(trade_id),)).fetchone()
                sid = str((life[0] if life else '') or '')
            except Exception:
                sid = ''
        if sid:
            _admin_setup_lifecycle_merge(
                int(AUTOTRADE_OWNER_UID or 0), sid,
                symbol=old_symbol,
                side=old_side,
                closed_ts=float(closed_ts or 0.0),
                state='closed',
                outcome=str(outcome or '').upper().strip(),
                pnl_usdt=float(pnl_usdt or 0.0),
                last_reason=str(note_append or ''),
            )
    except Exception:
        pass


def _autotrade_sync_closed_trades_from_exchange(uid: int, now_utc: Optional[datetime] = None, lookback_days: int = 14) -> dict:
    """Reconcile OPEN journal rows against live Bybit state and closed-PnL history.

    This is the missing link between live exchange closures and the bot's day accounting.
    Without this sync, /status and /autotrade_debug can only see still-open positions plus
    whatever was manually written into autotrade_trades.
    """
    summary = {'checked': 0, 'closed': 0, 'matched_events': 0}
    if str(_autotrade_runtime_mode()).lower() != 'live':
        return summary
    try:
        open_rows = _autotrade_db_open_trades(int(uid)) or []
    except Exception:
        open_rows = []
    if not open_rows:
        return summary

    try:
        live_positions = _bybit_get_open_positions_linear() or []
    except Exception:
        live_positions = []
    live_keys = {
        (str(_pos_symbol(p) or '').upper(), str(_pos_side_text(p) or '').upper())
        for p in (live_positions or [])
    }

    now_ts = float((now_utc or datetime.now(timezone.utc)).astimezone(timezone.utc).timestamp())
    min_open_ts = min(float(t.get('opened_ts') or now_ts) for t in open_rows) if open_rows else now_ts
    start_ts = max(0.0, min(min_open_ts, now_ts) - 86400.0 * max(1, int(lookback_days)))
    closed_rows = _bybit_get_closed_pnl_linear(start_ts, now_ts, limit=200)

    event_pool: dict[tuple[str, str], list[dict]] = defaultdict(list)
    for r in (closed_rows or []):
        try:
            sym = str(_bybit_linear_symbol((r or {}).get('symbol') or '')).upper()
            if not sym:
                continue
            ts = float(_bybit_closed_pnl_event_ts(r) or 0.0)
            if ts <= 0:
                continue
            pnl = float((r or {}).get('closedPnl') or 0.0)
            qty = float(_bybit_closed_pnl_event_qty(r) or 0.0)
            event = {
                'ts': ts,
                'pnl': pnl,
                'qty': qty,
                'raw': r,
                'used': False,
            }
            for side in _bybit_closed_pnl_event_side_candidates(r):
                event_pool[(sym, side)].append(event)
        except Exception:
            continue
    for key in list(event_pool.keys()):
        event_pool[key].sort(key=lambda x: (float(x.get('ts') or 0.0), float(x.get('qty') or 0.0)))

    rows_by_key: dict[tuple[str, str], list[dict]] = defaultdict(list)
    for t in open_rows:
        try:
            key = (str(t.get('symbol') or '').upper(), str(t.get('side') or '').upper())
            rows_by_key[key].append(t)
        except Exception:
            continue
    for key in list(rows_by_key.keys()):
        rows_by_key[key].sort(key=lambda x: float(x.get('opened_ts') or 0.0))

    for key, trades in rows_by_key.items():
        events = event_pool.get(key) or []
        for idx, trade in enumerate(trades):
            summary['checked'] += 1
            sym, side = key
            if key in live_keys:
                continue
            trade_id = str(trade.get('trade_id') or '')
            opened_ts = float(trade.get('opened_ts') or 0.0)
            trade_qty = abs(float(trade.get('qty') or 0.0))
            next_open_ts = None
            for later in trades[idx + 1:]:
                later_ts = float(later.get('opened_ts') or 0.0)
                if later_ts > opened_ts:
                    next_open_ts = later_ts
                    break

            candidates = []
            for ev in events:
                if ev.get('used'):
                    continue
                ev_ts = float(ev.get('ts') or 0.0)
                if ev_ts <= 0 or ev_ts + 300.0 < opened_ts:
                    continue
                if next_open_ts and ev_ts >= next_open_ts:
                    continue
                candidates.append(ev)
            if not candidates:
                continue

            matched = []
            matched_qty = 0.0
            matched_pnl = 0.0
            for ev in candidates:
                matched.append(ev)
                matched_pnl += float(ev.get('pnl') or 0.0)
                matched_qty += abs(float(ev.get('qty') or 0.0))
                if trade_qty > 0 and matched_qty > 0 and matched_qty >= trade_qty * 0.80:
                    break
                if trade_qty <= 0:
                    break
            if not matched:
                continue

            close_ts = max(float(ev.get('ts') or 0.0) for ev in matched)
            for ev in matched:
                ev['used'] = True
            outcome = 'BREAKEVEN'
            if matched_pnl > 0:
                outcome = 'WIN'
            elif matched_pnl < 0:
                outcome = 'LOSS'
            note_bits = ['exchange_close_sync']
            if len(matched) > 1:
                note_bits.append(f'partial_close_events={len(matched)}')
            _autotrade_db_close_trade(trade_id, close_ts, matched_pnl, outcome, ' | '.join(note_bits))
            summary['closed'] += 1
            summary['matched_events'] += len(matched)
    return summary


def _autotrade_trade_day_label(ts: float, user: dict) -> str:
    try:
        dt_local = datetime.fromtimestamp(float(ts), _user_tzinfo(user))
        start_local, _ = _anchored_day_window(dt_local, _user_day_reset_hhmm(user))
        return start_local.strftime('%Y-%m-%d')
    except Exception:
        return ''




def _autotrade_reconstruct_provisional_closes(uid: int, days: int = 7) -> list[dict]:
    """Conservative admin-history fallback for older deployments.

    Uses historical setup identity + exchange closed-PnL events when older journal rows are
    missing. This is only used to avoid a useless all-zero performance report after upgrades.
    It never overrides journal-confirmed bot trades.
    """
    if str(_autotrade_runtime_mode()).lower() != 'live':
        return []
    days = int(max(2, min(int(days or 7), 3650)))
    user = _autotrade_user_settings(int(uid))
    tz = _user_tzinfo(user)
    start_local, end_local = _anchored_day_window(datetime.now(tz), _user_day_reset_hhmm(user))
    start_local = start_local - timedelta(days=days - 1)
    start_ts = float(start_local.astimezone(timezone.utc).timestamp())
    end_ts = float(end_local.astimezone(timezone.utc).timestamp())

    try:
        journal_trades = db_list_autotrade_trades_all(int(uid)) or []
    except Exception:
        journal_trades = []

    trade_state_by_id: dict[str, dict] = {}
    for t in (journal_trades or []):
        try:
            tid = str((t or {}).get('trade_id') or '').strip()
            if not tid:
                continue
            trade_state_by_id[tid] = {
                'status': str((t or {}).get('status') or '').upper().strip(),
                'closed_ts': float((t or {}).get('closed_ts') or 0.0),
                'symbol': str(_bybit_linear_symbol((t or {}).get('symbol') or '')).upper(),
                'side': str((t or {}).get('side') or '').upper().strip(),
            }
        except Exception:
            continue

    live_keys = set()
    if str(_autotrade_runtime_mode()).lower() == 'live':
        try:
            for p in (_bybit_get_open_positions_linear() or []):
                sym = str(_bybit_linear_symbol(_pos_symbol(p)) or '').upper()
                side = str(_pos_side_text(p) or '').upper().strip()
                if sym and side:
                    live_keys.add((sym, side))
        except Exception:
            live_keys = set()

    closed_rows = _bybit_get_closed_pnl_linear(max(0.0, start_ts - 86400.0 * 5.0), end_ts, limit=300) or []
    if not closed_rows:
        return []

    journal_event_keys = set()
    for t in journal_trades:
        try:
            if float(t.get('closed_ts') or 0.0) <= 0:
                continue
            sym = str(t.get('symbol') or '').upper()
            side = str(t.get('side') or '').upper()
            cts = float(t.get('closed_ts') or 0.0)
            pnl = round(float(t.get('pnl') or 0.0), 8)
            journal_event_keys.add((sym, side, int(cts // 60), pnl))
            journal_event_keys.add((sym, _opposite_side_text(side), int(cts // 60), pnl))
        except Exception:
            continue

    try:
        with sqlite3.connect(DB_PATH) as con:
            con.row_factory = sqlite3.Row
            cur = con.cursor()
            rows = cur.execute(
                """
                WITH candidates AS (
                    SELECT e.setup_id AS setup_id,
                           e.user_id AS user_id,
                           e.emailed_ts AS emailed_ts,
                           0.0 AS generated_ts,
                           'emailed_setups' AS source_kind
                    FROM emailed_setups e
                    WHERE e.user_id = ?
                      AND e.emailed_ts >= ?
                    UNION ALL
                    SELECT g.setup_id AS setup_id,
                           g.user_id AS user_id,
                           0.0 AS emailed_ts,
                           MAX(g.created_ts) AS generated_ts,
                           'generated_setups' AS source_kind
                    FROM generated_setups g
                    WHERE g.user_id = ?
                      AND g.created_ts >= ?
                      AND COALESCE(NULLIF(g.setup_id,''),'') <> ''
                    GROUP BY g.user_id, g.setup_id
                )
                SELECT c.setup_id,
                       MAX(c.emailed_ts) AS emailed_ts,
                       MAX(c.generated_ts) AS generated_ts,
                       MIN(c.source_kind) AS source_kind,
                       COALESCE(MAX(l.executed_ts), 0) AS executed_ts,
                       COALESCE(MAX(l.closed_ts), 0) AS lifecycle_closed_ts,
                       COALESCE(MAX(NULLIF(l.trade_id,'')), '') AS trade_id,
                       COALESCE(MAX(NULLIF(l.symbol,'')), MAX(NULLIF(s.symbol,'')), MAX(NULLIF(g.symbol,'')), '') AS symbol,
                       COALESCE(MAX(NULLIF(l.side,'')), MAX(NULLIF(s.side,'')), MAX(NULLIF(g.side,'')), '') AS side,
                       COALESCE(MAX(NULLIF(l.state,'')), '') AS state,
                       COALESCE(MAX(s.created_ts), 0) AS signal_created_ts
                FROM candidates c
                LEFT JOIN admin_setup_lifecycle l ON l.setup_id = c.setup_id
                LEFT JOIN signals s ON s.setup_id = c.setup_id
                LEFT JOIN generated_setups g ON g.setup_id = c.setup_id AND g.user_id = c.user_id
                GROUP BY c.setup_id
                ORDER BY MAX(c.emailed_ts) ASC, MAX(c.generated_ts) ASC, COALESCE(MAX(s.created_ts),0) ASC, c.setup_id ASC
                """,
                (int(uid), float(start_ts - 86400.0 * 3.0), int(uid), float(start_ts - 86400.0 * 3.0)),
            ).fetchall() or []
            setup_rows = [dict(r) for r in rows]
    except Exception:
        setup_rows = []

    if not setup_rows:
        return []

    grouped: dict[str, list[dict]] = defaultdict(list)
    for r in setup_rows:
        sym = str(r.get('symbol') or '').upper()
        if not sym:
            continue
        base_ts = float(r.get('executed_ts') or 0.0) or float(r.get('emailed_ts') or 0.0) or float(r.get('generated_ts') or 0.0) or float(r.get('signal_created_ts') or 0.0)
        if base_ts <= 0:
            continue
        r['_base_ts'] = base_ts
        grouped[sym].append(r)
    for key in list(grouped.keys()):
        grouped[key].sort(key=lambda x: (float(x.get('_base_ts') or 0.0), str(x.get('setup_id') or '')))

    event_pool: dict[str, list[dict]] = defaultdict(list)
    for r in closed_rows:
        try:
            sym = str(_bybit_linear_symbol((r or {}).get('symbol') or '')).upper()
            ts = float(_bybit_closed_pnl_event_ts(r) or 0.0)
            pnl = round(float((r or {}).get('closedPnl') or 0.0), 8)
            if not sym or ts <= 0:
                continue
            qty = float(_bybit_closed_pnl_event_qty(r) or 0.0)
            sides = sorted(_bybit_closed_pnl_event_side_candidates(r))
            if any((sym, side, int(ts // 60), pnl) in journal_event_keys for side in sides):
                continue
            ev = {
                'ts': ts,
                'pnl': pnl,
                'qty': qty,
                'raw': r,
                'used': False,
                'sides': set(sides),
            }
            event_pool[sym].append(ev)
        except Exception:
            continue
    for key in list(event_pool.keys()):
        event_pool[key].sort(key=lambda x: (float(x.get('ts') or 0.0), abs(float(x.get('qty') or 0.0))))

    provisional = []
    for sym, setups in grouped.items():
        events = event_pool.get(sym) or []
        if not events:
            continue
        for i, srow in enumerate(setups):
            try:
                row_trade_id = str(srow.get('trade_id') or '').strip()
                setup_side = str(srow.get('side') or '').upper().strip()
                if float(srow.get('lifecycle_closed_ts') or 0.0) > 0:
                    continue
                if row_trade_id:
                    st = dict(trade_state_by_id.get(row_trade_id) or {})
                    if float(st.get('closed_ts') or 0.0) > 0 or str(st.get('status') or '').upper().strip() == 'CLOSED':
                        continue
                    if st and setup_side and (str(sym or '').upper(), setup_side) in live_keys:
                        continue
                base_ts = float(srow.get('_base_ts') or 0.0)
                if base_ts <= 0:
                    continue
                next_ts = None
                for later in setups[i+1:]:
                    later_ts = float(later.get('_base_ts') or 0.0)
                    if later_ts > base_ts:
                        next_ts = later_ts
                        break
                best = None
                fallback = None
                for ev in events:
                    if ev.get('used'):
                        continue
                    ev_ts = float(ev.get('ts') or 0.0)
                    if ev_ts + 300.0 < base_ts:
                        continue
                    if next_ts and ev_ts >= next_ts:
                        continue
                    if fallback is None:
                        fallback = ev
                    if not setup_side or setup_side in (ev.get('sides') or set()):
                        best = ev
                        break
                best = best or fallback
                if not best:
                    continue
                best['used'] = True
                pnl = float(best.get('pnl') or 0.0)
                provisional.append({
                    'setup_id': str(srow.get('setup_id') or ''),
                    'symbol': sym,
                    'side': setup_side,
                    'opened_ts': base_ts,
                    'closed_ts': float(best.get('ts') or 0.0),
                    'pnl': pnl,
                    'qty': abs(float(best.get('qty') or 0.0)),
                    'outcome': 'WIN' if pnl > 0 else ('LOSS' if pnl < 0 else 'BREAKEVEN'),
                    'provisional': True,
                    'note': 'provisional_exchange_match_from_setup_history',
                })
            except Exception:
                continue
    return provisional


def _autotrade_exchange_close_fallback_rows(uid: int, days: int = 7) -> list[dict]:
    """Last-resort exchange-close fallback for performance reporting.

    Used only when the bot journal has no usable closed trades for the requested window.
    It aggregates raw Bybit closed-PnL events inside the anchored trading-day window and
    excludes any events already represented by journal-confirmed or provisional matches.
    """
    if str(_autotrade_runtime_mode()).lower() != 'live':
        return []
    days = int(max(2, min(int(days or 7), 3650)))
    user = _autotrade_user_settings(int(uid))
    tz = _user_tzinfo(user)
    start_local, end_local = _anchored_day_window(datetime.now(tz), _user_day_reset_hhmm(user))
    start_local = start_local - timedelta(days=days - 1)
    start_ts = float(start_local.astimezone(timezone.utc).timestamp())
    end_ts = float(end_local.astimezone(timezone.utc).timestamp())

    excluded = set()
    try:
        for t in (db_list_autotrade_trades_all(int(uid)) or []):
            try:
                cts = float(t.get('closed_ts') or 0.0)
                if cts < start_ts or cts >= end_ts:
                    continue
                sym = str(t.get('symbol') or '').upper()
                side = str(t.get('side') or '').upper()
                pnl = round(float(t.get('pnl') or 0.0), 8)
                excluded.add((sym, side, int(cts), pnl))
            except Exception:
                continue
    except Exception:
        pass

    try:
        for t in (_autotrade_reconstruct_provisional_closes(int(uid), days=days) or []):
            try:
                cts = float(t.get('closed_ts') or 0.0)
                sym = str(t.get('symbol') or '').upper()
                side = str(t.get('side') or '').upper()
                pnl = round(float(t.get('pnl') or 0.0), 8)
                excluded.add((sym, side, int(cts), pnl))
            except Exception:
                continue
    except Exception:
        pass

    fallback = []
    for ev in (_bybit_get_closed_pnl_linear(start_ts, end_ts, limit=max(200, days * 80)) or []):
        try:
            sym = str(_bybit_linear_symbol((ev or {}).get('symbol') or '')).upper()
            ts = float(_bybit_closed_pnl_event_ts(ev) or 0.0)
            pnl = round(float((ev or {}).get('closedPnl') or 0.0), 8)
            if not sym or ts <= 0:
                continue
            sides = _bybit_closed_pnl_original_side_candidates(ev) or _bybit_closed_pnl_event_side_candidates(ev) or {''}
            if any((sym, str(side or '').upper(), int(ts), pnl) in excluded for side in sides):
                continue
            matched_side = ''
            for side in sides:
                key = (sym, str(side or '').upper(), int(ts), pnl)
                if key in excluded:
                    matched_side = str(side or '').upper()
                    break
            if not matched_side:
                matched_side = str(_bybit_closed_pnl_position_side(ev) or (sorted(sides)[0] if sides else '')).upper()
            fallback.append({
                'symbol': sym,
                'side': matched_side,
                'opened_ts': 0.0,
                'closed_ts': ts,
                'pnl': float(pnl),
                'qty': float(_bybit_closed_pnl_event_qty(ev) or 0.0),
                'outcome': 'WIN' if pnl > 0 else ('LOSS' if pnl < 0 else 'BREAKEVEN'),
                'exchange_only': True,
                'note': 'exchange_only_fallback_close',
            })
        except Exception:
            continue
    return fallback


def _autotrade_performance_rows(uid: int, days: int = 7) -> list[dict]:
    """Journal-first bot lifecycle performance rows.

    Primary source stays the bot journal. If older deployments are missing journal rows,
    a conservative *emailed-setup-linked* provisional fallback is added first, followed by
    a raw exchange-close fallback. Unlike older versions, fallback reconciliation is applied
    even when journal history is only partial.
    """
    days = int(max(2, min(int(days or 7), 3650)))
    user = _autotrade_user_settings(int(uid))
    _autotrade_sync_closed_trades_from_exchange(int(uid), lookback_days=max(14, days + 5))
    try:
        trades = db_list_autotrade_trades_all(int(uid)) or []
    except Exception:
        trades = []

    tz = _user_tzinfo(user)
    start_local, _ = _anchored_day_window(datetime.now(tz), _user_day_reset_hhmm(user))
    day_starts = [start_local - timedelta(days=i) for i in range(days - 1, -1, -1)]
    by_day: dict[str, dict] = {}
    for ds in day_starts:
        by_day[ds.strftime('%Y-%m-%d')] = {
            'day': ds.strftime('%Y-%m-%d'),
            'opened': 0,
            'closed': 0,
            'wins': 0,
            'losses': 0,
            'net_pnl': 0.0,
            'avg_win': 0.0,
            'avg_loss': 0.0,
            'gross_profit': 0.0,
            'gross_loss': 0.0,
            'journal_confirmed_closes': 0,
            'exchange_reconciled_closes': 0,
            'provisional_emailed_setup_closes': 0,
            'exchange_only_fallback_closes': 0,
        }

    def _label(ts: float) -> str:
        return _autotrade_trade_day_label(ts, user)

    for t in trades:
        try:
            ots = float(t.get('opened_ts') or 0.0)
            if ots > 0:
                lab = _label(ots)
                if lab in by_day:
                    by_day[lab]['opened'] += 1
            cts = float(t.get('closed_ts') or 0.0)
            if cts <= 0:
                continue
            lab = _label(cts)
            if lab not in by_day:
                continue
            pnl = float(t.get('pnl') or 0.0)
            row = by_day[lab]
            row['closed'] += 1
            row['journal_confirmed_closes'] += 1
            if 'exchange_close_sync' in str(t.get('note') or ''):
                row['exchange_reconciled_closes'] += 1
            row['net_pnl'] += pnl
            if pnl > 0:
                row['wins'] += 1
                row['gross_profit'] += pnl
            elif pnl < 0:
                row['losses'] += 1
                row['gross_loss'] += abs(pnl)
        except Exception:
            continue

    for t in _autotrade_reconstruct_provisional_closes(int(uid), days=days):
        try:
            lab = _label(float(t.get('closed_ts') or 0.0))
            if lab not in by_day:
                continue
            row = by_day[lab]
            row['closed'] += 1
            row['exchange_reconciled_closes'] += 1
            row['provisional_emailed_setup_closes'] += 1
            open_lab = _label(float(t.get('opened_ts') or 0.0))
            if open_lab in by_day:
                by_day[open_lab]['opened'] += 1
            pnl = float(t.get('pnl') or 0.0)
            row['net_pnl'] += pnl
            if pnl > 0:
                row['wins'] += 1
                row['gross_profit'] += pnl
            elif pnl < 0:
                row['losses'] += 1
                row['gross_loss'] += abs(pnl)
        except Exception:
            continue

    # Exchange-truth fallback: if local journal/provisional rows miss live Bybit closes,
    # add the missing close count/PnL by anchored day so /performance_report does not stay at zero.
    try:
        if str(_autotrade_runtime_mode()).lower() == 'live' and BYBIT_API_KEY and BYBIT_API_SECRET:
            start_ts = float(day_starts[0].astimezone(timezone.utc).timestamp())
            end_ts = float((day_starts[-1] + timedelta(days=1)).astimezone(timezone.utc).timestamp())
            raw_rows = _bybit_get_closed_pnl_linear(start_ts, end_ts, limit=max(200, days * 80)) or []
            raw_by_day = defaultdict(lambda: {'closed': 0, 'wins': 0, 'losses': 0, 'net': 0.0, 'gp': 0.0, 'gl': 0.0})
            for ev in raw_rows:
                ts_ev = float(_bybit_closed_pnl_event_ts(ev) or 0.0)
                if ts_ev <= 0:
                    continue
                lab = _label(ts_ev)
                if lab not in by_day:
                    continue
                pnl = float((ev or {}).get('closedPnl') or (ev or {}).get('closed_pnl') or 0.0)
                raw_by_day[lab]['closed'] += 1
                raw_by_day[lab]['net'] += pnl
                if pnl > 0:
                    raw_by_day[lab]['wins'] += 1
                    raw_by_day[lab]['gp'] += pnl
                elif pnl < 0:
                    raw_by_day[lab]['losses'] += 1
                    raw_by_day[lab]['gl'] += abs(pnl)
            for lab, raw in raw_by_day.items():
                row = by_day.get(lab)
                if not row:
                    continue
                if int(raw.get('closed') or 0) > int(row.get('closed') or 0):
                    row['exchange_only_fallback_closes'] += int(raw.get('closed') or 0) - int(row.get('closed') or 0)
                    row['closed'] = int(raw.get('closed') or 0)
                    row['wins'] = int(raw.get('wins') or 0)
                    row['losses'] = int(raw.get('losses') or 0)
                    row['net_pnl'] = float(raw.get('net') or 0.0)
                    row['gross_profit'] = float(raw.get('gp') or 0.0)
                    row['gross_loss'] = float(raw.get('gl') or 0.0)
    except Exception:
        pass

    for row in by_day.values():
        win_n = int(row.get('wins') or 0)
        loss_n = int(row.get('losses') or 0)
        gp = float(row.get('gross_profit') or 0.0)
        gl = float(row.get('gross_loss') or 0.0)
        row['avg_win'] = (gp / win_n) if win_n > 0 else 0.0
        row['avg_loss'] = (-(gl / loss_n)) if loss_n > 0 else 0.0
    return [by_day[ds.strftime('%Y-%m-%d')] for ds in day_starts]

def _autotrade_performance_summary(rows: list[dict]) -> dict:
    closed = sum(int(r.get('closed') or 0) for r in rows)
    wins = sum(int(r.get('wins') or 0) for r in rows)
    losses = sum(int(r.get('losses') or 0) for r in rows)
    net = sum(float(r.get('net_pnl') or 0.0) for r in rows)
    gross_profit = sum(float(r.get('gross_profit') or 0.0) for r in rows)
    gross_loss = sum(float(r.get('gross_loss') or 0.0) for r in rows)
    best_day = max(rows, key=lambda r: float(r.get('net_pnl') or 0.0)) if rows else None
    worst_day = min(rows, key=lambda r: float(r.get('net_pnl') or 0.0)) if rows else None
    win_rate = (wins / (wins + losses) * 100.0) if (wins + losses) > 0 else 0.0
    profit_factor = (gross_profit / gross_loss) if gross_loss > 0 else (float('inf') if gross_profit > 0 else 0.0)
    avg_win = (gross_profit / wins) if wins > 0 else 0.0
    avg_loss = (-(gross_loss / losses)) if losses > 0 else 0.0
    expectancy = (net / closed) if closed > 0 else 0.0
    return {
        'closed': closed,
        'wins': wins,
        'losses': losses,
        'net': net,
        'win_rate': win_rate,
        'profit_factor': profit_factor,
        'avg_win': avg_win,
        'avg_loss': avg_loss,
        'best_day': best_day,
        'worst_day': worst_day,
        'expectancy': expectancy,
    }

def _autotrade_daily_used_from_open_and_realized(open_risk_usd: float, realized_net_usd: float) -> float:
    """Conservative daily risk usage for AutoTrade.

    Positive realised PnL should reduce remaining risk pressure; realised losses
    should add to risk used.  Algebraically this is max(0, open_risk - realised_net),
    but the split form avoids accidental sign inversions in display/report code.
    """
    try:
        open_risk = max(0.0, float(open_risk_usd or 0.0))
    except Exception:
        open_risk = 0.0
    try:
        realised = float(realized_net_usd or 0.0)
    except Exception:
        realised = 0.0
    realised_profit = max(0.0, realised)
    realised_loss = max(0.0, -realised)
    return max(0.0, open_risk + realised_loss - realised_profit)


def _autotrade_day_risk_metrics(uid: int, equity: float) -> dict:
    """Compute authoritative AutoTrade day metrics using the configured trading-day window.

    Live-position day bucketing uses one authoritative open timestamp per current Bybit position.
    That timestamp is resolved from exchange evidence first, then matching journal state, then
    position.createdTime as a final fallback.
    """
    cap = 0.0
    open_pnl = 0.0
    realized_pnl_today = 0.0
    realized_loss_today = 0.0
    mode = str(_autotrade_runtime_mode()).lower()
    user = _autotrade_user_settings(uid)

    try:
        if equity and equity > 0:
            user = dict(user)
            user["equity"] = float(equity)
    except Exception:
        pass

    try:
        cap = float(_autotrade_daily_cap_usd(int(uid), float(equity or 0.0)) or 0.0) if equity and equity > 0 else 0.0
    except Exception:
        cap = 0.0

    try:
        if mode == "live":
            _autotrade_sync_closed_trades_from_exchange(int(uid), lookback_days=14)
    except Exception:
        pass

    start_utc, end_utc = _admin_today_window_utc(uid=int(uid), user=user)
    closed_summary = {'count': 0, 'net_pnl': 0.0, 'realized_loss': 0.0}
    try:
        if mode == "live":
            closed_summary = _bybit_closed_pnl_summary(float(start_utc.timestamp()), float(end_utc.timestamp()))
            realized_pnl_today = float(closed_summary.get('net_pnl') or 0.0)
            realized_loss_today = float(closed_summary.get('realized_loss') or 0.0)
        else:
            realized_pnl_today = float(_autotrade_realized_pnl_today(int(uid)) or 0.0)
            realized_loss_today = max(0.0, -float(realized_pnl_today))
    except Exception:
        realized_pnl_today = 0.0
        realized_loss_today = 0.0
        closed_summary = {'count': 0, 'net_pnl': 0.0, 'realized_loss': 0.0}

    start_ts = float(start_utc.timestamp())
    end_ts = float(end_utc.timestamp())

    current_total_open_risk = 0.0
    current_day_open_risk = 0.0
    live_open_risk_charged_today = 0.0
    carried_open_risk = 0.0
    open_positions_now = 0
    inherited_open_positions = 0
    opened_today_count = 0
    closed_today_count = 0
    closed_today_rows = []
    position_classifications = []

    try:
        with sqlite3.connect(DB_PATH) as conn:
            cur = conn.cursor()
            cur.execute(
                "SELECT COUNT(*) FROM autotrade_trades WHERE uid=? AND opened_ts>=? AND opened_ts<?",
                (int(uid), int(start_ts), int(end_ts)),
            )
            row = cur.fetchone()
            opened_today_count = int((row[0] if row else 0) or 0)
    except Exception:
        opened_today_count = 0
    try:
        closed_today_rows = _autotrade_closed_activity_rows_window(int(uid), float(start_ts), float(end_ts)) or []
        closed_today_count = int(len(closed_today_rows))
        if closed_today_rows:
            realized_pnl_today = float(sum(
                float((r or {}).get('pnl_usdt') if (r or {}).get('pnl_usdt') is not None else (r or {}).get('pnl') or 0.0)
                for r in closed_today_rows
            ))
            realized_loss_today = float(sum(
                abs(float((r or {}).get('pnl_usdt') if (r or {}).get('pnl_usdt') is not None else (r or {}).get('pnl') or 0.0))
                for r in closed_today_rows
                if float((r or {}).get('pnl_usdt') if (r or {}).get('pnl_usdt') is not None else (r or {}).get('pnl') or 0.0) < 0.0
            ))
        elif mode == "live":
            closed_today_count = int(closed_summary.get('count') or 0)
    except Exception:
        closed_today_rows = []
        closed_today_count = int(closed_summary.get('count') or 0) if mode == "live" else 0

    journal_open = []
    try:
        journal_open = _autotrade_db_open_trades(int(uid)) or []
    except Exception:
        journal_open = []

    def _opened_ts_from_trade(t: dict) -> float:
        try:
            return float(t.get('opened_ts') or 0.0)
        except Exception:
            return 0.0

    external_open_positions = 0
    external_open_risk = 0.0
    external_open_pnl = 0.0

    if mode == "live":
        try:
            buckets = _autotrade_live_position_bucket_rows(int(uid), journal_open=journal_open, fallback_unmatched_as_owned=True)
        except Exception:
            buckets = {}
        open_positions_now = int(buckets.get('open_positions_now') or 0)
        open_pnl = float(buckets.get('open_pnl') or 0.0)
        current_total_open_risk = float(buckets.get('current_total_open_risk') or 0.0)
        current_day_open_risk = float(buckets.get('current_day_open_risk') or 0.0)
        carried_open_risk = float(buckets.get('carried_open_risk') or 0.0)
        inherited_open_positions = int(buckets.get('inherited_open_positions') or 0)
        position_classifications = list(buckets.get('position_classifications') or [])
        external_open_positions = int(buckets.get('external_open_positions') or 0)
        external_open_risk = float(buckets.get('external_open_risk') or 0.0)
        external_open_pnl = float(buckets.get('external_open_pnl') or 0.0)
        current_day_open_positions = max(0, int(open_positions_now) - int(inherited_open_positions))
        live_open_risk_charged_today = float(current_day_open_risk)
        opened_today_count = max(int(opened_today_count), int(current_day_open_positions))
        opened_today_count = max(int(opened_today_count), int(closed_today_count) + int(current_day_open_positions))
    else:
        open_positions_now = len(journal_open)
        for t in journal_open:
            est = max(0.0, float(_autotrade_estimated_risk_usd(float(t.get('entry') or 0.0), float(t.get('sl') or 0.0), float(t.get('qty') or 0.0)) or 0.0))
            opened_ts = _opened_ts_from_trade(t)
            current_total_open_risk += est
            if opened_ts and opened_ts < start_ts:
                bucket = 'carried'
                carried_open_risk += est
                inherited_open_positions += 1
            else:
                bucket = 'current_day'
                current_day_open_risk += est
            position_classifications.append({
                'symbol': str(t.get('symbol') or '').upper(),
                'side': str(t.get('side') or '').upper(),
                'risk': float(est),
                'opened_ts': float(opened_ts or 0.0),
                'bucket': bucket,
                'source': 'autotrade_journal',
                'journal_ts': float(opened_ts or 0.0),
                'position_created_ts': 0.0,
                'exchange_order_ts': 0.0,
                'notes': '',
            })
        open_pnl = 0.0

    # Ver17: conservative AutoTrade cap accounting. Charge ALL current live AT risk
    # against the daily cap, not only positions opened after the day reset. This avoids
    # old/carried positions making Daily risk used look artificially low.
    if float(live_open_risk_charged_today or 0.0) <= 0.0:
        live_open_risk_charged_today = float(current_total_open_risk)
    live_open_risk_charged_today = max(float(current_total_open_risk or 0.0), float(live_open_risk_charged_today or 0.0))
    raw_daily_used_total = _autotrade_daily_used_from_open_and_realized(float(live_open_risk_charged_today), float(realized_pnl_today))
    effective_daily_used_total, reset_credit = _risk_day_reset_effective_used(int(uid), user, raw_daily_used_total)
    remaining_raw = float("inf") if cap <= 0 else (float(cap) - float(effective_daily_used_total))
    over_by = abs(float(remaining_raw)) if cap > 0 and remaining_raw < 0 else 0.0

    return {
        "cap": float(cap),
        "open_risk": float(current_total_open_risk),
        "used_risk": float(current_day_open_risk),
        "used_total": float(effective_daily_used_total),
        "used_total_raw": float(raw_daily_used_total),
        "risk_reset_credit": float(reset_credit),
        "open_pnl": float(open_pnl),
        "realized_pnl_today": float(realized_pnl_today),
        "realized_loss_today": float(realized_loss_today),
        "remaining": float(remaining_raw),
        "over_by": float(over_by),
        "current_total_open_risk": float(current_total_open_risk),
        "current_day_open_risk": float(current_day_open_risk),
        "live_open_risk_charged_today": float(live_open_risk_charged_today),
        "carried_open_risk": float(carried_open_risk),
        "open_positions_now": int(open_positions_now),
        "inherited_open_positions": int(inherited_open_positions),
        "opened_today_count": int(opened_today_count),
        "closed_today_count": int(closed_today_count),
        "closed_today_rows": closed_today_rows,
        "day_start_ts": float(start_ts),
        "day_end_ts": float(end_ts),
        "position_classifications": position_classifications,
        "external_open_positions": int(external_open_positions),
        "external_open_risk": float(external_open_risk),
        "external_open_pnl": float(external_open_pnl),
    }

def _autotrade_user_settings(uid: int) -> dict:
    """Return user dict after daily reset (so caps are current)."""
    try:
        return reset_daily_if_needed(get_user(int(uid)) or {})
    except Exception:
        return get_user(int(uid)) or {}

def _autotrade_per_trade_risk_usd(uid: int, equity: float) -> float:
    """AutoTrade per-position risk from /autotrade_config only.

    This must NOT use the manual /riskmode value. Manual trading and AutoTrade
    have separate risk controls; /autotrade_config AUTOTRADE_RISK_PER_TRADE_PCT
    is the source of truth for live bot entries.
    """
    try:
        eq = float(equity or 0.0)
    except Exception:
        eq = 0.0
    if eq <= 0:
        return 0.0
    try:
        pct = float(_autotrade_risk_per_trade_pct() or 0.0)
    except Exception:
        pct = float(AUTOTRADE_RISK_PER_TRADE_PCT or 0.0)
    pct = max(0.0, float(pct or 0.0))
    return float(_risk_amount_from_pct(eq, pct) or 0.0)

def _autotrade_daily_cap_usd(uid: int, equity: float) -> float:
    user = _autotrade_user_settings(uid)
    try:
        if equity and equity > 0:
            user = dict(user)
            user["equity"] = float(equity)
    except Exception:
        pass
    mode, val = _autotrade_daily_cap_settings()
    if mode == 'USD':
        return max(0.0, float(val or 0.0))
    eq = _effective_equity_for_risk(user, prefer_live=(str(_autotrade_runtime_mode()).lower() == 'live'))
    if eq <= 0:
        return 0.0
    return _risk_amount_from_pct(eq, float(val or 0.0))

def _autotrade_remaining_risk_usd(uid: int, equity: float) -> float:
    """Remaining AutoTrade risk from AutoTrade daily-cap settings only."""
    try:
        cap = float(_autotrade_daily_cap_usd(int(uid), float(equity or 0.0)) or 0.0)
        m = _autotrade_day_risk_metrics_cached(int(uid), float(equity or 0.0), ttl=3, force_refresh=True)
        used = float(m.get('used_total') or m.get('current_day_open_risk') or 0.0)
    except Exception:
        cap = 0.0
        used = 0.0
    if cap <= 0:
        return float("inf")
    return max(0.0, float(cap) - float(used))

def _autotrade_db_init():
    with sqlite3.connect(DB_PATH) as conn:
        c = conn.cursor()
        c.execute('''
            CREATE TABLE IF NOT EXISTS autotrade_trades (
                trade_id TEXT PRIMARY KEY,
                uid INTEGER,
                opened_ts INTEGER,
                day_utc TEXT NOT NULL DEFAULT \'\',
                session TEXT,
                setup_id TEXT,
                symbol TEXT,
                side TEXT,
                entry REAL,
                sl REAL,
                tp REAL,
                alt_target_a REAL,
                alt_target_b REAL,
                qty REAL,
                conf INTEGER,
                quality_score REAL,
                atr_pct REAL,
                engine TEXT,
                status TEXT DEFAULT 'OPEN',
                closed_ts INTEGER,
                outcome TEXT,
                pnl REAL
            )
        ''')
        c.execute("CREATE INDEX IF NOT EXISTS idx_autotrade_uid_opened ON autotrade_trades(uid, opened_ts)")
        c.execute("CREATE INDEX IF NOT EXISTS idx_autotrade_status ON autotrade_trades(status)")
        conn.commit()

def _autotrade_db_open_trades(uid: int) -> list[dict]:
    with sqlite3.connect(DB_PATH) as conn:
        conn.row_factory = sqlite3.Row
        c = conn.cursor()
        c.execute("SELECT * FROM autotrade_trades WHERE uid=? AND status='OPEN' ORDER BY opened_ts DESC", (uid,))
        return [dict(r) for r in c.fetchall()]

def _autotrade_db_get_trade(trade_id: str) -> dict:
    tid = str(trade_id or '').strip()
    if not tid:
        return {}
    try:
        with sqlite3.connect(DB_PATH) as conn:
            conn.row_factory = sqlite3.Row
            cur = conn.cursor()
            row = cur.execute("SELECT * FROM autotrade_trades WHERE trade_id=? LIMIT 1", (tid,)).fetchone()
            return dict(row) if row else {}
    except Exception:
        return {}



def _autotrade_trade_insert_cols(cur, payload: dict, preferred_order: list[str]) -> tuple[list[str], list]:
    """Return schema-safe INSERT columns/values for autotrade_trades.

    Some long-lived production SQLite DBs still contain legacy NOT NULL columns
    such as tp1. This helper always includes any required column that exists in
    the live schema, using safe single-TP compatible defaults, so a Bybit order
    cannot be opened and then fail to journal because of an old DB constraint.
    """
    try:
        info = list(cur.execute("PRAGMA table_info(autotrade_trades)").fetchall())
    except Exception:
        info = []
    cols = [str(r[1]) for r in info]
    live_payload = dict(payload or {})

    # Legacy/synonym columns used by older deployed DBs. Keep single-TP model:
    # tp1 mirrors tp, higher TPs stay zero/empty.
    tp_val = live_payload.get('tp')
    if tp_val is None:
        tp_val = live_payload.get(LEGACY_TP_COL) or live_payload.get('tp1') or 0.0
    for name in ('tp1', LEGACY_TP_COL, 'take_profit', 'target', 'target_price'):
        if name in cols and name not in live_payload:
            live_payload[name] = float(tp_val or 0.0)
    for name in ('tp2', 'tp3'):
        if name in cols and name not in live_payload:
            live_payload[name] = 0.0

    now_ts = float(live_payload.get('created_ts') or live_payload.get('updated_ts') or time.time())
    opened_ts = int(float(live_payload.get('opened_ts') or now_ts) or now_ts)
    defaults = {
        'created_ts': now_ts,
        'updated_ts': now_ts,
        'opened_ts': opened_ts,
        'day_utc': live_payload.get('day_utc') or datetime.fromtimestamp(opened_ts, tz=timezone.utc).strftime('%Y-%m-%d'),
        'status': live_payload.get('status') or 'OPEN',
        'outcome': live_payload.get('outcome') or '',
        'note': live_payload.get('note') or '',
        'family_id': live_payload.get('family_id') or '',
        'regime_primary': live_payload.get('regime_primary') or '',
        'allocator_plan_id': live_payload.get('allocator_plan_id') or '',
        'param_set_id': live_payload.get('param_set_id') or '',
        'setup_strategy': live_payload.get('setup_strategy') or live_payload.get('strategy') or live_payload.get('strategy_mode') or 'NORMAL',
        'original_setup_id': live_payload.get('original_setup_id') or '',
        'original_side': live_payload.get('original_side') or '',
        'strategy_reason': live_payload.get('strategy_reason') or '',
    }
    for k, v in defaults.items():
        if k in cols and (k not in live_payload or live_payload.get(k) is None):
            live_payload[k] = v

    insert_cols = [name for name in preferred_order if name in cols and name in live_payload]
    used = set(insert_cols)

    # Include every NOT NULL-without-default legacy column that is not already
    # covered. SQLite table_info columns: cid, name, type, notnull, dflt_value, pk.
    #
    # IMPORTANT: some long-lived Render DBs have a legacy primary-key column named
    # `id` in addition to (or instead of) `trade_id`. The previous schema-safe
    # filler treated unknown required TEXT columns as an empty string, or INTEGER
    # PKs as 0.0. That made every live autotrade journal attempt collide on
    # autotrade_trades.id.
    #
    # Rules here:
    #   • INTEGER PRIMARY KEY / rowid aliases are omitted so SQLite allocates them.
    #   • TEXT/legacy PK ids are populated with the unique trade_id.
    #   • other required legacy columns still get safe defaults.
    for r in info:
        name = str(r[1])
        col_type = str(r[2] or '').upper()
        name_l = name.lower()
        notnull = bool(r[3])
        dflt = r[4]
        pk = bool(r[5])
        if name in used:
            continue
        if not (notnull or pk) or dflt is not None:
            continue

        is_integer_pk = bool(pk and any(t in col_type for t in ('INT',)))
        if pk and is_integer_pk and name not in live_payload:
            # Do NOT insert id=0/0.0 for SQLite rowid primary keys.
            continue

        if name not in live_payload:
            if pk or name_l in {'id', 'uuid', 'journal_id'}:
                live_payload[name] = str(live_payload.get('trade_id') or f"AT-{int(time.time())}-{uuid.uuid4().hex[:8].upper()}")
            elif name_l in {'setup_strategy','strategy','strategy_mode'}:
                live_payload[name] = str(live_payload.get('setup_strategy') or live_payload.get('strategy') or live_payload.get('strategy_mode') or 'NORMAL')
            elif name_l in {'original_setup_id','original_side','strategy_reason','strategy_meta_json'}:
                live_payload[name] = str(live_payload.get(name) or '')
            elif name_l in {'tp1', 'take_profit', 'target', 'target_price'}:
                live_payload[name] = float(tp_val or 0.0)
            elif name_l in {'tp2', 'tp3', 'pnl', 'pnl_usdt', 'qty', 'entry', 'sl', 'tp', 'conf', 'quality_score', 'atr_pct', 'risk_usd', 'risk_pct', 'tp_usd', 'risk_multiplier', 'dynamic_risk_score', 'configured_risk_pct', 'allowed_risk_pct', 'rr_tp'} or any(t in col_type for t in ('INT', 'REAL', 'NUM', 'FLOAT', 'DOUBLE')):
                live_payload[name] = 0.0
            else:
                live_payload[name] = ''
        insert_cols.append(name)
        used.add(name)

    values = [live_payload.get(name) for name in insert_cols]
    return insert_cols, values

def _autotrade_db_insert_open_trade_row(uid: int, trade_row: dict) -> str:
    """Insert or replace an OPEN autotrade journal row from recovered live-position evidence."""
    _autotrade_migrate_tables()
    trade_id = str((trade_row or {}).get('trade_id') or '').strip() or f"AT-RECOVER-{datetime.now(timezone.utc).strftime('%Y%m%d%H%M%S')}-{uuid.uuid4().hex[:6].upper()}"
    opened_ts = int(float((trade_row or {}).get('opened_ts') or time.time()) or time.time())
    day_utc = datetime.fromtimestamp(opened_ts, tz=timezone.utc).strftime('%Y-%m-%d')
    payload = {
        'trade_id': trade_id,
        'uid': int(uid),
        'opened_ts': opened_ts,
        'day_utc': day_utc,
        'session': str((trade_row or {}).get('session') or ''),
        'setup_id': str((trade_row or {}).get('setup_id') or ''),
        'symbol': str((trade_row or {}).get('symbol') or '').upper(),
        'side': str((trade_row or {}).get('side') or '').upper(),
        'entry': float((trade_row or {}).get('entry') or 0.0),
        'sl': float((trade_row or {}).get('sl') or 0.0),
        'tp': float((trade_row or {}).get('tp') or (trade_row or {}).get('tp1') or 0.0),
        'tp1': float((trade_row or {}).get('tp1') or (trade_row or {}).get('tp') or 0.0),
        'alt_target_a': float((trade_row or {}).get('alt_target_a') or 0.0),
        'alt_target_b': float((trade_row or {}).get('alt_target_b') or 0.0),
        'qty': float((trade_row or {}).get('qty') or 0.0),
        'conf': int((trade_row or {}).get('conf') or 0),
        'quality_score': float((trade_row or {}).get('quality_score') or 0.0),
        'atr_pct': float((trade_row or {}).get('atr_pct') or 0.0),
        'engine': str((trade_row or {}).get('engine') or ''),
        'status': 'OPEN',
        'created_ts': float((trade_row or {}).get('created_ts') or opened_ts or time.time()),
        'updated_ts': float((trade_row or {}).get('updated_ts') or time.time()),
        'closed_ts': None,
        'pnl_usdt': None,
        'outcome': '',
        'note': str((trade_row or {}).get('note') or ''),
        'family_id': str((trade_row or {}).get('family_id') or ''),
        'regime_primary': str((trade_row or {}).get('regime_primary') or ''),
        'allocator_plan_id': str((trade_row or {}).get('allocator_plan_id') or ''),
        'param_set_id': str((trade_row or {}).get('param_set_id') or ''),
        'risk_usd': float((trade_row or {}).get('risk_usd') or (trade_row or {}).get('risk_usdt') or 0.0),
        'risk_pct': float((trade_row or {}).get('risk_pct') or 0.0),
        'tp_usd': float((trade_row or {}).get('tp_usd') or (trade_row or {}).get('tp_usdt') or 0.0),
        'risk_multiplier': float((trade_row or {}).get('risk_multiplier') or 0.0),
        'dynamic_risk_score': float((trade_row or {}).get('dynamic_risk_score') or 0.0),
        'configured_risk_pct': float((trade_row or {}).get('configured_risk_pct') or 0.0),
        'allowed_risk_pct': float((trade_row or {}).get('allowed_risk_pct') or 0.0),
        'rr_tp': float((trade_row or {}).get('rr_tp') or 0.0),
        'setup_strategy': _setup_strategy_label(trade_row or {}),
        'original_setup_id': str((trade_row or {}).get('original_setup_id') or ''),
        'original_side': str((trade_row or {}).get('original_side') or ''),
        'strategy_reason': str((trade_row or {}).get('strategy_reason') or ''),
    }
    try:
        with sqlite3.connect(DB_PATH) as conn:
            cur = conn.cursor()
            preferred_order = [
                'trade_id','uid','opened_ts','created_ts','updated_ts','day_utc','session','setup_id','symbol','side',
                'entry','sl','tp','tp1','alt_target_a','alt_target_b','qty','conf','quality_score','atr_pct','engine',
                'status','closed_ts','pnl_usdt','pnl','outcome','note','family_id','regime_primary','allocator_plan_id','param_set_id',
                'risk_usd','risk_pct','tp_usd','risk_multiplier','dynamic_risk_score','configured_risk_pct','allowed_risk_pct','rr_tp',
                'setup_strategy','original_setup_id','original_side','strategy_reason'
            ]
            insert_cols, values = _autotrade_trade_insert_cols(cur, payload, preferred_order)
            placeholders = ','.join(['?'] * len(insert_cols))
            cur.execute(f"INSERT OR REPLACE INTO autotrade_trades ({','.join(insert_cols)}) VALUES ({placeholders})", values)
            conn.commit()
        return trade_id
    except Exception:
        return ''


def _autotrade_adopt_orphan_live_position(uid: int, live_pos: dict, journal_open: list[dict] | None = None) -> dict:
    """Backfill a missing OPEN journal row for a bot-opened live position."""
    try:
        sym = str(_pos_symbol(live_pos) or '').upper().strip()
        side = str(_pos_side_text(live_pos) or '').upper().strip()
        if not sym or side not in {'BUY', 'SELL'}:
            return {}
        if journal_open:
            for row in (journal_open or []):
                if str(row.get('symbol') or '').upper() == sym and str(row.get('side') or '').upper() == side and str(row.get('status') or '').upper() in {'', 'OPEN'}:
                    return dict(row)
    except Exception:
        return {}

    try:
        with sqlite3.connect(DB_PATH) as conn:
            conn.row_factory = sqlite3.Row
            cur = conn.cursor()
            rows = cur.execute(
                """SELECT * FROM admin_setup_lifecycle
                   WHERE uid=? AND UPPER(COALESCE(symbol,''))=? AND UPPER(COALESCE(side,''))=?
                     AND COALESCE(closed_ts,0)<=0
                     AND COALESCE(executed_ts, attempted_ts, executable_ts, emailed_ts, signal_created_ts, generated_logged_ts, 0) > 0
                   ORDER BY COALESCE(executed_ts, attempted_ts, executable_ts, emailed_ts, signal_created_ts, generated_logged_ts, 0) DESC
                   LIMIT 10""",
                (int(uid), sym, side),
            ).fetchall() or []
            life_rows = [dict(r) for r in rows]
    except Exception:
        life_rows = []
    if not life_rows:
        return {}

    live_entry = float(_pos_entry(live_pos) or 0.0)
    live_qty = abs(float(_pos_size(live_pos) or 0.0))
    live_created = float(_ts_seconds_from_any((live_pos or {}).get('createdTime') or (live_pos or {}).get('created_time')) or 0.0)
    now_ts = float(time.time())
    best_life = None
    best_payload = {}
    best_score = None
    for life in life_rows:
        try:
            ts = float((life or {}).get('executed_ts') or (life or {}).get('attempted_ts') or (life or {}).get('executable_ts') or (life or {}).get('emailed_ts') or (life or {}).get('signal_created_ts') or (life or {}).get('generated_logged_ts') or 0.0)
            if ts <= 0:
                continue
            setup_id = str((life or {}).get('setup_id') or '').strip()
            payload = _signal_setup_eval_payload(setup_id) if setup_id else {}
            payload_entry = float((payload or {}).get('entry') or 0.0)
            entry_delta = abs(payload_entry - live_entry) if payload_entry > 0 and live_entry > 0 else 1e9
            time_delta = abs((live_created or now_ts) - ts)
            life_trade_id = str((life or {}).get('trade_id') or '').strip()
            trade_exists = bool(_autotrade_db_get_trade(life_trade_id)) if life_trade_id else False
            score = (0 if (not life_trade_id or not trade_exists) else 10000, entry_delta, time_delta)
            if best_life is None or score < best_score:
                best_life = life
                best_payload = payload
                best_score = score
        except Exception:
            continue
    if not best_life:
        return {}
    try:
        setup_id = str((best_life or {}).get('setup_id') or '').strip()
        trade_id = str((best_life or {}).get('trade_id') or '').strip()
        if trade_id and _autotrade_db_get_trade(trade_id):
            return _autotrade_db_get_trade(trade_id)
        opened_ts = float((best_life or {}).get('executed_ts') or (best_life or {}).get('attempted_ts') or live_created or now_ts)
        current_sl = float(_pos_stop(live_pos) or _bybit_detect_open_sl_price(sym, side=side) or 0.0)
        current_tp = float(_pos_take_profit(live_pos) or 0.0)
        payload_sl = float((best_payload or {}).get('sl') or 0.0)
        payload_tp = float(_resolve_single_tp(float((best_payload or {}).get('entry') or live_entry or 0.0), payload_sl, (best_payload or {}).get('tp'), (best_payload or {}).get('alt_target_a'), (best_payload or {}).get('alt_target_b'), side) or 0.0)
        row = {
            'trade_id': trade_id or '',
            'opened_ts': opened_ts,
            'session': str((best_life or {}).get('session') or ''),
            'setup_id': setup_id,
            'symbol': sym,
            'side': side,
            'entry': float(live_entry or float((best_payload or {}).get('entry') or 0.0) or 0.0),
            'sl': float(current_sl or payload_sl or 0.0),
            'tp': float(current_tp or payload_tp or 0.0),
            'alt_target_a': 0.0,
            'alt_target_b': 0.0,
            'qty': float(live_qty or 0.0),
            'conf': int((best_payload or {}).get('conf') or 0),
            'quality_score': float((best_payload or {}).get('quality_score') or 0.0),
            'atr_pct': float((best_payload or {}).get('atr_pct') or 0.0),
            'engine': str((best_payload or {}).get('engine') or ''),
            'note': 'recovered_orphan_live_position',
            'family_id': str((best_payload or {}).get('family_id') or ''),
            'regime_primary': str((best_payload or {}).get('regime_primary') or ''),
            'allocator_plan_id': str((best_payload or {}).get('allocator_plan_id') or ''),
            'param_set_id': str((best_payload or {}).get('param_set_id') or ''),
        }
        new_trade_id = _autotrade_db_insert_open_trade_row(int(uid), row)
        if not new_trade_id:
            return {}
        _admin_setup_lifecycle_merge(
            int(uid),
            setup_id,
            symbol=sym,
            side=side,
            session=str((best_life or {}).get('session') or ''),
            executed_ts=float(opened_ts),
            trade_id=str(new_trade_id),
            bybit_position_symbol=str(sym),
            state='executed_open',
            last_reason='recovered_orphan_live_position',
        )
        return _autotrade_db_get_trade(new_trade_id)
    except Exception:
        return {}

def _autotrade_db_closed_trades_window(uid: int, start_ts: float, end_ts: float) -> list[dict]:
    with sqlite3.connect(DB_PATH) as conn:
        conn.row_factory = sqlite3.Row
        c = conn.cursor()
        c.execute(
            """SELECT * FROM autotrade_trades
               WHERE uid=? AND closed_ts IS NOT NULL AND closed_ts>=? AND closed_ts<?
               ORDER BY closed_ts DESC""",
            (int(uid), float(start_ts), float(end_ts)),
        )
        return [dict(r) for r in c.fetchall()]


def _autotrade_closed_activity_rows_window(uid: int, start_ts: float, end_ts: float) -> list[dict]:
    """Closed-trade activity rows, journal-first with Bybit fallback for live admin.

    Why this exists:
    - /status and /autotrade_report should not show zero closed trades just because the
      local journal missed some closes during a restart or delayed reconciliation.
    - In LIVE mode for the owner/admin, Bybit closed-PnL rows are the source of truth for
      closed activity inside the requested window.
    """
    try:
        base_rows = _autotrade_db_closed_trades_window(int(uid), float(start_ts), float(end_ts)) or []
    except Exception:
        base_rows = []

    out = []
    seen = set()

    def _row_key(symbol: str, side: str, ts: float, pnl: float) -> tuple:
        return (
            str(_bybit_linear_symbol(symbol or '')).upper(),
            str(side or '').upper().strip(),
            int(float(ts or 0.0) // 60),
            round(float(pnl or 0.0), 8),
        )

    for r in (base_rows or []):
        try:
            sym = str(_bybit_linear_symbol((r or {}).get('symbol') or '')).upper()
            side = str((r or {}).get('side') or '').upper().strip()
            ts = float((r or {}).get('closed_ts') or 0.0)
            pnl = float((r or {}).get('pnl_usdt') if (r or {}).get('pnl_usdt') is not None else (r or {}).get('pnl') or 0.0)
            if not sym or ts <= 0:
                continue
            out.append(dict(r))
            seen.add(_row_key(sym, side, ts, pnl))
        except Exception:
            continue

    # Bot-only closed activity: add setup-linked provisional closes, but never raw exchange-only
    # fallback rows here because those can include manual/external trades.
    try:
        prov_days = max(2, int(math.ceil(max(1.0, (float(end_ts) - float(start_ts)) / 86400.0))) + 3)
        for p in (_autotrade_reconstruct_provisional_closes(int(uid), days=prov_days) or []):
            try:
                ts = float((p or {}).get('closed_ts') or 0.0)
                if ts <= 0 or ts < float(start_ts) or ts >= float(end_ts):
                    continue
                sym = str(_bybit_linear_symbol((p or {}).get('symbol') or '')).upper()
                side = str((p or {}).get('side') or '').upper().strip()
                pnl = float((p or {}).get('pnl_usdt') if (p or {}).get('pnl_usdt') is not None else (p or {}).get('pnl') or 0.0)
                if not sym or not side:
                    continue
                rk = _row_key(sym, side, ts, pnl)
                if rk in seen:
                    continue
                row = dict(p or {})
                row.setdefault('trade_id', f"prov::{row.get('setup_id') or sym}::{int(ts)}")
                row.setdefault('uid', int(uid))
                row.setdefault('symbol', sym)
                row.setdefault('side', side)
                row.setdefault('pnl_usdt', pnl)
                row.setdefault('status', 'CLOSED')
                row.setdefault('note', 'provisional_exchange_match_from_setup_history')
                out.append(row)
                seen.add(rk)
            except Exception:
                continue
    except Exception:
        pass

    out.sort(key=lambda r: float((r or {}).get('closed_ts') or 0.0), reverse=True)
    return out

AUTOTRADE_SYMBOL_GUARD_TTL_SEC = int(os.environ.get("AUTOTRADE_SYMBOL_GUARD_TTL_SEC", "1800") or 1800)
AUTOTRADE_RECENT_SYMBOL_SYNC_SEC = int(os.environ.get("AUTOTRADE_RECENT_SYMBOL_SYNC_SEC", "180") or 180)
AUTOTRADE_PLACED_GUARD_CLEANUP_SEC = int(os.environ.get("AUTOTRADE_PLACED_GUARD_CLEANUP_SEC", "172800") or 172800)

_AUTOTRADE_RUNTIME_SYMBOL_LOCKS: dict[str, float] = {}
_AUTOTRADE_RUNTIME_SYMBOL_LOCKS_GUARD = threading.Lock()

def _autotrade_symbol_lock_key(uid: int, symbol: str) -> str:
    return f"{int(uid)}:{_bybit_linear_symbol(symbol)}"

def _autotrade_runtime_symbol_lock_acquire(uid: int, symbol: str, ttl_sec: int | None = None) -> bool:
    ttl = int(ttl_sec or AUTOTRADE_SYMBOL_GUARD_TTL_SEC)
    key = _autotrade_symbol_lock_key(uid, symbol)
    now = float(time.time())
    with _AUTOTRADE_RUNTIME_SYMBOL_LOCKS_GUARD:
        ts = float(_AUTOTRADE_RUNTIME_SYMBOL_LOCKS.get(key) or 0.0)
        if ts and (now - ts) <= ttl:
            return False
        _AUTOTRADE_RUNTIME_SYMBOL_LOCKS[key] = now
        stale_before = now - max(float(ttl), 60.0)
        for k, v in list(_AUTOTRADE_RUNTIME_SYMBOL_LOCKS.items()):
            try:
                if float(v or 0.0) < stale_before:
                    _AUTOTRADE_RUNTIME_SYMBOL_LOCKS.pop(k, None)
            except Exception:
                _AUTOTRADE_RUNTIME_SYMBOL_LOCKS.pop(k, None)
    return True

def _autotrade_runtime_symbol_lock_release(uid: int, symbol: str) -> None:
    key = _autotrade_symbol_lock_key(uid, symbol)
    with _AUTOTRADE_RUNTIME_SYMBOL_LOCKS_GUARD:
        _AUTOTRADE_RUNTIME_SYMBOL_LOCKS.pop(key, None)

def _autotrade_runtime_symbol_lock_active(uid: int, symbol: str, ttl_sec: int | None = None) -> bool:
    ttl = int(ttl_sec or AUTOTRADE_SYMBOL_GUARD_TTL_SEC)
    key = _autotrade_symbol_lock_key(uid, symbol)
    now = float(time.time())
    with _AUTOTRADE_RUNTIME_SYMBOL_LOCKS_GUARD:
        ts = float(_AUTOTRADE_RUNTIME_SYMBOL_LOCKS.get(key) or 0.0)
        if not ts:
            return False
        if (now - ts) > ttl:
            _AUTOTRADE_RUNTIME_SYMBOL_LOCKS.pop(key, None)
            return False
        return True

def _autotrade_exec_cleanup(stale_pending_sec: int = 1800, stale_failed_sec: int = 86400, stale_placed_sec: int = AUTOTRADE_PLACED_GUARD_CLEANUP_SEC) -> None:
    try:
        now = float(time.time())
        with sqlite3.connect(DB_PATH) as conn:
            c = conn.cursor()
            c.execute("DELETE FROM autotrade_exec_guard WHERE status='PENDING' AND updated_ts<?", (now - float(stale_pending_sec),))
            c.execute("DELETE FROM autotrade_exec_guard WHERE status='FAILED' AND updated_ts<?", (now - float(stale_failed_sec),))
            c.execute("DELETE FROM autotrade_exec_guard WHERE status='PLACED' AND updated_ts<?", (now - float(stale_placed_sec),))
            conn.commit()
    except Exception:
        pass


def _autotrade_exec_reserve(uid: int, setup_id: str, symbol: str, side: str, setup_ttl_sec: int = 86400, symbol_ttl_sec: int = AUTOTRADE_SYMBOL_GUARD_TTL_SEC, symdir_ttl_sec: int = AUTOTRADE_SYMBOL_GUARD_TTL_SEC) -> tuple[bool, list[str], str]:
    """Atomically reserve execution keys to prevent duplicate orders."""
    now = float(time.time())
    sid = str(setup_id or '').strip()
    sym = _bybit_linear_symbol(symbol)
    sd = str(side or '').upper().strip()
    if not sym or sd not in {'BUY','SELL'}:
        return (False, [], 'bad_guard_identity')

    setup_key = f"setup:{int(uid)}:{sid}" if sid else ''
    symbol_key = f"symbol:{int(uid)}:{sym}"
    symdir_key = f"symdir:{int(uid)}:{sym}:{sd}"
    checks = []
    if setup_key:
        checks.append((setup_key, 'SETUP', float(setup_ttl_sec)))
    checks.append((symbol_key, 'SYMBOL', float(symbol_ttl_sec)))
    checks.append((symdir_key, 'SYMDIR', float(symdir_ttl_sec)))

    try:
        with sqlite3.connect(DB_PATH) as conn:
            c = conn.cursor()
            c.execute('BEGIN IMMEDIATE')
            reserved = []
            for guard_key, gtype, ttl in checks:
                row = c.execute("SELECT status, updated_ts, note FROM autotrade_exec_guard WHERE guard_key=?", (guard_key,)).fetchone()
                if row:
                    status = str(row[0] or '').upper()
                    updated_ts = float(row[1] or 0.0)
                    age = now - updated_ts
                    if status in {'PENDING', 'PLACED'} and age <= ttl:
                        conn.rollback()
                        # yver128: distinguish a genuine already-consumed setup from
                        # a short-lived duplicate/inflight lock.  This makes
                        # /autotrade_last clear: if a setup was already opened and
                        # later closed, it must not be opened again, but it should
                        # not look like a broken inflight lock.
                        if str(gtype or '').upper() == 'SETUP':
                            if status == 'PLACED':
                                return (False, reserved, 'setup_already_traded')
                            return (False, reserved, 'setup_execution_already_pending')
                        return (False, reserved, f'duplicate_guard_block:{gtype.lower()}')
                c.execute("INSERT OR REPLACE INTO autotrade_exec_guard(guard_key, uid, setup_id, symbol, side, guard_type, status, created_ts, updated_ts, note) VALUES(?,?,?,?,?,?,?,?,?,?)",
                          (guard_key, int(uid), sid, sym, sd, gtype, 'PENDING', now, now, ''))
                reserved.append(guard_key)
            conn.commit()
            return (True, reserved, '')
    except Exception as e:
        return (False, [], f'guard_reserve_error:{type(e).__name__}')


def _autotrade_exec_mark(keys: list[str], status: str, note: str = '') -> None:
    try:
        if not keys:
            return
        now = float(time.time())
        with sqlite3.connect(DB_PATH) as conn:
            c = conn.cursor()
            for k in keys:
                c.execute("UPDATE autotrade_exec_guard SET status=?, updated_ts=?, note=? WHERE guard_key=?",
                          (str(status or '').upper(), now, str(note or '')[:500], str(k)))
            conn.commit()
    except Exception:
        pass


def _autotrade_get_local_symbol_activity(uid: int, symbol: str) -> dict:
    sym = _bybit_linear_symbol(symbol)
    out = {"open_trades": [], "latest_open_ts": 0.0, "latest_close_ts": 0.0, "latest_trade_ts": 0.0}
    try:
        with sqlite3.connect(DB_PATH) as conn:
            conn.row_factory = sqlite3.Row
            c = conn.cursor()
            c.execute("SELECT * FROM autotrade_trades WHERE uid=? AND UPPER(symbol)=? ORDER BY opened_ts DESC", (int(uid), str(sym).upper()))
            rows = [dict(r) for r in c.fetchall()]
        opens = []
        for r in rows:
            status = str(r.get('status') or '').upper()
            try:
                open_ts = float(r.get('opened_ts') or 0.0)
            except Exception:
                open_ts = 0.0
            try:
                close_ts = float(r.get('closed_ts') or 0.0)
            except Exception:
                close_ts = 0.0
            out['latest_open_ts'] = max(float(out['latest_open_ts'] or 0.0), open_ts)
            out['latest_close_ts'] = max(float(out['latest_close_ts'] or 0.0), close_ts)
            out['latest_trade_ts'] = max(float(out['latest_trade_ts'] or 0.0), open_ts, close_ts)
            if status == 'OPEN':
                opens.append(r)
        try:
            reset_ts = float(_autotrade_cooldown_reset_ts() or 0.0)
            if reset_ts > 0:
                if float(out.get('latest_open_ts') or 0.0) < reset_ts:
                    out['latest_open_ts'] = 0.0
                if float(out.get('latest_close_ts') or 0.0) < reset_ts:
                    out['latest_close_ts'] = 0.0
                if float(out.get('latest_trade_ts') or 0.0) < reset_ts:
                    out['latest_trade_ts'] = 0.0
        except Exception:
            pass
        out['open_trades'] = opens
    except Exception:
        pass
    return out


def _autotrade_get_pending_symbol_guards(uid: int, symbol: str) -> list[dict]:
    sym = _bybit_linear_symbol(symbol)
    out = []
    try:
        now = float(time.time())
        with sqlite3.connect(DB_PATH) as conn:
            conn.row_factory = sqlite3.Row
            c = conn.cursor()
            c.execute("SELECT * FROM autotrade_exec_guard WHERE uid=? AND UPPER(symbol)=? ORDER BY updated_ts DESC", (int(uid), str(sym).upper()))
            rows = [dict(r) for r in c.fetchall()]
        for r in rows:
            status = str(r.get('status') or '').upper()
            upd_ts = float(r.get('updated_ts') or 0.0)
            try:
                if upd_ts < float(_autotrade_cooldown_reset_ts() or 0.0):
                    continue
            except Exception:
                pass
            age = now - upd_ts
            if status == 'PENDING' and age <= float(AUTOTRADE_SYMBOL_GUARD_TTL_SEC):
                out.append(r)
            elif status == 'PLACED' and age <= float(AUTOTRADE_RECENT_SYMBOL_SYNC_SEC):
                out.append(r)
        return out
    except Exception:
        return []


def _autotrade_symbol_cooldown_remaining(uid: int, symbol: str, session_label: str) -> float:
    act = _autotrade_get_local_symbol_activity(uid, symbol)
    last_ts = float(act.get('latest_trade_ts') or 0.0)
    if last_ts <= 0:
        return 0.0
    cooldown_sec = max(float(cooldown_hours_for_session(session_label)) * 3600.0, float(AUTOTRADE_RECENT_SYMBOL_SYNC_SEC))
    return max(0.0, (last_ts + cooldown_sec) - float(time.time()))


def _autotrade_log_symbol_block(uid: int, symbol: str, side: str, reason: str, extra: str = '') -> None:
    try:
        sym = _bybit_linear_symbol(symbol)
        sd = str(side or '').upper()
        msg = f"{reason} uid={int(uid)} symbol={sym} side={sd}"
        if extra:
            msg += f" | {extra}"
        reason_s = str(reason or '')
        key = f"autotrade_block:{int(uid)}:{sym}:{sd}:{reason_s}:{str(extra or '')[:80]}"
        # Same-symbol external/manual conflicts are expected safety blocks when
        # you already have a manual/external Bybit position. They are not bot
        # errors, so do not write them to Render logs at INFO/WARNING level.
        # They remain visible in Telegram diagnostics/last decision output.
        if reason_s.startswith('blocked_manual_same_symbol_position'):
            return
        _log_warning_throttled(key, 90.0, msg)
    except Exception:
        pass


def _autotrade_live_symbol_conflict(uid: int, symbol: str, side: str | None = None) -> dict:
    """Return same-symbol live-position conflict detail for AutoTrade.

    Manual/external positions should not contaminate bot risk or reporting, but a same-symbol
    live position in the same Bybit account is still an execution conflict because Bybit one-way
    mode merges the exposure and makes bot/manual ownership impossible to enforce cleanly.
    """
    sym = _bybit_linear_symbol(symbol)
    requested_side = str(side or '').upper().strip()
    out = {
        'has_conflict': False,
        'symbol': sym,
        'requested_side': requested_side,
        'position_side': '',
        'position_qty': 0.0,
        'owner_kind': '',
        'trade_id': '',
        'setup_id': '',
        'reason': '',
    }
    if not sym:
        return out
    try:
        journal_open = _autotrade_db_open_trades(int(uid)) or []
    except Exception:
        journal_open = []
    try:
        for p in (_bybit_get_open_positions_linear() or []):
            try:
                if _pos_symbol(p) != sym:
                    continue
                qty = abs(float(_pos_size(p) or 0.0))
                if qty <= 0:
                    continue
                pos_side = str(_pos_side_text(p) or '').upper().strip()
                owner_trade = _autotrade_live_position_owner_trade(int(uid), p, journal_open=journal_open)
                out.update({
                    'has_conflict': True,
                    'position_side': pos_side,
                    'position_qty': float(qty),
                    'owner_kind': 'bot' if owner_trade else 'external',
                    'trade_id': str((owner_trade or {}).get('trade_id') or ''),
                    'setup_id': str((owner_trade or {}).get('setup_id') or ''),
                })
                out['reason'] = 'blocked_duplicate_open_position' if owner_trade else 'blocked_manual_same_symbol_position'
                return out
            except Exception:
                continue
    except Exception:
        pass
    return out


def _autotrade_can_open_symbol(uid: int, symbol: str, side: str, session_label: str) -> tuple[bool, str, dict]:
    """Single hardened gatekeeper for symbol tradability."""
    sym = _bybit_linear_symbol(symbol)
    sd = str(side or '').upper().strip()
    detail = {
        'symbol': sym,
        'side': sd,
        'session': str(session_label or '').upper(),
        'live_open_position': False,
        'live_position_owner': '',
        'live_position_side': '',
        'live_position_qty': 0.0,
        'live_position_trade_id': '',
        'local_open_trade': False,
        'live_open_order': False,
        'pending_guard': False,
        'runtime_lock': False,
        'cooldown_remaining_sec': 0.0,
        'recent_trade_remaining_sec': 0.0,
        'local_open_count': 0,
        'pending_guard_count': 0,
    }
    if not sym or sd not in {'BUY', 'SELL'}:
        return (False, 'blocked_bad_symbol_identity', detail)

    _autotrade_exec_cleanup()

    if _autotrade_runtime_symbol_lock_active(uid, sym):
        detail['runtime_lock'] = True
        _autotrade_log_symbol_block(uid, sym, sd, 'blocked_duplicate_inflight_lock', 'runtime_lock_active')
        return (False, 'blocked_duplicate_inflight_lock', detail)

    if str(_autotrade_runtime_mode()).lower() == 'live':
        try:
            # yver72: use a fresh live position snapshot for the duplicate/same-symbol
            # gate. A stale pre-entry cache can allow a second same-symbol setup to
            # merge into the same Bybit position and overwrite its Full TP/SL.
            _bybit_invalidate_live_order_position_cache(sym)
        except Exception:
            pass
        try:
            conflict = _autotrade_live_symbol_conflict(uid, sym, side=sd)
        except Exception:
            conflict = {}
        if bool((conflict or {}).get('has_conflict')):
            detail['live_open_position'] = True
            detail['live_position_owner'] = str((conflict or {}).get('owner_kind') or '')
            detail['live_position_side'] = str((conflict or {}).get('position_side') or '')
            detail['live_position_qty'] = float((conflict or {}).get('position_qty') or 0.0)
            detail['live_position_trade_id'] = str((conflict or {}).get('trade_id') or '')
            block_reason = str((conflict or {}).get('reason') or 'blocked_duplicate_open_position')
            extra = f"owner={detail['live_position_owner'] or '?'} pos_side={detail['live_position_side'] or '?'} qty={detail['live_position_qty']:.6g}"
            _autotrade_log_symbol_block(uid, sym, sd, block_reason, extra)
            return (False, block_reason, detail)

    local_activity = _autotrade_get_local_symbol_activity(uid, sym)
    local_opens = local_activity.get('open_trades') or []
    if local_opens:
        detail['local_open_trade'] = True
        detail['local_open_count'] = len(local_opens)
        _autotrade_log_symbol_block(uid, sym, sd, 'blocked_by_existing_local_trade_state', f"open_trades={len(local_opens)}")
        return (False, 'blocked_by_existing_local_trade_state', detail)

    pending_guards = _autotrade_get_pending_symbol_guards(uid, sym)
    if pending_guards:
        detail['pending_guard'] = True
        detail['pending_guard_count'] = len(pending_guards)
        statuses = ','.join(sorted({str(x.get('status') or '').upper() for x in pending_guards}))
        _autotrade_log_symbol_block(uid, sym, sd, 'blocked_duplicate_pending_order', f"guards={len(pending_guards)} statuses={statuses}")
        return (False, 'blocked_duplicate_pending_order', detail)

    if str(_autotrade_runtime_mode()).lower() == 'live':
        try:
            if _autotrade_has_live_open_order(sym, side=None):
                detail['live_open_order'] = True
                _autotrade_log_symbol_block(uid, sym, sd, 'blocked_duplicate_pending_order', 'live_open_order_present')
                return (False, 'blocked_duplicate_pending_order', detail)
        except Exception:
            pass

    latest_open_ts = float(local_activity.get('latest_open_ts') or 0.0)
    if latest_open_ts > 0:
        recent_remaining = max(0.0, (latest_open_ts + float(AUTOTRADE_RECENT_SYMBOL_SYNC_SEC)) - float(time.time()))
        detail['recent_trade_remaining_sec'] = recent_remaining
        if recent_remaining > 0:
            _autotrade_log_symbol_block(uid, sym, sd, 'blocked_by_recent_symbol_trade', f"remaining_sec={int(recent_remaining)}")
            return (False, 'blocked_by_recent_symbol_trade', detail)

    cooldown_remaining = _autotrade_symbol_cooldown_remaining(uid, sym, session_label)
    detail['cooldown_remaining_sec'] = cooldown_remaining
    if cooldown_remaining > 0:
        _autotrade_log_symbol_block(uid, sym, sd, 'blocked_by_cooldown', f"remaining_sec={int(cooldown_remaining)}")
        return (False, 'blocked_by_cooldown', detail)

    return (True, '', detail)


def _bybit_get_open_orders_linear(symbol: str | None = None) -> list[dict]:
    sym = _bybit_linear_symbol(symbol) if symbol else None
    cache_key = f"bybit_open_orders_linear:{sym or 'ALL'}"
    try:
        ttl = max(1, int(BYBIT_OPEN_ORDERS_CACHE_TTL_SEC or 6))
        if cache_valid(cache_key, ttl):
            cached = cache_get(cache_key)
            return list(cached or []) if isinstance(cached, list) else []
    except Exception:
        pass
    try:
        if not BYBIT_API_KEY or not BYBIT_API_SECRET:
            return []
        merged: list[dict] = []
        seen: set[str] = set()
        # Keep the live guardian responsive: the old scan made up to 5 Bybit
        # realtime-order requests per symbol, which could exceed the guardian timeout
        # and create command lag under exchange slowness. Default to the filters that
        # carry active protection orders; enable BYBIT_FULL_OPEN_ORDER_SCAN=1 only for
        # deep debugging.
        if env_bool('BYBIT_FULL_OPEN_ORDER_SCAN', False):
            order_filters = [None, 'Order', 'StopOrder', 'tpslOrder', 'TPSLOrder']
        else:
            order_filters = [None, 'StopOrder', 'tpslOrder']
        for order_filter in order_filters:
            payload = {'category': 'linear', 'openOnly': 0, 'limit': 200}
            if sym:
                payload['symbol'] = sym
            if order_filter:
                payload['orderFilter'] = order_filter
            res = _bybit_v5_request('GET', '/v5/order/realtime', payload)
            if int((res or {}).get('retCode', -1)) != 0:
                continue
            for row in ((((res or {}).get('result') or {}).get('list') or [])):
                try:
                    oid = str(row.get('orderId') or row.get('stopOrderId') or row.get('orderLinkId') or '')
                except Exception:
                    oid = ''
                key = oid or json.dumps(row, sort_keys=True, default=str)
                if key in seen:
                    continue
                seen.add(key)
                merged.append(row)
        try:
            cache_set(cache_key, list(merged))
        except Exception:
            pass
        return merged
    except Exception:
        stale = cache_get(cache_key)
        return list(stale or []) if isinstance(stale, list) else []


def _bybit_get_order_linear_state(symbol: str, order_id: str = '', order_link_id: str = '') -> dict:
    sym = _bybit_linear_symbol(symbol)
    oid = str(order_id or '').strip()
    olid = str(order_link_id or '').strip()
    if not sym or (not oid and not olid):
        return {}
    lookups = [('/v5/order/realtime', {'openOnly': 0}), ('/v5/order/history', {'limit': 50})]
    for path, extra in lookups:
        for order_filter in (None, 'Order', 'StopOrder', 'tpslOrder', 'TPSLOrder'):
            payload = {'category': 'linear', 'symbol': sym}
            payload.update(extra)
            if oid:
                payload['orderId'] = oid
            if olid:
                payload['orderLinkId'] = olid
            if order_filter:
                payload['orderFilter'] = order_filter
            res = _bybit_v5_request('GET', path, payload)
            if int((res or {}).get('retCode', -1)) != 0:
                continue
            rows = (((res or {}).get('result') or {}).get('list') or [])
            if not rows:
                continue
            for row in rows:
                row_oid = str((row or {}).get('orderId') or '').strip()
                row_olid = str((row or {}).get('orderLinkId') or '').strip()
                if (oid and row_oid == oid) or (olid and row_olid == olid):
                    out = dict(row or {})
                    out['_source_path'] = path
                    out['_source_filter'] = order_filter
                    return out
    return {}


def _autotrade_has_live_open_order(symbol: str, side: str | None = None) -> bool:
    sym = _bybit_linear_symbol(symbol)
    side_u = str(side or '').upper().strip()
    try:
        for o in _bybit_get_open_orders_linear(sym):
            try:
                if _bybit_linear_symbol(str(o.get('symbol') or '')) != sym:
                    continue
                if side_u:
                    o_side = str(o.get('side') or '').upper().strip()
                    if (o_side == 'BUY' and side_u != 'BUY') or (o_side == 'SELL' and side_u != 'SELL'):
                        continue
                status = str(o.get('orderStatus') or '').upper()
                if status not in {'CANCELLED', 'FILLED', 'REJECTED', 'DEACTIVATED'}:
                    return True
            except Exception:
                continue
    except Exception:
        return False
    return False


def _autotrade_db_add_trade(uid: int, session_label: str, s: 'Setup', qty: float, lifecycle_state: str = 'executed_open', lifecycle_reason: str = '', report_meta: dict | None = None) -> str:
    """Persist a bot-opened trade into SQLite using the live DB schema.

    Older Render DBs can contain extra NOT NULL columns (created_ts/updated_ts).
    The previous hard-coded INSERT opened the Bybit position, then failed on the
    journal insert. This schema-aware INSERT always supplies lifecycle timestamps
    when those columns exist.
    """
    _autotrade_migrate_tables()
    trade_id = f"AT-{datetime.now(timezone.utc).strftime('%Y%m%d%H%M%S')}-{uuid.uuid4().hex[:6].upper()}"
    now_ts = float(time.time())
    opened_ts = int(now_ts)
    day_utc = datetime.fromtimestamp(opened_ts, tz=timezone.utc).strftime('%Y-%m-%d')
    setup_id = str(getattr(s, 'setup_id', '') or getattr(s, 'id', '') or '')
    symbol = str(getattr(s, 'symbol', '') or '').upper()
    side = str(getattr(s, 'side', '') or '').upper()
    report_meta = dict(report_meta or {})

    payload = {
        'trade_id': trade_id,
        'uid': int(uid),
        'opened_ts': opened_ts,
        'created_ts': now_ts,
        'updated_ts': now_ts,
        'day_utc': str(day_utc),
        'session': str(session_label or ''),
        'setup_id': setup_id,
        'symbol': symbol,
        'side': side,
        'entry': float(getattr(s, 'entry', 0.0) or 0.0),
        'sl': float(getattr(s, 'sl', 0.0) or 0.0),
        'tp': float(_setup_target_tp(s, 0.0) or 0.0),
        'tp1': float(_setup_target_tp(s, 0.0) or 0.0),
        'alt_target_a': 0.0,
        'alt_target_b': 0.0,
        'qty': float(qty or 0.0),
        'conf': int(getattr(s, 'conf', 0) or 0),
        'quality_score': float(getattr(s, 'quality_score', 0.0) or 0.0),
        'atr_pct': float(getattr(s, 'atr_pct', 0.0) or 0.0),
        'engine': str(getattr(s, 'engine', '') or ''),
        'status': 'OPEN',
        'closed_ts': None,
        'pnl_usdt': None,
        'pnl': None,
        'outcome': '',
        'note': str(lifecycle_reason or ''),
        'family_id': str(getattr(s, 'family_id', '') or ''),
        'regime_primary': str(getattr(s, 'regime_primary', '') or ''),
        'allocator_plan_id': str(getattr(s, 'allocator_plan_id', '') or ''),
        'param_set_id': str(getattr(s, 'param_set_id', '') or ''),
        'risk_usd': float(report_meta.get('risk_usd') or getattr(s, 'risk_usd', 0.0) or 0.0),
        'risk_pct': float(report_meta.get('risk_pct') or getattr(s, 'risk_pct', 0.0) or 0.0),
        'tp_usd': float(report_meta.get('tp_usd') or getattr(s, 'tp_usd', 0.0) or 0.0),
        'risk_multiplier': float(report_meta.get('risk_multiplier') or getattr(s, 'risk_multiplier', 0.0) or 0.0),
        'dynamic_risk_score': float(report_meta.get('dynamic_risk_score') or getattr(s, 'dynamic_risk_score', 0.0) or 0.0),
        'configured_risk_pct': float(report_meta.get('configured_risk_pct') or getattr(s, 'configured_risk_pct', 0.0) or 0.0),
        'allowed_risk_pct': float(report_meta.get('allowed_risk_pct') or getattr(s, 'allowed_risk_pct', 0.0) or 0.0),
        'rr_tp': float(report_meta.get('rr_tp') or getattr(s, 'rr_tp', 0.0) or 0.0),
        'setup_strategy': _setup_strategy_label(s),
        'original_setup_id': str(getattr(s, 'original_setup_id', '') or ''),
        'original_side': str(getattr(s, 'original_side', '') or ''),
        'strategy_reason': str(getattr(s, 'strategy_reason', '') or ''),
    }

    try:
        with sqlite3.connect(DB_PATH) as conn:
            c = conn.cursor()
            preferred_order = [
                'trade_id','uid','opened_ts','created_ts','updated_ts','day_utc','session','setup_id','symbol','side',
                'entry','sl','tp','tp1','alt_target_a','alt_target_b','qty','conf','quality_score','atr_pct','engine',
                'status','closed_ts','pnl_usdt','pnl','outcome','note','family_id','regime_primary','allocator_plan_id','param_set_id',
                'risk_usd','risk_pct','tp_usd','risk_multiplier','dynamic_risk_score','configured_risk_pct','allowed_risk_pct','rr_tp',
                'setup_strategy','original_setup_id','original_side','strategy_reason'
            ]
            insert_cols, values = _autotrade_trade_insert_cols(c, payload, preferred_order)
            placeholders = ','.join(['?'] * len(insert_cols))
            c.execute(f"INSERT INTO autotrade_trades ({','.join(insert_cols)}) VALUES ({placeholders})", values)
            conn.commit()
    except Exception as e:
        try:
            logger.exception("autotrade journal insert failed trade_id=%s setup=%s symbol=%s: %s", trade_id, setup_id, symbol, e)
        except Exception:
            pass
        raise

    try:
        _admin_setup_lifecycle_merge(
            int(uid),
            setup_id,
            session=str(session_label or ''),
            symbol=symbol,
            side=side,
            executed_ts=now_ts,
            trade_id=str(trade_id),
            state=str(lifecycle_state or 'executed_open'),
            last_reason=str(lifecycle_reason or ''),
        )
    except Exception:
        pass
    return trade_id

def _autotrade_estimated_risk_usd(entry: float, sl: float, qty: float) -> float:
    try:
        return abs(entry - sl) * abs(qty)
    except Exception:
        return 0.0

def _autotrade_open_risk_usd(uid: int, equity_usdt: float) -> float:
    total = 0.0
    for t in _autotrade_db_open_trades(uid):
        total += _autotrade_estimated_risk_usd(float(t.get('entry') or 0.0), float(t.get('sl') or 0.0), float(t.get('qty') or 0.0))
    return total

def _autotrade_qty_from_risk(entry: float, sl: float, equity_usdt: float, risk_usd: float | None = None, contract_size: float = 1.0) -> float:
    dist = abs(float(entry) - float(sl))
    cs = abs(float(contract_size or 1.0))
    if dist <= 0 or cs <= 0:
        return 0.0
    if risk_usd is None:
        # Backward-compat fallback only. Live sizing should pass explicit /riskmode-derived risk_usd.
        risk_usd = (float(equity_usdt) * (AUTOTRADE_RISK_PER_TRADE_PCT / 100.0))
    qty = float(risk_usd) / (dist * cs)
    if qty <= 0 or (not math.isfinite(qty)):
        return 0.0
    return float(qty)

def _autotrade_allowed_session(session_label: str) -> bool:
    allowed = {s.strip().upper() for s in (_autotrade_get_sessions() or []) if s.strip()}
    if not allowed:
        allowed = {'NY', 'LON', 'ASIA'}
    return str(session_label or '').upper() in allowed


# =========================================================
# AUTOTRADE: select best OPEN setup from DB (generated_setups + signals)
# =========================================================
def _autotrade_db_signal_structurally_valid(s: Any, session_name: str = "NY") -> tuple[bool, str]:
    """Validate DB-hydrated executable rows against the real executable gate when possible."""
    try:
        sess = str(session_name or "").upper().strip()
        if sess not in {"ASIA", "LON", "NY"}:
            return (False, "session_not_supported")
        # yver37: email matching is now optional.  When
        # AUTOTRADE_REQUIRE_SETUP_EMAIL_FOR_ENTRY=false, AutoTrade can consume
        # fresh executable KEEP rows directly so valid KEEP setups do not depend
        # on the setup-email loop.  When true, keep the older exact-email lock.
        try:
            if _autotrade_require_setup_email_for_entry():
                policy_uid = int(globals().get('AUTOTRADE_OWNER_UID', 0) or 0)
                email_ok, email_why = _autotrade_recent_email_gate_allows_setup(policy_uid, s, session_label=sess)
                if not email_ok:
                    return (False, str(email_why or 'missing_recent_setup_email'))
        except Exception:
            return (False, 'setup_email_gate_exception')
        # Ver53: setup-generation blackout only stops creating new setups.
        # It must not invalidate already persisted/emailed executable rows that
        # AutoTrade is trying to consume before their entry window expires.
        if not _setup_volume_ok(s):
            return (False, f"below_min_volume_{_setup_min_volume_floor_usd()/1e6:.0f}M")
        # yver45: AutoTrade structural validation must enforce Directional
        # Leaders/Losers before the matrix KEEP fast-path.  KEEP is not allowed
        # to override Leader->SELL or Loser->BUY.
        try:
            dir_ok, dir_why, _dir_meta = _setup_directional_context_guard_allows_setup(s, session_name=sess, user_id=int(globals().get('AUTOTRADE_OWNER_UID', 0) or 0))
            if not dir_ok:
                return (False, str(dir_why or 'directional_context_blocked'))
        except Exception:
            pass

        # yver24: if /setup_matrix policy says KEEP, this setup is executable
        # for the user-facing path.  Keep only the basic structural price-order
        # validation here; risk sizing, cooldowns, duplicate guards, email gate
        # and exchange safety remain downstream.
        try:
            if _setup_matrix_policy_is_keep_for_setup(s, session_name=sess, user_id=int(globals().get('AUTOTRADE_OWNER_UID', 0) or 0)):
                entry = float(getattr(s, 'entry', 0.0) or 0.0)
                sl = float(getattr(s, 'sl', 0.0) or 0.0)
                tp = float(_setup_target_tp(s, 0.0) or 0.0)
                side = str(getattr(s, 'side', '') or '').upper().strip()
                if side == 'BUY' and not (sl < entry < tp):
                    return (False, 'matrix_keep_bad_price_order')
                if side == 'SELL' and not (tp < entry < sl):
                    return (False, 'matrix_keep_bad_price_order')
                if entry <= 0 or sl <= 0 or tp <= 0:
                    return (False, 'matrix_keep_missing_prices')
                return (True, 'setup_matrix_policy_keep_source_of_truth')
        except Exception:
            pass
        try:
            policy_uid = int(globals().get('AUTOTRADE_OWNER_UID', 0) or 0)
            final_ok, final_why, _final_meta = _setup_final_quality_gate_allows_setup(s, sess, user_id=policy_uid)
            if not final_ok:
                return (False, str(final_why or 'final_quality_gate_blocked'))
        except Exception:
            return (False, 'final_quality_gate_exception')

        # yver90: AutoTrade execution is intentionally stricter than email/screen.
        # The fixed 15-May policy layer selects the best lanes; AutoTrade should not
        # spend real risk on WATCH/GATE/probation lanes while the overall WR is below target.
        if _autotrade_require_keep_policy():
            try:
                policy_uid = int(globals().get('AUTOTRADE_OWNER_UID', 0) or 0)
                pinfo = _setup_combo_policy_lookup_for_setup(s, session_name=sess, user_id=policy_uid)
                pfound = bool((pinfo or {}).get('found'))
                praw = str((pinfo or {}).get('status') or '').upper().strip()
                pstatus = _setup_policy_effective_status(praw, found=pfound)
                if pstatus not in _autotrade_allowed_policy_statuses():
                    return (False, f'autotrade_policy_not_allowed:{pstatus or praw or "WATCH"}')
            except Exception:
                return (False, 'autotrade_keep_policy_check_exception')

        # yver91: after KEEP policy passes, feed real AutoTrade combo performance
        # and the setup-audit side/session/symbol/hour context into execution selection.
        try:
            ctx_ok, ctx_reason = _autotrade_policy_context_execution_allows(s, session_name=sess, user_id=int(globals().get('AUTOTRADE_OWNER_UID', 0) or 0))
            if not ctx_ok:
                return (False, str(ctx_reason or 'autotrade_policy_context_block'))
        except Exception:
            return (False, 'autotrade_policy_context_check_exception')

        source_kind_u = str(getattr(s, "source_kind", "") or "").lower().strip()
        family_u = str(getattr(s, "family_id", "") or getattr(s, "engine", "") or "").upper().strip()
        # Rows that were already EMAILED are the authoritative execution lane.
        # Do not re-run the volatile live scanner gates here; that caused a real email
        # to be visible on /screen while AutoTrade later selected "no_setups".
        # We still enforce structural safety below: volume, prices, side, confidence and RR.
        has_rich_exec_snapshot = bool(
            source_kind_u not in {'emailed_setups', 'recent_email_cache', 'recent_email_lane'}
            and family_u not in {'F8', 'F8_BIGMOVE_CONT', 'BIGMOVE', 'BIG_MOVE'}
            and str(getattr(s, "engine", "") or "").strip()
            and float(getattr(s, "quality_score", 0.0) or 0.0) > 0.0
        )
        if has_rich_exec_snapshot:
            return is_executable_setup_eligible(s, session_name=sess)

        entry = float(getattr(s, "entry", 0.0) or 0.0)
        sl = float(getattr(s, "sl", 0.0) or 0.0)
        final_tp = float(_setup_target_tp(s, 0.0) or 0.0)
        if entry <= 0 or sl <= 0:
            return (False, "missing_prices")
        if final_tp <= 0:
            return (False, "missing_tp")
        if abs(entry - sl) <= 0:
            return (False, "zero_risk_distance")
        _, sess_conf, sess_rr = _execution_session_thresholds(sess)
        conf_floor = int(max(MIN_SETUP_CONF, sess_conf))
        conf = int(getattr(s, "conf", 0) or 0)
        if conf < conf_floor:
            return (False, "below_exec_conf")
        rr_final = float(rr_to_tp(entry, sl, final_tp)) if final_tp > 0 else 0.0
        if rr_final < float(sess_rr):
            return (False, "below_exec_rr")
        return (True, "ok")
    except Exception:
        return (False, "db_exec_validation_exception")


def _autotrade_select_db_setups(uid: int, session_label: str, lookback_hours: int = 12, limit: int = 1) -> list:
    """Return recent OPEN executable setup candidates for autotrade.

    Authoritative source of truth:
    - executable_setups = persisted executable-qualified queue
    - emailed_setups = downstream delivery state only (debug/telemetry)
    - generated_setups(source='email') = audit/debug correlation only
    """
    try:
        from types import SimpleNamespace
        lookback_hours = _autotrade_candidate_lookback_hours(float(lookback_hours or 12))
        cutoff = time.time() - float(lookback_hours) * 3600.0
        req_session_u = str(session_label or '').upper().strip()

        con = sqlite3.connect(DB_PATH)
        con.row_factory = sqlite3.Row
        cur = con.cursor()
        # yver129: AutoTrade is now email-matched by default.  The exact setup_id
        # must have a recent emailed_setups row inside AUTOTRADE_ENTRY_WINDOW_MIN.
        # This prevents AutoTrade from opening raw/fallback executable rows that
        # were never delivered to the subscriber/admin.
        require_email_entry = bool(_autotrade_require_setup_email_for_entry())
        email_cutoff = float(time.time()) - float(max(60, int(_autotrade_entry_window_min()) * 60))
        cur.execute(
            """
            SELECT x.*, COALESCE(e.emailed_ts, 0) AS emailed_ts
            FROM executable_setups x
            LEFT JOIN emailed_setups e
                   ON e.user_id = x.user_id
                  AND e.setup_id = x.setup_id
            LEFT JOIN signal_outcomes o ON o.setup_id = x.setup_id
            WHERE x.user_id = ?
              AND x.executable_ts >= ?
              AND (? = '' OR UPPER(COALESCE(x.session, '')) = ?)
              AND COALESCE(o.outcome, 'OPEN') = 'OPEN'
              AND (? = 0 OR COALESCE(e.emailed_ts, 0) >= ?)
            ORDER BY COALESCE(e.emailed_ts, x.executable_ts) DESC, x.executable_ts DESC, x.setup_id DESC
            LIMIT ?
            """,
            (int(uid), float(cutoff), req_session_u, req_session_u, 1 if require_email_entry else 0, float(email_cutoff), int(max(limit * 20, 80))),
        )
        rows = [dict(r) for r in (cur.fetchall() or [])]
        con.close()

        out = []
        selector_reject_counts = Counter()
        selector_reject_samples = []
        def _selector_reject(obj_or_row, why: str):
            try:
                reason_s = str(why or 'rejected')
                selector_reject_counts[reason_s] += 1
                if len(selector_reject_samples) < 12:
                    selector_reject_samples.append({
                        'setup_id': str((getattr(obj_or_row, 'setup_id', '') if not isinstance(obj_or_row, dict) else obj_or_row.get('setup_id', '')) or ''),
                        'symbol': str((getattr(obj_or_row, 'symbol', '') if not isinstance(obj_or_row, dict) else obj_or_row.get('symbol', '')) or ''),
                        'side': str((getattr(obj_or_row, 'side', '') if not isinstance(obj_or_row, dict) else obj_or_row.get('side', '')) or ''),
                        'source_session': str((getattr(obj_or_row, 'source_session', '') if not isinstance(obj_or_row, dict) else obj_or_row.get('session', '')) or req_session_u or ''),
                        'created_ts': float((getattr(obj_or_row, 'created_ts', 0.0) if not isinstance(obj_or_row, dict) else obj_or_row.get('created_ts', 0.0)) or 0.0),
                        'executable_ts': float((getattr(obj_or_row, 'executable_ts', 0.0) if not isinstance(obj_or_row, dict) else obj_or_row.get('executable_ts', 0.0)) or 0.0),
                        'status': 'SKIP',
                        'reason': reason_s,
                    })
            except Exception:
                pass
        for row in rows:
            try:
                item = _executable_rows_to_setup_objects([row], session_name=req_session_u)
                if not item:
                    continue
                obj = item[0]
                src_session_u = str(getattr(obj, 'source_session', '') or '').upper().strip()
                if req_session_u and src_session_u and src_session_u not in {'', req_session_u}:
                    try:
                        _admin_setup_lifecycle_merge(int(uid), str(getattr(obj, 'setup_id', '') or ''), session=src_session_u, symbol=str(getattr(obj, 'symbol', '') or ''), side=str(getattr(obj, 'side', '') or ''), state=_admin_setup_state_from_reason('session_mismatch'), last_reason=f'session_mismatch ({src_session_u}->{req_session_u})')
                    except Exception:
                        pass
                    _selector_reject(obj, f'session_mismatch:{src_session_u}->{req_session_u}')
                    continue
                now_ts = float(time.time())
                canonical_ts = float(getattr(obj, 'created_ts', 0.0) or 0.0)
                if _autotrade_require_setup_email_for_entry():
                    email_ok, email_why = _autotrade_recent_email_gate_allows_setup(int(uid), obj, session_label=req_session_u or src_session_u or session_label)
                    if not email_ok:
                        _selector_reject(obj, str(email_why or 'missing_recent_setup_email'))
                        continue
                    canonical_ts = float(getattr(obj, 'email_logged_ts', 0.0) or getattr(obj, 'emailed_ts', 0.0) or canonical_ts or 0.0)
                if canonical_ts <= 0 and _autotrade_keep_all_test_mode() and not _autotrade_require_setup_email_for_entry():
                    canonical_ts = now_ts
                    try:
                        setattr(obj, 'created_ts', now_ts)
                    except Exception:
                        pass
                expiry_grace_sec = float(max(60, int(_autotrade_entry_window_min()) * 60))
                if (canonical_ts <= 0 or (now_ts - canonical_ts) > expiry_grace_sec):
                    try:
                        _admin_setup_lifecycle_merge(int(uid), str(getattr(obj, 'setup_id', '') or ''), session=src_session_u or req_session_u, symbol=str(getattr(obj, 'symbol', '') or ''), side=str(getattr(obj, 'side', '') or ''), state=_admin_setup_state_from_reason('stale_deadline'), last_reason='stale_deadline')
                    except Exception:
                        pass
                    _selector_reject(obj, 'stale_deadline')
                    continue
                exec_ok, exec_why = _autotrade_db_signal_structurally_valid(obj, session_name=req_session_u or src_session_u or session_label)
                if not exec_ok:
                    try:
                        _admin_setup_lifecycle_merge(int(uid), str(getattr(obj, 'setup_id', '') or ''), session=src_session_u or req_session_u, symbol=str(getattr(obj, 'symbol', '') or ''), side=str(getattr(obj, 'side', '') or ''), state=_admin_setup_state_from_reason(exec_why), last_reason=str(exec_why))
                    except Exception:
                        pass
                    _selector_reject(obj, exec_why)
                    continue
                out.append(obj)
            except Exception:
                continue

        if not out:
            fallback_items = []
            try:
                fallback_items = _recent_delivery_lane_setup_objects(int(uid), session_name=req_session_u, max_age_min=max(20, int(_autotrade_entry_window_min())), limit=max(1, int(limit * 4))) or []
            except Exception:
                fallback_items = []
            for obj in (fallback_items or []):
                try:
                    src_session_u = str(getattr(obj, 'source_session', '') or '').upper().strip()
                    if req_session_u and src_session_u and src_session_u not in {'', req_session_u}:
                        continue
                    now_ts = float(time.time())
                    canonical_ts = float(getattr(obj, 'email_logged_ts', 0.0) or getattr(obj, 'emailed_ts', 0.0) or getattr(obj, 'created_ts', 0.0) or 0.0)
                    if _autotrade_require_setup_email_for_entry():
                        email_ok, email_why = _autotrade_recent_email_gate_allows_setup(int(uid), obj, session_label=req_session_u or src_session_u or session_label)
                        if not email_ok:
                            _selector_reject(obj, str(email_why or 'missing_recent_setup_email'))
                            continue
                        canonical_ts = float(getattr(obj, 'email_logged_ts', 0.0) or getattr(obj, 'emailed_ts', 0.0) or canonical_ts or 0.0)
                    if canonical_ts <= 0 and _autotrade_keep_all_test_mode() and not _autotrade_require_setup_email_for_entry():
                        canonical_ts = now_ts
                        try:
                            setattr(obj, 'created_ts', now_ts)
                        except Exception:
                            pass
                    expiry_grace_sec = float(max(60, int(_autotrade_entry_window_min()) * 60))
                    if (canonical_ts <= 0 or (now_ts - canonical_ts) > expiry_grace_sec):
                        continue
                    exec_ok, exec_why = _autotrade_db_signal_structurally_valid(obj, session_name=req_session_u or src_session_u or session_label)
                    if not exec_ok:
                        _selector_reject(obj, exec_why)
                        continue
                    out.append(obj)
                    try:
                        db_mark_executable_setup(int(uid), str(getattr(obj, 'setup_id', '') or getattr(obj, 'id', '') or ''), str(src_session_u or req_session_u or session_label), float(getattr(obj, 'email_logged_ts', 0.0) or now_ts), s=obj, source_kind=str(getattr(obj, 'source_kind', '') or 'emailed_setups'), state='executable_pending')
                    except Exception:
                        pass
                except Exception:
                    continue

        def _at_policy_rank_for_sort(x):
            try:
                pinfo = _setup_combo_policy_lookup_for_setup(x, session_name=req_session_u or str(getattr(x, 'source_session', '') or session_label), user_id=int(globals().get('AUTOTRADE_OWNER_UID', 0) or int(uid)))
                pfound = bool((pinfo or {}).get('found'))
                praw = str((pinfo or {}).get('status') or '').upper().strip()
                pstatus = _setup_policy_effective_status(praw, found=pfound)
                if pstatus == 'KEEP':
                    return 0
                if pstatus in {'WATCH', 'GATE', 'PART', 'TIGHTEN'}:
                    return 1
                return 2
            except Exception:
                return 2

        out = sorted(
            out,
            key=lambda x: (
                -int(_at_policy_rank_for_sort(x)),
                float(getattr(x, 'executable_ts', 0.0) or getattr(x, 'created_ts', 0.0) or 0.0),
                float(getattr(x, 'created_ts', 0.0) or 0.0),
                float(getattr(x, 'quality_score', 0.0) or 0.0),
                int(getattr(x, 'conf', 0) or 0),
                float(getattr(x, 'email_logged_ts', 0.0) or 0.0),
            ),
            reverse=True,
        )[:max(1, int(limit))]
        if out:
            try:
                for item in out:
                    _admin_setup_lifecycle_merge(
                        int(uid),
                        str(getattr(item, 'setup_id', '') or getattr(item, 'id', '') or ''),
                        session=str(getattr(item, 'source_session', '') or session_label or ''),
                        symbol=str(getattr(item, 'symbol', '') or ''),
                        side=str(getattr(item, 'side', '') or ''),
                        executable_ts=float(getattr(item, 'executable_ts', 0.0) or getattr(item, 'created_ts', 0.0) or time.time()),
                        state='executable_pending',
                        source_kind=str(getattr(item, 'source_kind', '') or 'executable_setups'),
                        signal_created_ts=float(getattr(item, 'signal_created_ts', 0.0) or 0.0),
                        emailed_ts=float(getattr(item, 'email_logged_ts', 0.0) or 0.0),
                        generated_logged_ts=float(getattr(item, 'generated_logged_ts', 0.0) or 0.0),
                    )
            except Exception:
                pass
        try:
            _LAST_AUTOTRADE_SELECTOR_REJECTS[int(uid)] = {
                'when': datetime.now(timezone.utc).isoformat(timespec='seconds'),
                'session': req_session_u,
                'scanned': len(rows or []),
                'selected': len(out or []),
                'top_reasons': dict(selector_reject_counts.most_common(10)),
                'samples': list(selector_reject_samples or []),
            }
        except Exception:
            pass
        return out
    except Exception as e:
        try:
            logger.error(f"_autotrade_select_db_setups failed: {type(e).__name__}: {e}")
        except Exception:
            pass
        return []




def _autotrade_candidate_dedupe_key(setup) -> tuple:
    """Practical candidate identity for AutoTrade queue merging."""
    try:
        return (
            str(getattr(setup, 'setup_id', '') or getattr(setup, 'id', '') or '').strip(),
            str(getattr(setup, 'symbol', '') or '').upper().strip(),
            str(getattr(setup, 'side', '') or '').upper().strip(),
            round(float(getattr(setup, 'entry', 0.0) or 0.0), 10),
            round(float(getattr(setup, 'sl', 0.0) or 0.0), 10),
        )
    except Exception:
        return (str(getattr(setup, 'setup_id', '') or getattr(setup, 'id', '') or ''), str(getattr(setup, 'symbol', '') or ''), str(getattr(setup, 'side', '') or ''))


def _autotrade_merge_candidate_lists_fresh_first(*lists, limit: int = 60) -> list:
    """Merge candidate lists, preserving order and avoiding duplicate setup/price rows."""
    out = []
    seen_exact = set()
    seen_setup_id = set()
    for items in lists:
        for item in list(items or []):
            try:
                sid = str(getattr(item, 'setup_id', '') or getattr(item, 'id', '') or '').strip()
                key = _autotrade_candidate_dedupe_key(item)
                if sid and sid in seen_setup_id:
                    continue
                if key in seen_exact:
                    continue
                seen_exact.add(key)
                if sid:
                    seen_setup_id.add(sid)
                out.append(item)
                if int(limit or 0) > 0 and len(out) >= int(limit):
                    return out
            except Exception:
                continue
    return out


def _autotrade_select_fresh_session_executable_setups(uid: int, session_label: str, window_min: int | None = None, limit: int | None = None) -> list:
    """Return fresh current-session executable rows and keep all live safety checks downstream."""
    try:
        owner_uid = int(uid or 0)
    except Exception:
        owner_uid = 0
    sess = str(session_label or '').upper().strip()
    if owner_uid <= 0 or sess not in {'ASIA', 'LON', 'NY'}:
        return []
    # yver129: when AutoTrade is synced to subscriber delivery, the broad fresh
    # executable queue is not an entry source. The normal DB selector already
    # returns recent emailed setup_ids only.
    try:
        if _autotrade_require_setup_email_for_entry():
            return []
    except Exception:
        return []
    if not bool(globals().get('AUTOTRADE_FRESH_SESSION_QUEUE_ENABLED', True)):
        return []
    try:
        win_min = int(window_min if window_min is not None else globals().get('AUTOTRADE_FRESH_SESSION_QUEUE_WINDOW_MIN', 150))
    except Exception:
        win_min = 150
    win_min = max(20, min(480, int(win_min or 150)))
    try:
        lim = int(limit if limit is not None else globals().get('AUTOTRADE_FRESH_SESSION_QUEUE_LIMIT', 60))
    except Exception:
        lim = 60
    lim = max(10, min(120, int(lim or 60)))
    cutoff = float(time.time()) - float(win_min) * 60.0
    rows = []
    try:
        con = sqlite3.connect(DB_PATH)
        con.row_factory = sqlite3.Row
        cur = con.cursor()
        cur.execute(
            """
            SELECT x.*, COALESCE(e.emailed_ts, 0) AS emailed_ts
            FROM executable_setups x
            LEFT JOIN emailed_setups e
                   ON e.user_id = x.user_id
                  AND e.setup_id = x.setup_id
            LEFT JOIN signal_outcomes o ON o.setup_id = x.setup_id
            WHERE x.user_id = ?
              AND x.executable_ts >= ?
              AND UPPER(COALESCE(x.session, '')) = ?
              AND COALESCE(o.outcome, 'OPEN') = 'OPEN'
            ORDER BY x.executable_ts DESC, x.setup_id DESC
            LIMIT ?
            """,
            (int(owner_uid), float(cutoff), sess, int(lim * 2)),
        )
        rows = [dict(r) for r in (cur.fetchall() or [])]
        con.close()
    except Exception as e:
        try:
            db_log_setup_pipeline_event(owner_uid, stage='autotrade_fresh_queue', status='error', session=sess, mode='autotrade', details={'error': f'{type(e).__name__}: {e}'})
        except Exception:
            pass
        return []

    out = []
    rejects = Counter()
    for row in rows:
        try:
            objs = _executable_rows_to_setup_objects([row], session_name=sess)
            if not objs:
                continue
            obj = objs[0]
            ok, why = _autotrade_db_signal_structurally_valid(obj, session_name=sess)
            if ok:
                out.append(obj)
            else:
                rejects[str(why or 'blocked')] += 1
        except Exception as e:
            rejects[f'exception:{type(e).__name__}'] += 1
            continue
    try:
        db_log_setup_pipeline_event(owner_uid, stage='autotrade_fresh_queue', status='ok' if out else 'empty', session=sess, mode='autotrade', details={'window_min': int(win_min), 'scanned': len(rows or []), 'selected': len(out or []), 'top_rejects': _pipeline_top_reasons(rejects, 6)})
    except Exception:
        pass
    return _autotrade_merge_candidate_lists_fresh_first(out, limit=lim)


def _autotrade_select_db_setups_cached(uid: int, session_label: str, lookback_hours: int = 12, limit: int = 1, ttl: int = 15, force_refresh: bool = False) -> list:
    lookback_hours = _autotrade_candidate_lookback_hours(float(lookback_hours or 12))
    cache_key = f"autotrade_db_setups_v129:{int(uid)}:{str(session_label or '').upper().strip()}:{int(lookback_hours or 12)}:{int(limit or 1)}"
    ttl_i = max(3, int(ttl or 15))
    try:
        if (not force_refresh) and cache_valid(cache_key, ttl_i):
            cached = cache_get(cache_key)
            if isinstance(cached, list):
                return list(cached)
        out = _autotrade_select_db_setups(int(uid), session_label, lookback_hours=int(lookback_hours or 12), limit=int(limit or 1))
        cache_set(cache_key, list(out or []))
        return list(out or [])
    except Exception:
        stale = cache_get(cache_key)
        return list(stale or []) if isinstance(stale, list) else []
def _autotrade_refresh_owner_executable_pool(uid: int, session_label: str, lookback_hours: int = 12) -> list:
    """Best-effort self-refresh of the owner's executable pool.

    This keeps autotrade independent from the email loop and /screen.
    If the persisted executable queue is empty or stale, rebuild the current
    executable pool for the owner directly from the live market snapshot,
    persist it, then re-read the same authoritative queue.
    """
    try:
        owner_uid = int(uid or 0)
    except Exception:
        owner_uid = 0
    sess = str(session_label or '').upper().strip()
    if owner_uid <= 0 or sess not in {'ASIA', 'LON', 'NY'}:
        return []
    # yver129: AutoTrade entries are email-matched. Do not self-refresh and
    # open raw executable rows that were not sent to subscribers.
    try:
        if _autotrade_require_setup_email_for_entry():
            return []
    except Exception:
        return []
    now_ts = float(time.time())
    try:
        existing_rows = db_list_executable_setups(owner_uid, session_name=sess, ts_from=float(now_ts - float(MAX_STALE_SCAN_SEC)), limit=6)
    except Exception:
        existing_rows = []
    if existing_rows:
        try:
            return _autotrade_select_db_setups(owner_uid, sess, lookback_hours=lookback_hours, limit=30)
        except Exception:
            return []

    try:
        best_fut = fetch_futures_tickers() or {}
    except Exception as e:
        try:
            db_log_setup_pipeline_event(owner_uid, stage='autotrade_exec_refresh', status='error', session=sess, mode='autotrade', details={'step': 'fetch_futures_tickers', 'error': f'{type(e).__name__}: {e}'})
        except Exception:
            pass
        return []
    if not best_fut:
        try:
            db_log_setup_pipeline_event(owner_uid, stage='autotrade_exec_refresh', status='empty', session=sess, mode='autotrade', details={'step': 'fetch_futures_tickers'})
        except Exception:
            pass
        return []

    try:
        pool = _run_coro_in_thread(
            build_priority_pool(
                best_fut,
                sess,
                mode='exec',
                scan_profile=str(DEFAULT_SCAN_PROFILE),
                uid=owner_uid,
            )
        ) or {}
    except Exception as e:
        try:
            db_log_setup_pipeline_event(owner_uid, stage='autotrade_exec_refresh', status='error', session=sess, mode='autotrade', details={'step': 'build_priority_pool', 'error': f'{type(e).__name__}: {e}'})
        except Exception:
            pass
        return []

    raw_pool = list((pool or {}).get('setups') or [])
    executable_ready = []
    reject_counts = Counter()
    for s in (raw_pool or []):
        try:
            s_eff = _setup_route_candidate_for_executable_lane(s, sess, owner_uid)
            ok, why = is_executable_setup_eligible(s_eff, session_name=sess)
        except Exception:
            s_eff = s
            ok, why = False, 'autotrade_exec_gate_exception'
        if ok:
            executable_ready.append(s_eff)
        else:
            reject_counts[str(why)] += 1

    persisted = 0
    if executable_ready:
        try:
            stats = _persist_executable_candidates(owner_uid, sess, executable_ready, source_kind='executable_setups', mode='autotrade') or {}
            persisted = int(stats.get('persisted') or 0)
        except Exception as e:
            try:
                db_log_setup_pipeline_event(owner_uid, stage='autotrade_exec_refresh', status='error', session=sess, mode='autotrade', details={'step': 'persist_executable', 'error': f'{type(e).__name__}: {e}', 'raw_pool': len(raw_pool), 'eligible': len(executable_ready)})
            except Exception:
                pass
            return []

    try:
        db_log_setup_pipeline_event(
            owner_uid,
            stage='autotrade_exec_refresh',
            status='ok' if executable_ready else 'empty',
            session=sess,
            mode='autotrade',
            details={
                'raw_pool': len(raw_pool),
                'eligible': len(executable_ready),
                'persisted': persisted,
                'top_exec_rejects': _pipeline_top_reasons(reject_counts, 5),
            },
        )
    except Exception:
        pass

    try:
        return _autotrade_select_db_setups(owner_uid, sess, lookback_hours=lookback_hours, limit=30)
    except Exception:
        return []

def _autotrade_clear_debug_state(uid: int | None = None) -> None:
    """Clear in-memory autotrade debug state. If uid is None, clears all."""
    global _LAST_AUTOTRADE_DECISION, _LAST_AUTOTRADE_DETAIL, _LAST_AUTOTRADE_ATTEMPTS
    try:
        if uid is None:
            _LAST_AUTOTRADE_DECISION.clear()
            _LAST_AUTOTRADE_DETAIL.clear()
            _LAST_AUTOTRADE_ATTEMPTS.clear()
        else:
            _LAST_AUTOTRADE_DECISION.pop(int(uid), None)
            _LAST_AUTOTRADE_DETAIL.pop(int(uid), None)
            _LAST_AUTOTRADE_ATTEMPTS.pop(int(uid), None)
    except Exception:
        pass


def _autotrade_setup_attr(setup, name: str, default=None):
    try:
        if isinstance(setup, dict):
            return setup.get(name, default)
        return getattr(setup, name, default)
    except Exception:
        return default


def _autotrade_setup_float(setup, name: str, default: float = 0.0) -> float:
    try:
        v = _autotrade_setup_attr(setup, name, default)
        f = float(v if v is not None else default)
        if math.isnan(f) or math.isinf(f):
            return float(default)
        return float(f)
    except Exception:
        return float(default)


def _autotrade_setup_family_code(setup) -> str:
    try:
        fam = str(_autotrade_setup_attr(setup, 'family_id', '') or '').upper().strip()
        if fam:
            m = re.search(r'F\d+', fam)
            if m:
                return m.group(0)
        eng = str(_autotrade_setup_attr(setup, 'engine', '') or '').upper().strip()
        aliases = {'A': 'F1', 'B': 'F2', 'C': 'F3', 'ENGINE_A': 'F1', 'ENGINE_B': 'F2', 'ENGINE_C': 'F3'}
        if eng in aliases:
            return aliases[eng]
        m = re.search(r'F\d+', eng)
        if m:
            return m.group(0)
    except Exception:
        pass
    return 'F0'


def _autotrade_setup_rr(setup) -> float:
    try:
        entry = float(_autotrade_setup_attr(setup, 'entry', 0.0) or 0.0)
        sl = float(_autotrade_setup_attr(setup, 'sl', 0.0) or 0.0)
        side = str(_autotrade_setup_attr(setup, 'side', '') or '').upper().strip()
        tp = _resolve_single_tp(
            entry,
            sl,
            _autotrade_setup_attr(setup, 'tp', None),
            _autotrade_setup_attr(setup, 'alt_target_a', None),
            _autotrade_setup_attr(setup, 'alt_target_b', None),
            side,
        )
        risk = abs(entry - sl)
        reward = abs(float(tp or 0.0) - entry)
        if entry <= 0 or risk <= 0 or reward <= 0:
            return 0.0
        return float(reward / risk)
    except Exception:
        return 0.0


def _autotrade_risk_metric_component(metrics: dict | None, key: str, label: str, max_abs: float, min_decided: int = 2) -> tuple[float, str | None]:
    try:
        m = dict((metrics or {}).get(str(key or '').upper().strip()) or {})
        dec = int(m.get('decided') or 0)
        if dec < int(min_decided):
            return 0.0, None
        wr = float(m.get('wr') or 0.0)
        avg_r = float(m.get('avg_r') or 0.0)
        raw = (wr - 50.0) * 0.22 + avg_r * 10.0 + min(12, dec) * 0.25
        comp = float(_clamp(raw, -abs(float(max_abs)), abs(float(max_abs))))
        return comp, f"{label}:{wr:.0f}%/{avg_r:+.2f}R/n{dec}={comp:+.1f}"
    except Exception:
        return 0.0, None


def _autotrade_dynamic_risk_score(uid: int, setup, session_name: str = '', regime: str = 'UNKNOWN') -> dict:
    """Score one setup for AutoTrade risk sizing.

    The score intentionally combines signal quality and live edge evidence:
    confidence/quality, family, session, side, symbol, Melbourne hour, RR,
    liquidity, trend regime and current entry drift. It returns a bounded
    multiplier that scales the user's configured AutoTrade base risk.
    """
    try:
        min_mult, max_mult, low_score, base_score, high_score = _autotrade_dynamic_risk_bounds()
        enabled = bool(_autotrade_dynamic_risk_enabled())
        if not enabled:
            return {
                'enabled': False, 'score': float(base_score), 'multiplier': 1.0,
                'components': ['dynamic_risk_disabled'], 'bounds': {'min_mult': min_mult, 'max_mult': max_mult, 'low_score': low_score, 'base_score': base_score, 'high_score': high_score},
            }

        conf = int(float(_autotrade_setup_attr(setup, 'conf', 0) or 0))
        q = float(_autotrade_setup_attr(setup, 'quality_score', 0.0) or 0.0)
        exec_score = float(_autotrade_setup_attr(setup, 'exec_score', 0.0) or 0.0)
        family_score = float(_autotrade_setup_attr(setup, 'family_score', 0.0) or 0.0)
        side = str(_autotrade_setup_attr(setup, 'side', '') or '').upper().strip()
        fam = _autotrade_setup_family_code(setup)
        sess = str(session_name or _autotrade_setup_attr(setup, 'session', '') or _autotrade_setup_attr(setup, 'source_session', '') or '').upper().strip() or '-'
        sym = str(_autotrade_setup_attr(setup, 'symbol', '') or _autotrade_setup_attr(setup, 'market_symbol', '') or '').upper().strip()
        if sym.endswith('USDT'):
            sym = sym[:-4]
        created_ts = float(_autotrade_setup_attr(setup, 'executable_ts', 0.0) or _autotrade_setup_attr(setup, 'created_ts', 0.0) or _autotrade_setup_attr(setup, 'signal_created_ts', 0.0) or time.time())
        hour = datetime.fromtimestamp(created_ts, tz=timezone.utc).astimezone(MEL_TZ).strftime('%H:00') if created_ts > 0 else '-'
        reg = str(regime or _autotrade_setup_attr(setup, 'regime_primary', '') or 'UNKNOWN').upper().strip()
        rr = _autotrade_setup_rr(setup)
        vol_usd = float(_autotrade_setup_attr(setup, 'fut_vol_usd', 0.0) or 0.0)
        vol_m = vol_usd / 1_000_000.0 if vol_usd > 0 else 0.0
        ch1 = float(_autotrade_setup_attr(setup, 'ch1', 0.0) or 0.0)
        ch4 = float(_autotrade_setup_attr(setup, 'ch4', 0.0) or 0.0)
        ch15 = float(_autotrade_setup_attr(setup, 'ch15', 0.0) or 0.0)

        score = 50.0
        components: list[str] = []

        c_comp = float(_clamp((conf - 80.0) * 0.70, -15.0, 16.0))
        score += c_comp
        components.append(f"conf{conf}={c_comp:+.1f}")

        if q > 0:
            q_comp = float(_clamp((q - 70.0) * 0.45, -12.0, 14.0))
            score += q_comp
            components.append(f"quality{q:.0f}={q_comp:+.1f}")
        elif exec_score > 0:
            e_comp = float(_clamp((exec_score - 70.0) * 0.35, -8.0, 10.0))
            score += e_comp
            components.append(f"exec{exec_score:.0f}={e_comp:+.1f}")

        if family_score:
            fsc_comp = float(_clamp(float(family_score) * 0.08, -6.0, 6.0))
            score += fsc_comp
            components.append(f"family_score={fsc_comp:+.1f}")

        if rr > 0:
            if rr >= 2.0:
                rr_comp = 8.0
            elif rr >= 1.55:
                rr_comp = 5.0
            elif rr >= 1.35:
                rr_comp = 1.5
            elif rr < 1.10:
                rr_comp = -12.0
            elif rr < 1.25:
                rr_comp = -6.0
            else:
                rr_comp = -2.0
            score += rr_comp
            components.append(f"RR{rr:.2f}={rr_comp:+.1f}")

        if vol_m > 0:
            if vol_m >= 200:
                v_comp = 5.0
            elif vol_m >= 75:
                v_comp = 3.0
            elif vol_m >= 25:
                v_comp = 1.0
            elif vol_m < 15:
                v_comp = -8.0
            elif vol_m < 20:
                v_comp = -5.0
            else:
                v_comp = -1.0
            score += v_comp
            components.append(f"vol{vol_m:.0f}M={v_comp:+.1f}")

        # Directional momentum alignment check.
        try:
            if side == 'BUY':
                agree = sum(1 for x in (ch15, ch1, ch4) if float(x) > 0)
                oppose = sum(1 for x in (ch15, ch1, ch4) if float(x) < 0)
            elif side == 'SELL':
                agree = sum(1 for x in (ch15, ch1, ch4) if float(x) < 0)
                oppose = sum(1 for x in (ch15, ch1, ch4) if float(x) > 0)
            else:
                agree = oppose = 0
            mom_comp = float(_clamp((agree - oppose) * 2.0, -6.0, 6.0))
            if mom_comp:
                score += mom_comp
                components.append(f"mom_align={mom_comp:+.1f}")
        except Exception:
            pass

        # Family/regime nudges. These are small because the edge matrix provides the main evidence.
        fam_comp = 0.0
        if fam == 'F8':
            fam_comp += 5.0 if reg in {'TRENDING', 'EXPANSION', 'VOLATILE'} else -4.0 if reg == 'RANGING' else 2.0
        elif fam == 'F3':
            fam_comp += 3.0 if reg in {'TRENDING', 'NORMAL', 'EXPANSION'} else -2.0 if reg == 'VOLATILE' else 1.0
        elif fam == 'F2':
            fam_comp += 2.0 if reg in {'TRENDING', 'EXPANSION'} else -5.0 if reg in {'RANGING', 'VOLATILE'} else 0.0
        elif fam == 'F1':
            fam_comp += 2.0 if reg in {'RANGING', 'NORMAL'} else -1.0 if reg == 'TRENDING' else 0.0
        if side == 'SELL':
            fam_comp += 1.5
        elif side == 'BUY':
            fam_comp -= 1.5
        fam_comp = float(_clamp(fam_comp, -8.0, 8.0))
        if fam_comp:
            score += fam_comp
            components.append(f"{fam}/{reg}/{side}={fam_comp:+.1f}")

        # Live learned edge evidence from the same executable audit lane used by /setup_matrix.
        data = _setup_edge_guard_build(int(uid or 0), hours=int(globals().get('SETUP_EDGE_GUARD_WINDOW_HOURS', 168) or 168), force=False)
        strategy_short = _setup_strategy_suffix(setup)
        combo_strategy_side = _setup_combo_strategy_side_key(fam, sess, strategy_short, side)
        combo_side = f'{fam}-{sess}-{side}'
        combo = f'{fam}-{sess}'
        combo_strategy = _setup_combo_strategy_key(fam, sess, strategy_short)
        for metrics_key, key, label, max_abs, min_dec in [
            ('combo_strategy_side_metrics', combo_strategy_side, 'strategy_side', 24.0, 3),
            ('combo_strategy_metrics', combo_strategy, 'strategy_combo', 16.0, 3),
            ('combo_side_metrics', combo_side, 'legacy_combo_side', 8.0, 5),
            ('combo_metrics', combo, 'legacy_combo', 6.0, 5),
            ('side_metrics', side, 'side', 12.0, 8),
            ('family_metrics', fam, 'family', 10.0, 6),
            ('session_metrics', sess, 'session', 8.0, 6),
            ('symbol_metrics', sym, 'symbol', 10.0, 2),
            ('hour_metrics', hour, 'hour', 7.0, 3),
        ]:
            comp, text = _autotrade_risk_metric_component((data or {}).get(metrics_key) or {}, key, label, max_abs, min_dec)
            if comp:
                score += comp
                if text:
                    components.append(text)

        # Explicit guard hits are strong de-risk signals. They should normally be blocked
        # before AutoTrade, but this keeps sizing safe if a stale setup slips through.
        if combo_strategy_side in dict((data or {}).get('combo_strategy_side_block') or (data or {}).get('combo_side_block') or {}):
            score -= 30.0
            components.append(f"guard_strategy_side_block={combo_strategy_side}:-30")
        if sym and sym in dict((data or {}).get('symbol_block') or {}):
            score -= 25.0
            components.append(f"guard_symbol_block={sym}:-25")
        if hour in dict((data or {}).get('hour_watch') or {}) and fam in {'F1', 'F2', 'F6'}:
            score -= 8.0
            components.append(f"weak_hour_{hour}:{fam}=-8")

        try:
            det = dict(_LAST_AUTOTRADE_DETAIL.get(int(uid), {}) or {})
            adverse = float(det.get('entry_drift_adverse_pct') or 0.0)
            if adverse >= 1.0:
                score -= 8.0
                components.append(f"adverse_drift{adverse:.2f}%=-8")
            elif adverse >= 0.5:
                score -= 4.0
                components.append(f"adverse_drift{adverse:.2f}%=-4")
        except Exception:
            pass

        unclamped_score = float(score)
        score = float(_clamp(score, 0.0, 100.0))
        if score >= base_score:
            mult = 1.0 + ((score - base_score) / max(1.0, high_score - base_score)) * (max_mult - 1.0)
        else:
            mult = 1.0 - ((base_score - score) / max(1.0, base_score - low_score)) * (1.0 - min_mult)
        mult = float(_clamp(mult, min_mult, max_mult))

        # yver81: WR-tier dynamic risk on the configured base risk.
        # The owner wants dynamic risk to multiply the configured base risk regardless
        # of whether the base is 0.30%, 0.60%, 1.00%, etc.  Therefore the old absolute
        # 0.35%/0.50% caps are removed.  Exact lane evidence now controls the multiplier:
        #   pass/min edge              -> 1.00x base risk
        #   exact lane WR >= 60%       -> mid tier (~1.25x when max_mult=1.50)
        #   exact lane WR >= 70%       -> configured max tier (1.50x by default)
        # AvgR must still pass the configured strict-edge minimum so high-WR/poor-payoff
        # lanes do not get oversized.
        evidence_dec = 0
        evidence_wr = 0.0
        evidence_avg = 0.0
        evidence_target_mult = 1.0
        try:
            exact_m = dict(((data or {}).get('combo_strategy_side_metrics') or {}).get(str(combo_strategy_side or '').upper().strip()) or {})
            evidence_dec = int(exact_m.get('decided') or 0)
            evidence_wr = float(exact_m.get('wr') or 0.0)
            evidence_avg = float(exact_m.get('avg_r') or 0.0)
            try:
                min_dec_for_risk = max(1, int(_autotrade_strict_keep_edge_min_decided()))
            except Exception:
                min_dec_for_risk = 3
            try:
                min_wr_for_base = float(_autotrade_strict_keep_edge_min_wr())
            except Exception:
                min_wr_for_base = 49.0
            try:
                min_avg_for_base = float(_autotrade_strict_keep_edge_min_avgr())
            except Exception:
                min_avg_for_base = 0.05

            high_mult = max(1.0, float(max_mult))
            mid_mult = 1.0 + ((high_mult - 1.0) * 0.50)  # default max 1.50 -> mid 1.25
            lane_passes_min_edge = (
                evidence_dec >= min_dec_for_risk
                and evidence_wr >= min_wr_for_base
                and evidence_avg >= min_avg_for_base
            )
            if lane_passes_min_edge and evidence_wr >= 70.0:
                evidence_target_mult = high_mult
                components.append(f"risk_tier:WR{evidence_wr:.1f}/AvgR{evidence_avg:+.2f}/n{evidence_dec}->max_mult_{high_mult:.2f}x")
            elif lane_passes_min_edge and evidence_wr >= 60.0:
                evidence_target_mult = min(high_mult, mid_mult)
                components.append(f"risk_tier:WR{evidence_wr:.1f}/AvgR{evidence_avg:+.2f}/n{evidence_dec}->mid_mult_{evidence_target_mult:.2f}x")
            elif lane_passes_min_edge:
                evidence_target_mult = 1.0
                components.append(f"risk_tier:WR{evidence_wr:.1f}/AvgR{evidence_avg:+.2f}/n{evidence_dec}->base_1.00x")
            else:
                evidence_target_mult = 1.0
                components.append(f"risk_tier:no_boost:WR{evidence_wr:.1f}/AvgR{evidence_avg:+.2f}/n{evidence_dec}")

            # v81: use the exact lane WR tier as the dynamic multiplier.  The raw
            # composite score remains stored for diagnostics, but it no longer imposes
            # an absolute risk-dollar cap or blocks WR-tier boosts above the base.
            mult = float(_clamp(float(evidence_target_mult), 1.0, float(max_mult)))
        except Exception as _tier_exc:
            components.append(f"risk_tier_error:{type(_tier_exc).__name__}")
            mult = float(_clamp(float(mult), 1.0, float(max_mult)))
        return {
            'enabled': True,
            'score': float(score),
            'unclamped_score': float(unclamped_score),
            'multiplier': float(mult),
            'components': components[:22],
            'edge_decided': int(evidence_dec),
            'edge_wr': float(evidence_wr),
            'edge_avg_r': float(evidence_avg),
            'edge_target_mult': float(evidence_target_mult),
            'family': fam,
            'session': sess,
            'side': side,
            'symbol': sym,
            'hour': hour,
            'regime': reg,
            'rr': float(rr),
            'volume_m': float(vol_m),
            'bounds': {'min_mult': min_mult, 'max_mult': max_mult, 'low_score': low_score, 'base_score': base_score, 'high_score': high_score},
        }
    except Exception as exc:
        min_mult, max_mult, low_score, base_score, high_score = _autotrade_dynamic_risk_bounds()
        return {
            'enabled': bool(_autotrade_dynamic_risk_enabled()), 'score': float(base_score), 'multiplier': 1.0,
            'components': [f'dynamic_risk_error:{type(exc).__name__}'],
            'bounds': {'min_mult': min_mult, 'max_mult': max_mult, 'low_score': low_score, 'base_score': base_score, 'high_score': high_score},
        }


def _autotrade_effective_risk_usd(uid: int, setup, equity: float, base_risk_usd: float, remaining_risk_usd: float, open_risk_usd: float, daily_cap_usd: float, session_name: str = '') -> tuple[float, float, str]:
    """Return (effective_risk_usd, multiplier, regime).

    Ver03 dynamic risk model:
    - /autotrade_config AUTOTRADE_RISK_PER_TRADE_PCT remains the base risk.
    - Each setup receives a composite risk score from confidence, RR, volume,
      family/session/side/symbol/hour edge, regime and entry drift.
    - Score maps to a bounded multiplier, default 0.50x..1.50x.
    - Daily/open caps and post-fill risk controls still cap the final size.
    """
    try:
        market_symbol = str(getattr(setup, 'market_symbol', '') or getattr(setup, 'symbol', '') or '')
        regime = str(getattr(setup, 'regime_primary', '') or '').upper().strip() or 'UNKNOWN'
        if regime in {'', '-', 'NONE', 'UNKNOWN'}:
            try:
                c1 = fetch_ohlcv(market_symbol, "1h", 60)
                regime = pf_market_regime(c1[-30:] if c1 else c1)
            except Exception:
                regime = 'UNKNOWN'

        score_info = _autotrade_dynamic_risk_score(uid=int(uid or 0), setup=setup, session_name=session_name, regime=regime)
        mult = float(score_info.get('multiplier') or 1.0)
        target_risk = max(0.0, float(base_risk_usd) * float(mult))

        if daily_cap_usd > 0:
            cap_left = max(0.0, float(daily_cap_usd) - max(0.0, float(open_risk_usd)))
            target_risk = min(target_risk, cap_left)

        if remaining_risk_usd >= 0:
            target_risk = min(target_risk, float(remaining_risk_usd))

        try:
            _LAST_AUTOTRADE_DETAIL.setdefault(int(uid), {})
            _LAST_AUTOTRADE_DETAIL[int(uid)].update({
                'dynamic_risk_enabled': bool(score_info.get('enabled')),
                'dynamic_risk_score': float(score_info.get('score') or 0.0),
                'dynamic_risk_unclamped_score': float(score_info.get('unclamped_score') or score_info.get('score') or 0.0),
                'dynamic_risk_components': list(score_info.get('components') or []),
                'dynamic_risk_bounds': dict(score_info.get('bounds') or {}),
                'dynamic_risk_family': str(score_info.get('family') or ''),
                'dynamic_risk_session': str(score_info.get('session') or session_name or ''),
                'dynamic_risk_side': str(score_info.get('side') or ''),
                'dynamic_risk_hour': str(score_info.get('hour') or ''),
                'dynamic_risk_rr': float(score_info.get('rr') or 0.0),
                'dynamic_risk_edge_decided': int(score_info.get('edge_decided') or 0),
                'dynamic_risk_edge_wr': float(score_info.get('edge_wr') or 0.0),
                'dynamic_risk_edge_avg_r': float(score_info.get('edge_avg_r') or 0.0),
                'dynamic_risk_edge_target_mult': float(score_info.get('edge_target_mult') or 0.0),
            })
        except Exception:
            pass
        return (max(0.0, float(target_risk)), float(mult), str(regime or 'UNKNOWN').upper())
    except Exception:
        return (max(0.0, float(base_risk_usd or 0.0)), 1.0, 'UNKNOWN')



def _autotrade_clone_setup_for_execution(setup, **overrides):
    """Return a setup-like object with execution prices updated.

    Some DB/email hydrated candidates are SimpleNamespace objects, not dataclass Setup
    instances. dataclasses.replace() raises TypeError on those objects, which previously
    opened a live Bybit position and then crashed before writing the autotrade journal.
    """
    try:
        fields = getattr(setup, '__dataclass_fields__', None)
        if fields:
            safe = {k: v for k, v in (overrides or {}).items() if k in fields}
            return replace(setup, **safe)
    except Exception:
        pass
    try:
        data = dict(getattr(setup, '__dict__', {}) or {})
    except Exception:
        data = {}
    # Minimum attributes needed by _autotrade_db_add_trade and reporting.
    defaults = {
        'setup_id': str(getattr(setup, 'setup_id', '') or getattr(setup, 'id', '') or ''),
        'id': str(getattr(setup, 'setup_id', '') or getattr(setup, 'id', '') or ''),
        'symbol': str(getattr(setup, 'symbol', '') or ''),
        'market_symbol': str(getattr(setup, 'market_symbol', '') or ''),
        'side': str(getattr(setup, 'side', '') or ''),
        'conf': int(getattr(setup, 'conf', 0) or 0),
        'entry': float(getattr(setup, 'entry', 0.0) or 0.0),
        'sl': float(getattr(setup, 'sl', 0.0) or 0.0),
        'tp': float(_setup_target_tp(setup, 0.0) or 0.0),
        'alt_target_a': 0.0,
        'alt_target_b': 0.0,
        'fut_vol_usd': float(getattr(setup, 'fut_vol_usd', 0.0) or 0.0),
        'ch24': float(getattr(setup, 'ch24', 0.0) or 0.0),
        'ch4': float(getattr(setup, 'ch4', 0.0) or 0.0),
        'ch1': float(getattr(setup, 'ch1', 0.0) or 0.0),
        'ch15': float(getattr(setup, 'ch15', 0.0) or 0.0),
        'quality_score': float(getattr(setup, 'quality_score', 0.0) or 0.0),
        'atr_pct': float(getattr(setup, 'atr_pct', 0.0) or 0.0),
        'engine': str(getattr(setup, 'engine', '') or ''),
        'created_ts': float(getattr(setup, 'created_ts', 0.0) or time.time()),
        'family_id': str(getattr(setup, 'family_id', '') or ''),
        'regime_primary': str(getattr(setup, 'regime_primary', '') or ''),
        'allocator_plan_id': str(getattr(setup, 'allocator_plan_id', '') or ''),
        'param_set_id': str(getattr(setup, 'param_set_id', '') or ''),
    }
    for k, v in defaults.items():
        data.setdefault(k, v)
    data.update(overrides or {})
    try:
        from types import SimpleNamespace
        return SimpleNamespace(**data)
    except Exception:
        return setup


def _autotrade_attempts_migrate() -> None:
    """Persist AutoTrade attempt diagnostics for /autotrade_last.

    Older versions only kept attempts in process memory, so /autotrade_last lost
    rows after restart and could show only a handful of recent rejects.  This table
    is diagnostic-only and does not affect execution/risk logic.
    """
    try:
        with sqlite3.connect(DB_PATH) as conn:
            c = conn.cursor()
            c.execute("""CREATE TABLE IF NOT EXISTS autotrade_attempts (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                uid INTEGER NOT NULL DEFAULT 0,
                when_ts REAL NOT NULL DEFAULT 0,
                when_iso TEXT NOT NULL DEFAULT '',
                setup_id TEXT NOT NULL DEFAULT '',
                symbol TEXT NOT NULL DEFAULT '',
                side TEXT NOT NULL DEFAULT '',
                status TEXT NOT NULL DEFAULT '',
                reason TEXT NOT NULL DEFAULT '',
                entry REAL,
                sl REAL,
                drift_pct REAL,
                drift_direction TEXT NOT NULL DEFAULT '',
                risk_pct REAL,
                payload_json TEXT NOT NULL DEFAULT ''
            )""")
            c.execute("CREATE INDEX IF NOT EXISTS idx_autotrade_attempts_uid_ts ON autotrade_attempts(uid, when_ts DESC)")
            conn.commit()
    except Exception:
        pass


def _autotrade_attempt_ts(row: dict) -> float:
    try:
        w = str((row or {}).get('when') or (row or {}).get('when_iso') or '').strip()
        if w:
            return float(datetime.fromisoformat(w.replace('Z', '+00:00')).timestamp())
    except Exception:
        pass
    try:
        return float((row or {}).get('when_ts') or 0.0)
    except Exception:
        return 0.0


def _autotrade_persist_attempt_row(uid: int, row: dict) -> None:
    try:
        _autotrade_attempts_migrate()
        rr = dict(row or {})
        when_iso = str(rr.get('when') or rr.get('when_iso') or datetime.now(timezone.utc).isoformat(timespec='seconds'))
        when_ts = _autotrade_attempt_ts({'when': when_iso}) or time.time()
        sym = str(rr.get('symbol') or rr.get('symbol_sent') or rr.get('symbol_raw') or '').upper().strip()
        if sym.endswith('USDT'):
            sym = sym[:-4]
        side = str(rr.get('side') or '').upper().strip()
        status = str(rr.get('status') or '').upper().strip()
        reason = str(rr.get('reason') or rr.get('reject_reason') or '').strip()
        setup_id = str(rr.get('setup_id') or rr.get('id') or '').strip()
        def _f(v):
            try:
                if v in (None, ''):
                    return None
                return float(v)
            except Exception:
                return None
        # yver46: do not persist 0.00% as the displayed risk when a richer
        # placement/skip detail contains the actual filled/configured risk.  Some
        # timeout/reconcile paths populate allowed_risk_pct=0 while risk_actual_pct
        # or filled_risk_pct has the useful value.
        risk_val = None
        for _rk in ('allowed_risk_pct', 'risk_actual_pct', 'filled_risk_pct', 'risk_effective_pct', 'configured_risk_pct'):
            try:
                _rv = rr.get(_rk)
                if _rv not in (None, '') and float(_rv) > 0:
                    risk_val = float(_rv)
                    break
            except Exception:
                continue
        with sqlite3.connect(DB_PATH) as conn:
            c = conn.cursor()
            c.execute(
                """INSERT INTO autotrade_attempts
                   (uid, when_ts, when_iso, setup_id, symbol, side, status, reason, entry, sl, drift_pct, drift_direction, risk_pct, payload_json)
                   VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?)""",
                (
                    int(uid), float(when_ts), when_iso, setup_id, sym, side, status, reason,
                    _f(rr.get('entry')), _f(rr.get('sl')),
                    _f(rr.get('entry_drift_adverse_pct') if str(rr.get('entry_drift_direction') or '').lower() == 'adverse' else rr.get('entry_drift_pct')),
                    str(rr.get('entry_drift_direction') or '').strip(), _f(risk_val), json.dumps(rr, default=str)[:12000],
                ),
            )
            # Keep the table bounded; this is diagnostics, not a trading ledger.
            c.execute("""DELETE FROM autotrade_attempts
                         WHERE uid=? AND id NOT IN (
                           SELECT id FROM autotrade_attempts WHERE uid=? ORDER BY when_ts DESC, id DESC LIMIT 500
                         )""", (int(uid), int(uid)))
            conn.commit()
    except Exception:
        pass


def _autotrade_load_attempt_rows(uid: int, limit: int = 30) -> list[dict]:
    try:
        _autotrade_attempts_migrate()
        lim = max(1, min(100, int(limit or 30)))
        out = []
        with sqlite3.connect(DB_PATH) as conn:
            conn.row_factory = sqlite3.Row
            cur = conn.cursor()
            rows = cur.execute(
                """SELECT * FROM autotrade_attempts
                   WHERE uid=? ORDER BY when_ts DESC, id DESC LIMIT ?""",
                (int(uid), int(max(lim * 2, lim + 10))),
            ).fetchall() or []
        for r in rows:
            try:
                payload = {}
                try:
                    payload = json.loads(str(r['payload_json'] or '{}')) if r['payload_json'] else {}
                except Exception:
                    payload = {}
                d = dict(payload or {})
                d.setdefault('when', str(r['when_iso'] or ''))
                d.setdefault('when_ts', float(r['when_ts'] or 0.0))
                d.setdefault('setup_id', str(r['setup_id'] or ''))
                d.setdefault('symbol', str(r['symbol'] or ''))
                d.setdefault('side', str(r['side'] or ''))
                d.setdefault('status', str(r['status'] or ''))
                d.setdefault('reason', str(r['reason'] or ''))
                if r['entry'] is not None:
                    d.setdefault('entry', float(r['entry']))
                if r['sl'] is not None:
                    d.setdefault('sl', float(r['sl']))
                if r['drift_pct'] is not None:
                    d.setdefault('entry_drift_pct', float(r['drift_pct']))
                    if str(r['drift_direction'] or '').lower() == 'adverse':
                        d.setdefault('entry_drift_adverse_pct', float(r['drift_pct']))
                if str(r['drift_direction'] or '').strip():
                    d.setdefault('entry_drift_direction', str(r['drift_direction'] or ''))
                if r['risk_pct'] is not None:
                    d.setdefault('allowed_risk_pct', float(r['risk_pct']))
                out.append(d)
            except Exception:
                continue
        return out[:lim]
    except Exception:
        return []


def _autotrade_record_attempt(uid: int, meta: dict | None = None, detail: dict | None = None, status: str = '', reason: str = '') -> None:
    """Keep a short in-memory list of recent AutoTrade attempts for /autotrade_last."""
    try:
        u = int(uid)
        row = {}
        if isinstance(meta, dict):
            row.update(meta)
        if isinstance(detail, dict):
            # yver46: detail_snapshot is a global last-detail cache.  During a
            # multi-candidate tick it can briefly hold the previous candidate, so
            # never let it overwrite the candidate identity/entry/SL already passed
            # in meta/attempt_summaries.  It may still fill missing diagnostics.
            _identity_keys = {'setup_id', 'symbol_sent', 'symbol_raw', 'side', 'entry', 'sl', 'setup_entry'}
            for k in ('when','setup_id','symbol_sent','symbol_raw','side','entry','sl','setup_entry','entry_drift_pct','entry_drift_direction','entry_drift_adverse_pct','entry_delta_pct','signal_created_time','email_logged_time','generated_logged_time','trade_id','filled_risk_usd','filled_risk_pct','dynamic_risk_score','risk_multiplier','configured_risk_pct','allowed_risk_pct','risk_actual_pct','risk_actual_usd','configured_leverage','safe_leverage','leverage_downgrade_applied','leverage_policy','leverage_downgrade_blocked'):
                if k in detail and detail.get(k) not in (None, ''):
                    if k in _identity_keys and row.get(k) not in (None, ''):
                        continue
                    row[k] = detail.get(k)
        row['when'] = str(row.get('when') or datetime.now(timezone.utc).isoformat(timespec='seconds'))
        row['status'] = str(status or row.get('status') or '').upper() or ('PLACED' if not reason else 'SKIP')
        row['reason'] = str(reason or row.get('reason') or row.get('reject_reason') or '')
        if not row.get('symbol'):
            row['symbol'] = str(row.get('symbol_sent') or row.get('symbol_raw') or '')
        if not row.get('setup_id'):
            row['setup_id'] = str(row.get('id') or '')
        hist = list(_LAST_AUTOTRADE_ATTEMPTS.get(u) or [])
        hist.insert(0, row)
        _LAST_AUTOTRADE_ATTEMPTS[u] = hist[:100]
        try:
            _autotrade_persist_attempt_row(u, row)
        except Exception:
            pass
    except Exception:
        pass


def _autotrade_should_try_next_after_skip(reason: str) -> bool:
    """Candidate-specific skips should not stop trying the rest of an emailed batch."""
    r = str(reason or '').lower()
    if not r:
        return False
    hard_stop_tokens = (
        'daily_risk_cap_reached', 'daily_cap_reached', 'daily_remaining_risk_zero',
        'max_open_trades_reached', 'max_trades_day_reached', 'max_autotrade_trades_day_reached', 'autotrade_not_ready',
        'session_not_allowed', 'trade_window_block', 'equity_unavailable',
        'per_trade_risk_zero', 'open_risk_cap_reached', 'autotrade_exec_lock_busy',
    )
    if any(tok in r for tok in hard_stop_tokens):
        return False
    retry_tokens = (
        'entry_drift_too_wide', 'setup_expired', 'missing_recent_setup_email', 'setup_email_gate_db_error', 'bad_prices', 'missing_tp',
        'sl_not_', 'stop_invalid', 'qty_invalid', 'blocked_duplicate_open_position',
        'blocked_manual_same_symbol_position', 'blocked_duplicate_pending_order',
        'blocked_duplicate_inflight_lock', 'blocked_by_cooldown',
        'setup_already_traded', 'setup_execution_already_pending',
        'blocked_by_recent_symbol_trade', 'blocked_by_existing_local_trade_state',
        'post_fill_risk_breach', 'exchange_reject', 'no_sltp',
        'leverage_set_failed_for_liq_guard', 'configured_leverage_not_safe',
        # yver100: these are candidate-level selection rejects, not whole-engine stops.
        'autotrade_policy_not_keep', 'autotrade_policy_not_allowed', 'autotrade_realized_combo_block',
        'autotrade_symbol_block', 'autotrade_weak_hour_block',
        'autotrade_weak_side_block', 'autotrade_weak_session_block',
        'final_quality_gate', 'below_exec_conf', 'below_exec_rr',
        'below_min_volume', 'directional_context_blocks', 'final_combo_disabled', 'final_combo_blocked',
        'watch_final_gate', 'context_guard_block', 'context_gate', 'symbol_block',
        'not_keep', 'policy_not_keep',
    )
    return any(tok in r for tok in retry_tokens)



def _autotrade_timeout_reconcile(uid: int, session_label: str, setup, timeout_reason: str = '') -> tuple[bool, str]:
    """Confirm whether a timed-out placement actually opened a position.

    wait_for() cancels the awaiting coroutine, but the worker thread may still finish
    the Bybit order + journal write.  Without this reconciliation /autotrade_last can
    show SKIP timeout even though the position is already open, which then causes
    confusing duplicate/manual-same-symbol skips on the next tick.
    """
    try:
        uid_i = int(uid or 0)
    except Exception:
        uid_i = 0
    reason_s = str(timeout_reason or 'autotrade_place_trade_timeout')
    try:
        sym = _bybit_linear_symbol(str(getattr(setup, 'symbol', '') or '').upper())
    except Exception:
        sym = str(getattr(setup, 'symbol', '') or '').upper().strip()
    side_u = str(getattr(setup, 'side', '') or '').upper().strip()
    setup_id = str(getattr(setup, 'setup_id', '') or getattr(setup, 'id', '') or '').strip()
    now_ts = float(time.time())

    def _matches_open_trade(t: dict) -> bool:
        try:
            if int(t.get('uid') or uid_i) != uid_i:
                return False
            ts = float(t.get('opened_ts') or t.get('created_ts') or 0.0)
            if ts > 0 and now_ts - ts > 20 * 60:
                return False
            if setup_id and str(t.get('setup_id') or '') == setup_id:
                return True
            tsym = _bybit_linear_symbol(str(t.get('symbol') or '').upper())
            tside = str(t.get('side') or '').upper().strip()
            return bool(sym) and tsym == sym and (not side_u or tside == side_u)
        except Exception:
            return False

    def _check_journal() -> tuple[bool, str]:
        try:
            for t in list(_autotrade_db_open_trades(uid_i) or []):
                if _matches_open_trade(t):
                    try:
                        _LAST_AUTOTRADE_DETAIL.setdefault(uid_i, {})
                        _LAST_AUTOTRADE_DETAIL[uid_i].update({
                            'timeout_reconciled': True,
                            'timeout_reconcile_source': 'journal',
                            'timeout_original_reason': reason_s,
                            'trade_id': str(t.get('trade_id') or _LAST_AUTOTRADE_DETAIL.get(uid_i, {}).get('trade_id') or ''),
                            'setup_id': str(t.get('setup_id') or setup_id or ''),
                            'symbol_sent': sym,
                            'side': side_u,
                        })
                    except Exception:
                        pass
                    return True, 'placed_after_timeout_confirmed_journal'
        except Exception:
            pass
        return False, reason_s

    ok, rr = _check_journal()
    if ok:
        return ok, rr

    # Give the worker thread a very short grace period to finish the journal write.
    try:
        time.sleep(float(os.environ.get('AUTOTRADE_TIMEOUT_RECONCILE_GRACE_SEC', '8.0') or 8.0))
    except Exception:
        pass
    ok, rr = _check_journal()
    if ok:
        return ok, rr

    # Fall back to live Bybit position detection.  This is still safer than showing
    # a timeout SKIP and immediately retrying the same symbol while the position is open.
    try:
        cache_delete('bybit_open_positions_linear')
    except Exception:
        pass
    try:
        for pos in list(_bybit_get_open_positions_linear() or []):
            try:
                if _pos_symbol(pos) != sym:
                    continue
                qty = abs(float(_pos_size(pos) or 0.0))
                if qty <= 0:
                    continue
                pos_side = str(_pos_side_text(pos) or '').upper().strip()
                if side_u and pos_side and pos_side != side_u:
                    continue
                try:
                    _LAST_AUTOTRADE_DETAIL.setdefault(uid_i, {})
                    _LAST_AUTOTRADE_DETAIL[uid_i].update({
                        'timeout_reconciled': True,
                        'timeout_reconcile_source': 'live_position',
                        'timeout_original_reason': reason_s,
                        'setup_id': setup_id,
                        'symbol_sent': sym,
                        'side': side_u,
                    })
                except Exception:
                    pass
                return True, 'placed_after_timeout_confirmed_live_position'
            except Exception:
                continue
    except Exception:
        pass
    return False, reason_s

def _autotrade_place_trade(uid: int, session_label: str, setups: list) -> tuple[bool, str]:
    if not _autotrade_ready():
        return (False, 'autotrade_not_ready_or_disabled')
    if int(uid) != int(AUTOTRADE_OWNER_UID):
        return (False, 'not_owner')
    if not _autotrade_allowed_session(session_label):
        return (False, f'autotrade_session_not_allowed ({session_label})')
    blacked, black_reason = _autotrade_entry_blackout_now()
    if blacked:
        try:
            _LAST_AUTOTRADE_DETAIL.setdefault(int(uid), {})
            _LAST_AUTOTRADE_DETAIL[int(uid)].update({'reject_reason': black_reason, 'entry_blackout': True})
        except Exception:
            pass
        return (False, black_reason)
    if not setups:
        return (False, 'no_setups')

    # yver91: real-money protection. If the current Melbourne trading day is already
    # beyond the configured realised-loss stop, keep setup generation/email alive but
    # stop opening new AutoTrades.
    _loss_ok, _loss_reason = _autotrade_daily_realized_loss_stop_allows(int(uid))
    if not _loss_ok:
        try:
            _LAST_AUTOTRADE_DETAIL.setdefault(int(uid), {})
            _LAST_AUTOTRADE_DETAIL[int(uid)].update({'reject_reason': _loss_reason, 'capital_protection': True})
        except Exception:
            pass
        return (False, _loss_reason)

    s = setups[0]
    try:
        # yver71: AutoTrade is a consumer, not a second strategy router.
        # Execute already-emailed/executable lanes exactly as delivered; only raw
        # ad-hoc candidates may still be routed before execution.
        s = _setup_route_unless_delivery_locked(s, session_label, int(uid))
    except Exception:
        pass
    side = str(getattr(s, 'side', '') or '').upper()
    intended_entry = float(getattr(s, 'entry', 0.0) or 0.0)
    intended_sl = float(getattr(s, 'sl', 0.0) or 0.0)
    sym = _bybit_linear_symbol(str(getattr(s, 'symbol', '') or '').upper())
    setup_id = str(getattr(s, 'setup_id', '') or getattr(s, 'id', '') or '').strip()
    reserved_keys: list[str] = []
    runtime_lock_acquired = False

    try:
        _admin_setup_lifecycle_merge(
            int(uid),
            setup_id,
            session=str(session_label or ''),
            symbol=str(getattr(s, 'symbol', '') or ''),
            side=str(side or ''),
            attempted_ts=float(time.time()),
            state='execution_attempted',
            source_kind=str(getattr(s, 'source_kind', '') or ''),
            signal_created_ts=float(getattr(s, 'signal_created_ts', 0.0) or 0.0),
            emailed_ts=float(getattr(s, 'email_logged_ts', 0.0) or 0.0),
            generated_logged_ts=float(getattr(s, 'generated_logged_ts', 0.0) or 0.0),
        )
    except Exception:
        pass

    try:
        _LAST_AUTOTRADE_DETAIL[int(uid)] = {
            'when': datetime.now(timezone.utc).isoformat(timespec='seconds'),
            'session': session_label,
            'setup_id': setup_id,
            'symbol_raw': str(getattr(s, 'symbol', '') or ''),
            'symbol_sent': sym,
            'side': side,
            'entry': float(intended_entry or 0.0),
            'sl': float(intended_sl or 0.0),
            'entry_source': 'setup',
            'sl_source': 'setup',
            'setup_entry': intended_entry,
            'setup_sl_raw': intended_sl,
        }
    except Exception:
        pass

    try:
        _signal_ts = float(getattr(s, 'signal_created_ts', 0.0) or 0.0)
        _email_ts = float(getattr(s, 'email_logged_ts', 0.0) or 0.0)
        _generated_ts = float(getattr(s, 'generated_logged_ts', 0.0) or 0.0)
        _cts = float(getattr(s, 'created_ts', 0.0) or 0.0)
        _canonical_ts = max(_cts, _email_ts, _generated_ts, _signal_ts)
        _setup_dt = datetime.fromtimestamp(_canonical_ts, tz=timezone.utc) if _canonical_ts > 0 else datetime.now(timezone.utc)
        _deadline_dt = _setup_dt + timedelta(minutes=_autotrade_entry_window_min())
        _LAST_AUTOTRADE_DETAIL[int(uid)].update({
            'setup_time': _setup_dt.isoformat(timespec='seconds'),
            'entry_deadline': _deadline_dt.isoformat(timespec='seconds'),
            'signal_created_time': datetime.fromtimestamp(_signal_ts, tz=timezone.utc).isoformat(timespec='seconds') if _signal_ts > 0 else '',
            'email_logged_time': datetime.fromtimestamp(_email_ts, tz=timezone.utc).isoformat(timespec='seconds') if _email_ts > 0 else '',
            'generated_logged_time': datetime.fromtimestamp(_generated_ts, tz=timezone.utc).isoformat(timespec='seconds') if _generated_ts > 0 else '',
            'source_kind': str(getattr(s, 'source_kind', '') or ''),
            'source_session': str(getattr(s, 'source_session', '') or ''),
        })
        if datetime.now(timezone.utc) > _deadline_dt:
            try:
                _admin_setup_lifecycle_merge(int(uid), setup_id, state=_admin_setup_state_from_reason('stale_deadline'), last_reason='stale_deadline')
            except Exception:
                pass
            return (False, 'setup_expired')
    except Exception:
        pass

    # yver37: final email gate is conditional.  Direct KEEP queue mode opens
    # fresh executable KEEP rows even if the email pipeline did not log the setup;
    # email-matched mode still requires an exact recent emailed_setups row.
    try:
        if _autotrade_require_setup_email_for_entry():
            _email_ok, _email_why = _autotrade_recent_email_gate_allows_setup(int(uid), s, session_label=session_label)
            if not _email_ok:
                try:
                    _admin_setup_lifecycle_merge(int(uid), setup_id, state=_admin_setup_state_from_reason(_email_why), last_reason=str(_email_why))
                except Exception:
                    pass
                return (False, str(_email_why or 'missing_recent_setup_email'))
        else:
            try:
                _LAST_AUTOTRADE_DETAIL.setdefault(int(uid), {}).update({'email_gate': 'disabled_direct_keep_queue'})
            except Exception:
                pass
    except Exception:
        return (False, 'setup_email_gate_exception')

    # yver143: final live entry must still pass the same user-visible KEEP/context
    # delivery gate used by setup email and /screen.  This prevents any fallback or
    # stale-delivery object from opening after the live gate would now label it OFF.
    try:
        _uv_ok, _uv_why, _uv_meta = _setup_user_visible_keep_policy_allows(s, session_name=session_label, user_id=int(uid), lane='email')
        if not _uv_ok:
            try:
                _admin_setup_lifecycle_merge(int(uid), setup_id, state=_admin_setup_state_from_reason('autotrade_user_visible_gate_block'), last_reason=str(_uv_why or 'autotrade_user_visible_gate_block'))
            except Exception:
                pass
            return (False, str(_uv_why or 'autotrade_user_visible_gate_block'))
    except Exception:
        return (False, 'autotrade_user_visible_gate_exception')

    try:
        _source_kind_u = str(getattr(s, 'source_kind', '') or '').lower().strip()
    except Exception:
        _source_kind_u = ''
    if _source_kind_u in {'executable_setups', 'emailed_setups', 'recent_email_lane', 'recent_email_cache'}:
        exec_ok, exec_why = _autotrade_db_signal_structurally_valid(s, session_name=session_label)
    else:
        exec_ok, exec_why = is_executable_setup_eligible(s, session_name=session_label)
    if not exec_ok:
        try:
            _admin_setup_lifecycle_merge(int(uid), setup_id, state=_admin_setup_state_from_reason(exec_why), last_reason=str(exec_why))
        except Exception:
            pass
        return (False, str(exec_why))

    if _autotrade_require_keep_policy():
        try:
            pinfo = _setup_combo_policy_lookup_for_setup(s, session_name=session_label, user_id=int(uid))
            pstatus = _setup_policy_effective_status(str((pinfo or {}).get('status') or '').upper().strip(), found=bool((pinfo or {}).get('found')))
            if pstatus not in _autotrade_allowed_policy_statuses():
                try:
                    _admin_setup_lifecycle_merge(int(uid), setup_id, state=_admin_setup_state_from_reason('autotrade_policy_not_allowed'), last_reason=f'autotrade_policy_not_allowed:{pstatus}')
                except Exception:
                    pass
                return (False, f'autotrade_policy_not_allowed:{pstatus or "WATCH"}')
        except Exception:
            return (False, 'autotrade_keep_policy_check_exception')

    # yver91: repeat the execution-context guard at the final place-order point.
    # This catches any candidate path that bypassed DB structural validation.
    try:
        ctx_ok, ctx_reason = _autotrade_policy_context_execution_allows(s, session_name=session_label, user_id=int(uid))
        if not ctx_ok:
            try:
                _admin_setup_lifecycle_merge(int(uid), setup_id, state=_admin_setup_state_from_reason('autotrade_context_block'), last_reason=str(ctx_reason))
            except Exception:
                pass
            return (False, str(ctx_reason or 'autotrade_policy_context_block'))
    except Exception:
        return (False, 'autotrade_policy_context_check_exception')

    def _as_pos_float(x):
        try:
            v = float(x)
            return v if v > 0 else None
        except Exception:
            return None

    tp = _as_pos_float(getattr(s, 'tp', None))
    alt_target_a = _as_pos_float(getattr(s, 'alt_target_a', None))
    alt_target_b = _as_pos_float(getattr(s, 'alt_target_b', None))
    final_tp = _resolve_single_tp(intended_entry, intended_sl, tp, alt_target_a, alt_target_b, side)

    if side not in {'BUY', 'SELL'}:
        return (False, f'bad_side ({side})')
    if intended_entry <= 0 or intended_sl <= 0:
        return (False, 'bad_prices')
    if final_tp <= 0:
        return (False, 'missing_tp')
    if side == 'BUY' and intended_sl >= intended_entry:
        return (False, 'sl_not_below_entry_for_buy')
    if side == 'SELL' and intended_sl <= intended_entry:
        return (False, 'sl_not_above_entry_for_sell')

    price_ref = intended_entry
    if str(_autotrade_runtime_mode()).lower() == 'live':
        live_ref = _autotrade_live_reference_price(sym, fallback_entry=intended_entry)
        if live_ref > 0:
            price_ref = live_ref

    entry_drift_pct = 0.0
    entry_delta_pct = 0.0
    adverse_entry_drift_pct = 0.0
    favourable_entry_drift_pct = 0.0
    entry_drift_direction = 'flat'
    try:
        if float(intended_entry) > 0 and float(price_ref) > 0:
            entry_delta_pct = ((float(price_ref) - float(intended_entry)) / float(intended_entry)) * 100.0
            entry_drift_pct = abs(float(entry_delta_pct))
            if side == 'BUY':
                adverse_entry_drift_pct = max(0.0, float(entry_delta_pct))
                favourable_entry_drift_pct = max(0.0, -float(entry_delta_pct))
            elif side == 'SELL':
                adverse_entry_drift_pct = max(0.0, -float(entry_delta_pct))
                favourable_entry_drift_pct = max(0.0, float(entry_delta_pct))
            if adverse_entry_drift_pct > 0:
                entry_drift_direction = 'adverse'
            elif favourable_entry_drift_pct > 0:
                entry_drift_direction = 'favourable'
    except Exception:
        entry_drift_pct = 0.0
        entry_delta_pct = 0.0
        adverse_entry_drift_pct = 0.0
        favourable_entry_drift_pct = 0.0
        entry_drift_direction = 'flat'

    try:
        _LAST_AUTOTRADE_DETAIL.setdefault(int(uid), {})
        _LAST_AUTOTRADE_DETAIL[int(uid)].update({
            'entry': float(price_ref),
            'entry_source': 'live_ref' if str(_autotrade_runtime_mode()).lower() == 'live' else 'setup',
            'setup_entry': float(intended_entry),
            'entry_drift_pct': float(entry_drift_pct),
            'entry_delta_pct': float(entry_delta_pct),
            'entry_drift_adverse_pct': float(adverse_entry_drift_pct),
            'entry_drift_favourable_pct': float(favourable_entry_drift_pct),
            'entry_drift_direction': str(entry_drift_direction),
            'max_adverse_entry_drift_pct': float(_autotrade_runtime_max_entry_drift_pct()),
        })
    except Exception:
        pass

    max_adverse_drift = float(_autotrade_runtime_max_entry_drift_pct())
    if str(_autotrade_runtime_mode()).lower() == 'live' and max_adverse_drift > 0 and adverse_entry_drift_pct > max_adverse_drift:
        try:
            _LAST_AUTOTRADE_DETAIL.setdefault(int(uid), {})
            _LAST_AUTOTRADE_DETAIL[int(uid)].update({
                'reject_reason': 'entry_drift_too_wide',
            })
        except Exception:
            pass
        try:
            _admin_setup_lifecycle_merge(int(uid), setup_id, state=_admin_setup_state_from_reason('stale_deadline'), last_reason=f'entry_drift_too_wide adverse={adverse_entry_drift_pct:.2f}%>{max_adverse_drift:.2f}% total={entry_drift_pct:.2f}% direction={entry_drift_direction}')
        except Exception:
            pass
        return (False, 'entry_drift_too_wide')

    filt = _bybit_get_instr_filters(sym)
    qty_step = filt.get('qtyStep')
    contract_size = float(filt.get('contractSize') or 1.0)
    stop_rounding = ROUND_UP if side == 'BUY' else ROUND_DOWN
    sl_for_order = _round_price_to_tick(sym, intended_sl, rounding=stop_rounding)
    if sl_for_order <= 0:
        sl_for_order = intended_sl
    if side == 'BUY' and sl_for_order >= price_ref:
        return (False, 'stop_invalid_after_tick_rounding_for_buy')
    if side == 'SELL' and sl_for_order <= price_ref:
        return (False, 'stop_invalid_after_tick_rounding_for_sell')

    equity = _effective_equity_for_risk(get_user(uid) or {}, prefer_live=(str(_autotrade_runtime_mode()).lower() == 'live'))
    if equity <= 0:
        return (False, 'equity_unavailable_or_zero')
    try:
        if str(_autotrade_runtime_mode()).lower() == 'live' and equity > 0:
            pass  # keep manual /equity isolated from AutoTrade live equity
    except Exception:
        pass

    base_per_trade_risk = float(_autotrade_per_trade_risk_usd(uid, equity) or 0.0)
    if base_per_trade_risk <= 0:
        return (False, 'per_trade_risk_zero')

    mday = _autotrade_day_risk_metrics(int(uid), float(equity))
    try:
        live_open_count = int(mday.get('open_positions_now') or 0)
    except Exception:
        live_open_count = 0
    # AutoTrade daily count cap is controlled only by /autotrade_config.
    # Do NOT use the manual /limits maxtrades value here.
    try:
        max_trades_day = int(_autotrade_runtime_max_trades_per_day() or 0)
    except Exception:
        max_trades_day = 0
    try:
        opened_today_count = int(mday.get('opened_today_count') or 0)
    except Exception:
        opened_today_count = 0
    if max_trades_day > 0 and opened_today_count >= max_trades_day:
        try:
            _LAST_AUTOTRADE_DETAIL[int(uid)].update({
                'reject_reason': 'max_autotrade_trades_day_reached',
                'opened_today_count': int(opened_today_count),
                'max_autotrade_trades_per_day': int(max_trades_day),
            })
        except Exception:
            pass
        try:
            _admin_setup_lifecycle_merge(
                int(uid),
                setup_id,
                state=_admin_setup_state_from_reason('risk_cap'),
                last_reason=f'max_autotrade_trades_day_reached ({opened_today_count}/{max_trades_day})',
            )
        except Exception:
            pass
        return (False, 'max_autotrade_trades_day_reached')
    if int(_autotrade_runtime_max_open_trades()) > 0 and live_open_count >= int(_autotrade_runtime_max_open_trades()):
        try:
            _LAST_AUTOTRADE_DETAIL[int(uid)].update({'reject_reason': 'max_open_trades_reached', 'open_positions_now': int(live_open_count)})
        except Exception:
            pass
        try:
            _admin_setup_lifecycle_merge(int(uid), setup_id, state=_admin_setup_state_from_reason('risk_cap'), last_reason=f'max_open_trades_reached ({live_open_count}/{int(_autotrade_runtime_max_open_trades())})')
        except Exception:
            pass
        return (False, 'max_open_trades_reached')
    daily_cap = float(mday.get('cap') or 0.0)
    open_risk = float(mday.get('open_risk') or 0.0)
    used_total_before = float(mday.get('used_total') or 0.0)
    remaining_risk = float(mday.get('remaining')) if daily_cap > 0 else float('inf')

    effective_risk, risk_mult, risk_regime = _autotrade_effective_risk_usd(
        uid=uid,
        setup=s,
        equity=float(equity),
        base_risk_usd=float(base_per_trade_risk),
        remaining_risk_usd=float(remaining_risk) if math.isfinite(remaining_risk) else float(base_per_trade_risk),
        open_risk_usd=float(open_risk),
        daily_cap_usd=float(daily_cap),
        session_name=str(session_label or ''),
    )

    stop_distance = abs(float(price_ref) - float(sl_for_order))
    # Ver03 dynamic risk: effective_risk may be below or above the base risk
    # (default 0.50x..1.50x). Daily and open-risk caps still bound the final size.
    allowed_risk_usd = float(effective_risk)
    open_risk_cap_usd = float(_risk_amount_from_pct(float(equity), float(_autotrade_open_risk_cap_pct())) or 0.0)
    remaining_open_risk_usd = float('inf')
    if open_risk_cap_usd > 0:
        remaining_open_risk_usd = max(0.0, float(open_risk_cap_usd) - float(open_risk))
        allowed_risk_usd = min(float(allowed_risk_usd), float(remaining_open_risk_usd))
    if math.isfinite(remaining_risk):
        allowed_risk_usd = min(float(allowed_risk_usd), float(remaining_risk))
    allowed_risk_usd = max(0.0, float(allowed_risk_usd))
    # Ver12: size slightly below the theoretical cap so normal market-order
    # slippage does not require an immediate reduce-only correction. This keeps
    # live positions on the intended TP/SL-only lifecycle.
    try:
        _prefill_mult = max(0.50, min(1.00, float(globals().get('AUTOTRADE_PREFILL_RISK_BUFFER_MULT', 0.92) or 0.92)))
        if bool(globals().get('AUTOTRADE_STRICT_TPSL_ONLY', True)):
            allowed_risk_usd_before_prefill_buffer = float(allowed_risk_usd)
            allowed_risk_usd = float(allowed_risk_usd) * float(_prefill_mult)
            _LAST_AUTOTRADE_DETAIL.setdefault(int(uid), {})
            _LAST_AUTOTRADE_DETAIL[int(uid)].update({
                'strict_tpsl_only': True,
                'prefill_risk_buffer_mult': float(_prefill_mult),
                'allowed_risk_usd_before_prefill_buffer': float(allowed_risk_usd_before_prefill_buffer),
                'allowed_risk_usd_after_prefill_buffer': float(allowed_risk_usd),
            })
    except Exception:
        pass

    configured_risk_pct = _risk_pct_from_amount(float(equity), float(base_per_trade_risk))
    allowed_risk_pct = _risk_pct_from_amount(float(equity), float(allowed_risk_usd))
    try:
        _LAST_AUTOTRADE_DETAIL.setdefault(int(uid), {})
        _LAST_AUTOTRADE_DETAIL[int(uid)].update({
            'entry': float(price_ref),
            'sl': float(sl_for_order),
            'entry_source': 'live_ref' if str(_autotrade_runtime_mode()).lower() == 'live' else 'setup',
            'sl_source': 'tick_rounded',
            'setup_entry_vs_live_delta_pct': (((float(price_ref) - float(intended_entry)) / float(intended_entry)) * 100.0) if float(intended_entry) > 0 else 0.0,
            'contractSize': float(contract_size),
            'tick_size': filt.get('tickSize'),
            'equity_used': float(equity),
            'risk_mode': 'AT_PCT',
            'risk_value': float(_autotrade_risk_per_trade_pct() or 0.0),
            'risk_base_usd': float(base_per_trade_risk),
            'risk_effective_usd': float(effective_risk),
            'risk_effective_pct': float(_risk_pct_from_amount(float(equity), float(effective_risk))),
            'risk_multiplier': float(risk_mult),
            'risk_regime': str(risk_regime),
            'configured_risk_pct': float(configured_risk_pct),
            'allowed_risk_usd': float(allowed_risk_usd),
            'allowed_risk_pct': float(allowed_risk_pct),
            'daily_cap_usd': float(daily_cap),
            'open_risk_cap_usd': float(open_risk_cap_usd),
            'remaining_open_risk_usd': float(remaining_open_risk_usd) if math.isfinite(remaining_open_risk_usd) else float('inf'),
            'open_risk_usd_before': float(open_risk),
            'daily_used_total_before': float(used_total_before),
            'realized_loss_today': float(mday.get('realized_loss_today') or 0.0),
            'remaining_risk_usd': float(remaining_risk) if math.isfinite(remaining_risk) else float('inf'),
            'stop_distance': float(stop_distance),
        })
    except Exception:
        pass

    if stop_distance <= 0:
        return (False, 'stop_distance_zero_or_invalid')

    # Liquidation safety guard: do not open a futures position where the exchange
    # liquidation price can be reached before the bot/exchange stop-loss. For wide
    # stops, automatically lower symbol leverage below AUTOTRADE_LEVERAGE.
    configured_lev = int(_autotrade_runtime_leverage())
    liq_plan = _autotrade_liq_safety_plan(price_ref, sl_for_order, side, configured_lev, _autotrade_runtime_liq_buffer_pct())
    try:
        _LAST_AUTOTRADE_DETAIL.setdefault(int(uid), {})
        _LAST_AUTOTRADE_DETAIL[int(uid)].update({
            'liq_guard': liq_plan,
            'configured_leverage': int(configured_lev),
            'safe_leverage': int(liq_plan.get('safe_leverage') or configured_lev),
            'liq_estimated_price': float(liq_plan.get('estimated_liq_price') or 0.0),
            'liq_buffer_pct': float(liq_plan.get('buffer_pct') or 0.0),
            'stop_distance_pct': float(liq_plan.get('stop_distance_pct') or 0.0),
        })
    except Exception:
        pass
    if not bool(liq_plan.get('ok')):
        try:
            _LAST_AUTOTRADE_DETAIL[int(uid)].update({'reject_reason': str(liq_plan.get('reason') or 'liq_guard_failed')})
        except Exception:
            pass
        try:
            _admin_setup_lifecycle_merge(int(uid), setup_id, state=_admin_setup_state_from_reason('risk_cap'), last_reason=f"liq_guard_failed:{liq_plan.get('reason')}")
        except Exception:
            pass
        return (False, f"liq_guard_failed:{liq_plan.get('reason')}")
    safe_lev = int(liq_plan.get('safe_leverage') or configured_lev)
    # Ver11: controlled leverage downgrade. Do not skip a good setup just because
    # 10x is too aggressive for the SL/liquidation buffer when a practical safe
    # leverage is available (e.g. use 7x instead of 10x). Still block very low
    # required leverage (default <5x) to avoid repeating the old silent 1x issue.
    if safe_lev < configured_lev:
        min_safe_lev = int(_autotrade_safe_leverage_downgrade_min())
        allow_downgrade = bool(_autotrade_allow_leverage_downgrade()) and int(safe_lev) >= int(min_safe_lev)
        if not allow_downgrade:
            reason = f'configured_leverage_not_safe requires_{safe_lev}x_but_configured_{configured_lev}x_min_allowed_{min_safe_lev}x'
            try:
                _LAST_AUTOTRADE_DETAIL.setdefault(int(uid), {})
                _LAST_AUTOTRADE_DETAIL[int(uid)].update({
                    'reject_reason': reason,
                    'leverage_downgrade_blocked': True,
                    'configured_leverage': int(configured_lev),
                    'safe_leverage': int(safe_lev),
                    'leverage_policy': f'blocked_below_min_{min_safe_lev}x',
                })
                _admin_setup_lifecycle_merge(int(uid), setup_id, state=_admin_setup_state_from_reason('risk_cap'), last_reason=reason)
            except Exception:
                pass
            return (False, reason)
        try:
            _LAST_AUTOTRADE_DETAIL.setdefault(int(uid), {})
            _LAST_AUTOTRADE_DETAIL[int(uid)].update({
                'leverage_downgrade_applied': True,
                'configured_leverage': int(configured_lev),
                'safe_leverage': int(safe_lev),
                'leverage_policy': f'controlled_safe_downgrade_{configured_lev}x_to_{safe_lev}x',
            })
        except Exception:
            pass
    if str(_autotrade_runtime_mode()).lower() == 'live':
        lev_ok, lev_msg, lev_res = _autotrade_set_symbol_leverage_safe(sym, safe_lev)
        try:
            _LAST_AUTOTRADE_DETAIL[int(uid)].update({'leverage_set_ok': bool(lev_ok), 'leverage_set_msg': str(lev_msg), 'leverage_set_res': lev_res})
        except Exception:
            pass
        if not lev_ok:
            try:
                _admin_setup_lifecycle_merge(int(uid), setup_id, state=_admin_setup_state_from_reason('risk_cap'), last_reason=f'leverage_set_failed_for_liq_guard:{lev_msg}')
            except Exception:
                pass
            return (False, f'leverage_set_failed_for_liq_guard:{lev_msg}')

    if open_risk_cap_usd > 0 and math.isfinite(remaining_open_risk_usd) and remaining_open_risk_usd <= 0:
        try:
            _LAST_AUTOTRADE_DETAIL.setdefault(int(uid), {})
            _LAST_AUTOTRADE_DETAIL[int(uid)].update({'reject_reason': 'open_risk_cap_reached'})
        except Exception:
            pass
        try:
            _admin_setup_lifecycle_merge(int(uid), setup_id, state=_admin_setup_state_from_reason('risk_cap'), last_reason=f'open_risk_cap_reached ({open_risk:.2f}/{open_risk_cap_usd:.2f})')
        except Exception:
            pass
        return (False, 'open_risk_cap_reached')

    if math.isfinite(remaining_risk) and remaining_risk <= 0:
        try:
            _LAST_AUTOTRADE_DETAIL[int(uid)].update({'reject_reason': 'daily_remaining_risk_zero'})
        except Exception:
            pass
        try:
            _admin_setup_lifecycle_merge(int(uid), setup_id, state=_admin_setup_state_from_reason('risk_cap'), last_reason='daily_remaining_risk_zero')
        except Exception:
            pass
        return (False, 'daily_remaining_risk_zero')
    if allowed_risk_usd <= 0:
        try:
            _admin_setup_lifecycle_merge(int(uid), setup_id, state=_admin_setup_state_from_reason('risk_cap'), last_reason='daily_risk_cap_reached')
        except Exception:
            pass
        return (False, 'daily_risk_cap_reached')
    if daily_cap > 0 and used_total_before >= daily_cap:
        try:
            _admin_setup_lifecycle_merge(int(uid), setup_id, state=_admin_setup_state_from_reason('risk_cap'), last_reason='daily_risk_cap_already_exceeded')
        except Exception:
            pass
        return (False, 'daily_risk_cap_already_exceeded')

    raw_qty = _autotrade_qty_from_risk(price_ref, sl_for_order, equity, risk_usd=allowed_risk_usd, contract_size=contract_size)
    if raw_qty <= 0:
        return (False, 'qty_calc_failed')
    qty, qreason = _round_qty_down(sym, raw_qty, price_ref)
    if qty is None:
        try:
            _LAST_AUTOTRADE_DETAIL[int(uid)].update({'reject_reason': f'qty_invalid:{qreason}'})
        except Exception:
            pass
        return (False, f'qty_invalid:{qreason}')

    actual_risk = _autotrade_true_risk_usd(price_ref, sl_for_order, qty, contract_size)
    if actual_risk > (allowed_risk_usd * 1.0005):
        qty2 = _autotrade_qty_from_risk(price_ref, sl_for_order, equity, risk_usd=allowed_risk_usd, contract_size=contract_size)
        qty2, qreason2 = _round_qty_down(sym, qty2, price_ref)
        if qty2 is None:
            return (False, f'qty_capped_but_invalid:{qreason2}')
        qty = qty2
        actual_risk = _autotrade_true_risk_usd(price_ref, sl_for_order, qty, contract_size)
        if actual_risk > (allowed_risk_usd * 1.0005):
            return (False, 'risk_cap_enforcement_failed')
    actual_risk_pct = _risk_pct_from_amount(float(equity), float(actual_risk))

    # Hard per-trade cap from /autotrade_config for ALL families, including
    # immediate Big-Move (F8) AutoTrades. Ver03 dynamic risk may scale the base
    # above 1.0x, but never above the configured dynamic max multiplier.
    try:
        base_cap_pct = max(0.0, float(_autotrade_risk_per_trade_pct() or 0.0))
        dyn_cap_mult = float(_autotrade_dynamic_risk_max_mult() if _autotrade_dynamic_risk_enabled() else 1.0)
        hard_cap_pct = float(base_cap_pct) * max(1.0, float(dyn_cap_mult))
        hard_cap_usd = float(_risk_amount_from_pct(float(equity), float(hard_cap_pct)) or 0.0)
        if hard_cap_usd > 0 and float(actual_risk) > (float(hard_cap_usd) * 1.0005):
            try:
                _LAST_AUTOTRADE_DETAIL.setdefault(int(uid), {})
                _LAST_AUTOTRADE_DETAIL[int(uid)].update({
                    'reject_reason': 'per_trade_risk_pct_exceeded',
                    'base_cap_pct': float(base_cap_pct),
                    'hard_cap_pct': float(hard_cap_pct),
                    'hard_cap_usd': float(hard_cap_usd),
                    'risk_actual_usd': float(actual_risk),
                    'risk_actual_pct': float(actual_risk_pct),
                    'family_id': str(getattr(s, 'family_id', '') or ''),
                })
            except Exception:
                pass
            try:
                _admin_setup_lifecycle_merge(int(uid), setup_id, state=_admin_setup_state_from_reason('risk_cap'), last_reason=f'per_trade_risk_pct_exceeded actual={actual_risk_pct:.2f}% cap={hard_cap_pct:.2f}%')
            except Exception:
                pass
            return (False, 'per_trade_risk_pct_exceeded')
    except Exception:
        pass

    if math.isfinite(remaining_risk) and (used_total_before + actual_risk) > (daily_cap * 1.0005):
        try:
            _admin_setup_lifecycle_merge(int(uid), setup_id, state=_admin_setup_state_from_reason('risk_cap'), last_reason='daily_cap_would_be_exceeded_by_new_trade')
        except Exception:
            pass
        return (False, 'daily_cap_would_be_exceeded_by_new_trade')

    try:
        _LAST_AUTOTRADE_DETAIL[int(uid)].update({
            'raw_qty': float(raw_qty),
            'rounded_qty': float(qty),
            'qty': float(qty),
            'qty_attempted': float(qty),
            'qty_round_reason': qreason,
            'risk_actual_usd': float(actual_risk),
            'risk_actual_pct': float(actual_risk_pct),
            'daily_used_total_after_est': float(used_total_before + actual_risk),
        })
    except Exception:
        pass

    # Ver14 F8 safety rule: a confirmed opposite BigMove setup should flatten
    # existing same-symbol opposite exposure before trying the new direction.
    try:
        f8_close_ok, f8_close_reason, f8_close_detail = _autotrade_f8_close_opposite_position_if_needed(uid, s, sym, side)
        _LAST_AUTOTRADE_DETAIL.setdefault(int(uid), {})
        _LAST_AUTOTRADE_DETAIL[int(uid)].update({
            'f8_opposite_close_ok': bool(f8_close_ok),
            'f8_opposite_close_reason': str(f8_close_reason or ''),
            'f8_opposite_close_detail': f8_close_detail,
        })
        if not f8_close_ok:
            try:
                _admin_setup_lifecycle_merge(int(uid), setup_id, state=_admin_setup_state_from_reason('risk_cap'), last_reason=str(f8_close_reason or 'f8_opposite_close_failed'))
            except Exception:
                pass
            return (False, str(f8_close_reason or 'f8_opposite_close_failed'))
    except Exception as _f8_exc:
        return (False, f'f8_opposite_close_exception:{type(_f8_exc).__name__}')

    can_open, can_open_reason, can_open_detail = _autotrade_can_open_symbol(uid, sym, side, session_label)
    try:
        _LAST_AUTOTRADE_DETAIL[int(uid)].update({
            'can_open_symbol': bool(can_open),
            'can_open_reason': str(can_open_reason or ''),
            'can_open_detail': can_open_detail,
        })
    except Exception:
        pass
    if not can_open:
        try:
            _admin_setup_lifecycle_merge(int(uid), setup_id, state=_admin_setup_state_from_reason(can_open_reason), last_reason=str(can_open_reason))
        except Exception:
            pass
        return (False, str(can_open_reason or 'blocked_before_order'))

    runtime_lock_acquired = _autotrade_runtime_symbol_lock_acquire(uid, sym)
    if not runtime_lock_acquired:
        try:
            _LAST_AUTOTRADE_DETAIL[int(uid)].update({'reject_reason': 'blocked_duplicate_inflight_lock'})
        except Exception:
            pass
        try:
            _admin_setup_lifecycle_merge(int(uid), setup_id, state=_admin_setup_state_from_reason('blocked_duplicate_inflight_lock'), last_reason='blocked_duplicate_inflight_lock')
        except Exception:
            pass
        return (False, 'blocked_duplicate_inflight_lock')

    ok_reserve, reserved_keys, reserve_reason = _autotrade_exec_reserve(uid, setup_id, sym, side)
    if not ok_reserve:
        try:
            _LAST_AUTOTRADE_DETAIL[int(uid)].update({'reject_reason': str(reserve_reason or 'guard_reserve_failed')})
        except Exception:
            pass
        try:
            _admin_setup_lifecycle_merge(int(uid), setup_id, state=_admin_setup_state_from_reason(reserve_reason), last_reason=str(reserve_reason or 'guard_reserve_failed'))
        except Exception:
            pass
        # yver125: release the short in-memory symbol lock when DB reservation
        # fails. Otherwise the next valid email/setup can be blocked for the
        # whole guard TTL as blocked_duplicate_inflight_lock.
        try:
            _autotrade_runtime_symbol_lock_release(uid, sym)
        except Exception:
            pass
        return (False, str(reserve_reason or 'guard_reserve_failed'))

    # Authoritative exit targets: use the exact setup TP/SL, tick-rounded once.
    # Do not recalculate TP/SL from live price, trailing logic, or later family rules.
    tp_rounding = ROUND_DOWN if side == 'BUY' else ROUND_UP
    live_final_tp = _round_price_to_tick(sym, final_tp, rounding=tp_rounding)
    if live_final_tp <= 0:
        live_final_tp = float(final_tp or 0.0)
    if side == 'BUY' and live_final_tp <= price_ref:
        try:
            _LAST_AUTOTRADE_DETAIL[int(uid)].update({'reject_reason': 'tp_not_above_live_entry', 'fixed_setup_tp': float(live_final_tp), 'live_entry': float(price_ref)})
        except Exception:
            pass
        try:
            _autotrade_exec_mark(reserved_keys, 'FAILED', 'tp_not_above_live_entry')
        except Exception:
            pass
        try:
            _autotrade_runtime_symbol_lock_release(uid, sym)
        except Exception:
            pass
        return (False, 'tp_not_above_live_entry')
    if side == 'SELL' and live_final_tp >= price_ref:
        try:
            _LAST_AUTOTRADE_DETAIL[int(uid)].update({'reject_reason': 'tp_not_below_live_entry', 'fixed_setup_tp': float(live_final_tp), 'live_entry': float(price_ref)})
        except Exception:
            pass
        try:
            _autotrade_exec_mark(reserved_keys, 'FAILED', 'tp_not_below_live_entry')
        except Exception:
            pass
        try:
            _autotrade_runtime_symbol_lock_release(uid, sym)
        except Exception:
            pass
        return (False, 'tp_not_below_live_entry')
    live_rr = _autotrade_rr_value(price_ref, sl_for_order, live_final_tp, side)
    try:
        if _autotrade_tp_rr_cap_enabled():
            _tp_before_dynamic = float(live_final_tp or 0.0)
            _new_tp, _tp_changed, _old_live_rr, _new_live_rr, _rr_detail = _autotrade_adjust_tp_to_dynamic_rr(
                sym, price_ref, sl_for_order, live_final_tp, side, setup=s, session_name=session_label, user_id=int(uid)
            )
            if _tp_changed:
                live_final_tp = float(_new_tp)
            live_rr = float(_new_live_rr or _autotrade_rr_value(price_ref, sl_for_order, live_final_tp, side))
            _LAST_AUTOTRADE_DETAIL.setdefault(int(uid), {})
            _LAST_AUTOTRADE_DETAIL[int(uid)].update({
                'dynamic_tp_rr_enabled': bool(_autotrade_dynamic_tp_rr_enabled()),
                'tp_rr_adjust_applied': bool(_tp_changed),
                'tp_rr_before_adjust': float(_old_live_rr or 0.0),
                'tp_rr_after_adjust': float(live_rr or 0.0),
                'tp_rr_target': float((_rr_detail or {}).get('target_rr') or live_rr or 0.0),
                'tp_rr_detail': _rr_detail,
                'tp_after_rr_adjust': float(live_final_tp or 0.0),
                'tp_before_rr_adjust': float(_tp_before_dynamic or 0.0),
            })
    except Exception as _rr_cap_exc:
        try:
            _LAST_AUTOTRADE_DETAIL.setdefault(int(uid), {})
            _LAST_AUTOTRADE_DETAIL[int(uid)].update({'tp_rr_dynamic_error': f'{type(_rr_cap_exc).__name__}: {_rr_cap_exc}'})
        except Exception:
            pass
    min_live_rr = max(0.50, float(_autotrade_min_live_rr() or 1.0))
    if live_rr < min_live_rr:
        # yver125: a BUY TP rounded down (or SELL TP rounded up) can land a few
        # ticks below the configured RR floor even though the setup is valid.
        # Repair once by rounding the minimum-floor TP away from entry before
        # rejecting, so BigMove/fixed-RR setups are not skipped incorrectly.
        try:
            _dist = abs(float(price_ref) - float(sl_for_order))
            if _dist > 0:
                if side == 'BUY':
                    _floor_tp = float(price_ref) + float(min_live_rr) * float(_dist)
                    _floor_tp = _round_price_to_tick(sym, _floor_tp, rounding=ROUND_UP)
                else:
                    _floor_tp = float(price_ref) - float(min_live_rr) * float(_dist)
                    _floor_tp = _round_price_to_tick(sym, _floor_tp, rounding=ROUND_DOWN)
                _floor_rr = _autotrade_rr_value(price_ref, sl_for_order, _floor_tp, side)
                if _floor_rr >= (float(min_live_rr) - 0.005):
                    live_final_tp = float(_floor_tp)
                    live_rr = float(_floor_rr)
                    _LAST_AUTOTRADE_DETAIL.setdefault(int(uid), {})
                    _LAST_AUTOTRADE_DETAIL[int(uid)].update({
                        'tp_rr_floor_repair_applied': True,
                        'tp_rr_after_floor_repair': float(live_rr),
                        'tp_after_rr_floor_repair': float(live_final_tp),
                    })
        except Exception as _rr_floor_exc:
            try:
                _LAST_AUTOTRADE_DETAIL.setdefault(int(uid), {})
                _LAST_AUTOTRADE_DETAIL[int(uid)].update({'tp_rr_floor_repair_error': f'{type(_rr_floor_exc).__name__}: {_rr_floor_exc}'})
            except Exception:
                pass
    if live_rr < (min_live_rr - 0.005):
        try:
            _LAST_AUTOTRADE_DETAIL[int(uid)].update({'reject_reason': 'live_rr_below_floor', 'live_rr': float(live_rr), 'min_live_rr': float(min_live_rr), 'fixed_setup_tp': float(live_final_tp), 'fixed_setup_sl': float(sl_for_order), 'live_entry': float(price_ref)})
        except Exception:
            pass
        try:
            _admin_setup_lifecycle_merge(int(uid), setup_id, state=_admin_setup_state_from_reason('below_min_rr'), last_reason=f'live_rr_below_floor {live_rr:.2f}<{min_live_rr:.2f}')
        except Exception:
            pass
        try:
            _autotrade_exec_mark(reserved_keys, 'FAILED', f'live_rr_below_floor {live_rr:.2f}<{min_live_rr:.2f}')
        except Exception:
            pass
        try:
            _autotrade_runtime_symbol_lock_release(uid, sym)
        except Exception:
            pass
        return (False, 'live_rr_below_floor')
    try:
        _LAST_AUTOTRADE_DETAIL[int(uid)].update({
            'position_opened_time': datetime.now(timezone.utc).isoformat(timespec='seconds'),
            'live_exit_tp': float(live_final_tp or 0.0),
            'live_exit_sl': float(sl_for_order or 0.0),
            'live_exit_rr': float(live_rr),
            'live_tp_design': 'dynamic_rr_single_full_tp',
            'exit_target_source': 'setup_fixed_then_dynamic_rr',
        })
    except Exception:
        pass

    try:
        if str(_autotrade_runtime_mode()).lower() != 'live':
            s_paper = _autotrade_clone_setup_for_execution(s, entry=float(price_ref), sl=float(sl_for_order), tp=float(live_final_tp or 0.0), alt_target_a=0.0, alt_target_b=0.0)
            try:
                _paper_risk_usd = _autotrade_true_risk_usd(float(getattr(s_paper, 'entry', 0.0) or 0.0), float(getattr(s_paper, 'sl', 0.0) or 0.0), float(qty or 0.0), float(contract_size or 1.0))
                _paper_tp_usd = abs(float(getattr(s_paper, 'tp', 0.0) or 0.0) - float(getattr(s_paper, 'entry', 0.0) or 0.0)) * abs(float(qty or 0.0)) * float(contract_size or 1.0)
                _paper_meta = {'risk_usd': _paper_risk_usd, 'risk_pct': _risk_pct_from_amount(float(equity), _paper_risk_usd), 'tp_usd': _paper_tp_usd, 'risk_multiplier': float(risk_mult or 0.0), 'dynamic_risk_score': float((_LAST_AUTOTRADE_DETAIL.get(int(uid)) or {}).get('dynamic_risk_score') or 0.0), 'configured_risk_pct': float(configured_risk_pct or 0.0), 'allowed_risk_pct': float(allowed_risk_pct or 0.0)}
            except Exception:
                _paper_meta = {}
            trade_id = _autotrade_db_add_trade(uid, session_label, s_paper, float(qty), lifecycle_state='executed_open', lifecycle_reason='paper_opened', report_meta=_paper_meta)
            _autotrade_exec_mark(reserved_keys, 'PLACED', trade_id)
            try:
                _LAST_AUTOTRADE_DETAIL[int(uid)].update({'trade_id': str(trade_id), 'mode': 'paper'})
            except Exception:
                pass
            return (True, f"[PAPER] Opened {trade_id}: {side} {sym} qty={qty:.8g} SL={sl_for_order:g} TP={live_final_tp:g}")

        open_payload = {
            'category': 'linear',
            'symbol': sym,
            'side': 'Buy' if side == 'BUY' else 'Sell',
            'orderType': 'Market',
            'qty': _fmt_qty(float(qty), qty_step),
            'timeInForce': 'IOC',
            'positionIdx': 0,
            'orderLinkId': f"pf_op_{sym}_{int(time.time()*1000)%100000000}_{uuid.uuid4().hex[:6]}"[:36],
            'tpslMode': 'Full',
            'tpOrderType': 'Market',
            'slOrderType': 'Market',
            'tpTriggerBy': str(AUTOTRADE_LIVE_TP_TRIGGER_BY),
            'slTriggerBy': str(AUTOTRADE_LIVE_TP_TRIGGER_BY),
            'takeProfit': str(float(live_final_tp or 0.0)) if float(live_final_tp or 0.0) > 0 else None,
            'stopLoss': str(float(sl_for_order or 0.0)) if float(sl_for_order or 0.0) > 0 else None,
        }
        open_payload = {k: v for k, v in open_payload.items() if v is not None}
        open_res = _bybit_v5_request('POST', '/v5/order/create', open_payload)
        try:
            _bybit_invalidate_live_order_position_cache(sym)
        except Exception:
            pass
        try:
            _LAST_AUTOTRADE_DETAIL[int(uid)].update({'open_payload': open_payload, 'open_res': open_res})
        except Exception:
            pass
        if int((open_res or {}).get('retCode', -1)) != 0:
            err = f"{(open_res or {}).get('retCode')} {(open_res or {}).get('retMsg')}"
            _autotrade_exec_mark(reserved_keys, 'FAILED', err)
            try:
                _admin_setup_lifecycle_merge(int(uid), setup_id, state=_admin_setup_state_from_reason('exchange_reject'), last_reason=str(err))
            except Exception:
                pass
            return (False, f'live_open_failed ({err})')

        corrected = False
        open_order_result = ((open_res or {}).get('result') or {})
        open_order_id = str(open_order_result.get('orderId') or '')
        open_order_link_id = str(open_order_result.get('orderLinkId') or '')
        live_conf = _autotrade_wait_live_entry_confirmation(sym, side=side, order_id=open_order_id, order_link_id=open_order_link_id, wait_sec=10.0, step_sec=0.4)
        live_pos = live_conf.get('position')
        confirmed_filled = bool(live_conf.get('filled_confirmed'))
        filled_qty = abs(float((live_conf.get('filled_qty') or (_pos_size(live_pos) if live_pos else qty)) or 0.0))
        if filled_qty <= 0:
            filled_qty = float(qty)
        filled_entry = float(live_conf.get('avg_price') or (_pos_entry(live_pos) if live_pos else price_ref) or price_ref)
        try:
            _LAST_AUTOTRADE_DETAIL[int(uid)].update({
                'entry_confirmation': live_conf,
                'filled_qty': float(filled_qty),
                'filled_entry': float(filled_entry),
            })
        except Exception:
            pass

        if not live_pos and not confirmed_filled:
            reject_reason = str(live_conf.get('reason') or 'live_entry_fill_not_confirmed')
            try:
                _LAST_AUTOTRADE_DETAIL[int(uid)].update({'reject_reason': reject_reason})
            except Exception:
                pass
            _autotrade_exec_mark(reserved_keys, 'FAILED', reject_reason)
            try:
                _admin_setup_lifecycle_merge(int(uid), setup_id, state=_admin_setup_state_from_reason('exchange_reject'), last_reason=reject_reason)
            except Exception:
                pass
            return (False, reject_reason)

        if live_pos:
            filled_risk = _autotrade_true_risk_usd(filled_entry, sl_for_order, filled_qty, contract_size)
            filled_risk_pct = _risk_pct_from_amount(float(equity), float(filled_risk))
            _LAST_AUTOTRADE_DETAIL[int(uid)].update({
                'filled_risk_usd': float(filled_risk),
                'filled_risk_pct': float(filled_risk_pct),
            })
            if filled_risk > (allowed_risk_usd * 1.0005):
                if bool(globals().get('AUTOTRADE_STRICT_TPSL_ONLY', True)) and not bool(globals().get('AUTOTRADE_MARKET_REDUCE_ON_RISK_BREACH', False)):
                    _LAST_AUTOTRADE_DETAIL[int(uid)].update({
                        'post_fill_risk_over_cap_no_market_reduce': True,
                        'post_fill_risk_policy': 'strict_tpsl_only_leave_native_tp_sl_to_manage',
                    })
                else:
                    allowed_qty = _autotrade_qty_from_risk(filled_entry, sl_for_order, equity, risk_usd=allowed_risk_usd, contract_size=contract_size)
                    allowed_qty, reduce_reason = _round_qty_down(sym, allowed_qty, filled_entry)
                    if allowed_qty is None or allowed_qty <= 0:
                        _autotrade_exec_mark(reserved_keys, 'FAILED', f'post_fill_risk_breach_no_valid_reduction:{reduce_reason}')
                        return (False, f'post_fill_risk_breach_no_valid_reduction:{reduce_reason}')
                    reduce_qty = max(0.0, filled_qty - float(allowed_qty))
                    reduce_qty, reduce_reason = _round_qty_down(sym, reduce_qty, filled_entry)
                    if reduce_qty is None or reduce_qty <= 0:
                        _autotrade_exec_mark(reserved_keys, 'FAILED', f'post_fill_risk_breach_reduce_qty_invalid:{reduce_reason}')
                        return (False, f'post_fill_risk_breach_reduce_qty_invalid:{reduce_reason}')
                    reduce_payload = {
                        'category': 'linear',
                        'symbol': sym,
                        'side': 'Sell' if side == 'BUY' else 'Buy',
                        'orderType': 'Market',
                        'qty': _fmt_qty(reduce_qty, qty_step),
                        'timeInForce': 'IOC',
                        'reduceOnly': True,
                        'closeOnTrigger': True,
                    }
                    reduce_res = _bybit_v5_request('POST', '/v5/order/create', reduce_payload)
                    _LAST_AUTOTRADE_DETAIL[int(uid)].update({'reduce_payload': reduce_payload, 'reduce_res': reduce_res})
                    if int((reduce_res or {}).get('retCode', -1)) != 0:
                        err = f"{(reduce_res or {}).get('retCode')} {(reduce_res or {}).get('retMsg')}"
                        _autotrade_exec_mark(reserved_keys, 'FAILED', f'post_fill_risk_breach_reduce_failed:{err}')
                        return (False, f'post_fill_risk_breach_reduce_failed ({err})')
                    corrected = True
                    live_pos = _autotrade_wait_live_position(sym, side=side, wait_sec=3.0, step_sec=0.25) or _autotrade_find_live_position(sym, side=side) or live_pos
                    filled_qty = abs(float((_pos_size(live_pos) if live_pos else allowed_qty) or allowed_qty or 0.0))
                    filled_entry = float((_pos_entry(live_pos) if live_pos else filled_entry) or filled_entry or price_ref)


        final_pos = _autotrade_wait_live_position(sym, side=side, wait_sec=5.0, step_sec=0.25) or _autotrade_find_live_position(sym, side=side) or live_pos
        qty_for_db = abs(float((_pos_size(final_pos) if final_pos else filled_qty) or qty))
        if final_pos is not None:
            try:
                final_entry_for_risk = float(_pos_entry(final_pos) or filled_entry or price_ref)
                final_risk = _autotrade_true_risk_usd(final_entry_for_risk, sl_for_order, qty_for_db, contract_size)
                base_cap_pct_live = max(0.0, float(_autotrade_risk_per_trade_pct() or 0.0))
                dyn_cap_mult_live = float(_autotrade_dynamic_risk_max_mult() if _autotrade_dynamic_risk_enabled() else 1.0)
                hard_cap_pct_live = float(base_cap_pct_live) * max(1.0, float(dyn_cap_mult_live))
                hard_cap_usd_live = float(_risk_amount_from_pct(float(equity), float(hard_cap_pct_live)) or 0.0)
                final_cap_usd = min(float(allowed_risk_usd), float(hard_cap_usd_live or allowed_risk_usd))
                _LAST_AUTOTRADE_DETAIL.setdefault(int(uid), {})
                _LAST_AUTOTRADE_DETAIL[int(uid)].update({'final_live_risk_usd': float(final_risk), 'final_live_risk_cap_usd': float(final_cap_usd)})
                if final_cap_usd > 0 and final_risk > (final_cap_usd * 1.0005):
                    if bool(globals().get('AUTOTRADE_STRICT_TPSL_ONLY', True)) and not bool(globals().get('AUTOTRADE_MARKET_REDUCE_ON_RISK_BREACH', False)):
                        _LAST_AUTOTRADE_DETAIL[int(uid)].update({
                            'final_risk_over_cap_no_market_reduce': True,
                            'final_risk_policy': 'strict_tpsl_only_leave_native_tp_sl_to_manage',
                        })
                    else:
                        allowed_qty_live = _autotrade_qty_from_risk(final_entry_for_risk, sl_for_order, equity, risk_usd=final_cap_usd, contract_size=contract_size)
                        allowed_qty_live, allowed_reason_live = _round_qty_down(sym, allowed_qty_live, final_entry_for_risk)
                        reduce_qty_live = max(0.0, float(qty_for_db) - float(allowed_qty_live or 0.0)) if allowed_qty_live and allowed_qty_live > 0 else float(qty_for_db)
                        reduce_qty_live, reduce_reason_live = _round_qty_down(sym, reduce_qty_live, final_entry_for_risk)
                        if reduce_qty_live and reduce_qty_live > 0:
                            reduce_payload_live = {
                                'category': 'linear',
                                'symbol': sym,
                                'side': 'Sell' if side == 'BUY' else 'Buy',
                                'orderType': 'Market',
                                'qty': _fmt_qty(reduce_qty_live, qty_step),
                                'timeInForce': 'IOC',
                                'reduceOnly': True,
                                'closeOnTrigger': True,
                            }
                            reduce_res_live = _bybit_v5_request('POST', '/v5/order/create', reduce_payload_live)
                            _LAST_AUTOTRADE_DETAIL[int(uid)].update({'final_risk_reduce_payload': reduce_payload_live, 'final_risk_reduce_res': reduce_res_live})
                            if int((reduce_res_live or {}).get('retCode', -1)) != 0:
                                err = f"{(reduce_res_live or {}).get('retCode')} {(reduce_res_live or {}).get('retMsg')}"
                                _autotrade_exec_mark(reserved_keys, 'FAILED', f'final_risk_cap_reduce_failed:{err}')
                                return (False, f'final_risk_cap_reduce_failed ({err})')
                            corrected = True
                            final_pos = _autotrade_wait_live_position(sym, side=side, wait_sec=3.0, step_sec=0.25) or _autotrade_find_live_position(sym, side=side) or final_pos
                            qty_for_db = abs(float((_pos_size(final_pos) if final_pos else max(0.0, float(qty_for_db) - float(reduce_qty_live))) or 0.0))
                            final_entry_for_risk = float((_pos_entry(final_pos) if final_pos else final_entry_for_risk) or final_entry_for_risk)
                            final_risk = _autotrade_true_risk_usd(final_entry_for_risk, sl_for_order, qty_for_db, contract_size)
                        if final_cap_usd > 0 and final_risk > (final_cap_usd * 1.0005):
                            close_res = _autotrade_force_close_live_position(sym, side, qty_for_db)
                            _LAST_AUTOTRADE_DETAIL[int(uid)].update({'reject_reason': 'final_per_trade_risk_pct_exceeded_closed', 'risk_close_res': close_res})
                            _autotrade_exec_mark(reserved_keys, 'FAILED', 'final_per_trade_risk_pct_exceeded')
                            try:
                                _admin_setup_lifecycle_merge(int(uid), setup_id, state='failed', last_reason=f'final_per_trade_risk_pct_exceeded actual={_risk_pct_from_amount(float(equity), float(final_risk)):.2f}% cap={hard_cap_pct_live:.2f}%')
                            except Exception:
                                pass
                            return (False, 'final_per_trade_risk_pct_exceeded_closed')

            except Exception as exc:
                try:
                    _LAST_AUTOTRADE_DETAIL[int(uid)].update({'final_risk_cap_check_error': f'{type(exc).__name__}: {exc}'})
                except Exception:
                    pass
        if final_pos is None:
            try:
                _LAST_AUTOTRADE_DETAIL[int(uid)].update({'reject_reason': 'live_position_visibility_pending_for_sltp_attach'})
            except Exception:
                pass
            _autotrade_exec_mark(reserved_keys, 'FAILED', 'live_position_visibility_pending_for_sltp_attach')
            try:
                _admin_setup_lifecycle_merge(int(uid), setup_id, state='failed', last_reason='live_position_visibility_pending_for_sltp_attach')
            except Exception:
                pass
            return (False, 'live_position_visibility_pending_for_sltp_attach')

        # Last-resort live liquidation verification. If Bybit reports a liq price
        # that would be hit before SL, first try to move liquidation farther away by
        # lowering leverage on the live symbol. Only flatten if the exchange still
        # reports an unsafe liquidation price after the adjustment attempts.
        live_liq = float(_pos_liq_price(final_pos) or 0.0)
        live_entry_for_liq = float(_pos_entry(final_pos) or filled_entry or price_ref or 0.0)
        live_liq_ok = _autotrade_live_liq_guard_ok(side, live_liq, sl_for_order, live_entry_for_liq, _autotrade_runtime_liq_buffer_pct())
        try:
            _LAST_AUTOTRADE_DETAIL[int(uid)].update({
                'live_liq_price': float(live_liq),
                'live_liq_entry': float(live_entry_for_liq),
                'live_liq_guard_ok': bool(live_liq_ok),
            })
        except Exception:
            pass
        if live_liq > 0 and not live_liq_ok:
            adjust = _autotrade_adjust_live_liq_beyond_sl(sym, side, sl_for_order, live_entry_for_liq, safe_lev, uid=int(uid))
            try:
                _LAST_AUTOTRADE_DETAIL[int(uid)].update({'live_liq_adjustment': adjust})
            except Exception:
                pass
            if bool((adjust or {}).get('ok')):
                final_pos = (adjust or {}).get('position') or final_pos
                live_liq = float((adjust or {}).get('liq_price') or _pos_liq_price(final_pos) or live_liq or 0.0)
                live_entry_for_liq = float((adjust or {}).get('entry') or _pos_entry(final_pos) or live_entry_for_liq or 0.0)
                try:
                    _LAST_AUTOTRADE_DETAIL[int(uid)].update({
                        'live_liq_price_after_adjust': float(live_liq),
                        'live_leverage_after_adjust': int((adjust or {}).get('leverage') or safe_lev),
                        'live_liq_guard_ok_after_adjust': True,
                    })
                except Exception:
                    pass
            else:
                liq_reason = f'live_liq_unsafe_after_adjust liq={live_liq:g} sl={sl_for_order:g}'
                if bool(globals().get('AUTOTRADE_STRICT_TPSL_ONLY', True)) and not bool(globals().get('AUTOTRADE_MARKET_CLOSE_ON_EXIT_ATTACH_FAIL', False)):
                    _LAST_AUTOTRADE_DETAIL[int(uid)].update({
                        'reject_reason': 'live_liq_unsafe_not_closed_strict_tpsl_only',
                        'live_liq_policy': 'strict_tpsl_only_no_market_close',
                    })
                    # Continue to attach/repair native TP/SL; do not create an
                    # intermediate market close. The setup may be flagged in /autotrade_last.
                else:
                    try:
                        close_payload = {
                            'category': 'linear',
                            'symbol': sym,
                            'side': 'Sell' if side == 'BUY' else 'Buy',
                            'orderType': 'Market',
                            'qty': _fmt_qty(float(qty_for_db), qty_step),
                            'timeInForce': 'IOC',
                            'reduceOnly': True,
                            'closeOnTrigger': True,
                        }
                        close_res = _bybit_v5_request('POST', '/v5/order/create', close_payload)
                        _LAST_AUTOTRADE_DETAIL[int(uid)].update({'reject_reason': 'live_liq_unsafe_closed', 'liq_close_payload': close_payload, 'liq_close_res': close_res})
                    except Exception as exc:
                        close_res = {'retCode': -1, 'retMsg': f'{type(exc).__name__}: {exc}'}
                        try:
                            _LAST_AUTOTRADE_DETAIL[int(uid)].update({'reject_reason': 'live_liq_unsafe_close_failed', 'liq_close_res': close_res})
                        except Exception:
                            pass
                    _autotrade_exec_mark(reserved_keys, 'FAILED', 'live_liq_unsafe_after_adjust')
                    try:
                        _admin_setup_lifecycle_merge(int(uid), setup_id, state='failed', last_reason=liq_reason)
                    except Exception:
                        pass
                    return (False, 'live_liq_unsafe_closed')


        # Ver28: persist authoritative dynamic-risk/reporting metrics at entry.
        # Do this before journalling so /autotrade_report does not have to guess from
        # the base risk config or current equity after the fact.
        try:
            _report_entry = float(filled_entry or price_ref or 0.0)
            _report_sl = float(sl_for_order or 0.0)
            _report_tp = float(live_final_tp or 0.0)
            _report_qty = float(qty_for_db or 0.0)
            _report_cs = float(contract_size or 1.0)
            _report_risk_usd = _autotrade_true_risk_usd(_report_entry, _report_sl, _report_qty, _report_cs)
            _report_tp_usd = abs(_report_tp - _report_entry) * abs(_report_qty) * abs(_report_cs) if _report_entry > 0 and _report_tp > 0 and _report_qty > 0 else 0.0
            _report_risk_pct = _risk_pct_from_amount(float(equity), float(_report_risk_usd))
            _report_rr = (_report_tp_usd / _report_risk_usd) if _report_risk_usd > 0 and _report_tp_usd > 0 else 0.0
        except Exception:
            _report_risk_usd = float(allowed_risk_usd or 0.0)
            _report_risk_pct = float(allowed_risk_pct or 0.0)
            _report_tp_usd = 0.0
            _report_rr = 0.0
        _report_meta = {
            'risk_usd': float(_report_risk_usd or 0.0),
            'risk_pct': float(_report_risk_pct or 0.0),
            'tp_usd': float(_report_tp_usd or 0.0),
            'risk_multiplier': float(risk_mult or 0.0),
            'dynamic_risk_score': float((_LAST_AUTOTRADE_DETAIL.get(int(uid)) or {}).get('dynamic_risk_score') or 0.0),
            'configured_risk_pct': float(configured_risk_pct or 0.0),
            'allowed_risk_pct': float(allowed_risk_pct or 0.0),
            'rr_tp': float(_report_rr or 0.0),
        }
        s_live = _autotrade_clone_setup_for_execution(s, entry=float(filled_entry or price_ref), sl=float(sl_for_order), tp=float(live_final_tp or 0.0), alt_target_a=0.0, alt_target_b=0.0, **_report_meta)
        trade_id = _autotrade_db_add_trade(uid, session_label, s_live, qty_for_db, lifecycle_state='executed_open', lifecycle_reason='live_opened_pending_exit_attach', report_meta=_report_meta)
        _autotrade_exec_mark(reserved_keys, 'PLACED', trade_id)
        try:
            _admin_setup_lifecycle_merge(
                int(uid),
                setup_id,
                trade_id=str(trade_id),
                bybit_position_symbol=str(sym or ''),
                bybit_order_id=str(open_order_id or ''),
                bybit_order_link_id=str(open_order_link_id or ''),
                state='executed_open',
                last_reason='live_opened_pending_exit_attach',
            )
        except Exception:
            pass

        trade_row_live = _autotrade_db_get_trade(trade_id) or {
            'trade_id': str(trade_id),
            'setup_id': str(setup_id),
            'symbol': str(sym),
            'side': str(side),
            'entry': float(filled_entry or price_ref or 0.0),
            'sl': float(sl_for_order or 0.0),
            'tp': float(live_final_tp or 0.0),
            'qty': float(qty_for_db or 0.0),
        }

        # Authoritative exit policy: native Full-position TP/SL only.
        # Do NOT create standalone reduce-only Conditional TP orders.
        full_tpsl_res = _autotrade_attach_position_full_tpsl_and_cleanup(
            sym,
            side,
            float(sl_for_order or 0.0),
            float(live_final_tp or 0.0),
            live_pos=final_pos,
        )
        sl_ok = bool(((full_tpsl_res.get('confirm_after_cleanup') or full_tpsl_res.get('confirm') or {}).get('sl_ok')))
        tp_ok = bool(((full_tpsl_res.get('confirm_after_cleanup') or full_tpsl_res.get('confirm') or {}).get('tp_ok')))

        repair_res = {}
        if not (sl_ok and tp_ok):
            repair_res = _autotrade_repair_live_exit_protection(int(uid), trade_row_live, live_pos=final_pos)
            sl_ok = bool((repair_res.get('confirm_after_cleanup') or repair_res.get('attach_res', {}).get('confirm_after_cleanup') or repair_res.get('attach_res', {}).get('confirm') or {}).get('sl_ok') or repair_res.get('sl_fixed'))
            tp_ok = bool((repair_res.get('confirm_after_cleanup') or repair_res.get('attach_res', {}).get('confirm_after_cleanup') or repair_res.get('attach_res', {}).get('confirm') or {}).get('tp_ok') or repair_res.get('tp_fixed'))

        _LAST_AUTOTRADE_DETAIL[int(uid)].update({
            'trade_id': str(trade_id),
            'exit_attach_res': full_tpsl_res,
            'repair_res': repair_res,
            'sl_stack_ok': bool(sl_ok),
            'tp_stack_ok': bool(tp_ok),
            'exit_policy': 'position_full_tpsl_only_no_conditional_orders',
        })

        suffix = ' corrected_for_post_fill_risk' if corrected else ''
        if not (sl_ok and tp_ok):
            # Bybit can lag before position-level TP/SL fields become visible.
            # Reconfirm once more before flattening to avoid open-then-immediate-close
            # false negatives like the reported ZEC case.
            try:
                grace_ok, grace_detail = _autotrade_confirm_position_full_tpsl(sym, side, float(sl_for_order or 0.0), float(live_final_tp or 0.0), wait_sec=8.0, step_sec=0.5)
                _LAST_AUTOTRADE_DETAIL[int(uid)].update({'exit_attach_grace_confirm': grace_detail})
                if grace_ok:
                    sl_ok = True
                    tp_ok = True
            except Exception:
                pass
        if not (sl_ok and tp_ok):
            if bool(globals().get('AUTOTRADE_STRICT_TPSL_ONLY', True)) and not bool(globals().get('AUTOTRADE_MARKET_CLOSE_ON_EXIT_ATTACH_FAIL', False)):
                try:
                    _LAST_AUTOTRADE_DETAIL[int(uid)].update({
                        'reject_reason': 'live_exit_attach_unconfirmed_not_closed_strict_tpsl_only',
                        'exit_attach_policy': 'no_market_close_continue_with_repair_guardian',
                    })
                except Exception:
                    pass
                try:
                    _admin_setup_lifecycle_merge(int(uid), setup_id, trade_id=str(trade_id), bybit_position_symbol=str(sym or ''), state='executed_open', last_reason='exit_attach_unconfirmed_guardian_will_repair')
                except Exception:
                    pass
                # Continue as opened. The guardian will retry native TP/SL repair; do not
                # create a market close that is neither TP nor SL.
            else:
                close_res = _autotrade_force_close_live_position(sym, side, qty=qty_for_db)
                try:
                    _LAST_AUTOTRADE_DETAIL[int(uid)].update({'reject_reason': 'live_exit_attach_failed_force_closed', 'force_close_res': close_res})
                except Exception:
                    pass
                try:
                    _admin_setup_lifecycle_merge(int(uid), setup_id, trade_id=str(trade_id), bybit_position_symbol=str(sym or ''), state='failed', last_reason='live_exit_attach_failed_force_closed')
                except Exception:
                    pass
                try:
                    _autotrade_mark_trade_closed(str(trade_id), status='SL', reason='live_exit_attach_failed_force_closed')
                except Exception:
                    pass
                _autotrade_exec_mark(reserved_keys, 'FAILED', 'live_exit_attach_failed_force_closed')
                return (False, f"live_exit_attach_failed_force_closed ({(close_res or {}).get('retCode')} {(close_res or {}).get('retMsg')})")

        # Ver06: after Bybit TP/SL attachment/repair, re-read the actual exchange
        # position and stop. If the true SL-based risk is above the cap, reduce/close
        # immediately before reporting the trade as successfully opened.
        try:
            post_pos = _autotrade_wait_live_position(sym, side=side, wait_sec=2.0, step_sec=0.25) or _autotrade_find_live_position(sym, side=side) or final_pos
            post_detail = _autotrade_live_position_risk_detail(post_pos) if post_pos else {}
            strict_cap = float(final_cap_usd or _autotrade_hard_risk_cap_usd(float(equity)) or allowed_risk_usd or 0.0)
            _LAST_AUTOTRADE_DETAIL[int(uid)].update({'post_attach_risk_detail': post_detail, 'post_attach_risk_cap_usd': float(strict_cap)})
            if strict_cap > 0 and float((post_detail or {}).get('risk_usd') or 0.0) > strict_cap * 1.0005:
                if bool(globals().get('AUTOTRADE_STRICT_TPSL_ONLY', True)) and not bool(globals().get('AUTOTRADE_MARKET_REDUCE_ON_RISK_BREACH', False)):
                    _LAST_AUTOTRADE_DETAIL[int(uid)].update({
                        'post_attach_risk_over_cap_no_market_reduce': True,
                        'post_attach_risk_policy': 'strict_tpsl_only_leave_native_tp_sl_to_manage',
                    })
                else:
                    rg = _autotrade_reduce_live_position_to_risk_cap(sym, side, strict_cap, reason='post_attach_risk_cap', live_pos=post_pos)
                    _LAST_AUTOTRADE_DETAIL[int(uid)].update({'post_attach_risk_guard': rg})
                    if not bool((rg or {}).get('ok')) or str((rg or {}).get('action') or '').startswith('closed'):
                        _autotrade_exec_mark(reserved_keys, 'FAILED', 'post_attach_risk_cap_closed')
                        try:
                            _admin_setup_lifecycle_merge(int(uid), setup_id, trade_id=str(trade_id), bybit_position_symbol=str(sym or ''), state='failed', last_reason='post_attach_risk_cap_closed')
                        except Exception:
                            pass
                        return (False, 'post_attach_risk_cap_closed')
        except Exception as exc:
            try:
                _LAST_AUTOTRADE_DETAIL[int(uid)].update({'post_attach_risk_guard_error': f'{type(exc).__name__}: {exc}'})
            except Exception:
                pass

        try:
            _admin_setup_lifecycle_merge(int(uid), setup_id, trade_id=str(trade_id), bybit_position_symbol=str(sym or ''), state='executed_open', last_reason='live_opened')
        except Exception:
            pass
        return (True, f"[LIVE] Opened {trade_id}: {side} {sym} qty={qty_for_db:.8g} SL={sl_for_order:g} TP={live_final_tp:g}{suffix}")

    except Exception as e:
        err_txt = f'{type(e).__name__}: {e}'
        try:
            _LAST_AUTOTRADE_DETAIL.setdefault(int(uid), {})
            _LAST_AUTOTRADE_DETAIL[int(uid)].update({'reject_reason': f'autotrade_execution_error:{err_txt}', 'exception': err_txt})
        except Exception:
            pass
        try:
            logger.exception('autotrade execution failed uid=%s setup=%s symbol=%s: %s', uid, setup_id, sym, err_txt)
        except Exception:
            pass
        try:
            _admin_setup_lifecycle_merge(int(uid), setup_id, state='failed', last_reason=f'autotrade_execution_error:{err_txt}')
        except Exception:
            pass
        try:
            _autotrade_exec_mark(reserved_keys, 'FAILED', err_txt)
        except Exception:
            pass
        return (False, f'autotrade_execution_error:{err_txt[:160]}')
    finally:
        if runtime_lock_acquired:
            _autotrade_runtime_symbol_lock_release(uid, sym)

