def _default_sessions_for_tz(tz_name: str) -> List[str]:
    # Default-enabled trading sessions for signaling.
    # Users can still deactivate any of them via /sessions_off.
    return ["NY", "LON", "ASIA"]

def _order_sessions(xs: List[str]) -> List[str]:
    cleaned = []
    for x in xs:
        x = str(x).strip().upper()
        if x in SESSIONS_UTC and x not in cleaned:
            cleaned.append(x)
    return [s for s in SESSION_PRIORITY if s in cleaned]

def get_user(user_id: int) -> dict:
    con = db_connect()
    cur = con.cursor()
    cur.execute("SELECT * FROM users WHERE user_id=?", (user_id,))
    row = cur.fetchone()

    if not row:
        tz_name = _default_user_tz_name()
        sessions = ['NY', 'LON', 'ASIA']
        now_local = datetime.now(ZoneInfo(tz_name)).date().isoformat()
        cur.execute("""
            INSERT INTO users (
                user_id, tz, scan_profile, equity, risk_mode, risk_value,
                daily_cap_mode, daily_cap_value,
                max_trades_day, notify_on,
                sessions_enabled, max_emails_per_session, email_gap_min,
                max_emails_per_day, day_reset_hhmm,
                day_trade_date, day_trade_count
            )
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        """, (
            user_id,
            tz_name,
            str(DEFAULT_SCAN_PROFILE),
            float(DEFAULT_EQUITY),
            DEFAULT_RISK_MODE,
            float(DEFAULT_RISK_VALUE),
            DEFAULT_DAILY_CAP_MODE,
            float(DEFAULT_DAILY_CAP_VALUE),
            int(DEFAULT_MAX_TRADES_DAY),
            
            # ✅ FIX: default notify_on should NOT depend on EMAIL_ENABLED
            1,
            
            json.dumps(sessions),
            int(DEFAULT_MAX_EMAILS_PER_SESSION),
            int(DEFAULT_MIN_EMAIL_GAP_MIN),
            int(DEFAULT_MAX_EMAILS_PER_DAY),
            str(DEFAULT_USER_DAY_RESET_HHMM),
            now_local,
            0
        ))
        con.commit()
        cur.execute("SELECT * FROM users WHERE user_id=?", (user_id,))
        row = cur.fetchone()

    con.close()
    return dict(row)

FAST_USER_CACHE_TTL_SEC = int(os.getenv("FAST_USER_CACHE_TTL_SEC", "45") or 55)

def _user_cache_key(user_id: int) -> str:
    return f"user_row:{int(user_id)}"

def invalidate_user_cache(user_id: int) -> None:
    try:
        _CACHE.pop(_user_cache_key(int(user_id)), None)
    except Exception:
        pass

def get_user_cached_fast(user_id: int, ttl: int | None = None) -> dict:
    """Fast cached user settings for instant commands like /size."""
    ttl_i = max(5, int(ttl if ttl is not None else FAST_USER_CACHE_TTL_SEC))
    key = _user_cache_key(int(user_id))
    try:
        if cache_valid(key, ttl_i):
            obj = cache_get(key)
            if isinstance(obj, dict) and obj:
                return dict(obj)
    except Exception:
        pass
    row = get_user(int(user_id))
    try:
        if isinstance(row, dict) and row:
            cache_set(key, dict(row))
    except Exception:
        pass
    return row if isinstance(row, dict) else {}

async def get_user_cached_fast_async(user_id: int, ttl: int | None = None) -> dict:
    """Async wrapper so instant commands never block the event loop on SQLite."""
    ttl_i = max(5, int(ttl if ttl is not None else FAST_USER_CACHE_TTL_SEC))
    key = _user_cache_key(int(user_id))
    try:
        if cache_valid(key, ttl_i):
            obj = cache_get(key)
            if isinstance(obj, dict) and obj:
                return dict(obj)
    except Exception:
        pass
    try:
        row = await to_thread_fast(get_user, int(user_id), timeout=2)
    except Exception:
        row = get_user(int(user_id))
    try:
        if isinstance(row, dict) and row:
            cache_set(key, dict(row))
    except Exception:
        pass
    return row if isinstance(row, dict) else {}

# =========================================================
# ACCESS CONTROL (FREE TRIAL + PAYWALL)
# =========================================================
def trial_expired_legacy(user: dict) -> bool:
    try:
        created = datetime.fromisoformat(user["created_at"])
    except Exception:
        return True
    return datetime.utcnow() > created + timedelta(days=FREE_TRIAL_DAYS)


def has_active_access_legacy(user: dict) -> bool:
    if user.get("plan") in ("standard", "pro"):
        return True
    if user.get("plan") == "free" and not trial_expired(user):
        return True
    return False


def enforce_access_or_block(update: Update, command: str) -> bool:
    """Synchronous access guard used by fast thread-offloaded checks.

    Never call Telegram async reply methods directly here; the async caller is responsible
    for sending any user-facing access-locked message.
    """
    uid = update.effective_user.id
    if is_admin_user(uid):
        return True

    user = get_user(uid)

    if has_active_access(uid, user):
        return True

    if command in ALLOWED_WHEN_LOCKED:
        return True

    return False

def update_user(user_id: int, **kwargs):
    if not kwargs:
        return
    con = db_connect()
    cur = con.cursor()
    sets = ", ".join([f"{k}=?" for k in kwargs.keys()])
    vals = list(kwargs.values()) + [user_id]
    cur.execute(f"UPDATE users SET {sets} WHERE user_id=?", vals)
    con.commit()
    con.close()
    invalidate_user_cache(int(user_id))

def set_user_email(uid: int, email: str) -> None:
    with sqlite3.connect(DB_PATH) as con:
        cur = con.cursor()
        # ensure row exists
        cur.execute(
            "INSERT OR IGNORE INTO users(user_id) VALUES(?)",
            (uid,)
        )
        cur.execute(
            "UPDATE users SET email_to = ? WHERE user_id = ?",
            (email, uid)
        )
        con.commit()
    invalidate_user_cache(int(uid))

