def ensure_billing_columns():
    """Ensure billing / plan / trial columns exist on users table (backward compatible migrations)."""
    with sqlite3.connect(DB_PATH) as con:
        cur = con.cursor()

        # Plan / trial columns
        for ddl, label in [
            ("ALTER TABLE users ADD COLUMN plan TEXT DEFAULT 'free'", "plan"),
            ("ALTER TABLE users ADD COLUMN trial_start_ts REAL DEFAULT 0", "trial_start_ts"),
            ("ALTER TABLE users ADD COLUMN trial_until REAL DEFAULT 0", "trial_until"),
            ("ALTER TABLE users ADD COLUMN plan_expires REAL DEFAULT 0", "plan_expires"),
            ("ALTER TABLE users ADD COLUMN access_source TEXT", "access_source"),
            ("ALTER TABLE users ADD COLUMN access_ref TEXT", "access_ref"),
            ("ALTER TABLE users ADD COLUMN access_updated_ts REAL DEFAULT 0", "access_updated_ts"),
        ]:
            try:
                cur.execute(ddl)
                con.commit()
                logger.info("Added %s column to users table", label)
            except sqlite3.OperationalError:
                # column already exists (or older sqlite limitation)
                pass


def reset_daily_if_needed(user: dict) -> dict:
    user = dict(user or {})
    uid = int(user.get("user_id") or 0)
    if uid <= 0:
        return user

    start_local, _, _ = _user_today_window(user)
    today_key = start_local.date().isoformat()

    if str(user.get("day_trade_date") or "") != today_key:
        update_user(uid, day_trade_date=today_key, day_trade_count=0)
        user = get_user(uid)

    return user


def list_users_notify_on() -> List[dict]:
    """Users who should receive trade-signal / scan emails.

    Sync rules:
    - Primary rule: notify_on=1 AND email_alerts_enabled=1 AND has a saved email address.
    - Admins are ALWAYS included if they have an email saved, even if notify_on=0,
      but still respect the master email switch when that column exists.
    """
    con = db_connect()
    try:
        import sqlite3
        con.row_factory = sqlite3.Row
    except Exception:
        pass

    cur = con.cursor()

    cols = set()
    try:
        cur.execute("PRAGMA table_info(users)")
        cols = {str(r[1]) for r in cur.fetchall()}
    except Exception:
        cols = set()

    email_fields = []
    if "email" in cols:
        email_fields.append("email")
    if "email_to" in cols:
        email_fields.append("email_to")
    if not email_fields:
        email_fields = ["email_to"]

    email_ok_where = " OR ".join([f"({c} IS NOT NULL AND TRIM({c})!='')" for c in email_fields])
    master_on_where = "COALESCE(email_alerts_enabled, 1) = 1" if "email_alerts_enabled" in cols else "1=1"

    # 1) users opted into trade-signal emails
    try:
        cur.execute(
            f"SELECT * FROM users WHERE notify_on=1 AND ({master_on_where}) AND ({email_ok_where})"
        )
        rows = [dict(r) for r in cur.fetchall()]
    except Exception:
        # fallback for older schemas
        try:
            cur.execute(f"SELECT * FROM users WHERE notify_on=1 AND ({email_ok_where})")
        except Exception:
            cur.execute("SELECT * FROM users WHERE notify_on=1")
        rows = [dict(r) for r in cur.fetchall()]

    # 2) admins with an email saved (even if notify_on=0), but respect master switch
    try:
        cur.execute(f"SELECT * FROM users WHERE ({master_on_where}) AND ({email_ok_where})")
        for r in cur.fetchall():
            d = dict(r)
            try:
                uid = int(d.get("user_id") or 0)
            except Exception:
                uid = 0
            if uid and is_admin_user(uid):
                if not any(int(x.get("user_id") or 0) == uid for x in rows):
                    rows.append(d)
    except Exception:
        pass

    filtered_rows = []
    for d in (rows or []):
        try:
            uid = int(d.get("user_id") or 0)
        except Exception:
            uid = 0
        if not uid:
            continue
        try:
            if is_admin_user(uid) or user_has_pro(uid, d):
                filtered_rows.append(d)
        except Exception:
            continue

    return filtered_rows


def list_users_with_email() -> List[dict]:
    """
    Users eligible for email sends (have a saved recipient email).
    This is used for Big-Move Alerts so it works even if notify_on=0 and even if
    the user has trade-signal email delivery switched off.

    IMPORTANT:
    Some DB versions don't have users.email (only users.email_to).
    This function auto-detects columns and builds a safe query.
    """
    con = db_connect()
    try:
        # Ensure rows are dict-convertible
        try:
            import sqlite3
            con.row_factory = sqlite3.Row
        except Exception:
            pass

        cur = con.cursor()

        # Detect available columns in users table
        try:
            cur.execute("PRAGMA table_info(users)")
            cols = {str(r[1]).lower() for r in cur.fetchall()}  # r[1] is column name
        except Exception:
            cols = set()

        has_email_to = ("email_to" in cols)
        has_email = ("email" in cols)

        # Build safe WHERE clause
        where_parts = []
        if has_email_to:
            where_parts.append("(email_to IS NOT NULL AND TRIM(email_to) != '')")
        if has_email:
            where_parts.append("(email IS NOT NULL AND TRIM(email) != '')")

        # If neither column exists, no one is eligible
        if not where_parts:
            return []

        where_sql = " OR ".join(where_parts)

        cur.execute(f"""
            SELECT *
            FROM users
            WHERE {where_sql}
        """)
        rows = cur.fetchall()
        return [dict(r) for r in rows]
    finally:
        try:
            con.close()
        except Exception:
            pass


    
def email_state_get(user_id: int) -> dict:
    con = db_connect()
    cur = con.cursor()
    cur.execute("SELECT * FROM email_state WHERE user_id=?", (user_id,))
    row = cur.fetchone()
    if not row:
        cur.execute("INSERT INTO email_state (user_id, session_key, sent_count, last_email_ts) VALUES (?, ?, ?, ?)",
                    (user_id, "NONE", 0, 0.0))
        con.commit()
        cur.execute("SELECT * FROM email_state WHERE user_id=?", (user_id,))
        row = cur.fetchone()
    con.close()
    return dict(row)

def email_state_set(user_id: int, **kwargs):
    if not kwargs:
        return
    con = db_connect()
    cur = con.cursor()
    sets = ", ".join([f"{k}=?" for k in kwargs.keys()])
    vals = list(kwargs.values()) + [user_id]
    cur.execute(f"UPDATE email_state SET {sets} WHERE user_id=?", vals)
    con.commit()
    con.close()


def _last_sent_email_meta(user_id: int, user: dict | None = None) -> dict:
    """Best-effort last successful email metadata for telemetry counters.

    This reconciles counters when SMTP succeeded but setup/email state tables lag or when
    the email was a market-scan / big-move email rather than an emailed_setup row.
    """
    try:
        row = dict(_LAST_EMAIL_SENT.get(int(user_id)) or {})
    except Exception:
        row = {}
    if not row:
        try:
            dec = dict(_LAST_EMAIL_DECISION.get(int(user_id)) or {})
            if str(dec.get('status') or '').upper().strip() == 'SENT':
                row = dec
        except Exception:
            row = {}
    ts_val = 0.0
    try:
        raw = row.get('ts')
        if raw not in (None, '', 0, '0'):
            ts_val = float(raw)
    except Exception:
        ts_val = 0.0
    if ts_val <= 0:
        try:
            dt = _parse_iso_utcish(str(row.get('when') or '').strip())
            ts_val = float(dt.timestamp()) if dt else 0.0
        except Exception:
            ts_val = 0.0
    sess_name = 'NONE'
    try:
        if ts_val > 0:
            sess_name = current_session_utc(datetime.fromtimestamp(float(ts_val), tz=timezone.utc)) or 'NONE'
    except Exception:
        sess_name = 'NONE'
    day_local = ''
    try:
        tz = _user_tzinfo(user or {})
        if ts_val > 0:
            day_local = datetime.fromtimestamp(float(ts_val), tz).date().isoformat()
    except Exception:
        day_local = ''
    return {
        'row': row,
        'ts': float(ts_val or 0.0),
        'session_name': str(sess_name or 'NONE'),
        'day_local': str(day_local or ''),
        'status': str(row.get('status') or '').upper().strip(),
    }

def mark_symbol_emailed(user_id: int, symbol: str, side: str, session_name: str = ""):
    """
    ✅ Direction-aware cooldown: stored per (symbol, side)
    Optionally stores session name (NY/LON/ASIA) for audit.
    """
    con = db_connect()
    cur = con.cursor()
    cur.execute("""
        INSERT INTO emailed_symbols (user_id, symbol, side, session, emailed_ts)
        VALUES (?, ?, ?, ?, ?)
        ON CONFLICT(user_id, symbol, side) DO UPDATE SET
            session=excluded.session,
            emailed_ts=excluded.emailed_ts
    """, (int(user_id), str(symbol).upper(), str(side).upper(), str(session_name or ""), time.time()))
    con.commit()
    con.close()

def symbol_recently_emailed(
    user_id: int,
    symbol: str,
    side: str,
    session_name: str,
) -> bool:
    """
    ✅ Session-aware + direction-aware cooldown check.
    Cooldown hours depend on CURRENT session (NY/LON/ASIA).
    """
    cooldown_hours = float(email_setup_cooldown_hours_for_session(session_name))

    con = db_connect()
    cur = con.cursor()
    cur.execute("""
        SELECT emailed_ts
        FROM emailed_symbols
        WHERE user_id=? AND symbol=? AND side=?
    """, (int(user_id), str(symbol).upper(), str(side).upper()))
    row = cur.fetchone()
    con.close()
    if not row:
        return False

    last_ts = float(row["emailed_ts"])
    try:
        if last_ts < float(_autotrade_cooldown_reset_ts() or 0.0):
            return False
    except Exception:
        pass
    return (time.time() - last_ts) < (cooldown_hours * 3600.0)



def _email_symbol_recently_sent(user_id: int, symbol: str, side: str, session_name: str, setup_id: str = '') -> bool:
    """Stronger duplicate suppression across email paths.

    Uses both the cooldown table and recent emailed_setups/setup lifecycle so the same symbol+side
    cannot be re-emailed before the session cooldown expires, even if a new setup_id is generated
    or /screen sync races the background email loop.
    """
    try:
        if symbol_recently_emailed(int(user_id), symbol, side, session_name):
            return True
    except Exception:
        pass
    try:
        sid = str(setup_id or '').strip()
        if sid and db_has_emailed_setup(int(user_id), sid, lookback_hours=max(1, int(math.ceil(float(email_setup_cooldown_hours_for_session(session_name) or 1))))):
            return True
    except Exception:
        pass
    try:
        cooldown_sec = float(email_setup_cooldown_hours_for_session(session_name)) * 3600.0
        cutoff = max(float(time.time() - cooldown_sec), float(_autotrade_cooldown_reset_ts() or 0.0))
        sym = str(_bybit_linear_symbol(symbol) or '').upper()
        sd = str(side or '').upper().strip()
        if not sym or not sd:
            return False
        with sqlite3.connect(DB_PATH) as conn:
            conn.row_factory = sqlite3.Row
            cur = conn.cursor()
            rows = cur.execute(
                """SELECT e.setup_id, e.emailed_ts, s.symbol, s.side
                       FROM emailed_setups e
                       LEFT JOIN signals s ON s.setup_id = e.setup_id
                       WHERE e.user_id=? AND e.emailed_ts>=?
                       ORDER BY e.emailed_ts DESC LIMIT 64""",
                (int(user_id), float(cutoff)),
            ).fetchall() or []
        for r in rows:
            try:
                rsym = str(_bybit_linear_symbol((r['symbol'] if isinstance(r, sqlite3.Row) else r.get('symbol')) or '')).upper()
                rside = str((r['side'] if isinstance(r, sqlite3.Row) else r.get('side')) or '').upper().strip()
                if rsym == sym and (bool(globals().get('EMAIL_SETUP_COOLDOWN_ANY_SIDE', False)) or rside == sd):
                    return True
            except Exception:
                continue
    except Exception:
        pass
    return False



def setup_generation_cooldown_hours_for_session(session_name: str) -> float:
    """Cooldown used before a setup is admitted to the executable lane."""
    try:
        return float(max(float(cooldown_hours_for_session(session_name)), float(SETUP_GENERATION_SYMBOL_COOLDOWN_HOURS)))
    except Exception:
        return float(SETUP_GENERATION_SYMBOL_COOLDOWN_HOURS or 3.0)


def email_setup_cooldown_hours_for_session(session_name: str) -> float:
    """Cooldown used before a setup email is sent."""
    try:
        return float(max(float(cooldown_hours_for_session(session_name)), float(EMAIL_SETUP_SYMBOL_COOLDOWN_HOURS)))
    except Exception:
        return float(EMAIL_SETUP_SYMBOL_COOLDOWN_HOURS or 3.0)


def _symbol_side_for_cooldown(symbol: str, side: str) -> tuple[str, str]:
    try:
        sym = str(_bybit_linear_symbol(symbol) or '').upper().strip()
    except Exception:
        sym = str(symbol or '').upper().strip()
    return sym, str(side or '').upper().strip()


def _setup_generation_symbol_recently_seen(user_id: int, symbol: str, side: str, session_name: str, setup_id: str = '') -> bool:
    """Block repeated executable setup generation for the same symbol/side.

    This is intentionally independent from AutoTrade. It reads the setup queues
    (executable_setups and generated_setups), not autotrade_trades, so the audit and
    generation lane stay separated from real trade outcomes and /autotrade_config.
    """
    try:
        cooldown_sec = float(setup_generation_cooldown_hours_for_session(session_name)) * 3600.0
        if cooldown_sec <= 0:
            return False
        cutoff = max(float(time.time()) - cooldown_sec, float(_autotrade_cooldown_reset_ts() or 0.0))
        sym, sd = _symbol_side_for_cooldown(symbol, side)
        sid = str(setup_id or '').strip()
        if not sym or not sd:
            return False
        base_sym = sym[:-4] if sym.endswith('USDT') else sym
        sym_aliases = list(dict.fromkeys([sym, base_sym]))
        sym_ph = ','.join(['?'] * len(sym_aliases))
        uid = int(user_id or 0)
        owner_uid = int(globals().get('AUTOTRADE_OWNER_UID', 0) or 0)
        uid_candidates = list(dict.fromkeys([uid, 0, owner_uid] if uid > 0 else [0, owner_uid]))
        uid_candidates = [int(x) for x in uid_candidates if int(x or 0) >= 0]
        if not uid_candidates:
            uid_candidates = [uid]
        ph = ','.join(['?'] * len(uid_candidates))
        with sqlite3.connect(DB_PATH) as conn:
            conn.row_factory = sqlite3.Row
            cur = conn.cursor()
            # 1) executable lane: this is the important production gate.
            try:
                side_clause = '' if SETUP_GENERATION_COOLDOWN_ANY_SIDE else 'AND UPPER(COALESCE(side,\'\'))=?'
                params = list(uid_candidates) + [float(cutoff)] + list(sym_aliases)
                if not SETUP_GENERATION_COOLDOWN_ANY_SIDE:
                    params.append(sd)
                rows = cur.execute(f"""
                    SELECT setup_id, executable_ts, symbol, side
                    FROM executable_setups
                    WHERE user_id IN ({ph})
                      AND executable_ts>=?
                      AND UPPER(COALESCE(symbol,'')) IN ({sym_ph})
                      {side_clause}
                    ORDER BY executable_ts DESC
                    LIMIT 12
                """, tuple(params)).fetchall() or []
                for r in rows:
                    old_sid = str(r['setup_id'] or '').strip()
                    if sid and old_sid == sid:
                        continue
                    return True
            except Exception:
                pass
            # 2) generated_setups fallback: catches raw/generated rows before they are executable.
            try:
                side_clause = '' if SETUP_GENERATION_COOLDOWN_ANY_SIDE else 'AND UPPER(COALESCE(side,\'\'))=?'
                params = list(uid_candidates) + [float(cutoff)] + list(sym_aliases)
                if not SETUP_GENERATION_COOLDOWN_ANY_SIDE:
                    params.append(sd)
                rows = cur.execute(f"""
                    SELECT setup_id, created_ts, symbol, side
                    FROM generated_setups
                    WHERE user_id IN ({ph})
                      AND created_ts>=?
                      AND UPPER(COALESCE(symbol,'')) IN ({sym_ph})
                      {side_clause}
                    ORDER BY created_ts DESC
                    LIMIT 12
                """, tuple(params)).fetchall() or []
                for r in rows:
                    old_sid = str(r['setup_id'] or '').strip()
                    if sid and old_sid == sid:
                        continue
                    return True
            except Exception:
                pass
    except Exception:
        pass
    return False

def _safe_float(x, default: float = 0.0) -> float:
    try:
        if x is None:
            return default
        s = str(x).strip()
        if s == "" or s == "-" or s.lower() == "none":
            return default
        return float(s)
    except Exception:
        return default



