def bigmove_recently_emailed(uid: int, symbol: str, direction: str) -> bool:
    """BigMove/F8 duplicate guard.

    Ver15 default: same-symbol / same-direction cooldown is ON for F8 BigMove alerts
    to stop repeated emails and repeated AutoTrade entries on the same move. Opposite
    direction is not blocked, so the F8 opposite-position close rule can still act.
    """
    try:
        if int(BIGMOVE_COOLDOWN_SEC or 0) <= 0:
            return False
        with sqlite3.connect(DB_PATH) as conn:
            cur = conn.cursor()
            cur.execute(
                "SELECT emailed_ts FROM emailed_bigmoves WHERE user_id=? AND symbol=? AND direction=?",
                (int(uid), str(symbol), str(direction)),
            )
            row = cur.fetchone()
            if not row:
                return False
            last_ts = float(row[0] or 0.0)
            return (time.time() - last_ts) < float(BIGMOVE_COOLDOWN_SEC or 0)
    except Exception:
        return False

def mark_bigmove_emailed(uid: int, symbol: str, direction: str) -> None:
    try:
        with sqlite3.connect(DB_PATH) as conn:
            cur = conn.cursor()
            cur.execute(
                "INSERT OR REPLACE INTO emailed_bigmoves(user_id, symbol, direction, emailed_ts) VALUES(?,?,?,?)",
                (int(uid), str(symbol), str(direction), time.time()),
            )
            conn.commit()
    except Exception:
        pass


def _bigmove_autotrade_trigger_migrate() -> None:
    """Deduplicate owner AutoTrade triggers for BigMove/F8 across multiple email recipients.

    BigMove alerts are sent per user, but owner AutoTrade must trigger only once per
    symbol+direction event. Otherwise one market event sent to multiple subscribers can
    create repeated owner trades for the same symbol/direction.
    """
    try:
        with sqlite3.connect(DB_PATH) as conn:
            cur = conn.cursor()
            cur.execute("""
                CREATE TABLE IF NOT EXISTS bigmove_autotrade_triggers (
                    user_id INTEGER NOT NULL,
                    symbol TEXT NOT NULL,
                    direction TEXT NOT NULL,
                    triggered_ts REAL NOT NULL DEFAULT 0,
                    note TEXT NOT NULL DEFAULT '',
                    PRIMARY KEY(user_id, symbol, direction)
                )
            """)
            conn.commit()
    except Exception:
        pass


def _bigmove_autotrade_claim_candidates(owner_uid: int, candidates: list) -> list:
    """Return only F8 candidates not recently AutoTrade-triggered for owner.

    Cooldown is same symbol + same direction only. Opposite direction is allowed so the
    safety rule can close an opposite open position immediately.
    """
    _bigmove_autotrade_trigger_migrate()
    out = []
    try:
        owner = int(owner_uid or 0)
        if owner <= 0:
            return []
        cooldown = max(0, int(BIGMOVE_AUTOTRADE_TRIGGER_COOLDOWN_SEC or 0))
        now_ts = float(time.time())
        with sqlite3.connect(DB_PATH) as conn:
            cur = conn.cursor()
            for c in list(candidates or []):
                try:
                    sym = str((c or {}).get('symbol') or '').upper().strip()
                    direction = str((c or {}).get('direction') or '').upper().strip()
                    if not sym or direction not in {'UP', 'DOWN'}:
                        continue
                    row = cur.execute(
                        "SELECT triggered_ts FROM bigmove_autotrade_triggers WHERE user_id=? AND symbol=? AND direction=?",
                        (owner, sym, direction),
                    ).fetchone()
                    if row and cooldown > 0 and (now_ts - float(row[0] or 0.0)) < float(cooldown):
                        continue
                    cur.execute(
                        "INSERT OR REPLACE INTO bigmove_autotrade_triggers(user_id, symbol, direction, triggered_ts, note) VALUES(?,?,?,?,?)",
                        (owner, sym, direction, now_ts, 'claimed_for_owner_autotrade'),
                    )
                    out.append(c)
                except Exception:
                    continue
            conn.commit()
    except Exception:
        return list(candidates or [])
    return out


# Big-move email confirmation gate:
# 1) first scan that meets 15m/1H/4H same-direction criteria records a pending trigger;
# 2) only the NEXT closed 15m candle can release the email;
# 3) if that next 15m candle is not in the same direction, the pending trigger is cancelled.
BIGMOVE_CONFIRM_NEXT_15M_ENABLED = True  # Admin rule: big-move email only after next closed 15m candle confirms direction
BIGMOVE_PENDING_TTL_SEC = int(os.environ.get("BIGMOVE_PENDING_TTL_SEC", str(3 * 60 * 60)) or (3 * 60 * 60))


def _bigmove_pending_migrate() -> None:
    try:
        with sqlite3.connect(DB_PATH) as conn:
            cur = conn.cursor()
            cur.execute("""
                CREATE TABLE IF NOT EXISTS pending_bigmoves (
                    user_id INTEGER NOT NULL,
                    symbol TEXT NOT NULL,
                    direction TEXT NOT NULL,
                    trigger_ts REAL NOT NULL DEFAULT 0,
                    trigger_candle_ts REAL NOT NULL DEFAULT 0,
                    p15 REAL NOT NULL DEFAULT 0,
                    p1 REAL NOT NULL DEFAULT 0,
                    p4 REAL NOT NULL DEFAULT 0,
                    min_vol_usd REAL NOT NULL DEFAULT 0,
                    ch15 REAL NOT NULL DEFAULT 0,
                    ch1 REAL NOT NULL DEFAULT 0,
                    ch4 REAL NOT NULL DEFAULT 0,
                    vol REAL NOT NULL DEFAULT 0,
                    status TEXT NOT NULL DEFAULT 'PENDING',
                    note TEXT NOT NULL DEFAULT '',
                    updated_ts REAL NOT NULL DEFAULT 0,
                    PRIMARY KEY(user_id, symbol, direction)
                )
            """)
            conn.commit()
    except Exception:
        pass


def _bigmove_pending_get(uid: int, symbol: str, direction: str) -> dict | None:
    _bigmove_pending_migrate()
    try:
        with sqlite3.connect(DB_PATH) as conn:
            conn.row_factory = sqlite3.Row
            cur = conn.cursor()
            row = cur.execute(
                "SELECT * FROM pending_bigmoves WHERE user_id=? AND symbol=? AND direction=? AND status='PENDING'",
                (int(uid), str(symbol).upper().strip(), str(direction).upper().strip()),
            ).fetchone()
            return dict(row) if row else None
    except Exception:
        return None


def _bigmove_pending_list(uid: int | None = None) -> list[dict]:
    _bigmove_pending_migrate()
    try:
        with sqlite3.connect(DB_PATH) as conn:
            conn.row_factory = sqlite3.Row
            cur = conn.cursor()
            if uid is None:
                rows = cur.execute(
                    "SELECT * FROM pending_bigmoves WHERE status='PENDING' ORDER BY trigger_ts ASC LIMIT 100"
                ).fetchall() or []
            else:
                rows = cur.execute(
                    "SELECT * FROM pending_bigmoves WHERE user_id=? AND status='PENDING' ORDER BY trigger_ts ASC LIMIT 100",
                    (int(uid),),
                ).fetchall() or []
            return [dict(r) for r in rows]
    except Exception:
        return []


def _bigmove_pending_upsert(uid: int, c: dict, p15: float, p1: float, p4: float, min_vol: float, trigger_candle_ts: float) -> None:
    _bigmove_pending_migrate()
    try:
        with sqlite3.connect(DB_PATH) as conn:
            cur = conn.cursor()
            cur.execute(
                """INSERT OR REPLACE INTO pending_bigmoves(
                    user_id, symbol, direction, trigger_ts, trigger_candle_ts,
                    p15, p1, p4, min_vol_usd, ch15, ch1, ch4, vol, status, note, updated_ts
                ) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)""",
                (
                    int(uid),
                    str(c.get('symbol') or '').upper().strip(),
                    str(c.get('direction') or '').upper().strip(),
                    float(time.time()),
                    float(trigger_candle_ts or 0.0),
                    float(p15 or 0.0), float(p1 or 0.0), float(p4 or 0.0), float(min_vol or 0.0),
                    float(c.get('ch15') or 0.0), float(c.get('ch1') or 0.0), float(c.get('ch4') or 0.0), float(c.get('vol') or 0.0),
                    'PENDING',
                    'waiting_for_next_15m_confirmation',
                    float(time.time()),
                ),
            )
            conn.commit()
    except Exception:
        pass


def _bigmove_pending_close(uid: int, symbol: str, direction: str, status: str, note: str = '') -> None:
    _bigmove_pending_migrate()
    try:
        with sqlite3.connect(DB_PATH) as conn:
            cur = conn.cursor()
            cur.execute(
                "UPDATE pending_bigmoves SET status=?, note=?, updated_ts=? WHERE user_id=? AND symbol=? AND direction=?",
                (str(status or '').upper().strip(), str(note or '')[:500], float(time.time()), int(uid), str(symbol).upper().strip(), str(direction).upper().strip()),
            )
            conn.commit()
    except Exception:
        pass


def _bigmove_prune_pending(uid: int | None = None) -> None:
    _bigmove_pending_migrate()
    try:
        cutoff = float(time.time()) - float(max(900, BIGMOVE_PENDING_TTL_SEC))
        with sqlite3.connect(DB_PATH) as conn:
            cur = conn.cursor()
            if uid is None:
                cur.execute("UPDATE pending_bigmoves SET status='EXPIRED', note='pending_ttl_expired', updated_ts=? WHERE status='PENDING' AND trigger_ts<?", (float(time.time()), cutoff))
            else:
                cur.execute("UPDATE pending_bigmoves SET status='EXPIRED', note='pending_ttl_expired', updated_ts=? WHERE user_id=? AND status='PENDING' AND trigger_ts<?", (float(time.time()), int(uid), cutoff))
            conn.commit()
    except Exception:
        pass


def _bigmove_last_closed_15m_candle(symbol: str, allow_cold: bool | None = None) -> dict | None:
    """Return the latest fully closed 15m candle for a Bybit/ccxt symbol.

    Bybit/CCXT may include the currently forming candle as the last row, so we choose
    the most recent candle whose open timestamp is at least 15 minutes behind now.
    The result is cached briefly because Big-Move confirmation may check the same
    staged symbols across consecutive email ticks and /email_decision calls.
    """
    try:
        sym = str(symbol or '').strip()
        if not sym:
            return None
        # Accept both base (TAO) and market symbol (TAO/USDT:USDT).
        if '/' not in sym and ':' not in sym:
            sym = f"{sym}/USDT:USDT"
        cache_key = f"bigmove:last_closed_15m:{sym}"
        try:
            if cache_valid(cache_key, int(BIGMOVE_LAST_CLOSED_15M_CACHE_TTL_SEC or 90)):
                cached = cache_get(cache_key)
                if isinstance(cached, dict) and cached.get('ts'):
                    return dict(cached)
        except Exception:
            pass
        if allow_cold is None:
            allow_cold = bool(BIGMOVE_ALLOW_COLD_CONFIRM_FETCH)
        rows = _ohlcv_cached_or_optional_fetch(sym, "15m", 4, allow_cold=bool(allow_cold))
        if not rows:
            return None
        now_ms = int(time.time() * 1000)
        tf_ms = 15 * 60 * 1000
        closed = []
        for r in rows:
            try:
                ts = int(float(r[0]))
                if ts + tf_ms <= now_ms - 5_000:
                    closed.append(r)
            except Exception:
                continue
        if not closed:
            closed = rows[:-1] if len(rows) >= 2 else rows
        if not closed:
            return None
        r = closed[-1]
        ts = int(float(r[0])); o = float(r[1]); c = float(r[4])
        pct = ((c - o) / o * 100.0) if o else 0.0
        out = {"ts": float(ts / 1000.0), "open": o, "close": c, "pct": float(pct)}
        try:
            cache_set(cache_key, dict(out))
        except Exception:
            pass
        return out
    except Exception:
        return None


def _bigmove_confirm_next_15m_for_user(uid: int, candidates: list, p15: float, p1: float, p4: float, min_vol: float) -> tuple[list, dict]:
    """Gate big-move alert candidates on the next closed 15m candle.

    First-time criteria hits are staged. On a later scan, the pending trigger is confirmed
    from the next fully closed 15m candle even if the symbol has dropped out of the raw
    current candidate list; the original criteria already passed when the pending row was
    created. This prevents missing alerts solely because the confirmation candle changed
    the rolling 15m/1h/4h metrics.
    """
    stats = {
        "pending_new": 0, "pending_wait": 0, "confirmed": 0, "cancelled": 0,
        "no_candle": 0, "cooldown": 0, "pending_checked": 0,
        "confirm_limited": 0, "cold_confirm_budget": int(BIGMOVE_CONFIRM_COLD_FETCH_MAX or 0),
    }
    if not BIGMOVE_CONFIRM_NEXT_15M_ENABLED:
        return list(candidates or []), stats
    _bigmove_prune_pending(int(uid))
    confirmed = []
    seen: set[tuple[str, str]] = set()
    cold_confirm_used = 0

    def _allow_confirm_cold_fetch() -> bool:
        nonlocal cold_confirm_used
        try:
            if not bool(BIGMOVE_ALLOW_COLD_CONFIRM_FETCH):
                return False
            if _ohlcv_timeframe_cooling("15m"):
                return False
            max_cold = max(0, int(BIGMOVE_CONFIRM_COLD_FETCH_MAX or 0))
            if cold_confirm_used >= max_cold:
                return False
            cold_confirm_used += 1
            return True
        except Exception:
            return False

    def _confirm_pending_row(row: dict, current_candidate: dict | None = None) -> None:
        try:
            sym = str((row or {}).get('symbol') or (current_candidate or {}).get('symbol') or '').upper().strip()
            direction = str((row or {}).get('direction') or (current_candidate or {}).get('direction') or '').upper().strip()
            if not sym or direction not in {'UP', 'DOWN'}:
                return
            if bigmove_recently_emailed(int(uid), sym, direction):
                stats['cooldown'] += 1
                return
            candle = _bigmove_last_closed_15m_candle(sym, allow_cold=_allow_confirm_cold_fetch())
            if not candle:
                stats['no_candle'] += 1
                return
            candle_ts = float(candle.get('ts') or 0.0)
            trigger_candle_ts = float((row or {}).get('trigger_candle_ts') or 0.0)
            if candle_ts <= trigger_candle_ts + 1:
                stats['pending_wait'] += 1
                return
            pct = float(candle.get('pct') or 0.0)
            same_direction = (pct > 0.0) if direction == 'UP' else (pct < 0.0)
            if same_direction:
                cc = dict(current_candidate or {})
                cc.setdefault('symbol', sym)
                cc.setdefault('direction', direction)
                cc.setdefault('ch15', float((row or {}).get('ch15') or 0.0))
                cc.setdefault('ch1', float((row or {}).get('ch1') or 0.0))
                cc.setdefault('ch4', float((row or {}).get('ch4') or 0.0))
                cc.setdefault('vol', float((row or {}).get('vol') or 0.0))
                cc['confirm_15m_pct'] = pct
                cc['confirm_15m_ts'] = candle_ts
                confirmed.append(cc)
                _bigmove_pending_close(int(uid), sym, direction, 'CONFIRMED', f'next_15m_same_direction:{pct:+.2f}%')
                stats['confirmed'] += 1
            else:
                _bigmove_pending_close(int(uid), sym, direction, 'CANCELLED', f'next_15m_failed:{pct:+.2f}%')
                stats['cancelled'] += 1
        except Exception:
            return

    # Stage or confirm current raw candidates. Keep this bounded so a single
    # user alert cannot check dozens of candles and time out the email loop.
    try:
        _max_cur = max(1, int(BIGMOVE_CONFIRM_MAX_CANDIDATES or 6))
    except Exception:
        _max_cur = 6
    _current_candidates = list(candidates or [])
    if len(_current_candidates) > _max_cur:
        stats['confirm_limited'] += int(len(_current_candidates) - _max_cur)
        _current_candidates = _current_candidates[:_max_cur]
    for c in _current_candidates:
        try:
            sym = str(c.get('symbol') or '').upper().strip()
            direction = str(c.get('direction') or '').upper().strip()
            if not sym or direction not in {'UP', 'DOWN'}:
                continue
            seen.add((sym, direction))
            if bigmove_recently_emailed(int(uid), sym, direction):
                stats['cooldown'] += 1
                continue
            candle = _bigmove_last_closed_15m_candle(sym, allow_cold=_allow_confirm_cold_fetch())
            if not candle:
                stats['no_candle'] += 1
                continue
            candle_ts = float(candle.get('ts') or 0.0)
            pending = _bigmove_pending_get(int(uid), sym, direction)
            if not pending:
                _bigmove_pending_upsert(int(uid), c, p15, p1, p4, min_vol, candle_ts)
                stats['pending_new'] += 1
                continue
            _confirm_pending_row(pending, c)
        except Exception:
            continue

    # Confirm already-staged symbols even if they are no longer in this scan's raw candidate list.
    try:
        _pending_rows = _bigmove_pending_list(int(uid))
        try:
            _max_pending = max(0, int(BIGMOVE_CONFIRM_MAX_PENDING or 12))
        except Exception:
            _max_pending = 12
        if _max_pending > 0 and len(_pending_rows) > _max_pending:
            stats['confirm_limited'] += int(len(_pending_rows) - _max_pending)
            _pending_rows = _pending_rows[:_max_pending]
        for row in _pending_rows:
            try:
                sym = str((row or {}).get('symbol') or '').upper().strip()
                direction = str((row or {}).get('direction') or '').upper().strip()
                key = (sym, direction)
                if key in seen:
                    continue
                stats['pending_checked'] += 1
                _confirm_pending_row(row, None)
            except Exception:
                continue
    except Exception:
        pass

    return confirmed, stats

def _user_bigmove_thresholds(user: dict | None) -> tuple[float, float, float]:
    """Return (15m, 1h, 4h) thresholds for big-move alerts."""
    try:
        u = dict(user or {})
    except Exception:
        u = {}

    def _pick(key: str, default: float) -> float:
        try:
            raw = u.get(key, None)
            if raw in (None, ""):
                return float(default)
            val = float(raw or 0.0)
            return float(val if val > 0 else default)
        except Exception:
            return float(default)

    p15 = _pick("bigmove_alert_15m", BIGMOVE_DEFAULT_15M_PCT)
    p1 = _pick("bigmove_alert_1h", BIGMOVE_DEFAULT_1H_PCT)
    p4 = _pick("bigmove_alert_4h", BIGMOVE_DEFAULT_4H_PCT)
    return float(p15), float(p1), float(p4)


def _user_bigmove_min_vol_usd(user: dict | None, default: float = BIGMOVE_DEFAULT_MIN_VOL_USD) -> float:
    """Resolve big-move min volume with backward-compatible fallback.

    Commercial floor: keep big-move alerts at or above 10M 24h volume unless a
    future code change intentionally introduces a lower supported floor.
    """
    floor = float(BIGMOVE_MIN_SUPPORTED_VOL_USD)
    try:
        u = dict(user or {})
    except Exception:
        u = {}
    for key in ("bigmove_min_vol_usd", "bigmove_min_usd"):
        try:
            raw = u.get(key, None)
            if raw in (None, ""):
                continue
            val = float(raw or 0.0)
            if val > 0:
                if abs(val - 15_000_000.0) < 1e-6 or abs(val - 18_000_000.0) < 1e-6:
                    return float(floor)
                return float(max(floor, val))
        except Exception:
            continue
    try:
        return float(max(floor, float(default or floor)))
    except Exception:
        return float(floor)


def _record_bigmove_settings_change(uid: int, on: bool, p15: float, p1: float, p4: float, min_vol: float, reason: str) -> None:
    ts_now = float(time.time())
    try:
        min_vol = max(float(min_vol or 0.0), float(BIGMOVE_MIN_SUPPORTED_VOL_USD))
    except Exception:
        min_vol = float(BIGMOVE_MIN_SUPPORTED_VOL_USD)
    try:
        update_user(
            int(uid),
            bigmove_alert_on=(1 if on else 0),
            bigmove_alert_15m=float(p15),
            bigmove_alert_4h=float(p4),
            bigmove_alert_1h=float(p1),
            bigmove_min_vol_usd=float(min_vol),
            bigmove_alert_updated_ts=ts_now,
            bigmove_alert_update_reason=str(reason or '').strip(),
        )
    except Exception:
        try:
            update_user(
                int(uid),
                bigmove_alert_on=(1 if on else 0),
                bigmove_alert_15m=float(p15),
                bigmove_alert_4h=float(p4),
                bigmove_alert_1h=float(p1),
                bigmove_alert_updated_ts=ts_now,
                bigmove_alert_update_reason=str(reason or '').strip(),
            )
        except Exception:
            pass

