def _bigmove_candidates(best_fut: dict, p15: float, p1: float, p4: float, min_vol_usd: float = 0.0, max_items: int = 12) -> list:
    """
    Returns list of dicts: {symbol, ch15, ch1, ch4, vol, direction, score}

    direction:
      - "UP"   → strong positive move
      - "DOWN" → strong negative move

    Triggers:
      - UP   if ch15 >= +p15 AND ch1 >= +p1 AND ch4 >= +p4
      - DOWN if ch15 <= -p15 AND ch1 <= -p1 AND ch4 <= -p4
      - all three timeframes must point in the same direction
    """

    def _pick_pct(mv, keys) -> float:
        for k in keys:
            try:
                v = getattr(mv, k, None)
                if v is None:
                    continue
                return float(v or 0.0)
            except Exception:
                continue
        return 0.0

    out = []

    # Production safety: Big-Move requires 15m + 1h + 4h context, but the raw
    # ticker universe can contain hundreds of symbols. Pre-filter by 24h volume
    # and rank by 24h movement before any optional OHLCV fallback so one alert
    # cycle cannot create a Bybit cold-fetch storm.
    try:
        ranked_items = []
        for sym0, mv0 in (best_fut or {}).items():
            try:
                vol0 = float(usd_notional(mv0) or 0.0)
            except Exception:
                vol0 = 0.0
            if float(min_vol_usd or 0.0) > 0 and vol0 < float(min_vol_usd):
                continue
            try:
                pct24 = abs(float(getattr(mv0, "percentage", 0.0) or 0.0))
            except Exception:
                pct24 = 0.0
            ranked_items.append((pct24, vol0, str(sym0 or "").upper(), mv0))
        # Big-Move is independent of the setup pool and scans only top-volume symbols.
        ranked_items.sort(key=lambda x: x[1], reverse=True)
        scan_limit = min(len(ranked_items), max(1, int(BIGMOVE_SYMBOL_LIMIT or 30)))
        items_iter = [(sym0, mv0) for _pct24, _vol0, sym0, mv0 in ranked_items[:scan_limit]]
    except Exception:
        items_iter = list((best_fut or {}).items())[:max(1, int(BIGMOVE_SYMBOL_LIMIT or 30))]

    fallback_symbols_checked = 0
    try:
        fallback_symbol_budget = max(0, int(os.getenv("BIGMOVE_OHLCV_FALLBACK_MAX_SYMBOLS", str(BIGMOVE_SYMBOL_LIMIT)) or BIGMOVE_SYMBOL_LIMIT))
    except Exception:
        fallback_symbol_budget = max(0, int(BIGMOVE_SYMBOL_LIMIT or 30))

    for sym, mv in items_iter:
        try:
            # Try multiple possible field names (fixes "different field names" issue)
            ch4 = _pick_pct(mv, ["ch4", "pct_4h", "change_4h", "chg_4h", "percentage_4h", "p4", "h4"])
            ch1 = _pick_pct(mv, ["ch1", "pct_1h", "change_1h", "chg_1h", "percentage_1h", "p1", "h1"])
            ch15 = _pick_pct(mv, ["ch15", "pct_15m", "change_15m", "chg_15m", "percentage_15m", "p15", "m15"])

            # ✅ FIX: correct 24H USD volume (MarketVol does NOT have fut_vol_usd)
            vol = float(usd_notional(mv) or 0.0)

            # If still missing, compute from candles for only a tiny ranked subset.
            # Without this cap, a cold Render instance can spend the whole 35s+ payload
            # timeout checking candles for every high-volume symbol.
            need_fallback = (abs(ch15) < 1e-9) or (abs(ch4) < 1e-9) or (abs(ch1) < 1e-9)
            allow_symbol_fallback = bool(
                need_fallback
                and getattr(mv, "symbol", None)
                and bool(BIGMOVE_ALLOW_COLD_OHLCV_FALLBACK)
                and fallback_symbols_checked < fallback_symbol_budget
                and not _ohlcv_timeframe_cooling("15m", "1h")
            )
            if allow_symbol_fallback:
                fallback_symbols_checked += 1
                try:
                    if abs(ch15) < 1e-9:
                        c15 = _ohlcv_cached_or_optional_fetch(mv.symbol, "15m", 4, allow_cold=True)
                        if c15 and len(c15) >= 2:
                            c15_last = float(c15[-1][4])
                            c15_prev = float(c15[-2][4])
                            ch15 = ((c15_last - c15_prev) / c15_prev) * 100.0 if c15_prev else 0.0
                except Exception:
                    pass
                try:
                    if abs(ch4) < 1e-9 or abs(ch1) < 1e-9:
                        c1 = _ohlcv_cached_or_optional_fetch(mv.symbol, "1h", 6, allow_cold=True)
                        if c1 and len(c1) >= 2:
                            closes_1h = [float(x[4]) for x in c1]
                            c_last = closes_1h[-1]
                            c_prev1 = closes_1h[-2]
                            c_prev4 = closes_1h[-5] if len(closes_1h) >= 5 else closes_1h[0]
                            if abs(ch1) < 1e-9:
                                ch1 = ((c_last - c_prev1) / c_prev1) * 100.0 if c_prev1 else 0.0
                            if abs(ch4) < 1e-9:
                                ch4 = ((c_last - c_prev4) / c_prev4) * 100.0 if c_prev4 else 0.0
                except Exception:
                    pass

        except Exception:
            continue

        # FIX5: warm-up proxy for Big-Move alert emails. Some Bybit ticker payloads do not
        # expose 15m/1h/4h change fields and cold OHLCV can be unavailable for the first cycles.
        # If the symbol is a genuine high-volume 24h mover, fill only missing timeframe values
        # with conservative same-direction proxies so Big-Move does not stay permanently at
        # debug_raw_hits:15m=0,1h=0,4h=0 during startup/cache hydration.
        try:
            pct24_now = float(getattr(mv, 'percentage', 0.0) or 0.0)
            sign = 1.0 if pct24_now >= 0 else -1.0
            if abs(pct24_now) >= max(float(p4) * 2.0, 10.0) and float(vol or 0.0) >= float(min_vol_usd or 0.0):
                if abs(float(ch4 or 0.0)) < 1e-9:
                    ch4 = sign * max(float(p4) + 0.10, min(abs(pct24_now) * 0.38, float(p4) * 1.60))
                if abs(float(ch1 or 0.0)) < 1e-9:
                    ch1 = sign * max(float(p1) + 0.10, min(abs(pct24_now) * 0.20, float(p1) * 1.50))
                if abs(float(ch15 or 0.0)) < 1e-9:
                    ch15 = sign * max(float(p15) + 0.05, min(abs(pct24_now) * 0.08, float(p15) * 1.40))
        except Exception:
            pass

        same_up = (ch15 > 0 and ch1 > 0 and ch4 > 0)
        same_down = (ch15 < 0 and ch1 < 0 and ch4 < 0)
        if not (same_up or same_down):
            continue

        up_hit = same_up and (ch15 >= float(p15)) and (ch1 >= float(p1)) and (ch4 >= float(p4))
        down_hit = same_down and (ch15 <= -float(p15)) and (ch1 <= -float(p1)) and (ch4 <= -float(p4))

        if not (up_hit or down_hit):
            continue

        # ✅ NEW: volume gate (skip low-volume coins completely)
        if float(min_vol_usd or 0.0) > 0.0 and vol < float(min_vol_usd):
            continue

        if down_hit and not up_hit:
            direction = "DOWN"
        elif up_hit and not down_hit:
            direction = "UP"
        else:
            direction = "UP" if ch1 >= 0 else "DOWN"

        score_up = max(
            (abs(ch4) / max(p4, 1e-9)) if ch4 > 0 else 0.0,
            (abs(ch1) / max(p1, 1e-9)) if ch1 > 0 else 0.0,
            (abs(ch15) / max(p15, 1e-9)) if ch15 > 0 else 0.0,
        )
        score_dn = max(
            (abs(ch4) / max(p4, 1e-9)) if ch4 < 0 else 0.0,
            (abs(ch1) / max(p1, 1e-9)) if ch1 < 0 else 0.0,
            (abs(ch15) / max(p15, 1e-9)) if ch15 < 0 else 0.0,
        )
        score = max(score_up, score_dn)

        out.append({
            "symbol": sym,
            "ch15": ch15,
            "ch4": ch4,
            "ch1": ch1,
            "vol": vol,
            "direction": direction,
            "score": score,
        })

    out.sort(key=lambda x: (x["score"], x["vol"]), reverse=True)
    return out[:max_items]



def _bigmove_autotrade_session_name(now_utc: Optional[datetime] = None) -> str:
    """Session label for immediate Big-Move AutoTrade.

    Big-Move alert emails are not tied to the normal setup-email session pool, but
    the central AutoTrade execution function requires ASIA/LON/NY for its risk and
    cooldown rules. Use the live session when available and the scan bucket during
    the small session gap.
    """
    try:
        live = str(current_session_utc(now_utc or datetime.now(timezone.utc)) or '').upper().strip()
        if live in {'ASIA', 'LON', 'NY'}:
            return live
    except Exception:
        pass
    try:
        scan = str(scan_session_name_utc(now_utc or datetime.now(timezone.utc)) or '').upper().strip()
        if scan in {'ASIA', 'LON', 'NY'}:
            return scan
    except Exception:
        pass
    return 'NY'


def _bigmove_candidate_marketvol(candidate: dict, best_fut: dict | None = None):
    try:
        sym = str((candidate or {}).get('symbol') or '').upper().strip()
        if not sym:
            return None
        best = best_fut or get_cached_futures_tickers() or {}
        mv = (best or {}).get(sym)
        if mv is not None:
            return mv
        # Fallback: loose match against base/name because some caches use BYBIT/ccxt forms.
        for _k, _mv in (best or {}).items():
            try:
                if str(_k or '').upper().strip() == sym:
                    return _mv
                if str(getattr(_mv, 'base', '') or '').upper().strip() == sym:
                    return _mv
            except Exception:
                continue
    except Exception:
        pass
    return None


def _bigmove_candidate_market_symbol(candidate: dict, best_fut: dict | None = None) -> str:
    try:
        mv = _bigmove_candidate_marketvol(candidate, best_fut)
        ms = str(getattr(mv, 'symbol', '') or '').strip()
        if ms:
            return ms
    except Exception:
        pass
    try:
        base = str((candidate or {}).get('symbol') or '').upper().strip()
        return f"{base}/USDT:USDT" if base else ''
    except Exception:
        return ''


def _bigmove_candidate_entry_price(candidate: dict, best_fut: dict | None = None) -> float:
    """Best immediate entry reference for a Big-Move alert candidate."""
    try:
        mv = _bigmove_candidate_marketvol(candidate, best_fut)
        for key in ('last', 'vwap', 'open'):
            try:
                px = float(getattr(mv, key, 0.0) or 0.0)
                if px > 0:
                    return px
            except Exception:
                continue
    except Exception:
        pass
    try:
        sym = str((candidate or {}).get('symbol') or '').upper().strip()
        px = _autotrade_live_reference_price(_bybit_linear_symbol(sym), fallback_entry=0.0)
        return float(px or 0.0)
    except Exception:
        return 0.0


def _bigmove_autotrade_atr_pct(candidate: dict, best_fut: dict | None = None) -> float:
    """15m ATR% used for the Big-Move AutoTrade stop distance."""
    try:
        market_symbol = _bigmove_candidate_market_symbol(candidate, best_fut)
        if not market_symbol:
            return 0.0
        limit = max(int(ATR_PERIOD) + 5, 80)
        rows = _ohlcv_cached_or_optional_fetch(
            market_symbol,
            str(BIGMOVE_AUTOTRADE_ATR_TIMEFRAME or '15m'),
            int(limit),
            allow_cold=bool(BIGMOVE_AUTOTRADE_ALLOW_COLD_OHLCV),
        )
        if not rows or len(rows) < int(ATR_PERIOD) + 1:
            return 0.0
        atr = float(compute_atr_from_ohlcv(rows, int(ATR_PERIOD)) or 0.0)
        close = float(rows[-1][4] or 0.0)
        if atr > 0 and close > 0:
            return float((atr / close) * 100.0)
    except Exception:
        pass
    return 0.0


def _bigmove_autotrade_price_plan(candidate: dict, best_fut: dict | None = None) -> dict:
    """Return entry/SL/TP plan for a confirmed Big-Move alert.

    Rules:
    - direction UP => BUY; DOWN => SELL
    - SL distance = clamp(2.2 × 15m ATR%, 3%, 10%)
    - TP distance = min(SL distance × 2R, 20%)
    - if ATR is unavailable, use the requested 10% SL / 20% TP fallback.
    """
    out = {
        'ok': False,
        'reason': 'not_computed',
        'side': '',
        'entry': 0.0,
        'sl': 0.0,
        'tp': 0.0,
        'sl_pct': 0.0,
        'tp_pct': 0.0,
        'rr': float(BIGMOVE_AUTOTRADE_RR),
        'atr_pct': 0.0,
        'sl_model': 'ATR_CAPPED',
    }
    try:
        direction = str((candidate or {}).get('direction') or '').upper().strip()
        side = 'BUY' if direction == 'UP' else 'SELL' if direction == 'DOWN' else ''
        entry = float(_bigmove_candidate_entry_price(candidate, best_fut) or 0.0)
        if side not in {'BUY', 'SELL'}:
            out['reason'] = 'bad_bigmove_direction'
            return out
        if entry <= 0:
            out['reason'] = 'entry_unavailable'
            return out

        atr_pct = float(_bigmove_autotrade_atr_pct(candidate, best_fut) or 0.0)
        if atr_pct > 0:
            sl_pct = max(float(BIGMOVE_AUTOTRADE_SL_MIN_PCT), min(float(BIGMOVE_AUTOTRADE_SL_MAX_PCT), atr_pct * float(BIGMOVE_AUTOTRADE_ATR_MULT)))
            sl_model = f"{BIGMOVE_AUTOTRADE_ATR_TIMEFRAME}_ATRx{float(BIGMOVE_AUTOTRADE_ATR_MULT):g}_clamped"
        else:
            sl_pct = float(BIGMOVE_AUTOTRADE_SL_MAX_PCT)
            sl_model = 'fallback_fixed_10pct'

        rr = max(1.0, float(BIGMOVE_AUTOTRADE_RR or 2.0))
        tp_pct = min(float(BIGMOVE_AUTOTRADE_TP_MAX_PCT), float(sl_pct) * rr)
        if side == 'BUY':
            sl = entry * (1.0 - sl_pct / 100.0)
            tp = entry * (1.0 + tp_pct / 100.0)
        else:
            sl = entry * (1.0 + sl_pct / 100.0)
            tp = entry * (1.0 - tp_pct / 100.0)
        if sl <= 0 or tp <= 0:
            out['reason'] = 'bad_sl_tp'
            return out
        out.update({
            'ok': True,
            'reason': 'ok',
            'side': side,
            'entry': float(entry),
            'sl': float(sl),
            'tp': float(tp),
            'sl_pct': float(sl_pct),
            'tp_pct': float(tp_pct),
            'rr': float(rr_to_tp(entry, sl, tp) or rr),
            'atr_pct': float(atr_pct),
            'sl_model': sl_model,
        })
        return out
    except Exception as exc:
        out['reason'] = f'{type(exc).__name__}: {exc}'
        return out


def _bigmove_candidate_to_autotrade_setup(candidate: dict, best_fut: dict | None = None, session_name: str = '') -> Optional[Setup]:
    """Convert a confirmed Big-Move email row into a single-TP executable Setup.

    This conversion is used for BOTH /screen/executable audit visibility and live
    AutoTrade. Therefore it must not be disabled when a user temporarily turns
    BigMove AutoTrade off; the alert still needs a real setup row.
    """
    try:
        c = dict(candidate or {})
        sym = str(c.get('symbol') or '').upper().strip()
        if not sym:
            return None
        plan = _bigmove_autotrade_price_plan(c, best_fut)
        if not bool(plan.get('ok')):
            return None
        mv = _bigmove_candidate_marketvol(c, best_fut)
        fut_vol = float(c.get('vol') or (usd_notional(mv) if mv is not None else 0.0) or 0.0)
        ch15 = float(c.get('confirm_15m_pct', c.get('ch15', 0.0)) or 0.0)
        ch1 = float(c.get('ch1', 0.0) or 0.0)
        ch4 = float(c.get('ch4', 0.0) or 0.0)
        ch24 = float(getattr(mv, 'percentage', 0.0) or 0.0) if mv is not None else 0.0
        side = str(plan.get('side') or '').upper().strip()
        conf = _bigmove_signal_confidence(side, ch24, ch4, ch1, ch15, fut_vol, 0.0)
        conf = int(clamp(max(float(conf), 82.0), 68.0, 96.0))
        setup_id = f"BMAT-{sym}-{side}-{int(time.time())}-{uuid.uuid4().hex[:6]}"
        market_symbol = _bigmove_candidate_market_symbol(c, best_fut)
        s = Setup(
            setup_id=setup_id,
            symbol=sym,
            market_symbol=market_symbol,
            side=side,
            conf=int(conf),
            entry=float(plan.get('entry') or 0.0),
            sl=float(plan.get('sl') or 0.0),
            tp=float(plan.get('tp') or 0.0),
            alt_target_a=0.0,
            alt_target_b=0.0,
            fut_vol_usd=float(fut_vol),
            ch24=float(ch24),
            ch4=float(ch4),
            ch1=float(ch1),
            ch15=float(ch15),
            ema_support_period=0,
            ema_support_dist_pct=0.0,
            pullback_ema_period=0,
            pullback_ema_dist_pct=0.0,
            pullback_ready=True,
            pullback_bypass_hot=True,
            leader_base_override=True,
            engine='F8',  # Big-Move family; quality_score=0 keeps DB structural gate simple.
            is_trailing_alt_target_b=False,
            created_ts=float(time.time()),
            family_id=BIGMOVE_FAMILY_ID,
            family_name=BIGMOVE_FAMILY_NAME,
            session=str(session_name or '').upper().strip(),
        )

        # yver127: BigMove/F8 candidates must pass through the same NOR→REV
        # router BEFORE becoming an emailed/executable delivery lane.  Previously
        # a raw disabled F8-ASIA-NOR-SELL could be emailed and then AutoTrade
        # correctly skipped it as final_combo_disabled, while /setup_audit showed
        # the routed F8-ASIA-REV-BUY.  Route first, then lock the delivered lane.
        try:
            owner_for_policy = int(globals().get('AUTOTRADE_OWNER_UID', 0) or 0)
        except Exception:
            owner_for_policy = 0
        try:
            s = _setup_route_candidate_for_executable_lane(s, session_name=session_name, user_id=owner_for_policy)
        except Exception:
            pass

        setattr(s, 'atr_pct', float(plan.get('atr_pct') or 0.0))
        setattr(s, 'quality_score', 0.0)
        setattr(s, 'source_kind', 'emailed_setups')
        setattr(s, 'source_session', str(session_name or '').upper().strip())
        setattr(s, 'delivery_lane_locked', True)
        setattr(s, 'email_logged_ts', float(time.time()))
        setattr(s, 'emailed_ts', float(time.time()))
        setattr(s, 'bigmove_signal', True)
        setattr(s, 'bigmove_alert_autotrade', True)
        setattr(s, 'bigmove_direction', str(c.get('direction') or '').upper().strip())
        setattr(s, 'bigmove_sl_model', str(plan.get('sl_model') or ''))
        setattr(s, 'bigmove_sl_pct', float(plan.get('sl_pct') or 0.0))
        setattr(s, 'bigmove_tp_pct', float(plan.get('tp_pct') or 0.0))
        setattr(s, 'bigmove_rr', float(plan.get('rr') or BIGMOVE_AUTOTRADE_RR))
        # No separate Big-Move risk setting: F8 must use the same /autotrade_config
        # AUTOTRADE_RISK_PER_TRADE_PCT, open cap, and daily cap as every other family.
        setattr(s, 'risk_source', 'autotrade_config')
        try:
            routed_side = str(getattr(s, 'side', '') or '').upper().strip()
            routed_strategy = str(_setup_strategy_label(s) or '').upper().strip()
            setattr(s, 'bigmove_routed_side', routed_side)
            setattr(s, 'bigmove_routed_strategy', routed_strategy)
        except Exception:
            routed_side, routed_strategy = str(side or '').upper().strip(), ''
        setattr(s, 'why', f"Confirmed Big-Move alert {str(c.get('direction') or '').upper()} | Routed {routed_strategy or 'NOR'} {routed_side or str(side).upper()} | SL {float(plan.get('sl_pct') or 0.0):.2f}% ({plan.get('sl_model')}) | TP {float(plan.get('tp_pct') or 0.0):.2f}% (~{float(plan.get('rr') or BIGMOVE_AUTOTRADE_RR):.2f}R)")
        return _research_finalize_setup(s, session_name=session_name)
    except Exception:
        return None


def _bigmove_candidates_to_autotrade_setups(candidates: list, best_fut: dict | None = None, session_name: str = '') -> list:
    out = []
    try:
        max_n = max(1, int(BIGMOVE_AUTOTRADE_MAX_ALERT_SETUPS or 1))
    except Exception:
        max_n = 8
    for c in list(candidates or [])[:max_n]:
        try:
            s = _bigmove_candidate_to_autotrade_setup(c, best_fut, session_name=session_name)
            if s is not None:
                out.append(s)
        except Exception:
            continue
    return out


async def _trigger_autotrade_after_bigmove_email_async(uid: int, session_name: str, candidates: list, best_fut: dict | None = None, tag: str = 'bigmove'):
    """Run immediate owner AutoTrade after a confirmed Big-Move email is sent.

    This deliberately reuses _autotrade_place_trade, the same execution/risk/SL/TP
    enforcement lane used by normal setup emails. The only Big-Move-specific part is
    converting the alert into a synthetic single-TP Setup with ATR-capped SL/TP.
    """
    try:
        owner_uid = int(AUTOTRADE_OWNER_UID or 0)
        caller_uid = int(uid or 0)
        sess = str(session_name or _bigmove_autotrade_session_name()).upper().strip()
        now_utc = datetime.now(timezone.utc)
        if owner_uid <= 0 or sess not in {'ASIA', 'LON', 'NY'}:
            return
        if not bool(BIGMOVE_AUTOTRADE_ENABLED):
            _LAST_AUTOTRADE_DECISION[owner_uid] = {
                'status': 'SKIP', 'when': now_utc.isoformat(timespec='seconds'),
                'reason': 'bigmove_autotrade_disabled', 'session': sess,
                'mode': str(_autotrade_runtime_mode()).lower(), 'trigger': 'bigmove_email_immediate',
            }
            return
        if not _autotrade_ready():
            _LAST_AUTOTRADE_DECISION[owner_uid] = {
                'status': 'SKIP', 'when': now_utc.isoformat(timespec='seconds'),
                'reason': 'autotrade_not_ready_or_disabled', 'session': sess,
                'mode': str(_autotrade_runtime_mode()).lower(), 'trigger': 'bigmove_email_immediate',
            }
            return
        # The confirmed Big-Move email is an authorized bot action. Route it to
        # AUTOTRADE_OWNER_UID even when the alert recipient uid differs from owner.
        if not _autotrade_allowed_session(sess):
            _LAST_AUTOTRADE_DECISION[owner_uid] = {
                'status': 'SKIP', 'when': now_utc.isoformat(timespec='seconds'),
                'reason': f'session_not_allowed ({sess})', 'session': sess,
                'mode': str(_autotrade_runtime_mode()).lower(), 'trigger': 'bigmove_email_immediate',
            }
            return
        try:
            user_owner = get_user(owner_uid) or {}
            if not trade_window_allows_now(user_owner):
                _LAST_AUTOTRADE_DECISION[owner_uid] = {
                    'status': 'SKIP', 'when': now_utc.isoformat(timespec='seconds'),
                    'reason': 'trade_window_block', 'session': sess,
                    'mode': str(_autotrade_runtime_mode()).lower(), 'trigger': 'bigmove_email_immediate',
                }
                return
        except Exception:
            pass
        # Do not silently skip a just-emailed BigMove setup because the scheduled
        # AutoTrade job is holding the lock for a few seconds. Wait briefly instead;
        # the setup is also persisted so the next scheduled run can pick it up.

        fresh_candidates = await to_thread_autotrade(_bigmove_autotrade_claim_candidates, owner_uid, list(candidates or []), timeout=5)
        if not fresh_candidates:
            _LAST_AUTOTRADE_DECISION[owner_uid] = {
                'status': 'SKIP', 'when': now_utc.isoformat(timespec='seconds'),
                'reason': 'bigmove_same_direction_cooldown_active', 'session': sess,
                'mode': str(_autotrade_runtime_mode()).lower(), 'trigger': 'bigmove_email_immediate',
            }
            return

        setup_list = await to_thread_autotrade(_bigmove_candidates_to_autotrade_setups, list(fresh_candidates or []), best_fut or {}, sess, timeout=8)
        if not setup_list:
            _LAST_AUTOTRADE_DECISION[owner_uid] = {
                'status': 'SKIP', 'when': now_utc.isoformat(timespec='seconds'),
                'reason': 'no_bigmove_autotrade_setups_built', 'session': sess,
                'mode': str(_autotrade_runtime_mode()).lower(), 'trigger': 'bigmove_email_immediate',
            }
            return

        async with AUTOTRADE_EXEC_LOCK:
            now_ts = float(time.time())
            for _s in list(setup_list or []):
                try:
                    setattr(_s, 'source_kind', 'emailed_setups')
                    setattr(_s, 'source_session', sess)
                    setattr(_s, 'delivery_lane_locked', True)
                    setattr(_s, 'email_logged_ts', now_ts)
                    setattr(_s, 'emailed_ts', now_ts)
                    setattr(_s, 'created_ts', float(getattr(_s, 'created_ts', 0.0) or now_ts))
                except Exception:
                    pass
            try:
                await to_thread_autotrade(_persist_executable_candidates, owner_uid, sess, list(setup_list or []), 'emailed_setups', 'bigmove_email_autotrade_immediate', timeout=6)
                try:
                    cache_delete(f"autotrade_db_setups_v129:{owner_uid}:{sess}:24:30")
                except Exception:
                    pass
            except Exception as e:
                try:
                    db_log_setup_pipeline_event(owner_uid, stage='bigmove_autotrade_persist', status='error', session=sess, mode='autotrade', details={'error': f'{type(e).__name__}: {e}'})
                except Exception:
                    pass

            attempted = 0
            placed = 0
            attempts_meta = []
            last_reason = 'no_bigmove_candidates_attempted'
            for cand in list(setup_list or [])[:max(1, int(BIGMOVE_AUTOTRADE_MAX_ALERT_SETUPS or 1))]:
                attempted += 1
                meta = {
                    'setup_id': str(getattr(cand, 'setup_id', '') or getattr(cand, 'id', '') or ''),
                    'symbol': str(getattr(cand, 'symbol', '') or ''),
                    'side': str(getattr(cand, 'side', '') or ''),
                    'source_kind': str(getattr(cand, 'source_kind', '') or ''),
                    'sl_pct': float(getattr(cand, 'bigmove_sl_pct', 0.0) or 0.0),
                    'tp_pct': float(getattr(cand, 'bigmove_tp_pct', 0.0) or 0.0),
                    'rr': float(getattr(cand, 'bigmove_rr', 0.0) or 0.0),
                    'sl_model': str(getattr(cand, 'bigmove_sl_model', '') or ''),
                }
                try:
                    ok, reason = await to_thread_autotrade(_autotrade_place_trade, owner_uid, sess, [cand], timeout=min(int(AUTOTRADE_JOB_TIMEOUT_SEC or 55), max(10, int(AUTOTRADE_JOB_TIMEOUT_SEC or 55))))
                except asyncio.TimeoutError:
                    _timeout_reason = 'autotrade_place_trade_timeout_after_bigmove_email'
                    try:
                        ok, reason = await to_thread_autotrade(_autotrade_timeout_reconcile, owner_uid, sess, cand, _timeout_reason, timeout=8)
                    except Exception:
                        ok, reason = False, _timeout_reason
                except Exception as e:
                    ok, reason = False, f'{type(e).__name__}: {e}'
                last_reason = '' if ok else str(reason or '')
                if ok:
                    placed += 1
                try:
                    detail_snapshot = dict(_LAST_AUTOTRADE_DETAIL.get(owner_uid) or {})
                    meta.update({
                        'status': 'PLACED' if ok else 'SKIP',
                        'reason': '' if ok else str(reason or ''),
                        'entry': detail_snapshot.get('entry') or getattr(cand, 'entry', ''),
                        'sl': detail_snapshot.get('sl') or getattr(cand, 'sl', ''),
                        'tp': detail_snapshot.get('live_exit_tp') or getattr(cand, 'tp', ''),
                        'entry_drift_pct': detail_snapshot.get('entry_drift_pct', ''),
                        'entry_drift_direction': detail_snapshot.get('entry_drift_direction', ''),
                        'entry_drift_adverse_pct': detail_snapshot.get('entry_drift_adverse_pct', ''),
                    })
                    _autotrade_record_attempt(owner_uid, meta, detail_snapshot, 'PLACED' if ok else 'SKIP', '' if ok else str(reason or ''))
                except Exception:
                    pass
                attempts_meta.append(meta)
                if not ok and not _autotrade_should_try_next_after_skip(reason):
                    break

            _LAST_AUTOTRADE_DECISION[owner_uid] = {
                'status': 'PLACED' if placed > 0 else 'SKIP',
                'when': datetime.now(timezone.utc).isoformat(timespec='seconds'),
                'reason': '' if placed > 0 else str(last_reason or 'no_tradable_bigmove_setup'),
                'attempted': int(attempted),
                'placed': int(placed),
                'session': sess,
                'mode': str(_autotrade_runtime_mode()).lower(),
                'attempted_candidates': attempts_meta,
                'latest_candidate': attempts_meta[0] if attempts_meta else {},
                'trigger': 'bigmove_email_immediate',
            }
            try:
                db_log_setup_pipeline_event(owner_uid, stage='bigmove_autotrade_after_email', status='placed' if placed > 0 else 'skip', session=sess, mode='autotrade', details={'reason': last_reason, 'attempted': attempted, 'placed': placed, 'tag': str(tag or ''), 'candidates': attempts_meta[:8]})
            except Exception:
                pass
    except Exception as e:
        try:
            owner_uid = int(AUTOTRADE_OWNER_UID or 0)
            if owner_uid:
                _LAST_AUTOTRADE_DECISION[owner_uid] = {
                    'status': 'ERROR', 'when': datetime.now(timezone.utc).isoformat(timespec='seconds'),
                    'reason': f'{type(e).__name__}: {e}', 'trigger': 'bigmove_email_immediate',
                }
        except Exception:
            pass

def _spike_reversal_candidates(
    best_fut: Dict[str, Any],
    min_vol_usd: float = 10_000_000.0,
    wick_ratio_min: float = 0.55,
    atr_mult_min: float = 1.20,
    max_items: int = 10,
) -> List[dict]:
    """
    Detects wick-spike rejection in the direction opposite to the spike, aligned with the bigger trend.
    Downtrend: upper-wick spike rejection -> SELL
    Uptrend: lower-wick spike rejection -> BUY
    """
    out: List[dict] = []
    if not best_fut:
        return out

    for base, mv in (best_fut or {}).items():
        try:
            sym_base = str(base).upper()
            market_symbol = str(getattr(mv, "symbol", "") or "")
            vol24 = float(getattr(mv, "fut_vol_usd", 0.0) or 0.0)
            if vol24 < float(min_vol_usd):
                continue
            if not market_symbol:
                continue

            # 1H candles for spike detection + ATR + trend
            c1 = fetch_ohlcv(market_symbol, "1h", limit=max(ATR_PERIOD + 10, 220))
            if not c1 or len(c1) < (ATR_PERIOD + 50):
                continue

            atr_1h = compute_atr_from_ohlcv(c1, ATR_PERIOD)
            if atr_1h <= 0:
                continue

            closes_1h = [float(x[4]) for x in c1]
            ema50 = float(ema(closes_1h[-200:], 50) or 0.0)
            ema200 = float(ema(closes_1h[-220:], 200) or 0.0)
            if ema50 <= 0 or ema200 <= 0:
                continue

            uptrend = (ema50 > ema200)
            downtrend = (ema50 < ema200)
            if not (uptrend or downtrend):
                continue

            # Spike candle = most recent closed 1H candle
            o = float(c1[-1][1]); h = float(c1[-1][2]); l = float(c1[-1][3]); c = float(c1[-1][4])
            rng = max(1e-12, h - l)

            upper_wick = h - max(o, c)
            lower_wick = min(o, c) - l
            upper_ratio = upper_wick / rng
            lower_ratio = lower_wick / rng

            big_range = (rng >= (atr_1h * float(atr_mult_min)))

            
            # 15m confirmation (stronger): last 15m close must confirm rejection
            # SELL: close below spike mid (and preferably below spike open)
            # BUY : close above spike mid (and preferably above spike open)
            c15 = fetch_ohlcv(market_symbol, "15m", limit=60)
            if not c15 or len(c15) < 12:
                continue
            c15_last_close = float(c15[-1][4])

            spike_mid = (h + l) / 2.0
            sell_confirm = (c15_last_close < spike_mid)
            buy_confirm  = (c15_last_close > spike_mid)

            # Downtrend: spike UP into resistance -> SELL reversal
            if downtrend and big_range and upper_ratio >= float(wick_ratio_min) and c < o:
                weak_confirm = (not sell_confirm)
                # allow weak confirmations with lower confidence

                entry = float(l)  # break of spike candle low
                sl = float(h) + (0.10 * atr_1h)
                r = max(1e-12, sl - entry)

                tp = entry - 1.0 * r
                alt_target_a = 0.0
                alt_target_b = 0.0

                conf = 82
                if weak_confirm:
                    conf -= 6
                if (c - l) / rng < 0.40:
                    conf += 4

                out.append({
                    "symbol": sym_base,
                    "market_symbol": market_symbol,
                    "side": "SELL",
                    "direction": "DOWN",
                    "conf": int(clamp(conf, 1, 99)),
                    "entry": float(entry),
                    "sl": float(sl),
                    "tp": float(tp),
                    "alt_target_a": float(alt_target_a),
                    "alt_target_b": float(alt_target_b),
                    "vol": float(vol24),
                    "why": f"Downtrend (EMA50<EMA200). 1H upper-wick spike rejection (wick={upper_ratio:.2f}, range={rng/atr_1h:.2f} ATR). " + ("15m confirm: WEAK" if weak_confirm else "15m confirm: OK"),
                })
                continue

            # Uptrend: spike DOWN into support -> BUY reversal
            if uptrend and big_range and lower_ratio >= float(wick_ratio_min) and c > o:
                weak_confirm = (not buy_confirm)
                # allow weak confirmations with lower confidence

                entry = float(h)  # break of spike candle high
                sl = float(l) - (0.10 * atr_1h)
                r = max(1e-12, entry - sl)

                tp = entry + 1.0 * r
                alt_target_a = 0.0
                alt_target_b = 0.0

                conf = 82
                if weak_confirm:
                    conf -= 6
                if (h - c) / rng < 0.40:
                    conf += 4

                out.append({
                    "symbol": sym_base,
                    "market_symbol": market_symbol,
                    "side": "BUY",
                    "direction": "UP",
                    "conf": int(clamp(conf, 1, 99)),
                    "entry": float(entry),
                    "sl": float(sl),
                    "tp": float(tp),
                    "alt_target_a": float(alt_target_a),
                    "alt_target_b": float(alt_target_b),
                    "vol": float(vol24),
                    "why": f"Uptrend (EMA50>EMA200). 1H lower-wick spike rejection (wick={lower_ratio:.2f}, range={rng/atr_1h:.2f} ATR). " + ("15m confirm: WEAK" if weak_confirm else "15m confirm: OK"),
                })
                continue

        except Exception:
            continue

    out = sorted(out, key=lambda x: (int(x.get("conf", 0)), float(x.get("vol", 0.0))), reverse=True)
    return out[:max_items]



def _spike_reversal_warnings(
    best_fut: Dict[str, Any],
    min_vol_usd: float = 10_000_000.0,
    atr_mult_min: float = 1.05,
    body_ratio_min: float = 0.50,
    lookback_1h: int = 8,
    retrace_min: float = 0.22,
    max_items: int = 8,
) -> List[dict]:
    """
    EARLY WARNING (non-trade):
    Flags possible reversal zones after a recent 1H impulse (spike) when price starts
    retracing and momentum cools, but BEFORE strict wick-rejection + 15m-confirm rules.

    Output dict: {symbol, side, conf, vol, why}
    """
    out: List[dict] = []
    if not best_fut:
        return out

    for base, mv in (best_fut or {}).items():
        try:
            sym_base = str(base).upper()
            market_symbol = str(getattr(mv, "symbol", "") or "")
            vol24 = float(getattr(mv, "fut_vol_usd", 0.0) or 0.0)
            if vol24 < float(min_vol_usd):
                continue
            if not market_symbol:
                continue

            c1 = fetch_ohlcv(market_symbol, "1h", limit=max(ATR_PERIOD + 10, 240))
            if not c1 or len(c1) < (ATR_PERIOD + 60):
                continue

            atr_1h = compute_atr_from_ohlcv(c1, ATR_PERIOD)
            if atr_1h <= 0:
                continue

            closes_1h = [float(x[4]) for x in c1]
            ema50 = float(ema(closes_1h[-200:], 50) or 0.0)
            ema200 = float(ema(closes_1h[-220:], 200) or 0.0)
            if ema50 <= 0 or ema200 <= 0:
                continue

            uptrend = (ema50 > ema200)
            downtrend = (ema50 < ema200)

            # find most recent impulse candle in lookback window
            imp = None
            for i in range(1, int(lookback_1h) + 1):
                o = float(c1[-i][1]); h = float(c1[-i][2]); l = float(c1[-i][3]); c = float(c1[-i][4])
                rng = max(1e-12, h - l)
                body = abs(c - o)
                if rng >= (atr_1h * float(atr_mult_min)) and (body / rng) >= float(body_ratio_min):
                    imp = (i, o, h, l, c, rng, body)
                    break
            if not imp:
                continue

            i, oI, hI, lI, cI, rngI, bodyI = imp
            impulse_up = (cI > oI)
            impulse_dn = (cI < oI)
            if not (impulse_up or impulse_dn):
                continue

            c0 = float(c1[-1][4])

            # momentum cooling on 1H closes (soft)
            cooling_dn = (float(c1[-1][4]) <= float(c1[-2][4]) <= float(c1[-3][4])) if len(c1) >= 3 else True
            cooling_up = (float(c1[-1][4]) >= float(c1[-2][4]) >= float(c1[-3][4])) if len(c1) >= 3 else True

            if impulse_up:
                retrace = (hI - c0) / max(1e-12, rngI)
                if retrace < float(retrace_min) or not cooling_dn:
                    continue
                trend_note = "Downtrend context. " if downtrend else ("Uptrend context. " if uptrend else "")
                conf = 72 + int(clamp(retrace * 20.0, 0, 15))
                out.append({
                    "symbol": sym_base,
                    "market_symbol": market_symbol,
                    "side": "SELL",
                    "conf": int(clamp(conf, 1, 99)),
                    "vol": float(vol24),
                    "why": f"{trend_note}Recent 1H impulse UP (range={rngI/atr_1h:.2f} ATR, body={bodyI/rngI:.2f}). Retrace={retrace:.2f}; cooling closes.",
                })
                continue

            if impulse_dn:
                retrace = (c0 - lI) / max(1e-12, rngI)
                if retrace < float(retrace_min) or not cooling_up:
                    continue
                trend_note = "Uptrend context. " if uptrend else ("Downtrend context. " if downtrend else "")
                conf = 72 + int(clamp(retrace * 20.0, 0, 15))
                out.append({
                    "symbol": sym_base,
                    "market_symbol": market_symbol,
                    "side": "BUY",
                    "conf": int(clamp(conf, 1, 99)),
                    "vol": float(vol24),
                    "why": f"{trend_note}Recent 1H impulse DOWN (range={rngI/atr_1h:.2f} ATR, body={bodyI/rngI:.2f}). Retrace={retrace:.2f}; cooling closes.",
                })
                continue

        except Exception:
            continue

    out = sorted(out, key=lambda x: (int(x.get("conf", 0)), float(x.get("vol", 0.0))), reverse=True)
    return out[:max_items]

def symbol_flip_guard_active(
    user_id: int,
    symbol: str,
    side: str,
    session_name: str,
) -> bool:
    """
    Blocks opposite-direction alerts for the same symbol only.

    Ver05: fixed 3-hour guard by default. It no longer shortens to NY=1h or
    LON=2h via session cooldowns. This protects against same-symbol whipsaw
    without blocking any other symbols.
    """
    if not FLIP_GUARD_ENABLED:
        return False

    try:
        cooldown_hours = max(0.0, float(FLIP_GUARD_HOURS or 3.0))
    except Exception:
        cooldown_hours = 3.0
    opposite = "SELL" if str(side).upper() == "BUY" else "BUY"

    con = db_connect()
    cur = con.cursor()
    cur.execute("""
        SELECT emailed_ts
        FROM emailed_symbols
        WHERE user_id=? AND symbol=? AND side=?
    """, (int(user_id), str(symbol).upper(), opposite))
    row = cur.fetchone()
    con.close()

    if not row:
        return False

    last_ts = float(row["emailed_ts"])
    try:
        if last_ts < float(_autotrade_cooldown_reset_ts() or 0.0):
            return False
    except Exception:
        pass
    return (time.time() - last_ts) < (cooldown_hours * 3600.0)


def list_cooldowns(user_id: int) -> List[dict]:
    """
    Returns list of cooldown stamps for user:
    [{symbol, side, session, emailed_ts}, ...]
    """
    con = db_connect()
    cur = con.cursor()
    cur.execute("""
        SELECT symbol, side, session, emailed_ts
        FROM emailed_symbols
        WHERE user_id=?
        ORDER BY emailed_ts DESC
    """, (int(user_id),))
    rows = cur.fetchall() or []
    con.close()
    return [dict(r) for r in rows]


def _fmt_dur(seconds: float) -> str:
    s = int(max(0, seconds))
    h = s // 3600
    m = (s % 3600) // 60
    if h <= 0:
        return f"{m}m"
    return f"{h}h {m}m"

def _email_daily_get(user_id: int, day_local: str) -> int:
    con = db_connect()
    cur = con.cursor()
    cur.execute("SELECT sent_count FROM email_daily WHERE user_id=? AND day_local=?", (user_id, day_local))
    row = cur.fetchone()
    if not row:
        cur.execute("INSERT INTO email_daily (user_id, day_local, sent_count) VALUES (?, ?, ?)", (user_id, day_local, 0))
        con.commit()
        con.close()
        return 0
    con.close()
    return int(row["sent_count"])

def _email_daily_inc(user_id: int, day_local: str, inc: int = 1):
    con = db_connect()
    cur = con.cursor()
    cur.execute("""
        INSERT INTO email_daily (user_id, day_local, sent_count)
        VALUES (?, ?, ?)
        ON CONFLICT(user_id, day_local) DO UPDATE SET sent_count = sent_count + excluded.sent_count
    """, (user_id, day_local, int(inc)))
    con.commit()
    con.close()

