def db_mark_emailed_setup(user_id: int, setup_id: str, session: str, emailed_ts: float):
    con = db_connect()
    cur = con.cursor()
    cur.execute(
        """INSERT OR REPLACE INTO emailed_setups (user_id, setup_id, session, emailed_ts)
           VALUES (?, ?, ?, ?)""",
        (int(user_id), str(setup_id).strip(), str(session or ""), float(emailed_ts)),
    )
    con.commit()
    con.close()
    try:
        _admin_setup_lifecycle_merge(
            int(user_id),
            str(setup_id).strip(),
            session=str(session or ''),
            emailed_ts=float(emailed_ts or 0.0),
            state='emailed',
            source_kind='emailed_setups',
        )
    except Exception:
        pass


_LAST_SETUP_PIPELINE_EVENT: Dict[str, dict] = {}


def _setup_pipeline_event_key(user_id: int | None = None, stage: str = '', session: str = '', mode: str = '') -> str:
    try:
        return f"{int(user_id or 0)}::{str(stage or '').strip().lower()}::{str(session or '').strip().upper()}::{str(mode or '').strip().lower()}"
    except Exception:
        return f"0::{str(stage or '').strip().lower()}::{str(session or '').strip().upper()}::{str(mode or '').strip().lower()}"


def db_log_setup_pipeline_event(user_id: int | None, stage: str, status: str, session: str = '', mode: str = '', setup_id: str = '', symbol: str = '', side: str = '', details: dict | None = None) -> None:
    payload = dict(details or {})
    ts = float(time.time())
    row = {
        'user_id': int(user_id or 0),
        'event_ts': ts,
        'stage': str(stage or ''),
        'status': str(status or ''),
        'session': str(session or ''),
        'mode': str(mode or ''),
        'setup_id': str(setup_id or ''),
        'symbol': str(symbol or ''),
        'side': str(side or ''),
        'details_json': json.dumps(payload, separators=(",", ":"), ensure_ascii=False, sort_keys=True),
    }
    try:
        _LAST_SETUP_PIPELINE_EVENT[_setup_pipeline_event_key(user_id, stage, session, mode)] = dict(row)
        _LAST_SETUP_PIPELINE_EVENT[_setup_pipeline_event_key(user_id, 'latest', session, mode)] = dict(row)
    except Exception:
        pass
    try:
        con = db_connect()
        cur = con.cursor()
        cur.execute(
            """INSERT INTO setup_pipeline_events (user_id, event_ts, stage, status, session, mode, setup_id, symbol, side, details_json)
                   VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)""",
            (
                int(row['user_id']), float(row['event_ts']), str(row['stage']), str(row['status']),
                str(row['session']), str(row['mode']), str(row['setup_id']), str(row['symbol']),
                str(row['side']), str(row['details_json']),
            ),
        )
        cutoff = float(time.time()) - 86400.0 * 14.0
        cur.execute("DELETE FROM setup_pipeline_events WHERE event_ts < ?", (float(cutoff),))
        con.commit()
        con.close()
    except Exception:
        pass


def _pipeline_top_reasons(counts: dict | Counter | None, limit: int = 5) -> dict:
    try:
        if isinstance(counts, Counter):
            items = counts.most_common(int(limit))
        else:
            items = Counter(dict(counts or {})).most_common(int(limit))
        return {str(k): int(v) for k, v in items}
    except Exception:
        return {}


def _latest_setup_pipeline_event(user_id: int | None = None, stage: str = '', session: str = '', mode: str = '') -> dict:
    try:
        key = _setup_pipeline_event_key(user_id, (stage if str(stage).strip().lower() != 'latest' else '') or 'latest', session, mode)
        row = dict(_LAST_SETUP_PIPELINE_EVENT.get(key) or {})
        if row:
            return row
    except Exception:
        pass
    try:
        with sqlite3.connect(DB_PATH) as conn:
            conn.row_factory = sqlite3.Row
            cur = conn.cursor()
            sql = "SELECT * FROM setup_pipeline_events WHERE 1=1 "
            params = []
            if user_id is not None:
                sql += " AND user_id=? "
                params.append(int(user_id))
            if stage and str(stage).strip().lower() != 'latest':
                sql += " AND LOWER(COALESCE(stage,''))=? "
                params.append(str(stage).strip().lower())
            if session:
                sql += " AND UPPER(COALESCE(session,''))=? "
                params.append(str(session).strip().upper())
            if mode:
                sql += " AND LOWER(COALESCE(mode,''))=? "
                params.append(str(mode).strip().lower())
            sql += " ORDER BY event_ts DESC LIMIT 1 "
            row = cur.execute(sql, tuple(params)).fetchone()
            return dict(row) if row else {}
    except Exception:
        return {}


