def db_mark_executable_setup(user_id: int, setup_id: str, session: str, executable_ts: float, s=None, source_kind: str = 'executable_setups', state: str = 'executable_pending'):
    try:
        if s is not None:
            s = _research_finalize_setup(s, session_name=str(session or getattr(s, 'session', '') or ''))
    except Exception:
        pass
    sid = str(setup_id or getattr(s, 'setup_id', '') or '').strip()
    if not sid:
        return
    session_txt = str(session or '')
    exec_ts = float(executable_ts or 0.0)
    signal_created_ts = float(getattr(s, 'created_ts', 0.0) or 0.0) if s is not None else 0.0
    symbol = str(getattr(s, 'symbol', '') or '') if s is not None else ''
    market_symbol = str(getattr(s, 'market_symbol', '') or '') if s is not None else ''
    side = str(getattr(s, 'side', '') or '') if s is not None else ''
    conf = int(getattr(s, 'conf', 0) or 0) if s is not None else 0
    entry = float(getattr(s, 'entry', 0.0) or 0.0) if s is not None else 0.0
    sl = float(getattr(s, 'sl', 0.0) or 0.0) if s is not None else 0.0
    tp = float(_setup_target_tp(s, 0.0) or 0.0) if s is not None else 0.0
    alt_target_a = 0.0
    alt_target_b = 0.0
    fut_vol_usd = float(getattr(s, 'fut_vol_usd', 0.0) or 0.0) if s is not None else 0.0
    ch24 = float(getattr(s, 'ch24', 0.0) or 0.0) if s is not None else 0.0
    ch4 = float(getattr(s, 'ch4', 0.0) or 0.0) if s is not None else 0.0
    ch1 = float(getattr(s, 'ch1', 0.0) or 0.0) if s is not None else 0.0
    ch15 = float(getattr(s, 'ch15', 0.0) or 0.0) if s is not None else 0.0
    quality_score = float(getattr(s, 'quality_score', 0.0) or 0.0) if s is not None else 0.0
    atr_pct = float(getattr(s, 'atr_pct', 0.0) or 0.0) if s is not None else 0.0
    engine = str(getattr(s, 'engine', '') or '') if s is not None else ''
    pullback_ready = 1 if bool(getattr(s, 'pullback_ready', False)) else 0
    pullback_bypass_hot = 1 if bool(getattr(s, 'pullback_bypass_hot', False)) else 0
    pullback_ema_dist_pct = float(getattr(s, 'pullback_ema_dist_pct', 0.0) or 0.0) if s is not None else 0.0
    ema_support_period = int(getattr(s, 'ema_support_period', 0) or 0) if s is not None else 0
    ema_support_dist_pct = float(getattr(s, 'ema_support_dist_pct', 0.0) or 0.0) if s is not None else 0.0
    details_json = _setup_executable_details_json(s, session=session_txt) if s is not None else ''

    con = db_connect()
    cur = con.cursor()
    cur.execute(
        """INSERT OR REPLACE INTO executable_setups (
               user_id, setup_id, session, executable_ts, signal_created_ts,
               symbol, market_symbol, side, conf, entry, sl, tp, alt_target_a, alt_target_b,
               fut_vol_usd, ch24, ch4, ch1, ch15, quality_score, atr_pct, engine,
               pullback_ready, pullback_bypass_hot, pullback_ema_dist_pct,
               ema_support_period, ema_support_dist_pct, source_kind, details_json
           ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)""",
        (
            int(user_id), sid, session_txt, exec_ts, signal_created_ts,
            symbol, market_symbol, side, conf, entry, sl, tp, alt_target_a, alt_target_b,
            fut_vol_usd, ch24, ch4, ch1, ch15, quality_score, atr_pct, engine,
            int(pullback_ready), int(pullback_bypass_hot), pullback_ema_dist_pct,
            int(ema_support_period), ema_support_dist_pct, str(source_kind or 'executable_setups'), details_json,
        ),
    )
    try:
        cur.execute(
            """UPDATE executable_setups
                   SET family_id=?, family_version=?, regime_id=?, regime_primary=?, allocator_plan_id=?, param_set_id=?,
                       family_score=?, exec_score=?, validation_state=?, challenger_flag=?
                   WHERE user_id=? AND setup_id=?
            """,
            (
                str(getattr(s, 'family_id', '') or '') if s is not None else '',
                str(getattr(s, 'family_version', '') or RESEARCH_FAMILY_VERSION) if s is not None else RESEARCH_FAMILY_VERSION,
                str(getattr(s, 'regime_id', '') or '') if s is not None else '',
                str(getattr(s, 'regime_primary', '') or '') if s is not None else '',
                str(getattr(s, 'allocator_plan_id', '') or '') if s is not None else '',
                str(getattr(s, 'param_set_id', '') or '') if s is not None else '',
                float(getattr(s, 'family_score', 0.0) or 0.0) if s is not None else 0.0,
                float(getattr(s, 'exec_score', 0.0) or 0.0) if s is not None else 0.0,
                str(getattr(s, 'validation_state', '') or 'approved') if s is not None else 'approved',
                int(bool(getattr(s, 'challenger_flag', False))) if s is not None else 0,
                int(user_id), sid,
            ),
        )
    except Exception:
        pass
    try:
        _setup_strategy_db_migrate()
        cur.execute(
            """UPDATE executable_setups SET setup_strategy=?, original_setup_id=?, original_side=?, strategy_reason=? WHERE user_id=? AND setup_id=?""",
            (
                _setup_strategy_label(s) if s is not None else 'NORMAL',
                str(getattr(s, 'original_setup_id', '') or '') if s is not None else '',
                str(getattr(s, 'original_side', '') or '') if s is not None else '',
                str(getattr(s, 'strategy_reason', '') or '')[:500] if s is not None else '',
                int(user_id), sid,
            ),
        )
    except Exception:
        pass
    try:
        cutoff_ts = float(time.time()) - float(max(86400, int(_autotrade_entry_window_min()) * 60 + 21600))
        cur.execute(
            """DELETE FROM executable_setups
                   WHERE user_id=?
                     AND executable_ts < ?""",
            (int(user_id), float(cutoff_ts)),
        )
        cur.execute(
            """DELETE FROM executable_setups
                   WHERE user_id=?
                     AND setup_id IN (
                         SELECT setup_id FROM signal_outcomes WHERE COALESCE(outcome, 'OPEN') <> 'OPEN'
                     )""",
            (int(user_id),),
        )
    except Exception:
        pass
    con.commit()
    con.close()
    try:
        _admin_setup_lifecycle_merge(
            int(user_id),
            sid,
            session=session_txt,
            symbol=symbol,
            side=side,
            executable_ts=exec_ts,
            state=str(state or 'executable_pending'),
            source_kind=str(source_kind or 'executable_setups'),
            signal_created_ts=signal_created_ts,
            details_json=details_json,
        )
    except Exception:
        pass


def db_list_executable_setups(user_id: int, session_name: str = '', ts_from: float = 0.0, limit: int = 10) -> List[dict]:
    con = db_connect()
    cur = con.cursor()
    params = [int(user_id), float(ts_from)]
    where_session = ''
    sess = str(session_name or '').upper().strip()
    if sess:
        where_session = ' AND UPPER(COALESCE(x.session, "")) = ? '
        params.append(sess)
    fetch_limit = max(int(limit or 10), min(max(int(limit or 10) * 6, int(limit or 10) + 30), 250))
    params.append(int(fetch_limit))
    cur.execute(
        f"""
        SELECT x.*, COALESCE(MAX(e.emailed_ts), 0) AS emailed_ts
        FROM executable_setups x
        LEFT JOIN signal_outcomes o ON o.setup_id = x.setup_id
        LEFT JOIN emailed_setups e ON e.user_id = x.user_id AND e.setup_id = x.setup_id
        WHERE x.user_id=?
          AND x.executable_ts>=?
          {where_session}
          AND COALESCE(o.outcome, 'OPEN')='OPEN'
        GROUP BY x.user_id, x.setup_id
        ORDER BY x.executable_ts DESC, x.setup_id DESC
        LIMIT ?
        """,
        tuple(params),
    )
    rows = [dict(r) for r in (cur.fetchall() or [])]
    con.close()
    # Filter already-persisted stale/old rows before email/autotrade consume them.
    # Ver32 uses the same final gate as live generation, so old low-confidence rows
    # from pre-patch deployments no longer leak into email or AutoTrade.
    out = []
    for r in rows:
        try:
            final_ok, _final_why, _final_meta = _setup_final_quality_gate_allows_setup(r, str(r.get('session') or session_name or ''), user_id=int(user_id or 0))
            if not final_ok:
                continue
        except Exception:
            continue
        out.append(r)
        if len(out) >= int(limit or 10):
            break
    return out


def _persist_executable_candidates(user_id: int, session_name: str, setups: List[Setup], source_kind: str = 'executable_setups', mode: str = 'email') -> dict:
    stats = {
        'attempted': 0,
        'persisted': 0,
        'signal_errors': 0,
        'queue_errors': 0,
        'errors': [],
    }
    try:
        uid = int(user_id or 0)
        if uid < 0:
            return stats
        now_ts = float(time.time())
        sess = str(session_name or '').upper().strip()

        # user_id=0 is the shared authoritative executable lane used by the email pool
        # builder before any per-user fan-out. It must be persisted even though there is no
        # corresponding user-scoped signals row for uid=0. Positive user ids keep the normal
        # signal+queue path, and admin callers may still fan out to the autotrade owner.
        target_uids = [int(uid)]
        try:
            owner_uid = int(AUTOTRADE_OWNER_UID or 0)
        except Exception:
            owner_uid = 0
        try:
            if uid > 0 and owner_uid > 0 and owner_uid not in target_uids and is_admin_user(int(uid)):
                target_uids.append(owner_uid)
        except Exception:
            pass

        stats['combo_policy_skips'] = 0
        stats['edge_quality_skips'] = 0
        stats['cooldown_skips'] = 0
        stats['setup_blackout_skips'] = 0
        # yver51: setup generation/executable persistence is shadow-on forever.
        # Blackout now controls only delivery (/screen setups + setup emails) and live AutoTrade entries.
        try:
            _blk, _blk_reason = _setup_generation_blackout_now(now_ts)
            if _blk:
                db_log_setup_pipeline_event(
                    int(uid),
                    stage='executable_setup_shadow_during_delivery_blackout',
                    status='shadow',
                    session=sess,
                    mode=str(mode or ''),
                    details={'reason': str(_blk_reason or 'setup_delivery_blackout'), 'windows': _setup_generation_blackout_windows(), 'attempted_setups': len(list(setups or [])), 'target_uids': target_uids},
                )
        except Exception:
            pass
        for s in (setups or []):
            sid = str(getattr(s, 'setup_id', '') or '').strip()
            sym = str(getattr(s, 'symbol', '') or '').upper()
            side = str(getattr(s, 'side', '') or '').upper()
            for _target_uid in target_uids:
                stats['attempted'] += 1
                try:
                    # yver71: raw generation must route NOR→REV here, but already
                    # delivered/email candidates are locked to the exact lane that
                    # the user received and that was persisted for AutoTrade.
                    if _setup_delivery_lane_locked(s, source_kind=str(source_kind or '')):
                        s_eff = s
                    else:
                        s_eff = _setup_adaptive_strategy_route_setup(s, sess, int(_target_uid))
                except Exception:
                    s_eff = s
                sid = str(getattr(s_eff, 'setup_id', '') or '').strip()
                sym = str(getattr(s_eff, 'symbol', '') or '').upper()
                side = str(getattr(s_eff, 'side', '') or '').upper()
                try:
                    final_ok, final_why, final_meta = _setup_final_quality_gate_allows_setup(s_eff, sess, user_id=int(_target_uid))
                    if not final_ok:
                        stats['combo_policy_skips'] += 1
                        db_log_setup_pipeline_event(
                            int(_target_uid),
                            stage='executable_final_quality_gate',
                            status='skip',
                            session=sess,
                            mode=str(mode or ''),
                            setup_id=sid,
                            symbol=sym,
                            side=side,
                            details={'reason': str(final_why or 'final_quality_gate_blocked'), 'source_kind': str(source_kind or 'executable_setups'), **dict(final_meta or {})},
                        )
                        continue
                except Exception:
                    stats['combo_policy_skips'] += 1
                    continue
                try:
                    # Ver52: do not apply the micro-edge guard twice.  The shared
                    # final gate above has already decided whether a controlled
                    # scout is safe enough to enter the executable queue.
                    if not (bool(_autotrade_setup_attr(s_eff, 'final_pipeline_locked_scout', False)) or bool(_autotrade_setup_attr(s_eff, 'ver52_executable_unblock', False))):
                        _edge_allowed, _edge_reason = _setup_edge_quality_guard_allows_setup(s_eff, sess, user_id=int(_target_uid))
                        if not _edge_allowed:
                            stats['edge_quality_skips'] = int(stats.get('edge_quality_skips', 0) or 0) + 1
                            db_log_setup_pipeline_event(
                                int(_target_uid),
                                stage='executable_edge_quality_guard',
                                status='skip',
                                session=sess,
                                mode=str(mode or ''),
                                setup_id=sid,
                                symbol=sym,
                                side=side,
                                details={'reason': str(_edge_reason or 'edge_quality_guard_block'), 'source_kind': str(source_kind or 'executable_setups')},
                            )
                            continue
                except Exception:
                    pass
                try:
                    if _setup_generation_symbol_recently_seen(int(_target_uid), sym, side, sess, setup_id=sid):
                        stats['cooldown_skips'] = int(stats.get('cooldown_skips', 0) or 0) + 1
                        db_log_setup_pipeline_event(
                            int(_target_uid),
                            stage='executable_generation_cooldown',
                            status='skip',
                            session=sess,
                            mode=str(mode or ''),
                            setup_id=sid,
                            symbol=sym,
                            side=side,
                            details={
                                'reason': 'same_symbol_side_setup_generation_cooldown_active',
                                'cooldown_hours': float(setup_generation_cooldown_hours_for_session(sess)),
                                'source_kind': str(source_kind or 'executable_setups'),
                            },
                        )
                        continue
                except Exception:
                    pass
                if int(_target_uid) > 0:
                    try:
                        db_insert_signal(s_eff, user_id=int(_target_uid))
                    except Exception as e:
                        stats['signal_errors'] += 1
                        if len(stats['errors']) < 6:
                            stats['errors'].append(f"signal:{sid or sym}:{type(e).__name__}")
                    try:
                        db_log_generated_setup(int(_target_uid), "exec", sess, s_eff)
                    except Exception:
                        pass
                try:
                    db_mark_executable_setup(int(_target_uid), sid, sess, float(now_ts), s=s_eff, source_kind=str(source_kind or 'executable_setups'))
                    stats['persisted'] += 1
                except Exception as e:
                    stats['queue_errors'] += 1
                    if len(stats['errors']) < 6:
                        stats['errors'].append(f"queue:{sid or sym}:{type(e).__name__}")
                    db_log_setup_pipeline_event(
                        int(_target_uid),
                        stage='executable_queue_write',
                        status='error',
                        session=sess,
                        mode=str(mode or ''),
                        setup_id=sid,
                        symbol=sym,
                        side=side,
                        details={'source_kind': str(source_kind or 'executable_setups'), 'error': f'{type(e).__name__}: {e}'},
                    )
        if stats['queue_errors'] or stats['signal_errors']:
            db_log_setup_pipeline_event(
                int(uid),
                stage='executable_queue_write',
                status='partial_error' if stats['persisted'] > 0 else 'error',
                session=sess,
                mode=str(mode or ''),
                details=dict(stats),
            )
        elif stats['persisted'] > 0:
            db_log_setup_pipeline_event(
                int(uid),
                stage='executable_queue_write',
                status='ok',
                session=sess,
                mode=str(mode or ''),
                details=dict(stats),
            )
        return stats
    except Exception as e:
        stats['errors'].append(f"persist_exception:{type(e).__name__}")
        db_log_setup_pipeline_event(
            int(user_id or 0),
            stage='executable_queue_write',
            status='error',
            session=str(session_name or ''),
            mode=str(mode or ''),
            details={'error': f'{type(e).__name__}: {e}', **stats},
        )
        return stats


def _executable_rows_to_setup_objects(rows: List[dict], session_name: str = '') -> list:
    from types import SimpleNamespace
    out = []
    for row in (rows or []):
        try:
            item = SimpleNamespace(
                setup_id=str(row.get('setup_id') or ''),
                id=str(row.get('setup_id') or ''),
                symbol=str(row.get('symbol') or ''),
                market_symbol=str(row.get('market_symbol') or ''),
                side=str(row.get('side') or ''),
                conf=int(row.get('conf') or 0),
                entry=float(row.get('entry') or 0.0),
                sl=float(row.get('sl') or 0.0),
                tp=float(_setup_target_tp(row, 0.0) or 0.0),
                alt_target_a=0.0,
                alt_target_b=0.0,
                fut_vol_usd=float(row.get('fut_vol_usd') or 0.0),
                ch24=float(row.get('ch24') or 0.0),
                ch4=float(row.get('ch4') or 0.0),
                ch1=float(row.get('ch1') or 0.0),
                ch15=float(row.get('ch15') or 0.0),
                quality_score=float(row.get('quality_score') or 0.0),
                atr_pct=float(row.get('atr_pct') or 0.0),
                engine=str(row.get('engine') or ''),
                pullback_ready=bool(int(row.get('pullback_ready') or 0)),
                pullback_bypass_hot=bool(int(row.get('pullback_bypass_hot') or 0)),
                pullback_ema_dist_pct=float(row.get('pullback_ema_dist_pct') or 0.0),
                ema_support_period=int(row.get('ema_support_period') or 0),
                ema_support_dist_pct=float(row.get('ema_support_dist_pct') or 0.0),
                created_ts=float(float(row.get('signal_created_ts') or 0.0) or float(row.get('executable_ts') or 0.0) or 0.0),
                signal_created_ts=float(row.get('signal_created_ts') or 0.0),
                executable_ts=float(row.get('executable_ts') or 0.0),
                email_logged_ts=float(row.get('emailed_ts') or 0.0),
                generated_logged_ts=0.0,
                source_kind=str(row.get('source_kind') or 'executable_setups'),
                source_session=str(row.get('session') or ''),
                family_id=str(row.get('family_id') or ''),
                family_version=str(row.get('family_version') or RESEARCH_FAMILY_VERSION),
                regime_id=str(row.get('regime_id') or ''),
                regime_primary=str(row.get('regime_primary') or ''),
                allocator_plan_id=str(row.get('allocator_plan_id') or ''),
                param_set_id=str(row.get('param_set_id') or ''),
                family_score=float(row.get('family_score') or 0.0),
                exec_score=float(row.get('exec_score') or 0.0),
                validation_state=str(row.get('validation_state') or 'approved'),
                challenger_flag=bool(int(row.get('challenger_flag') or 0)),
                setup_strategy=str(row.get('setup_strategy') or ''),
                strategy=str(row.get('setup_strategy') or ''),
                strategy_mode=str(row.get('setup_strategy') or ''),
                strategy_reason=str(row.get('strategy_reason') or ''),
                original_setup_id=str(row.get('original_setup_id') or ''),
                original_side=str(row.get('original_side') or ''),
                delivery_lane_locked=True,
            )
            item = _research_finalize_setup(item, session_name=str(row.get('session') or session_name or ''))
            out.append(item)
        except Exception:
            continue
    return out


# =========================================================
# RECENT EMAILED SETUP CACHE (exact email -> screen/autotrade sync)
# =========================================================
_RECENT_EMAILED_SETUP_CACHE: Dict[int, List[dict]] = {}

def _recent_emailed_cache_ttl_sec() -> int:
    try:
        return int(max(1800, int(_autotrade_entry_window_min()) * 60 + 900))
    except Exception:
        return 1800

def _recent_emailed_cache_prune(uid: int | None = None) -> None:
    cutoff = float(time.time()) - float(_recent_emailed_cache_ttl_sec())
    try:
        targets = [int(uid)] if uid is not None else list(_RECENT_EMAILED_SETUP_CACHE.keys())
    except Exception:
        targets = []
    for _uid in (targets or []):
        rows = []
        for row in list(_RECENT_EMAILED_SETUP_CACHE.get(int(_uid), []) or []):
            try:
                ts = float(row.get('emailed_ts', 0.0) or 0.0)
            except Exception:
                ts = 0.0
            if ts >= cutoff:
                rows.append(row)
        if rows:
            _RECENT_EMAILED_SETUP_CACHE[int(_uid)] = rows
        else:
            _RECENT_EMAILED_SETUP_CACHE.pop(int(_uid), None)

def _cache_recent_emailed_setup(user_id: int, setup: Any, session: str = '', emailed_ts: float | None = None, source_kind: str = 'recent_email_cache') -> None:
    try:
        uid = int(user_id or 0)
    except Exception:
        uid = 0
    if uid <= 0 or setup is None:
        return
    ts = float(emailed_ts or time.time())
    row = {
        'setup_id': str(getattr(setup, 'setup_id', '') or getattr(setup, 'id', '') or '').strip(),
        'symbol': str(getattr(setup, 'symbol', '') or '').upper(),
        'market_symbol': str(getattr(setup, 'market_symbol', '') or ''),
        'side': str(getattr(setup, 'side', '') or '').upper(),
        'conf': int(getattr(setup, 'conf', 0) or 0),
        'entry': float(getattr(setup, 'entry', 0.0) or 0.0),
        'sl': float(getattr(setup, 'sl', 0.0) or 0.0),
        'tp': float(_setup_target_tp(setup, 0.0) or 0.0),
        'alt_target_a': 0.0,
        'alt_target_b': 0.0,
        'fut_vol_usd': float(getattr(setup, 'fut_vol_usd', 0.0) or 0.0),
        'ch24': float(getattr(setup, 'ch24', 0.0) or 0.0),
        'ch4': float(getattr(setup, 'ch4', 0.0) or 0.0),
        'ch1': float(getattr(setup, 'ch1', 0.0) or 0.0),
        'ch15': float(getattr(setup, 'ch15', 0.0) or 0.0),
        'ema_support_period': int(getattr(setup, 'ema_support_period', 0) or 0),
        'ema_support_dist_pct': float(getattr(setup, 'ema_support_dist_pct', 0.0) or 0.0),
        'pullback_ema_period': int(getattr(setup, 'pullback_ema_period', 0) or 0),
        'pullback_ema_dist_pct': float(getattr(setup, 'pullback_ema_dist_pct', 0.0) or 0.0),
        'pullback_ready': bool(getattr(setup, 'pullback_ready', False)),
        'pullback_bypass_hot': bool(getattr(setup, 'pullback_bypass_hot', False)),
        'leader_base_override': bool(getattr(setup, 'leader_base_override', False)),
        'engine': str(getattr(setup, 'engine', '') or ''),
        'is_trailing_alt_target_b': bool(getattr(setup, 'is_trailing_alt_target_b', False)),
        'created_ts': float(getattr(setup, 'created_ts', 0.0) or 0.0),
        'signal_created_ts': float(getattr(setup, 'created_ts', 0.0) or 0.0),
        'family_id': str(getattr(setup, 'family_id', '') or ''),
        'family_version': str(getattr(setup, 'family_version', '') or RESEARCH_FAMILY_VERSION),
        'regime_id': str(getattr(setup, 'regime_id', '') or ''),
        'regime_primary': str(getattr(setup, 'regime_primary', '') or ''),
        'allocator_plan_id': str(getattr(setup, 'allocator_plan_id', '') or ''),
        'param_set_id': str(getattr(setup, 'param_set_id', '') or ''),
        'family_score': float(getattr(setup, 'family_score', 0.0) or 0.0),
        'exec_score': float(getattr(setup, 'exec_score', 0.0) or 0.0),
        'validation_state': str(getattr(setup, 'validation_state', '') or 'approved'),
        'challenger_flag': bool(getattr(setup, 'challenger_flag', False)),
        'emailed_ts': ts,
        'email_logged_ts': ts,
        'generated_logged_ts': float(getattr(setup, 'created_ts', 0.0) or 0.0),
        'source_session': str(session or ''),
        'source_kind': str(source_kind or 'recent_email_cache'),
        'setup_strategy': _setup_strategy_label(setup),
        'strategy': _setup_strategy_label(setup),
        'strategy_mode': _setup_strategy_label(setup),
        'strategy_reason': str(getattr(setup, 'strategy_reason', '') or ''),
        'original_setup_id': str(getattr(setup, 'original_setup_id', '') or ''),
        'original_side': str(getattr(setup, 'original_side', '') or ''),
        'delivery_lane_locked': True,
    }
    if not row['setup_id']:
        return
    bucket = list(_RECENT_EMAILED_SETUP_CACHE.get(uid, []) or [])
    bucket = [r for r in bucket if str(r.get('setup_id') or '') != row['setup_id']]
    bucket.insert(0, row)
    _RECENT_EMAILED_SETUP_CACHE[uid] = bucket[:50]
    _recent_emailed_cache_prune(uid)

def _recent_cached_emailed_setups(user_id: int, session_name: str = '', max_age_min: int | None = None, limit: int = 3) -> list:
    from types import SimpleNamespace
    try:
        uid = int(user_id or 0)
    except Exception:
        uid = 0
    if uid <= 0:
        return []
    try:
        if max_age_min is None:
            max_age_min = _screen_actionable_fallback_max_age_min()
        max_age_min = max(1, int(max_age_min or _screen_actionable_fallback_max_age_min()))
    except Exception:
        max_age_min = _screen_actionable_fallback_max_age_min()
    cutoff = float(time.time()) - float(max_age_min) * 60.0
    req_session_u = str(session_name or '').upper().strip()
    _recent_emailed_cache_prune(uid)
    out = []
    seen = set()
    for row in list(_RECENT_EMAILED_SETUP_CACHE.get(uid, []) or []):
        try:
            sid = str(row.get('setup_id') or '').strip()
            ident = _setup_identity_from_obj(dict(row))
            dedupe_key = ident or sid
            if not sid or dedupe_key in seen:
                continue
            ts = float(row.get('emailed_ts', 0.0) or 0.0)
            if ts < cutoff:
                continue
            src_session_u = str(row.get('source_session') or '').upper().strip()
            if req_session_u and src_session_u and src_session_u not in {'', req_session_u}:
                continue
            seen.add(dedupe_key)
            item = SimpleNamespace(**row)
            item = _research_finalize_setup(item, session_name=str(row.get('session') or req_session_u or ''))
            out.append(item)
            if len(out) >= int(limit):
                break
        except Exception:
            continue
    return out[:int(limit)]

def _db_recent_emailed_setup_objects(user_id: int, session_name: str = '', max_age_min: int | None = None, limit: int = 3) -> list:
    """Hydrate recently emailed setups from DB for screen/autotrade recovery.

    This is the durable fallback when the in-memory recent-email cache is empty
    or the executable queue write was missed on a prior tick.
    """
    from types import SimpleNamespace
    try:
        uid = int(user_id or 0)
    except Exception:
        uid = 0
    if uid <= 0:
        return []
    try:
        cutoff = float(time.time()) - float(max_age_min) * 60.0
    except Exception:
        cutoff = float(time.time()) - float(_screen_actionable_fallback_max_age_min()) * 60.0
    req_session_u = str(session_name or '').upper().strip()
    try:
        try:
            _setup_strategy_db_migrate()
        except Exception:
            pass
        with sqlite3.connect(DB_PATH) as conn:
            conn.row_factory = sqlite3.Row
            cur = conn.cursor()
            params = [int(uid), float(cutoff)]
            where_session = ''
            if req_session_u:
                where_session = " AND UPPER(COALESCE(e.session,''))=? "
                params.append(req_session_u)
            params.append(int(max(1, int(limit) * 6)))
            rows = cur.execute(
                f"""
                SELECT
                    e.setup_id, e.session, e.emailed_ts,
                    COALESCE(s.market_symbol, '') AS market_symbol,
                    COALESCE(s.symbol, '') AS symbol,
                    COALESCE(s.side, '') AS side,
                    COALESCE(s.conf, 0) AS conf,
                    COALESCE(s.entry, 0) AS entry,
                    COALESCE(s.sl, 0) AS sl,
                    COALESCE(s.tp, 0) AS tp,
                    COALESCE(s.alt_target_a, 0) AS alt_target_a,
                    COALESCE(s.alt_target_b, 0) AS alt_target_b,
                    COALESCE(s.fut_vol_usd, 0) AS fut_vol_usd,
                    COALESCE(s.ch24, 0) AS ch24,
                    COALESCE(s.ch4, 0) AS ch4,
                    COALESCE(s.ch1, 0) AS ch1,
                    COALESCE(s.ch15, 0) AS ch15,
                    COALESCE(s.created_ts, e.emailed_ts) AS signal_created_ts,
                    COALESCE(x.quality_score, 0) AS quality_score,
                    COALESCE(x.atr_pct, 0) AS atr_pct,
                    COALESCE(x.engine, '') AS engine,
                    COALESCE(x.pullback_ready, 0) AS pullback_ready,
                    COALESCE(x.pullback_bypass_hot, 0) AS pullback_bypass_hot,
                    COALESCE(x.pullback_ema_dist_pct, 0) AS pullback_ema_dist_pct,
                    COALESCE(x.ema_support_period, 0) AS ema_support_period,
                    COALESCE(x.ema_support_dist_pct, 0) AS ema_support_dist_pct,
                    COALESCE(NULLIF(x.family_id,''), NULLIF(s.family_id,''), '') AS family_id,
                    COALESCE(NULLIF(x.source_kind,''), 'emailed_setups') AS source_kind,
                    COALESCE(NULLIF(x.setup_strategy,''), NULLIF(s.setup_strategy,''), 'NORMAL') AS setup_strategy,
                    COALESCE(NULLIF(x.original_setup_id,''), NULLIF(s.original_setup_id,''), '') AS original_setup_id,
                    COALESCE(NULLIF(x.original_side,''), NULLIF(s.original_side,''), '') AS original_side,
                    COALESCE(NULLIF(x.strategy_reason,''), NULLIF(s.strategy_reason,''), '') AS strategy_reason
                FROM emailed_setups e
                LEFT JOIN signals s ON s.setup_id = e.setup_id
                LEFT JOIN executable_setups x ON x.user_id = e.user_id AND x.setup_id = e.setup_id
                LEFT JOIN signal_outcomes o ON o.setup_id = e.setup_id
                WHERE e.user_id=?
                  AND e.emailed_ts>=?
                  {where_session}
                  AND COALESCE(o.outcome, 'OPEN')='OPEN'
                ORDER BY e.emailed_ts DESC, e.setup_id DESC
                LIMIT ?
                """,
                tuple(params),
            ).fetchall() or []
    except Exception:
        rows = []

    out = []
    seen = set()
    for row in rows:
        try:
            row = dict(row)
            sid = str(row.get('setup_id') or '').strip()
            ident = _setup_identity_from_obj(row)
            dedupe_key = ident or sid
            if not sid or dedupe_key in seen:
                continue
            seen.add(dedupe_key)
            src_session_u = str(row.get('session') or '').upper().strip()
            if req_session_u and src_session_u and src_session_u not in {'', req_session_u}:
                continue
            item = SimpleNamespace(
                setup_id=sid,
                id=sid,
                symbol=str(row.get('symbol') or ''),
                market_symbol=str(row.get('market_symbol') or ''),
                side=str(row.get('side') or ''),
                conf=int(row.get('conf') or 0),
                entry=float(row.get('entry') or 0.0),
                sl=float(row.get('sl') or 0.0),
                tp=float(_resolve_single_tp(float(row.get('entry') or 0.0), float(row.get('sl') or 0.0), row.get('tp'), row.get('alt_target_a'), row.get('alt_target_b'), str(row.get('side') or '')) or 0.0),
                alt_target_a=0.0,
                alt_target_b=0.0,
                fut_vol_usd=float(row.get('fut_vol_usd') or 0.0),
                ch24=float(row.get('ch24') or 0.0),
                ch4=float(row.get('ch4') or 0.0),
                ch1=float(row.get('ch1') or 0.0),
                ch15=float(row.get('ch15') or 0.0),
                quality_score=float(row.get('quality_score') or 0.0),
                atr_pct=float(row.get('atr_pct') or 0.0),
                engine=str(row.get('engine') or ''),
                pullback_ready=bool(int(row.get('pullback_ready') or 0)),
                pullback_bypass_hot=bool(int(row.get('pullback_bypass_hot') or 0)),
                pullback_ema_dist_pct=float(row.get('pullback_ema_dist_pct') or 0.0),
                ema_support_period=int(row.get('ema_support_period') or 0),
                ema_support_dist_pct=float(row.get('ema_support_dist_pct') or 0.0),
                is_trailing_alt_target_b=bool(int(row.get('is_trailing_alt_target_b') or 0)) if str(row.get('is_trailing_alt_target_b') or '').strip() not in {'', 'None'} else False,
                created_ts=float(row.get('signal_created_ts') or row.get('emailed_ts') or 0.0),
                signal_created_ts=float(row.get('signal_created_ts') or 0.0),
                executable_ts=float(row.get('emailed_ts') or 0.0),
                email_logged_ts=float(row.get('emailed_ts') or 0.0),
                generated_logged_ts=float(row.get('signal_created_ts') or 0.0),
                source_kind=str(row.get('source_kind') or 'emailed_setups'),
                source_session=str(row.get('session') or ''),
                family_id=str(row.get('family_id') or ''),
                family_version=str(row.get('family_version') or RESEARCH_FAMILY_VERSION),
                setup_strategy=str(row.get('setup_strategy') or 'NORMAL'),
                strategy=str(row.get('setup_strategy') or 'NORMAL'),
                strategy_mode=str(row.get('setup_strategy') or 'NORMAL'),
                strategy_reason=str(row.get('strategy_reason') or ''),
                original_setup_id=str(row.get('original_setup_id') or ''),
                original_side=str(row.get('original_side') or ''),
                delivery_lane_locked=True,
            )
            out.append(item)
            if len(out) >= int(limit):
                break
        except Exception:
            continue
    return out[:int(limit)]


def _recent_delivery_lane_setup_objects(user_id: int, session_name: str = '', max_age_min: int | None = None, limit: int = 3) -> list:
    """Return recent emailed/executable setups with cache -> DB fallback order."""
    try:
        if max_age_min is None:
            max_age_min = _screen_actionable_fallback_max_age_min()
        max_age_min = max(1, int(max_age_min or _screen_actionable_fallback_max_age_min()))
    except Exception:
        max_age_min = _screen_actionable_fallback_max_age_min()
    out = []
    seen = set()
    for getter in (
        lambda: _recent_cached_emailed_setups(user_id, session_name=session_name, max_age_min=max_age_min, limit=limit),
        lambda: _db_recent_emailed_setup_objects(user_id, session_name=session_name, max_age_min=max_age_min, limit=limit),
    ):
        try:
            rows = getter() or []
        except Exception:
            rows = []
        for item in rows:
            try:
                sid = str(getattr(item, 'setup_id', '') or getattr(item, 'id', '') or '').strip()
                ident = _setup_identity_from_obj(item)
            except Exception:
                sid = ''
                ident = ''
            dedupe_key = ident or sid
            if not sid or dedupe_key in seen:
                continue
            seen.add(dedupe_key)
            out.append(item)
            if len(out) >= int(limit):
                return out[:int(limit)]
    return out[:int(limit)]




def _latest_recent_delivery_ts(user_id: int, session_name: str = '', max_age_min: int | None = None) -> float:
    """Latest setup-email delivery timestamp for /screen cache invalidation.

    /screen can have a valid but older executable snapshot while a newer setup email has
    already been sent. In that case /screen must show the latest emailed setup set, not
    the old cache or a quick ticker snapshot.
    """
    try:
        uid = int(user_id or 0)
    except Exception:
        uid = 0
    if uid <= 0:
        return 0.0
    req_session_u = str(session_name or '').upper().strip()
    if max_age_min is None:
        max_age_min = _screen_actionable_fallback_max_age_min()
    cutoff = float(time.time()) - float(max(2, int(max_age_min or _screen_actionable_fallback_max_age_min()))) * 60.0
    latest = 0.0
    try:
        _recent_emailed_cache_prune(uid)
        for row in list(_RECENT_EMAILED_SETUP_CACHE.get(uid, []) or []):
            try:
                src = str(row.get('source_session') or row.get('session') or '').upper().strip()
                if req_session_u and src and src not in {'', req_session_u}:
                    continue
                ts = float(row.get('emailed_ts') or row.get('email_logged_ts') or 0.0)
                if ts >= cutoff:
                    latest = max(latest, ts)
            except Exception:
                continue
    except Exception:
        pass
    try:
        with sqlite3.connect(DB_PATH) as conn:
            cur = conn.cursor()
            if req_session_u:
                row = cur.execute(
                    "SELECT MAX(emailed_ts) FROM emailed_setups WHERE user_id=? AND emailed_ts>=? AND UPPER(COALESCE(session,''))=?",
                    (uid, float(cutoff), req_session_u),
                ).fetchone()
            else:
                row = cur.execute(
                    "SELECT MAX(emailed_ts) FROM emailed_setups WHERE user_id=? AND emailed_ts>=?",
                    (uid, float(cutoff)),
                ).fetchone()
            if row and row[0] is not None:
                latest = max(latest, float(row[0] or 0.0))
    except Exception:
        pass
    return float(latest or 0.0)

def _db_setup_stage_exists(table_name: str, user_id: int, setup_id: str, ts_column: str, lookback_hours: int = 12) -> bool:
    try:
        sid = str(setup_id or '').strip()
        if not sid:
            return False
        cutoff = float(time.time()) - float(max(1, int(lookback_hours))) * 3600.0
        con = db_connect()
        cur = con.cursor()
        cur.execute(
            f"SELECT 1 FROM {table_name} WHERE user_id=? AND setup_id=? AND {ts_column}>=? LIMIT 1",
            (int(user_id), sid, float(cutoff)),
        )
        row = cur.fetchone()
        con.close()
        return bool(row)
    except Exception:
        return False


def db_has_emailed_setup(user_id: int, setup_id: str, lookback_hours: int = 12) -> bool:
    return _db_setup_stage_exists('emailed_setups', user_id, setup_id, 'emailed_ts', lookback_hours=lookback_hours)


def db_has_executable_setup(user_id: int, setup_id: str, lookback_hours: int = 12) -> bool:
    return _db_setup_stage_exists('executable_setups', user_id, setup_id, 'executable_ts', lookback_hours=lookback_hours)


def db_recent_generated_setups(user_id: int, source: str, lookback_hours: int = 6, limit: int = 5) -> list[dict]:
    """Fetch recent generated_setups rows for UI correlation (/screen showing email setups too)."""
    try:
        cutoff = time.time() - float(lookback_hours) * 3600.0
        con = db_connect()
        cur = con.cursor()
        cur.execute("""
            SELECT setup_id, session, symbol, side, conf, created_ts
            FROM generated_setups
            WHERE user_id = ?
              AND source = ?
              AND created_ts >= ?
            ORDER BY created_ts DESC
            LIMIT ?
        """, (int(user_id), str(source).strip().lower(), float(cutoff), int(limit)))
        rows = cur.fetchall() or []
        con.close()
        out = []
        for r in rows:
            sid, sess, sym, side, conf, ts = r
            out.append({
                "setup_id": sid,
                "session": sess,
                "symbol": sym,
                "side": side,
                "conf": int(conf or 0),
                "created_ts": float(ts or 0.0),
            })
        return out
    except Exception:
        return []

def db_log_generated_setup(user_id: int, source: str, session: str, s) -> None:
    """Log a generated setup (from /screen) or a sent setup (email) for correlation.

    Ver20: during the admin-defined setup-generation blackout, do not create new
    setup rows for the production/audit lane. Market context snapshots may still be
    shown by /screen, but no setup should enter generated/executable/email records.
    """
    con = None
    ts_now = float(time.time())
    try:
        # yver51: never suppress generated_setups logging during blackout.
        # This keeps the shadow/audit database complete so /setup_open_times can
        # identify better future blackout windows. Delivery and AutoTrade entry
        # blackouts are enforced downstream, not here.
        try:
            src_l = str(source or '').strip().lower()
            if src_l in {'screen', 'exec', 'email', 'bigmove_email', 'executable', 'setup', 'autotrade'}:
                _blk, _why = _setup_generation_blackout_now(ts_now)
                if _blk:
                    pass
        except Exception:
            pass
        try:
            s = _research_finalize_setup(s, session_name=str(session or getattr(s, 'session', '') or ''))
        except Exception:
            pass
        try:
            _setup_strategy_db_migrate()
        except Exception:
            pass
        con = db_connect()
        cur = con.cursor()
        cur.execute(
            """INSERT INTO generated_setups
               (user_id, source, created_ts, session, setup_id, symbol, market_symbol, side, conf,
                entry, sl, tp, alt_target_a, alt_target_b, fut_vol_usd, ch24, ch4, ch1, ch15, engine)
               VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)""",
            (
                int(user_id),
                str(source or "").strip().lower(),
                ts_now,
                str(session or ""),
                str(getattr(s, "setup_id", "") or ""),
                str(getattr(s, "symbol", "") or ""),
                str(getattr(s, "market_symbol", "") or ""),
                str(getattr(s, "side", "") or ""),
                int(getattr(s, "conf", 0) or 0),
                float(getattr(s, "entry", 0.0) or 0.0),
                float(getattr(s, "sl", 0.0) or 0.0),
                float(_setup_target_tp(s, 0.0) or 0.0),
                0.0,
                0.0,
                float(getattr(s, "fut_vol_usd", 0.0) or 0.0),
                float(getattr(s, "ch24", 0.0) or 0.0),
                float(getattr(s, "ch4", 0.0) or 0.0),
                float(getattr(s, "ch1", 0.0) or 0.0),
                float(getattr(s, "ch15", 0.0) or 0.0),
                str(getattr(s, "engine", "") or ""),
            ),
        )
        try:
            cur.execute(
                """UPDATE generated_setups
                       SET family_id=?, regime_primary=?, allocator_plan_id=?, param_set_id=?
                       WHERE rowid = last_insert_rowid()
                """,
                (
                    str(getattr(s, 'family_id', '') or _setup_engine_to_family_id(str(getattr(s, 'engine', '') or ''), {}) or ''),
                    str(getattr(s, 'regime_primary', '') or ''),
                    str(getattr(s, 'allocator_plan_id', '') or ''),
                    str(getattr(s, 'param_set_id', '') or ''),
                ),
            )
        except Exception:
            pass
        try:
            cur.execute(
                """UPDATE generated_setups
                       SET setup_strategy=?, original_setup_id=?, original_side=?, strategy_reason=?
                       WHERE rowid = last_insert_rowid()
                """,
                (
                    _setup_strategy_label(s),
                    str(getattr(s, 'original_setup_id', '') or ''),
                    str(getattr(s, 'original_side', '') or ''),
                    str(getattr(s, 'strategy_reason', '') or '')[:500],
                ),
            )
        except Exception:
            pass
        con.commit()
    except Exception:
        pass
    finally:
        try:
            if con:
                con.close()
        except Exception:
            pass
    try:
        sid = str(getattr(s, 'setup_id', '') or '')
        state = 'screened' if str(source or '').strip().lower() == 'screen' else 'emailed'
        payload = {
            'session': str(session or ''),
            'symbol': str(getattr(s, 'symbol', '') or ''),
            'side': str(getattr(s, 'side', '') or ''),
            'state': state,
        }
        if state == 'screened':
            payload['screened_ts'] = ts_now
            payload['source_kind'] = 'generated_setups'
        else:
            payload['emailed_ts'] = ts_now
            payload['generated_logged_ts'] = ts_now
            payload['source_kind'] = 'generated_setups'
        _admin_setup_lifecycle_merge(int(user_id), sid, **payload)
    except Exception:
        pass

