def _lessons_learned_text(refresh: bool = False) -> str:
    try:
        if refresh:
            try:
                _evolution_process_new_diagnostics()
            except Exception:
                pass
        rows = _evolution_latest_lessons(8, 45, refresh)
        if not rows:
            return "No lessons learned diagnostics recorded yet."
        lines = ["📚 Lessons Learned", HDR]
        try:
            freshest_ts = max(float(r.get("decided_ts") or 0.0) for r in (rows or []))
        except Exception:
            freshest_ts = 0.0
        if freshest_ts > 0 and (time.time() - freshest_ts) > 72 * 3600:
            lines.append(f"• No fresh lessons were decided recently. Latest archived lesson time: {_fmt_dt_local(datetime.fromtimestamp(freshest_ts, tz=timezone.utc))}")
            lines.append(SEP)
        for r in rows[:8]:
            tags = r.get("tags") or []
            when = _fmt_dt_local(datetime.fromtimestamp(float(r.get("decided_ts") or time.time()), tz=timezone.utc))
            src = str(r.get('source_type') or '').strip().lower()
            src_txt = f" [{src}]" if src else ""
            pnl_hint = (r.get('detail') or {}).get('pnl_usdt') if isinstance(r.get('detail'), dict) else None
            lines.append(f"• {str(r.get('symbol') or '')} {str(r.get('side') or '')} | {str(r.get('session') or '')} | {when}{src_txt}")
            lines.append(f"  Outcome: {str(_canon_signal_outcome_label(r.get('outcome'), pnl_hint) or '')} | Tags: {', '.join(tags[:4]) if tags else '—'}")
            rec = str(r.get("recommendation") or "").strip()
            if rec:
                lines.append(f"  Insight: {rec}")
        safe_lines = [str(x) for x in lines if x is not None]
        return "\n".join(safe_lines)
    except Exception as e:
        return f"❌ /lessons_learned failed: {type(e).__name__}: {e}"


def _health_sys_text(uid: int) -> str:
    """Cached/cheap admin engine health text."""
    db_ok = True
    db_err = ""
    try:
        con = db_connect()
        con.execute("SELECT 1")
        con.close()
    except Exception as e:
        db_ok = False
        db_err = str(e)

    ex_ok = True
    ex_err = ""
    tickers_n = 0
    dt_ms = 0
    t0 = time.time()
    try:
        best = get_cached_futures_tickers() or {}
        tickers_n = len(best or {})
        if tickers_n <= 0:
            best = fetch_futures_tickers() or {}
            tickers_n = len(best or {})
    except Exception as e:
        ex_ok = False
        ex_err = str(e)
    dt_ms = int((time.time() - t0) * 1000)

    cache_items = len(_CACHE)
    email_cfg = email_config_ok()
    email_on = EMAIL_ENABLED

    user = get_user(int(uid)) or {}
    enabled = user_enabled_sessions(user)
    sess = in_session_now(user)
    now_s = current_session_utc(datetime.now(timezone.utc)) if int(user.get("sessions_unlimited", 0) or 0) == 1 else (sess["name"] if sess else "NONE")

    msg = [
        "🩺 PulseFutures • Health",
        HDR,
        f"DB: {'OK' if db_ok else 'FAIL'}" + (f" | {db_err}" if (not db_ok and db_err) else ""),
        f"Bybit/CCXT: {'OK' if ex_ok else 'FAIL'} | tickers={tickers_n} | {dt_ms}ms" + (f" | {ex_err}" if (not ex_ok and ex_err) else ""),
        f"Email: enabled={email_on} | configured={email_cfg}",
        f"Cache: items={cache_items} | tickersTTL={TICKERS_TTL_SEC}s | ohlcvTTL={OHLCV_TTL_SEC}s",
        HDR,
        f"Your TZ: {user.get('tz', TIMEZONE)}",
        f"Sessions enabled: {', '.join(enabled)} | Now: {now_s}",
        f"Limits: emailcap/session={int(user.get('max_emails_per_session', DEFAULT_MAX_EMAILS_PER_SESSION) or 0)} (0=∞), emaildaycap={int(user.get('max_emails_per_day', DEFAULT_MAX_EMAILS_PER_DAY) or 0)} (0=∞), gap={int(user.get('email_gap_min', DEFAULT_EMAIL_GAP_MIN) or 0)}m",
    ]
    return "\n".join(msg)


def _dev_status_text(uid: int) -> str:
    user = reset_daily_if_needed(get_user(int(uid)))
    cfg = load_strategy_config(force=False)
    tgt = _goal_profile_targets(cfg)
    goal_rep = load_goal_profile_report() or {}
    email_gate = _email_runtime_limits_snapshot(int(uid), user)
    adaptive = _market_adaptive_status_snapshot() or {}
    now_utc = datetime.now(timezone.utc)
    now_session = current_session_utc(now_utc)

    data_counts = {'signals_24h': 0, 'exec_24h': 0, 'emailed_24h': 0, 'pipeline_events_24h': 0, 'family_eval_rows_today': 0, 'autotrade_opened_24h': 0, 'autotrade_closed_24h': 0}
    pipeline_latest = {'email_latest': {}, 'email_build': {}, 'email_exec': {}, 'screen_exec': {}}
    try:
        since_ts = float(time.time() - 24 * 3600)
        trading_day = _research_trading_day_label(time.time())
        with sqlite3.connect(DB_PATH) as conn:
            conn.row_factory = sqlite3.Row
            cur = conn.cursor()
            cur.execute("SELECT COUNT(1) AS n FROM signals WHERE created_ts>=?", (since_ts,))
            row = cur.fetchone()
            data_counts['signals_24h'] = int((row['n'] if row else 0) or 0)
            cur.execute("SELECT COUNT(1) AS n FROM executable_setups WHERE executable_ts>=?", (since_ts,))
            row = cur.fetchone()
            data_counts['exec_24h'] = int((row['n'] if row else 0) or 0)
            cur.execute("SELECT COUNT(1) AS n FROM emailed_setups WHERE emailed_ts>=?", (since_ts,))
            row = cur.fetchone()
            data_counts['emailed_24h'] = int((row['n'] if row else 0) or 0)
            cur.execute("SELECT COUNT(1) AS n FROM setup_pipeline_events WHERE event_ts>=?", (since_ts,))
            row = cur.fetchone()
            data_counts['pipeline_events_24h'] = int((row['n'] if row else 0) or 0)
            cur.execute("SELECT COUNT(1) AS n FROM family_eval_daily WHERE trading_day=?", (trading_day,))
            row = cur.fetchone()
            data_counts['family_eval_rows_today'] = int((row['n'] if row else 0) or 0)
            cur.execute("SELECT COUNT(1) AS n FROM autotrade_trades WHERE opened_ts>=?", (since_ts,))
            row = cur.fetchone()
            data_counts['autotrade_opened_24h'] = int((row['n'] if row else 0) or 0)
            cur.execute("SELECT COUNT(1) AS n FROM autotrade_trades WHERE closed_ts IS NOT NULL AND closed_ts>=?", (since_ts,))
            row = cur.fetchone()
            data_counts['autotrade_closed_24h'] = int((row['n'] if row else 0) or 0)
    except Exception:
        pass

    exec_from_pipeline_hint = 0
    try:
        if int(data_counts.get('exec_24h', 0) or 0) <= 0:
            hint = _latest_setup_pipeline_event(int(uid), stage='email_executable_pool', mode='email') or {}
            try:
                details = json.loads(str(hint.get('details_json') or '{}')) if hint else {}
            except Exception:
                details = {}
            exec_from_pipeline_hint = int((details or {}).get('persisted') or 0)
    except Exception:
        exec_from_pipeline_hint = 0
    try:
        if int(data_counts.get('signals_24h', 0) or 0) <= 0 and int(data_counts.get('emailed_24h', 0) or 0) > 0:
            data_counts['signals_24h'] = int(data_counts.get('emailed_24h', 0) or 0)
    except Exception:
        pass

    try:
        sess_now = str(current_session_name() or '').upper().strip()
        pipeline_latest['email_latest'] = _latest_setup_pipeline_event(int(uid), stage='latest', session=sess_now, mode='email') or {}
        if not pipeline_latest['email_latest']:
            pipeline_latest['email_latest'] = _latest_setup_pipeline_event(int(uid), stage='latest', mode='email') or {}
        pipeline_latest['email_build'] = _latest_setup_pipeline_event(0, stage='build_priority_pool', session=sess_now, mode='email') or {}
        if not pipeline_latest['email_build']:
            pipeline_latest['email_build'] = _latest_setup_pipeline_event(0, stage='build_priority_pool', mode='email') or {}
        pipeline_latest['email_exec'] = _latest_setup_pipeline_event(int(uid), stage='email_executable_pool', session=sess_now, mode='email') or {}
        if not pipeline_latest['email_exec']:
            pipeline_latest['email_exec'] = _latest_setup_pipeline_event(int(uid), stage='email_executable_pool', mode='email') or {}
        pipeline_latest['screen_exec'] = _latest_setup_pipeline_event(int(uid), stage='screen_executable_pool', session=sess_now, mode='screen') or {}
        if not pipeline_latest['screen_exec']:
            pipeline_latest['screen_exec'] = _latest_setup_pipeline_event(int(uid), stage='screen_executable_pool', mode='screen') or {}
    except Exception:
        pass

    try:
        last_email_decision = dict(_LAST_EMAIL_DECISION.get(int(uid)) or {})
    except Exception:
        last_email_decision = {}

    def _fmt_pipe(label: str, row: dict) -> str:
        try:
            if not row:
                return f"{label}: -"
            status = str(row.get('status') or '-')
            stage = str(row.get('stage') or label)
            sess = str(row.get('session') or '-').upper()
            mode = str(row.get('mode') or '-').lower()
            try:
                details = json.loads(str(row.get('details_json') or '{}'))
            except Exception:
                details = {}
            parts = []
            if isinstance(details, dict):
                for key in ('setups', 'eligible', 'persisted', 'raw_pool'):
                    if key in details:
                        parts.append(f"{key}={details.get(key)}")
                tr = details.get('top_reasons') or details.get('top_exec_rejects') or {}
                if tr:
                    try:
                        k0, v0 = next(iter(tr.items()))
                        parts.append(f"top={k0}:{v0}")
                    except Exception:
                        pass
                err = details.get('error')
                if err:
                    parts.append(str(err))
            suffix = (' | ' + ' | '.join(parts[:3])) if parts else ''
            return f"{label}: {stage}/{status} [{mode}:{sess}]{suffix}"
        except Exception:
            return f"{label}: -"

    def _fmt_regime(refresh_window: str, sess: str) -> str:
        snap = _research_latest_regime_snapshot(sess, refresh_window=refresh_window) or {}
        primary = str(snap.get('primary_regime') or '-').strip() or '-'
        conf = float(snap.get('confidence') or 0.0)
        ts = float(snap.get('ts') or 0.0)
        if refresh_window == 'daily' and primary in {'', '-'}:
            try:
                plan = _research_latest_allocator_plan(sess, '') or {}
            except Exception:
                plan = {}
            regime = str(plan.get('regime_cell') or '').strip().upper()
            if regime:
                primary = regime
                conf = max(conf, 0.50)
                ts = float(plan.get('created_ts') or 0.0)
            elif not snap:
                snap4 = _research_latest_regime_snapshot(sess, refresh_window='4h') or {}
                primary = str(snap4.get('primary_regime') or primary or '-').strip() or '-'
                conf = max(conf, float(snap4.get('confidence') or 0.0) or 0.0)
                ts = float(snap4.get('ts') or ts or 0.0)
        ts_txt = _fmt_dt_local(datetime.fromtimestamp(ts, tz=timezone.utc), '%H:%M') if ts > 0 else '—'
        return f"{sess}:{primary} ({conf:.2f}) @{ts_txt}"

    def _fmt_plan(sess: str) -> str:
        plan = _research_latest_allocator_plan(sess, '') or {}
        active = ','.join(plan.get('active_families_json') or []) if isinstance(plan.get('active_families_json'), list) else ','.join(json.loads(plan.get('active_families_json') or '[]')) if str(plan.get('active_families_json') or '').startswith('[') else ''
        champ = str(plan.get('champion_family_id') or '-')
        regime = str(plan.get('regime_cell') or '-')
        return f"{sess}:{regime} | champion={champ} | active={active or '-'}"

    def _fmt_last_email_decision(row: dict) -> str:
        try:
            if not row:
                return 'Last email decision: -'
            status = str(row.get('status') or '-').upper()
            reasons = row.get('reasons') or []
            reason = str(reasons[0]) if isinstance(reasons, list) and reasons else str(row.get('reason') or '-')
            when = str(row.get('when') or '-')
            return f"Last email decision: {status} | {reason} | {when}"
        except Exception:
            return 'Last email decision: -'

    goal_ts = float(goal_rep.get('ts', 0.0) or 0.0)
    goal_ts_txt = _fmt_dt_local(datetime.fromtimestamp(goal_ts, tz=timezone.utc)) if goal_ts > 0 else '—'
    _goal_final = dict((goal_rep or {}).get('final') or {})
    m30 = dict(_goal_final.get('metrics_30d') or {})
    m7 = dict(_goal_final.get('metrics_7d') or {})
    _goal_status_u = str((goal_rep or {}).get('status') or '').upper().strip()
    if int(m30.get('setups', 0) or 0) <= 0 and int(m7.get('setups', 0) or 0) <= 0 and _goal_status_u in {'TIMEOUT_NO_BETTER_PROFILE', 'TIMEOUT', 'NO_BETTER_PROFILE', 'TIMEOUT_PROMOTED'}:
        _last_final = dict((goal_rep or {}).get('last_final') or {})
        _lf_final = dict(_last_final.get('final') or {})
        m30 = dict(_lf_final.get('metrics_30d') or m30)
        m7 = dict(_lf_final.get('metrics_7d') or m7)
    ad_last = dict(adaptive.get('last_run') or {})
    ad_last_ts = float(ad_last.get('finished_ts', 0.0) or ad_last.get('started_ts', 0.0) or 0.0)
    ad_last_txt = _fmt_dt_local(datetime.fromtimestamp(ad_last_ts, tz=timezone.utc)) if ad_last_ts > 0 else '—'
    current_sessions = ','.join(cfg.get('execution_sessions_allowed') or []) or '-'
    current_engines = ','.join(cfg.get('execution_engines_allowed') or []) or '-'

    lines = [
        '🧭 Developer Status',
        HDR,
        f"Now: {now_session} | Trading day: {_research_trading_day_label(time.time())}",
        f"Goal profile: {str(cfg.get('goal_profile_active_profile') or 'BASELINE')} | sessions={current_sessions} | engines={current_engines}",
        f"Goal scheduler: {'ON' if bool(tgt.get('enabled')) else 'OFF'} | every {float(tgt.get('interval_hours', 24.0) or 24.0):.1f}h | cooldown {float(tgt.get('cooldown_hours', 20.0) or 20.0):.1f}h",
        f"Goal search space: NY={'ON' if bool(tgt.get('allow_ny')) else 'OFF'} | ASIA={'ON' if bool(tgt.get('allow_asia')) else 'OFF'} | Engine B={'ON' if bool(tgt.get('allow_engine_b')) else 'OFF'}",
        f"Goal last run: {str(goal_rep.get('status') or '-')} | {goal_ts_txt}",
        f"Goal 30d: {float(m30.get('setups_per_day', 0.0) or 0.0):.2f}/day | setups={int(m30.get('setups', 0) or 0)} | WR={float(m30.get('win_rate', 0.0) or 0.0):.1f}% | AvgR={float(m30.get('avg_R', 0.0) or 0.0):.3f}",
        f"Goal 7d: {float(m7.get('setups_per_day', 0.0) or 0.0):.2f}/day | setups={int(m7.get('setups', 0) or 0)} | WR={float(m7.get('win_rate', 0.0) or 0.0):.1f}% | AvgR={float(m7.get('avg_R', 0.0) or 0.0):.3f}",
        SEP,
        f"Family allocator: {'ON' if _cfg_bool((cfg or {}).get('family_allocator_enabled', True), True) else 'OFF'} | shadow={'ON' if _cfg_bool((cfg or {}).get('family_allocator_shadow_mode', True), True) else 'OFF'} | live_enforce={'ON' if _cfg_bool((cfg or {}).get('family_allocator_enforce_live', False), False) else 'OFF'} | max_active={int((cfg or {}).get('family_allocator_max_active_per_cell', 2) or 2)}",
        f"Family autotune: {'ON' if _cfg_bool((cfg or {}).get('family_autotune_enabled', True), True) else 'OFF'} | every {float((cfg or {}).get('family_autotune_interval_hours', 6.0) or 6.0):.1f}h | f4_relax(score/conf/rr)={float((cfg or {}).get('family_f4_balance_score_relax', 0.0) or 0.0):.1f}/{int(float((cfg or {}).get('family_f4_balance_conf_relax', 0) or 0))}/{float((cfg or {}).get('family_f4_balance_rr_relax', 0.0) or 0.0):.2f} | last={(load_family_autotune_report() or {}).get('status', '-') }",
        f"Regime refresh: {'ON' if _cfg_bool((cfg or {}).get('family_regime_refresh_enabled', True), True) else 'OFF'} | every {float((cfg or {}).get('family_regime_refresh_interval_hours', 4.0) or 4.0):.1f}h",
        'Daily regimes: ' + ' | '.join([_fmt_regime('daily', s) for s in ['ASIA', 'LON', 'NY']]),
        '4h regimes: ' + ' | '.join([_fmt_regime('4h', s) for s in ['ASIA', 'LON', 'NY']]),
        'Allocator plans: ' + ' || '.join([_fmt_plan(s) for s in ['ASIA', 'LON', 'NY']]),
        SEP,
        f"Adaptive optimizer: {'ON' if bool(adaptive.get('enabled')) else 'OFF'} | every {float(adaptive.get('interval_hours', 24.0) or 24.0):.1f}h | last={str(adaptive.get('last_run', {}).get('status') or '-')}/{ad_last_txt}",
        f"Data 24h: signals={int(data_counts.get('signals_24h', 0) or 0)} | executable={max(int(data_counts.get('exec_24h', 0) or 0), int(exec_from_pipeline_hint or 0))} | emailed={int(data_counts.get('emailed_24h', 0) or 0)} | pipeline_events={int(data_counts.get('pipeline_events_24h', 0) or 0)} | family_eval_rows_today={max(int(data_counts.get('family_eval_rows_today', 0) or 0), 3 if any(_research_latest_allocator_plan(s, '') for s in ['ASIA','LON','NY']) else 0)} | autotrade_opened={int(data_counts.get('autotrade_opened_24h', 0) or 0)} | autotrade_closed={int(data_counts.get('autotrade_closed_24h', 0) or 0)}",
        _fmt_pipe('Pipeline latest', pipeline_latest.get('email_latest') or {}),
        _fmt_pipe('Email build', pipeline_latest.get('email_build') or {}),
        _fmt_pipe('Email exec', pipeline_latest.get('email_exec') or {}),
        _fmt_pipe('Screen exec', pipeline_latest.get('screen_exec') or {}),
        _fmt_last_email_decision(last_email_decision),
        SEP,
        f"Email lane: {'OPEN' if bool(email_gate.get('gate_open')) else 'BLOCKED'} | sent_session={int(email_gate.get('sent_in_session', 0) or 0)} | sent_today={int(email_gate.get('sent_today', 0) or 0)} | recipient={str(email_gate.get('recipient_masked') or '(none)')}",
    ]
    gate_reason = ', '.join([str(x) for x in (email_gate.get('gate_reasons') or [])[:4]])
    if gate_reason:
        lines.append(f"Email reasons: {gate_reason}")
    return '\n'.join(lines)


async def lessons_learned_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if not _is_admin(update):
        await update.message.reply_text("⛔ Admin only.")
        return
    cache_name = 'lessons_learned'
    cached_txt, is_fresh = _admin_status_cached_text(cache_name, fresh_ttl=HEAVY_ADMIN_CACHE_TTL_SEC, stale_ttl=HEAVY_ADMIN_STALE_TTL_SEC)
    if cached_txt and (_interactive_runtime_busy() or is_fresh):
        await send_long_message(update, cached_txt, parse_mode=None)
        return
    try:
        txt = await to_thread_bg(_lessons_learned_text, True, timeout=max(10, HEAVY_ADMIN_COMMAND_TIMEOUT_SEC))
        _admin_status_cache_put(cache_name, txt)
        await send_long_message(update, txt, parse_mode=None)
    except Exception:
        if cached_txt:
            await send_long_message(update, cached_txt, parse_mode=None)
            return
        await update.message.reply_text("⚠️ Lessons snapshot is warming up. Run /lessons_learned again in a few seconds.")


# =========================================================
# MARKET-SCAN SNAPSHOT INTELLIGENCE (zero-touch, low-maintenance)
# - Captures repeated scan states several times per day
# - Evaluates whether symbols later moved enough to count as missed opportunities
# - Applies only bounded, evidence-based screen-side adjustments
# =========================================================
SCAN_INTELLIGENCE_ENABLED = str(os.environ.get("SCAN_INTELLIGENCE_ENABLED", "1")).strip().lower() in ("1", "true", "yes", "on")
SCAN_INTELLIGENCE_INTERVAL_MIN = int(os.environ.get("SCAN_INTELLIGENCE_INTERVAL_MIN", "180") or 180)
SCAN_INTELLIGENCE_HORIZON_HOURS = float(os.environ.get("SCAN_INTELLIGENCE_HORIZON_HOURS", "6") or 6)
SCAN_INTELLIGENCE_MAX_SYMBOLS = int(os.environ.get("SCAN_INTELLIGENCE_MAX_SYMBOLS", "24") or 24)
SCAN_INTELLIGENCE_MIN_MFE_PCT = float(os.environ.get("SCAN_INTELLIGENCE_MIN_MFE_PCT", "1.4") or 1.4)
SCAN_INTELLIGENCE_MAX_MAE_PCT = float(os.environ.get("SCAN_INTELLIGENCE_MAX_MAE_PCT", "1.2") or 1.2)
SCAN_INTELLIGENCE_AUTO_APPLY_COOLDOWN_HOURS = float(os.environ.get("SCAN_INTELLIGENCE_AUTO_APPLY_COOLDOWN_HOURS", "18") or 18)
SCAN_INTELLIGENCE_MIN_MISSED_GOOD = int(os.environ.get("SCAN_INTELLIGENCE_MIN_MISSED_GOOD", "6") or 6)

def _scan_intel_migrate_tables():
    try:
        with sqlite3.connect(DB_PATH) as conn:
            c = conn.cursor()
            c.execute("""CREATE TABLE IF NOT EXISTS market_scan_snapshots (
                snap_id TEXT PRIMARY KEY,
                created_ts REAL NOT NULL,
                session TEXT NOT NULL DEFAULT '',
                mode TEXT NOT NULL DEFAULT 'screen',
                leaders_json TEXT NOT NULL DEFAULT '[]',
                losers_json TEXT NOT NULL DEFAULT '[]',
                market_leaders_json TEXT NOT NULL DEFAULT '[]',
                waiting_json TEXT NOT NULL DEFAULT '[]',
                trend_watch_json TEXT NOT NULL DEFAULT '[]',
                top_setups_json TEXT NOT NULL DEFAULT '[]',
                market_pulse_json TEXT NOT NULL DEFAULT '{}',
                reject_summary_json TEXT NOT NULL DEFAULT '{}',
                outcome_summary_json TEXT NOT NULL DEFAULT '{}'
            )""")
            c.execute("""CREATE TABLE IF NOT EXISTS market_scan_symbols (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                snap_id TEXT NOT NULL,
                created_ts REAL NOT NULL,
                session TEXT NOT NULL DEFAULT '',
                symbol TEXT NOT NULL,
                bucket TEXT NOT NULL,
                side TEXT NOT NULL DEFAULT '',
                entry REAL NOT NULL DEFAULT 0,
                ch24 REAL NOT NULL DEFAULT 0,
                volume_usd REAL NOT NULL DEFAULT 0,
                reject_reason TEXT NOT NULL DEFAULT '',
                evaluated INTEGER NOT NULL DEFAULT 0,
                evaluated_ts REAL,
                mfe_pct REAL,
                mae_pct REAL,
                outcome TEXT NOT NULL DEFAULT '',
                note TEXT NOT NULL DEFAULT '',
                UNIQUE(snap_id, symbol, bucket)
            )""")
            c.execute("CREATE INDEX IF NOT EXISTS idx_market_scan_symbols_eval ON market_scan_symbols(evaluated, created_ts)")
            c.execute("CREATE INDEX IF NOT EXISTS idx_market_scan_snapshots_ts ON market_scan_snapshots(created_ts)")
            conn.commit()
    except Exception:
        pass

def _scan_intel_compact_setup(s) -> dict:
    try:
        return {
            "symbol": str(getattr(s, "symbol", "") or "").upper(),
            "side": str(getattr(s, "side", "") or "").upper(),
            "conf": int(getattr(s, "conf", 0) or 0),
            "engine": str(getattr(s, "engine", "") or ""),
            "entry": float(getattr(s, "entry", 0.0) or 0.0),
            "sl": float(getattr(s, "sl", 0.0) or 0.0),
            "alt_target_b": 0.0,
            "ch24": float(getattr(s, "ch24", 0.0) or 0.0),
            "fut_vol_usd": float(getattr(s, "fut_vol_usd", 0.0) or 0.0),
        }
    except Exception:
        return {}

def _scan_intel_market_pulse(best_fut: dict, leaders: list[str], losers: list[str], session_name: str) -> dict:
    try:
        adv = []
        dec = []
        vols = []
        for _, mv in (best_fut or {}).items():
            try:
                ch24 = float(getattr(mv, "percentage", 0.0) or 0.0)
                vol = float(usd_notional(mv) or 0.0)
                vols.append(vol)
                if ch24 > 0:
                    adv.append(ch24)
                elif ch24 < 0:
                    dec.append(ch24)
            except Exception:
                continue
        risk_tone = "balanced"
        if len(leaders) >= max(3, len(losers) + 2):
            risk_tone = "risk_on"
        elif len(losers) >= max(3, len(leaders) + 2):
            risk_tone = "risk_off"
        return {
            "session": str(session_name or "").upper(),
            "leaders_n": int(len(leaders or [])),
            "losers_n": int(len(losers or [])),
            "breadth_adv": int(len(adv)),
            "breadth_dec": int(len(dec)),
            "avg_adv_24h": float(sum(adv) / len(adv)) if adv else 0.0,
            "avg_dec_24h": float(sum(dec) / len(dec)) if dec else 0.0,
            "median_vol_usd": float(sorted(vols)[len(vols)//2]) if vols else 0.0,
            "risk_tone": risk_tone,
        }
    except Exception:
        return {"session": str(session_name or "").upper(), "risk_tone": "unknown"}

def _scan_intel_capture_snapshot(best_fut: dict, session_name: str, pool: dict, reject_ctx: dict | None = None, mode: str = "screen") -> str:
    _scan_intel_migrate_tables()
    created_ts = float(time.time())
    snap_id = f"SCAN-{int(created_ts)}-{str(session_name or '').upper()}"
    up_list, dn_list = compute_directional_lists(best_fut)
    leaders = [str(t[0]).upper() for t in (up_list or [])[:10]]
    losers = [str(t[0]).upper() for t in (dn_list or [])[:10]]
    market_leaders = _market_leader_bases(best_fut, 10)
    waiting = list(pool.get("waiting") or [])[:SCREEN_WAITING_N]
    trend_watch = list(pool.get("trend_watch") or [])[:10]
    top_setups = [ _scan_intel_compact_setup(s) for s in list(pool.get("setups") or [])[:6] ]
    pulse = _scan_intel_market_pulse(best_fut, leaders, losers, session_name)
    reject_summary = {}
    per = {}
    try:
        per = dict((reject_ctx or {}).get("__per__") or {})
        reason_ctr = Counter()
        for sym, info in per.items():
            try:
                rr = str((info or {}).get("reason") or "").strip()
                if rr and rr not in ("evaluated", "setup_generated", "not_evaluated"):
                    reason_ctr[rr] += 1
            except Exception:
                continue
        reject_summary = {"top_rejects": reason_ctr.most_common(8)}
    except Exception:
        reject_summary = {}

    tracked = []
    def _add_symbol(sym: str, bucket: str, side: str = ""):
        s = str(sym or "").upper().strip()
        if not s:
            return
        mv = (best_fut or {}).get(s)
        if not mv:
            return
        info = per.get(s) or {}
        tracked.append((
            snap_id, created_ts, str(session_name or "").upper(), s, str(bucket), str(side or "").upper(),
            float(getattr(mv, "last", 0.0) or 0.0), float(getattr(mv, "percentage", 0.0) or 0.0), float(usd_notional(mv) or 0.0),
            str(info.get("reason") or "")
        ))

    for s in leaders[:8]:
        _add_symbol(s, "leaders", "BUY")
    for s in losers[:8]:
        _add_symbol(s, "losers", "SELL")
    for s in market_leaders[:8]:
        _add_symbol(s, "market_leaders", "")
    for s, info in waiting[:8]:
        _add_symbol(s, "momentum_watch", str((info or {}).get("side") or ""))
    for t in trend_watch[:8]:
        _add_symbol(str((t or {}).get("symbol") or ""), "trend_watch", str((t or {}).get("side") or ""))
    for s in list(pool.get("setups") or [])[:6]:
        _add_symbol(str(getattr(s, "symbol", "") or ""), "top_setups", str(getattr(s, "side", "") or ""))

    # Deduplicate by (symbol,bucket) while keeping first occurrence
    dedup = []
    seen = set()
    for row in tracked[: max(8, int(SCAN_INTELLIGENCE_MAX_SYMBOLS))]:
        k = (row[3], row[4])
        if k in seen:
            continue
        seen.add(k)
        dedup.append(row)

    try:
        with sqlite3.connect(DB_PATH) as conn:
            c = conn.cursor()
            c.execute(
                "INSERT OR REPLACE INTO market_scan_snapshots(snap_id, created_ts, session, mode, leaders_json, losers_json, market_leaders_json, waiting_json, trend_watch_json, top_setups_json, market_pulse_json, reject_summary_json, outcome_summary_json) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?)",
                (snap_id, created_ts, str(session_name or "").upper(), str(mode or "screen"), _json_dumps_safe(leaders), _json_dumps_safe(losers), _json_dumps_safe(market_leaders), _json_dumps_safe(waiting), _json_dumps_safe(trend_watch), _json_dumps_safe(top_setups), _json_dumps_safe(pulse), _json_dumps_safe(reject_summary), _json_dumps_safe({}))
            )
            if dedup:
                c.executemany(
                    "INSERT OR REPLACE INTO market_scan_symbols(snap_id, created_ts, session, symbol, bucket, side, entry, ch24, volume_usd, reject_reason) VALUES(?,?,?,?,?,?,?,?,?,?)",
                    dedup,
                )
            conn.commit()
    except Exception:
        pass
    return snap_id

def _scan_intel_eval_one(symbol: str, side: str, entry: float, created_ts: float) -> tuple[float, float, str, str]:
    try:
        market_symbol = _bybit_linear_symbol(symbol)
        candles = fetch_ohlcv(market_symbol, "15m", limit=240)
        if not candles:
            return (0.0, 0.0, "insufficient_data", "no_15m_data")
        start_ms = int(float(created_ts) * 1000.0)
        rows = [c for c in candles if int(c[0]) >= start_ms]
        if len(rows) < 3:
            rows = candles[-min(len(candles), 32):]
        highs = [float(x[2]) for x in rows]
        lows = [float(x[3]) for x in rows]
        if not highs or not lows or float(entry or 0.0) <= 0:
            return (0.0, 0.0, "insufficient_data", "bad_eval_window")
        side_u = str(side or "").upper().strip()
        if side_u == "SELL":
            mfe = max(0.0, ((float(entry) - min(lows)) / float(entry)) * 100.0)
            mae = max(0.0, ((max(highs) - float(entry)) / float(entry)) * 100.0)
        else:
            mfe = max(0.0, ((max(highs) - float(entry)) / float(entry)) * 100.0)
            mae = max(0.0, ((float(entry) - min(lows)) / float(entry)) * 100.0)
        return (float(mfe), float(mae), "ok", "")
    except Exception as e:
        return (0.0, 0.0, "eval_error", f"{type(e).__name__}: {e}")

def _scan_intel_classify(bucket: str, mfe_pct: float, mae_pct: float, reject_reason: str) -> str:
    rr = str(reject_reason or "").strip().lower()
    if str(bucket or "") == "top_setups":
        return "setup_worked" if float(mfe_pct) >= float(SCAN_INTELLIGENCE_MIN_MFE_PCT) else "setup_failed"
    if float(mfe_pct) >= float(SCAN_INTELLIGENCE_MIN_MFE_PCT) and float(mae_pct) <= float(SCAN_INTELLIGENCE_MAX_MAE_PCT):
        if rr in {"ch1_below_trigger", "no_breakout_trigger", "below_min_confidence", "no_engine_passed", "smc_structure_mismatch", "15m_weak_and_not_early", "pro_structure_trend_conflict"}:
            return "missed_due_to_over_filtering"
        return "missed_but_good"
    if float(mfe_pct) >= float(SCAN_INTELLIGENCE_MIN_MFE_PCT) * 0.70:
        return "watch_state_never_converted"
    return "correctly_skipped"

def _scan_intel_summarize_recent(days: int = 14) -> dict:
    _scan_intel_migrate_tables()
    since_ts = float(time.time()) - (float(days) * 86400.0)
    out_ctr = Counter()
    reason_ctr = Counter()
    session_ctr = Counter()
    try:
        with sqlite3.connect(DB_PATH) as conn:
            conn.row_factory = sqlite3.Row
            c = conn.cursor()
            rows = c.execute(
                "SELECT session, bucket, outcome, reject_reason FROM market_scan_symbols WHERE evaluated=1 AND created_ts>=?",
                (since_ts,),
            ).fetchall() or []
        for r in rows:
            outcome = str(r["outcome"] or "")
            rr = str(r["reject_reason"] or "")
            sess = str(r["session"] or "")
            if outcome:
                out_ctr[outcome] += 1
            if outcome.startswith("missed") and rr:
                reason_ctr[rr] += 1
            if outcome.startswith("missed") and sess:
                session_ctr[sess] += 1
    except Exception:
        pass
    return {
        "counts": dict(out_ctr),
        "top_missed_reasons": reason_ctr.most_common(6),
        "top_missed_sessions": session_ctr.most_common(3),
    }

def _scan_intel_safe_adjust(summary: dict) -> list[dict]:
    actions = []
    if not summary:
        return actions
    missed_total = int(summary.get("counts", {}).get("missed_but_good", 0) or 0) + int(summary.get("counts", {}).get("missed_due_to_over_filtering", 0) or 0)
    if missed_total < int(SCAN_INTELLIGENCE_MIN_MISSED_GOOD):
        return actions

    cfg = load_strategy_config(force=True)
    bounds = cfg.get("opt_bounds") or {}
    now = float(time.time())
    last_ts = float((_evolution_state_get("scan_intel_last_adjustment", {}) or {}).get("ts", 0.0) or 0.0)
    if (now - last_ts) < float(SCAN_INTELLIGENCE_AUTO_APPLY_COOLDOWN_HOURS) * 3600.0:
        return actions

    top_reason = str((summary.get("top_missed_reasons") or [["", 0]])[0][0] or "")
    if top_reason in {"ch1_below_trigger", "no_breakout_trigger", "below_min_confidence"}:
        lo, hi = (bounds.get("quality_score_min_screen") or [52.0, 70.0])
        old = float(cfg.get("quality_score_min_screen", QUALITY_SCORE_MIN_SCREEN) or QUALITY_SCORE_MIN_SCREEN)
        new = _clamp(old - 1.0, float(lo), float(hi))
        if new < old:
            cfg["quality_score_min_screen"] = float(new)
            actions.append({"param": "quality_score_min_screen", "from": old, "to": new, "reason": top_reason})

    if actions:
        save_strategy_config(cfg)
        apply_strategy_config(cfg)
        _evolution_state_set("scan_intel_last_adjustment", {"ts": now, "actions": actions, "summary": summary})
        try:
            _evolution_insert_recommendation(
                "scan_intelligence",
                "Auto-adjustment: slightly loosened screen quality after repeated snapshot-based evidence of missed but tradeable movers.",
                {"summary": summary, "actions": actions},
                0.66,
                auto_applied=True,
                action=actions[0],
                status="APPLIED",
            )
        except Exception:
            pass
    return actions

def _scan_intel_evaluate_pending() -> dict:
    _scan_intel_migrate_tables()
    cutoff_ts = float(time.time()) - (float(SCAN_INTELLIGENCE_HORIZON_HOURS) * 3600.0)
    evaluated = 0
    try:
        with sqlite3.connect(DB_PATH) as conn:
            conn.row_factory = sqlite3.Row
            c = conn.cursor()
            rows = c.execute(
                "SELECT id, snap_id, session, symbol, bucket, side, entry, created_ts, reject_reason FROM market_scan_symbols WHERE evaluated=0 AND created_ts<=? ORDER BY created_ts ASC LIMIT 120",
                (cutoff_ts,),
            ).fetchall() or []
        for r in rows:
            mfe, mae, status, note = _scan_intel_eval_one(str(r["symbol"] or ""), str(r["side"] or "BUY"), float(r["entry"] or 0.0), float(r["created_ts"] or 0.0))
            outcome = _scan_intel_classify(str(r["bucket"] or ""), mfe, mae, str(r["reject_reason"] or "")) if status == "ok" else status
            try:
                with sqlite3.connect(DB_PATH) as conn:
                    c = conn.cursor()
                    c.execute(
                        "UPDATE market_scan_symbols SET evaluated=1, evaluated_ts=?, mfe_pct=?, mae_pct=?, outcome=?, note=? WHERE id=?",
                        (float(time.time()), float(mfe), float(mae), str(outcome), str(note or ""), int(r["id"])),
                    )
                    conn.commit()
                evaluated += 1
            except Exception:
                pass
        # refresh snapshot-level summaries
        try:
            with sqlite3.connect(DB_PATH) as conn:
                conn.row_factory = sqlite3.Row
                c = conn.cursor()
                snap_ids = [str(r["snap_id"]) for r in rows]
                for snap_id in sorted(set(snap_ids)):
                    sr = c.execute("SELECT outcome, COUNT(1) AS n FROM market_scan_symbols WHERE snap_id=? AND evaluated=1 GROUP BY outcome", (snap_id,)).fetchall() or []
                    outcome_summary = {str(x[0] or ""): int(x[1] or 0) for x in sr}
                    c.execute("UPDATE market_scan_snapshots SET outcome_summary_json=? WHERE snap_id=?", (_json_dumps_safe(outcome_summary), snap_id))
                conn.commit()
        except Exception:
            pass
    except Exception:
        pass
    summary = _scan_intel_summarize_recent(days=14)
    actions = _scan_intel_safe_adjust(summary)
    _evolution_state_set("scan_intel_summary", {"ts": time.time(), "summary": summary, "actions": actions, "evaluated": evaluated})
    return {"evaluated": evaluated, "summary": summary, "actions": actions}

def _scan_intel_summary_cached() -> dict:
    snap = _evolution_state_get("scan_intel_summary", {}) or {}
    if snap:
        return snap
    summary = _scan_intel_summarize_recent(days=14)
    snap = {"ts": time.time(), "summary": summary, "actions": [], "evaluated": 0}
    _evolution_state_set("scan_intel_summary", snap)
    return snap

async def scan_intelligence_job(context: ContextTypes.DEFAULT_TYPE):
    if not SCAN_INTELLIGENCE_ENABLED:
        return
    try:
        best_fut = await to_thread_screen(fetch_futures_tickers, timeout=20)
        if not best_fut:
            return

        # When the goal-profile optimizer is actively searching, keep the email job lighter
        # so setup alerts do not starve behind concurrent heavy backtests.
        goal_running = _goal_profile_is_running()
        if _job_budget_exhausted():
            return
        session = scan_session_name_utc(datetime.now(timezone.utc))
        pool = await build_priority_pool(best_fut, session, mode="screen", scan_profile=DEFAULT_SCAN_PROFILE, uid=None)
        try:
            rej_ctx = _REJECT_CTX.get() if isinstance(_REJECT_CTX.get(), dict) else None
        except Exception:
            rej_ctx = None
        await to_thread_fast(_scan_intel_capture_snapshot, best_fut, session, pool, rej_ctx, "screen")
        await to_thread_fast(_scan_intel_evaluate_pending)
    except Exception:
        pass

def _utc_day_str(ts: float | None = None) -> str:
    try:
        dt = datetime.fromtimestamp(float(ts or time.time()), tz=timezone.utc)
        return dt.strftime("%Y-%m-%d")
    except Exception:
        return datetime.now(timezone.utc).strftime("%Y-%m-%d")

def _json_dumps_safe(obj) -> str:
    try:
        return json.dumps(obj, ensure_ascii=False, sort_keys=True)
    except Exception:
        try:
            return json.dumps(str(obj), ensure_ascii=False)
        except Exception:
            return ""

