def _goal_profile_profile_bundles(profile_name: str, bundles: list[dict]) -> list[dict]:
    name = str(profile_name or '').upper().strip()
    if not bundles:
        return []
    by_name = {str((b or {}).get('name') or '').strip(): dict(b or {}) for b in (bundles or [])}
    preferred = {
        'LON_A_ONLY': ['strict', 'balanced'],
        'LON_A_REACH': ['flex', 'reach'],
        'LON_C_ONLY': ['balanced', 'c_breakout_focus'],
        'LON_A_C_ONLY': ['balanced'],
        'LON_A_C_REACH': ['flex', 'reach'],
    }.get(name, [])
    out = [by_name[n] for n in preferred if n in by_name]
    if out:
        return out
    return list(bundles or [])

def _goal_profile_apply_candidate(base_cfg: dict, profile: dict, bundle: dict) -> dict:
    cfg = json.loads(json.dumps(base_cfg or {}))
    cfg['quality_score_min_screen'] = float(bundle.get('quality_score_min_screen', cfg.get('quality_score_min_screen', QUALITY_SCORE_MIN_SCREEN)))
    cfg['quality_score_min_email'] = float(bundle.get('quality_score_min_email', cfg.get('quality_score_min_email', QUALITY_SCORE_MIN_EMAIL)))
    cfg['tf_align_1h_min_abs'] = float(bundle.get('tf_align_1h_min_abs', cfg.get('tf_align_1h_min_abs', TF_ALIGN_1H_MIN_ABS)))
    cfg['tf_align_4h_min_abs'] = float(bundle.get('tf_align_4h_min_abs', cfg.get('tf_align_4h_min_abs', TF_ALIGN_4H_MIN_ABS)))
    cfg['atr_min_pct'] = float(bundle.get('atr_min_pct', cfg.get('atr_min_pct', ATR_MIN_PCT)))
    cfg['min_rr_tp'] = float(bundle.get('min_rr_tp', cfg.get('min_rr_tp', MIN_RR_TP)))
    cfg['regime_slope_trend_min_pct'] = float(bundle.get('regime_slope_trend_min_pct', cfg.get('regime_slope_trend_min_pct', 0.06)))
    cfg['execution_sessions_allowed'] = [str(x).upper().strip() for x in (profile.get('execution_sessions_allowed') or ['LON']) if str(x).strip()]
    cfg['execution_engines_allowed'] = [str(x).upper().strip() for x in (profile.get('execution_engines_allowed') or ['A']) if str(x).strip()]
    cfg['execution_asia_enabled'] = bool(profile.get('execution_asia_enabled', False))
    cfg['execution_asia_user_override'] = True
    cfg['execution_engine_b_email_enabled'] = bool(profile.get('execution_engine_b_email_enabled', False))
    cfg['goal_profile_active_profile'] = str(profile.get('name') or 'PROFILE')
    bundle_name = str(bundle.get('name') or '').upper().strip()
    profile_name = str(profile.get('name') or '').upper().strip()
    cfg['goal_profile_reach_mode'] = bool(('REACH' in profile_name) or bundle_name in {'FLEX', 'REACH', 'C_BREAKOUT_FOCUS'})
    sess_ov = json.loads(json.dumps(cfg.get('session_exec_overrides') or {}))
    for sess in ('NY', 'LON', 'ASIA'):
        sess_ov.setdefault(sess, {'quality_add': 0.0, 'conf_add': 0, 'rr_add': 0.0})
    sess_ov['LON'] = {
        'quality_add': float(bundle.get('lon_quality_add', 0.0) or 0.0),
        'conf_add': int(bundle.get('lon_conf_add', 0) or 0),
        'rr_add': float(bundle.get('lon_rr_add', 0.0) or 0.0),
    }
    if 'NY' not in cfg.get('execution_sessions_allowed', []):
        sess_ov['NY'] = {'quality_add': max(2.0, float((sess_ov.get('NY') or {}).get('quality_add', 0.0) or 0.0)), 'conf_add': max(2, int((sess_ov.get('NY') or {}).get('conf_add', 0) or 0)), 'rr_add': max(0.12, float((sess_ov.get('NY') or {}).get('rr_add', 0.0) or 0.0))}
    if 'ASIA' not in cfg.get('execution_sessions_allowed', []):
        sess_ov['ASIA'] = {'quality_add': max(3.0, float((sess_ov.get('ASIA') or {}).get('quality_add', 0.0) or 0.0)), 'conf_add': max(3, int((sess_ov.get('ASIA') or {}).get('conf_add', 0) or 0)), 'rr_add': max(0.16, float((sess_ov.get('ASIA') or {}).get('rr_add', 0.0) or 0.0))}
    cfg['session_exec_overrides'] = sess_ov
    weights = {'NY': 0.0, 'LON': 0.0, 'ASIA': 0.0}
    allowed = cfg.get('execution_sessions_allowed') or []
    if allowed == ['LON']:
        weights = {'NY': 0.0, 'LON': 1.0, 'ASIA': 0.0}
    elif allowed == ['LON', 'NY'] or allowed == ['NY', 'LON']:
        weights = {'NY': 0.35, 'LON': 0.65, 'ASIA': 0.0}
    else:
        for sess in allowed:
            if sess in weights:
                weights[sess] = 1.0
        tot = sum(weights.values()) or 1.0
        weights = {k: float(v) / float(tot) for k, v in weights.items()}
    cfg['session_weights'] = weights
    return cfg


def _goal_profile_summary_from_rep(rep: dict) -> dict:
    ov = dict((rep or {}).get('overall') or {})
    return {
        'setups': int(ov.get('setups', 0) or 0),
        'setups_per_day': float(ov.get('setups_per_day', 0.0) or 0.0),
        'win_rate': float(ov.get('win_rate', 0.0) or 0.0),
        'avg_R': float(ov.get('avg_R', 0.0) or 0.0),
    }


def _goal_profile_stage1_score(rep30: dict, cfg: dict) -> dict:
    tgt = _goal_profile_targets(cfg)
    s30 = _goal_profile_summary_from_rep(rep30)
    n30 = int(s30['setups'])
    sdp30 = float(s30['setups_per_day'])
    wr30 = float(s30['win_rate'])
    ar30 = float(s30['avg_R'])

    def _freq_pen(v: float, lo: float, hi: float, weight_under: float, weight_over: float) -> float:
        if v < lo:
            return (lo - v) * weight_under
        if v > hi:
            return (v - hi) * weight_over
        return 0.0

    freq_pen = _freq_pen(sdp30, tgt['target_lo'], tgt['target_hi'], 40.0, 18.0)
    wr_pen = max(0.0, tgt['target_wr'] - wr30) * 2.4
    avg_r_pen = max(0.0, tgt['target_avg_r'] - ar30) * 62.0
    sample_pen = max(0, tgt['min_live_30d'] - n30) * 7.0
    zero_pen = 350.0 if n30 <= 0 else 0.0
    score = (wr30 * 2.2) + (ar30 * 55.0) + (sdp30 * 10.0) - freq_pen - wr_pen - avg_r_pen - sample_pen - zero_pen
    return {
        'score': float(score),
        'metrics_30d': s30,
        'penalties': {
            'freq_pen': float(freq_pen),
            'wr_pen': float(wr_pen),
            'avg_r_pen': float(avg_r_pen),
            'sample_pen': float(sample_pen),
            'zero_pen': float(zero_pen),
        },
    }


def _goal_profile_score_candidate(rep30: dict, rep7: dict, cfg: dict) -> dict:
    tgt = _goal_profile_targets(cfg)
    s30 = _goal_profile_summary_from_rep(rep30)
    s7 = _goal_profile_summary_from_rep(rep7)
    n30 = int(s30['setups'])
    n7 = int(s7['setups'])
    sdp30 = float(s30['setups_per_day'])
    sdp7 = float(s7['setups_per_day'])
    wr30 = float(s30['win_rate'])
    wr7 = float(s7['win_rate'])
    ar30 = float(s30['avg_R'])
    ar7 = float(s7['avg_R'])

    def _freq_pen(v: float, lo: float, hi: float, weight_under: float, weight_over: float) -> float:
        if v < lo:
            return (lo - v) * weight_under
        if v > hi:
            return (v - hi) * weight_over
        return 0.0

    freq_pen = _freq_pen(sdp30, tgt['target_lo'], tgt['target_hi'], 52.0, 18.0) + _freq_pen(sdp7, tgt['target_lo'], tgt['target_hi'], 18.0, 5.0)
    wr_pen = max(0.0, tgt['target_wr'] - wr30) * 2.3 + max(0.0, tgt['target_wr'] - wr7) * 0.6
    avg_r_pen = max(0.0, tgt['target_avg_r'] - ar30) * 65.0 + max(0.0, tgt['target_avg_r'] - ar7) * 18.0
    sample_pen = max(0, tgt['min_live_30d'] - n30) * 7.0 + max(0, tgt['min_live_7d'] - n7) * 4.5
    instability_pen = abs(wr30 - wr7) * (0.10 if (n30 > 0 and n7 > 0) else 0.0)
    zero_pen = 350.0 if n30 <= 0 else 0.0
    score = (wr30 * 2.1) + (wr7 * 0.6) + (ar30 * 55.0) + (ar7 * 15.0) + (sdp30 * 14.0) + (sdp7 * 4.0) - freq_pen - wr_pen - avg_r_pen - sample_pen - instability_pen - zero_pen
    feasible = bool(n30 >= tgt['min_live_30d'] and n7 >= tgt['min_live_7d'] and wr30 >= tgt['target_wr'] and ar30 >= tgt['target_avg_r'] and sdp30 >= (tgt['target_lo'] * 0.70) and sdp30 <= (tgt['target_hi'] * 1.25))
    return {
        'score': float(score),
        'feasible': feasible,
        'metrics_30d': s30,
        'metrics_7d': s7,
        'penalties': {
            'freq_pen': float(freq_pen),
            'wr_pen': float(wr_pen),
            'avg_r_pen': float(avg_r_pen),
            'sample_pen': float(sample_pen),
            'instability_pen': float(instability_pen),
            'zero_pen': float(zero_pen),
        },
    }


def _goal_profile_is_due(now_ts: float | None = None, cfg: dict | None = None, rep: dict | None = None) -> bool:
    now_ts = float(now_ts or time.time())
    cfg = dict(cfg or load_strategy_config(force=False) or {})
    tgt = _goal_profile_targets(cfg)
    if not bool(tgt.get('enabled')):
        return False
    rep = dict(rep or load_goal_profile_report() or {})
    status = str(rep.get('status') or '').upper().strip()
    if status in {'RUNNING', 'STOPPING'} and _goal_profile_is_running():
        return False
    last_ts = max(
        float(rep.get('ts', 0.0) or 0.0),
        float((cfg or {}).get('goal_profile_last_run_ts', 0.0) or 0.0),
        float(rep.get('started_ts', 0.0) or 0.0),
    )
    if last_ts <= 0:
        return True
    due_after = max(3600.0, float(tgt.get('interval_hours', 24.0) or 24.0) * 3600.0)
    return (now_ts - last_ts) >= max(60.0, due_after - 120.0)


def _run_goal_profile_cycle(force: bool = False) -> dict:
    cfg0 = load_strategy_config(force=True)
    tgt = _goal_profile_targets(cfg0)
    now_ts = float(time.time())
    current_profile = str((cfg0 or {}).get('goal_profile_active_profile') or 'BASELINE')
    current_sessions = list((cfg0 or {}).get('execution_sessions_allowed') or [])
    current_engines = list((cfg0 or {}).get('execution_engines_allowed') or [])
    if not tgt['enabled']:
        rep = {
            'ok': False,
            'status': 'DISABLED',
            'ts': now_ts,
            'started_ts': now_ts,
            'targets': tgt,
            'current': {
                'goal_profile_active_profile': current_profile,
                'execution_sessions_allowed': current_sessions,
                'execution_engines_allowed': current_engines,
            },
        }
        save_goal_profile_report(rep)
        return rep
    if not _GOAL_PROFILE_LOCK.acquire(blocking=False):
        rep = load_goal_profile_report() or {}
        return {
            'ok': False,
            'status': 'BUSY',
            'ts': now_ts,
            'started_ts': float(rep.get('started_ts', now_ts) or now_ts),
            'targets': tgt,
            'current': {
                'goal_profile_active_profile': current_profile,
                'execution_sessions_allowed': current_sessions,
                'execution_engines_allowed': current_engines,
            },
        }
    started_ts = float(time.time())
    stop_event = threading.Event()
    _GOAL_PROFILE_STATE['stop_event'] = stop_event
    _GOAL_PROFILE_STATE['started_ts'] = started_ts
    _GOAL_PROFILE_STATE['run_id'] = f"goal-{int(started_ts)}"
    last_final = load_goal_profile_report() or {}
    if str(last_final.get('status') or '').upper() == 'RUNNING':
        last_final = {}

    def _persist_running(stage: str, candidate_idx: int = 0, candidate_total: int = 0, current_candidate: dict | None = None, best_candidate: dict | None = None, note: str = ''):
        rep = {
            'ok': True,
            'status': 'RUNNING',
            'ts': float(time.time()),
            'started_ts': started_ts,
            'targets': tgt,
            'current': {
                'goal_profile_active_profile': current_profile,
                'execution_sessions_allowed': current_sessions,
                'execution_engines_allowed': current_engines,
            },
            'progress': {
                'stage': str(stage or 'running'),
                'candidate_idx': int(candidate_idx or 0),
                'candidate_total': int(candidate_total or 0),
                'current_candidate': current_candidate or {},
                'best_candidate': best_candidate or {},
                'elapsed_sec': float(max(0.0, time.time() - started_ts)),
                'note': str(note or ''),
            },
            'last_final': last_final if isinstance(last_final, dict) else {},
        }
        save_goal_profile_report(rep)

    try:
        if (not force) and float(last_final.get('applied_ts', 0.0) or 0.0) > 0 and (time.time() - float(last_final.get('applied_ts', 0.0) or 0.0)) < (tgt['cooldown_hours'] * 3600.0):
            rep = {'ok': False, 'status': 'COOLDOWN', 'ts': float(time.time()), 'started_ts': started_ts, 'targets': tgt, 'last': last_final}
            save_goal_profile_report(rep)
            return rep

        base_cfg = json.loads(json.dumps(cfg0 or {}))
        exec_tf = str((base_cfg or {}).get('universe_backtest_exec_tf') or (base_cfg or {}).get('exec_tf_default') or '15m').strip().lower()
        top_n = int((base_cfg or {}).get('universe_backtest_top_n', 80) or 80)
        max_run_sec = max(180.0, float(tgt.get('max_run_minutes', 18.0) or 18.0) * 60.0)

        save_strategy_config(base_cfg)
        apply_strategy_config(base_cfg)
        _persist_running('baseline')
        baseline30 = run_universe_backtest(30, 'ALL', exec_tf, top_n, None, False, False)
        baseline7 = run_universe_backtest(7, 'ALL', exec_tf, top_n, None, False, False)
        baseline_eval = _goal_profile_score_candidate(baseline30, baseline7, base_cfg)

        best_cfg = json.loads(json.dumps(base_cfg))
        best_eval = dict(baseline_eval)
        best_profile = {'name': 'BASELINE'}
        best_bundle = {'name': 'current'}
        stage1_rows = []
        stage2_rows = []
        profiles = _goal_profile_candidate_profiles(base_cfg)
        bundles = _goal_profile_candidate_bundles(base_cfg)
        bundle_plan = {str((p or {}).get('name') or ''): _goal_profile_profile_bundles(str((p or {}).get('name') or ''), bundles) for p in profiles}
        candidate_total = max(0, sum(len(bundle_plan.get(str((p or {}).get('name') or ''), [])) for p in profiles))
        cand_counter = 0

        for profile in profiles:
            for bundle in (bundle_plan.get(str((profile or {}).get('name') or ''), []) or []):
                cand_counter += 1
                if stop_event.is_set():
                    raise TimeoutError('goal_profile_aborted')
                if (time.time() - started_ts) > max_run_sec:
                    raise TimeoutError('goal_profile_timeout')
                current_row = {
                    'profile': str(profile.get('name') or ''),
                    'bundle': str(bundle.get('name') or ''),
                    'sessions': list(profile.get('execution_sessions_allowed') or []),
                    'engines': list(profile.get('execution_engines_allowed') or []),
                }
                _persist_running('search_30d', cand_counter, candidate_total, current_row, {
                    'profile': str(best_profile.get('name') or 'BASELINE'),
                    'bundle': str(best_bundle.get('name') or 'current'),
                    'score': float(best_eval.get('score', -1e9)),
                })
                cand_cfg = _goal_profile_apply_candidate(base_cfg, profile, bundle)
                apply_strategy_config(cand_cfg)
                rep30 = run_universe_backtest(30, 'ALL', exec_tf, top_n, None, False, False)
                apply_strategy_config(base_cfg)
                stage1 = _goal_profile_stage1_score(rep30, cand_cfg)
                stage1_rows.append({
                    'profile': str(profile.get('name') or ''),
                    'bundle': str(bundle.get('name') or ''),
                    'stage1_score': float(stage1.get('score', -1e9)),
                    'metrics_30d': stage1.get('metrics_30d') or {},
                    'penalties_30d': stage1.get('penalties') or {},
                    'execution_sessions_allowed': list(cand_cfg.get('execution_sessions_allowed') or []),
                    'execution_engines_allowed': list(cand_cfg.get('execution_engines_allowed') or []),
                    'cand_cfg': cand_cfg,
                })

        shortlist_n = max(1, min(int(tgt.get('shortlist', 4) or 4), len(stage1_rows) or 1))
        shortlist = sorted(stage1_rows, key=lambda x: float(x.get('stage1_score', -1e9)), reverse=True)[:shortlist_n]

        for idx, row in enumerate(shortlist, start=1):
            if stop_event.is_set():
                raise TimeoutError('goal_profile_aborted')
            if (time.time() - started_ts) > max_run_sec:
                raise TimeoutError('goal_profile_timeout')
            current_row = {
                'profile': str(row.get('profile') or ''),
                'bundle': str(row.get('bundle') or ''),
                'sessions': list(row.get('execution_sessions_allowed') or []),
                'engines': list(row.get('execution_engines_allowed') or []),
            }
            _persist_running('search_7d', idx, len(shortlist), current_row, {
                'profile': str(best_profile.get('name') or 'BASELINE'),
                'bundle': str(best_bundle.get('name') or 'current'),
                'score': float(best_eval.get('score', -1e9)),
            }, note=f"shortlist={len(shortlist)} of {candidate_total}")
            cand_cfg = dict(row.get('cand_cfg') or {})
            apply_strategy_config(cand_cfg)
            rep7 = run_universe_backtest(7, 'ALL', exec_tf, top_n, None, False, False)
            apply_strategy_config(base_cfg)
            evald = _goal_profile_score_candidate({'overall': row.get('metrics_30d') or {}}, rep7, cand_cfg)
            full_row = {
                'profile': str(row.get('profile') or ''),
                'bundle': str(row.get('bundle') or ''),
                'score': float(evald.get('score', -1e9)),
                'feasible': bool(evald.get('feasible')),
                'metrics_30d': evald.get('metrics_30d') or {},
                'metrics_7d': evald.get('metrics_7d') or {},
                'penalties': evald.get('penalties') or {},
                'execution_sessions_allowed': list(cand_cfg.get('execution_sessions_allowed') or []),
                'execution_engines_allowed': list(cand_cfg.get('execution_engines_allowed') or []),
            }
            stage2_rows.append(full_row)
            if float(evald.get('score', -1e9)) > float(best_eval.get('score', -1e9)):
                best_cfg = json.loads(json.dumps(cand_cfg))
                best_eval = dict(evald)
                best_profile = {'name': str(row.get('profile') or '')}
                best_bundle = {'name': str(row.get('bundle') or '')}

        promoted = bool(best_eval.get('feasible')) and float(best_eval.get('score', -1e9)) > float(baseline_eval.get('score', -1e9)) + 0.5
        final_cfg = json.loads(json.dumps(best_cfg if promoted else base_cfg))
        final_eval = dict(best_eval if promoted else baseline_eval)
        final_cfg['goal_profile_last_run_ts'] = float(time.time())
        save_strategy_config(final_cfg)
        apply_strategy_config(final_cfg)

        report = {
            'ok': True,
            'status': 'PROMOTED' if promoted else 'NO_BETTER_PROFILE',
            'ts': float(time.time()),
            'started_ts': started_ts,
            'finished_ts': float(time.time()),
            'applied_ts': float(time.time()) if promoted else float((last_final or {}).get('applied_ts', 0.0) or 0.0),
            'targets': tgt,
            'current': {
                'goal_profile_active_profile': str(final_cfg.get('goal_profile_active_profile') or current_profile),
                'execution_sessions_allowed': list(final_cfg.get('execution_sessions_allowed') or current_sessions),
                'execution_engines_allowed': list(final_cfg.get('execution_engines_allowed') or current_engines),
            },
            'baseline': {'score': float(baseline_eval.get('score', -1e9)), 'metrics_30d': baseline_eval.get('metrics_30d') or {}, 'metrics_7d': baseline_eval.get('metrics_7d') or {}},
            'best_candidate': {'profile': str(best_profile.get('name') or ''), 'bundle': str(best_bundle.get('name') or ''), 'score': float(best_eval.get('score', -1e9)), 'feasible': bool(best_eval.get('feasible')), 'metrics_30d': best_eval.get('metrics_30d') or {}, 'metrics_7d': best_eval.get('metrics_7d') or {}, 'execution_sessions_allowed': list(best_cfg.get('execution_sessions_allowed') or []), 'execution_engines_allowed': list(best_cfg.get('execution_engines_allowed') or [])},
            'final': {'score': float(final_eval.get('score', -1e9)), 'metrics_30d': final_eval.get('metrics_30d') or {}, 'metrics_7d': final_eval.get('metrics_7d') or {}, 'execution_sessions_allowed': list(final_cfg.get('execution_sessions_allowed') or []), 'execution_engines_allowed': list(final_cfg.get('execution_engines_allowed') or []), 'goal_profile_active_profile': str(final_cfg.get('goal_profile_active_profile') or 'BASELINE')},
            'progress': {'stage': 'done', 'candidate_idx': len(stage2_rows), 'candidate_total': len(shortlist), 'elapsed_sec': float(max(0.0, time.time() - started_ts)), 'shortlist_from': int(candidate_total)},
            'top_candidates': sorted(stage2_rows, key=lambda x: float(x.get('score', -1e9)), reverse=True)[:8],
            'stage1_shortlist': [{k: v for k, v in row.items() if k != 'cand_cfg'} for row in shortlist],
        }
        save_goal_profile_report(report)
        return report
    except TimeoutError as e:
        status = 'ABORTED' if 'aborted' in str(e).lower() else 'TIMEOUT'
        timed_out = (status == 'TIMEOUT')
        partial_best_cfg = None
        partial_best_eval = None
        partial_best_profile = {'name': ''}
        partial_best_bundle = {'name': ''}
        try:
            partial_best_cfg = json.loads(json.dumps(best_cfg)) if isinstance(best_cfg, dict) else None
            partial_best_eval = dict(best_eval) if isinstance(best_eval, dict) else None
            partial_best_profile = dict(best_profile) if isinstance(best_profile, dict) else {'name': ''}
            partial_best_bundle = dict(best_bundle) if isinstance(best_bundle, dict) else {'name': ''}
        except Exception:
            partial_best_cfg = None
            partial_best_eval = None
        if timed_out and (not stage2_rows) and stage1_rows:
            try:
                top_stage1 = sorted(stage1_rows, key=lambda x: float(x.get('stage1_score', -1e9)), reverse=True)[0]
                cand_cfg = dict(top_stage1.get('cand_cfg') or {})
                if cand_cfg:
                    apply_strategy_config(cand_cfg)
                    rep7 = run_universe_backtest(7, 'ALL', exec_tf, top_n, None, False, False)
                    apply_strategy_config(base_cfg)
                    evald = _goal_profile_score_candidate({'overall': top_stage1.get('metrics_30d') or {}}, rep7, cand_cfg)
                    partial_best_cfg = json.loads(json.dumps(cand_cfg))
                    partial_best_eval = dict(evald)
                    partial_best_profile = {'name': str(top_stage1.get('profile') or '')}
                    partial_best_bundle = {'name': str(top_stage1.get('bundle') or '')}
                    stage2_rows.append({
                        'profile': str(top_stage1.get('profile') or ''),
                        'bundle': str(top_stage1.get('bundle') or ''),
                        'score': float(evald.get('score', -1e9)),
                        'feasible': bool(evald.get('feasible')),
                        'metrics_30d': evald.get('metrics_30d') or {},
                        'metrics_7d': evald.get('metrics_7d') or {},
                        'penalties': evald.get('penalties') or {},
                        'execution_sessions_allowed': list(cand_cfg.get('execution_sessions_allowed') or []),
                        'execution_engines_allowed': list(cand_cfg.get('execution_engines_allowed') or []),
                    })
            except Exception:
                try:
                    apply_strategy_config(base_cfg)
                except Exception:
                    pass
        baseline_score = float((baseline_eval or {}).get('score', -1e9) if isinstance(locals().get('baseline_eval'), dict) else -1e9)
        best_score = float((partial_best_eval or {}).get('score', -1e9) if isinstance(partial_best_eval, dict) else -1e9)
        promote_partial = bool(timed_out and isinstance(partial_best_cfg, dict) and isinstance(partial_best_eval, dict) and bool(partial_best_eval.get('feasible')) and best_score > baseline_score + 0.5)
        final_cfg = json.loads(json.dumps(partial_best_cfg if promote_partial else (cfg0 or {})))
        try:
            final_cfg['goal_profile_last_run_ts'] = float(time.time())
        except Exception:
            pass
        try:
            save_strategy_config(final_cfg)
            apply_strategy_config(final_cfg)
        except Exception:
            pass
        final_eval = dict(partial_best_eval) if (promote_partial and isinstance(partial_best_eval, dict)) else (dict(baseline_eval) if isinstance(locals().get('baseline_eval'), dict) else {})
        final_status = 'TIMEOUT_PROMOTED' if promote_partial else ('TIMEOUT_NO_BETTER_PROFILE' if timed_out and baseline_score >= best_score else status)
        if timed_out and isinstance(partial_best_eval, dict) and (not bool(partial_best_eval.get('feasible'))):
            status_note = 'best_timeout_candidate_infeasible_not_promoted'
        else:
            status_note = ''
        err_report = {
            'ok': False,
            'status': final_status,
            'ts': float(time.time()),
            'started_ts': started_ts,
            'finished_ts': float(time.time()),
            'targets': tgt,
            'error': str(e),
            'note': str(status_note or ''),
            'current': {
                'goal_profile_active_profile': str(final_cfg.get('goal_profile_active_profile') or current_profile),
                'execution_sessions_allowed': list(final_cfg.get('execution_sessions_allowed') or current_sessions),
                'execution_engines_allowed': list(final_cfg.get('execution_engines_allowed') or current_engines),
            },
            'baseline': {'score': baseline_score, 'metrics_30d': (baseline_eval or {}).get('metrics_30d') or {}, 'metrics_7d': (baseline_eval or {}).get('metrics_7d') or {}},
            'best_candidate': {
                'profile': str((partial_best_profile or {}).get('name') or ''),
                'bundle': str((partial_best_bundle or {}).get('name') or ''),
                'score': best_score,
                'feasible': bool((partial_best_eval or {}).get('feasible')) if isinstance(partial_best_eval, dict) else False,
                'metrics_30d': (partial_best_eval or {}).get('metrics_30d') or {},
                'metrics_7d': (partial_best_eval or {}).get('metrics_7d') or {},
                'execution_sessions_allowed': list((partial_best_cfg or {}).get('execution_sessions_allowed') or []),
                'execution_engines_allowed': list((partial_best_cfg or {}).get('execution_engines_allowed') or []),
            },
            'final': {
                'score': float(final_eval.get('score', -1e9)) if isinstance(final_eval, dict) else -1e9,
                'metrics_30d': (final_eval or {}).get('metrics_30d') or {},
                'metrics_7d': (final_eval or {}).get('metrics_7d') or {},
                'execution_sessions_allowed': list(final_cfg.get('execution_sessions_allowed') or current_sessions),
                'execution_engines_allowed': list(final_cfg.get('execution_engines_allowed') or current_engines),
                'goal_profile_active_profile': str(final_cfg.get('goal_profile_active_profile') or current_profile),
            },
            'progress': {
                'stage': 'timeout_finalize' if timed_out else 'aborted',
                'candidate_idx': int(len(stage1_rows) if isinstance(locals().get('stage1_rows'), list) else 0),
                'candidate_total': int(candidate_total if 'candidate_total' in locals() else 0),
                'elapsed_sec': float(max(0.0, time.time() - started_ts)),
                'shortlist_from': int(len(stage1_rows) if isinstance(locals().get('stage1_rows'), list) else 0),
            },
            'top_candidates': sorted(stage2_rows, key=lambda x: float(x.get('score', -1e9)), reverse=True)[:8] if isinstance(locals().get('stage2_rows'), list) else [],
            'last_final': last_final if isinstance(last_final, dict) else {},
        }
        save_goal_profile_report(err_report)
        return err_report
    except Exception as e:
        try:
            save_strategy_config(cfg0 or {})
            apply_strategy_config(cfg0 or {})
            err_cfg = load_strategy_config(force=True)
        except Exception:
            err_cfg = cfg0 or {}
        err_report = {
            'ok': False,
            'status': 'ERROR',
            'ts': float(time.time()),
            'started_ts': started_ts,
            'finished_ts': float(time.time()),
            'targets': tgt,
            'error': f'{type(e).__name__}: {e}',
            'current': {
                'goal_profile_active_profile': str((err_cfg or {}).get('goal_profile_active_profile') or current_profile),
                'execution_sessions_allowed': list((err_cfg or {}).get('execution_sessions_allowed') or current_sessions),
                'execution_engines_allowed': list((err_cfg or {}).get('execution_engines_allowed') or current_engines),
            },
            'last_final': last_final if isinstance(last_final, dict) else {},
        }
        save_goal_profile_report(err_report)
        return err_report
    finally:
        try:
            ev = _GOAL_PROFILE_STATE.get('stop_event')
            if ev is not None:
                ev.set()
        except Exception:
            pass
        _GOAL_PROFILE_STATE['stop_event'] = None
        _GOAL_PROFILE_STATE['started_ts'] = 0.0
        _GOAL_PROFILE_STATE['run_id'] = ''
        _GOAL_PROFILE_LOCK.release()


async def goal_profile_abort_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if not _is_admin(update):
        await update.message.reply_text('⛔ Admin only.')
        return
    ev = _GOAL_PROFILE_STATE.get('stop_event')
    if ev is None or ev.is_set():
        await update.message.reply_text('No goal-profile optimizer run is active.')
        return
    ev.set()
    rep = load_goal_profile_report() or {}
    rep['status'] = 'STOPPING'
    rep['ts'] = float(time.time())
    prog = dict(rep.get('progress') or {})
    prog['note'] = 'Abort requested by admin.'
    rep['progress'] = prog
    save_goal_profile_report(rep)
    await update.message.reply_text('🛑 Goal-profile optimizer abort requested. It will stop after the current evaluation step.')


async def goal_profile_run_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if not _is_admin(update):
        await update.message.reply_text('⛔ Admin only.')
        return
    force = False
    try:
        args = list(context.args or [])
        force = bool(args and str(args[0]).strip().lower() in ('force', 'now', 'override'))
    except Exception:
        force = False
    await update.message.reply_text('✅ Goal-profile optimizer has been queued in the background. Use /goal_status for the latest cached/progress snapshot.')
    async def _runner():
        try:
            rep = await to_thread_bg(_run_goal_profile_cycle, force, timeout=3600)
            if isinstance(rep, dict) and rep.get('ok'):
                _hb_touch('goal_profile', ok=True, details='manual_run_ok')
            else:
                _hb_touch('goal_profile', ok=True, details=f"manual_run_{str((rep or {}).get('status') or 'skipped').lower()}")
        except Exception as e:
            _hb_touch('goal_profile', ok=False, error=f"{type(e).__name__}: {e}", details='manual_run_error')
    try:
        _safe_create_task(_runner(), 'manual_optimizer_runner')
    except Exception:
        pass

async def goal_profile_status_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if not _is_admin(update):
        await update.message.reply_text('⛔ Admin only.')
        return
    cfg = load_strategy_config(force=False)
    tgt = _goal_profile_targets(cfg)
    rep = load_goal_profile_report() or {}
    final = rep.get('final') or {}
    current = rep.get('current') or {}
    m30 = dict(final.get('metrics_30d') or {})
    m7 = dict(final.get('metrics_7d') or {})
    _goal_status_u = str(rep.get('status') or '').upper().strip()
    _goal_metrics_missing = (int(m30.get('setups', 0) or 0) <= 0 and int(m7.get('setups', 0) or 0) <= 0)
    if _goal_metrics_missing and _goal_status_u in {'TIMEOUT_NO_BETTER_PROFILE', 'TIMEOUT', 'NO_BETTER_PROFILE', 'TIMEOUT_PROMOTED'}:
        _last_final = dict(rep.get('last_final') or {})
        _lf_final = dict(_last_final.get('final') or {})
        _m30_fallback = dict(_lf_final.get('metrics_30d') or {})
        _m7_fallback = dict(_lf_final.get('metrics_7d') or {})
        if _m30_fallback or _m7_fallback:
            m30 = _m30_fallback or m30
            m7 = _m7_fallback or m7
    current_profile = str(cfg.get('goal_profile_active_profile') or current.get('goal_profile_active_profile') or 'BASELINE')
    current_sessions = ','.join(cfg.get('execution_sessions_allowed') or current.get('execution_sessions_allowed') or []) or '-'
    current_engines = ','.join(cfg.get('execution_engines_allowed') or current.get('execution_engines_allowed') or []) or '-'
    lines = [
        '🎯 Goal Profile Status',
        HDR,
        f"Enabled: {'ON' if tgt['enabled'] else 'OFF'} | Interval: {float(tgt['interval_hours']):.1f}h | Cooldown: {float(tgt['cooldown_hours']):.1f}h",
        f"Target: {float(tgt['target_lo']):.2f}–{float(tgt['target_hi']):.2f} setups/day | WR≥{float(tgt['target_wr']):.1f}% | AvgR≥{float(tgt['target_avg_r']):.2f}",
        f"Minimum live sample: 30d≥{int(tgt['min_live_30d'])} | 7d≥{int(tgt['min_live_7d'])}",
        f"Search space: NY={'ON' if bool(tgt.get('allow_ny')) else 'OFF'} | ASIA={'ON' if bool(tgt.get('allow_asia')) else 'OFF'} | Engine B={'ON' if bool(tgt.get('allow_engine_b')) else 'OFF'}",
        f"Current execution profile: {current_profile} | sessions={current_sessions} | engines={current_engines}",
    ]
    if rep:
        ts_val = float(rep.get('ts', 0.0) or 0.0)
        lines.append(f"Last run status: {rep.get('status','')} | ts={_fmt_dt_local(datetime.fromtimestamp(ts_val, tz=timezone.utc)) if ts_val > 0 else '—'}")
        if str(rep.get('status') or '').upper() in ('RUNNING', 'STOPPING'):
            started_ts = float(rep.get('started_ts', 0.0) or 0.0)
            if started_ts > 0:
                lines.append(f"Started: {_fmt_dt_local(datetime.fromtimestamp(started_ts, tz=timezone.utc))}")
            prog = dict(rep.get('progress') or {})
            if prog:
                idx = int(prog.get('candidate_idx', 0) or 0)
                total = int(prog.get('candidate_total', 0) or 0)
                stage = str(prog.get('stage') or 'running')
                elapsed = float(prog.get('elapsed_sec', 0.0) or 0.0)
                lines.append(f"Progress: {stage} | candidate {idx}/{total} | elapsed {elapsed/60.0:.1f} min")
                cur = dict(prog.get('current_candidate') or {})
                if cur:
                    lines.append(f"Current candidate: {cur.get('profile','?')}/{cur.get('bundle','?')} | sessions={','.join(cur.get('sessions') or []) or '-'} | engines={','.join(cur.get('engines') or []) or '-'}")
                best = dict(prog.get('best_candidate') or {})
                if best:
                    lines.append(f"Best so far: {best.get('profile','?')}/{best.get('bundle','?')} | score={float(best.get('score',0.0) or 0.0):.2f}")
                note = str(prog.get('note') or '').strip()
                if note:
                    lines.append(f"Note: {note}")
            last_final = dict(rep.get('last_final') or {})
            last_final_metrics = dict((last_final.get('final') or {}).get('metrics_30d') or {})
            last_final_metrics7 = dict((last_final.get('final') or {}).get('metrics_7d') or {})
            if last_final_metrics:
                lines.append(f"Last finalized 30d: setups/day={float(last_final_metrics.get('setups_per_day',0.0) or 0.0):.2f} | setups={int(last_final_metrics.get('setups',0) or 0)} | WR={float(last_final_metrics.get('win_rate',0.0) or 0.0):.1f}% | AvgR={float(last_final_metrics.get('avg_R',0.0) or 0.0):.3f}")
            if last_final_metrics7:
                lines.append(f"Last finalized 7d: setups/day={float(last_final_metrics7.get('setups_per_day',0.0) or 0.0):.2f} | setups={int(last_final_metrics7.get('setups',0) or 0)} | WR={float(last_final_metrics7.get('win_rate',0.0) or 0.0):.1f}% | AvgR={float(last_final_metrics7.get('avg_R',0.0) or 0.0):.3f}")
        elif final:
            lines.append(f"30d live: setups/day={float(m30.get('setups_per_day',0.0) or 0.0):.2f} | setups={int(m30.get('setups',0) or 0)} | WR={float(m30.get('win_rate',0.0) or 0.0):.1f}% | AvgR={float(m30.get('avg_R',0.0) or 0.0):.3f}")
            lines.append(f"7d live: setups/day={float(m7.get('setups_per_day',0.0) or 0.0):.2f} | setups={int(m7.get('setups',0) or 0)} | WR={float(m7.get('win_rate',0.0) or 0.0):.1f}% | AvgR={float(m7.get('avg_R',0.0) or 0.0):.3f}")
        if _goal_metrics_missing and _goal_status_u in {'TIMEOUT_NO_BETTER_PROFILE', 'TIMEOUT', 'NO_BETTER_PROFILE', 'TIMEOUT_PROMOTED'} and (int(m30.get('setups', 0) or 0) > 0 or int(m7.get('setups', 0) or 0) > 0):
            lines.append('Note: showing the last finalized goal-profile metrics because the most recent run did not produce a valid finalized sample.')
        if rep.get('error') and str(rep.get('status') or '').upper().strip() not in {'TIMEOUT_PROMOTED', 'TIMEOUT_NO_BETTER_PROFILE'}:
            lines.append(f"Error: {rep.get('error')}")
    await send_long_message(update, '\n'.join(lines), parse_mode=None)

async def goal_profile_set_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if not _is_admin(update):
        await update.message.reply_text('⛔ Admin only.')
        return
    args = list(context.args or [])
    if len(args) < 3:
        await update.message.reply_text('Usage: /goal_set <setups_per_day_low> <setups_per_day_high> <win_rate_target> [avgR_target]')
        return
    try:
        lo = float(args[0])
        hi = float(args[1])
        wr = float(args[2])
        avg_r = float(args[3]) if len(args) >= 4 else None
    except Exception:
        await update.message.reply_text('Invalid numbers. Example: /goal_set 5 8 60 0.10')
        return
    cfg = load_strategy_config(force=True)
    target_lo = float(max(0.1, lo))
    target_hi = float(max(target_lo, hi))
    cfg['goal_profile_target_setups_per_day_lo'] = target_lo
    cfg['goal_profile_target_setups_per_day_hi'] = target_hi
    cfg['goal_profile_target_win_rate'] = float(max(1.0, min(95.0, wr)))
    if avg_r is not None:
        cfg['goal_profile_target_avg_r'] = float(avg_r)

    # Keep the self-improvement stack wired to the same operator goal. Previously
    # /goal_set only changed the goal-profile optimizer target, while the generic
    # optimizer/objective, governor, and market-adaptive modules could continue using
    # stale setup-frequency targets. That made diagnostics look contradictory and could
    # let self-optimization fight the operator's requested daily setup range.
    cfg['target_setups_per_day_lo'] = target_lo
    cfg['target_setups_per_day_hi'] = target_hi
    cfg['governor_target_lo'] = target_lo
    cfg['governor_target_hi'] = target_hi
    cfg['market_adaptive_target_setups_per_day_lo'] = target_lo
    cfg['market_adaptive_target_setups_per_day_hi'] = target_hi

    save_strategy_config(cfg)
    apply_strategy_config(cfg)
    await update.message.reply_text(f"✅ Goal updated: {cfg['goal_profile_target_setups_per_day_lo']:.2f}–{cfg['goal_profile_target_setups_per_day_hi']:.2f}/day | WR≥{cfg['goal_profile_target_win_rate']:.1f}% | AvgR≥{float(cfg.get('goal_profile_target_avg_r', 0.10) or 0.10):.2f}")



_FAMILY_AUTOTUNE_LOCK = threading.Lock()


def _family_autotune_is_running() -> bool:
    try:
        return bool(_FAMILY_AUTOTUNE_LOCK.locked())
    except Exception:
        return False


def _family_autotune_latest_reject_agg() -> dict:
    cand = []
    try:
        for bucket in ('latest', 'email', 'screen'):
            rec = (_LAST_REJECTS_SHARED or {}).get(bucket) or {}
            if isinstance(rec, dict):
                cand.append(rec)
    except Exception:
        pass
    if not cand:
        return {}
    out = {}
    for rec in cand:
        agg = dict((rec or {}).get('__agg__') or {})
        if agg:
            for k, v in agg.items():
                out[str(k)] = int(out.get(str(k), 0) or 0) + int(v or 0)
            continue
        counts = dict((rec or {}).get('counts') or {})
        for k, v in counts.items():
            rr = str(k).split(':', 1)[-1]
            out[rr] = int(out.get(rr, 0) or 0) + int(v or 0)
    return out


def _family_autotune_data_snapshot(hours: int = 24) -> dict:
    out = {'signals': 0, 'exec': 0, 'executable': 0, 'emailed': 0, 'trading_day': _research_trading_day_label(time.time())}
    since_ts = float(time.time() - max(1, int(hours)) * 3600.0)
    try:
        with sqlite3.connect(DB_PATH) as conn:
            cur = conn.cursor()
            cur.execute('SELECT COUNT(1) FROM signals WHERE created_ts>=?', (since_ts,))
            out['signals'] = int((cur.fetchone() or [0])[0] or 0)
            cur.execute('SELECT COUNT(1) FROM executable_setups WHERE executable_ts>=?', (since_ts,))
            out['exec'] = int((cur.fetchone() or [0])[0] or 0)
            out['executable'] = int(out['exec'] or 0)
            cur.execute('SELECT COUNT(1) FROM emailed_setups WHERE emailed_ts>=?', (since_ts,))
            out['emailed'] = int((cur.fetchone() or [0])[0] or 0)
    except Exception:
        pass
    return out


def _family_autotune_clamp_cfg(cfg: dict) -> dict:
    cfg = dict(cfg or {})
    cfg['family_f4_balance_score_relax'] = round(_clamp(float(cfg.get('family_f4_balance_score_relax', 0.0) or 0.0), 0.0, 6.0), 2)
    cfg['family_f4_balance_conf_relax'] = int(_clamp(int(float(cfg.get('family_f4_balance_conf_relax', 0) or 0)), 0, 8))
    cfg['family_f4_balance_rr_relax'] = round(_clamp(float(cfg.get('family_f4_balance_rr_relax', 0.0) or 0.0), 0.0, 0.40), 3)
    cfg['family_f4_balance_pb_relax'] = round(_clamp(float(cfg.get('family_f4_balance_pb_relax', 0.0) or 0.0), 0.0, 0.70), 3)
    cfg['family_f4_balance_ch1_relax'] = round(_clamp(float(cfg.get('family_f4_balance_ch1_relax', 0.0) or 0.0), 0.0, 1.25), 3)
    cfg['family_f4_balance_ch15_relax'] = round(_clamp(float(cfg.get('family_f4_balance_ch15_relax', 0.0) or 0.0), 0.0, 0.65), 3)
    cfg['quality_score_min_screen'] = round(_clamp(float(cfg.get('quality_score_min_screen', QUALITY_SCORE_MIN_SCREEN) or QUALITY_SCORE_MIN_SCREEN), 48.0, 66.0), 2)
    cfg['quality_score_min_email'] = round(_clamp(float(cfg.get('quality_score_min_email', QUALITY_SCORE_MIN_EMAIL) or QUALITY_SCORE_MIN_EMAIL), 56.0, 70.0), 2)
    cfg['min_rr_tp'] = round(_clamp(float(cfg.get('min_rr_tp', MIN_RR_TP) or MIN_RR_TP), 0.94, 1.55), 3)
    cfg['tf_align_1h_min_abs'] = round(_clamp(float(cfg.get('tf_align_1h_min_abs', TF_ALIGN_1H_MIN_ABS) or TF_ALIGN_1H_MIN_ABS), 0.15, 1.20), 3)
    return cfg


def _run_family_autotune_cycle(force: bool = False) -> dict:
    if not _FAMILY_AUTOTUNE_LOCK.acquire(blocking=False):
        return {'status': 'BUSY'}
    try:
        cfg = load_strategy_config(force=True)
        if not _cfg_bool((cfg or {}).get('family_autotune_enabled', True), True):
            return {'status': 'DISABLED'}
        rep = load_family_autotune_report() or {}
        now_ts = float(time.time())
        cooldown_h = float((cfg or {}).get('family_autotune_cooldown_hours', 4.0) or 4.0)
        last_ts = float((rep or {}).get('ts') or 0.0)
        if (not force) and last_ts > 0 and (now_ts - last_ts) < cooldown_h * 3600.0:
            return {'status': 'COOLDOWN', 'remaining_sec': int(cooldown_h * 3600.0 - (now_ts - last_ts))}

        snap = _family_autotune_data_snapshot(24)
        rejects = _family_autotune_latest_reject_agg()
        plans = {s: _research_latest_allocator_plan(s, '') or {} for s in ['ASIA', 'LON', 'NY']}
        active_champions = {str((plans.get(s) or {}).get('champion_family_id') or '') for s in plans}
        active_regimes = {str((plans.get(s) or {}).get('regime_cell') or '').upper() for s in plans}
        balance_f4 = any(str((plans.get(s) or {}).get('champion_family_id') or '') == 'F4_SWEEP_RECLAIM' and str((plans.get(s) or {}).get('regime_cell') or '').upper() in {'BALANCE', 'EXHAUSTION'} for s in plans)
        trend_active = bool(active_regimes & {'TREND_UP', 'TREND_DOWN', 'EXPANSION'})
        mrep = load_goal_profile_report() or {}
        final = dict((mrep or {}).get('final') or {})
        m30 = dict(final.get('metrics_30d') or {})
        wr30 = float(m30.get('win_rate') or 0.0)
        spd30 = float(m30.get('setups_per_day') or 0.0)

        actions = []
        max_actions = int((cfg or {}).get('family_autotune_max_actions_per_run', 6) or 6)
        def act(key, new_val, why):
            nonlocal actions, cfg
            if len(actions) >= max_actions:
                return
            old = cfg.get(key)
            if old == new_val:
                return
            cfg[key] = new_val
            actions.append({'key': key, 'old': old, 'new': new_val, 'why': why})

        total_flow = max(int(snap.get('signals', 0) or 0), int(snap.get('executable', 0) or 0), int(snap.get('emailed', 0) or 0))
        low_flow = total_flow < 2
        severe_drought = total_flow < 1
        missing_data = int(rejects.get('ohlcv_missing_or_insufficient', 0) or 0)

        if missing_data >= 4 and low_flow:
            report = {
                'ts': now_ts, 'status': 'DATA_STARVED', 'actions': [], 'snapshot': snap,
                'rejects': dict(sorted(rejects.items(), key=lambda kv: int(kv[1]), reverse=True)[:8]),
                'goal_30d': {'setups_per_day': spd30, 'win_rate': wr30},
                'active_regimes': sorted(list(active_regimes)), 'active_champions': sorted([x for x in active_champions if x]),
                'note': 'Dominant OHLCV starvation detected; threshold autotune skipped.'
            }
            save_family_autotune_report(report)
            return report

        if balance_f4 and low_flow:
            if int(rejects.get('no_breakout_trigger', 0) or 0) >= 1 or int(rejects.get('no_engine_passed', 0) or 0) >= 1:
                act('family_f4_balance_score_relax', round(float(cfg.get('family_f4_balance_score_relax', 0.0) or 0.0) + 1.00, 2), 'balance_low_flow_breakout')
                act('family_f4_balance_pb_relax', round(float(cfg.get('family_f4_balance_pb_relax', 0.0) or 0.0) + 0.10, 3), 'balance_low_flow_breakout')
                act('family_f4_balance_ch1_relax', round(float(cfg.get('family_f4_balance_ch1_relax', 0.0) or 0.0) + 0.16, 3), 'balance_low_flow_breakout')
                act('family_f4_balance_ch15_relax', round(float(cfg.get('family_f4_balance_ch15_relax', 0.0) or 0.0) + 0.08, 3), 'balance_low_flow_breakout')
            if int(rejects.get('below_min_confidence', 0) or 0) >= 1:
                act('family_f4_balance_conf_relax', int(float(cfg.get('family_f4_balance_conf_relax', 0) or 0)) + 1, 'balance_low_flow_conf')
                act('quality_score_min_screen', round(float(cfg.get('quality_score_min_screen', QUALITY_SCORE_MIN_SCREEN) or QUALITY_SCORE_MIN_SCREEN) - 2.0, 2), 'balance_low_flow_conf')
                act('quality_score_min_email', round(float(cfg.get('quality_score_min_email', QUALITY_SCORE_MIN_EMAIL) or QUALITY_SCORE_MIN_EMAIL) - 1.0, 2), 'balance_low_flow_conf')
            if int(rejects.get('below_min_rr_tp_session', 0) or 0) >= 1:
                act('family_f4_balance_rr_relax', round(float(cfg.get('family_f4_balance_rr_relax', 0.0) or 0.0) + 0.05, 3), 'balance_low_flow_rr')
                act('min_rr_tp', round(float(cfg.get('min_rr_tp', MIN_RR_TP) or MIN_RR_TP) - 0.05, 3), 'balance_low_flow_rr')
            if int(rejects.get('far_from_ema_anchor_1h', 0) or 0) >= 1 or int(rejects.get('pullback_required_not_met', 0) or 0) >= 1:
                act('family_f4_balance_pb_relax', round(float(cfg.get('family_f4_balance_pb_relax', 0.0) or 0.0) + 0.10, 3), 'balance_low_flow_ema')
                act('tf_align_1h_min_abs', round(float(cfg.get('tf_align_1h_min_abs', TF_ALIGN_1H_MIN_ABS) or TF_ALIGN_1H_MIN_ABS) - 0.05, 3), 'balance_low_flow_ema')
            if int(rejects.get('smc_choch_against_long', 0) or 0) >= 1 or int(rejects.get('pro_structure_trend_conflict', 0) or 0) >= 1:
                act('family_f4_balance_score_relax', round(float(cfg.get('family_f4_balance_score_relax', 0.0) or 0.0) + 0.75, 2), 'balance_low_flow_structure')
        elif trend_active and low_flow:
            if int(rejects.get('ch1_below_trigger', 0) or 0) >= 1 or int(rejects.get('15m_weak_and_not_early', 0) or 0) >= 1 or int(rejects.get('no_breakout_trigger', 0) or 0) >= 2:
                act('quality_score_min_screen', round(float(cfg.get('quality_score_min_screen', QUALITY_SCORE_MIN_SCREEN) or QUALITY_SCORE_MIN_SCREEN) - 0.75, 2), 'trend_low_flow_trigger')
                act('quality_score_min_email', round(float(cfg.get('quality_score_min_email', QUALITY_SCORE_MIN_EMAIL) or QUALITY_SCORE_MIN_EMAIL) - 0.50, 2), 'trend_low_flow_trigger')
                if severe_drought:
                    act('min_rr_tp', round(float(cfg.get('min_rr_tp', MIN_RR_TP) or MIN_RR_TP) - 0.03, 3), 'trend_low_flow_trigger')
            if int(rejects.get('asia_tf_align_fail_long', 0) or 0) >= 1 or int(rejects.get('asia_tf_align_fail_short', 0) or 0) >= 1 or int(rejects.get('far_from_ema_anchor_1h', 0) or 0) >= 1 or int(rejects.get('pullback_required_not_met', 0) or 0) >= 1:
                act('tf_align_1h_min_abs', round(float(cfg.get('tf_align_1h_min_abs', TF_ALIGN_1H_MIN_ABS) or TF_ALIGN_1H_MIN_ABS) - 0.10, 3), 'trend_low_flow_align')
                act('quality_score_min_screen', round(float(cfg.get('quality_score_min_screen', QUALITY_SCORE_MIN_SCREEN) or QUALITY_SCORE_MIN_SCREEN) - 1.0, 2), 'trend_low_flow_align')
            if int(rejects.get('below_min_confidence', 0) or 0) >= 1 or severe_drought:
                act('quality_score_min_screen', round(float(cfg.get('quality_score_min_screen', QUALITY_SCORE_MIN_SCREEN) or QUALITY_SCORE_MIN_SCREEN) - 0.75, 2), 'trend_low_flow_conf')
                act('quality_score_min_email', round(float(cfg.get('quality_score_min_email', QUALITY_SCORE_MIN_EMAIL) or QUALITY_SCORE_MIN_EMAIL) - 0.50, 2), 'trend_low_flow_conf')
                if severe_drought:
                    act('min_rr_tp', round(float(cfg.get('min_rr_tp', MIN_RR_TP) or MIN_RR_TP) - 0.03, 3), 'trend_low_flow_conf')
            if int(rejects.get('below_min_rr_tp_session', 0) or 0) >= 1:
                act('min_rr_tp', round(float(cfg.get('min_rr_tp', MIN_RR_TP) or MIN_RR_TP) - 0.05, 3), 'trend_low_flow_rr')
        elif spd30 > 4.5 and wr30 < 42.0:
            act('quality_score_min_email', round(float(cfg.get('quality_score_min_email', QUALITY_SCORE_MIN_EMAIL) or QUALITY_SCORE_MIN_EMAIL) + 1.0, 2), 'tighten_high_flow_low_wr')
            act('min_rr_tp', round(float(cfg.get('min_rr_tp', MIN_RR_TP) or MIN_RR_TP) + 0.03, 3), 'tighten_high_flow_low_wr')

        cfg = _family_autotune_clamp_cfg(cfg)
        save_strategy_config(cfg)
        apply_strategy_config(cfg)
        report = {
            'ts': now_ts, 'status': 'ADJUSTED' if actions else 'NO_CHANGE',
            'actions': actions, 'snapshot': snap, 'rejects': dict(sorted(rejects.items(), key=lambda kv: int(kv[1]), reverse=True)[:8]),
            'goal_30d': {'setups_per_day': spd30, 'win_rate': wr30}, 'active_regimes': sorted(list(active_regimes)), 'active_champions': sorted([x for x in active_champions if x]),
        }
        save_family_autotune_report(report)
        return report
    except Exception as e:
        rep = {'ts': float(time.time()), 'status': 'ERROR', 'error': f'{type(e).__name__}: {e}'}
        save_family_autotune_report(rep)
        return rep
    finally:
        try:
            _FAMILY_AUTOTUNE_LOCK.release()
        except Exception:
            pass


async def family_autotune_job(context: ContextTypes.DEFAULT_TYPE):
    if _heavy_background_defer():
        return
    await to_thread_bg(_run_family_autotune_cycle)


async def goal_profile_job(context: ContextTypes.DEFAULT_TYPE):
    try:
        if _recent_user_activity(25):
            return
        cfg = load_strategy_config(force=False)
        tgt = _goal_profile_targets(cfg)
        if not tgt['enabled']:
            return
        if _SELF_OPT_STATE.get('stop_event') is not None:
            return
        if _goal_profile_is_running():
            return
        if ALERT_LOCK.locked() or SCAN_LOCK.locked() or _SCREEN_LOCK.locked():
            return
        now_ts = float(time.time())
        if not _goal_profile_is_due(now_ts, cfg=cfg):
            return
        if not _goal_profile_quiet_window_ok(now_ts):
            return
        await to_thread_bg(_run_goal_profile_cycle, False, timeout=max(900, int(float(tgt.get('interval_hours', 24.0) or 24.0) * 1800)))
    except Exception:
        return


async def research_framework_watchdog_job(context: ContextTypes.DEFAULT_TYPE):
    """Cheap safety net for daily research refresh only.

    Keep this watchdog intentionally light. It must never run the full goal-profile search itself,
    because long optimizer work here causes APScheduler overlap warnings and steals executor budget
    from /screen, /autotrade_report, and other user-facing commands on small Render instances.
    """
    try:
        if _recent_user_activity(90) or _backtest_runtime_busy():
            return
        now_ts = float(time.time())
        cfg = load_strategy_config(force=False)
        if ALERT_LOCK.locked() or SCAN_LOCK.locked() or _SCREEN_LOCK.locked() or _goal_profile_is_running():
            return

        if _cfg_bool((cfg or {}).get('family_allocator_enabled', True), True) and _research_daily_refresh_due(now_ts):
            try:
                await to_thread_bg(_research_run_daily_refresh, True, timeout=25)
            except Exception:
                pass

        # Intentionally do not run _run_goal_profile_cycle() here. The dedicated scheduled
        # goal_profile_job already owns that responsibility, and keeping the watchdog light
        # materially reduces Render lag and APScheduler overlap warnings.
        return
    except Exception:
        return


def _session_entry_quality_limits(session_name: str, source: str = 'email') -> dict:
    sess = str(session_name or '').upper().strip() or 'NY'
    base = {
        'NY': {'max_pb_ema_dist': 0.86, 'max_ch15_abs': 0.78, 'max_ch1_abs': 1.55, 'max_atr_pct': 5.8},
        'LON': {'max_pb_ema_dist': 0.88, 'max_ch15_abs': 0.80, 'max_ch1_abs': 1.58, 'max_atr_pct': 5.9},
        'ASIA': {'max_pb_ema_dist': 0.70, 'max_ch15_abs': 0.62, 'max_ch1_abs': 1.22, 'max_atr_pct': 4.6},
    }.get(sess, {'max_pb_ema_dist': 0.74, 'max_ch15_abs': 0.64, 'max_ch1_abs': 1.28, 'max_atr_pct': 4.9}).copy()
    src = str(source or '').strip().lower()
    if src == 'screen':
        base['max_pb_ema_dist'] *= (1.10 if sess != 'ASIA' else 1.06)
        base['max_ch15_abs'] *= (1.08 if sess != 'ASIA' else 1.04)
        base['max_ch1_abs'] *= (1.08 if sess != 'ASIA' else 1.04)
        base['max_atr_pct'] *= (1.06 if sess != 'ASIA' else 1.03)
    elif src == 'exec':
        # The executable lane has its own stricter family/session gate later.
        # Keep this pre-gate somewhat broader than email, but not so broad that it
        # floods NY/ASIA with low-quality converts.
        if sess == 'LON':
            base['max_pb_ema_dist'] *= 1.10
            base['max_ch15_abs'] *= 1.08
            base['max_ch1_abs'] *= 1.07
            base['max_atr_pct'] *= 1.05
        elif sess == 'NY':
            base['max_pb_ema_dist'] *= 1.06
            base['max_ch15_abs'] *= 1.05
            base['max_ch1_abs'] *= 1.04
            base['max_atr_pct'] *= 1.03
        else:
            base['max_pb_ema_dist'] *= 1.02
            base['max_ch15_abs'] *= 1.02
            base['max_ch1_abs'] *= 1.02
            base['max_atr_pct'] *= 1.01
    return base


def _setup_entry_quality_gate(s: 'Setup', session_name: str = 'NY', source: str = 'email') -> tuple[bool, str]:
    try:
        limits = _session_entry_quality_limits(session_name, source=source)
        src = str(source or '').strip().lower()
        leader_base = bool(getattr(s, 'leader_base_override', False))
        engine = str(getattr(s, 'engine', '') or '').upper().strip()
        cfg_live = load_strategy_config(force=False)
        active_profile = str((cfg_live or {}).get('goal_profile_active_profile', '') or '').upper().strip()
        reach_mode = bool(_cfg_bool((cfg_live or {}).get('goal_profile_reach_mode', False), False) or ('REACH' in active_profile) or active_profile.endswith('_SCOUT'))
        sess = str(session_name or '').upper().strip()
        engine = str(getattr(s, 'engine', '') or '').upper().strip()
        fam = str(getattr(s, 'family_id', '') or _family_id_from_engine(engine, s)).upper().strip()
        regime = str(getattr(s, 'regime_primary', '') or getattr(s, 'regime', '') or '').upper().strip()
        conf = int(getattr(s, 'conf', 0) or 0)
        score = float(getattr(s, 'quality_score', 0.0) or 0.0)
        pb_dist = float(getattr(s, 'pullback_ema_dist_pct', 999.0) or 999.0)
        ch15_abs = abs(float(getattr(s, 'ch15', 0.0) or 0.0))
        ch1_abs = abs(float(getattr(s, 'ch1', 0.0) or 0.0))
        ch4_abs = abs(float(getattr(s, 'ch4', 0.0) or 0.0))
        ch24_abs = abs(float(getattr(s, 'ch24', 0.0) or 0.0))
        atr_pct = float(getattr(s, 'atr_pct', 0.0) or 0.0)

        if leader_base:
            return (True, 'ok')

        max_pb = float(limits['max_pb_ema_dist']) + (0.10 if engine == 'B' else 0.0)
        max_ch15 = float(limits['max_ch15_abs']) + (0.20 if engine == 'B' else 0.0)
        max_ch1 = float(limits['max_ch1_abs']) + (0.50 if engine == 'B' else 0.0)
        max_atr = float(limits['max_atr_pct']) + (0.60 if engine == 'B' else 0.0)
        if reach_mode and sess == 'LON' and engine in {'A', 'C'}:
            max_pb += 0.18
            max_ch15 += 0.20
            max_ch1 += 0.24
            max_atr += 0.55

        # Family-aware calibration: modest session/regime tuning only.
        # Keep ASIA tighter, allow a little more conversion in LON/NY where the allocator
        # already selected the family as active.
        f4_pb_relax = float((cfg_live or {}).get('family_f4_balance_pb_relax', 0.0) or 0.0)
        f4_ch1_relax = float((cfg_live or {}).get('family_f4_balance_ch1_relax', 0.0) or 0.0)
        f4_ch15_relax = float((cfg_live or {}).get('family_f4_balance_ch15_relax', 0.0) or 0.0)
        if fam == 'F4_SWEEP_RECLAIM' and regime in {'BALANCE', 'EXHAUSTION'}:
            if sess in {'LON', 'NY'}:
                max_pb += 0.14 + f4_pb_relax
                max_ch15 += 0.12 + f4_ch15_relax
                max_ch1 += 0.14 + f4_ch1_relax
            else:
                max_pb += 0.06 + f4_pb_relax
                max_ch15 += 0.04 + f4_ch15_relax
                max_ch1 += 0.04 + f4_ch1_relax
        elif fam == 'F2_MOMENTUM_IGNITION' and regime == 'EXPANSION':
            if sess in {'LON', 'NY'}:
                max_pb += 0.12
                max_ch15 += 0.14
                max_ch1 += 0.24
                max_atr += 0.24
        elif fam == 'F3_IMPULSE_BASE_CONT' and regime in {'EXPANSION', 'SQUEEZE'}:
            if sess in {'LON', 'NY'}:
                max_pb += 0.10
                max_ch15 += 0.12
                max_ch1 += 0.20
                max_atr += 0.18
        elif fam in {'F5_ORB_RETEST', 'F6_VWAP_RECLAIM'}:
            # Breakout/reclaim families naturally sit farther from EMA than pullback setups.
            max_pb += 0.22
            max_ch15 += 0.20
            max_ch1 += 0.28
            max_atr += 0.22
        elif fam == 'F7_EXHAUSTION_FAILURE':
            # Reversal after exhaustion can be extended by definition; keep RR/liquidity
            # gates later, but do not reject solely for extension here.
            max_pb += 0.42
            max_ch15 += 0.40
            max_ch1 += 0.50
            max_atr += 0.35
        elif fam == BIGMOVE_FAMILY_ID:
            if sess in {'LON', 'NY'}:
                max_pb += 0.16
                max_ch15 += 0.18
                max_ch1 += 0.34
                max_atr += 0.30
            else:
                max_pb += 0.10
                max_ch15 += 0.10
                max_ch1 += 0.18
                max_atr += 0.18
        elif fam == 'F1_PULLBACK_CONT' and 'TREND' in regime and sess == 'LON':
            max_pb += 0.04
            max_ch15 += 0.05
            max_ch1 += 0.08

        if pb_dist > max_pb:
            return (False, 'entry_far_from_pullback_ema')
        if ch15_abs > max_ch15:
            return (False, 'entry_too_extended_15m')
        if engine not in {'B', 'C'} and ch1_abs > max_ch1:
            return (False, 'entry_too_extended_1h')
        if atr_pct > 0 and atr_pct > max_atr:
            return (False, 'poor_volatility_regime_exec')

        if engine == 'A':
            if fam == 'F7_EXHAUSTION_FAILURE':
                return (True, 'ok')
            if sess == 'LON':
                if src == 'exec':
                    lon_ctx_ch4_min = 0.30 if reach_mode else 0.42
                    lon_ctx_ch1_min = 0.08 if reach_mode else 0.14
                else:
                    lon_ctx_ch4_min = 0.32 if reach_mode else 0.46
                    lon_ctx_ch1_min = 0.08 if reach_mode else 0.16
                if ch4_abs < lon_ctx_ch4_min or ch1_abs < lon_ctx_ch1_min:
                    return (False, 'lon_pullback_context_too_weak')
            if sess == 'NY':
                ny_ctx_ch4_min = 0.54 if src == 'exec' else 0.58
                ny_ctx_ch1_min = 0.20 if src == 'exec' else 0.24
                if ch4_abs < ny_ctx_ch4_min or ch1_abs < ny_ctx_ch1_min:
                    return (False, 'ny_pullback_context_too_weak')
            if sess == 'ASIA':
                if fam == 'F4_SWEEP_RECLAIM' and regime in {'BALANCE', 'EXHAUSTION'}:
                    if ch24_abs < 5.0 or ch15_abs < 0.01:
                        return (False, 'asia_pullback_context_too_weak')
                else:
                    asia_ctx_ch4_min = 0.68 if src == 'exec' else 0.72
                    asia_ctx_ch1_min = 0.28 if src == 'exec' else 0.34
                    if ch4_abs < asia_ctx_ch4_min or ch1_abs < asia_ctx_ch1_min:
                        return (False, 'asia_pullback_context_too_weak')
            if sess == 'LON':
                lon_hot_ch24 = 14.8 if (reach_mode or src == 'exec') else 12.8
                lon_hot_pb = 0.54 if (reach_mode or src == 'exec') else 0.40
                if ch24_abs > lon_hot_ch24 and pb_dist > lon_hot_pb:
                    return (False, 'lon_trend_overheated')
        if sess == 'NY' and ch1_abs >= 1.72 and ch15_abs >= 0.82 and conf < 85 and score < 80.0:
            return (False, 'ny_breakout_chase_risk')
        return (True, 'ok')
    except Exception:
        return (False, 'entry_quality_gate_exception')


def is_top_setup_eligible(

    s: "Setup",
    source: str = "screen",
    session_name: str = "LON",
) -> tuple[bool, str]:
    """Unified single-TP eligibility using scoring + a few safety checks.

    - source='screen' => loosest display lane
    - source='exec'   => authoritative executable pool pre-gate
    - source='email'  => strictest downstream lane
    """
    try:
        entry = float(getattr(s, "entry", 0.0) or 0.0)
        sl = float(getattr(s, "sl", 0.0) or 0.0)
        final_tp = float(_setup_target_tp(s, 0.0) or 0.0)
        side = str(getattr(s, "side", "") or "").upper()

        if entry <= 0 or sl <= 0 or final_tp <= 0 or side not in ("BUY", "SELL"):
            return (False, "bad_prices_or_side")

        if side == "BUY" and not (sl < entry < final_tp):
            return (False, "bad_price_order_buy")
        if side == "SELL" and not (final_tp < entry < sl):
            return (False, "bad_price_order_sell")
        geom_ok, geom_why, _geom_meta = _setup_basic_geometry_guard(s, min_rr=float(globals().get('SETUP_FINAL_GEOMETRY_MIN_RR', 1.05) or 1.05))
        if not geom_ok:
            return (False, str(geom_why or "bad_geometry"))

        try:
            setattr(s, "tp", float(final_tp))
            setattr(s, "alt_target_a", 0.0)
            setattr(s, "alt_target_b", 0.0)
        except Exception:
            pass

        score, comps = compute_setup_quality_score(s, session_name=session_name)
        setattr(s, "quality_score", float(score))
        try:
            setattr(s, "quality_components", comps)
        except Exception:
            pass

        cfg_live = load_strategy_config(force=False)
        engine_c_base_score_add = float((cfg_live or {}).get('engine_c_base_score_add', 0.0) or 0.0)
        src = str(source or "screen").strip().lower()
        if src not in {"screen", "email", "exec"}:
            src = "screen"
        sess = str(session_name or 'LON').upper().strip()
        engine = str(getattr(s, 'engine', '') or '').upper().strip()
        fam = str(getattr(s, 'family_id', '') or _family_id_from_engine(engine, s)).upper().strip()
        regime = str(getattr(s, 'regime_primary', '') or getattr(s, 'regime', '') or '').upper().strip()
        active_profile = str((cfg_live or {}).get('goal_profile_active_profile', '') or '').upper().strip()
        reach_mode = bool(_cfg_bool((cfg_live or {}).get('goal_profile_reach_mode', False), False) or ('REACH' in active_profile) or active_profile.endswith('_SCOUT'))

        # Controlled drought recovery: when the normal OHLCV engines are starved by cold
        # cache/rate limits, fallback setups are created from the current live ticker
        # snapshot. Let them pass this shared pre-gate if they still have valid price
        # order, RR, confidence and liquidity. The stricter executable gate below also
        # re-checks these before email/autotrade consumption.
        try:
            if bool(getattr(s, 'recovery_fallback', False)):
                rr_final = float(rr_to_tp(entry, sl, final_tp)) if entry > 0 and sl > 0 and final_tp > 0 else 0.0
                fut_vol = float(getattr(s, 'fut_vol_usd', 0.0) or 0.0)
                conf = int(getattr(s, 'conf', 0) or 0)
                ch24_abs = abs(float(getattr(s, 'ch24', 0.0) or 0.0))
                # FIX5: controlled drought fallback should not be killed by stale high-volume floors.
                vol_floor = max(4_000_000.0, float(MIN_FUT_VOL_USD) * 0.45)
                if sess == 'NY':
                    vol_floor = max(vol_floor, 5_000_000.0)
                if src == 'email':
                    vol_floor = max(vol_floor, 6_000_000.0)
                if engine == 'A' and conf >= 72 and rr_final >= 1.18 and fut_vol >= vol_floor and ch24_abs >= 1.2:
                    try:
                        setattr(s, 'quality_score', float(max(float(getattr(s, 'quality_score', score) or score), 68.0)))
                    except Exception:
                        pass
                    return (True, 'ok')
        except Exception:
            pass

        if src == "screen":
            min_score = float(QUALITY_SCORE_MIN_SCREEN)
        elif src == "exec":
            # Exec has a second, stricter gate in is_executable_setup_eligible().
            # Keep this source-truth pre-gate only moderately above screen so the
            # executable lane is not self-starved before family/engine/session checks run.
            min_score = float(max(QUALITY_SCORE_MIN_SCREEN + 1.0, QUALITY_SCORE_MIN_EMAIL - 4.0))
        else:
            min_score = float(QUALITY_SCORE_MIN_EMAIL)

        if src == 'email':
            if engine == 'A':
                if sess == 'LON':
                    min_score += 0.5
                elif sess == 'NY':
                    min_score += 1.0
                elif sess == 'ASIA':
                    min_score += 1.5
            elif engine == 'B':
                min_score += 4.0 if sess in {'NY', 'ASIA'} else 2.5
            elif engine == 'C':
                min_score += (1.5 if sess != 'ASIA' else 2.0) + engine_c_base_score_add
        elif src == 'exec':
            if engine == 'A':
                min_score += -0.75 if sess == 'LON' else (-0.25 if sess == 'NY' else 0.20)
            elif engine == 'B':
                min_score += 1.25 if sess in {'NY', 'ASIA'} else 1.00
            elif engine == 'C':
                min_score += (0.75 if sess != 'ASIA' else 1.25) + engine_c_base_score_add
        else:
            if engine == 'A':
                min_score += 0.0 if sess == 'LON' else (0.5 if sess == 'NY' else 1.0)
            elif engine == 'B':
                min_score += 2.0 if sess in {'NY', 'ASIA'} else 1.0
            elif engine == 'C':
                min_score += (0.8 if sess != 'ASIA' else 1.2) + engine_c_base_score_add
        if reach_mode and sess == 'LON' and engine in {'A', 'C'}:
            if src == 'exec':
                min_score -= 2.75 if engine == 'A' else 2.00
            elif src == 'email':
                min_score -= 1.5 if engine == 'A' else 1.0
            else:
                min_score -= 0.75 if engine == 'A' else 0.50

        # Family-aware score calibration: modest conversion help where the allocator already
        # indicates family/regime fit. Keep ASIA comparatively tighter.
        f4_score_relax = float((cfg_live or {}).get('family_f4_balance_score_relax', 0.0) or 0.0)
        f4_conf_relax = int(float((cfg_live or {}).get('family_f4_balance_conf_relax', 0) or 0))
        f4_rr_relax = float((cfg_live or {}).get('family_f4_balance_rr_relax', 0.0) or 0.0)
        f4_pb_relax = float((cfg_live or {}).get('family_f4_balance_pb_relax', 0.0) or 0.0)
        f4_ch1_relax = float((cfg_live or {}).get('family_f4_balance_ch1_relax', 0.0) or 0.0)
        f4_ch15_relax = float((cfg_live or {}).get('family_f4_balance_ch15_relax', 0.0) or 0.0)
        if fam == 'F4_SWEEP_RECLAIM' and regime in {'BALANCE', 'EXHAUSTION'}:
            if sess in {'LON', 'NY'}:
                min_score -= (1.25 if src == 'exec' else (1.5 if src == 'email' else 1.0)) + f4_score_relax
            else:
                min_score -= (1.75 if src == 'exec' else (1.5 if src == 'email' else 1.0)) + f4_score_relax
        elif fam == 'F2_MOMENTUM_IGNITION' and regime == 'EXPANSION':
            if sess in {'LON', 'NY'}:
                min_score -= 0.90 if src == 'exec' else (0.75 if src == 'email' else 0.50)
        elif fam == 'F3_IMPULSE_BASE_CONT' and regime in {'EXPANSION', 'SQUEEZE'}:
            if sess in {'LON', 'NY'}:
                min_score -= 0.80 if src == 'exec' else (0.60 if src == 'email' else 0.50)
        elif fam == BIGMOVE_FAMILY_ID:
            # Big Move is a separate family that shares engine B, but it should not inherit
            # the exact same source-truth score pressure as generic breakouts or it gets
            # silently starved before the executable gate can evaluate its multi-timeframe edge.
            if sess in {'LON', 'NY'}:
                min_score -= 1.60 if src == 'exec' else (1.30 if src == 'email' else 1.00)
            else:
                min_score -= 1.20 if src == 'exec' else (1.00 if src == 'email' else 0.80)
        elif fam == 'F1_PULLBACK_CONT' and 'TREND' in regime and sess == 'LON':
            # LON was over-converting weak pullback-continuation ideas.
            # Keep NY broad, but require slightly better LON scores here.
            min_score += 0.50 if src == 'exec' else (0.50 if src == 'email' else 0.25)

        min_floor = 58.0 if src == 'exec' else (55.0 if reach_mode and sess == 'LON' else 58.0)
        min_score = float(clamp(min_score, min_floor, 90.0))

        if float(score) < float(min_score):
            try:
                if bool(getattr(s, 'recovery_fallback', False)) and float(score) >= 55.0:
                    setattr(s, 'quality_score', float(max(score, 64.0)))
                else:
                    return (False, f"below_score_{int(round(min_score))}")
            except Exception:
                return (False, f"below_score_{int(round(min_score))}")

        ok_entry, why_entry = _setup_entry_quality_gate(s, session_name=session_name, source=src)
        if not ok_entry:
            return (False, why_entry)

        fut_vol = float(getattr(s, "fut_vol_usd", 0.0) or 0.0)
        vol_floor = float(MIN_FUT_VOL_USD)
        if sess == 'NY':
            vol_floor = max(vol_floor, 12_000_000.0)
        elif sess == 'ASIA':
            vol_floor = max(vol_floor * 1.05, ASIA_MIN_FUT_VOL_USD)
        if fut_vol < vol_floor:
            return (False, "below_min_fut_vol")

        return (True, "ok")
    except Exception:
        return (False, "eligibility_exception")

def _setup_low_flow_recovery_active(session_name: str = '', lookback_hours: float | None = None) -> bool:
    """True when setup generation is below target and a small recovery relax is allowed.

    Counts DB-backed executable and emailed setups. This keeps normal strict behaviour when
    the bot is already producing enough signals, while preventing full-session droughts.
    """
    if not SETUP_LOW_FLOW_RECOVERY_ENABLED:
        return False
    try:
        sess = str(session_name or '').upper().strip()
        hours = float(lookback_hours if lookback_hours is not None else SETUP_LOW_FLOW_LOOKBACK_HOURS)
        since_ts = float(time.time()) - max(1.0, hours) * 3600.0
        exec_count = 0
        email_count = 0
        with sqlite3.connect(DB_PATH) as conn:
            cur = conn.cursor()
            if sess:
                cur.execute("SELECT COUNT(1) FROM executable_setups WHERE executable_ts>=? AND UPPER(session)=?", (since_ts, sess))
            else:
                cur.execute("SELECT COUNT(1) FROM executable_setups WHERE executable_ts>=?", (since_ts,))
            exec_count = int((cur.fetchone() or [0])[0] or 0)
            try:
                if sess:
                    cur.execute("SELECT COUNT(1) FROM emailed_setups WHERE emailed_ts>=? AND UPPER(session)=?", (since_ts, sess))
                else:
                    cur.execute("SELECT COUNT(1) FROM emailed_setups WHERE emailed_ts>=?", (since_ts,))
                email_count = int((cur.fetchone() or [0])[0] or 0)
            except Exception:
                email_count = 0
        return bool(exec_count < int(SETUP_LOW_FLOW_MIN_EXECUTABLES) and email_count < int(SETUP_LOW_FLOW_MIN_EMAILED))
    except Exception:
        return False


def _execution_session_thresholds(session_name: str) -> tuple[float, int, float]:
    """Moderately strict executable thresholds for a shared cross-session pool.

    These floors are intentionally below the final per-engine executable checks so the
    authoritative executable lane does not self-starve before email/autotrade consume it.
    """
    sess = str(session_name or "").upper().strip()
    if sess == "NY":
        quality, conf, rr = 65.5, 69, 1.10
    elif sess == "LON":
        quality, conf, rr = 63.0, 67, 1.04
    elif sess == "ASIA":
        quality, conf, rr = 63.0, 67, 1.03
    else:
        quality, conf, rr = 69.0, 72, 1.18

    try:
        cfg = load_strategy_config(force=False)
        ov_all = (cfg or {}).get("session_exec_overrides") or {}
        ov = ov_all.get(sess) or {}
        quality += float(ov.get("quality_add", 0.0) or 0.0)
        conf += int(round(float(ov.get("conf_add", 0) or 0)))
        rr += float(ov.get("rr_add", 0.0) or 0.0)
    except Exception:
        pass

    try:
        if _research_balance_reversal_mode(sess):
            if sess == 'ASIA':
                quality -= 2.0
                conf -= 2
                rr -= 0.08
            elif sess in {'LON', 'NY'}:
                quality -= 1.5
                conf -= 1
                rr -= 0.05
    except Exception:
        pass
    quality = float(clamp(quality, 60.0, 92.0))
    conf = int(max(65, min(95, conf)))
    rr = float(clamp(rr, 0.95, 2.30))
    return (quality, conf, rr)


def is_executable_setup_eligible(
    s: "Setup",
    session_name: str = "NY",
    min_quality: float = 68.0,
    min_conf: int = 74,
    min_rr_final: float = 0.0,
) -> tuple[bool, str]:
    """Production-grade gate for executable/email/autotrade path.

    Key rule:
    - executability is session-aware by thresholds
    - executability is NOT silently session-blocked by strategy policy
    - downstream email/autotrade session preferences decide consumption
    """
    try:
        sess = str(session_name or "").upper().strip()
        if sess not in {"ASIA", "LON", "NY"}:
            return (False, "session_not_supported")
        try:
            _sym_blocked, _sym_block_reason = _autotrade_symbol_blocked(str(getattr(s, 'symbol', '') or getattr(s, 'market_symbol', '') or ''))
            if _sym_blocked:
                return (False, _sym_block_reason)
        except Exception:
            pass
        if not _setup_volume_ok(s):
            return (False, f"below_min_volume_{_setup_min_volume_floor_usd()/1e6:.0f}M")
        # yver24: if /setup_matrix policy says KEEP, this setup is executable
        # for the user-facing path.  Keep only the basic structural price-order
        # validation here; risk sizing, cooldowns, duplicate guards, email gate
        # and exchange safety remain downstream.
        try:
            if _setup_matrix_policy_is_keep_for_setup(s, session_name=sess, user_id=int(globals().get('AUTOTRADE_OWNER_UID', 0) or 0)):
                entry = float(getattr(s, 'entry', 0.0) or 0.0)
                sl = float(getattr(s, 'sl', 0.0) or 0.0)
                tp = float(_setup_target_tp(s, 0.0) or 0.0)
                side = str(getattr(s, 'side', '') or '').upper().strip()
                if side == 'BUY' and not (sl < entry < tp):
                    return (False, 'matrix_keep_bad_price_order')
                if side == 'SELL' and not (tp < entry < sl):
                    return (False, 'matrix_keep_bad_price_order')
                if entry <= 0 or sl <= 0 or tp <= 0:
                    return (False, 'matrix_keep_missing_prices')
                return (True, 'setup_matrix_policy_keep_source_of_truth')
        except Exception:
            pass
        try:
            policy_uid = int(globals().get('AUTOTRADE_OWNER_UID', 0) or 0)
            final_ok, final_why, _final_meta = _setup_final_quality_gate_allows_setup(s, sess, user_id=policy_uid)
            if not final_ok:
                return (False, str(final_why or 'final_quality_gate_blocked'))
            # Ver51 FINAL_PIPELINE_LOCKED: if the shared final gate explicitly accepted
            # a starvation-safe scout candidate, do not let old duplicated legacy
            # session/engine floors block the same setup later.  Autotrade risk, caps,
            # cooldowns, max open/day and Bybit SL/TP attachment still run downstream.
            try:
                if bool(_autotrade_setup_attr(s, 'final_pipeline_locked_scout', False)):
                    return (True, 'ok')
            except Exception:
                pass
        except Exception:
            return (False, 'final_quality_gate_exception')

        cfg_live = load_strategy_config(force=False)
        exec_engine_b_enabled = _cfg_bool((cfg_live or {}).get("execution_engine_b_email_enabled", EXECUTION_ENGINE_B_EMAIL_ENABLED), bool(EXECUTION_ENGINE_B_EMAIL_ENABLED))
        engine_c_exec_quality_add = float((cfg_live or {}).get('engine_c_exec_quality_add', 0.0) or 0.0)
        engine_c_exec_conf_add = int(round(float((cfg_live or {}).get('engine_c_exec_conf_add', 0) or 0)))
        engine_c_exec_rr_add = float((cfg_live or {}).get('engine_c_exec_rr_add', 0.0) or 0.0)
        engine_c_exec_liq_mult = float((cfg_live or {}).get('engine_c_exec_liq_mult', 1.10) or 1.10)
        engine_c_exec_ch1_cap_lon = float((cfg_live or {}).get('engine_c_exec_ch1_cap_lon', 1.20) or 1.20)
        engine_c_exec_pb_dist_lon = float((cfg_live or {}).get('engine_c_exec_pb_dist_lon', 0.68) or 0.68)
        active_profile = str((cfg_live or {}).get('goal_profile_active_profile', '') or '').upper().strip()
        reach_mode = bool(_cfg_bool((cfg_live or {}).get('goal_profile_reach_mode', False), False) or ('REACH' in active_profile) or active_profile.endswith('_SCOUT'))
        low_flow_recovery = _setup_low_flow_recovery_active(sess)
        allowed_sessions = _strategy_cfg_execution_sessions_allowed(cfg_live)
        if allowed_sessions and sess not in allowed_sessions:
            return (False, 'execution_profile_session_disabled')
        allowed_engines = _strategy_cfg_execution_engines_allowed(cfg_live)
        try:
            s = _research_finalize_setup(s, session_name=sess)
        except Exception:
            pass
        _engine_pre = str(getattr(s, "engine", "") or "").upper().strip()
        _fam_pre = str(getattr(s, 'family_id', '') or _family_id_from_engine(_engine_pre, s)).upper().strip()
        if allowed_engines and _engine_pre and _engine_pre not in allowed_engines:
            # Ver14 all-family discovery: a setup may use the proven A/B/C engine
            # plumbing while being tagged as F4-F7. Allow it when either the engine
            # or the compact family code is enabled.
            try:
                fam_code_pre = _setup_family_id_to_code(_fam_pre)
            except Exception:
                fam_code_pre = ''
            if not (
                (_fam_pre == globals().get('BIGMOVE_FAMILY_ID', 'F8_BIGMOVE_CONT') and 'F8' in allowed_engines)
                or (fam_code_pre and fam_code_pre in allowed_engines)
            ):
                return (False, 'execution_profile_engine_disabled')

        # Drought-recovery setups are generated from the current live ticker snapshot only
        # after the normal OHLCV engines fail. Do not let allocator shadow/probation state
        # block them before basic executable validation. Final email/autotrade risk gates
        # still run after this function.
        try:
            if bool(getattr(s, 'recovery_fallback', False)):
                entry = float(getattr(s, "entry", 0.0) or 0.0)
                sl = float(getattr(s, "sl", 0.0) or 0.0)
                final_tp = float(_setup_target_tp(s, 0.0) or 0.0)
                side = str(getattr(s, 'side', '') or '').upper().strip()
                rr_final = float(rr_to_tp(entry, sl, final_tp)) if entry > 0 and sl > 0 and final_tp > 0 else 0.0
                fut_vol = float(getattr(s, "fut_vol_usd", 0.0) or 0.0)
                conf = int(getattr(s, 'conf', 0) or 0)
                if side == 'BUY' and not (sl < entry < final_tp):
                    return (False, 'recovery_bad_price_order')
                if side == 'SELL' and not (final_tp < entry < sl):
                    return (False, 'recovery_bad_price_order')
                if conf >= 72 and rr_final >= 1.12 and fut_vol >= max(3_500_000.0, float(MIN_FUT_VOL_USD) * 0.40):
                    return (True, 'ok')
        except Exception:
            pass

        alloc_ok, alloc_why = _research_plan_allows_setup(s, session_name=sess)
        if not alloc_ok:
            return (False, str(alloc_why or 'allocator_blocked'))

        ok, why = is_top_setup_eligible(s, source='exec', session_name=sess)
        if not ok:
            return (False, f"base_gate_{why}")

        sess_quality, sess_conf, sess_rr = _execution_session_thresholds(sess)
        score_floor = float(max(min_quality, QUALITY_SCORE_MIN_EMAIL - 3.0, sess_quality))
        conf_floor = int(max(min_conf, MIN_SETUP_CONF, sess_conf))
        rr_floor = float(max(min_rr_final, sess_rr))

        engine = str(getattr(s, "engine", "") or "").upper().strip()
        fam = str(getattr(s, 'family_id', '') or _family_id_from_engine(engine, s)).upper().strip()
        # F8/Big-Move is evaluated through the momentum branch but has its own
        # stricter family-specific gates below.
        if fam == globals().get('BIGMOVE_FAMILY_ID', 'F8_BIGMOVE_CONT') and engine not in {'A', 'B', 'C'}:
            engine = 'B'
        combo_override = _setup_combo_exec_override(cfg_live, fam, sess)
        regime = str(getattr(s, 'regime', '') or '').upper()
        trend = str(getattr(s, 'trend', '') or '').upper()
        structure = str(getattr(s, 'structure', '') or '').upper()
        side = str(getattr(s, 'side', '') or '').upper()
        want = 'BULLISH' if side == 'BUY' else 'BEARISH' if side == 'SELL' else ''

        if engine == 'A':
            if fam == 'F7_EXHAUSTION_FAILURE':
                return (True, 'ok')
            if sess == 'LON':
                score_floor = max((65.5 if reach_mode else 68.5), score_floor)
                conf_floor = max((70 if reach_mode else 72), conf_floor)
                rr_floor = max((1.08 if reach_mode else 1.16), rr_floor)
            elif sess == 'NY':
                score_floor = max(68.5, score_floor)
                conf_floor = max(70, conf_floor)
                rr_floor = max(1.14, rr_floor)
            else:
                score_floor = max(69.5, score_floor)
                conf_floor = max(71, conf_floor)
                rr_floor = max(1.12, rr_floor)
        elif engine == 'C':
            if sess == 'LON':
                score_floor = max((64.5 if reach_mode else 67.5), score_floor - 0.75 + engine_c_exec_quality_add)
                conf_floor = max((70 if reach_mode else 73), conf_floor + engine_c_exec_conf_add)
                rr_floor = max((1.06 if reach_mode else 1.14), rr_floor - 0.03 + engine_c_exec_rr_add)
            elif sess == 'NY':
                score_floor = max(69.0, score_floor + 0.10 + engine_c_exec_quality_add)
                conf_floor = max(72, conf_floor + engine_c_exec_conf_add)
                rr_floor = max(1.16, rr_floor + 0.01 + engine_c_exec_rr_add)
            else:
                score_floor = max(68.5, score_floor + 0.20 + engine_c_exec_quality_add)
                conf_floor = max(71, conf_floor + engine_c_exec_conf_add)
                rr_floor = max(1.12, rr_floor + 0.01 + engine_c_exec_rr_add)
        elif engine == 'B':
            if not exec_engine_b_enabled:
                return (False, 'engine_b_disabled')
            if sess == 'LON':
                score_floor = max(74.5, score_floor + 0.5)
                conf_floor = max(77, conf_floor + 1)
                rr_floor = max(1.30, rr_floor + 0.04)
            elif sess == 'NY':
                score_floor = max(76.0, score_floor + 0.75)
                conf_floor = max(78, conf_floor + 1)
                rr_floor = max(1.38, rr_floor + 0.05)
            else:
                score_floor = max(77.0, score_floor + 1.0)
                conf_floor = max(79, conf_floor + 1)
                rr_floor = max(1.40, rr_floor + 0.05)
        else:
            return (False, 'engine_not_supported')

        # Modest profile-aware relaxation for currently active research families in GLOBAL profiles.
        # This helps the widened family allocator actually surface candidates without turning the
        # executable lane into a loose screen lane.
        try:
            plan = _research_latest_allocator_plan(sess, regime_primary=str(getattr(s, 'regime_primary', '') or '').upper().strip()) or {}
            active_json = plan.get('active_families_json') or []
            if isinstance(active_json, str):
                active_fams = [str(x).upper().strip() for x in json.loads(active_json or '[]') if str(x).strip()]
            else:
                active_fams = [str(x).upper().strip() for x in (active_json or []) if str(x).strip()]
        except Exception:
            active_fams = []

        if active_profile.startswith('GLOBAL_') and fam and fam in set(active_fams):
            # Keep the broader NY reach, but do not let active-family relaxations over-loosen LON.
            if engine in {'A', 'C'} and sess == 'NY' and ('TREND' in regime or 'EXPANSION' in regime):
                score_floor -= 0.75
                conf_floor -= 1
                rr_floor -= 0.02
            elif engine == 'B' and sess == 'NY' and 'EXPANSION' in regime:
                score_floor -= 1.25
                conf_floor -= 1
                rr_floor -= 0.03
            elif engine in {'A', 'C'} and sess == 'LON' and ('TREND' in regime or 'EXPANSION' in regime):
                score_floor -= 0.10
                rr_floor -= 0.00

        # Family-aware executable calibration. These are deliberately modest and only help
        # regime-consistent families convert a little better without turning the email lane
        # into a loose screen lane.
        if fam == 'F4_SWEEP_RECLAIM' and regime in {'BALANCE', 'EXHAUSTION'}:
            if sess in {'LON', 'NY'}:
                score_floor -= 2.75
                conf_floor -= 2
                rr_floor -= 0.08
            else:
                score_floor -= 3.25
                conf_floor -= 3
                rr_floor -= 0.10
        elif fam == 'F2_MOMENTUM_IGNITION' and regime == 'EXPANSION':
            if sess == 'NY':
                score_floor -= 0.90
                conf_floor -= 1
                rr_floor -= 0.02
            elif sess == 'LON':
                score_floor -= 0.25
                rr_floor -= 0.00
        elif fam == 'F3_IMPULSE_BASE_CONT' and regime in {'EXPANSION', 'SQUEEZE'}:
            if sess == 'NY':
                score_floor -= 0.80
                conf_floor -= 1
                rr_floor -= 0.02
            elif sess == 'LON':
                score_floor -= 0.20
                rr_floor -= 0.00
        elif fam == 'F1_PULLBACK_CONT' and 'TREND' in regime and sess == 'LON':
            score_floor += 0.50
            rr_floor += 0.02

        # Low-flow recovery: when the last 24h has too few executable/email setups,
        # soften final executable gates slightly. This targets droughts only and avoids
        # opening a generic low-quality momentum lane.
        if low_flow_recovery:
            if fam == BIGMOVE_FAMILY_ID:
                score_floor -= 1.25
                conf_floor -= 1
                rr_floor -= 0.12
            elif engine in {'A', 'C'}:
                score_floor -= 1.10 if sess in {'NY', 'LON'} else 0.75
                conf_floor -= 1
                rr_floor -= 0.04 if sess in {'NY', 'LON'} else 0.03
            elif engine == 'B' and sess == 'NY' and regime == 'EXPANSION':
                score_floor -= 0.60
                rr_floor -= 0.02

        # Ver13 Setup Matrix -> optimizer bridge. These per family/session adjustments
        # are generated by scheduled weekly review or daily severe-loser safety review.
        try:
            if combo_override:
                score_floor += float(combo_override.get('quality_add', 0.0) or 0.0)
                conf_floor += int(round(float(combo_override.get('conf_add', 0) or 0)))
                rr_floor += float(combo_override.get('rr_add', 0.0) or 0.0)
        except Exception:
            pass

        score_floor = float(clamp(score_floor, 58.0 if active_profile.startswith('GLOBAL_') else 60.0, 92.0))
        conf_floor = int(max(68 if active_profile.startswith('GLOBAL_') else 69, min(95, conf_floor)))
        rr_floor = float(clamp(rr_floor, 0.98 if active_profile.startswith('GLOBAL_') else 1.02, 2.30))

        if fam == 'F4_SWEEP_RECLAIM' and regime in {'BALANCE', 'EXHAUSTION'}:
            pass
        elif fam == 'F5_ORB_RETEST' and regime in {'SQUEEZE', 'EXPANSION'}:
            pass
        elif fam == 'F3_IMPULSE_BASE_CONT' and regime in {'EXPANSION', 'SQUEEZE'}:
            pass
        elif 'TREND' not in regime and 'EXPANSION' not in regime:
            return (False, 'regime_not_trend')
        if fam == 'F4_SWEEP_RECLAIM' and regime in {'BALANCE', 'EXHAUSTION'}:
            pass
        elif want and (want not in trend or want not in structure):
            return (False, 'trend_structure_not_aligned')

        score = float(getattr(s, "quality_score", 0.0) or 0.0)
        conf = int(getattr(s, "conf", 0) or 0)
        entry = float(getattr(s, "entry", 0.0) or 0.0)
        sl = float(getattr(s, "sl", 0.0) or 0.0)
        final_tp = float(_setup_target_tp(s, 0.0) or 0.0)
        rr_final = float(rr_to_tp(entry, sl, final_tp)) if entry > 0 and sl > 0 and final_tp > 0 else 0.0
        fut_vol = float(getattr(s, "fut_vol_usd", 0.0) or 0.0)

        # Ver13 per-combo hard refinements from Setup Matrix optimizer bridge.
        # Used mainly after a disabled combo is allowed back for re-testing.
        try:
            if combo_override:
                fam_code_for_override = _setup_combo_compact_family_from_runtime(fam)
                min_vol_mult = float(combo_override.get('min_volume_mult', 0.0) or 0.0)
                if min_vol_mult > 0 and fut_vol < float(_setup_min_volume_floor_usd()) * min_vol_mult:
                    return (False, 'combo_bridge_below_liquidity')
                if fam_code_for_override != 'F8':
                    ema_max = float(combo_override.get('ema_max_pct', 0.0) or 0.0)
                    if ema_max > 0 and pb_dist > ema_max:
                        return (False, 'combo_bridge_ema_too_far')
                max_ch15 = float(combo_override.get('max_ch15_abs', 0.0) or 0.0)
                if max_ch15 > 0 and ch15_abs > max_ch15:
                    return (False, 'combo_bridge_15m_too_extended')
                max_ch1 = float(combo_override.get('max_ch1_abs', 0.0) or 0.0)
                if max_ch1 > 0 and ch1_abs > max_ch1:
                    return (False, 'combo_bridge_1h_too_extended')
        except Exception:
            pass

        # FIX5: low-flow executable bridge. If the scan is producing valid current-market setups
        # but the normal production gates are still too tight, allow clean A/C candidates into
        # the authoritative executable pool. This feeds /screen, setup emails, and admin autotrade
        # without bypassing price order, RR, confidence, or liquidity.
        try:
            ch24_bridge = abs(float(getattr(s, "ch24", 0.0) or 0.0))
            if low_flow_recovery and engine in {'A', 'C'}:
                if score >= 58.0 and conf >= 68 and rr_final >= 1.05 and fut_vol >= max(4_000_000.0, float(MIN_FUT_VOL_USD) * 0.40) and ch24_bridge >= 1.0:
                    return (True, 'ok')
        except Exception:
            pass

        # Recovery setups are generated only when normal OHLCV engines return nothing.
        # They already passed structural price checks in the shared gate above, so do not
        # kill them on the normal high-quality floor before their recovery checks run.
        try:
            if bool(getattr(s, 'recovery_fallback', False)):
                if engine != 'A':
                    return (False, 'recovery_engine_not_a')
                if conf < 72:
                    return (False, 'recovery_below_conf')
                if rr_final < 1.12:
                    return (False, 'recovery_below_rr')
                if fut_vol < max(3_500_000.0, float(MIN_FUT_VOL_USD) * 0.40):
                    return (False, 'recovery_below_liquidity')
                return (True, 'ok')
        except Exception:
            pass

        if score < score_floor:
            return (False, "below_exec_quality")

        if conf < conf_floor:
            return (False, "below_exec_conf")

        if rr_final < rr_floor:
            return (False, "below_exec_rr")
        pb_dist = float(getattr(s, "pullback_ema_dist_pct", 999.0) or 999.0)
        ch15_val = float(getattr(s, "ch15", 0.0) or 0.0)
        ch1_val = float(getattr(s, "ch1", 0.0) or 0.0)
        ch4_val = float(getattr(s, "ch4", 0.0) or 0.0)
        ch15_abs = abs(ch15_val)
        ch1_abs = abs(ch1_val)
        ch4_abs = abs(ch4_val)
        ch24_abs = abs(float(getattr(s, "ch24", 0.0) or 0.0))

        # Big-Move is a confirmed impulse family. It must not be killed by the
        # generic late-extension/pullback gates used for normal A/B/C setups; those
        # gates are exactly where a valid Big-Move signal is expected to be large.
        if fam == BIGMOVE_FAMILY_ID:
            same_dir = (
                (side == 'BUY' and ch15_val > 0 and ch1_val > 0 and ch4_val > 0) or
                (side == 'SELL' and ch15_val < 0 and ch1_val < 0 and ch4_val < 0)
            )
            if not same_dir:
                return (False, "bigmove_direction_mismatch")

            bm_quality_floor = max(68.0 if sess != 'ASIA' else 69.0, float(score_floor) - 4.0)
            bm_conf_floor = max(78 if sess != 'ASIA' else 80, int(conf_floor))
            bm_rr_floor = max(1.65 if low_flow_recovery else 1.75, float(rr_floor) + 0.05)
            bm_vol_floor = max(float(BIGMOVE_DEFAULT_MIN_VOL_USD), float(MIN_FUT_VOL_USD) * (1.10 if sess == 'ASIA' else 1.05))

            if score < bm_quality_floor:
                return (False, f"bigmove_below_quality_{bm_quality_floor:.0f}")
            if conf < bm_conf_floor:
                return (False, f"bigmove_below_conf_{bm_conf_floor}")
            if rr_final < bm_rr_floor:
                return (False, f"bigmove_rr_below_{bm_rr_floor:.2f}")
            if fut_vol < bm_vol_floor:
                return (False, f"bigmove_liquidity_below_{bm_vol_floor/1e6:.1f}M")
            if ch15_abs < float(BIGMOVE_DEFAULT_15M_PCT) or ch1_abs < float(BIGMOVE_DEFAULT_1H_PCT) or ch4_abs < float(BIGMOVE_DEFAULT_4H_PCT):
                return (False, "bigmove_thresholds_not_met")
            if want and ((trend and want not in trend) or (structure and want not in structure)):
                return (False, "bigmove_structure_not_aligned")
            return (True, "ok")

        if sess == "NY":
            if fam == 'F4_SWEEP_RECLAIM' and regime in {'BALANCE', 'EXHAUSTION'}:
                if pb_dist > (1.10 + f4_pb_relax):
                    return (False, "ny_entry_too_far_from_ema")
                if ch15_abs > (1.05 + f4_ch15_relax) or ch1_abs > (1.90 + f4_ch1_relax):
                    return (False, "ny_late_extension_exec")
                if ch24_abs < 4.0:
                    return (False, "ny_context_too_weak_exec")
                if fut_vol < float(max(MIN_FUT_VOL_USD * 0.68, 7_500_000.0)):
                    return (False, "ny_below_liquidity")
            else:
                ny_pb_cap = 1.28 if low_flow_recovery else 1.18
                ny_ch15_cap = 1.34 if low_flow_recovery else 1.24
                ny_ch15_pair_cap = 1.12 if low_flow_recovery else 1.02
                ny_ch1_cap = 2.22 if low_flow_recovery else 2.08
                ny_ctx_ch4_min = 0.22 if low_flow_recovery else 0.28
                ny_ctx_ch1_min = 0.06 if low_flow_recovery else 0.08
                if pb_dist > ny_pb_cap:
                    return (False, "ny_entry_too_far_from_ema")
                if ch15_abs > ny_ch15_cap or (ch15_abs > ny_ch15_pair_cap and ch1_abs > ny_ch1_cap):
                    return (False, "ny_late_extension_exec")
                if ch4_abs < ny_ctx_ch4_min or ch1_abs < ny_ctx_ch1_min:
                    return (False, "ny_context_too_weak_exec")
                if fut_vol < max(MIN_FUT_VOL_USD * 0.68, 6_500_000.0):
                    return (False, "ny_below_liquidity")
        elif sess == "LON":
            if fam == 'F4_SWEEP_RECLAIM' and regime in {'BALANCE', 'EXHAUSTION'}:
                if pb_dist > (1.00 + f4_pb_relax):
                    return (False, "lon_entry_too_far_from_ema")
                if ch15_abs > (0.96 + f4_ch15_relax) or ch1_abs > (1.75 + f4_ch1_relax):
                    return (False, "lon_late_extension_exec")
                if ch24_abs < 4.2:
                    return (False, "lon_context_too_weak_exec")
                if fut_vol < float(max(MIN_FUT_VOL_USD * 0.66, 7_000_000.0)):
                    return (False, "lon_below_liquidity")
            else:
                lon_pb_max = 0.98 if reach_mode else 0.90
                lon_ch15_cap = 0.96 if reach_mode else 0.84
                lon_ch1_cap = 1.72 if reach_mode else 1.54
                lon_ctx_ch4_min = 0.18 if reach_mode else 0.26
                lon_ctx_ch1_min = 0.04 if reach_mode else 0.08
                lon_liq_floor = max(MIN_FUT_VOL_USD * (0.66 if reach_mode else 0.72), 6_000_000.0 if reach_mode else 7_000_000.0)
                if low_flow_recovery:
                    lon_pb_max += 0.08
                    lon_ch15_cap += 0.07
                    lon_ch1_cap += 0.12
                    lon_ctx_ch4_min = max(0.12, lon_ctx_ch4_min - 0.06)
                    lon_ctx_ch1_min = max(0.03, lon_ctx_ch1_min - 0.03)
                if engine == 'C':
                    lon_pb_max = max(lon_pb_max, engine_c_exec_pb_dist_lon)
                    lon_ch1_cap = max(lon_ch1_cap, engine_c_exec_ch1_cap_lon)
                    lon_liq_floor = max(MIN_FUT_VOL_USD * engine_c_exec_liq_mult, ENGINE_C_MIN_FUT_VOL_USD)
                    lon_ctx_ch4_min = min(lon_ctx_ch4_min, 0.48)
                    lon_ctx_ch1_min = min(lon_ctx_ch1_min, 0.22)
                if pb_dist > lon_pb_max:
                    return (False, "lon_entry_too_far_from_ema")
                if ch15_abs > lon_ch15_cap or ch1_abs > lon_ch1_cap:
                    return (False, "lon_late_extension_exec")
                if ch4_abs < lon_ctx_ch4_min or ch1_abs < lon_ctx_ch1_min:
                    return (False, "lon_context_too_weak_exec")
                if ch4_abs > (3.30 if reach_mode else 2.95) or ch24_abs > (17.5 if reach_mode else 15.8):
                    return (False, "lon_trend_overheated_exec")
                if fut_vol < lon_liq_floor:
                    return (False, "lon_below_liquidity")
        elif sess == "ASIA":
            if fam == 'F4_SWEEP_RECLAIM' and regime in {'BALANCE', 'EXHAUSTION'}:
                if pb_dist > (1.05 + f4_pb_relax):
                    return (False, "asia_entry_too_far_from_ema")
                if ch15_abs > (0.98 + f4_ch15_relax) or ch1_abs > (1.70 + f4_ch1_relax):
                    return (False, "asia_late_extension_exec")
                if ch24_abs < 5.5:
                    return (False, "asia_context_too_weak_exec")
                if fut_vol < float(max(MIN_FUT_VOL_USD * 0.70, 6_500_000.0)):
                    return (False, "asia_below_liquidity")
            else:
                asia_pb_cap = 0.96 if low_flow_recovery else 0.88
                asia_ch15_cap = 0.96 if low_flow_recovery else 0.88
                asia_ch1_cap = 1.66 if low_flow_recovery else 1.56
                asia_ctx_ch4_min = 0.28 if low_flow_recovery else 0.34
                asia_ctx_ch1_min = 0.09 if low_flow_recovery else 0.12
                if pb_dist > asia_pb_cap:
                    return (False, "asia_entry_too_far_from_ema")
                if ch15_abs > asia_ch15_cap or ch1_abs > asia_ch1_cap:
                    return (False, "asia_late_extension_exec")
                if ch4_abs < asia_ctx_ch4_min or ch1_abs < asia_ctx_ch1_min:
                    return (False, "asia_context_too_weak_exec")
                if fut_vol < float(max(MIN_FUT_VOL_USD * 0.60, 8_000_000.0)):
                    return (False, "asia_below_liquidity")

        if engine == "A":
            if fam == 'F4_SWEEP_RECLAIM' and regime in {'BALANCE', 'EXHAUSTION'}:
                if sess == 'ASIA' and ch24_abs < 5.0:
                    return (False, 'asia_balance_reclaim_too_weak')
                return (True, "ok")
            if fam == 'F7_EXHAUSTION_FAILURE':
                if fut_vol < max(12_000_000.0, MIN_FUT_VOL_USD * 0.70):
                    return (False, 'f7_below_liquidity')
                if ch24_abs < 14.0:
                    return (False, 'f7_not_exhausted_enough')
                if rr_final < max(1.10, rr_floor - 0.05):
                    return (False, 'f7_below_rr')
                return (True, "ok")
            if not (bool(getattr(s, "pullback_ready", False)) or bool(getattr(s, "pullback_bypass_hot", False))):
                return (False, "pullback_not_ready")
            if pb_dist > ((0.96 if reach_mode else 0.82) if sess == 'LON' else (0.86 if sess == 'NY' else 0.78)):
                return (False, "pullback_still_too_shallow")
            if sess == 'LON' and (ch15_abs > (0.86 if reach_mode else 0.66) or ch1_abs < (0.06 if reach_mode else 0.12) or ch1_abs > (1.52 if reach_mode else 1.28) or ch4_abs < (0.24 if reach_mode else 0.34)):
                return (False, 'lon_pullback_not_clean_enough')
            return (True, "ok")

        if engine == "C":
            c_quality_floor = score_floor + (0.00 if reach_mode and sess == 'LON' else 0.00)
            c_conf_floor = max(71 if (reach_mode and sess == 'LON') else conf_floor, conf_floor - (1 if reach_mode and sess == 'LON' else 0))
            c_rr_floor = max(1.04 if (reach_mode and sess == 'LON') else rr_floor, rr_floor - (0.08 if reach_mode and sess == 'LON' else 0.03))
            c_liq_floor = float(max(MIN_FUT_VOL_USD * ((max(0.96, engine_c_exec_liq_mult - 0.08)) if not (reach_mode and sess == 'LON') else 0.68), 5_500_000.0 if (reach_mode and sess == 'LON') else 7_500_000.0))
            c_ch1_cap = (max(engine_c_exec_ch1_cap_lon, 1.88) if (reach_mode and sess == 'LON') else max(engine_c_exec_ch1_cap_lon, 1.56)) if sess == 'LON' else (1.78 if sess == 'NY' else 1.42)
            if score < c_quality_floor:
                return (False, "engine_c_below_quality")
            if conf < c_conf_floor:
                return (False, "engine_c_below_conf")
            if rr_final < c_rr_floor:
                return (False, "engine_c_below_rr")
            if fut_vol < c_liq_floor:
                return (False, "engine_c_below_liquidity")
            if ch1_abs > c_ch1_cap:
                return (False, "engine_c_too_extended")
            return (True, "ok")

        if engine == "B":
            if fam in {'F5_ORB_RETEST', 'F6_VWAP_RECLAIM'}:
                if fut_vol < max(10_000_000.0, MIN_FUT_VOL_USD * 0.65):
                    return (False, f"{fam.lower()}_below_liquidity")
                if conf < max(70, conf_floor - 2):
                    return (False, f"{fam.lower()}_below_conf")
                if rr_final < max(1.08, rr_floor - 0.07):
                    return (False, f"{fam.lower()}_below_rr")
                return (True, "ok")
            if fam == BIGMOVE_FAMILY_ID:
                bm_quality_floor = max(score_floor + 0.5, 66.5 if sess != 'ASIA' else 67.5)
                bm_conf_floor = max(conf_floor, 78 if sess != 'ASIA' else 80)
                bm_rr_floor = max(rr_floor + 0.08, 1.65 if low_flow_recovery else 1.75)
                if score < bm_quality_floor:
                    return (False, "bigmove_below_quality")
                if conf < bm_conf_floor:
                    return (False, "bigmove_below_conf")
                if rr_final < bm_rr_floor:
                    return (False, "bigmove_below_rr")
                if fut_vol < float(max(BIGMOVE_DEFAULT_MIN_VOL_USD, MIN_FUT_VOL_USD * (1.05 if sess != 'ASIA' else 1.10))):
                    return (False, "bigmove_below_liquidity")
                if abs(ch15_abs) < float(BIGMOVE_DEFAULT_15M_PCT) or abs(ch1_abs) < float(BIGMOVE_DEFAULT_1H_PCT) or abs(ch4_abs) < float(BIGMOVE_DEFAULT_4H_PCT):
                    return (False, "bigmove_thresholds_not_held")
                return (True, "ok")
            if score < (score_floor + 1.0):
                return (False, "engine_b_below_quality")
            if conf < (conf_floor + 1):
                return (False, "engine_b_below_conf")
            if rr_final < (rr_floor + 0.03):
                return (False, "engine_b_below_rr")
            if fut_vol < float(max(MIN_FUT_VOL_USD * (1.00 if sess != 'ASIA' else 1.05), 12_000_000.0 if sess != 'ASIA' else ASIA_MIN_FUT_VOL_USD)):
                return (False, "engine_b_below_liquidity")
            return (True, "ok")

        return (False, "engine_not_supported")
    except Exception:
        return (False, "executable_gate_exception")

def compute_confidence(side: str, ch24: float, ch4: float, ch1: float, ch15: float, fut_vol_usd: float) -> int:
    """
    Stricter confidence designed for:
    - Fewer, higher quality continuation signals
    - Avoiding mid-wave / pump entries
    - Preferring "pullback then continuation" (15m should be mild or slightly counter-trend)
    """
    is_long = (side == "BUY")

    # Base score starts lower to reduce inflated confidences
    score = 36.0

    # -----------------------------
    # 1) Higher-TF alignment first
    # -----------------------------
    def aligned(x: float) -> bool:
        return (x > 0) if is_long else (x < 0)

    a24 = aligned(ch24)
    a4  = aligned(ch4)
    a1  = aligned(ch1)
    a15 = aligned(ch15)

    align_count = int(a24) + int(a4) + int(a1) + int(a15)

    # Stronger reward for 4H/1H alignment (regime + execution TF)
    score += 14.0 if a4 else -18.0
    score += 12.0 if a1 else -16.0

    # 24H matters, but less than 4H/1H for trade execution quality
    score += 8.0 if a24 else -10.0

    # 15m alignment is NOT always good for entries (pumps are bad entries)
    # We'll handle 15m separately as "pullback quality"
    # (so do not add big alignment reward here)
    score += 2.0 if a15 else -2.0

    # Hard cap if the structure is weak:
    # If 4H+1H disagree with your side, confidence should never be high.
    if (not a4) and (not a1):
        return int(55)  # keep it low; you can also return 0 if you want total block

    # If at least 3 TFs align (24/4/1/15), small boost
    if align_count >= 3:
        score += 6.0
    elif align_count <= 1:
        score -= 10.0

    # -----------------------------
    # 2) Magnitude scoring (capped)
    # -----------------------------
    def signed_mag(x: float, k: float) -> float:
        return (abs(x) * k) if aligned(x) else (-abs(x) * k)

    mag = (
        signed_mag(ch24, 0.5) +
        signed_mag(ch4,  0.9) +
        signed_mag(ch1,  1.2) +
        signed_mag(ch15, 0.6)
    )
    mag = clamp(mag, -18.0, 18.0)
    score += mag

    # -----------------------------
    # 3) Anti-pump + pullback preference (15m behavior)
    # -----------------------------
    # For continuation entries:
    # - We *don't* want 15m strongly in-trend (often means mid-wave / extended).
    # - We *do* like mild pullback against the trend (e.g. -0.3% to -1.2% in BUY).
    ch15_abs = abs(float(ch15))

    if is_long:
        # Mid-wave pump penalty: 15m strongly positive
        if ch15 >= 0.8:
            score -= 12.0
        elif ch15 >= 0.4:
            score -= 6.0

        # Preferred pullback zone (slight red 15m)
        if -1.2 <= ch15 <= -0.25:
            score += 10.0
        elif -2.2 <= ch15 < -1.2:
            score += 4.0

        # Too much dump into support = unstable
        if ch15 <= -2.8:
            score -= 10.0
    else:
        # Mid-wave dump penalty: 15m strongly negative
        if ch15 <= -0.8:
            score -= 12.0
        elif ch15 <= -0.4:
            score -= 6.0

        # Preferred pullback zone (slight green 15m)
        if 0.25 <= ch15 <= 1.2:
            score += 10.0
        elif 1.2 < ch15 <= 2.2:
            score += 4.0

        # Too much pump into resistance = unstable
        if ch15 >= 2.8:
            score -= 10.0

    # -----------------------------
    # 4) Volume bonus (smaller + only when structure is already good)
    # -----------------------------
    # Volume should NOT rescue a bad setup.
    # Only add if score already indicates decent structure.
    if score >= 60.0:
        if fut_vol_usd >= 40_000_000:
            score += 5.0
        elif fut_vol_usd >= 15_000_000:
            score += 3.0
        elif fut_vol_usd >= 6_000_000:
            score += 1.5

    # Public confidence should remain conservative; quality_score is the main gate.
    score = clamp(score, 0.0, 92.0)
    return int(round(score))


def build_leaders_table(best_fut: Dict[str, MarketVol]) -> str:
    leaders = sorted(best_fut.items(), key=lambda kv: usd_notional(kv[1]), reverse=True)[:LEADERS_N]
    rows = []

    for base, mv in leaders:
        # ✅ 4H change from real 4h candles (light: limit=2)
        ch4 = 0.0
        try:
            c4h = fetch_ohlcv(mv.symbol, "4h", limit=2)
            if c4h and len(c4h) >= 2:
                c_last = float(c4h[-1][4])
                c_prev = float(c4h[-2][4])
                if c_prev > 0:
                    ch4 = ((c_last - c_prev) / c_prev) * 100.0
        except Exception:
            ch4 = 0.0

        rows.append([
            base,
            fmt_money(usd_notional(mv)),
            pct_with_emoji(float(mv.percentage or 0.0)),  # 24H
            pct_with_emoji(float(ch4)),                  # 4H
        ])

    return "*Market Leaders (Top 10 by Futures Volume)*\n" + table_md(rows, ["SYM", "F Vol", "24H", "4H"])

def compute_directional_lists(best_fut: Dict[str, MarketVol]) -> Tuple[List[Tuple], List[Tuple]]:
    """
    Fast + rate-limit-safe directional movers.

    Cached briefly because /screen may be called repeatedly while the market snapshot
    itself has barely changed.
    """
    try:
        bases = sorted(str(k) for k in (best_fut or {}).keys())
        fingerprint = f"{len(bases)}:{'|'.join(bases[:30])}:{'|'.join(bases[-5:]) if len(bases) > 35 else ''}"
    except Exception:
        fingerprint = f"{len(best_fut or {})}"
    cache_key = f"screen_directional_lists:{fingerprint}"
    try:
        if cache_valid(cache_key, int(SCREEN_DIRECTIONAL_CACHE_TTL_SEC or 55)):
            cached = cache_get(cache_key)
            if isinstance(cached, dict):
                return list(cached.get('up') or []), list(cached.get('dn') or [])
    except Exception:
        pass

    up, dn = [], []
    try:
        candidates = []
        for base, mv in best_fut.items():
            vol = usd_notional(mv)
            if vol < MOVER_VOL_USD_MIN:
                continue
            ch24 = float(mv.percentage or 0.0)
            if ch24 < MOVER_UP_24H_MIN and ch24 > MOVER_DN_24H_MAX:
                continue
            candidates.append((base, mv, vol, ch24))
        candidates.sort(key=lambda x: x[2], reverse=True)
        candidates = candidates[:18]
    except Exception:
        candidates = []

    for base, mv, vol, ch24 in candidates:
        try:
            c4h = fetch_ohlcv(mv.symbol, "4h", limit=2)
            if not c4h or len(c4h) < 2:
                continue
            c_last = float(c4h[-1][4])
            c_prev = float(c4h[-2][4])
            if c_prev <= 0:
                continue
            ch4 = ((c_last - c_prev) / c_prev) * 100.0
        except Exception:
            continue

        if ch24 >= MOVER_UP_24H_MIN and ch4 > 0:
            up.append((base, vol, ch24, ch4, float(mv.last or 0.0)))
        if ch24 <= MOVER_DN_24H_MAX and ch4 < 0:
            dn.append((base, vol, ch24, ch4, float(mv.last or 0.0)))

    up.sort(key=lambda x: (x[2], x[1]), reverse=True)
    dn.sort(key=lambda x: (x[2], x[1]))
    try:
        cache_set(cache_key, {'up': list(up), 'dn': list(dn)})
    except Exception:
        pass
    return up, dn

def movers_tables(best_fut: Dict[str, MarketVol]) -> Tuple[str, str]:
    up, dn = compute_directional_lists(best_fut)
    up_rows = [[b, fmt_money(v), pct_with_emoji(c24), pct_with_emoji(c4)] for b, v, c24, c4, px in up[:10]]
    dn_rows = [[b, fmt_money(v), pct_with_emoji(c24), pct_with_emoji(c4)] for b, v, c24, c4, px in dn[:10]]
    up_txt = "*Directional Leaders (24H ≥ +10%, F vol ≥ 5M, 4H aligned)*\n" + (table_md(up_rows, ["SYM", "F Vol", "24H", "4H"]) if up_rows else "_None_")
    dn_txt = "*Directional Losers (24H ≤ -10%, F vol ≥ 5M, 4H aligned)*\n" + (table_md(dn_rows, ["SYM", "F Vol", "24H", "4H"]) if dn_rows else "_None_")
    return up_txt, dn_txt


def _engine_c_detect_pump_base(
    side: str,
    entry: float,
    atr_1h: float,
    ch24: float,
    ch4: float,
    fut_vol: float,
    c15: list,
    ema_support_15m: float,
    aggressive_screen: bool = False,
) -> dict:
    """Detect post-impulse 15m compression / range continuation.

    Idea:
    - a strong impulse already happened (pump/dump candle)
    - then price pauses in a narrow 15m base near the impulse highs/lows
    - support/resistance holds and price starts to break/reclaim the base again

    This is deliberately stricter than Engine B so it targets "pump then base then continue"
    instead of raw expansion candles.
    """
    out = {
        'ok': False,
        'reason': 'na',
        'side': str(side or '').upper(),
        'impulse_pct': 0.0,
        'base_width_pct': 999.0,
        'base_bars': 0,
        'support_level': 0.0,
        'resistance_level': 0.0,
        'breakout_ready': False,
    }
    try:
        side = str(side or '').upper().strip()
        if side not in ('BUY', 'SELL'):
            out['reason'] = 'bad_side'
            return out
        if entry <= 0 or atr_1h <= 0 or not c15 or len(c15) < 18:
            out['reason'] = 'missing_inputs'
            return out
        if abs(float(ch24 or 0.0)) < float(ENGINE_C_MIN_CH24):
            out['reason'] = 'ch24_too_small'
            return out
        if abs(float(ch4 or 0.0)) < float(ENGINE_C_MIN_ABS_CH4):
            out['reason'] = 'ch4_too_small'
            return out
        if float(fut_vol or 0.0) < float(ENGINE_C_MIN_FUT_VOL_USD):
            out['reason'] = 'fut_vol_too_small'
            return out

        bars = c15[-24:]
        opens = [float(x[1]) for x in bars]
        highs = [float(x[2]) for x in bars]
        lows = [float(x[3]) for x in bars]
        closes = [float(x[4]) for x in bars]
        vols = [float(x[5]) for x in bars]
        if len(closes) < 18:
            out['reason'] = 'window_too_small'
            return out

        ranges = [max(0.0, h - l) for h, l in zip(highs, lows)]
        prior = ranges[:-1]
        med_range = sorted(prior)[len(prior)//2] if prior else 0.0
        if med_range <= 0:
            med_range = max(entry * 0.002, float(atr_1h) * 0.18)
        vol_hist = vols[:-1]
        vol_med = sorted(vol_hist)[len(vol_hist)//2] if vol_hist else 0.0

        impulse_idx = None
        impulse_score = -1.0
        lookback = min(16, len(closes) - int(ENGINE_C_MIN_BASE_BARS) - 1)
        for idx in range(max(1, len(closes) - lookback - 1), len(closes) - int(ENGINE_C_MIN_BASE_BARS)):
            o = opens[idx]
            h = highs[idx]
            l = lows[idx]
            c = closes[idx]
            rng = max(1e-12, h - l)
            body_pct = abs(c - o) / max(o, 1e-12) * 100.0
            range_mult = rng / max(med_range, 1e-12)
            vol_mult = (vols[idx] / max(vol_med, 1e-12)) if vol_med > 0 else 1.0
            close_loc = (c - l) / rng if side == 'BUY' else (h - c) / rng
            directional_ok = (c > o) if side == 'BUY' else (c < o)
            if not directional_ok:
                continue
            need_impulse = float(ENGINE_C_MIN_IMPULSE_15M_PCT) * (0.88 if aggressive_screen else 1.0)
            need_vol = float(ENGINE_C_MIN_IMPULSE_VOL_MULT) * (0.92 if aggressive_screen else 1.0)
            if body_pct < need_impulse:
                continue
            if range_mult < 2.0:
                continue
            if close_loc < 0.60:
                continue
            if vol_mult < need_vol:
                continue
            score = body_pct + (range_mult * 1.2) + min(2.5, vol_mult)
            if score > impulse_score:
                impulse_score = score
                impulse_idx = idx

        if impulse_idx is None:
            out['reason'] = 'no_impulse_bar'
            return out

        base = bars[impulse_idx + 1:]
        if len(base) < int(ENGINE_C_MIN_BASE_BARS):
            out['reason'] = 'base_too_short'
            return out
        if len(base) > int(ENGINE_C_MAX_BASE_BARS):
            base = base[-int(ENGINE_C_MAX_BASE_BARS):]

        b_highs = [float(x[2]) for x in base]
        b_lows = [float(x[3]) for x in base]
        b_closes = [float(x[4]) for x in base]
        b_opens = [float(x[1]) for x in base]
        b_ranges = [max(1e-12, float(x[2]) - float(x[3])) for x in base]

        impulse_high = highs[impulse_idx]
        impulse_low = lows[impulse_idx]
        impulse_range = max(1e-12, impulse_high - impulse_low)
        impulse_close = closes[impulse_idx]
        last_close = b_closes[-1]
        base_high = max(b_highs)
        base_low = min(b_lows)
        base_width_pct = ((base_high - base_low) / max(last_close, 1e-12)) * 100.0
        out['impulse_pct'] = abs((impulse_close - opens[impulse_idx]) / max(opens[impulse_idx], 1e-12) * 100.0)
        out['base_width_pct'] = float(base_width_pct)
        out['base_bars'] = int(len(base))
        out['support_level'] = float(base_low)
        out['resistance_level'] = float(base_high)

        width_limit = float(ENGINE_C_MAX_BASE_WIDTH_PCT) * (1.18 if aggressive_screen else 1.0)
        if base_width_pct > width_limit:
            out['reason'] = 'base_too_wide'
            return out

        hold_portion = float(ENGINE_C_HOLD_PORTION)
        if side == 'BUY':
            hold_line = impulse_low + (impulse_range * hold_portion)
            if base_low < hold_line:
                out['reason'] = 'lost_impulse_support'
                return out
            if ema_support_15m > 0 and last_close < (ema_support_15m * 0.985):
                out['reason'] = 'below_ema_support'
                return out
            upper_half = sum(1 for c in b_closes if c >= (base_low + (base_high - base_low) * 0.50))
            if upper_half < max(2, len(base) // 2):
                out['reason'] = 'base_not_holding_high'
                return out
            breakout_ready = last_close >= (base_high * (1.0 - float(ENGINE_C_BREAKOUT_BUFFER_PCT) / 100.0))
            reclaim_ok = b_closes[-1] >= b_opens[-1]
            if not (breakout_ready and reclaim_ok):
                out['reason'] = 'not_ready_for_breakout'
                out['breakout_ready'] = bool(breakout_ready)
                return out
        else:
            hold_line = impulse_high - (impulse_range * hold_portion)
            if base_high > hold_line:
                out['reason'] = 'lost_impulse_resistance'
                return out
            if ema_support_15m > 0 and last_close > (ema_support_15m * 1.015):
                out['reason'] = 'above_ema_resistance'
                return out
            lower_half = sum(1 for c in b_closes if c <= (base_low + (base_high - base_low) * 0.50))
            if lower_half < max(2, len(base) // 2):
                out['reason'] = 'base_not_holding_low'
                return out
            breakout_ready = last_close <= (base_low * (1.0 + float(ENGINE_C_BREAKOUT_BUFFER_PCT) / 100.0))
            reclaim_ok = b_closes[-1] <= b_opens[-1]
            if not (breakout_ready and reclaim_ok):
                out['reason'] = 'not_ready_for_breakdown'
                out['breakout_ready'] = bool(breakout_ready)
                return out

        # Extra stability: base should actually compress after impulse.
        avg_base_range = sum(b_ranges) / max(1, len(b_ranges))
        if avg_base_range > (impulse_range * 0.62):
            out['reason'] = 'base_not_compressed'
            return out

        out['ok'] = True
        out['reason'] = 'ok'
        out['breakout_ready'] = True
        return out
    except Exception as e:
        out['reason'] = f'exception:{type(e).__name__}'
        return out

