def _ver14_infer_active_family_hint(
    side: str,
    entry: float,
    ch24: float,
    ch4: float,
    ch1: float,
    ch15: float,
    fut_vol: float,
    c15: list,
    c1: list,
    session_name: str = "",
) -> tuple[str, str, str]:
    """Lightweight F4-F7 discovery overlays.

    The original live engines produced F1/F2/F3 plus F8. Ver14 keeps those and
    adds safe identification rules for the research families so we can collect
    live samples before prioritising them. The returned side may flip only for
    explicit reversal families (F4/F7).
    """
    try:
        sess = str(session_name or '').upper().strip()
        sd = str(side or '').upper().strip()
        vol = float(fut_vol or 0.0)
        if vol < max(5_000_000.0, float(MIN_FUT_VOL_USD or 0.0) * 0.45):
            return ('', sd, '')
        closes15 = [float(x[4]) for x in (c15 or []) if len(x) >= 5]
        highs15 = [float(x[2]) for x in (c15 or []) if len(x) >= 5]
        lows15 = [float(x[3]) for x in (c15 or []) if len(x) >= 5]
        vols15 = [float(x[5]) for x in (c15 or []) if len(x) >= 6]
        last_close = float(closes15[-1]) if closes15 else float(entry or 0.0)

        # F7 — Exhaustion failure reversal: very extended 24h/4h move starts failing.
        try:
            if vol >= max(12_000_000.0, float(MIN_FUT_VOL_USD or 0.0) * 0.75):
                if float(ch24 or 0.0) >= 18.0 and (float(ch1 or 0.0) <= -0.22 or float(ch15 or 0.0) <= -0.18):
                    return ('F7_EXHAUSTION_FAILURE', 'SELL', 'exhaustion_failure_short')
                if float(ch24 or 0.0) <= -18.0 and (float(ch1 or 0.0) >= 0.22 or float(ch15 or 0.0) >= 0.18):
                    return ('F7_EXHAUSTION_FAILURE', 'BUY', 'exhaustion_failure_long')
        except Exception:
            pass

        # F6 — VWAP reclaim/rejection aligned with intraday direction.
        try:
            if len(closes15) >= 16 and len(vols15) >= 16:
                typical = []
                for i in range(-24, 0):
                    try:
                        typical.append(((highs15[i] + lows15[i] + closes15[i]) / 3.0, vols15[i]))
                    except Exception:
                        continue
                denom = sum(v for _, v in typical) or 0.0
                vwap = (sum(px * v for px, v in typical) / denom) if denom > 0 else 0.0
                prev_close = float(closes15[-2])
                if vwap > 0:
                    if prev_close <= vwap and last_close > vwap and (float(ch1 or 0.0) >= -0.05 or float(ch24 or 0.0) >= 3.0):
                        return ('F6_VWAP_RECLAIM', 'BUY', 'vwap_reclaim_long')
                    if prev_close >= vwap and last_close < vwap and (float(ch1 or 0.0) <= 0.05 or float(ch24 or 0.0) <= -3.0):
                        return ('F6_VWAP_RECLAIM', 'SELL', 'vwap_reclaim_short')
        except Exception:
            pass

        # F5 — ORB/retest style breakout: close breaks recent range after a retest.
        try:
            if sess in {'ASIA', 'LON', 'NY'} and len(closes15) >= 18:
                prior_high = max(highs15[-13:-1])
                prior_low = min(lows15[-13:-1])
                recent_low = min(lows15[-5:])
                recent_high = max(highs15[-5:])
                if last_close > prior_high and recent_low <= prior_high * 1.004 and (float(ch24 or 0.0) >= 3.0 or float(ch1 or 0.0) >= 0.15):
                    return ('F5_ORB_RETEST', 'BUY', 'range_break_retest_long')
                if last_close < prior_low and recent_high >= prior_low * 0.996 and (float(ch24 or 0.0) <= -3.0 or float(ch1 or 0.0) <= -0.15):
                    return ('F5_ORB_RETEST', 'SELL', 'range_break_retest_short')
        except Exception:
            pass

        return ('', sd, '')
    except Exception:
        return ('', str(side or '').upper().strip(), '')

def make_setup(
    base: str,
    mv: MarketVol,
    strict_15m: bool = True,
    session_name: str = "LON",
    allow_no_pullback: bool = True,     # /screen True, Email False (except HOT bypass)
    hot_vol_usd: float = HOT_VOL_USD,   # 50M
    trigger_loosen_mult: float = 1.0,
    waiting_near_pct: float = SCREEN_WAITING_NEAR_PCT,
    scan_profile: str = DEFAULT_SCAN_PROFILE,
) -> Optional[Setup]:

    fut_vol = usd_notional(mv)
    if fut_vol <= 0:
        _rej("no_futures_volume", base, mv)
        return None

    entry = float(mv.last or 0.0)
    if entry <= 0:
        _rej("bad_entry", base, mv)
        return None

    ch24 = float(mv.percentage or 0.0)

    _note_status("evaluated", base, mv)


    notes = []  # collect internal notes for pullback policy / diagnostics
    try:

        ch1, ch4, ch15, atr_1h, ema_support_15m, ema_period, c15, c1 = metrics_from_candles_1h_15m(mv.symbol)

    except Exception:

        _rej("ohlcv_missing_or_insufficient", base, mv)

        return None
    # Use true 4H change from 4H candles (more stable than 1H*4 approximation)
    try:
        ch4_exact = 0.0
        try:
            c4h = fetch_ohlcv(mv.symbol, "4h", limit=6)
            if c4h and len(c4h) >= 2:
                c_last_4h = float(c4h[-1][4])
                c_prev_4h = float(c4h[-2][4])
                ch4_exact = ((c_last_4h - c_prev_4h) / c_prev_4h) * 100.0 if c_prev_4h else 0.0
        except Exception:
            ch4_exact = 0.0

        ch4_used = ch4_exact if abs(ch4_exact) > 0.0001 else ch4

        if (ch1 == 0.0 and ch4 == 0.0 and ch15 == 0.0 and atr_1h == 0.0) or (not c15) or (ema_support_15m == 0.0):
            _rej("ohlcv_missing_or_insufficient", base, mv, "metrics/ema missing")
            return None

        # Scan profile tuning
        prof = str(scan_profile or DEFAULT_SCAN_PROFILE).strip().lower()
        if prof not in SCAN_PROFILES:
            prof = DEFAULT_SCAN_PROFILE
        aggressive_screen = (prof == "aggressive" and (not strict_15m))

        # --------- SESSION-DYNAMIC 1H TRIGGER ----------
        atr_pct_now = (atr_1h / entry) * 100.0 if (atr_1h and entry) else 0.0
        trig_min_raw = trigger_1h_abs_min_atr_adaptive(atr_pct_now, session_name)

        floor_min = 0.02 if aggressive_screen else 0.04  # further loosened: allow setups in quiet 1H candles
        trig_min = max(float(floor_min), float(trig_min_raw) * float(trigger_loosen_mult))

        if abs(ch1) < trig_min:
            # Waiting for Trigger (near-miss) — store ONLY side + a color dot (no numbers)
            if trig_min > 0:
                ratio = abs(ch1) / trig_min  # internal only
                if ratio >= float(waiting_near_pct):
                    # color indicates "how close" WITHOUT revealing thresholds
                    if ratio >= 0.92:
                        dot = "🟢"
                    elif ratio >= 0.82:
                        dot = "🟡"
                    else:
                        dot = "🟠"

                    side_guess = ("BUY" if ch4 >= 0 else "SELL") if abs(ch4) >= 0.25 else ("BUY" if ch1 > 0 else "SELL")
                    _WAITING_TRIGGER[str(base)] = {"side": side_guess, "dot": dot}

            # Balanced breakout override: even if 1H change is small, allow true breakouts
            # Additional overrides: allow setups during quiet 1H candles if 4H/24H move is strong and 15m confirms.
            override_4h = (abs(float(ch4_used or 0.0)) >= max(0.75, float(trig_min) * 1.45)) and (abs(float(ch15 or 0.0)) >= 0.08)
            override_24h = (abs(float(ch24 or 0.0)) >= 8.0) and (abs(float(ch15 or 0.0)) >= 0.06)
            # Extra override: if 24H is very strong AND 4H aligns, don't require 15m confirmation (quiet consolidation after a big move)
            override_24h_strong = (abs(float(ch24 or 0.0)) >= 15.0) and (abs(float(ch4_used or 0.0)) >= 0.50) and (float(fut_vol or 0.0) >= 5_000_000.0)
            breakout_override = False
            # Trend override: if 4H regime move is meaningful, allow even if this 1H is quiet.
            try:
                if abs(float(ch4_used or 0.0)) >= max(0.60, float(trig_min) * 2.5) and float(fut_vol or 0.0) >= 5_000_000.0:
                    breakout_override = True
            except Exception:
                pass
            try:
                if c1 and len(c1) >= 25 and abs(ch24) >= 5.0:
                    highs_1h = [float(x[2]) for x in c1]
                    lows_1h  = [float(x[3]) for x in c1]
                    closes_1h = [float(x[4]) for x in c1]
                    vols_1h  = [float(x[5]) for x in c1]
                    last_close = float(closes_1h[-1])
                    last_high  = float(highs_1h[-1])
                    last_low   = float(lows_1h[-1])
                    hh20 = max(highs_1h[-21:-1])
                    ll20 = min(lows_1h[-21:-1])
                    vnow = float(vols_1h[-1])
                    vavg = (sum(vols_1h[-21:-1]) / 20.0) if vols_1h[-21:-1] else 0.0

                    vol_mult = 1.04  # balanced default
                    if (ch24 >= 6.0) and (last_high > hh20 or last_close > hh20) and ((vavg > 0 and vnow >= vavg * vol_mult) or (vavg <= 0 and vnow > 0)):
                        breakout_override = True
                    if (ch24 <= -6.0) and (last_low < ll20 or last_close < ll20) and ((vavg > 0 and vnow >= vavg * vol_mult) or (vavg <= 0 and vnow > 0)):
                        breakout_override = True
            except Exception:
                breakout_override = False

            # Soft override: if we are close to the trigger and the higher timeframe move supports direction,
            # allow a lower-confidence setup instead of rejecting everything on a quiet 1H candle.
            try:
                ratio = (abs(float(ch1)) / float(trig_min)) if float(trig_min) > 0 else 0.0
            except Exception:
                ratio = 0.0
            trend_active_mode = not _research_balance_reversal_mode(session_name)
            soft_override = (ratio >= 0.70) and (float(fut_vol or 0.0) >= 5_000_000.0) and (
                abs(float(ch4_used or 0.0)) >= 0.50 or abs(float(ch24 or 0.0)) >= 12.0
            )
            try:
                if _setup_low_flow_recovery_active(session_name, lookback_hours=24):
                    soft_override = soft_override or (
                        ratio >= 0.30 and float(fut_vol or 0.0) >= 4_000_000.0 and (
                            abs(float(ch24 or 0.0)) >= 4.0 or abs(float(ch4_used or 0.0)) >= 0.18 or abs(float(ch15 or 0.0)) >= 0.05
                        )
                    )
                # Very strong current market leaders/losers should not be rejected only
                # because the latest single 1h candle is quiet.
                soft_override = soft_override or (
                    abs(float(ch24 or 0.0)) >= 10.0 and float(fut_vol or 0.0) >= 8_000_000.0 and (
                        abs(float(ch4_used or 0.0)) >= 0.25 or abs(float(ch15 or 0.0)) >= 0.04
                    )
                )
            except Exception:
                pass
            if trend_active_mode and str(session_name).upper() == 'ASIA':
                soft_override = soft_override or (
                    ratio >= 0.38 and float(fut_vol or 0.0) >= 3_000_000.0 and (
                        abs(float(ch4_used or 0.0)) >= 0.24 or abs(float(ch24 or 0.0)) >= 5.0 or abs(float(ch15 or 0.0)) >= 0.08
                    )
                )
            balance_reversal_mode = _research_balance_reversal_mode(session_name)
            balance_reversal_override = False
            try:
                sess_u = str(session_name).upper()
                if balance_reversal_mode:
                    if sess_u == 'ASIA':
                        balance_reversal_override = (ratio >= 0.05) and (float(fut_vol or 0.0) >= 2_000_000.0) and (
                            abs(float(ch24 or 0.0)) >= 2.0 or abs(float(ch4_used or 0.0)) >= 0.08
                        )
                    elif sess_u in {'LON', 'NY'}:
                        balance_reversal_override = (ratio >= 0.05) and (float(fut_vol or 0.0) >= 2_500_000.0) and (
                            abs(float(ch24 or 0.0)) >= 2.8 or abs(float(ch4_used or 0.0)) >= 0.10
                        )
            except Exception:
                balance_reversal_override = False

            if not (breakout_override or override_4h or override_24h or override_24h_strong or soft_override or balance_reversal_override):
                _rej("ch1_below_trigger", base, mv, f"ch1={ch1:+.2f}% trig={trig_min:.2f}% ch4={ch4:+.2f}% ch24={ch24:+.2f}% ch15={ch15:+.2f}%")
                return None


        # ✅ IMPORTANT: this must be OUTSIDE the if block (no extra indent)
        family_id_hint = ""
        balance_reversal_side = ""
        try:
            if balance_reversal_mode:
                rev_vol_floor = 2_000_000.0 if str(session_name).upper() == 'ASIA' else 2_500_000.0
                up_ext = float(ch24 or 0.0) >= (1.8 if str(session_name).upper() == 'ASIA' else 2.6)
                dn_ext = float(ch24 or 0.0) <= (-(1.8 if str(session_name).upper() == 'ASIA' else 2.6))
                fade_long = dn_ext and float(fut_vol or 0.0) >= rev_vol_floor and (float(ch15 or 0.0) >= -0.45 or float(ch1 or 0.0) >= -0.85 or float(ch4_used or 0.0) >= -1.10)
                fade_short = up_ext and float(fut_vol or 0.0) >= rev_vol_floor and (float(ch15 or 0.0) <= 0.45 or float(ch1 or 0.0) <= 0.85 or float(ch4_used or 0.0) <= 1.10)
                if fade_long:
                    balance_reversal_side = 'BUY'
                    family_id_hint = 'F4_SWEEP_RECLAIM'
                elif fade_short:
                    balance_reversal_side = 'SELL'
                    family_id_hint = 'F4_SWEEP_RECLAIM'
        except Exception:
            family_id_hint = family_id_hint or ""
            balance_reversal_side = balance_reversal_side or ""
        side = str(balance_reversal_side or (("BUY" if ch4 >= 0 else "SELL") if abs(ch4) >= 0.40 else ("BUY" if ch1 > 0 else "SELL")))  # trend-side gating: prefer 4H regime over 1H noise

        # Ver14: identify all active research families (F4-F7) when their
        # lightweight price/trend rules are met. These are overlays on the
        # existing engines so they do not break the proven A/B/C/F8 plumbing.
        try:
            fam_extra, side_extra, fam_reason_extra = _ver14_infer_active_family_hint(
                side, entry, ch24, ch4_used, ch1, ch15, fut_vol, c15, c1, session_name=session_name
            )
            if fam_extra and not family_id_hint:
                family_id_hint = str(fam_extra)
                side = str(side_extra or side).upper().strip()
                if fam_reason_extra:
                    notes.append(str(fam_reason_extra))
        except Exception:
            pass

        # 4H alignment
        # If 4H is basically flat, don't block (leaders often show ch4 ~ 0 while 24H is huge).
        if family_id_hint not in {'F4_SWEEP_RECLAIM', 'F7_EXHAUSTION_FAILURE'} and abs(ch4) >= float(ALIGN_4H_NEUTRAL_ZONE):
            if side == "BUY" and ch4 < ALIGN_4H_MIN:
                _rej("4h_not_aligned_for_long", base, mv, f"side=BUY ch4={ch4:+.2f}%")
                return None
            if side == "SELL" and ch4 > -ALIGN_4H_MIN:
                _rej("4h_not_aligned_for_short", base, mv, f"side=SELL ch4={ch4:+.2f}%")
                return None

        # ✅ HARD regime gate: don't fight the 4H direction (unless "strong reversal exception")
        if family_id_hint not in {'F4_SWEEP_RECLAIM', 'F7_EXHAUSTION_FAILURE'} and TF_ALIGN_ENABLED and abs(ch4) >= float(ALIGN_4H_NEUTRAL_ZONE):
            if side == "BUY" and ch4 < 0:
                if not strong_reversal_exception_ok(side, ch24, ch4, ch1):
                    _rej("4h_bear_regime_blocks_long", base, mv, f"ch4={ch4:+.2f}%")
                    return None
            if side == "SELL" and ch4 > 0:
                if not strong_reversal_exception_ok(side, ch24, ch4, ch1):
                    _rej("4h_bull_regime_blocks_short", base, mv, f"ch4={ch4:+.2f}%")
                    return None


        # ✅ Approach A (ASIA): require basic 1H+4H alignment with the signal direction
        # (NY/LON unchanged to keep flow)
        try:
            if str(session_name).upper() == "ASIA":
                min1, min4 = tf_align_mins_for_session(session_name)
                balance_reversal_mode = _research_balance_reversal_mode(session_name)
                if balance_reversal_mode:
                    min1 = max(0.10, float(min1) * 0.28)
                    min4 = max(0.05, float(min4) * 0.14)
                if family_id_hint in {'F4_SWEEP_RECLAIM'} and balance_reversal_mode:
                    if side == "BUY":
                        asia_ok = bool(float(ch24 or 0.0) <= -3.0 and (float(ch15 or 0.0) >= -0.10 or float(ch1 or 0.0) >= -0.28 or float(ch4 or 0.0) >= -0.50))
                        if not asia_ok:
                            _rej("asia_tf_align_fail_long", base, mv, f"f4_balance ch1={ch1:+.2f}% ch4={ch4:+.2f}% ch24={ch24:+.2f}%")
                            return None
                    else:
                        asia_ok = bool(float(ch24 or 0.0) >= 3.0 and (float(ch15 or 0.0) <= 0.10 or float(ch1 or 0.0) <= 0.28 or float(ch4 or 0.0) <= 0.50))
                        if not asia_ok:
                            _rej("asia_tf_align_fail_short", base, mv, f"f4_balance ch1={ch1:+.2f}% ch4={ch4:+.2f}% ch24={ch24:+.2f}%")
                            return None
                elif side == "BUY":
                    trend_soft_asia = (not balance_reversal_mode) and (float(ch24 or 0.0) >= 3.8) and (float(fut_vol or 0.0) >= 2_500_000.0) and (
                        float(ch4 or 0.0) >= max(0.10, float(min4) * 0.32)
                    ) and (float(ch1 or 0.0) >= max(0.04, float(min1) * 0.28) or float(ch15 or 0.0) >= -0.12)
                    asia_ok = bool(ch1 >= min1 and (ch4 >= min4 or balance_reversal_mode and ch24 >= 4.0)) or trend_soft_asia
                    if not asia_ok:
                        _rej("asia_tf_align_fail_long", base, mv, f"ch1={ch1:+.2f}% ch4={ch4:+.2f}% need>=({min1},{min4})")
                        return None
                else:
                    trend_soft_asia = (not balance_reversal_mode) and (float(ch24 or 0.0) <= -3.8) and (float(fut_vol or 0.0) >= 2_500_000.0) and (
                        float(ch4 or 0.0) <= -max(0.10, float(min4) * 0.32)
                    ) and (float(ch1 or 0.0) <= -max(0.04, float(min1) * 0.28) or float(ch15 or 0.0) <= 0.12)
                    asia_ok = bool(ch1 <= -min1 and (ch4 <= -min4 or balance_reversal_mode and ch24 <= -4.0)) or trend_soft_asia
                    if not asia_ok:
                        _rej("asia_tf_align_fail_short", base, mv, f"ch1={ch1:+.2f}% ch4={ch4:+.2f}% need<=(-{min1},-{min4})")
                        return None
        except Exception:
            pass

        # =========================================================
        # ✅ PULLBACK EMA (7/14/21) selection (15m)
        # =========================================================
        closes_15 = [float(x[4]) for x in c15]
        pb_ema_val, pb_ema_p, pb_dist_pct = best_pullback_ema_15m(closes_15, c15, entry, side, session_name, atr_1h)

        # ✅ No HOT bypass: pullback is ALWAYS required for high-quality continuation entries
        pullback_bypass_hot = False

        pb_ok = False
        pb_thr_pct = 0.0
        pb_dist_pct2 = 999.0

        if pb_ema_val > 0:
            pb_ok, pb_dist_pct2, pb_thr_pct, _ = ema_support_proximity_ok(entry, pb_ema_val, atr_1h, session_name)

        pullback_ready = bool(pb_ok)

        leader_base_override = _leader_base_override_ok(side, ch24, ch4_used, ch15, fut_vol, pullback_ready, pb_dist_pct2, session_name)

        # Aggressive /screen: allow "near-EMA" pullback (slightly looser proximity)
        if (not pullback_ready) and aggressive_screen and (pb_ema_val > 0) and (pb_thr_pct > 0):
            try:
                if float(pb_dist_pct2) <= float(pb_thr_pct) * 1.35:
                    pullback_ready = True
            except Exception:
                pass

        # 15m rejection candle requirement (skip in Aggressive /screen)
        require_rejection = bool(REQUIRE_15M_EMA_REJECTION and (not aggressive_screen))

        # ✅ Strict continuation entry: must show EMA interaction + strong 15m rejection/reclaim
        if pullback_ready and require_rejection:
            if (not c15) or (pb_ema_val <= 0):
                _rej("no_ema_touch_reclaim_recent", base, mv,
                     f"ema{pb_ema_p} pb_dist={pb_dist_pct2:.2f}% thr={pb_thr_pct:.2f}%")
                return None

            if not ema_rejection_candle_ok_15m(c15, pb_ema_val, side):
                _rej("no_strong_rejection_candle_15m", base, mv, f"ema{pb_ema_p} pb_dist={pb_dist_pct2:.2f}%")
                return None

        # =========================================================
        # ENGINE A (Mean-Reversion) vs ENGINE B (Momentum)
        # =========================================================
        engine_a_ok = bool(ENGINE_A_PULLBACK_ENABLED and pullback_ready)

        engine_b_ok = False
        engine_c_ok = False
        engine_c_info = {"ok": False, "reason": "disabled"}

        if ENGINE_B_MOMENTUM_ENABLED:
            # Aggressive /screen: slightly looser momentum requirements
            mom_min_ch1 = float(MOMENTUM_MIN_CH1) * (0.75 if aggressive_screen else 1.0)
            mom_min_24h = float(MOMENTUM_MIN_24H) * (0.75 if aggressive_screen else 1.0)
            mom_body_mult = float(MOMENTUM_ATR_BODY_MULT) * (0.85 if aggressive_screen else 1.0)
            mom_max_ema_dist = float(MOMENTUM_MAX_ADAPTIVE_EMA_DIST) * ((1.60 if (not strict_15m) else 1.0)) * (1.30 if aggressive_screen else 1.0)

            # ------------------------------------------------------------------
            # B1) Momentum continuation (existing)
            # ------------------------------------------------------------------
            if abs(ch1) >= mom_min_ch1 and abs(ch24) >= mom_min_24h:
                if fut_vol >= (MOVER_VOL_USD_MIN * MOMENTUM_VOL_MULT):
                    body_pct = abs(ch1)
                    if atr_pct_now > 0 and body_pct >= (mom_body_mult * atr_pct_now):
                        _, dist_pct, _, _ = ema_support_proximity_ok(entry, ema_support_15m, atr_1h, session_name)
                        if dist_pct <= mom_max_ema_dist:
                            engine_b_ok = True

            # ------------------------------------------------------------------
            # B2) Balanced Breakout continuation (NEW)
            # Purpose: avoid "leaders full, setups empty" during expansion phases.
            # Uses the already-fetched 1H candles (c1) to avoid extra API calls / rate limits.
            # ------------------------------------------------------------------
            try:
                ch24_thr = 4.0 if aggressive_screen else 5.0
                vol_mult = 1.05 if aggressive_screen else 1.08

                # Use 4H/side gating already computed as the trend regime.
                uptrend = (ch4_used >= 0)
                downtrend = (ch4 < 0)

                if abs(ch24) >= ch24_thr and fut_vol >= max(5_000_000.0, float(MOVER_VOL_USD_MIN) * 0.70) and c1 and len(c1) >= 25:
                    highs_1h = [float(x[2]) for x in c1]
                    lows_1h  = [float(x[3]) for x in c1]
                    closes_1h = [float(x[4]) for x in c1]
                    vols_1h  = [float(x[5]) for x in c1]

                    last_close = float(closes_1h[-1])
                    last_high = float(highs_1h[-1])
                    last_low  = float(lows_1h[-1])
                    vnow = float(vols_1h[-1])
                    vavg = (sum(vols_1h[-21:-1]) / 20.0) if vols_1h[-21:-1] else 0.0

                    # Prior 20-candle extremes (exclude the current candle)
                    hh20 = max(highs_1h[-21:-1])
                    ll20 = min(lows_1h[-21:-1])

                    # Breakout BUY
                    if uptrend and ch24 >= ch24_thr and (last_high > hh20 or last_close > hh20) and ((vavg > 0 and vnow >= vavg * vol_mult) or (vavg <= 0 and vnow > 0)):
                        engine_b_ok = True
                        mv._pf_breakout_hint = "BUY"

                    # Breakdown SELL
                    if downtrend and ch24 <= -ch24_thr and (last_low < ll20 or last_close < ll20) and ((vavg > 0 and vnow >= vavg * vol_mult) or (vavg <= 0 and vnow > 0)):
                        engine_b_ok = True
                        mv._pf_breakout_hint = "SELL"
            except Exception:
                pass
    
        # If breakout engine fired, force side to match the breakout direction (prevents green BUY / red mismatch)
        try:
            hint = getattr(mv, "_pf_breakout_hint", None)
            if engine_b_ok and hint in ("BUY", "SELL"):
                side = hint
        except Exception:
            pass

        # If breakout engine fired, force side to match the breakout direction (prevents green BUY / red mismatch)
        try:
            hint = getattr(mv, "_pf_breakout_hint", None)
            if engine_b_ok and hint in ("BUY", "SELL"):
                side = hint
        except Exception:
            pass

        # ---------------------------------------------------------
        # ENGINE C (Pump-base / range continuation after impulse)
        # ---------------------------------------------------------
        if ENGINE_C_PUMP_BASE_ENABLED:
            try:
                engine_c_info = _engine_c_detect_pump_base(
                    side=side,
                    entry=entry,
                    atr_1h=atr_1h,
                    ch24=ch24,
                    ch4=ch4_used,
                    fut_vol=fut_vol,
                    c15=c15,
                    ema_support_15m=ema_support_15m,
                    aggressive_screen=aggressive_screen,
                )
                engine_c_ok = bool(engine_c_info.get('ok'))
            except Exception:
                engine_c_ok = False

        # Ver14 research family overlays can activate the underlying engine lane
        # when their own pattern rules pass. This keeps the downstream setup/email/
        # autotrade plumbing stable while still tagging the correct family.
        try:
            if family_id_hint in {'F5_ORB_RETEST', 'F6_VWAP_RECLAIM'}:
                engine_b_ok = True
                notes.append(f"{family_id_hint.lower()}_engine_b_overlay")
            elif family_id_hint == 'F7_EXHAUSTION_FAILURE':
                engine_a_ok = True
                notes.append('f7_exhaustion_failure_overlay')
        except Exception:
            pass

        if not engine_a_ok and not engine_b_ok and not engine_c_ok:
            if family_id_hint in {'F4_SWEEP_RECLAIM'} and balance_reversal_mode and float(fut_vol or 0.0) >= 2_500_000.0 and abs(float(ch24 or 0.0)) >= 3.0:
                engine_a_ok = True
                notes.append("🟡 f4_balance_reclaim_fallback")
            else:
                _rej("no_engine_passed", base, mv, f"ch1={ch1:.2f} ch24={ch24:.2f} pb_dist={pb_dist_pct:.2f} ec={engine_c_info.get('reason','na')}")
                return None

        # ---------------------------------------------------------
        # Pullback policy (optional for Engine B / Engine C on /screen)
        # ---------------------------------------------------------
        engine = "A" if engine_a_ok else ("C" if engine_c_ok else "B")
        require_pullback = (not bool(allow_no_pullback))

        # Compute confidence BEFORE applying optional pullback penalty
        conf = compute_confidence(side, ch24, ch4, ch1, ch15, fut_vol)

        # ---------------------------------------------------------
        # ✅ PulseFutures PRO quality overlay (safe integration)
        # Uses the appended advanced engines as a confirmation layer
        # without rewriting the whole live signal pipeline.
        # ---------------------------------------------------------
        try:
            # SMC structure (HH/HL/LH/LL + BOS/CHOCH) — higher-quality trend filter
            smc = pf_market_structure_smc(c1[-220:] if c1 else c1, fractal=2, lookback=220)
            structure = str(smc.get("bias", "UNKNOWN")).upper()
            bos = str(smc.get("bos", "NONE")).upper()
            choch = str(smc.get("choch", "NONE")).upper()

            trend = pf_mtf_alignment(mv.symbol, fetch_ohlcv)  # 4H + 1H only (5m too noisy for hard gating)
            regime = pf_market_regime(c1[-60:] if c1 else c1)

            sweep_info = pf_liquidity_sweep_v2(c15[-90:] if c15 else c15, lookback_swings=90, fractal=2)
            sweep = str(sweep_info.get("event", "NONE")).upper()

            momentum = pf_orderflow_momentum(c15[-20:] if c15 else c15)

            smf = pf_smart_money_flow(c15[-90:] if c15 else c15, vol_lookback=30)
            smf_event = str(smf.get("event", "NONE")).upper()
            smf_score = int(smf.get("score", 0) or 0)


            want_trend = "BULLISH" if side == "BUY" else "BEARISH"
            # Do NOT hard-block merely because SMC structure is not the exact wanted bias.
            # In live markets many valid continuation or base-break setups print as RANGE/UNKNOWN
            # for stretches, and the stricter hard reject was starving setup generation.
            # We only hard-block when structure is explicitly opposite *and* the broader trend
            # also disagrees a few lines below. Otherwise keep the setup and let confidence /
            # quality scoring decide.
            if structure not in (want_trend, "RANGE", "UNKNOWN", "NEUTRAL", "NONE", ""):
                notes.append(f"smc_structure_soft_mismatch={structure}")
                conf = max(0.0, float(conf) - 5.0)

            # CHOCH is useful, but making it a hard block caused total NY/LON droughts
            # when the broader ticker/volume context was still tradable. In low-flow or
            # strong-volume conditions, soften it into a confidence penalty and let the
            # shared executable/email gates decide.
            choch_against = (side == "BUY" and choch == "CHOCH_DOWN") or (side == "SELL" and choch == "CHOCH_UP")
            if choch_against:
                try:
                    low_flow_now = _setup_low_flow_recovery_active(session_name, lookback_hours=24)
                except Exception:
                    low_flow_now = False
                strong_context_now = bool(abs(float(ch24 or 0.0)) >= 6.0 and float(fut_vol or 0.0) >= 8_000_000.0)
                if low_flow_now or strong_context_now or family_id_hint in {'F1_PULLBACK_CONT', 'F3_IMPULSE_BASE_CONT', 'F4_SWEEP_RECLAIM'}:
                    notes.append(f"smc_choch_soft={choch}")
                    conf = max(0.0, float(conf) - (4.0 if strong_context_now else 5.0))
                else:
                    _rej("smc_choch_against_long" if side == "BUY" else "smc_choch_against_short", base, mv, f"choch={choch} bos={bos} structure={structure} smf={smf_event}")
                    return None
            opposite_trend = "BEARISH" if side == "BUY" else "BULLISH"
            sweep_ok = (side == "BUY" and sweep == "BUY_SWEEP") or (side == "SELL" and sweep == "SELL_SWEEP")
            momentum_ok = (side == "BUY" and momentum == "BULLISH") or (side == "SELL" and momentum == "BEARISH")
            momentum_bad = (side == "BUY" and momentum == "BEARISH") or (side == "SELL" and momentum == "BULLISH")

            # Hard block only when the advanced engines strongly disagree.
            if structure == opposite_trend and trend == opposite_trend:
                if family_id_hint in {'F4_SWEEP_RECLAIM'} and balance_reversal_mode:
                    notes.append(f"smc_structure_trend_soft_conflict={structure}/{trend}")
                    conf = max(0.0, float(conf) - 1.0)
                else:
                    _rej("pro_structure_trend_conflict", base, mv, f"side={side} structure={structure} trend={trend}")
                    return None

            # Momentum engine works best in trend regimes, not ranging.
            if engine == "B" and strict_15m and regime == "RANGING" and (not sweep_ok):
                _rej("pro_ranging_regime_blocks_momentum_soft", base, mv, f"side={side} regime={regime}")
                conf -= 3
                notes.append("ranging_penalty")

            # Confidence nudges: reward alignment, penalize conflict.
            if structure == want_trend:
                conf += 3
            elif structure == "RANGE":
                conf -= 1

            if trend == want_trend:
                conf += 3
            elif trend == "MIXED":
                conf -= 1

            if sweep_ok:
                conf += 4
            if momentum_ok:
                conf += 3
            if momentum_bad:
                conf -= 4

            # BOS adds confidence for continuation entries
            if side == "BUY" and bos == "BOS_UP":
                conf += 2
            if side == "SELL" and bos == "BOS_DOWN":
                conf += 2

            # Smart Money Flow detection (institutional activity / liquidation / ignition)
            smf_buy = smf_event in ("BUY_IGNITION", "LIQUIDATION_BUY")
            smf_sell = smf_event in ("SELL_IGNITION", "LIQUIDATION_SELL")
            if side == "BUY" and smf_buy:
                conf += 2 + min(2, max(0, smf_score - 2))
            elif side == "SELL" and smf_sell:
                conf += 2 + min(2, max(0, smf_score - 2))
            elif (side == "BUY" and smf_sell) or (side == "SELL" and smf_buy):
                # Strong opposite smart-money signature: avoid
                if family_id_hint in {'F4_SWEEP_RECLAIM'} and balance_reversal_mode:
                    notes.append("smf_opposes_soft")
                    conf -= 3
                else:
                    _rej("smart_money_opposes_side_soft", base, mv, f"side={side} smf={smf_event} score={smf_score} structure={structure} trend={trend}")
                    conf -= 6
                    notes.append("smf_opposes_soft")
            # Require at least 2 of 3 core confirmations for aggressive momentum setups.
            if engine == "B":
                core_hits = 0
                if trend == want_trend:
                    core_hits += 1
                if structure == want_trend:
                    core_hits += 1
                if sweep_ok or momentum_ok:
                    core_hits += 1
                if core_hits < 2:
                    _rej("pro_quality_gate_failed_soft", base, mv, f"side={side} hits={core_hits} trend={trend} structure={structure} sweep={sweep} momentum={momentum}")
                    conf -= 5
                    notes.append(f"pro_hits={core_hits}")

            if engine == "C":
                if trend == want_trend:
                    conf += 2
                if structure == want_trend:
                    conf += 2
                if bos in ("BOS_UP", "BOS_DOWN"):
                    conf += 1
                if str(regime or "").upper() == "RANGING":
                    conf += 2
                c_base_width = float(engine_c_info.get('base_width_pct', 999.0) or 999.0)
                if c_base_width <= 4.0:
                    conf += 3
                elif c_base_width <= 6.5:
                    conf += 1
                else:
                    conf -= 2

            conf = int(clamp(float(conf), 0.0, 100.0))
        except Exception:
            pass

        # Email/autotrade quality path can require a real 15m pullback for both engines.
        # This was previously bypassed for Engine B, which let too many NY momentum setups through.
        pullback_ok_local = bool(pullback_ready) if require_pullback else True

        keep, conf2 = apply_pullback_policy(
            require_pullback=require_pullback,
            pullback_ok=pullback_ok_local,
            pullback_price=(pb_ema_val if pb_ema_val > 0 else None),
            confidence=float(conf),
            notes=notes,
        )

        conf = conf2

        if not keep:
            balance_reversal_mode = _research_balance_reversal_mode(session_name)
            if family_id_hint in {'F4_SWEEP_RECLAIM'} and balance_reversal_mode:
                notes.append("🟡 f4_pullback_override")
                conf = max(0.0, float(conf) - 3.0)
                keep = True
            elif balance_reversal_mode and engine in {"A", "C"}:
                notes.append("🟡 balance_reversal_pullback_override")
                conf = max(0.0, float(conf) - 4.0)
                keep = True
            else:
                _rej("pullback_required_not_met", base, mv, "require_pullback=1")
                return None

        if engine == "A" and abs(float(ch1)) >= float(SHARP_1H_MOVE_PCT):
            # EMA touch/reaction on 15m is OPTIONAL: do not hard-reject if it's missing.
            # (Ramin requested: no hard requirement to touch 15m EMA.)
            if not ema_support_reaction_ok_15m(c15, pb_ema_val, side, session_name):
                notes.append("🟡 No strong 15m EMA reaction detected (optional check).")
                conf = max(0.0, float(conf) - 4.0)

        thr = clamp(max(12.0, 2.5 * ((atr_1h / entry) * 100.0 if (atr_1h and entry) else 0.0)), 12.0, 22.0)
        if side == "BUY" and ch24 <= -thr:
            if family_id_hint in {'F4_SWEEP_RECLAIM'} and balance_reversal_mode:
                notes.append("f4_24h_contradiction_soft")
                conf = max(0.0, float(conf) - 2.0)
            else:
                _rej("24h_contradiction_for_long", base, mv, f"ch24={ch24:+.1f}% <= -{thr:.1f}%")
                return None
        if side == "SELL" and ch24 >= +thr:
            if family_id_hint in {'F4_SWEEP_RECLAIM'} and balance_reversal_mode:
                notes.append("f4_24h_contradiction_soft")
                conf = max(0.0, float(conf) - 2.0)
            else:
                _rej("24h_contradiction_for_short", base, mv, f"ch24={ch24:+.1f}% >= +{thr:.1f}%")
                return None

        is_confirm_15m = abs(ch15) >= CONFIRM_15M_ABS_MIN
        is_early_allowed = (abs(ch1) >= EARLY_1H_ABS_MIN)

        if strict_15m:
            if (not is_confirm_15m) and (not is_early_allowed):
                try:
                    low_flow_now = _setup_low_flow_recovery_active(session_name, lookback_hours=24)
                except Exception:
                    low_flow_now = False
                strong_context_now = bool(abs(float(ch24 or 0.0)) >= 8.0 and float(fut_vol or 0.0) >= 8_000_000.0)
                if family_id_hint in {'F4_SWEEP_RECLAIM'} and balance_reversal_mode:
                    notes.append('🟡 f4_weak15m_soft')
                    conf = max(0.0, float(conf) - 2.0)
                elif low_flow_now or strong_context_now:
                    notes.append('🟡 weak15m_low_flow_soft')
                    conf = max(0.0, float(conf) - (3.0 if strong_context_now else 4.0))
                else:
                    _rej("15m_weak_and_not_early", base, mv, f"ch15={ch15:+.2f}% ch1={ch1:+.2f}%")
                    return None

        if strict_15m and (not is_confirm_15m):
            conf = max(0, int(conf) - int(EARLY_CONF_PENALTY))


        # ---------------------------------------------------------
        # ✅ Global quality gate: session-aware confidence floor
        # ---------------------------------------------------------
        try:
            sess_min = int(_session_generation_conf_floor(session_name))
            if family_id_hint in {'F4_SWEEP_RECLAIM'} and balance_reversal_mode:
                if str(session_name or '').upper() == 'ASIA':
                    sess_min = min(int(sess_min), 52)
                else:
                    sess_min = min(int(sess_min), 54)
            if str(session_name or '').upper() == 'NY' and require_pullback and family_id_hint not in {'F4_SWEEP_RECLAIM', 'F1_PULLBACK_CONT', 'F3_IMPULSE_BASE_CONT'}:
                sess_min = max(int(sess_min), int(_session_generation_conf_floor('NY')) + 1)
            try:
                if _setup_low_flow_recovery_active(session_name, lookback_hours=24):
                    sess_min = max(58, int(sess_min) - 4)
            except Exception:
                pass
            if int(conf) < int(sess_min):
                _rej("below_min_confidence", base, mv, f"conf={int(conf)} min={int(sess_min)} sess={session_name}")
                return None
        except Exception:

            pass

        tp_cap_pct = tp_cap_pct_for_coin(fut_vol, ch24)

        rr_bonus = ENGINE_B_RR_BONUS if engine_b_ok else 0.0
        tp_cap_bonus = ENGINE_B_TP_CAP_BONUS_PCT if engine_b_ok else 0.0
        if engine == "C":
            rr_bonus = float(rr_bonus) + float(ENGINE_C_RR_BONUS)
            tp_cap_bonus = float(tp_cap_bonus) + float(ENGINE_C_TP_CAP_BONUS_PCT)

        # ✅ Approach A: volatility-aware TP cap tightening (higher hit-rate on choppy/high-ATR coins)
        try:
            atr_pct = (float(atr_1h) / float(entry)) * 100.0 if float(entry) > 0 else 0.0
            if atr_pct >= 6.0:
                tp_cap_pct = min(float(tp_cap_pct), 9.0)
            elif atr_pct >= 4.5:
                tp_cap_pct = min(float(tp_cap_pct), 10.5)
        except Exception:
            pass

        atr_for_sl = float(atr_1h)
        if leader_base_override:
            try:
                atr_for_sl = min(float(atr_for_sl), float(entry) * (float(_leader_base_sl_cap_pct(session_name)) / 100.0))
                notes.append("leader_base_override")
            except Exception:
                atr_for_sl = float(atr_1h)

        sl, alt_target_b_single, R = compute_sl_tp(
            entry, side, atr_for_sl, conf, tp_cap_pct,
            rr_bonus=rr_bonus, tp_cap_bonus_pct=tp_cap_bonus
        )
        if sl <= 0 or alt_target_b_single <= 0 or R <= 0:
            _rej("bad_sl_tp_or_atr", base, mv, f"atr={atr_1h:.6g} entry={entry:.6g}")
            return None

        tp_target = float(alt_target_b_single)

        # ---------------------------------------------------------
        # ✅ Session-aware final-target RR floor (single TP model)
        # ---------------------------------------------------------
        try:
            rr_final = rr_to_tp(entry, sl, tp_target)
            sess_rr_min = float(_session_generation_rr_floor(session_name))
            if family_id_hint in {'F4_SWEEP_RECLAIM'} and balance_reversal_mode:
                if str(session_name or '').upper() == 'ASIA':
                    sess_rr_min = min(float(sess_rr_min), 0.88)
                else:
                    sess_rr_min = min(float(sess_rr_min), 0.94)
            if str(session_name or '').upper() == 'NY' and require_pullback and family_id_hint not in {'F4_SWEEP_RECLAIM', 'F7_EXHAUSTION_FAILURE'}:
                sess_rr_min = max(float(sess_rr_min), float(_session_generation_rr_floor('NY')) + 0.05)
            if float(rr_final) < float(sess_rr_min):
                _rej("below_min_rr_tp_session", base, mv, f"rr_final={rr_final:.2f} min={sess_rr_min:.2f} sess={session_name}")
                return None
        except Exception:
            pass

        sid = next_setup_id()
        hot = is_hot_coin(fut_vol, ch24)

        # ✅ trailing only for the setups that need it (Momentum + Hot)
        trailing_alt_target_b = False

        s = Setup(
            setup_id=sid,
            symbol=base,
            market_symbol=mv.symbol,
            side=side,
            conf=int(conf),
            entry=entry,
            sl=sl,
            tp=float(tp_target),
            alt_target_a=0.0,
            alt_target_b=0.0,
            fut_vol_usd=fut_vol,
            ch24=ch24,
            ch4=ch4,
            ch1=ch1,
            ch15=ch15,
            ema_support_period=int(ema_period),
            ema_support_dist_pct=float(abs(entry - float(ema_support_15m)) / entry * 100.0 if entry > 0 else 999.0),
            pullback_ema_period=int(pb_ema_p),
            pullback_ema_dist_pct=float(pb_dist_pct2),
            pullback_ready=bool(pullback_ready),
            pullback_bypass_hot=bool(pullback_bypass_hot),
            leader_base_override=bool(leader_base_override),
            engine=str(engine),
            is_trailing_alt_target_b=False,
            created_ts=time.time(),
            family_id=str(family_id_hint or ""),
        )
        try:
            # Attach lightweight diagnostics for scoring/backtests (safe even if unused elsewhere)
            setattr(s, 'atr_pct', float(atr_pct_now or 0.0))
            setattr(s, 'regime', str(regime or 'UNKNOWN'))
            setattr(s, 'trend', str(trend or 'UNKNOWN'))
            setattr(s, 'structure', str(structure or 'UNKNOWN'))
            setattr(s, 'bos', str(bos or 'NONE'))
            setattr(s, 'choch', str(choch or 'NONE'))
            setattr(s, 'sweep', str(sweep or 'NONE'))
            setattr(s, 'smf_event', str(smf_event or 'NONE'))
            setattr(s, 'smf_score', int(smf_score or 0))
            setattr(s, 'engine', str(engine or ''))
            setattr(s, 'raw_conf', int(conf or 0))
            try:
                setattr(s, 'engine_c_reason', str(engine_c_info.get('reason', '')))
                setattr(s, 'engine_c_base_width_pct', float(engine_c_info.get('base_width_pct', 0.0) or 0.0))
                setattr(s, 'engine_c_base_bars', int(engine_c_info.get('base_bars', 0) or 0))
                setattr(s, 'engine_c_support_level', float(engine_c_info.get('support_level', 0.0) or 0.0))
                setattr(s, 'engine_c_resistance_level', float(engine_c_info.get('resistance_level', 0.0) or 0.0))
            except Exception:
                pass
            # Single-TP model: keep only one authoritative target on tp.
            try:
                t = float(_setup_target_tp(s, 0.0) or 0.0)
                setattr(s, 'tp', t)
                setattr(s, 'alt_target_a', 0.0)
                setattr(s, 'alt_target_b', 0.0)
            except Exception:
                pass
            try:
                public_conf, quality_score, quality_components = _recalibrate_public_confidence(s, session_name=session_name)
                setattr(s, 'quality_score', float(quality_score or 0.0))
                setattr(s, 'quality_components', quality_components or {})
                setattr(s, 'conf', int(public_conf or 0))
            except Exception:
                pass
        except Exception:
            pass
        try:
            s = _research_finalize_setup(s, session_name=session_name)
        except Exception:
            pass
        return s
    except Exception as e:
        try:
            _rej("exception_in_make_setup", base, mv, f"{type(e).__name__}: {e}")
        except Exception:
            pass
        return None




def make_breakout_setup(
    base: str,
    mv: MarketVol,
    session_name: str = "LON",
    scan_profile: str = DEFAULT_SCAN_PROFILE,
) -> Optional[Setup]:
    """
    Engine B: Momentum Breakout/Breakdown setups.
    Uses already-fetched 1H candles from metrics_from_candles_1h_15m().
    """
    fut_vol = usd_notional(mv)
    if fut_vol <= 0:
        _rej("no_futures_volume", base, mv)
        return None

    entry = float(mv.last or 0.0)
    if entry <= 0:
        _rej("bad_entry", base, mv)
        return None

    ch24 = float(mv.percentage or 0.0)

    try:
        ch1, ch4, ch15, atr_1h, ema_support_15m, ema_period, c15, c1 = metrics_from_candles_1h_15m(mv.symbol)
    except Exception:
        _rej("ohlcv_missing_or_insufficient", base, mv)
        return None

    # Align naming with make_setup()
    ch4_used = float(ch4 or 0.0)
    family_id_hint = ""
    balance_reversal_side = ""
    notes = []
    conf = 80.0

    if not c1 or len(c1) < 25 or atr_1h <= 0:
        _rej("no_candles_breakout", base, mv)
        return None

    # Prefer trend regime from 4H
    trend_up = ch4_used > 0
    trend_dn = ch4_used < 0

    highs = [float(x[2]) for x in c1 if x and len(x) >= 6][-25:]
    lows  = [float(x[3]) for x in c1 if x and len(x) >= 6][-25:]
    closes= [float(x[4]) for x in c1 if x and len(x) >= 6][-25:]
    vols  = [float(x[5]) for x in c1 if x and len(x) >= 6][-25:]

    if len(highs) < 22 or len(vols) < 22:
        _rej("insufficient_1h_window", base, mv)
        return None

    # prior window excludes the last candle to avoid self-referencing
    prior_high20 = max(highs[-21:-1])
    prior_low20  = min(lows[-21:-1])

    last_high = highs[-1]
    last_low  = lows[-1]
    last_close = closes[-1]

    vol_avg20 = sum(vols[-21:-1]) / 20.0
    vol_now = vols[-1]
    vol_ok = (vol_now > 0) and ((vol_avg20 <= 0) or (vol_now >= vol_avg20 * 1.00))  # looser

    # Balanced thresholds
    ch24_buy_min = 6.0
    ch24_sell_max = -6.0

    # Breakout/Breakdown by wick OR close
    is_breakout = (last_high > prior_high20) or (last_close > prior_high20)
    is_breakdown = (last_low < prior_low20) or (last_close < prior_low20)

    # If 4H is strongly up/down, allow direction to follow regime
    if trend_up and is_breakout and vol_ok and ch24 >= ch24_buy_min:
        side = "BUY"
    elif trend_dn and is_breakdown and vol_ok and ch24 <= ch24_sell_max:
        side = "SELL"
    else:
        # As a fallback, allow if 4H is neutral but 24H is strong
        if is_breakout and vol_ok and ch24 >= max(10.0, ch24_buy_min) and (ch4 >= 0):
            side = "BUY"
        elif is_breakdown and vol_ok and ch24 <= min(-10.0, ch24_sell_max) and (ch4_used <= 0):
            side = "SELL"
        else:
            # Balanced fallback: strong momentum continuation (not a fresh HH/LL break)
            if vol_ok:
                if (ch4_used >= 2.5 and ch24 >= 8.0):
                    side = "BUY"
                elif (ch4_used <= -2.5 and ch24 <= -8.0):
                    side = "SELL"
                elif _research_balance_reversal_mode(session_name) and abs(float(ch24 or 0.0)) >= 2.6:
                    # In BALANCE / reclaim regimes, allow a fade-style trigger when the 24h move is extended
                    # and the 1h/15m move is stalling, instead of demanding a fresh HH/LL breakout.
                    if float(ch24 or 0.0) >= 2.6 and (float(ch15 or 0.0) <= 0.45 or float(ch1 or 0.0) <= 0.85 or float(ch4_used or 0.0) <= 1.10):
                        side = "SELL"
                        family_id_hint = family_id_hint or 'F4_SWEEP_RECLAIM'
                    elif float(ch24 or 0.0) <= -2.6 and (float(ch15 or 0.0) >= -0.45 or float(ch1 or 0.0) >= -0.85 or float(ch4_used or 0.0) >= -1.10):
                        side = "BUY"
                        family_id_hint = family_id_hint or 'F4_SWEEP_RECLAIM'
                    elif family_id_hint in {'F4_SWEEP_RECLAIM'} or _research_balance_reversal_mode(session_name):
                        # Soft-fail instead of killing a balance/reclaim candidate behind breakout logic.
                        family_id_hint = family_id_hint or 'F4_SWEEP_RECLAIM'
                        side = balance_reversal_side or side
                        notes.append('🟡 f4_no_breakout_soft')
                        conf = max(0.0, float(conf) - 1.0)
                    else:
                        _rej("no_breakout_trigger", base, mv)
                        return None
                elif trend_up and float(ch24 or 0.0) >= (2.4 if str(session_name).upper() == 'ASIA' else 2.8) and float(ch4_used or 0.0) >= (0.06 if str(session_name).upper() == 'ASIA' else 0.16) and (float(ch1 or 0.0) >= (-0.60 if str(session_name).upper() == 'ASIA' else -0.45) or float(ch15 or 0.0) >= (-0.42 if str(session_name).upper() == 'ASIA' else -0.30)):
                    # Trend-continuation soft path: permit F1/F3 style continuation candidates even without a fresh HH breakout.
                    side = "BUY"
                    family_id_hint = family_id_hint or ('F1_PULLBACK_CONT' if float(ch1 or 0.0) >= 0 else 'F3_IMPULSE_BASE_CONT')
                    notes.append('🟡 trend_no_breakout_soft_buy')
                    conf = max(0.0, float(conf) - 0.5)
                elif trend_dn and float(ch24 or 0.0) <= (-2.4 if str(session_name).upper() == 'ASIA' else -2.8) and float(ch4_used or 0.0) <= (-0.06 if str(session_name).upper() == 'ASIA' else -0.16) and (float(ch1 or 0.0) <= (0.60 if str(session_name).upper() == 'ASIA' else 0.45) or float(ch15 or 0.0) <= (0.42 if str(session_name).upper() == 'ASIA' else 0.30)):
                    side = "SELL"
                    family_id_hint = family_id_hint or ('F1_PULLBACK_CONT' if float(ch1 or 0.0) <= 0 else 'F3_IMPULSE_BASE_CONT')
                    notes.append('🟡 trend_no_breakout_soft_sell')
                    conf = max(0.0, float(conf) - 0.5)
                else:
                    _rej("no_breakout_trigger", base, mv)
                    return None
            else:
                _rej("no_breakout_trigger", base, mv)
                return None


    # SL/TP using ATR (simple + robust)
    sl_atr = 1.35
    rr_target = 2.0  # TP RR target for momentum
    if side == "BUY":
        sl = entry - (atr_1h * sl_atr)
        tp_target = entry + (entry - sl) * rr_target
    else:
        sl = entry + (atr_1h * sl_atr)
        tp_target = entry - (sl - entry) * rr_target

    if sl <= 0 or tp_target <= 0:
        _rej("bad_sl_tp", base, mv)
        return None

    # Confidence scoring (balanced)
    conf = int(round(float(conf or 80.0)))
    if abs(ch4_used) >= 5:
        conf += 2
    if abs(ch24) >= 20:
        conf += 2
    if vol_avg20 > 0 and vol_now >= vol_avg20 * 1.25:
        conf += 2
    conf = int(min(conf, 90))

    setup_id = make_setup_id(base, side)
    s = Setup(
        setup_id=setup_id,
        symbol=base,
        market_symbol=mv.symbol,
        side=side,
        conf=conf,
        entry=float(entry),
        sl=float(sl),
        tp=float(tp_target),
        alt_target_a=0.0,
        alt_target_b=0.0,
        fut_vol_usd=float(fut_vol),
        ch24=float(ch24),
        ch4=float(ch4_used),
        ch1=float(ch1),
        ch15=float(ch15),
        ema_support_period=int(ema_period or 0),
        ema_support_dist_pct=float(0.0),
        pullback_ema_period=int(0),
        pullback_ema_dist_pct=float(0.0),
        pullback_ready=False,
        pullback_bypass_hot=False,
        leader_base_override=False,
        engine="B",
        is_trailing_alt_target_b=False,
        created_ts=time.time(),
    )
    setattr(s, 'atr_pct', float((float(atr_1h) / float(entry) * 100.0) if float(entry) > 0 and float(atr_1h) > 0 else 0.0))
    setattr(s, 'regime', 'EXPANSION' if abs(float(ch1 or 0.0)) >= 1.0 else ('TRENDING' if abs(float(ch4_used or 0.0)) >= 1.0 else 'BALANCE'))
    setattr(s, 'trend', 'BULLISH' if side == 'BUY' else 'BEARISH')
    setattr(s, 'structure', getattr(s, 'trend'))
    try:
        score, _ = compute_setup_quality_score(s, session_name=session_name)
        setattr(s, 'quality_score', float(score))
    except Exception:
        pass
    return _research_finalize_setup(s, session_name=session_name)


def pick_setups(
    best_fut: Dict[str, MarketVol],
    n: int,
    strict_15m: bool = True,
    session_name: str = "LON",
    universe_n: int = 35,
    trigger_loosen_mult: float = 1.0,
    waiting_near_pct: float = SCREEN_WAITING_NEAR_PCT,
    allow_no_pullback: bool = False,   # /screen True, email False (except HOT bypass inside make_setup)
    scan_profile: str = DEFAULT_SCAN_PROFILE,
) -> List[Setup]:
    global _REJECT_STATS, _REJECT_SAMPLES, _REJECT_BY_SYMBOL, _WAITING_TRIGGER
    _REJECT_STATS = Counter()
    _REJECT_SAMPLES = {}
    _REJECT_BY_SYMBOL = {}
    # _WAITING_TRIGGER is cleared once per scan inside build_priority_pool().
    # Do not reset it here, otherwise later passes erase earlier near-miss symbols.

    universe_n = int(max(10, universe_n))
    universe = sorted(best_fut.items(), key=lambda kv: usd_notional(kv[1]), reverse=True)[:universe_n]

    setups: List[Setup] = []
    for base, mv in universe:
        try:
            s = make_setup(
                base,
                mv,
                strict_15m=strict_15m,
                session_name=session_name,
                allow_no_pullback=allow_no_pullback,
                trigger_loosen_mult=float(trigger_loosen_mult),
                waiting_near_pct=float(waiting_near_pct),
                scan_profile=str(scan_profile or DEFAULT_SCAN_PROFILE),
            )
        except Exception:
            try:
                _rej("make_setup_exception", base, mv)
            except Exception:
                pass
            s = None

        if s:
            try:
                _note_status("setup_generated", base, mv)
            except Exception:
                pass
            setups.append(s)
        else:
            # If make_setup returns None without recording a reject, add a generic reject
            # so /why is never empty and tuning is possible.
            try:
                ctx = _REJECT_CTX.get()
                b = str(base or "").upper().strip()
                per = (ctx or {}).get("__per__") if isinstance(ctx, dict) else None
                if b and isinstance(ctx, dict) and (not isinstance(per, dict) or b not in per):
                    _rej("no_setup_candidate", base, mv, "make_setup_returned_none")
            except Exception:
                pass

    setups.sort(key=lambda x: (x.conf, x.fut_vol_usd), reverse=True)
    return setups[:n]


# =========================================================
# EMAIL
# =========================================================

def pick_breakout_setups(
    best_fut: Dict[str, MarketVol],
    n: int,
    session_name: str,
    universe_cap: int,
    scan_profile: str = DEFAULT_SCAN_PROFILE,
) -> List[Setup]:
    """
    Engine B selector: iterate symbols and build momentum breakout/breakdown setups.
    """
    items = list((best_fut or {}).items())
    # simple volume-based ordering
    items.sort(key=lambda kv: usd_notional(kv[1] or MarketVol()), reverse=True)
    if universe_cap and universe_cap > 0:
        items = items[:universe_cap]

    out: List[Setup] = []
    for base, mv in items:
        try:
            s = make_breakout_setup(base, mv, session_name=session_name, scan_profile=scan_profile)
            if s:
                out.append(s)
        except Exception:
            continue

    # order by confidence then volume
    out.sort(key=lambda s: (s.conf, s.fut_vol_usd), reverse=True)
    return out[: max(0, int(n)) ]






def _setup_display_label(s: Any) -> str:
    try:
        fam = str(getattr(s, 'family_id', '') or '').upper().strip()
        if fam == BIGMOVE_FAMILY_ID:
            return BIGMOVE_FAMILY_NAME
        name = str(getattr(s, 'family_name', '') or '').strip()
        if name:
            return name
    except Exception:
        pass
    eng = str(getattr(s, 'engine', '') or '').upper().strip()
    if eng == 'A':
        return 'Pullback'
    if eng == 'B':
        return 'Momentum Breakout'
    if eng == 'C':
        return 'Impulse Base Continuation'
    if eng == 'F':
        return 'Fallback'
    return 'Setup'


def _bigmove_signal_confidence(side: str, ch24: float, ch4: float, ch1: float, ch15: float, fut_vol_usd: float, ema_dist_pct: float) -> int:
    try:
        p15 = float(BIGMOVE_DEFAULT_15M_PCT)
        p1 = float(BIGMOVE_DEFAULT_1H_PCT)
        p4 = float(BIGMOVE_DEFAULT_4H_PCT)
        conf = 72.0
        conf += min(7.0, max(0.0, (abs(float(ch15 or 0.0)) - p15) * 2.2))
        conf += min(8.0, max(0.0, (abs(float(ch1 or 0.0)) - p1) * 1.7))
        conf += min(9.0, max(0.0, (abs(float(ch4 or 0.0)) - p4) * 1.2))
        conf += min(4.0, max(0.0, (abs(float(ch24 or 0.0)) - max(p4, 6.0)) * 0.35))
        if float(fut_vol_usd or 0.0) >= 25_000_000.0:
            conf += 3.0
        elif float(fut_vol_usd or 0.0) >= 18_000_000.0:
            conf += 2.0
        if float(ema_dist_pct or 999.0) <= 0.70:
            conf += 4.0
        elif float(ema_dist_pct or 999.0) <= 1.05:
            conf += 2.0
        else:
            conf -= min(5.0, (float(ema_dist_pct or 0.0) - 1.05) * 4.0)
        if str(side or '').upper().strip() == 'BUY' and float(ch15 or 0.0) > 0 and float(ch1 or 0.0) > 0 and float(ch4 or 0.0) > 0:
            conf += 1.0
        if str(side or '').upper().strip() == 'SELL' and float(ch15 or 0.0) < 0 and float(ch1 or 0.0) < 0 and float(ch4 or 0.0) < 0:
            conf += 1.0
        return int(clamp(conf, 68.0, 96.0))
    except Exception:
        return 82


def make_bigmove_family_setup(base: str, mv: Any, session_name: str = 'LON', scan_profile: str = DEFAULT_SCAN_PROFILE) -> Optional[Setup]:
    try:
        fut_vol = float(usd_notional(mv) or 0.0)
        if fut_vol < float(BIGMOVE_DEFAULT_MIN_VOL_USD):
            return None

        ch1, ch4, ch15, atr_1h, ema_support_15m, ema_period, c15, c1 = metrics_from_candles_1h_15m(mv.symbol)
        if (not c15) or len(c15) < 12 or atr_1h <= 0:
            return None
        try:
            pct24_now = float(getattr(mv, 'percentage', 0.0) or 0.0)
            sign = 1.0 if pct24_now >= 0 else -1.0
            # If short-horizon fields/candles are missing during cold start but the symbol
            # is a genuine high-volume mover, derive conservative same-direction context.
            # This makes the Big-Move family usable by /screen, email and autotrade instead
            # of staying empty until every OHLCV timeframe is hydrated.
            if abs(pct24_now) >= max(float(BIGMOVE_DEFAULT_4H_PCT) * 2.0, 10.0):
                if abs(float(ch4 or 0.0)) < 0.50:
                    ch4 = sign * max(float(BIGMOVE_DEFAULT_4H_PCT) + 0.10, min(abs(pct24_now) * 0.38, float(BIGMOVE_DEFAULT_4H_PCT) * 1.60))
                if abs(float(ch1 or 0.0)) < 0.20:
                    ch1 = sign * max(float(BIGMOVE_DEFAULT_1H_PCT) + 0.10, min(abs(pct24_now) * 0.20, float(BIGMOVE_DEFAULT_1H_PCT) * 1.50))
                if abs(float(ch15 or 0.0)) < 0.05:
                    ch15 = sign * max(float(BIGMOVE_DEFAULT_15M_PCT) + 0.05, min(abs(pct24_now) * 0.08, float(BIGMOVE_DEFAULT_15M_PCT) * 1.40))
        except Exception:
            pass

        same_up = float(ch15 or 0.0) >= float(BIGMOVE_DEFAULT_15M_PCT) and float(ch1 or 0.0) >= float(BIGMOVE_DEFAULT_1H_PCT) and float(ch4 or 0.0) >= float(BIGMOVE_DEFAULT_4H_PCT)
        same_down = float(ch15 or 0.0) <= -float(BIGMOVE_DEFAULT_15M_PCT) and float(ch1 or 0.0) <= -float(BIGMOVE_DEFAULT_1H_PCT) and float(ch4 or 0.0) <= -float(BIGMOVE_DEFAULT_4H_PCT)
        if not (same_up or same_down):
            return None

        side = 'BUY' if same_up else 'SELL'
        entry = float(c15[-1][4] or getattr(mv, 'last', 0.0) or 0.0)
        if entry <= 0:
            return None

        ema_dist_pct = abs(entry - float(ema_support_15m or 0.0)) / entry * 100.0 if float(ema_support_15m or 0.0) > 0 else 999.0
        sess = str(session_name or '').upper().strip() or 'NY'
        max_pb = 2.20 if sess in {'LON', 'NY'} else 1.90
        if ema_dist_pct > max_pb:
            return None

        last = c15[-1]
        last_o = float(last[1] or 0.0); last_h = float(last[2] or 0.0); last_l = float(last[3] or 0.0); last_c = float(last[4] or 0.0)
        prev_chunk = c15[-6:] if len(c15) >= 6 else c15
        lows_recent = [float(x[3] or 0.0) for x in prev_chunk if float(x[3] or 0.0) > 0]
        highs_recent = [float(x[2] or 0.0) for x in prev_chunk if float(x[2] or 0.0) > 0]
        if side == 'BUY':
            if float(last_c) < max(float(last_o), float(ema_support_15m or 0.0) * 0.992):
                return None
            swing = min(lows_recent) if lows_recent else float(last_l or entry)
            sl = min(float(entry) - max(float(atr_1h) * 1.35, float(entry) * 0.0060), float(swing) - max(float(atr_1h) * 0.20, float(entry) * 0.0015))
            trend = 'BULLISH'
        else:
            if float(last_c) > min(float(last_o), float(ema_support_15m or entry) * 1.008):
                return None
            swing = max(highs_recent) if highs_recent else float(last_h or entry)
            sl = max(float(entry) + max(float(atr_1h) * 1.35, float(entry) * 0.0060), float(swing) + max(float(atr_1h) * 0.20, float(entry) * 0.0015))
            trend = 'BEARISH'
        if side == 'BUY' and sl >= entry:
            return None
        if side == 'SELL' and sl <= entry:
            return None

        R = abs(float(entry) - float(sl))
        if R <= 0:
            return None
        tp1 = 0.0  # single-TP model; kept only for backward-compatible display fields
        tp2 = float(entry) + float(BIGMOVE_SIGNAL_FINAL_RR) * R if side == 'BUY' else float(entry) - float(BIGMOVE_SIGNAL_FINAL_RR) * R
        conf = _bigmove_signal_confidence(side, float(getattr(mv, 'percentage', 0.0) or 0.0), float(ch4), float(ch1), float(ch15), float(fut_vol), float(ema_dist_pct))

        s = Setup(
            setup_id=make_setup_id(base, side),
            symbol=str(base or '').upper().strip(),
            market_symbol=str(getattr(mv, 'symbol', '') or str(base or '')).upper(),
            side=side,
            conf=int(conf),
            entry=float(entry),
            sl=float(sl),
            tp=float(tp2),
            alt_target_a=0.0,
            alt_target_b=0.0,
            fut_vol_usd=float(fut_vol),
            ch24=float(getattr(mv, 'percentage', 0.0) or 0.0),
            ch4=float(ch4),
            ch1=float(ch1),
            ch15=float(ch15),
            ema_support_period=int(ema_period or 0),
            ema_support_dist_pct=float(ema_dist_pct),
            pullback_ema_period=int(ema_period or 0),
            pullback_ema_dist_pct=float(ema_dist_pct),
            pullback_ready=bool(ema_dist_pct <= 0.85),
            pullback_bypass_hot=bool(fut_vol >= 35_000_000.0),
            leader_base_override=False,
            engine='B',
            is_trailing_alt_target_b=False,
            created_ts=time.time(),
            family_id=BIGMOVE_FAMILY_ID,
        )
        setattr(s, 'atr_pct', float((float(atr_1h) / float(entry) * 100.0) if float(entry) > 0 and float(atr_1h) > 0 else 0.0))
        setattr(s, 'regime', 'EXPANSION' if abs(float(ch1 or 0.0)) >= max(1.0, float(BIGMOVE_DEFAULT_1H_PCT) * 0.75) else 'TRENDING')
        setattr(s, 'trend', trend)
        setattr(s, 'structure', trend)
        setattr(s, 'bigmove_signal', True)
        setattr(s, 'bigmove_tp1_rr_hint', float(BIGMOVE_SIGNAL_TP1_RR))
        setattr(s, 'bigmove_tp2_rr_hint', float(BIGMOVE_SIGNAL_TP2_RR))
        setattr(s, 'bigmove_tp1_hint', float(tp1))
        setattr(s, 'bigmove_direction', 'UP' if side == 'BUY' else 'DOWN')
        try:
            score, comps = compute_setup_quality_score(s, session_name=session_name)
            score = float(clamp(float(score or 0.0) + (4.0 if str(getattr(s, 'family_id', '') or '') == BIGMOVE_FAMILY_ID else 2.0), 0.0, 100.0))
            setattr(s, 'quality_score', float(score))
            setattr(s, 'quality_components', comps or {})
        except Exception:
            pass
        return _research_finalize_setup(s, session_name=session_name)
    except Exception:
        return None


def pick_bigmove_family_setups(best_fut: Dict[str, MarketVol], n: int, session_name: str, universe_cap: int, scan_profile: str = DEFAULT_SCAN_PROFILE) -> List[Setup]:
    """Independent Big-Move setup family over the top-volume universe only."""
    out: List[Setup] = []
    try:
        items = list((best_fut or {}).items())
        ranked = []
        for base, mv in items:
            try:
                b = str(base or '').upper().strip()
                if not b:
                    continue
                vol = float(usd_notional(mv) or getattr(mv, 'quoteVolume', 0.0) or 0.0)
                if vol < float(BIGMOVE_MIN_FUT_VOL_USD):
                    continue
                ranked.append((vol, b, mv))
            except Exception:
                continue
        ranked.sort(key=lambda x: x[0], reverse=True)
        scan_cap = min(len(ranked), max(1, int(BIGMOVE_SYMBOL_LIMIT or 30)))
        for _vol, base, mv in ranked[:scan_cap]:
            try:
                setup = make_bigmove_family_setup(base, mv, session_name=session_name)
                if setup:
                    out.append(setup)
                    _rej("ok_bigmove", base, mv, "big-move family setup")
            except Exception as e:
                try:
                    _rej("bigmove_family_exception", base, mv, f"{type(e).__name__}: {e}")
                except Exception:
                    pass
                continue
        out.sort(key=lambda s: (
            int(getattr(s, 'conf', 0) or 0),
            float(getattr(s, 'quality_score', 0.0) or 0.0),
            abs(float(getattr(s, 'ch15', 0.0) or 0.0)) + abs(float(getattr(s, 'ch1', 0.0) or 0.0)),
            float(getattr(s, 'fut_vol_usd', 0.0) or 0.0),
        ), reverse=True)
        return out[:int(max(0, n))]
    except Exception:
        return out[:int(max(0, n))]




# =========================================================
# F9 — Multi-Day Leader/Loser Continuation
# =========================================================
def _f9_melbourne_day(ts: float | None = None) -> str:
    try:
        return datetime.fromtimestamp(float(ts or time.time()), tz=timezone.utc).astimezone(MEL_TZ).date().isoformat()
    except Exception:
        try:
            return datetime.now(MEL_TZ).date().isoformat()
        except Exception:
            return datetime.utcnow().date().isoformat()


def _f9_repeated_bucket_days(symbol: str, bucket: str, current_ts: float | None = None, lookback_days: int | None = None) -> int:
    """Distinct Melbourne dates the symbol appeared in a leaders/losers bucket.

    The current scan bucket is counted immediately, so a symbol that was in Leaders
    yesterday and is again in Leaders today qualifies without waiting for the
    asynchronous scan-intelligence snapshot writer.
    """
    sym = str(symbol or '').upper().strip()
    buck = str(bucket or '').lower().strip()
    if not sym or buck not in {'leaders', 'losers'}:
        return 0
    days = {_f9_melbourne_day(current_ts)}
    try:
        _scan_intel_migrate_tables()
        cutoff = float(current_ts or time.time()) - 86400.0 * float(lookback_days or F9_LOOKBACK_DAYS or 4)
        with sqlite3.connect(DB_PATH) as conn:
            rows = conn.execute(
                "SELECT created_ts FROM market_scan_symbols WHERE UPPER(symbol)=? AND LOWER(bucket)=? AND created_ts>=?",
                (sym, buck, float(cutoff)),
            ).fetchall() or []
        for (ts_val,) in rows:
            try:
                days.add(_f9_melbourne_day(float(ts_val or 0.0)))
            except Exception:
                continue
    except Exception:
        pass
    return len(days)


def _f9_ema_entry_limit_pct(session_name: str = '') -> float:
    sess = str(session_name or '').upper().strip()
    if sess == 'ASIA':
        return 1.10
    if sess == 'LON':
        return 1.25
    return 1.35


def make_multiday_mover_family_setup(base: str, mv: Any, side: str, days: int, bucket: str, session_name: str = 'LON') -> Optional[Setup]:
    """Build a F9 candidate only after a repeated Leaders/Losers symbol gives an entry.

    F9 does not force execution. It enters the normal policy pipeline as a new
    Family-Session-Strategy-Side lane, which starts as WATCH and can promote to KEEP
    only through /setup_matrix evidence.
    """
    try:
        b = str(base or '').upper().strip()
        side = str(side or '').upper().strip()
        if not b or side not in {'BUY', 'SELL'}:
            return None
        fut_vol = float(usd_notional(mv) or 0.0)
        if fut_vol < float(F9_MIN_FUT_VOL_USD):
            return None
        if int(days or 0) < int(F9_MIN_DAYS or 2):
            return None

        ch1, ch4, ch15, atr_1h, ema_support_15m, ema_period, c15, c1 = metrics_from_candles_1h_15m(mv.symbol)
        entry = float((c15[-1][4] if c15 else 0.0) or getattr(mv, 'last', 0.0) or 0.0)
        if entry <= 0 or float(atr_1h or 0.0) <= 0:
            return None

        ch24 = float(getattr(mv, 'percentage', 0.0) or 0.0)
        if side == 'BUY' and ch24 <= 0:
            return None
        if side == 'SELL' and ch24 >= 0:
            return None

        # Entry point: repeated-mover trend is allowed only when price is still
        # controlled near the adaptive 15m EMA and short-term movement is not sharply
        # against the continuation direction.
        ema_val = float(ema_support_15m or 0.0)
        ema_dist_pct = abs(entry - ema_val) / entry * 100.0 if ema_val > 0 else 999.0
        if ema_dist_pct > float(_f9_ema_entry_limit_pct(session_name)):
            try:
                _rej('f9_waiting_for_entry_ema', b, mv, f'days={days} dist={ema_dist_pct:.2f}%')
            except Exception:
                pass
            return None
        if side == 'BUY' and (float(ch1 or 0.0) < -0.55 or float(ch15 or 0.0) < -0.35 or float(ch4 or 0.0) < -0.45):
            return None
        if side == 'SELL' and (float(ch1 or 0.0) > 0.55 or float(ch15 or 0.0) > 0.35 or float(ch4 or 0.0) > 0.45):
            return None

        recent = list(c15[-10:] if c15 else [])
        lows = [float(x[3] or 0.0) for x in recent if len(x) >= 5 and float(x[3] or 0.0) > 0]
        highs = [float(x[2] or 0.0) for x in recent if len(x) >= 5 and float(x[2] or 0.0) > 0]
        atr = float(atr_1h or 0.0)
        if side == 'BUY':
            swing = min(lows) if lows else entry
            sl = min(entry - max(1.15 * atr, entry * 0.0055), swing - max(0.15 * atr, entry * 0.0012))
            if sl <= 0 or sl >= entry:
                return None
            r = abs(entry - sl)
            tp = entry + float(F9_TARGET_RR or 1.5) * r
            trend = 'BULLISH'
        else:
            swing = max(highs) if highs else entry
            sl = max(entry + max(1.15 * atr, entry * 0.0055), swing + max(0.15 * atr, entry * 0.0012))
            if sl <= entry:
                return None
            r = abs(sl - entry)
            tp = max(entry - float(F9_TARGET_RR or 1.5) * r, entry * 0.001)
            trend = 'BEARISH'
        if r <= 0 or tp <= 0:
            return None

        conf = int(clamp(75 + min(8.0, abs(ch24) * 0.35) + min(4.0, max(0, int(days or 0) - 2) * 1.5) + (2.0 if fut_vol >= 50_000_000 else 0.0), 75, 94))
        s = Setup(
            setup_id=make_setup_id(b, side),
            symbol=b,
            market_symbol=str(getattr(mv, 'symbol', '') or b).upper(),
            side=side,
            conf=int(conf),
            entry=float(entry),
            sl=float(sl),
            tp=float(tp),
            alt_target_a=0.0,
            alt_target_b=0.0,
            fut_vol_usd=float(fut_vol),
            ch24=float(ch24),
            ch4=float(ch4),
            ch1=float(ch1),
            ch15=float(ch15),
            ema_support_period=int(ema_period or 0),
            ema_support_dist_pct=float(ema_dist_pct),
            pullback_ema_period=int(ema_period or 0),
            pullback_ema_dist_pct=float(ema_dist_pct),
            pullback_ready=bool(ema_dist_pct <= 0.85),
            pullback_bypass_hot=bool(fut_vol >= 35_000_000.0),
            leader_base_override=True,
            engine='F9',
            is_trailing_alt_target_b=False,
            created_ts=time.time(),
            family_id=F9_FAMILY_ID,
            family_name=F9_FAMILY_NAME,
        )
        setattr(s, 'atr_pct', float((atr / entry * 100.0) if entry > 0 else 0.0))
        setattr(s, 'regime', 'TRENDING')
        setattr(s, 'trend', trend)
        setattr(s, 'structure', f'{trend} MULTI_DAY_CONTINUATION')
        setattr(s, 'f9_multiday_mover', True)
        setattr(s, 'f9_days', int(days or 0))
        setattr(s, 'f9_bucket', str(bucket or ''))
        setattr(s, 'entry_reason', f'F9 repeated {bucket} {int(days or 0)}d controlled EMA entry')
        try:
            score, comps = compute_setup_quality_score(s, session_name=session_name)
            score = float(clamp(float(score or 0.0) + 2.0 + min(3.0, max(0, int(days or 0) - 2) * 0.8), 0.0, 100.0))
            setattr(s, 'quality_score', float(score))
            setattr(s, 'quality_components', comps or {})
        except Exception:
            pass
        return _research_finalize_setup(s, session_name=session_name)
    except Exception:
        return None


def pick_multiday_mover_family_setups(best_fut: Dict[str, MarketVol], leaders: list[str], losers: list[str], n: int, session_name: str, scan_profile: str = DEFAULT_SCAN_PROFILE) -> List[Setup]:
    out: List[Setup] = []
    try:
        pairs = []
        for b in list(leaders or [])[:10]:
            pairs.append((str(b).upper(), 'leaders', 'BUY'))
        for b in list(losers or [])[:10]:
            pairs.append((str(b).upper(), 'losers', 'SELL'))
        seen = set()
        for b, bucket, side in pairs:
            if not b or (b, side) in seen:
                continue
            seen.add((b, side))
            mv = (best_fut or {}).get(b)
            if not mv:
                continue
            days = _f9_repeated_bucket_days(b, bucket, current_ts=time.time(), lookback_days=int(F9_LOOKBACK_DAYS or 4))
            if int(days or 0) < int(F9_MIN_DAYS or 2):
                continue
            s = make_multiday_mover_family_setup(b, mv, side, int(days), bucket, session_name=session_name)
            if s:
                out.append(s)
                try:
                    _rej('ok_f9_multiday_mover', b, mv, f'{bucket} {days}d')
                except Exception:
                    pass
        out.sort(key=lambda s: (
            int(getattr(s, 'conf', 0) or 0),
            float(getattr(s, 'quality_score', 0.0) or 0.0),
            int(getattr(s, 'f9_days', 0) or 0),
            float(getattr(s, 'fut_vol_usd', 0.0) or 0.0),
        ), reverse=True)
        return out[:int(max(0, n))]
    except Exception:
        return out[:int(max(0, n))]


def _email_market_regime(best_fut: dict) -> str:
    try:
        best = dict(best_fut or {})
        vals = list(best.values())
        if not vals:
            return 'mixed'
        adv = sum(1 for mv in vals[:40] if float(getattr(mv, 'percentage', 0.0) or 0.0) > 0.0)
        dec = sum(1 for mv in vals[:40] if float(getattr(mv, 'percentage', 0.0) or 0.0) < 0.0)
        btc = float(getattr(best.get('BTC') or MarketVol('','','',0,0,0,0,0,0), 'percentage', 0.0) or 0.0)
        eth = float(getattr(best.get('ETH') or MarketVol('','','',0,0,0,0,0,0), 'percentage', 0.0) or 0.0)
        if adv >= dec + 8 and btc >= 0.8 and eth >= 0.8:
            return 'risk_on'
        if dec >= adv + 8 and btc <= -0.8 and eth <= -0.8:
            return 'risk_off'
        return 'mixed'
    except Exception:
        return 'mixed'


def _email_symbol_cluster(symbol: str) -> str:
    b = _symbol_base(symbol)
    if b in {'BTC', 'ETH', 'SOL', 'XRP', 'DOGE', 'ADA', 'LINK', 'NEAR', 'AAVE', 'TAO'}:
        return 'majors'
    if b in {'XAU', 'XAUT', 'PAXG'}:
        return 'metals'
    if b in {'PEPE', '1000PEPE', 'FARTCOIN', 'TRUMP', 'WIF', 'BONK', 'FLOKI'}:
        return 'memes'
    if b in {'UAI', 'SAHARA', 'FET', 'AGIX', 'RNDR'}:
        return 'ai'
    return b or 'other'


def _email_diversification_guard(s: 'Setup', chosen_list: list, best_fut: dict, session_name: str) -> tuple[bool, str]:
    try:
        cfg = load_strategy_config(force=False)
        sess = str(session_name or '').upper().strip() or 'NY'
        caps = (cfg or {}).get('email_same_side_cap') or {}
        same_side_cap = int((caps.get(sess) if isinstance(caps, dict) else None) or (1 if sess == 'ASIA' else 2))
        cluster_cap = int((cfg or {}).get('email_cluster_side_cap', 1) or 1)
        bias = _email_market_regime(best_fut)
        score = float(getattr(s, 'quality_score', 0.0) or 0.0)
        conf = int(getattr(s, 'conf', 0) or 0)
        entry = float(getattr(s, 'entry', 0.0) or 0.0)
        sl = float(getattr(s, 'sl', 0.0) or 0.0)
        final_tp = float(_setup_target_tp(s, 0.0) or 0.0)
        rr_final = float(rr_to_tp(entry, sl, final_tp)) if entry > 0 and sl > 0 and final_tp > 0 else 0.0
        side = str(getattr(s, 'side', '') or '').upper().strip()
        cluster = _email_symbol_cluster(str(getattr(s, 'symbol', '') or ''))
        same_side_count = 0
        same_cluster_side_count = 0
        for c in (chosen_list or []):
            c_side = str(getattr(c, 'side', '') or '').upper().strip()
            if c_side == side:
                same_side_count += 1
                if _email_symbol_cluster(str(getattr(c, 'symbol', '') or '')) == cluster:
                    same_cluster_side_count += 1
        if same_side_count >= same_side_cap:
            return (False, 'same_side_burst_cap')
        if same_cluster_side_count >= cluster_cap and not (score >= 86.0 and conf >= 90 and rr_final >= 1.90):
            return (False, 'cluster_side_burst_cap')

        q_add_map = (cfg or {}).get('counter_regime_quality_add') or {}
        c_add_map = (cfg or {}).get('counter_regime_conf_add') or {}
        r_add_map = (cfg or {}).get('counter_regime_rr_add') or {}
        q_add = float((q_add_map.get(sess) if isinstance(q_add_map, dict) else None) or (3.0 if sess == 'ASIA' else 2.5))
        c_add = int((c_add_map.get(sess) if isinstance(c_add_map, dict) else None) or (3 if sess == 'ASIA' else 2))
        r_add = float((r_add_map.get(sess) if isinstance(r_add_map, dict) else None) or (0.12 if sess == 'ASIA' else 0.10))
        sess_q, sess_c, sess_r = _execution_session_thresholds(sess)
        if bias == 'risk_on' and side == 'SELL':
            if not (score >= (sess_q + q_add) and conf >= (sess_c + c_add) and rr_final >= (sess_r + r_add)):
                return (False, 'counter_regime_sell')
        if bias == 'risk_off' and side == 'BUY':
            if not (score >= (sess_q + q_add) and conf >= (sess_c + c_add) and rr_final >= (sess_r + r_add)):
                return (False, 'counter_regime_buy')

        ch15_abs = abs(float(getattr(s, 'ch15', 0.0) or 0.0))
        pb_dist = float(getattr(s, 'pullback_ema_dist_pct', 999.0) or 999.0)
        if cluster == 'majors' and same_side_count >= 1 and ch15_abs > 0.82 and pb_dist > 0.62 and conf < 90:
            return (False, 'correlated_major_chase')
        return (True, 'ok')
    except Exception:
        return (True, 'ok')

def user_email_alerts_enabled(user: dict) -> bool:
    # Admin always receives emails
    try:
        uid = int((user or {}).get("user_id") or 0)
        if uid and is_admin_user(uid):
            return True
    except Exception:
        pass
    try:
        return int((user or {}).get("email_alerts_enabled", 1)) == 1
    except Exception:
        return True


def set_user_email_alerts_enabled(uid: int, enabled: bool):
    update_user(int(uid), email_alerts_enabled=(1 if enabled else 0))


def set_user_trade_signal_email_enabled(uid: int, enabled: bool):
    """Keep the trade-signal recipient gate aligned with the user's email master switch."""
    flag = 1 if enabled else 0
    update_user(int(uid), email_alerts_enabled=flag, notify_on=flag)


def _mask_email_addr(email: str) -> str:
    try:
        email = str(email or '').strip()
        if not email or '@' not in email:
            return '(none)'
        local, domain = email.split('@', 1)
        if not local:
            return f"***@{domain}"
        if len(local) <= 2:
            masked_local = local[0] + '*' * max(1, len(local) - 1)
        else:
            masked_local = local[0] + ('*' * max(1, len(local) - 2)) + local[-1]
        return f"{masked_local}@{domain}"
    except Exception:
        return '(none)'


def _email_runtime_limits_snapshot(uid: int, user: dict) -> dict:
    fresh_user = get_user(int(uid)) or {}
    merged = dict(fresh_user)
    merged.update(dict(user or {}))
    user = merged
    try:
        tz, _ = _zoneinfo_or_default(user.get('tz') or user.get('timezone'))
    except Exception:
        tz = timezone.utc
    # Use the anchored trading day (/dayreset), not midnight local day.
    try:
        day_local = _user_day_local(user)
    except Exception:
        day_local = datetime.now(tz).date().isoformat()
    recipient = str(user.get('email_to') or user.get('email') or '').strip()
    alerts_on = bool(user_email_alerts_enabled(user))
    smtp_ready = bool(EMAIL_ENABLED and email_config_ok())

    try:
        st = email_state_get(int(uid))
    except Exception:
        st = {'session_key': 'NONE', 'sent_count': 0, 'last_email_ts': 0.0}

    try:
        session_cap = int(user.get('max_emails_per_session', DEFAULT_MAX_EMAILS_PER_SESSION))
    except Exception:
        session_cap = int(DEFAULT_MAX_EMAILS_PER_SESSION)
    try:
        gap_min = int(user.get('email_gap_min', DEFAULT_MIN_EMAIL_GAP_MIN))
    except Exception:
        gap_min = int(DEFAULT_MIN_EMAIL_GAP_MIN)
    try:
        day_cap = int(user.get('max_emails_per_day', DEFAULT_MAX_EMAILS_PER_DAY))
    except Exception:
        day_cap = int(DEFAULT_MAX_EMAILS_PER_DAY)

    # Ver35: do not apply hidden hard email caps by default.
    # /limits emailcap 0 and /limits emaildaycap 0 must mean unlimited.
    # Optional emergency caps are only active when EMAIL_HARD_CAPS_ENABLED=1.
    if bool(globals().get('EMAIL_HARD_CAPS_ENABLED', False)):
        try:
            hard_day = int(globals().get('EMAIL_VER32_HARD_MAX_PER_DAY', 0) or 0)
            if hard_day > 0:
                day_cap = hard_day if day_cap <= 0 else min(int(day_cap), int(hard_day))
        except Exception:
            pass
        try:
            hard_sess = int(globals().get('EMAIL_VER32_HARD_MAX_PER_SESSION', 0) or 0)
            if hard_sess > 0:
                session_cap = hard_sess if session_cap <= 0 else min(int(session_cap), int(hard_sess))
        except Exception:
            pass

    current_sess = None
    current_session_key = ''
    try:
        current_sess = in_session_now(user)
        current_session_key = str((current_sess or {}).get('session_key') or '')
    except Exception:
        current_sess = None
        current_session_key = ''
    try:
        sent_in_session = int(st.get('sent_count', 0) or 0)
        if (not current_session_key) or str(st.get('session_key') or '') != current_session_key:
            sent_in_session = 0
    except Exception:
        sent_in_session = 0
    try:
        last_email_ts = float(st.get('last_email_ts', 0.0) or 0.0)
    except Exception:
        last_email_ts = 0.0
    try:
        sent_today = int(_email_daily_get(int(uid), day_local))
    except Exception:
        sent_today = 0

    inferred_sent_today = 0
    inferred_sent_in_session = 0
    try:
        last_sent = _last_sent_email_meta(int(uid), user)
        last_sent_ts = float(last_sent.get('ts') or 0.0)
        current_sess_name = str((current_sess or {}).get('session_name') or current_session_utc(datetime.now(timezone.utc)) or 'NONE').upper().strip()
        if last_sent_ts > 0 and str(last_sent.get('day_local') or '') == str(day_local or ''):
            inferred_sent_today = 1
            evt_sess = str(last_sent.get('session_name') or 'NONE').upper().strip()
            if evt_sess and evt_sess != 'NONE':
                if str(current_session_key or '').upper().endswith('_' + evt_sess) or evt_sess == current_sess_name:
                    inferred_sent_in_session = 1
    except Exception:
        inferred_sent_today = 0
        inferred_sent_in_session = 0

    sent_today = max(int(sent_today or 0), int(inferred_sent_today or 0))
    sent_in_session = max(int(sent_in_session or 0), int(inferred_sent_in_session or 0))

    gap_sec = max(0, int(gap_min)) * 60
    gap_remaining_sec = max(0, int(round(gap_sec - (time.time() - last_email_ts)))) if gap_sec > 0 and last_email_ts > 0 else 0

    reasons = []
    if not alerts_on:
        reasons.append('email_alerts_disabled')
    if not recipient:
        reasons.append('no_recipient_email_set')
    if not EMAIL_ENABLED:
        reasons.append('EMAIL_ENABLED=0')
    elif not smtp_ready:
        reasons.append('smtp_not_configured')
    if day_cap > 0 and sent_today >= day_cap:
        reasons.append(f'daily_email_cap_reached ({sent_today}/{day_cap})')
    if session_cap > 0 and sent_in_session >= session_cap:
        reasons.append(f'session_email_cap_reached ({sent_in_session}/{session_cap})')
    if gap_remaining_sec > 0:
        reasons.append(f'email_gap_active ({gap_remaining_sec}s remaining)')

    return {
        'alerts_on': alerts_on,
        'smtp_ready': smtp_ready,
        'recipient': recipient,
        'recipient_masked': _mask_email_addr(recipient),
        'session_key': str(current_session_key or st.get('session_key') or 'NONE'),
        'sent_in_session': sent_in_session,
        'session_cap': session_cap,
        'sent_today': sent_today,
        'day_cap': day_cap,
        'sent_today_inferred': inferred_sent_today,
        'sent_in_session_inferred': inferred_sent_in_session,
        'gap_min': gap_min,
        'gap_remaining_sec': gap_remaining_sec,
        'last_email_ts': last_email_ts,
        'gate_open': len(reasons) == 0,
        'gate_reasons': reasons,
        'day_local': day_local,
    }

async def email_on_off_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """User command to enable/disable ALL email alerts without removing the saved email address."""
    uid = update.effective_user.id
    user = get_user(uid) or {}

    arg = (context.args[0].strip().lower() if context.args else "")
    if arg not in ("on", "off", "enable", "disable"):
        cur = "ON" if user_email_alerts_enabled(user) else "OFF"
        await update.message.reply_text(
            "📧 Email alerts (master switch)\n"
            "────────────────────\n"
            f"Current: {cur}\n\n"
            "Usage:\n"
            "/email_on_off on\n"
            "/email_on_off off\n\n"
            "Note: This does not remove your saved email address."
        )
        return

    enabled = arg in ("on", "enable")
    set_user_trade_signal_email_enabled(uid, enabled)
    await update.message.reply_text(
        "✅ Email alerts updated\n"
        "────────────────────\n"
        f"Now: {'ON' if enabled else 'OFF'}"
    )

def email_config_ok() -> bool:
    """
    Only checks SMTP sender config.
    Recipient is per-user (users.email_to OR users.email) OR fallback EMAIL_TO.
    """
    return all([EMAIL_HOST, EMAIL_PORT, EMAIL_USER, EMAIL_PASS, EMAIL_FROM])


def send_email(
    subject: str,
    body: str,
    body_html: Optional[str] = None,
    user_id_for_debug: Optional[int] = None,
    enforce_trade_window: bool = True,
    bypass_user_email_master: bool = False,
) -> bool:
    """
    Sends an email.

    Recipient resolution:
    - If user_id_for_debug is provided: uses users.email_to OR users.email
    - Otherwise falls back to EMAIL_TO (if set)

    Trade window:
    - Enforced only if enforce_trade_window=True
      (use False for system alerts like big-move alerts)

    Tracks last SMTP error + last email decision for /health and /email_decision.
    """
    global _SMTP_CONN, _SMTP_CONN_IS_SSL, _SMTP_CONN_TS

    uid = int(user_id_for_debug) if user_id_for_debug is not None else None

    # Per-user master email alerts switch
    if uid is not None:
        u = get_user(int(uid))
        if (not bypass_user_email_master) and u and not user_email_alerts_enabled(u):
            _LAST_EMAIL_DECISION[int(uid)] = {
                "status": "SKIP",
                "reason": "user_email_alerts_disabled",
                "ts": _now(),
            }
            return False

    # --- SMTP config check (sender side) ---
    if not email_config_ok():
        msg = "Email not configured (missing SMTP env vars)."
        logger.warning(msg)
        if uid is not None:
            _LAST_SMTP_ERROR[uid] = msg
            _LAST_EMAIL_DECISION[uid] = {
                "status": "FAIL",
                "reason": msg,
                "ts": time.time(),
            }
        return False

    # --- Resolve recipient ---
    to_email = ""
    user = None
    now_local = None

    if uid is not None:
        user = get_user(uid) or {}
        to_email = str(user.get("email_to") or user.get("email") or "").strip()

        if not to_email:
            _LAST_EMAIL_DECISION[uid] = {
                "status": "FAIL",
                "reasons": ["no_recipient_email_set"],
                "when": datetime.now(timezone.utc).isoformat(timespec="seconds"),
            }
            return False

        if enforce_trade_window:
            try:
                try:
                    tz, _ = _zoneinfo_or_default(user.get("tz") or user.get("timezone"))
                except Exception:
                    tz = timezone.utc
                now_local = datetime.now(tz)

                if not in_trade_window_now(user, now_local):
                    _LAST_EMAIL_DECISION[uid] = {
                        "status": "SKIP",
                        "reason": "outside_trade_window",
                        "ts": time.time(),
                    }
                    return False
            except Exception:
                _LAST_EMAIL_DECISION[uid] = {
                    "status": "SKIP",
                    "reason": "trade_window_check_failed",
                    "ts": time.time(),
                }
                return False
    else:
        to_email = str(EMAIL_TO or "").strip()
        if not to_email:
            logger.warning("No recipient email (EMAIL_TO empty and no user_id provided).")
            return False

    # --- Build message ---
    msg = EmailMessage()
    msg["Subject"] = subject
    msg["From"] = EMAIL_FROM
    msg["To"] = to_email
    msg.set_content(body)
    if body_html:
        try:
            msg.add_alternative(body_html, subtype="html")
        except Exception:
            pass


      
    def _close_cached():
        global _SMTP_CONN, _SMTP_CONN_IS_SSL, _SMTP_CONN_TS
        try:
            if _SMTP_CONN is not None:
                try:
                    _SMTP_CONN.quit()
                except Exception:
                    try:
                        _SMTP_CONN.close()
                    except Exception:
                        pass
        finally:
            _SMTP_CONN = None
            _SMTP_CONN_IS_SSL = None
            _SMTP_CONN_TS = 0.0

    def _need_new_conn(is_ssl: bool) -> bool:
        global _SMTP_CONN, _SMTP_CONN_IS_SSL, _SMTP_CONN_TS
        if _SMTP_CONN is None:
            return True
        if _SMTP_CONN_IS_SSL is None or _SMTP_CONN_IS_SSL != is_ssl:
            return True
        if (time.time() - float(_SMTP_CONN_TS or 0.0)) > float(SMTP_REUSE_TTL_SEC or 0.0):
            return True
        return False


    def _connect_and_login(is_ssl: bool) -> smtplib.SMTP:
        timeout = float(EMAIL_SEND_TIMEOUT_SEC)
        if is_ssl:
            ctx = ssl.create_default_context()
            s = smtplib.SMTP_SSL(EMAIL_HOST, int(EMAIL_PORT), context=ctx, timeout=timeout)
        else:
            s = smtplib.SMTP(EMAIL_HOST, int(EMAIL_PORT), timeout=timeout)
            s.ehlo()
            s.starttls(context=ssl.create_default_context())
            s.ehlo()

        # login can be slow; keep under socket timeout
        s.login(EMAIL_USER, EMAIL_PASS)
        return s

    # --- Send (with connection reuse + lock) ---
    try:
        is_ssl = (int(EMAIL_PORT) == 465)

        with _SMTP_LOCK:
            # Refresh connection if needed
            if _need_new_conn(is_ssl):
                _close_cached()
                _SMTP_CONN = _connect_and_login(is_ssl)
                _SMTP_CONN_IS_SSL = is_ssl
                _SMTP_CONN_TS = time.time()
            else:
                # Light keepalive; if dropped, reconnect
                try:
                    _SMTP_CONN.noop()
                except Exception:
                    _close_cached()
                    _SMTP_CONN = _connect_and_login(is_ssl)
                    _SMTP_CONN_IS_SSL = is_ssl
                    _SMTP_CONN_TS = time.time()

            # Actual send
            _SMTP_CONN.send_message(msg)
            _SMTP_CONN_TS = time.time()

        if uid is not None:
            _LAST_SMTP_ERROR.pop(uid, None)
            _tmp_dec = {
                "status": "SENT",
                "reason": "ok",
                "ts": time.time(),
            }
            _LAST_EMAIL_DECISION[uid] = _tmp_dec
            _LAST_EMAIL_SENT[uid] = dict(_tmp_dec)
        return True

    except Exception as e:
        err = f"{type(e).__name__}: {e}"
        logger.exception("send_email failed: %s", err)

        # On any send failure, drop cached connection (often becomes poisoned)
        try:
            with _SMTP_LOCK:
                _close_cached()
        except Exception:
            pass

        if uid is not None:
            _LAST_SMTP_ERROR[uid] = err
            _LAST_EMAIL_DECISION[uid] = {
                "status": "FAIL",
                "reason": err,
                "ts": time.time(),
            }
        return False


