def user_enabled_sessions(user: dict) -> List[str]:
    try:
        xs = json.loads(user["sessions_enabled"])
        if isinstance(xs, list) and xs:
            ordered = _order_sessions(xs)
            return ordered or ['NY', 'LON', 'ASIA']
    except Exception:
        pass
    return ['NY', 'LON', 'ASIA']

def _session_label_utc(now_utc: datetime) -> Optional[str]:
    """
    Returns NY/LON/ASIA if within their UTC windows (priority NY > LON > ASIA).
    Returns None if we are in the gap (not in any defined session window).
    """
    for name in SESSION_PRIORITY:  # ["NY","LON","ASIA"]
        w = SESSIONS_UTC[name]
        sh, sm = parse_hhmm(w["start"])
        eh, em = parse_hhmm(w["end"])
        start_utc = now_utc.replace(hour=sh, minute=sm, second=0, microsecond=0)
        end_utc = now_utc.replace(hour=eh, minute=em, second=0, microsecond=0)
        if end_utc <= start_utc:
            end_utc += timedelta(days=1)
        if now_utc < start_utc and (start_utc - now_utc) > timedelta(hours=12):
            start_utc -= timedelta(days=1)
            end_utc -= timedelta(days=1)
        if start_utc <= now_utc < end_utc:
            return name
    return None


def _guess_session_name_utc(now_utc: datetime) -> str:
    """Backward-compatible alias for scan-session fallback logic."""
    return scan_session_name_utc(now_utc)


def in_session_now(user: dict) -> Optional[dict]:
    try:
        tz, tz_name = _zoneinfo_or_default((user or {}).get("tz") or (user or {}).get("timezone"))
    except Exception:
        tz = timezone.utc
    now_local = datetime.now(tz)
    now_utc = now_local.astimezone(timezone.utc)

    # Unlimited mode is an ACCESS mode, not a synthetic market session.
    # We still need to resolve to a real setup bucket (ASIA/LON/NY), otherwise
    # the email pipeline will look for setups under "UNLIMITED" and find none.
    # During the 1-hour gap between NY close and ASIA open, fall back to the
    # scan-session heuristic so 24h emailing can still work.
    if int((user or {}).get("sessions_unlimited", 0) or 0) == 1:
        ctx = _session_gap_context(now_utc)
        live_name = str(ctx.get("live_session") or "NONE").upper().strip()
        name = live_name if live_name != "NONE" else str(ctx.get("scan_session") or "NY").upper().strip()
        session_key = f"{now_utc.strftime('%Y-%m-%d')}_{name}_UNLIMITED"
        return {
            "name": str(name or "NY"),
            "session_key": session_key,
            "start_utc": now_utc,
            "end_utc": now_utc,
            "now_local": now_local,
            "access_mode": "UNLIMITED",
            "live_session": live_name or "NONE",
            "scan_session": str(ctx.get("scan_session") or name or "NY").upper().strip(),
            "is_session_gap": bool(ctx.get("is_session_gap", live_name == "NONE")),
        }

    enabled = user_enabled_sessions(user or {})
    for name in enabled:
        w = SESSIONS_UTC[name]
        sh, sm = parse_hhmm(w["start"])
        eh, em = parse_hhmm(w["end"])
        start_utc = now_utc.replace(hour=sh, minute=sm, second=0, microsecond=0)
        end_utc = now_utc.replace(hour=eh, minute=em, second=0, microsecond=0)
        if end_utc <= start_utc:
            end_utc += timedelta(days=1)
        if now_utc < start_utc and (start_utc - now_utc) > timedelta(hours=12):
            start_utc -= timedelta(days=1)
            end_utc -= timedelta(days=1)
        if start_utc <= now_utc < end_utc:
            session_key = f"{start_utc.strftime('%Y-%m-%d')}_{name}"
            return {
                "name": name,
                "session_key": session_key,
                "start_utc": start_utc,
                "end_utc": end_utc,
                "now_local": now_local,
            }
    return None



