def _autotrade_dayrisk_reset_raw_used(owner: int, user: dict, snap: dict | None = None) -> tuple[float, float, float]:
    """Return the exact raw daily-risk usage used by /autotrade_debug.

    yver126: /dayrisk_reset must credit the same number that /autotrade_debug
    displays as daily risk used.  The quick metrics path can be stale or can miss
    exchange-closed rows; this function mirrors the debug reconciliation:
      raw_used = max(0, live_open_risk - realised_net_today)
    where realised_net_today is sourced from the same closed-report rows that
    /autotrade_debug uses.
    """
    owner_i = int(owner or 0)
    user_d = dict(user or {})
    snap_d = dict(snap or {})
    try:
        if not snap_d:
            snap_d = _accounting_snapshot_cached(owner_i, user_d, is_admin=True, ttl=0, force_refresh=True)
    except Exception:
        try:
            snap_d = _accounting_snapshot(owner_i, user_d, is_admin=True)
        except Exception:
            snap_d = {}
    try:
        start_utc, end_utc = _admin_today_window_utc(uid=owner_i, user=user_d)
        rows = _autotrade_closed_report_rows(owner_i, float(start_utc.timestamp()), float(end_utc.timestamp()), lookback_h=24, limit=0) or []
        realised_net = float(sum(float((r or {}).get('pnl_usdt') if (r or {}).get('pnl_usdt') is not None else (r or {}).get('pnl') or 0.0) for r in rows))
    except Exception:
        try:
            realised_net = float(snap_d.get('pnl_today') or 0.0)
        except Exception:
            realised_net = 0.0
    try:
        open_risk = max(0.0, float(snap_d.get('current_total_open_risk') or snap_d.get('live_open_risk_charged_today') or snap_d.get('current_day_open_risk') or 0.0))
    except Exception:
        open_risk = 0.0
    raw_used = max(0.0, float(open_risk) - float(realised_net))
    return float(raw_used), float(realised_net), float(open_risk)

async def dayrisk_reset_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Admin-only: baseline-reset current AutoTrade day risk so remaining daily cap is restored."""
    uid = int(update.effective_user.id)
    if not is_admin_user(uid):
        await update.message.reply_text("⛔ Admin only.")
        return
    # yver125: /dayrisk_reset is an AutoTrade risk command. Always reset the
    # AutoTrade owner ledger, not the Telegram admin user's manual ledger. This
    # fixes the case where the reset reply showed $334 remaining while
    # /autotrade_debug still showed the owner account with $271 remaining.
    owner = int(AUTOTRADE_OWNER_UID or uid)
    user = reset_daily_if_needed(get_user(owner) or {})
    day_local = _user_day_local(user)
    cap = float(_autotrade_daily_cap_usd(owner, float(_effective_equity_for_risk(user, prefer_live=(str(_autotrade_runtime_mode()).lower() == 'live')) or 0.0)) or 0.0)
    try:
        snap = _accounting_snapshot_cached(owner, user, is_admin=True, ttl=0, force_refresh=True)
    except Exception:
        snap = _accounting_snapshot(owner, user, is_admin=True)
    # yver126: force-refresh the exact raw daily-used number that /autotrade_debug
    # displays. The quick metrics path can miss the exchange-closed report rows,
    # which caused /dayrisk_reset to credit $0 while /autotrade_debug still showed
    # realised-loss usage.
    try:
        raw_used, _reset_realised_net, _reset_open_risk = _autotrade_dayrisk_reset_raw_used(owner, user, snap)
        existing_credit = float(_risk_day_reset_credit_get(owner, day_local) or 0.0)
        effective_used = max(0.0, float(raw_used) - float(existing_credit))
        snap['used_today_raw'] = float(raw_used)
        snap['used_today'] = float(effective_used)
        snap['risk_reset_credit'] = float(existing_credit)
        snap['pnl_today'] = float(_reset_realised_net)
        snap['current_total_open_risk'] = float(_reset_open_risk)
    except Exception:
        raw_used = float(snap.get('used_today_raw', snap.get('used_today', 0.0)) or 0.0)
        effective_used = float(snap.get('used_today', 0.0) or 0.0)
        existing_credit = float(snap.get('risk_reset_credit', 0.0) or 0.0)

    action = str((context.args[0] if context.args else "reset") or "reset").strip().lower()
    if action in {"show", "status"}:
        await update.message.reply_text(
            "🧮 Daily Risk Reset Status\n"
            f"• Trading day: {snap.get('today_window_label')}\n"
            f"• Daily cap: {str(_autotrade_daily_cap_settings()[0]).upper()} {float(_autotrade_daily_cap_settings()[1] or 0.0):.2f}{'%' if str(_autotrade_daily_cap_settings()[0]).upper() == 'PCT' else ''} (≈ ${cap:.2f})\n"
            f"• Raw used today: ${raw_used:.2f}\n"
            f"• Reset credit: ${existing_credit:.2f}\n"
            f"• Effective used today: ${effective_used:.2f}\n"
            f"• Remaining today: {'∞' if cap <= 0 else f'${max(0.0, cap - effective_used):.2f}'}\n\n"
            "Commands:\n"
            "• /dayrisk_reset\n"
            "• /dayrisk_reset clear"
        )
        return

    if action in {"clear", "restore", "undo"}:
        _risk_day_reset_credit_clear(owner, day_local)
        try:
            _autotrade_purge_day_risk_caches(int(owner))
        except Exception:
            pass
        try:
            _eq_for_metrics = float(snap.get('equity') or _effective_equity_for_risk(user, prefer_live=(str(_autotrade_runtime_mode()).lower() == 'live')) or 0.0)
            _autotrade_day_risk_metrics_cached(owner, _eq_for_metrics, ttl=0, force_refresh=True)
        except Exception:
            pass
        snap2 = _accounting_snapshot_cached(owner, user, is_admin=True, ttl=0, force_refresh=True)
        remaining2 = float(snap2.get('remaining_today', float('inf')))
        remaining2_txt = '∞' if not math.isfinite(remaining2) else f'${float(remaining2 or 0.0):.2f}'
        await update.message.reply_text(
            "✅ Daily risk reset cleared.\n"
            f"• Trading day: {snap2.get('today_window_label')}\n"
            f"• Daily risk used: ${float(snap2.get('used_today', 0.0) or 0.0):.2f}\n"
            f"• Daily risk remaining: {remaining2_txt}"
        )
        return

    _risk_day_reset_credit_set(owner, day_local, raw_used, note=f"admin_dayrisk_reset_by_{uid}")
    try:
        _autotrade_purge_day_risk_caches(int(owner))
    except Exception:
        pass
    try:
        _eq_for_metrics = float(snap.get('equity') or _effective_equity_for_risk(user, prefer_live=(str(_autotrade_runtime_mode()).lower() == 'live')) or 0.0)
        _autotrade_day_risk_metrics_cached(owner, _eq_for_metrics, ttl=0, force_refresh=True)
    except Exception:
        pass
    snap2 = _accounting_snapshot_cached(owner, user, is_admin=True, ttl=0, force_refresh=True)
    try:
        _raw2, _realised2, _open2 = _autotrade_dayrisk_reset_raw_used(owner, user, snap2)
        _credit2 = float(_risk_day_reset_credit_get(owner, day_local) or 0.0)
        _used2 = max(0.0, float(_raw2) - float(_credit2))
        snap2['used_today_raw'] = float(_raw2)
        snap2['used_today'] = float(_used2)
        snap2['risk_reset_credit'] = float(_credit2)
        snap2['pnl_today'] = float(_realised2)
        snap2['current_total_open_risk'] = float(_open2)
        _cap2 = float(snap2.get('cap') or cap or 0.0)
        snap2['remaining_today'] = (float('inf') if _cap2 <= 0 else max(0.0, _cap2 - _used2))
    except Exception:
        pass
    remaining2 = float(snap2.get('remaining_today', float('inf')))
    remaining2_txt = '∞' if not math.isfinite(remaining2) else f'${float(remaining2 or 0.0):.2f}'
    await update.message.reply_text(
        "✅ Daily risk baseline reset for the active trading day.\n"
        f"• Trading day: {snap2.get('today_window_label')}\n"
        f"• Previous raw used: ${raw_used:.2f}\n"
        f"• Reset credit now applied: ${float(snap2.get('risk_reset_credit', 0.0) or 0.0):.2f}\n"
        f"• Daily risk used now: ${float(snap2.get('used_today', 0.0) or 0.0):.2f}\n"
        f"• Daily risk remaining now: {remaining2_txt}\n\n"
        "Use /dayrisk_reset clear to restore the original day accounting."
    )


async def limits_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    uid = update.effective_user.id
    user = get_user(uid)

    if len(context.args) < 2:
        await update.message.reply_text(
            f"Limits:\n"
            f"- maxtrades: {int(user['max_trades_day'])}\n"
            f"- emailcap: {int(user['max_emails_per_session'])} (0 = unlimited)\n"
            f"- emailgap: {int(user['email_gap_min'])} min\n"
            f"- emaildaycap: {int(user.get('max_emails_per_day', DEFAULT_MAX_EMAILS_PER_DAY))} (0 = unlimited)\n\n"
            f"Set examples:\n"
            f"/limits maxtrades 5\n"
            f"/limits emailcap 0\n"
            f"/limits emailgap 60\n"
            f"/limits emaildaycap 0\n\n"
            f"Note: maxtrades is manual-trading only. AutoTrade uses /autotrade_config AUTOTRADE_MAX_TRADES_PER_DAY.\n"
        )
        return

    key = context.args[0].strip().lower()
    try:
        val = int(float(context.args[1]))
    except Exception:
        await update.message.reply_text("Value must be a number.")
        return

    if key == "maxtrades":
        if not (1 <= val <= 50):
            await update.message.reply_text("maxtrades must be 1..50")
            return
        update_user(uid, max_trades_day=val)
        await update.message.reply_text(f"✅ maxtrades/day set to {val}")

    elif key == "emailcap":
        if not (0 <= val <= 50):
            await update.message.reply_text("emailcap must be 0..50 (0 = unlimited)")
            return
        update_user(uid, max_emails_per_session=val)
        await update.message.reply_text(f"✅ emailcap/session set to {val} (0 = unlimited)")

    elif key == "emailgap":
        if not (0 <= val <= 360):
            await update.message.reply_text("emailgap must be 0..360 minutes")
            return
        update_user(uid, email_gap_min=val)
        await update.message.reply_text(f"✅ emailgap set to {val} minutes")

    elif key in {"emaildaycap", "dailyemailcap", "emailcapday"}:
        if not (0 <= val <= 50):
            await update.message.reply_text("emaildaycap must be 0..50 (0 = unlimited)")
            return
        update_user(uid, max_emails_per_day=val)
        await update.message.reply_text(f"✅ daily email cap set to {val} (0 = unlimited)")

    else:
        await update.message.reply_text("Unknown key. Use: maxtrades | emailcap | emailgap | emaildaycap")

