        if is_admin:
            snap = await to_thread_fast(_accounting_snapshot_cached, uid, user, is_admin=status_is_admin, ttl=FAST_ADMIN_SNAPSHOT_TTL_SEC, timeout=FAST_ADMIN_COMMAND_TIMEOUT_SEC)
