# =========================================================
# TREND ENGINE — ADAPTIVE EMA (NO FIXED EMA7/21/50)
# =========================================================

TREND_EMA_PULLBACK_ATR = 1.2
TREND_MAX_CONFIDENCE = 90

def ema_series(values, period):
    if not values or len(values) < period:
        return []
    k = 2.0 / (period + 1.0)
    ema_vals = [values[0]]
    for v in values[1:]:
        ema_vals.append(v * k + ema_vals[-1] * (1 - k))
    return ema_vals

def ema_slope(series, n=3):
    if len(series) < n + 1:
        return 0.0
    return series[-1] - series[-1 - n]

def trend_dynamic_confidence(base_conf, price, ema_fast_last, atr_15m, ch24_pct, reclaimed):
    score = base_conf
    if reclaimed:
        score += 8

    dist_atr = abs(price - ema_fast_last) / atr_15m
    if dist_atr < 0.4:
        score += 8
    elif dist_atr < 0.8:
        score += 4

    score += min(10, abs(ch24_pct) / 2)
    return int(min(score, TREND_MAX_CONFIDENCE))


# =====================================================================
def trend_watch_for_symbol(base, mv, session_name):
    try:

        c4h = fetch_ohlcv(mv.symbol, "4h", 60)
        c15 = fetch_ohlcv(mv.symbol, "15m", 140)
        if not c4h or not c15 or len(c15) < 40:
            return None

        closes_4h = [float(x[4]) for x in c4h]
        closes_15 = [float(x[4]) for x in c15]

        ch24 = float(mv.percentage or 0.0)
        side = "BUY" if ch24 > 0 else "SELL"

        # volatility proxy for adaptive EMA
        atr_15m = compute_atr_from_ohlcv(c15, ATR_PERIOD)
        price = float(mv.last or closes_15[-1])
        atr_pct = (atr_15m / price) * 100.0 if (atr_15m and price) else 2.0

        # adaptive EMA periods
        p_fast = adaptive_ema_period(atr_pct)          # 8..21
        p_slow = int(clamp(p_fast * 2, 16, 55))        # adaptive slow

        ema_fast = ema_series(closes_15[-120:], p_fast)
        ema_slow = ema_series(closes_15[-120:], p_slow)
        if not ema_fast or not ema_slow:
            return None

        if side == "BUY":
            if not (ema_fast[-1] > ema_slow[-1]):
                return None
            if ema_slope(ema_fast, 3) <= 0:
                return None

            # pullback touch or near-touch
            last = closes_15[-1]
            near = abs(last - ema_fast[-1]) / last * 100.0
            if near > 1.2:
                return None

        else:
            if not (ema_fast[-1] < ema_slow[-1]):
                return None
            if ema_slope(ema_fast, 3) >= 0:
                return None

            last = closes_15[-1]
            near = abs(last - ema_fast[-1]) / last * 100.0
            if near > 1.2:
                return None

        conf = 80
        # session boost (optional)
        if session_name == "NY":
            conf += 5
        elif session_name == "LON":
            conf += 2

        return {
            "symbol": base,
            "side": side,
            "conf": int(clamp(conf, 1, 99)),
            "ch24": float(ch24),
        }

    except Exception:
        return None


# =========================================================
# PRIORITY SIGNAL POOL (USED BY /screen AND EMAIL)
# Directional Leaders/Losers → Trend Continuation Watch → Waiting for Trigger → Market Leaders
# =========================================================

def _bases_from_directional(rows, n):
    out = []
    for r in (rows or [])[:n]:
        try:
            out.append(str(r[0]).upper())
        except Exception:
            continue
    return out

def _subset_best(best_fut: dict, bases: list) -> dict:
    s = set([str(b).upper() for b in (bases or [])])
    return {k: v for k, v in (best_fut or {}).items() if str(k).upper() in s}

def _market_leader_bases(best_fut: dict, n: int) -> list:
    """Top market leaders by true futures USD notional.

    IMPORTANT:
    MarketVol does not expose `fut_vol_usd`, so using getattr(..., "fut_vol_usd")
    silently returns 0 and breaks the fallback market-leader universe.
    """
    try:
        items = [(b, mv) for b, mv in (best_fut or {}).items()]
        items = sorted(items, key=lambda x: float(usd_notional(x[1]) or 0.0), reverse=True)
        return [str(b).upper() for b, _ in items[:n]]
    except Exception:
        return []

def _norm_sym(s: str) -> str:
    s = (s or "").upper().strip()
    # common variants -> base
    s = s.replace("USDT.P", "").replace("USDT", "")
    s = s.replace("-PERP", "").replace("PERP", "")
    s = s.replace("/", "").replace("-", "").replace("_", "")
    return s

def _best_fut_vol_usd(best_fut: dict, symbol: str) -> float:
    """
    Returns futures volume USD from best_fut dict using robust symbol matching.
    Handles keys like BTC, BTCUSDT, BTCUSDT.P, BTC/USDT, etc.
    """
    if not best_fut:
        return 0.0

    sym_raw = str(symbol or "").upper().strip()
    sym_n = _norm_sym(sym_raw)

    # direct hits first
    mv = (best_fut or {}).get(sym_raw)
    if mv is None:
        mv = (best_fut or {}).get(sym_n)

    # brute search by normalized keys
    if mv is None:
        for k, v in (best_fut or {}).items():
            if _norm_sym(str(k)) == sym_n:
                mv = v
                break

    if mv is None:
        return 0.0

    try:
        v = float(getattr(mv, "fut_vol_usd", 0.0) or 0.0)
        if v > 0:
            return v
    except Exception:
        pass
    try:
        return float(usd_notional(mv) or 0.0)
    except Exception:
        return 0.0


def _fut_vol_usd_from_best(best_fut: dict, symbol: str) -> float:
    """Backward-compatible alias used by recovery setup generation."""
    try:
        return float(_best_fut_vol_usd(best_fut, symbol) or 0.0)
    except Exception:
        return 0.0


def _median(values: list) -> float:
    try:
        vals = sorted([float(x) for x in values if float(x) > 0])
        if not vals:
            return 0.0
        mid = len(vals) // 2
        if len(vals) % 2 == 1:
            return float(vals[mid])
        return float((vals[mid - 1] + vals[mid]) / 2.0)
    except Exception:
        return 0.0

def _email_priority_bases(best_fut: dict, directional_take: int = 12) -> set:
    # Directional Leaders/Losers = priority symbols (email override)
    try:
        up_list, dn_list = compute_directional_lists(best_fut)
        leaders = _bases_from_directional(up_list, directional_take)
        losers  = _bases_from_directional(dn_list, directional_take)
        return set([str(x).upper() for x in (leaders + losers)])
    except Exception:
        return set()



def _recovery_family_and_reason(side: str, ch24: float, ch4: float, ch1: float, ch15: float, fut_vol: float) -> tuple[str, str, str, str]:
    """Classify recovery/fallback candidates into the best-fit family and produce an entry reason."""
    try:
        sd = str(side or '').upper().strip()
        sign = 1.0 if sd == 'BUY' else -1.0
        s15 = sign * float(ch15 or 0.0)
        s1 = sign * float(ch1 or 0.0)
        s4 = sign * float(ch4 or 0.0)
        s24 = sign * float(ch24 or 0.0)
        vol_m = float(fut_vol or 0.0) / 1_000_000.0
        reasons = []
        if abs(float(ch24 or 0.0)) >= 10.0:
            reasons.append(f"24h {float(ch24):+.0f}% directional mover")
        if s4 >= 2.0:
            reasons.append(f"4h aligned {float(ch4):+.0f}%")
        elif s4 >= 0.35:
            reasons.append(f"4h supportive {float(ch4):+.1f}%")
        if s1 >= 1.0:
            reasons.append(f"1h trigger {float(ch1):+.1f}%")
        elif s1 >= 0.20:
            reasons.append(f"1h supportive {float(ch1):+.1f}%")
        if s15 >= 0.20:
            reasons.append(f"15m timing {float(ch15):+.1f}%")
        if vol_m >= 50.0:
            reasons.append(f"high liquidity {vol_m:.0f}M")
        if s15 >= 1.5 and s1 >= 3.0 and s4 >= 5.0:
            fam = str(globals().get('BIGMOVE_FAMILY_ID', 'F8_BIGMOVE_CONT'))
            name = str(globals().get('BIGMOVE_FAMILY_NAME', 'Big Move Continuation'))
            engine = 'M'
        elif s15 >= 0.35 and s1 >= 0.75 and s4 >= 0.20:
            fam, name, engine = 'F2_MOMENTUM_IGNITION', 'Momentum Ignition', 'B'
        elif s24 >= 10.0 and s4 >= 1.2 and s15 >= -0.10:
            fam, name, engine = 'F3_IMPULSE_BASE_CONT', 'Impulse Base Continuation', 'C'
        elif s24 >= 5.0 and s4 >= 0.20:
            fam, name, engine = 'F1_PULLBACK_CONT', 'Pullback Continuation', 'A'
        else:
            fam, name, engine = 'F1_PULLBACK_CONT', 'Pullback Continuation', 'A'
        reason = '; '.join(reasons[:4]) if reasons else 'current price near continuation zone'
        return fam, name, engine, reason
    except Exception:
        return 'F1_PULLBACK_CONT', 'Pullback Continuation', 'A', 'current continuation context'


def _recovery_entry_quality_ok(side: str, ch24: float, ch4: float, ch1: float, ch15: float, fut_vol: float) -> tuple[bool, str]:
    """Final quality gate for fallback/recovery entries."""
    try:
        sd = str(side or '').upper().strip()
        sign = 1.0 if sd == 'BUY' else -1.0
        s24 = sign * float(ch24 or 0.0)
        s4 = sign * float(ch4 or 0.0)
        s1 = sign * float(ch1 or 0.0)
        s15 = sign * float(ch15 or 0.0)
        if float(fut_vol or 0.0) < _setup_min_volume_floor_usd():
            return False, 'below_min_volume'
        if s24 < 2.0:
            return False, '24h_not_directional'
        if s1 <= -0.75 and s15 <= -0.15:
            return False, '1h_and_15m_against_entry'
        if s4 <= -3.0 and s1 <= -0.20:
            return False, '4h_and_1h_against_entry'
        if not (s15 >= 0.05 or s1 >= 0.20 or s4 >= 0.35 or s24 >= 12.0):
            return False, 'no_entry_timing_trigger'
        return True, 'ok'
    except Exception:
        return False, 'entry_quality_exception'


def _fallback_setups_from_universe(best_fut: dict, leaders: list, losers: list, market_bases: list, session_name: str, max_items: int = 4) -> list:
    """Bounded recovery generator used only when the normal OHLCV engines return nothing.

    It does not read old emailed setups and it does not bypass SL/TP/RR/liquidity rules.
    It creates conservative single-TP continuation setups from the current top-volume
    ticker snapshot so the executable/email/autotrade lane does not stay empty during
    Bybit OHLCV rate limits or cold Render restarts.
    """
    bases: list[tuple[str, str]] = []

    def _add(base: str, side: str) -> None:
        b = str(base or '').upper().strip()
        sd = str(side or '').upper().strip()
        if not b or sd not in {'BUY', 'SELL'}:
            return
        if any(b == x[0] for x in bases):
            return
        bases.append((b, sd))

    try:
        for b in (leaders or [])[:6]:
            _add(b, 'BUY')
        for b in (losers or [])[:6]:
            _add(b, 'SELL')
        for b in (market_bases or [])[:12]:
            bb = str(b or '').upper().strip()
            mv = (best_fut or {}).get(bb)
            pct = float(getattr(mv, 'percentage', 0.0) or 0.0) if mv else 0.0
            _add(bb, 'BUY' if pct >= 0 else 'SELL')
        ranked = sorted((best_fut or {}).items(), key=lambda kv: float(usd_notional(kv[1]) or 0.0), reverse=True)
        for b, mv in ranked[:max(10, int(SCAN_SYMBOL_LIMIT))]:
            pct = float(getattr(mv, 'percentage', 0.0) or 0.0)
            _add(b, 'BUY' if pct >= 0 else 'SELL')
            if len(bases) >= max(12, int(max_items) * 3):
                break
    except Exception:
        pass

    setups = []
    sess = str(session_name or '').upper().strip() or 'NY'
    for base, side in bases:
        mv = (best_fut or {}).get(base)
        if not mv:
            continue
        market_symbol = str(getattr(mv, "symbol", base) or base)
        entry = float(getattr(mv, "last", 0.0) or 0.0)
        if entry <= 0:
            continue

        fut_vol = float(_fut_vol_usd_from_best(best_fut, base) or usd_notional(mv) or 0.0)
        if fut_vol < _setup_min_volume_floor_usd():
            continue

        pct24_raw = float(getattr(mv, "percentage", 0.0) or 0.0)
        sign = 1.0 if side == 'BUY' else -1.0
        pct24_abs = abs(pct24_raw)
        if pct24_abs < 1.20:
            continue

        atr_1h = 0.0
        ch1 = 0.0
        ch4 = 0.0
        ch15 = 0.0
        try:
            c1 = _ohlcv_best_effort_cached(market_symbol, "1h", max(ATR_PERIOD + 6, 35))
            if c1 and len(c1) >= 5:
                closes_1h = [float(x[4]) for x in c1]
                c_last = closes_1h[-1]
                c_prev1 = closes_1h[-2]
                c_prev4 = closes_1h[-5]
                ch1 = ((c_last - c_prev1) / c_prev1) * 100.0 if c_prev1 else 0.0
                ch4 = ((c_last - c_prev4) / c_prev4) * 100.0 if c_prev4 else 0.0
                atr_1h = compute_atr_from_ohlcv(c1, ATR_PERIOD) if c1 else 0.0
        except Exception:
            atr_1h = 0.0

        if abs(ch4) < 1e-9:
            ch4 = sign * float(clamp(pct24_abs * 0.13, 0.38 if sess != 'NY' else 0.30, 1.05))
        if abs(ch1) < 1e-9:
            ch1 = sign * float(clamp(pct24_abs * 0.035, 0.14 if sess != 'NY' else 0.09, 0.52))
        try:
            c15 = _ohlcv_best_effort_cached(market_symbol, "15m", 20)
            if c15 and len(c15) >= 2:
                c15_last = float(c15[-1][4])
                c15_prev = float(c15[-2][4])
                ch15_real = ((c15_last - c15_prev) / c15_prev) * 100.0 if c15_prev else 0.0
                if (ch15_real > 0 and side == 'BUY') or (ch15_real < 0 and side == 'SELL'):
                    ch15 = ch15_real
        except Exception:
            pass
        if abs(ch15) < 1e-9:
            ch15 = sign * float(clamp(pct24_abs * 0.010, 0.05, 0.24))

        entry_ok, entry_quality_reason = _recovery_entry_quality_ok(side, pct24_raw, ch4, ch1, ch15, fut_vol)
        if not entry_ok:
            try:
                _rej(str(entry_quality_reason or 'recovery_entry_quality_reject'), base, mv)
            except Exception:
                pass
            continue

        family_id, family_name, engine_id, entry_reason = _recovery_family_and_reason(side, pct24_raw, ch4, ch1, ch15, fut_vol)

        if atr_1h <= 0:
            atr_1h = max(entry * 0.0065, 0.0000001)
        atr_pct = float((atr_1h / entry) * 100.0) if entry > 0 else 0.80

        sl_dist = max(1.20 * atr_1h, entry * 0.0045)
        try:
            recent_c15 = _ohlcv_best_effort_cached(market_symbol, "15m", 12) or []
            if recent_c15 and len(recent_c15) >= 4:
                lows15 = [float(x[3]) for x in recent_c15[-8:] if float(x[3] or 0.0) > 0]
                highs15 = [float(x[2]) for x in recent_c15[-8:] if float(x[2] or 0.0) > 0]
            else:
                lows15, highs15 = [], []
        except Exception:
            lows15, highs15 = [], []
        rr_target = 1.55
        if side == "BUY":
            swing_sl = (min(lows15) - max(0.18 * atr_1h, entry * 0.0010)) if lows15 else (entry - sl_dist)
            sl = max(min(entry - sl_dist, swing_sl), entry * 0.001)
            actual_r = abs(entry - sl)
            tp_target = entry + rr_target * actual_r
            trend = 'BULLISH TREND'
            structure = 'BULLISH CONTINUATION'
        else:
            swing_sl = (max(highs15) + max(0.18 * atr_1h, entry * 0.0010)) if highs15 else (entry + sl_dist)
            sl = max(entry + sl_dist, swing_sl)
            actual_r = abs(sl - entry)
            tp_target = max(entry - rr_target * actual_r, entry * 0.001)
            trend = 'BEARISH TREND'
            structure = 'BEARISH CONTINUATION'

        conf = int(clamp(76 + min(9.0, pct24_abs * 0.45) + (2.0 if fut_vol >= 12_000_000.0 else 0.0), 76, 90))
        setup = Setup(
            setup_id=make_setup_id(base, side),
            symbol=base,
            market_symbol=market_symbol,
            side=side,
            conf=conf,
            entry=float(entry),
            sl=float(sl),
            tp=float(tp_target),
            alt_target_a=0.0,
            alt_target_b=0.0,
            fut_vol_usd=float(fut_vol or 0.0),
            ch24=float(pct24_raw),
            ch4=float(ch4),
            ch1=float(ch1),
            ch15=float(ch15),
            ema_support_period=13,
            ema_support_dist_pct=0.25,
            pullback_ema_period=13,
            pullback_ema_dist_pct=0.32,
            pullback_ready=True,
            pullback_bypass_hot=bool(fut_vol >= 20_000_000.0),
            leader_base_override=True,
            engine=str(engine_id or 'A'),
            is_trailing_alt_target_b=False,
            created_ts=time.time(),
            family_id=str(family_id or 'F1_PULLBACK_CONT'),
            family_name=str(family_name or 'Pullback Continuation'),
            regime_primary='TRENDING',
            regime_secondary='RECOVERY',
            regime_confidence=0.55,
        )
        try:
            setattr(setup, 'atr_pct', float(atr_pct))
            setattr(setup, 'regime', 'TRENDING')
            setattr(setup, 'trend', trend)
            setattr(setup, 'structure', structure)
            setattr(setup, 'recovery_fallback', True)
            setattr(setup, 'entry_reason', str(entry_reason or ''))
            setattr(setup, 'generated_reason', str(entry_reason or ''))
            score, comps = compute_setup_quality_score(setup, session_name=session_name)
            setattr(setup, 'quality_score', float(max(score, 68.0)))
            setattr(setup, 'quality_components', comps or {})
            setup = _research_finalize_setup(setup, session_name=session_name)
            setattr(setup, 'recovery_fallback', True)
        except Exception:
            pass

        setups.append(setup)
        if len(setups) >= int(max_items):
            break
    return setups

def _setup_family_id_to_code(family_id: str) -> str:
    """Compact family label for Telegram tables: F1, F2, ... F9."""
    try:
        fam = str(family_id or '').strip().upper().replace('-', '_')
        if not fam:
            return '-'
        m = re.match(r'^(F\d+)', fam)
        if m:
            return m.group(1)
        if fam in {'A', 'ENGINE_A', 'PULLBACK', 'PULLBACK_CONT', 'PULLBACK_CONTINUATION'}:
            return 'F1'
        if fam in {'B', 'ENGINE_B', 'MOMENTUM', 'MOMENTUM_IGNITION'}:
            return 'F2'
        if fam in {'C', 'ENGINE_C', 'IMPULSE_BASE', 'IMPULSE_BASE_CONT'}:
            return 'F3'
        if 'BIGMOVE' in fam or 'BIG_MOVE' in fam:
            return 'F8'
        return fam
    except Exception:
        return '-'


def _setup_engine_to_family_id(engine: str, row: dict | None = None) -> str:
    """Best-effort engine→family mapping for legacy rows that missed family_id."""
    try:
        eng = str(engine or '').strip().upper().replace('-', '_')
        if eng in {'A', 'ENGINE_A', 'PULLBACK', 'PULLBACK_CONT', 'PULLBACK_CONTINUATION'}:
            return 'F1_PULLBACK_CONT'
        if eng in {'B', 'ENGINE_B', 'MOMENTUM', 'MOMENTUM_IGNITION'}:
            return 'F2_MOMENTUM_IGNITION'
        if eng in {'C', 'ENGINE_C', 'IMPULSE_BASE', 'IMPULSE_BASE_CONT', 'PUMP_BASE'}:
            return 'F3_IMPULSE_BASE_CONT'
        if eng in {'F4', 'SWEEP', 'SWEEP_RECLAIM', 'BALANCE_REVERSAL'}:
            return 'F4_SWEEP_RECLAIM'
        if eng in {'F5', 'ORB', 'ORB_RETEST'}:
            return 'F5_ORB_RETEST'
        if eng in {'F6', 'VWAP', 'VWAP_RECLAIM'}:
            return 'F6_VWAP_RECLAIM'
        if eng in {'F7', 'EXHAUSTION', 'EXHAUSTION_FAILURE'}:
            return 'F7_EXHAUSTION_FAILURE'
        if eng in {'F8', 'ENGINE_F8', 'BIGMOVE', 'BIG_MOVE', 'BIGMOVE_CONT', 'F8_BIGMOVE_CONT'} or 'BIGMOVE' in eng or 'BIG_MOVE' in eng:
            return 'F8_BIGMOVE_CONT'
        if eng in {'F9', 'ENGINE_F9', 'MULTIDAY', 'MULTI_DAY', 'MULTIDAY_MOVER', 'F9_MULTI_DAY_MOVER_CONT'} or 'MULTIDAY' in eng or 'MULTI_DAY' in eng:
            return 'F9_MULTI_DAY_MOVER_CONT'
        try:
            return _family_id_from_engine(eng, None)
        except Exception:
            pass
    except Exception:
        pass
    return ''


def _setup_audit_family_from_row(row: dict) -> str:
    """Return the canonical family id for setup audit/reporting."""
    try:
        rr = dict(row or {})
        # 1) Direct DB fields.
        for key in ('family_id', 'family', 'engine_family'):
            val = str(rr.get(key) or '').strip()
            if val:
                fam = val.upper().replace('-', '_')
                # If a short code was persisted, expand where possible.
                if fam == 'F1':
                    return 'F1_PULLBACK_CONT'
                if fam == 'F2':
                    return 'F2_MOMENTUM_IGNITION'
                if fam == 'F3':
                    return 'F3_IMPULSE_BASE_CONT'
                if fam == 'F4':
                    return 'F4_SWEEP_RECLAIM'
                if fam == 'F5':
                    return 'F5_ORB_RETEST'
                if fam == 'F6':
                    return 'F6_VWAP_RECLAIM'
                if fam == 'F7':
                    return 'F7_EXHAUSTION_FAILURE'
                if fam == 'F8':
                    return 'F8_BIGMOVE_CONT'
                if fam == 'F9':
                    return 'F9_MULTI_DAY_MOVER_CONT'
                return fam

        # 2) details_json from executable/admin lifecycle. This is where modern setups
        # store family_id when older DB schemas lack a dedicated column.
        for raw_key in ('details_json', 'details', 'metadata_json'):
            details = str(rr.get(raw_key) or '').strip()
            if not details:
                continue
            try:
                obj = json.loads(details)
                if isinstance(obj, dict):
                    for key in ('family_id', 'family', 'engine_family'):
                        val = str(obj.get(key) or '').strip()
                        if val:
                            return val.upper().replace('-', '_')
                    eng2 = str(obj.get('engine') or '').strip()
                    fam2 = _setup_engine_to_family_id(eng2, rr)
                    if fam2 and fam2 != 'F0_UNKNOWN':
                        return fam2
            except Exception:
                pass

        # 3) Engine fallback for legacy/open rows.
        eng = str(rr.get('engine') or '').strip()
        fam = _setup_engine_to_family_id(eng, rr)
        if fam and fam != 'F0_UNKNOWN':
            return fam

        # 4) Setup-id/name fallback for rare family-coded rows.
        text = ' '.join(str(rr.get(k) or '') for k in ('setup_id', 'note', 'open_reason', 'close_reason')).upper()
        m = re.search(r'\b(F[1-9])\b', text)
        if m:
            code = m.group(1)
            return {
                'F1': 'F1_PULLBACK_CONT',
                'F2': 'F2_MOMENTUM_IGNITION',
                'F3': 'F3_IMPULSE_BASE_CONT',
                'F4': 'F4_SWEEP_RECLAIM',
                'F5': 'F5_ORB_RETEST',
                'F6': 'F6_VWAP_RECLAIM',
                'F7': 'F7_EXHAUSTION_FAILURE',
                'F8': 'F8_BIGMOVE_CONT',
                'F9': 'F9_MULTI_DAY_MOVER_CONT',
            }.get(code, code)
        return 'F0_UNKNOWN'
    except Exception:
        return 'F0_UNKNOWN'


def _setup_audit_family_display(row: dict, compact: bool = True) -> str:
    """Display label used by /autotrade_report and /setup_audit."""
    fam = _setup_audit_family_from_row(row)
    if compact:
        return _setup_family_id_to_code(fam)
    return str(fam or 'F0_UNKNOWN').upper().replace('-', '_')


def _setup_audit_reason_from_row(row: dict) -> str:
    """Short entry-quality reason for /setup_audit.

    This is intentionally one line. It focuses on why the entry exists, not a
    repeated raw diagnostic dump.
    """
    try:
        for key in ('entry_reason', 'generated_reason', 'reason_to_enter'):
            val = str((row or {}).get(key) or '').strip()
            if val:
                return val.replace('\n', ' ')[:140]
        details = str((row or {}).get('details_json') or '').strip()
        if details:
            try:
                obj = json.loads(details)
                if isinstance(obj, dict):
                    for key in ('entry_reason', 'generated_reason', 'reason_to_enter', 'reason', 'entry_trigger'):
                        val = str(obj.get(key) or '').strip()
                        if val:
                            return val.replace('\n', ' ')[:140]
            except Exception:
                pass

        fam = _setup_audit_family_from_row(row)
        ch24 = float((row or {}).get('ch24') or 0.0)
        ch4 = float((row or {}).get('ch4') or 0.0)
        ch1 = float((row or {}).get('ch1') or 0.0)
        ch15 = float((row or {}).get('ch15') or 0.0)
        vol_m = float((row or {}).get('fut_vol_usd') or 0.0) / 1e6
        side = str((row or {}).get('side') or '').upper().strip()
        sign = 1.0 if side == 'BUY' else -1.0

        parts = []
        if fam and fam != '-':
            parts.append(fam)
        if sign * ch24 >= 8:
            parts.append(f"24h momentum {ch24:+.0f}%")
        elif sign * ch24 >= 2:
            parts.append(f"24h supportive {ch24:+.0f}%")
        if sign * ch4 >= 2:
            parts.append(f"4h aligned {ch4:+.0f}%")
        elif sign * ch4 >= 0.3:
            parts.append(f"4h supportive {ch4:+.1f}%")
        elif sign * ch4 < -2:
            parts.append(f"4h countertrend {ch4:+.0f}%")
        if sign * ch1 >= 1:
            parts.append(f"1h trigger {ch1:+.1f}%")
        elif sign * ch1 >= 0.2:
            parts.append(f"1h supportive {ch1:+.1f}%")
        if sign * ch15 >= 0.2:
            parts.append(f"15m timing {ch15:+.1f}%")
        if vol_m >= 10:
            parts.append(f"vol {vol_m:.1f}M")
        if len(parts) <= 1:
            parts.append("valid entry/SL/TP structure")
        return '; '.join(parts[:5])
    except Exception:
        return 'valid entry/SL/TP structure'


def _setup_audit_current_price_for_row(row: dict) -> float:
    """No-network current/stale last price for audit fallback."""
    try:
        sym = str((row or {}).get('symbol') or '').upper().strip()
        base = sym[:-4] if sym.endswith('USDT') else sym
        ticks = get_cached_futures_tickers() or {}
        mv = ticks.get(base)
        if mv is None:
            # Some caches are keyed by exchange symbol/base variants.
            for k, v in (ticks or {}).items():
                try:
                    if str(k).upper().replace('/USDT:USDT', '').replace('USDT', '') == base:
                        mv = v
                        break
                except Exception:
                    continue
        px = float(getattr(mv, 'last', 0.0) or 0.0) if mv is not None else 0.0
        return px if px > 0 else 0.0
    except Exception:
        return 0.0


def _setup_audit_result_from_cached_price_moves(row: dict, horizon_hours: int = 24) -> str:
    """Resolve WIN/LOSE/OPEN without live OHLCV fetching.

    /setup_audit must be instant. The previous implementation called the full
    report evaluator for every setup, which could fetch 1m/5m/15m OHLCV and
    time out. This version uses already-cached OHLCV first and then the cached
    ticker price. That still reflects actual price movement while keeping the
    command fast and safe for production.
    """
    try:
        # Prefer the bot's existing signal_outcomes table when available. It is
        # created by the price-move evaluator and avoids showing OPEN for older
        # setups that were already resolved by the background outcome sync.
        try:
            sid0 = str((row or {}).get('setup_id') or '').strip()
            if sid0:
                out0 = db_get_outcome(sid0) or {}
                oc0 = str((out0 or {}).get('outcome') or '').upper().strip()
                if oc0 in {'TP', 'WIN', 'WIN_TP', 'TP1', 'TP2', 'TP3'}:
                    return 'WIN'
                if oc0 in {'SL', 'LOSS', 'LOSE'}:
                    return 'LOSE'
        except Exception:
            pass
        side = str((row or {}).get('side') or '').upper().strip()
        symbol_raw = str((row or {}).get('symbol') or '').upper().strip()
        base = symbol_raw[:-4] if symbol_raw.endswith('USDT') else symbol_raw
        market_symbol = str((row or {}).get('market_symbol') or '').strip() or _market_symbol_from_base(base)
        entry = float((row or {}).get('entry') or 0.0)
        sl = float((row or {}).get('sl') or 0.0)
        tp = float((row or {}).get('tp') or 0.0)
        if tp <= 0:
            tp = _resolve_single_tp(entry, sl, (row or {}).get('tp'), (row or {}).get('alt_target_a'), (row or {}).get('alt_target_b'), side)
        created_ts = float((row or {}).get('ts') or (row or {}).get('created_ts') or (row or {}).get('signal_created_ts') or 0.0)
        if side not in {'BUY', 'SELL'} or not market_symbol or entry <= 0 or sl <= 0 or tp <= 0:
            return 'OPEN'

        now_ts = float(time.time())
        horizon_end = (min(now_ts, created_ts + float(max(1, int(horizon_hours or 0))) * 3600.0) if (created_ts > 0 and int(horizon_hours or 0) > 0) else now_ts)
        candles_all = []
        # Prefer cached candles only; never call fetch_ohlcv/fetch_ohlcv_paged here.
        for tf, lim in (('1m', 300), ('5m', 300), ('15m', 200)):
            try:
                rows = _ohlcv_best_effort_cached(market_symbol, tf, lim) or []
            except Exception:
                rows = []
            if not rows:
                continue
            for c in rows:
                try:
                    ts_sec = float(c[0]) / 1000.0
                    if created_ts > 0 and ts_sec < created_ts - 60.0:
                        continue
                    if ts_sec > horizon_end + 60.0:
                        continue
                    candles_all.append((ts_sec, float(c[2]), float(c[3])))
                except Exception:
                    continue
            if candles_all:
                break

        candles_all.sort(key=lambda x: x[0])
        for _ts, hi, lo in candles_all:
            if side == 'BUY':
                hit_tp = hi >= tp
                hit_sl = lo <= sl
            else:
                hit_tp = lo <= tp
                hit_sl = hi >= sl
            if hit_tp and hit_sl:
                # Same-candle ambiguity in cached/coarse data: be conservative for audit.
                # The grouped evaluator tries 1m first; this fallback should not leave
                # an old resolved setup as OPEN forever.
                return 'LOSE'
            if hit_tp:
                return 'WIN'
            if hit_sl:
                return 'LOSE'

        # Fast current-price fallback from the cached ticker snapshot.
        px = _setup_audit_current_price_for_row(row)
        if px > 0:
            if side == 'BUY':
                if px >= tp:
                    return 'WIN'
                if px <= sl:
                    return 'LOSE'
            else:
                if px <= tp:
                    return 'WIN'
                if px >= sl:
                    return 'LOSE'
        # v56: no audit expiry. If neither TP nor SL has been touched yet,
        # the setup remains OPEN until a future price path resolves it.
        return 'OPEN'
    except Exception:
        return 'OPEN'




def _setup_audit_migrate() -> None:
    """Persistent setup-audit result store.

    This is separate from autotrade_trades on purpose: /setup_audit is a price-path
    audit of every generated setup, whether or not Bybit ever opened a position.
    """
    try:
        with sqlite3.connect(DB_PATH) as conn:
            c = conn.cursor()
            c.execute("""CREATE TABLE IF NOT EXISTS setup_audit_results (
                setup_id TEXT PRIMARY KEY,
                user_id INTEGER NOT NULL DEFAULT 0,
                created_ts REAL NOT NULL DEFAULT 0,
                evaluated_ts REAL NOT NULL DEFAULT 0,
                horizon_hours INTEGER NOT NULL DEFAULT 24,
                symbol TEXT NOT NULL DEFAULT '',
                side TEXT NOT NULL DEFAULT '',
                session TEXT NOT NULL DEFAULT '',
                family TEXT NOT NULL DEFAULT '',
                engine TEXT NOT NULL DEFAULT '',
                conf INTEGER NOT NULL DEFAULT 0,
                fut_vol_usd REAL NOT NULL DEFAULT 0,
                entry REAL NOT NULL DEFAULT 0,
                sl REAL NOT NULL DEFAULT 0,
                tp REAL NOT NULL DEFAULT 0,
                ch24 REAL NOT NULL DEFAULT 0,
                ch4 REAL NOT NULL DEFAULT 0,
                ch1 REAL NOT NULL DEFAULT 0,
                ch15 REAL NOT NULL DEFAULT 0,
                result TEXT NOT NULL DEFAULT 'OPEN',
                hit_level TEXT NOT NULL DEFAULT '',
                hit_ts REAL,
                net_r REAL NOT NULL DEFAULT 0,
                actual_pnl_usdt REAL NOT NULL DEFAULT 0,
                source TEXT NOT NULL DEFAULT '',
                entry_reason TEXT NOT NULL DEFAULT '',
                note TEXT NOT NULL DEFAULT ''
            )""")
            c.execute("CREATE INDEX IF NOT EXISTS idx_setup_audit_results_user_created ON setup_audit_results(user_id, created_ts)")
            c.execute("CREATE INDEX IF NOT EXISTS idx_setup_audit_results_family ON setup_audit_results(family, result)")
            conn.commit()
    except Exception:
        pass


def _setup_audit_short_text(value, max_len: int = 44) -> str:
    try:
        txt = str(value or '').replace('\n', ' ').replace('\r', ' ').strip()
        txt = re.sub(r'\s+', ' ', txt)
        if len(txt) <= int(max_len):
            return txt
        return txt[:max(1, int(max_len) - 1)] + '…'
    except Exception:
        return ''


def _setup_audit_result_horizon_hours() -> int:
    """Setup-audit TP/SL evaluation lifetime.

    v56: generated setups do NOT expire for audit/policy purposes. The hour
    argument on /setup_audit only selects which setup rows to display; outcome
    evaluation checks the price path from setup time until now. A setup remains
    OPEN until price actually hits either TP or SL.

    Set SETUP_AUDIT_UNLIMITED_RESULT_HORIZON=0 only for a temporary diagnostic
    rollback to the old fixed-hour horizon.
    """
    try:
        if env_bool('SETUP_AUDIT_UNLIMITED_RESULT_HORIZON', True):
            return 0
        return max(1, min(8760, int(float(os.environ.get('SETUP_AUDIT_RESULT_HOURS', '24') or 24))))
    except Exception:
        return 0


def _setup_audit_result_horizon_label(hours: int | None = None) -> str:
    try:
        h = _setup_audit_result_horizon_hours() if hours is None else int(hours or 0)
        if h <= 0:
            return 'until TP/SL (no expiry)'
        return f'{int(h)}h'
    except Exception:
        return 'until TP/SL (no expiry)'


def _setup_audit_result_horizon_is_unlimited(hours: int | None = None) -> bool:
    try:
        h = _setup_audit_result_horizon_hours() if hours is None else int(hours or 0)
        return int(h or 0) <= 0
    except Exception:
        return True


def _setup_audit_family_code(row_or_family) -> str:
    """Compact family label: F1, F2, ... F9."""
    try:
        if isinstance(row_or_family, dict):
            return _setup_audit_family_display(row_or_family, compact=True)
        s = str(row_or_family or '').upper().replace('-', '_').strip()
        m = re.search(r'\b(F[0-9]+)\b', s)
        if m:
            return m.group(1)
        return _setup_family_id_to_code(s) if s else '-'
    except Exception:
        return '-'


def _setup_audit_row_ts(row: dict) -> float:
    try:
        return float((row or {}).get('ts') or (row or {}).get('created_ts') or (row or {}).get('signal_created_ts') or (row or {}).get('executable_ts') or 0.0)
    except Exception:
        return 0.0


def _setup_audit_local_date_key(ts: float) -> str:
    try:
        if float(ts or 0.0) <= 0:
            return 'unknown_date'
        return datetime.fromtimestamp(float(ts), tz=timezone.utc).astimezone(MEL_TZ).strftime('%Y-%m-%d')
    except Exception:
        return 'unknown_date'


def _setup_audit_unique_key(row: dict) -> str:
    """De-duplicate repeated scanner saves into one practical setup.

    Default behaviour is intentionally stricter than raw setup_id uniqueness:
    the same symbol + side + family inside a time bucket is one actionable setup.
    Raw scanner saves often have tiny entry/SL/TP drift and would otherwise inflate
    /setup_audit and /setup_audit_overall counts.
    """
    try:
        rr = _setup_audit_payload_from_row(row)
        ts = _setup_audit_row_ts(rr)
        mode = str(globals().get('SETUP_AUDIT_DEDUP_MODE', 'LOCAL_DAY') or 'LOCAL_DAY').upper().strip()
        if mode in {'DAY', 'DAILY', 'LOCAL_DAY', 'MELBOURNE_DAY'} and float(ts or 0.0) > 0:
            bucket = _setup_audit_local_date_key(float(ts))
        elif mode in {'NONE', 'SETUP_ID'}:
            bucket = str(rr.get('setup_id') or int(float(ts or 0.0)))
        else:
            bucket_h = max(1, int(globals().get('SETUP_AUDIT_DEDUP_BUCKET_HOURS', 24) or 24))
            bucket = int(float(ts or 0.0) // (bucket_h * 3600)) if float(ts or 0.0) > 0 else 0
        sym = str(rr.get('symbol') or '').upper().strip()
        if sym.endswith('USDT'):
            sym = sym[:-4]
        side = str(rr.get('side') or '').upper().strip()
        fam = _setup_audit_family_code(rr)
        sess = str(rr.get('session') or rr.get('source_session') or '').upper().strip() or 'NOSESSION'
        strat = _setup_strategy_suffix(rr)
        key = f'{bucket}|{sess}|{strat}|{sym}|{side}|{fam}'
        if bool(globals().get('SETUP_AUDIT_DEDUP_INCLUDE_LEVELS', False)):
            entry = float(rr.get('entry') or 0.0)
            sl = float(rr.get('sl') or 0.0)
            tp = float(rr.get('tp') or 0.0)
            if entry > 0:
                entry_b = round(entry, max(0, 3 - int(math.log10(abs(entry))) if entry > 0 else 3))
                sl_b = round(((entry - sl) / entry) * 100.0, 1) if sl > 0 else 0.0
                tp_b = round(((tp - entry) / entry) * 100.0, 1) if tp > 0 else 0.0
            else:
                entry_b, sl_b, tp_b = 0.0, 0.0, 0.0
            key += f'|{entry_b}|{sl_b}|{tp_b}'
        return key
    except Exception:
        sid = str((row or {}).get('setup_id') or '').strip()
        return sid or str(id(row))


def _setup_audit_window_summary(rows: list[dict]) -> dict:
    try:
        ts_vals = sorted([_setup_audit_row_ts(r) for r in (rows or []) if _setup_audit_row_ts(r) > 0])
        if not ts_vals:
            return {'start_ts': 0.0, 'end_ts': 0.0, 'duration_days': 0.0, 'avg_daily': 0.0, 'start_txt': '-', 'end_txt': '-'}
        start_ts, end_ts = float(ts_vals[0]), float(ts_vals[-1])
        duration_days = max(1.0 / 24.0, ((end_ts - start_ts) / 86400.0) if end_ts > start_ts else (1.0 / 24.0))
        avg_daily = float(len(rows or [])) / duration_days if duration_days > 0 else 0.0
        start_txt = datetime.fromtimestamp(start_ts, tz=timezone.utc).astimezone(MEL_TZ).strftime('%Y-%m-%d %H:%M')
        end_txt = datetime.fromtimestamp(end_ts, tz=timezone.utc).astimezone(MEL_TZ).strftime('%Y-%m-%d %H:%M')
        return {'start_ts': start_ts, 'end_ts': end_ts, 'duration_days': duration_days, 'avg_daily': avg_daily, 'start_txt': start_txt, 'end_txt': end_txt}
    except Exception:
        return {'start_ts': 0.0, 'end_ts': 0.0, 'duration_days': 0.0, 'avg_daily': 0.0, 'start_txt': '-', 'end_txt': '-'}


def _setup_audit_help_text() -> str:
    return (
        "🧪 <b>Setup Audit Guide</b>\n"
        f"{HDR}\n"
        "<b>Purpose</b>: check generated setups against the real post-setup price path, independent from AutoTrade.\n\n"
        "<b>Commands</b>\n"
        "• <code>/setup_audit</code> — unique setups from the last 24h.\n"
        "• <code>/setup_audit 1</code> — unique setups generated in the last 1h.\n"
        "• <code>/setup_audit 6</code> — unique setups generated in the last 6h.\n"
        "• <code>/setup_audit 24</code> — unique setups generated in the last 24h.\n"
        "• <code>/setup_audit 48</code> — unique setups generated in the last 48h.\n"
        "• <code>/setup_audit overall</code> — same as <code>/setup_audit_overall</code>.\n"
        "• <code>/setup_audit h</code> or <code>/setup_audit help</code> — this guide.\n\n"
        "<b>Columns</b>\n"
        "• Symbol — coin.\n"
        "• Type — BUY/SELL.\n"
        "• Conf — setup confidence.\n"
        "• Family — compact family code, e.g. F1/F2/F3/F8/F9.\n"
        "• Result — TP, SL, or OPEN.\n"
        "  OPEN means price has not hit TP or SL yet; it can stay OPEN forever until resolved.\n\n"
        "<b>Important</b>: the hour argument filters setup generation time only. "
        "TP/SL checking has no due date: it evaluates from setup time until now."
    )


def _setup_audit_result_label(value: str) -> str:
    v = str(value or '').upper().strip()
    if v in {'TP', 'WIN', 'WIN_TP', 'TP1', 'TP2', 'TP3', 'HIT_TP_WIN'}:
        return 'TP'
    if v in {'SL', 'LOSS', 'LOSE', 'HIT_SL_LOSS'}:
        return 'SL'
    if v in {'NOHIT', 'NO_HIT', 'TIMEOUT', 'EXPIRED', 'HORIZON_EXPIRED_NO_HIT', 'NO_TP_SL'}:
        # v56: setups have no due date. Legacy NOHIT/expired states are unresolved, not terminal.
        return 'OPEN'
    return 'OPEN'


def _setup_audit_binary_display_result(row: dict | None, result: str, horizon_hours: int | None = None) -> str:
    """v56 user-facing setup-audit result resolver.

    Setups have no due date. TP and SL are terminal. Any unresolved/no-hit/
    expired legacy state displays as OPEN until the future price path touches TP
    or SL. This is reporting-only and does not change live AutoTrade entry,
    TP/SL placement, or risk logic.
    """
    lab = _setup_audit_result_label(result)
    if lab in {'TP', 'SL'}:
        return lab
    return 'OPEN'


def _setup_audit_net_r_for_result(row: dict, result: str) -> float:
    try:
        side = str((row or {}).get('side') or '').upper().strip()
        entry = float((row or {}).get('entry') or 0.0)
        sl = float((row or {}).get('sl') or 0.0)
        tp = float((row or {}).get('tp') or 0.0)
        if tp <= 0:
            tp = float(_resolve_single_tp(entry, sl, (row or {}).get('tp'), (row or {}).get('alt_target_a'), (row or {}).get('alt_target_b'), side) or 0.0)
        risk = abs(entry - sl)
        if entry <= 0 or sl <= 0 or tp <= 0 or risk <= 0:
            return 0.0
        res = _setup_audit_result_label(result)
        if res == 'SL':
            return -1.0
        if res == 'TP':
            reward = (tp - entry) if side == 'BUY' else (entry - tp)
            return float(reward / risk) if reward > 0 else 0.0
        return 0.0
    except Exception:
        return 0.0



def _setup_audit_find_nearest_setup_row(symbol: str, side: str, ref_ts: float = 0.0, uid: int | None = None) -> dict:
    """Best-effort family/setup metadata recovery for AutoTrade rows.

    Older live/provisional AutoTrade rows sometimes have no setup_id/family_id,
    which made /autotrade_report show F0 for everything. This looks up the
    nearest generated/executable setup by symbol+side around the trade open time
    and returns its metadata for reporting only.
    """
    try:
        sym_full = _bybit_linear_symbol(symbol)
        base = _symbol_base(sym_full)
        sd = _norm_trade_side(side)
        ref = float(ref_ts or 0.0)
        if not base or sd not in {'BUY', 'SELL'}:
            return {}
        symbols = list(dict.fromkeys([base, sym_full, str(symbol or '').upper().strip()]))
        # First pass: tight window around open; second pass: wider fallback.
        windows = [(12 * 3600.0, 3 * 3600.0), (48 * 3600.0, 12 * 3600.0)]
        best_rows: list[dict] = []
        with sqlite3.connect(DB_PATH) as conn:
            conn.row_factory = sqlite3.Row
            cur = conn.cursor()
            for before_s, after_s in windows:
                lo = max(0.0, ref - before_s) if ref > 0 else 0.0
                hi = (ref + after_s) if ref > 0 else float(time.time()) + 3600.0
                # executable_setups
                try:
                    cols = {r[1] for r in cur.execute('PRAGMA table_info(executable_setups)').fetchall()}
                    if cols:
                        fam_expr = "COALESCE(family_id, '') AS family_id" if 'family_id' in cols else "'' AS family_id"
                        strategy_expr = "COALESCE(setup_strategy, '') AS setup_strategy" if 'setup_strategy' in cols else "'' AS setup_strategy"
                        orig_id_expr = "COALESCE(original_setup_id, '') AS original_setup_id" if 'original_setup_id' in cols else "'' AS original_setup_id"
                        orig_side_expr = "COALESCE(original_side, '') AS original_side" if 'original_side' in cols else "'' AS original_side"
                        strategy_reason_expr = "COALESCE(strategy_reason, '') AS strategy_reason" if 'strategy_reason' in cols else "'' AS strategy_reason"
                        q = f"""
                            SELECT executable_ts AS ts, signal_created_ts, 'EXEC' AS source, session, setup_id, symbol, market_symbol, side, conf,
                                   fut_vol_usd, ch24, ch4, ch1, ch15, engine, details_json, quality_score,
                                   {fam_expr}, {strategy_expr}, {orig_id_expr}, {orig_side_expr}, {strategy_reason_expr}, entry, sl, tp, alt_target_a, alt_target_b
                            FROM executable_setups
                            WHERE UPPER(side)=? AND UPPER(symbol) IN ({','.join(['?']*len(symbols))})
                        """
                        params = [sd] + symbols
                        if uid is not None and 'user_id' in cols:
                            q += " AND user_id=?"
                            params.append(int(uid))
                        if ref > 0:
                            q += " AND executable_ts>=? AND executable_ts<=?"
                            params.extend([lo, hi])
                        q += " ORDER BY ABS(executable_ts-?) ASC LIMIT 8"
                        params.append(ref if ref > 0 else time.time())
                        best_rows.extend([dict(r) for r in cur.execute(q, tuple(params)).fetchall() or []])
                except Exception:
                    pass
                # generated_setups
                try:
                    cols = {r[1] for r in cur.execute('PRAGMA table_info(generated_setups)').fetchall()}
                    if cols:
                        market_expr = 'market_symbol' if 'market_symbol' in cols else "'' AS market_symbol"
                        reason_expr = 'entry_reason' if 'entry_reason' in cols else "'' AS entry_reason"
                        alt_a_expr = 'alt_target_a' if 'alt_target_a' in cols else '0 AS alt_target_a'
                        alt_b_expr = 'alt_target_b' if 'alt_target_b' in cols else '0 AS alt_target_b'
                        fam_expr = "COALESCE(family_id, '') AS family_id" if 'family_id' in cols else "'' AS family_id"
                        strategy_expr = "COALESCE(setup_strategy, '') AS setup_strategy" if 'setup_strategy' in cols else "'' AS setup_strategy"
                        orig_id_expr = "COALESCE(original_setup_id, '') AS original_setup_id" if 'original_setup_id' in cols else "'' AS original_setup_id"
                        orig_side_expr = "COALESCE(original_side, '') AS original_side" if 'original_side' in cols else "'' AS original_side"
                        strategy_reason_expr = "COALESCE(strategy_reason, '') AS strategy_reason" if 'strategy_reason' in cols else "'' AS strategy_reason"
                        source_expr = 'UPPER(source)' if 'source' in cols else "'GEN'"
                        q = f"""
                            SELECT created_ts AS ts, 0 AS signal_created_ts, {source_expr} AS source, session, setup_id, symbol, {market_expr}, side, conf,
                                   fut_vol_usd, ch24, ch4, ch1, ch15, engine, '' AS details_json, 0 AS quality_score,
                                   {fam_expr}, {strategy_expr}, {orig_id_expr}, {orig_side_expr}, {strategy_reason_expr}, entry, sl, tp, {alt_a_expr}, {alt_b_expr}, {reason_expr}
                            FROM generated_setups
                            WHERE UPPER(side)=? AND UPPER(symbol) IN ({','.join(['?']*len(symbols))})
                        """
                        params = [sd] + symbols
                        if uid is not None and 'user_id' in cols:
                            q += " AND user_id=?"
                            params.append(int(uid))
                        if ref > 0:
                            q += " AND created_ts>=? AND created_ts<=?"
                            params.extend([lo, hi])
                        q += " ORDER BY ABS(created_ts-?) ASC LIMIT 8"
                        params.append(ref if ref > 0 else time.time())
                        best_rows.extend([dict(r) for r in cur.execute(q, tuple(params)).fetchall() or []])
                except Exception:
                    pass
                if best_rows:
                    break
        if not best_rows:
            return {}
        def _score(r: dict):
            ts = float(r.get('ts') or r.get('signal_created_ts') or 0.0)
            fam_ok = 0 if _setup_audit_family_display(r, compact=True) not in {'', '-', 'F0'} else 1
            dt = abs(ts - ref) if ref > 0 and ts > 0 else 10**12
            # Prefer setup created before or near the trade open, then nearest.
            future_pen = 0 if (ref <= 0 or ts <= ref + 1800.0) else 1
            return (fam_ok, future_pen, dt, -ts)
        best_rows.sort(key=_score)
        return dict(best_rows[0])
    except Exception:
        return {}


def _setup_audit_find_row_by_setup_id(setup_id: str) -> dict:
    sid = str(setup_id or '').strip()
    if not sid:
        return {}
    try:
        with sqlite3.connect(DB_PATH) as conn:
            conn.row_factory = sqlite3.Row
            cur = conn.cursor()
            try:
                x_cols = {r[1] for r in cur.execute('PRAGMA table_info(executable_setups)').fetchall()}
                x_family_expr = "COALESCE(family_id, '') AS family_id" if 'family_id' in x_cols else "'' AS family_id"
                x_strategy_expr = "COALESCE(setup_strategy, '') AS setup_strategy" if 'setup_strategy' in x_cols else "'' AS setup_strategy"
                x_orig_id_expr = "COALESCE(original_setup_id, '') AS original_setup_id" if 'original_setup_id' in x_cols else "'' AS original_setup_id"
                x_orig_side_expr = "COALESCE(original_side, '') AS original_side" if 'original_side' in x_cols else "'' AS original_side"
                x_strategy_reason_expr = "COALESCE(strategy_reason, '') AS strategy_reason" if 'strategy_reason' in x_cols else "'' AS strategy_reason"
                row = cur.execute(f"""
                    SELECT executable_ts AS ts, signal_created_ts, 'EXEC' AS source, session, setup_id, symbol, market_symbol, side, conf,
                           fut_vol_usd, ch24, ch4, ch1, ch15, engine, details_json, quality_score,
                           {x_family_expr}, {x_strategy_expr}, {x_orig_id_expr}, {x_orig_side_expr}, {x_strategy_reason_expr}, entry, sl, tp, alt_target_a, alt_target_b
                    FROM executable_setups
                    WHERE setup_id=?
                    ORDER BY executable_ts DESC
                    LIMIT 1
                """, (sid,)).fetchone()
                if row:
                    return dict(row)
            except Exception:
                pass
            try:
                cols = {r[1] for r in cur.execute('PRAGMA table_info(generated_setups)').fetchall()}
                market_expr = 'market_symbol' if 'market_symbol' in cols else "'' AS market_symbol"
                reason_expr = 'entry_reason' if 'entry_reason' in cols else "'' AS entry_reason"
                alt_a_expr = 'alt_target_a' if 'alt_target_a' in cols else '0 AS alt_target_a'
                alt_b_expr = 'alt_target_b' if 'alt_target_b' in cols else '0 AS alt_target_b'
                row = cur.execute(f"""
                    SELECT created_ts AS ts, 0 AS signal_created_ts, UPPER(source) AS source, session, setup_id, symbol, {market_expr}, side, conf,
                           fut_vol_usd, ch24, ch4, ch1, ch15, engine, '' AS details_json, 0 AS quality_score,
                           COALESCE(family_id, '') AS family_id, entry, sl, tp, {alt_a_expr}, {alt_b_expr}, {reason_expr}
                    FROM generated_setups
                    WHERE setup_id=?
                    ORDER BY created_ts DESC
                    LIMIT 1
                """, (sid,)).fetchone()
                if row:
                    return dict(row)
            except Exception:
                pass
    except Exception:
        pass
    return {}



def _autotrade_report_find_nearest_trade_metadata(row: dict, uid: int | None = None) -> dict:
    """Best-effort repair for report rows built from exchange close events.

    Some Bybit closed-PnL rows arrive without the original bot journal fields.  For
    reporting only, recover the nearest AutoTrade journal row by setup_id/trade_id or
    symbol+side+time so Dyn/Risk%/Risk$/TP$/Strategy are not blank for fresh closes.
    """
    try:
        rr = dict(row or {})
        uid_i = int(uid or rr.get('uid') or globals().get('AUTOTRADE_OWNER_UID', 0) or 0)
        sid = str(rr.get('setup_id') or '').strip()
        tid = str(rr.get('trade_id') or '').strip()
        sym = str(_bybit_linear_symbol(rr.get('symbol') or '')).upper().strip()
        base = _symbol_base(sym)
        side = str(rr.get('side') or '').upper().strip()
        ref = float(rr.get('closed_ts') or rr.get('opened_ts') or rr.get('ts') or time.time())
        if uid_i <= 0:
            return {}
        with sqlite3.connect(DB_PATH) as conn:
            conn.row_factory = sqlite3.Row
            cur = conn.cursor()
            if tid and not tid.startswith(('exchange::', 'report::', 'prov::', 'manual::')):
                r = cur.execute("SELECT * FROM autotrade_trades WHERE uid=? AND trade_id=? LIMIT 1", (uid_i, tid)).fetchone()
                if r:
                    return dict(r)
            if sid:
                r = cur.execute("SELECT * FROM autotrade_trades WHERE uid=? AND setup_id=? ORDER BY COALESCE(closed_ts, opened_ts, created_ts, 0) DESC LIMIT 1", (uid_i, sid)).fetchone()
                if r:
                    return dict(r)
            if not sym or side not in {'BUY','SELL'}:
                return {}
            variants = list(dict.fromkeys([sym, base, str(rr.get('symbol') or '').upper().strip()]))
            q = f"""
                SELECT * FROM autotrade_trades
                WHERE uid=?
                  AND UPPER(side)=?
                  AND UPPER(symbol) IN ({','.join(['?']*len(variants))})
                  AND COALESCE(opened_ts, created_ts, 0) <= ?
                  AND COALESCE(opened_ts, created_ts, 0) >= ?
                ORDER BY ABS(COALESCE(NULLIF(closed_ts,0), opened_ts, created_ts, 0) - ?) ASC,
                         ABS(COALESCE(opened_ts, created_ts, 0) - ?) ASC
                LIMIT 1
            """
            params = [uid_i, side] + variants + [float(ref) + 2*3600.0, float(ref) - 36*3600.0, float(ref), float(ref)]
            r = cur.execute(q, tuple(params)).fetchone()
            return dict(r) if r else {}
    except Exception:
        return {}


def _autotrade_report_fill_missing_from_trade_metadata(row: dict, uid: int | None = None) -> dict:
    try:
        out = dict(row or {})
        meta = _autotrade_report_find_nearest_trade_metadata(out, uid=uid)
        if not meta:
            return out
        numeric_keys = {
            'entry','sl','tp','alt_target_a','alt_target_b','qty','conf','quality_score','atr_pct',
            'risk_usd','risk_usdt','risk_pct','tp_usd','tp_usdt','risk_multiplier','dynamic_risk_score',
            'configured_risk_pct','allowed_risk_pct','rr_tp','opened_ts'
        }
        text_keys = {
            'trade_id','setup_id','family_id','engine','session','setup_strategy','strategy','strategy_mode',
            'original_setup_id','original_side','strategy_reason','regime_primary','allocator_plan_id','param_set_id'
        }
        for k in numeric_keys:
            try:
                cur = float(out.get(k) or 0.0)
                val = float(meta.get(k) or 0.0)
                if cur <= 0 and val > 0:
                    out[k] = val
            except Exception:
                pass
        for k in text_keys:
            try:
                if not str(out.get(k) or '').strip() and str(meta.get(k) or '').strip():
                    out[k] = meta.get(k)
            except Exception:
                pass
        # Keep the exchange close PnL/timestamp as authoritative.
        for k in ('closed_ts','pnl','pnl_usdt','outcome','note','close_reason','result_path','result_label','source_note'):
            if k in (row or {}) and (row or {}).get(k) not in (None, ''):
                out[k] = (row or {}).get(k)
        return out
    except Exception:
        return dict(row or {})

def _setup_audit_merge_trade_setup_row(trade_row: dict | None) -> dict:
    row = dict(trade_row or {})
    try:
        row = _autotrade_report_fill_missing_from_trade_metadata(row, uid=int(row.get('uid') or globals().get('AUTOTRADE_OWNER_UID', 0) or 0))
    except Exception:
        pass
    sid = str(row.get('setup_id') or '').strip()
    setup_row = {}
    if sid:
        setup_row = _setup_audit_find_row_by_setup_id(sid)
    # Legacy/provisional rows often have no setup_id/family_id. Recover the
    # family from the nearest setup by symbol+side+opened_ts so /autotrade_report
    # does not show F0 for every closed trade.
    if not setup_row:
        try:
            ref_ts = float(row.get('opened_ts') or row.get('created_ts') or row.get('closed_ts') or 0.0)
            setup_row = _setup_audit_find_nearest_setup_row(
                str(row.get('symbol') or ''),
                str(row.get('side') or ''),
                ref_ts=ref_ts,
                uid=int(row.get('uid') or AUTOTRADE_OWNER_UID or 0) if (row.get('uid') or AUTOTRADE_OWNER_UID) else None,
            )
        except Exception:
            setup_row = {}
    if setup_row:
        merged = dict(setup_row)
        # Keep real trade fields where they are more authoritative for report display.
        for k, v in row.items():
            if k in {'trade_id', 'uid', 'opened_ts', 'closed_ts', 'pnl_usdt', 'pnl', 'status', 'qty', 'note', 'outcome', 'risk_usd', 'risk_usdt', 'risk_pct', 'tp_usd', 'tp_usdt', 'risk_multiplier', 'dynamic_risk_score', 'configured_risk_pct', 'allowed_risk_pct', 'rr_tp', 'result_path', 'result_label', 'close_reason', 'source_note', 'policy_at_open', 'policy_combo_at_open', 'policy_execnow_at_open'}:
                merged[k] = v
            elif not str(merged.get(k) or '').strip():
                merged[k] = v
        return merged
    return row


def _setup_audit_payload_from_row(row: dict) -> dict:
    out = dict(row or {})
    try:
        out['setup_id'] = str(out.get('setup_id') or '').strip()
        out['symbol'] = _bybit_linear_symbol(str(out.get('symbol') or ''))
        out['market_symbol'] = str(out.get('market_symbol') or '').strip() or _market_symbol_from_base(out.get('symbol'))
        out['side'] = _norm_trade_side(str(out.get('side') or ''))
        created = float(out.get('first_seen_ts') or out.get('signal_created_ts') or out.get('created_ts') or out.get('ts') or out.get('opened_ts') or 0.0)
        out['created_ts'] = float(created or 0.0)
        out['entry'] = float(out.get('entry') or 0.0)
        out['sl'] = float(out.get('sl') or 0.0)
        out['tp'] = float(_resolve_single_tp(out['entry'], out['sl'], out.get('tp'), out.get('alt_target_a'), out.get('alt_target_b'), out.get('side')) or 0.0)
        out['alt_target_a'] = 0.0
        out['alt_target_b'] = 0.0
        out['setup_strategy'] = _setup_strategy_label(out)
        out['strategy'] = out['setup_strategy']
    except Exception:
        pass
    return out


def _setup_audit_cached_result(setup_id: str, horizon_hours: int, allow_open_fresh_sec: int = 240) -> dict:
    sid = str(setup_id or '').strip()
    if not sid:
        return {}
    try:
        _setup_audit_migrate()
        with sqlite3.connect(DB_PATH) as conn:
            conn.row_factory = sqlite3.Row
            cur = conn.cursor()
            row = cur.execute("SELECT * FROM setup_audit_results WHERE setup_id=? LIMIT 1", (sid,)).fetchone()
            if not row:
                return {}
            d = dict(row)
            result = _setup_audit_result_label(d.get('result'))
            if result in {'TP', 'SL'}:
                return d
            # v56: old NOHIT/expired cache rows are not terminal anymore; ignore
            # them so the setup can continue resolving until TP or SL.
            if result == 'NOHIT':
                return {}
            # OPEN can change forever; reuse only a very recent OPEN cache.
            age = float(time.time()) - float(d.get('evaluated_ts') or 0.0)
            req_h = int(horizon_hours or 0)
            stored_h = int(d.get('horizon_hours') or 0)
            if (req_h <= 0 or stored_h == req_h) and age <= max(30, int(allow_open_fresh_sec)):
                return d
    except Exception:
        pass
    return {}


def _setup_audit_upsert_result(user_id: int, row: dict, result_payload: dict, horizon_hours: int, actual_pnl_usdt: float = 0.0) -> None:
    try:
        _setup_audit_migrate()
        rr = dict(row or {})
        sid = str(rr.get('setup_id') or '').strip()
        if not sid:
            return
        result = _setup_audit_result_label((result_payload or {}).get('result') or (result_payload or {}).get('outcome'))
        hit_level = str((result_payload or {}).get('hit_level') or (result if result in {'TP', 'SL'} else '')).upper().strip()
        hit_ts = (result_payload or {}).get('hit_ts')
        try:
            hit_ts_v = float(hit_ts) if hit_ts is not None else None
        except Exception:
            hit_ts_v = None
        side = str(rr.get('side') or '').upper().strip()
        entry = float(rr.get('entry') or 0.0)
        sl = float(rr.get('sl') or 0.0)
        tp = float(rr.get('tp') or 0.0)
        if tp <= 0:
            tp = float(_resolve_single_tp(entry, sl, rr.get('tp'), rr.get('alt_target_a'), rr.get('alt_target_b'), side) or 0.0)
        fam = _setup_audit_family_from_row(rr)
        reason = _setup_audit_reason_from_row(rr)
        created_ts = float(rr.get('first_seen_ts') or rr.get('signal_created_ts') or rr.get('created_ts') or rr.get('ts') or 0.0)
        net_r = _setup_audit_net_r_for_result({**rr, 'tp': tp}, result)
        with sqlite3.connect(DB_PATH) as conn:
            cur = conn.cursor()
            cur.execute("""INSERT OR REPLACE INTO setup_audit_results
                (setup_id, user_id, created_ts, evaluated_ts, horizon_hours, symbol, side, session, family, engine, conf, fut_vol_usd,
                 entry, sl, tp, ch24, ch4, ch1, ch15, result, hit_level, hit_ts, net_r, actual_pnl_usdt, source, entry_reason, note)
                VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)""",
                (
                    sid, int(user_id), float(created_ts or 0.0), float(time.time()), int(horizon_hours),
                    str(_bybit_linear_symbol(rr.get('symbol') or '')).upper(), side, str(rr.get('session') or '').upper().strip(),
                    str(fam or ''), str(rr.get('engine') or '').upper().strip(), int(float(rr.get('conf') or 0.0)), float(rr.get('fut_vol_usd') or 0.0),
                    float(entry or 0.0), float(sl or 0.0), float(tp or 0.0), float(rr.get('ch24') or 0.0), float(rr.get('ch4') or 0.0),
                    float(rr.get('ch1') or 0.0), float(rr.get('ch15') or 0.0), result, hit_level, hit_ts_v, float(net_r or 0.0),
                    float(actual_pnl_usdt or 0.0), str(rr.get('source') or '').upper().strip(), str(reason or ''), str((result_payload or {}).get('note') or '')[:240],
                )
            )
            conn.commit()
    except Exception:
        pass


def _setup_audit_price_result_payload(row: dict, horizon_hours: int = 24, user_id: int = 0, force: bool = False, actual_pnl_usdt: float = 0.0) -> dict:
    """Price-path result independent of AutoTrade.

    Uses the setup's entry/SL/TP and historical Bybit candles to decide which level
    was touched first. It never treats an AutoTrade close as proof unless the same
    price path independently resolves to TP/SL.
    """
    try:
        row = _setup_audit_payload_from_row(row)
        sid = str(row.get('setup_id') or '').strip()
        horizon_hours = 0 if int(horizon_hours or 0) <= 0 else int(max(1, min(int(horizon_hours or 24), 8760)))
        if sid and not force:
            cached = _setup_audit_cached_result(sid, horizon_hours)
            if cached:
                return {'result': _setup_audit_result_label(cached.get('result')), 'hit_level': cached.get('hit_level'), 'hit_ts': cached.get('hit_ts'), 'note': cached.get('note') or 'cached_setup_audit_result'}
        if not sid or not row.get('market_symbol') or float(row.get('entry') or 0.0) <= 0 or float(row.get('sl') or 0.0) <= 0 or float(row.get('tp') or 0.0) <= 0:
            res = {'result': 'OPEN', 'hit_level': '', 'hit_ts': None, 'note': 'missing_or_invalid_setup_levels'}
        else:
            # Fast path: use existing outcome table + cached OHLCV/current ticker first.
            # This keeps /setup_audit responsive and independent from autotrade even when
            # Bybit rate-limits historical 1m/5m requests.
            quick_result = _setup_audit_result_from_cached_price_moves(row, horizon_hours=horizon_hours)
            if _setup_audit_result_label(quick_result) in {'TP', 'SL'}:
                res = {
                    'result': _setup_audit_result_label(quick_result),
                    'hit_level': _setup_audit_result_label(quick_result),
                    'hit_ts': None,
                    'best_level': _setup_audit_result_label(quick_result),
                    'best_ts': None,
                    'note': 'fast_cached_price_path',
                }
            else:
                best = None
                allow_heavy = bool(force) or str(os.environ.get('SETUP_AUDIT_HEAVY_EVAL', '0')).strip().lower() in {'1', 'true', 'yes', 'on'}
                if allow_heavy:
                    # Use 15m first for speed; it still falls back internally if data is available.
                    for tf in ('15m', '5m'):
                        try:
                            tmp = evaluate_signal_hit_order(row, horizon_hours=horizon_hours, timeframe=tf)
                        except Exception as exc:
                            tmp = {'outcome': 'OPEN', 'hit_level': '', 'hit_ts': None, 'note': f'eval_error_{tf}:{type(exc).__name__}'}
                        canon = _setup_audit_result_label((tmp or {}).get('outcome'))
                        if canon in {'TP', 'SL'}:
                            best = dict(tmp or {})
                            best['result'] = canon
                            break
                        if best is None:
                            best = dict(tmp or {})
                if not isinstance(best, dict):
                    best = {'outcome': 'OPEN', 'hit_level': '', 'hit_ts': None, 'note': 'fast_no_hit_or_no_cached_price_data'}
                res = {
                    'result': _setup_audit_result_label(best.get('result') or best.get('outcome')),
                    'hit_level': str(best.get('hit_level') or '').upper().strip(),
                    'hit_ts': best.get('hit_ts'),
                    'best_level': best.get('best_level'),
                    'best_ts': best.get('best_ts'),
                    'note': str(best.get('note') or 'price_path_eval'),
                }
        try:
            _setup_audit_upsert_result(int(user_id or 0), row, res, horizon_hours, actual_pnl_usdt=actual_pnl_usdt)
        except Exception:
            pass
        return res
    except Exception as exc:
        return {'result': 'OPEN', 'hit_level': '', 'hit_ts': None, 'note': f'setup_audit_error:{type(exc).__name__}'}


def _setup_audit_price_result_from_row(row: dict, horizon_hours: int = 24) -> str:
    """Backward-compatible wrapper used by /setup_audit."""
    return _setup_audit_result_label(_setup_audit_price_result_payload(row, horizon_hours=horizon_hours).get('result'))


def _setup_audit_tf_seconds(timeframe: str) -> int:
    try:
        tf = str(timeframe or '').strip().lower()
        if tf.endswith('m'):
            return max(60, int(float(tf[:-1])) * 60)
        if tf.endswith('h'):
            return max(3600, int(float(tf[:-1])) * 3600)
    except Exception:
        pass
    return 300


def _setup_audit_market_symbol_for_row(row: dict) -> str:
    try:
        rr = _setup_audit_payload_from_row(row)
        ms = str(rr.get('market_symbol') or '').strip()
        if ms:
            return ms
        sym = str(rr.get('symbol') or '').upper().strip()
        base = sym[:-4] if sym.endswith('USDT') else sym
        return str(_market_symbol_from_base(base) or '').strip()
    except Exception:
        return ''


def _setup_audit_preload_ohlcv(rows: list[dict], hours: int = 24, timeframe: str | None = None) -> dict:
    """Fetch one OHLCV window per symbol for /setup_audit.

    The old audit evaluated each setup independently and usually fell back to cached
    tickers, which left many rows as OPEN. This grouped loader makes the command
    check the real post-setup price path while avoiding one exchange call per row.
    """
    out: dict[str, list] = {}
    try:
        tf = str(timeframe or os.environ.get('SETUP_AUDIT_TIMEFRAME', '5m') or '5m').strip().lower() or '5m'
        now_ts = float(time.time())
        by_symbol: dict[str, list[dict]] = {}
        for raw in (rows or []):
            try:
                rr = _setup_audit_payload_from_row(raw)
                ms = _setup_audit_market_symbol_for_row(rr)
                created_ts = float(rr.get('created_ts') or rr.get('ts') or rr.get('signal_created_ts') or 0.0)
                if not ms or created_ts <= 0:
                    continue
                by_symbol.setdefault(ms, []).append(rr)
            except Exception:
                continue
        for ms, items in by_symbol.items():
            try:
                min_created = min(float(x.get('created_ts') or x.get('ts') or x.get('signal_created_ts') or now_ts) for x in items)
                max_end = now_ts if int(hours or 0) <= 0 else max(min(now_ts, float(x.get('created_ts') or x.get('ts') or x.get('signal_created_ts') or now_ts) + float(hours) * 3600.0) for x in items)
                # Buffer one candle before and after so a setup created inside a candle can still be evaluated.
                buf = _setup_audit_tf_seconds(tf) + 60
                since_ms = int(max(0.0, min_created - buf) * 1000)
                until_ms = int(min(now_ts + 60.0, max_end + buf) * 1000)
                candles = fetch_ohlcv_paged(ms, tf, since_ms=since_ms, until_ms=until_ms, limit=1000) or []
                if candles:
                    out[ms] = sorted(candles, key=lambda c: c[0])
                    # Also update the general cache for later commands.
                    try:
                        _ohlcv_update_superset_cache(ms, tf, out[ms])
                    except Exception:
                        pass
            except Exception:
                continue
    except Exception:
        pass
    return out


def _setup_audit_payload_result_from_candles(row: dict, candles: list, horizon_hours: int = 24, timeframe: str = '5m') -> dict:
    try:
        rr = _setup_audit_payload_from_row(row)
        side = str(rr.get('side') or '').upper().strip()
        entry = float(rr.get('entry') or 0.0)
        sl = float(rr.get('sl') or 0.0)
        tp = float(rr.get('tp') or 0.0)
        created_ts = float(rr.get('created_ts') or rr.get('ts') or rr.get('signal_created_ts') or 0.0)
        if side not in {'BUY', 'SELL'} or entry <= 0 or sl <= 0 or tp <= 0 or created_ts <= 0:
            return {'result': 'OPEN', 'hit_level': '', 'hit_ts': None, 'note': 'missing_or_invalid_setup_levels'}
        tf_sec = _setup_audit_tf_seconds(timeframe)
        now_ts = float(time.time())
        horizon_end = (min(now_ts, created_ts + float(max(1, int(horizon_hours or 0))) * 3600.0) if int(horizon_hours or 0) > 0 else now_ts)
        filt = []
        for c in (candles or []):
            try:
                ts_s = float(c[0]) / 1000.0
                # yver84: only evaluate candles whose open time is at/after the
                # setup timestamp. Using the whole candle that started before the
                # setup can falsely count a TP/SL touch that happened before the
                # setup existed.
                if ts_s < created_ts - 2:
                    continue
                if ts_s > horizon_end + tf_sec:
                    continue
                filt.append(c)
            except Exception:
                continue
        if not filt:
            return {'result': 'OPEN', 'hit_level': '', 'hit_ts': None, 'note': 'no_price_candles'}
        res = _signal_hit_order_from_candles(side, sl, tp, filt) or {}
        canon = _setup_audit_result_label(res.get('outcome') or res.get('result'))
        note = str(res.get('note') or '')
        # If coarse candles crossed both TP and SL in the same bar, do a 1m targeted check.
        if canon == 'OPEN' and 'same_candle' in note.lower():
            try:
                ms = _setup_audit_market_symbol_for_row(rr)
                since_ms = int(max(0.0, created_ts - 90.0) * 1000)
                until_ms = int(min(now_ts + 60.0, horizon_end + 90.0) * 1000)
                c1 = fetch_ohlcv_paged(ms, '1m', since_ms=since_ms, until_ms=until_ms, limit=1000) or []
                if c1:
                    r1 = _signal_hit_order_from_candles(side, sl, tp, sorted(c1, key=lambda x: x[0])) or {}
                    c1canon = _setup_audit_result_label(r1.get('outcome') or r1.get('result'))
                    if c1canon in {'TP', 'SL'}:
                        r1['result'] = c1canon
                        r1['note'] = str(r1.get('note') or '') or 'resolved_1m_after_ambiguous_coarse_candle'
                        return r1
            except Exception:
                pass
        # v56: no NOHIT expiry. If the filtered post-setup candles have not
        # touched TP/SL yet, keep the setup OPEN.
        return {
            'result': canon,
            'hit_level': str(res.get('hit_level') or (canon if canon in {'TP', 'SL'} else '')).upper().strip(),
            'hit_ts': res.get('hit_ts'),
            'best_level': res.get('best_level'),
            'best_ts': res.get('best_ts'),
            'note': (note or f'resolved_{timeframe}') if canon in {'TP', 'SL'} else (note or 'not_hit_yet'),
        }
    except Exception as exc:
        return {'result': 'OPEN', 'hit_level': '', 'hit_ts': None, 'note': f'candles_eval_error:{type(exc).__name__}'}


def _setup_audit_resolve_result(row: dict, horizon_hours: int, user_id: int, candles_by_symbol: dict | None = None, audit_timeframe: str = '5m', actual_pnl_usdt: float = 0.0) -> dict:
    """Authoritative result resolver for /setup_audit.

    yver86: fresh OHLCV candle path is the authority. Older builds cached some
    TP/SL decisions before the candle-start filtering fix, so trusting cache
    first can keep a wrong setup result alive forever. We now recompute from the
    post-setup candle path whenever candles are available, overwrite the cached
    result, and use cached/outcome rows only as fallback when price candles are not
    available.
    """
    try:
        rr = _setup_audit_payload_from_row(row)
        sid = str(rr.get('setup_id') or '').strip()
        ms = _setup_audit_market_symbol_for_row(rr)
        candles = (candles_by_symbol or {}).get(ms) or []
        last_ev = {'result': 'OPEN', 'hit_level': '', 'hit_ts': None, 'note': 'no_grouped_candles'}

        # 1) Fresh price-path evaluation first. This is the only source that should
        # drive self-improvement when candles are available.
        if candles:
            ev = _setup_audit_payload_result_from_candles(rr, candles, horizon_hours=horizon_hours, timeframe=audit_timeframe)
            canon = _setup_audit_result_label(ev.get('result'))
            if canon in {'TP', 'SL'}:
                ev['result'] = canon
                try:
                    _setup_audit_upsert_result(int(user_id or 0), rr, ev, int(horizon_hours), actual_pnl_usdt=actual_pnl_usdt)
                except Exception:
                    pass
                return ev
            last_ev = ev or last_ev

        # 2) Only if candles were unavailable/ambiguous, use cached decided rows.
        # Keep this fallback configurable so future audits can be forced fully live.
        trust_cache = env_bool('SETUP_AUDIT_TRUST_CACHE_WHEN_NO_CANDLES', True)
        if trust_cache and sid and str((last_ev or {}).get('note') or '').lower() in {'no_grouped_candles', 'no_price_candles'}:
            try:
                cached = _setup_audit_cached_result(sid, horizon_hours, allow_open_fresh_sec=0) if sid else {}
                if cached and _setup_audit_result_label(cached.get('result')) in {'TP', 'SL'}:
                    return {'result': _setup_audit_result_label(cached.get('result')), 'hit_level': cached.get('hit_level'), 'hit_ts': cached.get('hit_ts'), 'note': cached.get('note') or 'cached_decided_result_no_candles'}
            except Exception:
                pass

            # Existing signal outcome table can be a decided source only when candles
            # are missing. It must not override freshly recomputed price-path evidence.
            try:
                out0 = db_get_outcome(sid) or {}
                oc0 = _setup_audit_result_label((out0 or {}).get('outcome'))
                if oc0 in {'TP', 'SL'}:
                    return {'result': oc0, 'hit_level': oc0, 'hit_ts': (out0 or {}).get('hit_ts'), 'note': 'signal_outcome_decided_no_candles'}
            except Exception:
                pass

        # 3) Optional heavy fallback for rows where grouped candles were missing.
        allow_heavy = str(os.environ.get('SETUP_AUDIT_HEAVY_EVAL', '0')).strip().lower() in {'1', 'true', 'yes', 'on'}
        if allow_heavy and str((last_ev or {}).get('note') or '').lower() in {'no_grouped_candles', 'no_price_candles'}:
            try:
                tmp = evaluate_signal_hit_order(rr, horizon_hours=int(horizon_hours), timeframe=str(audit_timeframe or '5m'))
                canon = _setup_audit_result_label((tmp or {}).get('outcome') or (tmp or {}).get('result'))
                if canon in {'TP', 'SL'}:
                    ev = dict(tmp or {})
                    ev['result'] = canon
                    try:
                        _setup_audit_upsert_result(int(user_id or 0), rr, ev, int(horizon_hours), actual_pnl_usdt=actual_pnl_usdt)
                    except Exception:
                        pass
                    return ev
            except Exception:
                pass

        # 4) Current-price fallback catches active rows that just crossed TP/SL.
        quick = _setup_audit_result_from_cached_price_moves(rr, horizon_hours=horizon_hours)
        canon = _setup_audit_result_label(quick)
        if canon in {'TP', 'SL'}:
            ev = {'result': canon, 'hit_level': canon, 'hit_ts': None, 'note': 'current_price_or_cached_outcome'}
        else:
            ev = dict(last_ev or {})
            ev['result'] = _setup_audit_result_label(ev.get('result'))
            if ev['result'] == 'OPEN':
                ev.setdefault('note', 'not_hit_yet')
        try:
            _setup_audit_upsert_result(int(user_id or 0), rr, ev, int(horizon_hours), actual_pnl_usdt=actual_pnl_usdt)
        except Exception:
            pass
        return ev
    except Exception as exc:
        return {'result': 'OPEN', 'hit_level': '', 'hit_ts': None, 'note': f'setup_audit_resolve_error:{type(exc).__name__}'}

def _setup_audit_actual_pnl_by_setup(user_id: int, start_ts: float = 0.0, end_ts: float = 0.0) -> dict:
    """Optional AutoTrade PnL lookup for diagnostics only.

    Ver02 default is OFF because /setup_audit and /setup_audit_overall must be fully
    independent from real AutoTrade results and /autotrade_config. The setup result is
    resolved from post-setup price path against entry/SL/TP, not from live trades.
    """
    if not env_bool('SETUP_AUDIT_INCLUDE_AUTOTRADE_PNL', False):
        return {}
    out = {}
    try:
        with sqlite3.connect(DB_PATH) as conn:
            conn.row_factory = sqlite3.Row
            cur = conn.cursor()
            q = "SELECT setup_id, SUM(COALESCE(pnl_usdt,0)) AS pnl FROM autotrade_trades WHERE uid=? AND setup_id IS NOT NULL AND setup_id<>'' AND closed_ts IS NOT NULL"
            params = [int(user_id)]
            if float(start_ts or 0.0) > 0:
                q += " AND closed_ts>=?"
                params.append(float(start_ts))
            if float(end_ts or 0.0) > 0:
                q += " AND closed_ts<?"
                params.append(float(end_ts))
            q += " GROUP BY setup_id"
            for r in cur.execute(q, tuple(params)).fetchall() or []:
                out[str(r['setup_id'] or '').strip()] = float(r['pnl'] or 0.0)
    except Exception:
        pass
    return out


def _setup_audit_load_rows(uid: int, hours: int | None = 24, limit: int = 0, dedup: bool = True, start_ts: float | None = None, apply_final_quality_gate: bool | None = None, source_mode_override: str | None = None) -> list[dict]:
    """Load setup rows for audit.

    Default source is executable_setups only. Raw generated_setups can be enabled with
    SETUP_AUDIT_SOURCE_MODE=ALL/GENERATED, but the normal audit should reflect the
    actionable/executable lane used by email and AutoTrade, not every raw scan candidate.
    """
    try:
        _migrate_generated_setups()
    except Exception:
        pass
    try:
        _setup_audit_migrate()
    except Exception:
        pass
    cutoff = 0.0
    try:
        if start_ts is not None and float(start_ts or 0.0) > 0:
            cutoff = float(start_ts or 0.0)
        elif hours is not None and int(hours or 0) > 0:
            cutoff = float(time.time()) - float(int(hours)) * 3600.0
    except Exception:
        cutoff = 0.0

    mode = str(source_mode_override if source_mode_override is not None else (globals().get('SETUP_AUDIT_SOURCE_MODE', 'EXECUTABLE') or 'EXECUTABLE')).strip().upper()
    include_exec = mode in {'EXEC', 'EXECUTABLE', 'ACTIONABLE', 'EMAIL', 'AUTOTRADE', 'ALL'}
    include_gen = mode in {'GEN', 'GENERATED', 'RAW', 'RAW_GENERATED', 'ALL'}
    fallback_to_generated = bool(globals().get('SETUP_AUDIT_FALLBACK_TO_GENERATED', True))

    def _pull(include_generated: bool) -> list[dict]:
        rows: list[dict] = []
        lim_clause = ''
        params_extra = []
        if int(limit or 0) > 0:
            lim_clause = ' LIMIT ?'
            params_extra = [max(int(limit) * 12, int(limit) + 50)]
        try:
            with sqlite3.connect(DB_PATH) as con:
                con.row_factory = sqlite3.Row
                cur = con.cursor()
                if include_exec:
                    try:
                        params = [int(uid)]
                        where = "WHERE user_id=?"
                        if cutoff > 0:
                            where += " AND executable_ts>=?"
                            params.append(float(cutoff))
                        x_cols = {r[1] for r in cur.execute('PRAGMA table_info(executable_setups)').fetchall()}
                        if x_cols:
                            x_family_expr = "COALESCE(family_id, '') AS family_id" if 'family_id' in x_cols else "'' AS family_id"
                            x_strategy_expr = "COALESCE(setup_strategy, '') AS setup_strategy" if 'setup_strategy' in x_cols else "'' AS setup_strategy"
                            x_orig_id_expr = "COALESCE(original_setup_id, '') AS original_setup_id" if 'original_setup_id' in x_cols else "'' AS original_setup_id"
                            x_orig_side_expr = "COALESCE(original_side, '') AS original_side" if 'original_side' in x_cols else "'' AS original_side"
                            x_strategy_reason_expr = "COALESCE(strategy_reason, '') AS strategy_reason" if 'strategy_reason' in x_cols else "'' AS strategy_reason"
                            cur.execute(f"""
                                SELECT executable_ts AS ts, signal_created_ts, 'EXEC' AS source, session, setup_id, symbol, market_symbol, side, conf,
                                       fut_vol_usd, ch24, ch4, ch1, ch15, engine, details_json, quality_score,
                                       {x_family_expr}, {x_strategy_expr}, {x_orig_id_expr}, {x_orig_side_expr}, {x_strategy_reason_expr}, entry, sl, tp, alt_target_a, alt_target_b
                                FROM executable_setups
                                {where}
                                ORDER BY executable_ts DESC{lim_clause}
                            """, tuple(params + params_extra))
                            rows.extend([dict(r) for r in (cur.fetchall() or [])])
                    except Exception:
                        pass
                if include_generated:
                    try:
                        cols = {r[1] for r in cur.execute('PRAGMA table_info(generated_setups)').fetchall()}
                        if cols:
                            market_expr = 'market_symbol' if 'market_symbol' in cols else "'' AS market_symbol"
                            reason_expr = 'entry_reason' if 'entry_reason' in cols else "'' AS entry_reason"
                            alt_a_expr = 'alt_target_a' if 'alt_target_a' in cols else '0 AS alt_target_a'
                            alt_b_expr = 'alt_target_b' if 'alt_target_b' in cols else '0 AS alt_target_b'
                            family_expr = "COALESCE(family_id, '') AS family_id" if 'family_id' in cols else "'' AS family_id"
                            strategy_expr = "COALESCE(setup_strategy, '') AS setup_strategy" if 'setup_strategy' in cols else "'' AS setup_strategy"
                            orig_id_expr = "COALESCE(original_setup_id, '') AS original_setup_id" if 'original_setup_id' in cols else "'' AS original_setup_id"
                            orig_side_expr = "COALESCE(original_side, '') AS original_side" if 'original_side' in cols else "'' AS original_side"
                            strategy_reason_expr = "COALESCE(strategy_reason, '') AS strategy_reason" if 'strategy_reason' in cols else "'' AS strategy_reason"
                            source_expr = 'UPPER(source)' if 'source' in cols else "'GEN'"
                            params = [int(uid)]
                            where = "WHERE user_id=?"
                            if cutoff > 0:
                                where += " AND created_ts>=?"
                                params.append(float(cutoff))
                            cur.execute(f"""
                                SELECT created_ts AS ts, 0 AS signal_created_ts, {source_expr} AS source, session, setup_id, symbol, {market_expr}, side, conf,
                                       fut_vol_usd, ch24, ch4, ch1, ch15, engine, '' AS details_json, 0 AS quality_score,
                                       {family_expr}, {strategy_expr}, {orig_id_expr}, {orig_side_expr}, {strategy_reason_expr}, entry, sl, tp, {alt_a_expr}, {alt_b_expr}, {reason_expr}
                                FROM generated_setups
                                {where}
                                ORDER BY created_ts DESC{lim_clause}
                            """, tuple(params + params_extra))
                            rows.extend([dict(r) for r in (cur.fetchall() or [])])
                    except Exception:
                        pass
        except Exception:
            return []
        return rows

    rows = _pull(include_gen)
    if not rows and (not include_gen) and fallback_to_generated:
        rows = _pull(True)
        try:
            for r in rows:
                r['source'] = 'GEN_FALLBACK'
        except Exception:
            pass

    cleaned: list[dict] = []
    for r in rows:
        try:
            rr = _setup_audit_payload_from_row(r)
            if not str(rr.get('setup_id') or '').strip():
                rr['setup_id'] = _setup_audit_unique_key(rr)
            if not _setup_volume_ok(float(rr.get('fut_vol_usd') or 0.0)):
                continue
            _apply_gate = bool(globals().get('SETUP_AUDIT_APPLY_FINAL_QUALITY_GATE', True)) if apply_final_quality_gate is None else bool(apply_final_quality_gate)
            if _apply_gate:
                try:
                    sess_rr = str(rr.get('session') or rr.get('source_session') or '').upper().strip()
                    final_ok, _final_why, _final_meta = _setup_final_quality_gate_allows_setup(rr, sess_rr, user_id=int(uid or 0))
                    if not final_ok:
                        continue
                except Exception:
                    continue
            cleaned.append(rr)
        except Exception:
            continue

    cleaned = sorted(cleaned, key=lambda x: _setup_audit_row_ts(x), reverse=True)
    if bool(dedup):
        deduped: dict[str, dict] = {}
        # Keep the earliest actionable row within the practical setup key. Keeping
        # the newest row turns repeated snapshots into fake OPENs and inflates counts.
        for r in sorted(cleaned, key=lambda x: _setup_audit_row_ts(x)):
            key = _setup_audit_unique_key(r)
            if key not in deduped:
                deduped[key] = r
        final = sorted(list(deduped.values()), key=lambda x: _setup_audit_row_ts(x), reverse=True)
    else:
        seen_sid: set[str] = set()
        final = []
        for r in cleaned:
            sid = str(r.get('setup_id') or '').strip()
            if sid and sid in seen_sid:
                continue
            if sid:
                seen_sid.add(sid)
            final.append(r)
    if int(limit or 0) > 0:
        final = final[:int(limit)]
    return final




_SETUP_AUDIT_LIVE_POS_CACHE = {'ts': 0.0, 'rows': []}

def _setup_audit_live_position_present(symbol: str, side: str) -> bool:
    """Return whether a matching live Bybit position currently exists.

    yver144: /setup_audit AT should not keep showing AT_OPEN just because the
    local journal row has not yet been closed/synced. Use the short cached live
    Bybit position list as the source of truth for whether an already-executed
    setup is still open.
    """
    try:
        sym_lin = _bybit_linear_symbol(str(symbol or '')).upper().strip()
        sym_base = _symbol_base(sym_lin)
        side_u = str(side or '').upper().strip()
        if not sym_base or side_u not in {'BUY', 'SELL'}:
            return False
        cache = globals().setdefault('_SETUP_AUDIT_LIVE_POS_CACHE', {'ts': 0.0, 'rows': []})
        now = float(time.time())
        rows = []
        try:
            if isinstance(cache, dict) and (now - float(cache.get('ts') or 0.0)) <= 8.0:
                rows = list(cache.get('rows') or [])
            else:
                rows = list(_bybit_get_open_positions_linear() or [])
                cache['ts'] = now
                cache['rows'] = list(rows or [])
        except Exception:
            rows = list(cache.get('rows') or []) if isinstance(cache, dict) else []
        for p in rows or []:
            try:
                psym = _symbol_base(str(_pos_symbol(p) or p.get('symbol') or ''))
                pside = str(_pos_side_text(p) or p.get('side') or '').upper().strip()
                if psym == sym_base and pside == side_u:
                    return True
            except Exception:
                continue
    except Exception:
        pass
    return False


def _yver58_setup_audit_trade_match_safe(setup_row: dict, trade_row: dict, uid: int = 0, allow_missing_open_ts: bool = False) -> bool:
    """Strictly verify that an AutoTrade row belongs to this visible setup row.

    v58: /setup_audit is a setup report, not a loose symbol/side trade report.
    A real trade can only be attached to a setup row when the trade opened soon
    after that setup (inside the AutoTrade entry deadline plus a small logging
    buffer), and when the stored open-time combo snapshot does not contradict the
    row combo. This prevents older same-symbol trades, or reused/legacy setup_id
    metadata, from showing AT_CLOSED/ATPol/PnL on a newer setup row.
    """
    try:
        rr = dict(setup_row or {})
        tr = dict(trade_row or {})
        setup_ts = float(_setup_audit_row_ts(rr) or 0.0)
        if setup_ts <= 0:
            return bool(allow_missing_open_ts)
        opened_ts = float(tr.get('opened_ts') or tr.get('created_ts') or 0.0)
        if opened_ts <= 0:
            return bool(allow_missing_open_ts)
        try:
            entry_win = float(max(60, int(_autotrade_entry_window_min()) * 60))
        except Exception:
            entry_win = 60.0 * 60.0
        # Allow fill/logging clock drift, but do not attach positions opened long
        # before/after this setup. Analysis has no expiry; AutoTrade entry matching does.
        if opened_ts < setup_ts - 10.0 * 60.0:
            return False
        if opened_ts > setup_ts + entry_win + 20.0 * 60.0:
            return False

        sym_setup = _symbol_base(str(rr.get('symbol') or rr.get('market_symbol') or '')).upper().strip()
        sym_trade = _symbol_base(str(tr.get('symbol') or tr.get('market_symbol') or '')).upper().strip()
        if sym_setup and sym_trade and sym_setup != sym_trade:
            return False
        side_setup = str(rr.get('side') or '').upper().strip()
        side_trade = str(tr.get('side') or '').upper().strip()
        if side_setup in {'BUY','SELL'} and side_trade in {'BUY','SELL'} and side_setup != side_trade:
            return False

        # If the trade stored an open-time matrix combo, it must agree with this
        # row's combo.  This catches cases where a Bybit/journal row is enriched
        # with an older setup while a newer same-symbol setup is also visible.
        combo_snap = str(tr.get('policy_combo_at_open') or tr.get('setup_combo_at_open') or '').upper().strip()
        if combo_snap:
            try:
                sess = str(rr.get('session') or rr.get('source_session') or '-').upper().strip() or '-'
                row_combo = _setup_combo_strategy_side_key(_setup_audit_family_code(rr), sess, rr, side_setup).upper().strip()
                if row_combo and combo_snap != row_combo:
                    return False
            except Exception:
                pass
        return True
    except Exception:
        return False


def _setup_audit_autotrade_state_label(row: dict, uid: int = 0, session_name: str = '') -> str:
    """Return setup lifecycle state for /setup_audit display.

    yver143: A row can be OFF for *new delivery now* after the 60-minute entry
    window, while the same setup has already been emailed and opened by
    AutoTrade.  That is not an invalid trade; it is an already-consumed setup.
    This helper makes that visible so /setup_audit is not mistaken for the live
    /screen candidate list.
    """
    try:
        rr = dict(row or {})
        owner_uid = int(globals().get('AUTOTRADE_OWNER_UID', 0) or uid or 0)
        if owner_uid <= 0:
            return '-'
        sid = str(rr.get('setup_id') or rr.get('id') or '').strip()
        sym_raw = str(rr.get('symbol') or rr.get('market_symbol') or '').upper().strip()
        sym_lin = _bybit_linear_symbol(sym_raw) if sym_raw else ''
        sym_base = _symbol_base(sym_raw) if sym_raw else ''
        side_u = str(rr.get('side') or '').upper().strip()
        setup_ts = float(_setup_audit_row_ts(rr) or 0.0)
        entry_win_sec = float(max(60, int(_autotrade_entry_window_min()) * 60))
        # Generous linkage window for fallback symbol/side matching where older DBs
        # may not have preserved setup_id exactly.
        match_start = max(0.0, setup_ts - 300.0) if setup_ts > 0 else 0.0
        match_end = (setup_ts + entry_win_sec + 900.0) if setup_ts > 0 else float(time.time()) + 3600.0
        try:
            with sqlite3.connect(DB_PATH) as conn:
                conn.row_factory = sqlite3.Row
                cur = conn.cursor()
                rows = []
                if sid:
                    rows = [dict(r) for r in (cur.execute(
                        """
                        SELECT setup_id, symbol, side, status, opened_ts, closed_ts, outcome
                        FROM autotrade_trades
                        WHERE uid=? AND setup_id=?
                        ORDER BY COALESCE(opened_ts,0) DESC
                        LIMIT 3
                        """,
                        (int(owner_uid), sid),
                    ).fetchall() or [])]
                if not rows and (sym_base or sym_lin) and side_u in {'BUY', 'SELL'}:
                    q = """
                        SELECT setup_id, symbol, side, status, opened_ts, closed_ts, outcome
                        FROM autotrade_trades
                        WHERE uid=? AND UPPER(COALESCE(side,''))=?
                          AND COALESCE(opened_ts,0)>=? AND COALESCE(opened_ts,0)<=?
                        ORDER BY COALESCE(opened_ts,0) DESC
                        LIMIT 20
                    """
                    cand = [dict(r) for r in (cur.execute(q, (int(owner_uid), side_u, float(match_start), float(match_end))).fetchall() or [])]
                    rows = []
                    for r in cand:
                        rsym = str(r.get('symbol') or '').upper().strip()
                        if _symbol_base(rsym) == sym_base or _bybit_linear_symbol(rsym) == sym_lin:
                            rows.append(r)
                            break
                if rows:
                    # v58: even an exact setup_id can be stale/legacy metadata.
                    # Attach lifecycle only if the AutoTrade open time is safe for
                    # this visible setup row.
                    try:
                        rows = [dict(x or {}) for x in rows if _yver58_setup_audit_trade_match_safe(rr, dict(x or {}), uid=int(owner_uid))]
                    except Exception:
                        rows = []
                if rows:
                    r0 = dict(rows[0] or {})
                    st = str(r0.get('status') or '').upper().strip()
                    out = str(r0.get('outcome') or st or '').upper().strip()
                    if out in {'TP', 'SL'}:
                        return f'AT_{out}'
                    if st == 'OPEN' and not r0.get('closed_ts'):
                        # yver147: if the independent audit path has already hit
                        # TP/SL for this setup, do not label it AT_OPEN just
                        # because a newer same-symbol/same-side position exists.
                        # This avoids stale rows like old ZEC BUY showing AT_OPEN
                        # while /autotrade_report has already closed that trade.
                        try:
                            audit_res = str(rr.get('result') or rr.get('res') or rr.get('outcome') or '').upper().strip()
                            if audit_res in {'TP', 'SL'}:
                                return 'AT_CLOSED'
                        except Exception:
                            pass
                        # yver144: the local journal can lag Bybit close sync.
                        # Only show AT_OPEN if the symbol/side is still live now;
                        # otherwise mark it as already consumed/closed instead of
                        # making /setup_audit disagree with /autotrade_debug.
                        if _setup_audit_live_position_present(sym_lin or sym_raw, side_u):
                            return 'AT_OPEN'
                        return 'AT_CLOSED'
                    return 'AT_CLOSED' if r0.get('closed_ts') else 'AT'
                if sid:
                    er = cur.execute(
                        "SELECT MAX(emailed_ts) FROM emailed_setups WHERE user_id=? AND setup_id=?",
                        (int(owner_uid), sid),
                    ).fetchone()
                    ets = float((er[0] if er else 0.0) or 0.0)
                    if ets > 0:
                        try:
                            if (float(time.time()) - ets) <= entry_win_sec:
                                return 'SENT'
                        except Exception:
                            return 'SENT'
                        return 'SENT_OLD'
        except Exception:
            return '-'
        return '-'
    except Exception:
        return '-'


def _setup_audit_short_autotrade_reason(reason: str) -> str:
    """Compact reason label for the /setup_audit ATWhy column."""
    r = str(reason or '').strip().lower()
    if not r:
        return '-'
    mapping = [
        ('directional_context_blocks_sell_leader', 'DIRECTION'),
        ('directional_context_blocks_buy_loser', 'DIRECTION'),
        ('directional_context', 'DIRECTION'),
        ('leader_sell', 'DIRECTION'),
        ('loser_buy', 'DIRECTION'),
        ('entry_drift_too_wide', 'DRIFT'),
        ('max_open_trades', 'MAX_OPEN'),
        ('max_trades', 'MAX_DAY'),
        ('daily_risk', 'DAILY_CAP'),
        ('open_risk', 'OPEN_CAP'),
        ('blocked_manual_same_symbol_position', 'MANUAL_POS'),
        ('manual_same_symbol', 'MANUAL_POS'),
        ('manual_position', 'MANUAL_POS'),
        ('missing_recent_setup_email', 'NO_EMAIL'),
        ('setup_email', 'NO_EMAIL'),
        ('email_gate', 'EMAIL_GATE'),
        ('setup_expired', 'EXPIRED'),
        ('expired', 'EXPIRED'),
        ('trade_window_block', 'BLACKOUT'),
        ('blackout', 'BLACKOUT'),
        ('session_not_allowed', 'SESSION'),
        ('duplicate', 'DUPLICATE'),
        ('already_open', 'DUPLICATE'),
        ('liq_guard', 'LIQ_GUARD'),
        ('liquidation', 'LIQ_GUARD'),
        ('bad_prices', 'BAD_GEOM'),
        ('bad_geometry', 'BAD_GEOM'),
        ('missing_tp', 'BAD_GEOM'),
        ('leverage', 'LEVERAGE'),
        ('autotrade_off', 'AT_OFF'),
        ('entry_disabled', 'AT_OFF'),
        ('mode_not_live', 'MODE'),
        ('capital', 'CAPITAL'),
    ]
    for token, label in mapping:
        if token in r:
            return label
    return re.sub(r'[^A-Z0-9_]+', '_', str(reason or '').upper()).strip('_')[:16] or '-'


def _setup_audit_recent_attempt_reason(row: dict, uid: int = 0) -> str:
    """Best-effort match against the recent in-memory AutoTrade attempt list."""
    try:
        owner_uid = int(globals().get('AUTOTRADE_OWNER_UID', 0) or uid or 0)
        hist = list((_LAST_AUTOTRADE_ATTEMPTS.get(owner_uid) or []))
        if not hist:
            dec = _LAST_AUTOTRADE_DECISION.get(owner_uid) or {}
            hist = list((dec or {}).get('attempted_candidates') or []) if isinstance(dec, dict) else []
        if not hist:
            return ''
        rr = dict(row or {})
        sid = str(rr.get('setup_id') or rr.get('id') or '').strip()
        sym = _symbol_base(str(rr.get('symbol') or rr.get('market_symbol') or ''))
        side = str(rr.get('side') or '').upper().strip()
        setup_ts = float(_setup_audit_row_ts(rr) or 0.0)
        best = None
        best_dt = 10**18
        for a in hist:
            try:
                aa = dict(a or {})
                asid = str(aa.get('setup_id') or aa.get('id') or '').strip()
                asym = _symbol_base(str(aa.get('symbol') or aa.get('symbol_sent') or aa.get('symbol_raw') or ''))
                aside = str(aa.get('side') or '').upper().strip()
                if sid and asid and sid == asid:
                    best = aa
                    break
                if sym and asym == sym and side and aside == side:
                    when_raw = str(aa.get('when') or '')
                    try:
                        dt_ts = datetime.fromisoformat(when_raw.replace('Z', '+00:00')).timestamp() if when_raw else 0.0
                    except Exception:
                        dt_ts = 0.0
                    if setup_ts > 0 and dt_ts > 0:
                        delta = abs(float(dt_ts) - setup_ts)
                        if delta < best_dt and delta <= max(7200.0, float(_autotrade_entry_window_min()) * 60.0 + 1800.0):
                            best = aa
                            best_dt = delta
                    elif best is None:
                        best = aa
            except Exception:
                continue
        if isinstance(best, dict):
            return str(best.get('reason') or best.get('reject_reason') or best.get('status') or '').strip()
    except Exception:
        pass
    return ''


def _setup_audit_autotrade_skip_reason(row: dict, uid: int = 0, policy_label: str = '', at_state: str = '', session_name: str = '') -> str:
    """Explain why a /setup_audit row has not become an AutoTrade position.

    The column is diagnostic, not a second policy engine. It prioritises actual
    recent AutoTrade reject reasons, then falls back to the main live gates.
    """
    try:
        rr = dict(row or {})
        pol = str(policy_label or '').upper().strip()
        at = str(at_state or '').upper().strip()
        if at.startswith('AT_') or at == 'AT':
            return '-'
        if pol and pol != 'KEEP':
            return pol
        # yver45: surface hard leader/loser direction blocks in ATWhy instead
        # of showing PENDING/NO_EMAIL for a row that should never trade.
        try:
            sess_u = str(session_name or rr.get('session') or rr.get('source_session') or '').upper().strip()
            dir_ok, dir_why, _dir_meta = _setup_directional_context_guard_allows_setup(rr, session_name=sess_u, user_id=int(uid or 0))
            if not dir_ok:
                return 'DIRECTION'
        except Exception:
            pass
        reason = _setup_audit_recent_attempt_reason(rr, uid=int(uid or 0))
        if reason:
            return _setup_audit_short_autotrade_reason(reason)
        if not bool(_autotrade_entry_enabled()):
            return 'AT_OFF'
        if str(_autotrade_runtime_mode()).lower() != 'live':
            return 'MODE'
        try:
            blk, _why = _autotrade_entry_blackout_now()
            if blk:
                return 'BLACKOUT_NOW'
        except Exception:
            pass
        setup_ts = float(_setup_audit_row_ts(rr) or 0.0)
        entry_win_sec = float(max(60, int(_autotrade_entry_window_min()) * 60))
        age_sec = float(time.time()) - setup_ts if setup_ts > 0 else 0.0
        if setup_ts > 0 and age_sec > entry_win_sec:
            return 'EXPIRED'
        if bool(_autotrade_require_setup_email_for_entry()):
            if at == 'SENT_OLD':
                return 'SENT_OLD'
            if at not in {'SENT'}:
                return 'NO_EMAIL'
        try:
            side_u = str(rr.get('side') or '').upper().strip()
            sym = str(rr.get('symbol') or rr.get('market_symbol') or '')
            if side_u in {'BUY','SELL'} and sym and _setup_audit_live_position_present(sym, side_u):
                return 'DUPLICATE'
        except Exception:
            pass
        return 'PENDING'
    except Exception:
        return '-'

def _setup_audit_policy_label(row: dict, uid: int = 0, session_name: str = '', side: str = '') -> str:
    """Policy label for one /setup_audit row.

    yver24: this column is no longer a separate actionability calculation.
    It reads the same source-of-truth lane state rendered by /setup_matrix policy
    and returns that table's Policy value (KEEP / WATCH / TIGHTEN / DISABLE).
    Delivery, cooldown, risk and exchange safety remain separate downstream gates.
    """
    try:
        rr = dict(row or {})
        sess = str(session_name or rr.get('session') or rr.get('source_session') or '-').upper().strip() or '-'
        side_u = str(side or rr.get('side') or '').upper().strip()
        if side_u in {'BUY', 'SELL'}:
            rr['side'] = side_u
        policy_uid = int(globals().get('AUTOTRADE_OWNER_UID', 0) or uid or 0)
        state = _setup_matrix_policy_source_state_for_setup(rr, session_name=sess, user_id=policy_uid) or {}
        pol = str(state.get('policy') or '').upper().strip()
        if pol in {'KEEP', 'WATCH', 'TIGHTEN', 'DISABLE', 'OFF'}:
            return 'DISABLE' if pol == 'OFF' else pol
        return 'WATCH'
    except Exception:
        return 'DISABLE'


def _setup_audit_policy_wr_label(row: dict, uid: int = 0, session_name: str = '', side: str = '') -> str:
    """Display the current /setup_matrix policy WR for the row's exact lane.

    This is the broad lane WR from /setup_matrix policy, not the individual
    setup result in the Res column.  WR is shown only when the lane has decided
    TP/SL evidence; otherwise '-' keeps zero-evidence lanes clear.
    """
    try:
        rr = dict(row or {})
        sess = str(session_name or rr.get('session') or rr.get('source_session') or '-').upper().strip() or '-'
        side_u = str(side or rr.get('side') or '').upper().strip()
        if side_u in {'BUY', 'SELL'}:
            rr['side'] = side_u
        policy_uid = int(globals().get('AUTOTRADE_OWNER_UID', 0) or uid or 0)
        state = _setup_matrix_policy_source_state_for_setup(rr, session_name=sess, user_id=policy_uid) or {}
        dec = int(float(state.get('decided') or 0.0))
        if dec <= 0:
            return '-'
        wr = float(state.get('wr') or 0.0)
        return f"{wr:.1f}%"
    except Exception:
        return '-'


def _setup_audit_closed_pnl_index(rows: list[dict], uid: int = 0, hours: int = 24) -> dict:
    """Build a display-only PnL lookup for /setup_audit from canonical closed rows.

    /autotrade_closed uses the canonical closed-row pipeline, including Bybit Closed
    P&L enrichment.  yver43 only queried autotrade_trades by setup_id, so rows that
    /autotrade_closed could show still rendered '-' in /setup_audit.  This index
    keeps the two reports aligned without changing setup-audit TP/SL scoring.
    """
    idx = {'by_setup': {}, 'candidates': []}
    try:
        owner = int(globals().get('AUTOTRADE_OWNER_UID', 0) or uid or 0)
        ts_vals = [float(_setup_audit_row_ts(r) or 0.0) for r in (rows or []) if float(_setup_audit_row_ts(r) or 0.0) > 0]
        now_ts = float(time.time())
        if ts_vals:
            start_ts = max(0.0, min(ts_vals) - 6 * 3600.0)
            end_ts = max(now_ts + 3600.0, max(ts_vals) + float(_setup_audit_result_horizon_hours() + 6) * 3600.0)
        else:
            start_ts = now_ts - max(1, int(hours or 24)) * 3600.0
            end_ts = now_ts + 3600.0
        lookback_h = max(int(hours or 24) + 12, int((end_ts - start_ts) / 3600.0) + 2)
        closed_rows = _autotrade_closed_report_rows(owner, float(start_ts), float(end_ts), lookback_h=lookback_h, limit=0) or []
        for cr0 in closed_rows:
            try:
                cr = dict(cr0 or {})
                pnl = cr.get('pnl_usdt') if cr.get('pnl_usdt') is not None else cr.get('pnl')
                pnl_f = float(pnl or 0.0)
                sid = str(cr.get('setup_id') or cr.get('id') or '').strip()
                if sid:
                    idx['by_setup'][sid] = float(idx['by_setup'].get(sid, 0.0) or 0.0) + pnl_f
                sym = str(_bybit_linear_symbol(cr.get('symbol') or cr.get('market_symbol') or '')).upper().strip()
                side = str(cr.get('side') or '').upper().strip()
                if not sym or side not in {'BUY', 'SELL'}:
                    continue
                idx['candidates'].append({
                    'setup_id': sid,
                    'symbol': sym,
                    'base': _symbol_base(sym),
                    'side': side,
                    'opened_ts': float(cr.get('opened_ts') or 0.0),
                    'closed_ts': float(cr.get('closed_ts') or cr.get('close_ts') or 0.0),
                    'pnl': pnl_f,
                })
            except Exception:
                continue
    except Exception:
        pass
    return idx


def _setup_audit_match_closed_pnl_from_index(row: dict, idx: dict | None = None) -> float | None:
    try:
        rr = dict(row or {})
        idx = dict(idx or {})
        sid = str(rr.get('setup_id') or rr.get('id') or '').strip()
        if sid:
            # v58: exact setup_id alone is not enough for display matching because
            # older/enriched rows can carry stale setup metadata.  Confirm that
            # the trade opened inside this setup's AutoTrade entry window.
            vals = []
            for cand0 in list((idx or {}).get('candidates') or []):
                try:
                    cand = dict(cand0 or {})
                    if str(cand.get('setup_id') or '').strip() != sid:
                        continue
                    if _yver58_setup_audit_trade_match_safe(rr, cand):
                        vals.append(float(cand.get('pnl') or 0.0))
                except Exception:
                    continue
            if vals:
                return float(sum(vals))
        setup_ts = float(_setup_audit_row_ts(rr) or 0.0)
        sym_base = _symbol_base(str(rr.get('symbol') or rr.get('market_symbol') or ''))
        side_u = str(rr.get('side') or '').upper().strip()
        if setup_ts <= 0 or not sym_base or side_u not in {'BUY', 'SELL'}:
            return None
        # Prefer a closed row whose open time is close to the setup time.  If open
        # time is unavailable, use the close time as a weaker fallback inside the
        # audit horizon.  This mirrors /autotrade_closed enrichment but avoids
        # showing random same-symbol PnL from much older trades.
        entry_win = float(max(60, int(_autotrade_entry_window_min()) * 60))
        best = None
        best_score = 10**18
        for cand in list((idx or {}).get('candidates') or []):
            try:
                if str(cand.get('base') or '') != sym_base:
                    continue
                if str(cand.get('side') or '').upper().strip() != side_u:
                    continue
                opened = float(cand.get('opened_ts') or 0.0)
                closed = float(cand.get('closed_ts') or 0.0)
                if not _yver58_setup_audit_trade_match_safe(rr, cand):
                    continue
                if opened > 0:
                    if opened < setup_ts - 30 * 60.0 or opened > setup_ts + entry_win + 45 * 60.0:
                        continue
                    score = abs(opened - setup_ts)
                elif closed > 0:
                    if closed < setup_ts - 10 * 60.0 or closed > setup_ts + float(_setup_audit_result_horizon_hours() + 2) * 3600.0:
                        continue
                    score = 3600.0 + abs(closed - setup_ts)
                else:
                    continue
                if score < best_score:
                    best = cand
                    best_score = score
            except Exception:
                continue
        if best is not None:
            return float(best.get('pnl') or 0.0)
    except Exception:
        pass
    return None

def _setup_audit_closed_pnl_for_row(row: dict, uid: int = 0, at_state: str = '', pnl_index: dict | None = None) -> str:
    """Return realised AutoTrade PnL for a /setup_audit row when it is closed.

    This is display-only.  It does not change setup-audit TP/SL scoring.  It first
    matches by setup_id, then falls back to the same symbol/side/open-time window
    used by the AutoTrade journal, so the PnL column stays aligned with
    /autotrade_closed and /autotrade_report closed rows as closely as possible.
    """
    try:
        at = str(at_state or '').upper().strip()
        if at not in {'AT_CLOSED', 'AT_TP', 'AT_SL'}:
            return '-'
        rr = dict(row or {})
        # First use the canonical /autotrade_closed index.  This catches Bybit
        # Closed-PnL rows that were reconciled/enriched for /autotrade_closed but
        # not stored cleanly in autotrade_trades with the exact setup_id.
        try:
            ix_val = _setup_audit_match_closed_pnl_from_index(rr, pnl_index or {})
            if ix_val is not None:
                return f"{float(ix_val):+.2f}"
        except Exception:
            pass
        uid_i = int(globals().get('AUTOTRADE_OWNER_UID', 0) or uid or 0)
        sid = str(rr.get('setup_id') or rr.get('id') or '').strip()
        setup_ts = float(_setup_audit_row_ts(rr) or 0.0)
        sym_base = _symbol_base(str(rr.get('symbol') or rr.get('market_symbol') or ''))
        side_u = str(rr.get('side') or '').upper().strip()
        pnl_val = None
        n = 0
        with sqlite3.connect(DB_PATH) as conn:
            conn.row_factory = sqlite3.Row
            cur = conn.cursor()
            if sid:
                # v58: setup_id-only matching can attach an older trade to a newer
                # visible setup row.  Sum only rows whose open time is safe for
                # this setup.
                qrows = cur.execute(
                    """
                    SELECT setup_id, symbol, side, opened_ts, closed_ts, COALESCE(pnl_usdt,0) AS pnl, policy_combo_at_open
                    FROM autotrade_trades
                    WHERE uid=? AND setup_id=? AND closed_ts IS NOT NULL
                    """,
                    (uid_i, sid),
                ).fetchall() or []
                vals = []
                for qr in qrows:
                    try:
                        d = dict(qr)
                        if _yver58_setup_audit_trade_match_safe(rr, d, uid=uid_i):
                            vals.append(float(d.get('pnl') or 0.0))
                    except Exception:
                        continue
                if vals:
                    pnl_val = float(sum(vals))
                    n = len(vals)
            if pnl_val is None and setup_ts > 0 and sym_base and side_u in {'BUY', 'SELL'}:
                # Allow a small buffer around the setup entry window so journal rows
                # created a little late still reconcile to the visible setup row.
                start_ts = float(setup_ts) - 30.0 * 60.0
                end_ts = float(setup_ts) + float(max(60, int(_autotrade_entry_window_min()) * 60)) + 30.0 * 60.0
                rows = cur.execute(
                    """
                    SELECT symbol, side, opened_ts, closed_ts, COALESCE(pnl_usdt,0) AS pnl
                    FROM autotrade_trades
                    WHERE uid=? AND closed_ts IS NOT NULL
                      AND UPPER(COALESCE(side,''))=?
                      AND COALESCE(opened_ts,0)>=? AND COALESCE(opened_ts,0)<=?
                    ORDER BY ABS(COALESCE(opened_ts,0)-?) ASC
                    LIMIT 20
                    """,
                    (uid_i, side_u, float(start_ts), float(end_ts), float(setup_ts)),
                ).fetchall() or []
                vals = []
                for r in rows:
                    try:
                        d = dict(r)
                        if _symbol_base(str(d.get('symbol') or '')) == sym_base and _yver58_setup_audit_trade_match_safe(rr, d, uid=uid_i):
                            vals.append(float(d.get('pnl') or 0.0))
                    except Exception:
                        continue
                if vals:
                    pnl_val = float(sum(vals))
                    n = len(vals)
        if pnl_val is None or n <= 0:
            return '-'
        return f"{float(pnl_val):+.2f}"
    except Exception:
        return '-'



def _yver57_policy_at_open_for_setup_row(row: dict, uid: int = 0, at_state: str = '') -> str:
    """Return stored /setup_matrix policy snapshot used by AutoTrade at open.

    /setup_audit Policy/WR are intentionally current matrix values and can change
    after a position has already opened.  ATPol is the immutable open-time policy
    snapshot written to autotrade_trades by the yver48 KEEP-only pre-trade gate.
    """
    try:
        st = str(at_state or '').upper().strip()
        if st not in {'AT_OPEN', 'AT_CLOSED', 'AT_TP', 'AT_SL'}:
            return '-'
        rr = dict(row or {})
        uid_i = int(uid or globals().get('AUTOTRADE_OWNER_UID', 0) or 0)
        sid = str(rr.get('setup_id') or rr.get('id') or '').strip()
        sym = _symbol_base(str(rr.get('symbol') or rr.get('market_symbol') or '')).upper().strip()
        side = str(rr.get('side') or '').upper().strip()
        setup_ts = float(_setup_audit_row_ts(rr) or 0.0)
        vals = []
        with sqlite3.connect(DB_PATH) as conn:
            conn.row_factory = sqlite3.Row
            cur = conn.cursor()
            try:
                cols = [r[1] for r in cur.execute('PRAGMA table_info(autotrade_trades)').fetchall()]
            except Exception:
                cols = []
            if 'policy_at_open' not in cols:
                return 'NO_SNAPSHOT'
            if sid:
                vals = [dict(r) for r in cur.execute(
                    """
                    SELECT policy_at_open, policy_combo_at_open, setup_id, symbol, side, opened_ts
                    FROM autotrade_trades
                    WHERE (?<=0 OR uid=?) AND setup_id=?
                    ORDER BY COALESCE(opened_ts,0) DESC
                    LIMIT 1
                    """,
                    (uid_i, uid_i, sid),
                ).fetchall() or []]
            if not vals and sym and side in {'BUY','SELL'} and setup_ts > 0:
                entry_win = float(max(60, int(_autotrade_entry_window_min()) * 60))
                vals = [dict(r) for r in cur.execute(
                    """
                    SELECT policy_at_open, policy_combo_at_open, setup_id, symbol, side, opened_ts
                    FROM autotrade_trades
                    WHERE (?<=0 OR uid=?)
                      AND UPPER(REPLACE(COALESCE(symbol,''),'USDT',''))=?
                      AND UPPER(COALESCE(side,''))=?
                      AND COALESCE(opened_ts,0)>=?
                      AND COALESCE(opened_ts,0)<=?
                    ORDER BY ABS(COALESCE(opened_ts,0)-?) ASC
                    LIMIT 1
                    """,
                    (uid_i, uid_i, sym, side, setup_ts - 30*60.0, setup_ts + entry_win + 45*60.0, setup_ts),
                ).fetchall() or []]
        if vals:
            # v58: policy snapshot is only meaningful for this setup row if the
            # underlying trade opened inside this setup's AutoTrade entry window.
            try:
                vals = [dict(v or {}) for v in vals if _yver58_setup_audit_trade_match_safe(rr, dict(v or {}), uid=uid_i)]
            except Exception:
                vals = []
        if vals:
            pol = str(vals[0].get('policy_at_open') or '').upper().strip()
            if pol == 'OFF':
                pol = 'DISABLE'
            if pol in {'KEEP','WATCH','TIGHTEN','DISABLE'}:
                return pol
            return 'NO_SNAPSHOT'
    except Exception:
        pass
    return 'NO_SNAPSHOT'

def _setup_audit_text(uid: int, limit: int = 0, hours: int = 24) -> str:
    """Compact setup audit with current Policy lane per setup."""
    limit = max(0, int(limit or 0))
    hours = max(1, min(8760, int(hours or 24)))
    result_horizon = _setup_audit_result_horizon_hours()
    rows = _setup_audit_load_rows(int(uid), hours=hours, limit=limit, dedup=True)
    min_vol_m = _setup_min_volume_floor_usd() / 1e6
    if not rows:
        return (
            f"🧪 <b>Setup Audit</b>\n{HDR}\n"
            f"No stored setup rows above ${min_vol_m:.0f}M volume in the last {hours}h.\n"
            f"This is an analytics-data message only; it does not mean setup generation is blocked. "
            f"Check <code>/email_decision</code>, <code>/why</code>, and <code>/screen</code> for current live scan status.\n\n"
            f"Use <code>/setup_audit h</code> for the guide."
        )

    audit_tf = str(os.environ.get('SETUP_AUDIT_TIMEFRAME', '5m') or '5m').strip().lower() or '5m'
    candles_by_symbol = _setup_audit_preload_ohlcv(rows, hours=result_horizon, timeframe=audit_tf)
    actual_pnl_by_setup = _setup_audit_actual_pnl_by_setup(int(uid), start_ts=float(time.time()) - float(hours) * 3600.0, end_ts=float(time.time()) + 3600.0)
    closed_pnl_index = _setup_audit_closed_pnl_index(rows, uid=int(uid), hours=int(hours))

    table_rows = []
    tp_n = sl_n = nohit_n = open_n = 0
    for r in rows:
        sid = str(r.get('setup_id') or '').strip()
        side = str(r.get('side') or '').upper().strip()
        sym = str(r.get('symbol') or '').upper().strip()
        if sym.endswith('USDT'):
            sym = sym[:-4]
        family_code = _setup_audit_family_code(r)
        actual_pnl = float(actual_pnl_by_setup.get(sid, 0.0) or 0.0)
        ev = _setup_audit_resolve_result(r, horizon_hours=result_horizon, user_id=int(uid), candles_by_symbol=candles_by_symbol, audit_timeframe=audit_tf, actual_pnl_usdt=actual_pnl)
        result = _setup_audit_binary_display_result(r, ev.get('result'), result_horizon)
        if result == 'TP':
            tp_n += 1
        elif result == 'SL':
            sl_n += 1
        elif result == 'NOHIT':
            nohit_n += 1
        else:
            open_n += 1
        sess_row = str(r.get('session') or r.get('source_session') or '-').upper().strip() or '-'
        ts = _setup_audit_row_ts(r)
        try:
            ttxt = datetime.fromtimestamp(float(ts or 0.0), tz=timezone.utc).astimezone(MEL_TZ).strftime('%m-%d %H:%M') if ts > 0 else '-'
        except Exception:
            ttxt = '-'
        try:
            volm = float(r.get('fut_vol_usd') or r.get('volume_usd') or r.get('vol_usd') or 0.0) / 1e6
        except Exception:
            volm = 0.0
        combo_key = _setup_combo_strategy_side_key(family_code, sess_row, r, side)
        policy_label = _setup_audit_policy_label(r, uid=int(uid), session_name=sess_row, side=side)
        at_state = _setup_audit_autotrade_state_label(r, uid=int(uid), session_name=sess_row)
        at_pol = _yver57_policy_at_open_for_setup_row(r, uid=int(uid), at_state=at_state)
        at_why = _setup_audit_autotrade_skip_reason(r, uid=int(uid), policy_label=policy_label, at_state=at_state, session_name=sess_row)
        pnl_txt = _setup_audit_closed_pnl_for_row(r, uid=int(uid), at_state=at_state, pnl_index=closed_pnl_index)
        policy_wr = _setup_audit_policy_wr_label(r, uid=int(uid), session_name=sess_row, side=side)
        table_rows.append([ttxt, sym, side, combo_key, policy_label, policy_wr, at_state, at_pol, at_why, int(float(r.get('conf') or 0.0)), f"{volm:.0f}", pnl_txt, result])

    decided = tp_n + sl_n
    # v56: WR excludes OPEN/unresolved rows.
    wr = (tp_n / decided * 100.0) if decided > 0 else 0.0
    try:
        now_txt = datetime.fromtimestamp(time.time(), tz=timezone.utc).astimezone(MEL_TZ).strftime("%Y-%m-%d %H:%M")
    except Exception:
        now_txt = ''
    win = _setup_audit_window_summary(rows)

    # Ver16: show all rows. send_long_message now chunks <pre> tables safely,
    # so there is no need to hide audit rows for Telegram length limits.
    display_rows = list(table_rows)
    hidden_rows = 0
    table = tabulate(
        display_rows,
        headers=['Time', 'Sym', 'Side', 'Combo', 'Policy', 'WR', 'AT', 'ATPol', 'ATWhy', 'Conf', 'VolM', 'PnL', 'Res'],
        tablefmt='plain',
        colalign=('left', 'left', 'center', 'left', 'center', 'right', 'center', 'center', 'center', 'right', 'right', 'right', 'center'),
    )
    header_lines = [
        "🧪 <b>Setup Audit</b>",
        HDR,
        f"Window: <b>last {hours}h</b> | Unique setups: <b>{len(rows)}</b> | Min vol: <b>${min_vol_m:.0f}M</b>" + (f" | Now: <b>{now_txt}</b>" if now_txt else ""),
        f"Start: <b>{html.escape(str(win.get('start_txt') or '-'))}</b> | End: <b>{html.escape(str(win.get('end_txt') or '-'))}</b>",
        "AT legend: <b>SENT_OLD</b> = setup email was sent but the entry window has expired; <b>WR</b> is the current /setup_matrix lane WR; <b>ATPol</b> is the stored AutoTrade open-time policy snapshot; <b>ATWhy</b> explains the current non-entry reason; <b>PnL</b> shows realised AutoTrade PnL for AT_CLOSED rows. Result view has no expiry: unresolved setups stay OPEN until TP or SL is hit.",
    ]
    return "\n".join(header_lines) + "\n<pre>" + html.escape(table) + "</pre>"




def _setup_open_times_parse_scope(arg: str | None = None) -> tuple[str, float | None, int]:
    """Return (label, start_ts, hours) for /setup_open_times.

    Default is the fixed setup-policy baseline (01 Jun 2026 Melbourne).  Numeric
    arguments are hours; 7d/week and 24h are accepted for quick blackout tuning.
    """
    try:
        a = str(arg or '').strip().lower()
        now_ts = float(time.time())
        if not a or a in {'all', 'overall', 'start', 'baseline', 'since'}:
            st = float(_overall_report_start_ts() or 0.0)
            return (f"from {_overall_report_start_txt()} Melbourne", st, 0)
        if a in {'24', '24h', '1d', 'day', 'today'}:
            return ('last 24h', now_ts - 24.0 * 3600.0, 24)
        if a in {'7d', '7', 'week', 'lastweek', 'last_week'}:
            return ('last 7d', now_ts - 7.0 * 86400.0, 168)
        if a in {'14d', '14', 'fortnight'}:
            return ('last 14d', now_ts - 14.0 * 86400.0, 336)
        m = re.fullmatch(r'(\d+(?:\.\d+)?)(h|hr|hrs|hour|hours|d|day|days)?', a)
        if m:
            val = float(m.group(1))
            unit = str(m.group(2) or 'h').lower()
            hours = int(max(1, min(8760, round(val * 24.0 if unit.startswith('d') else val))))
            if hours >= 24 and hours % 24 == 0:
                label = f"last {hours//24}d"
            else:
                label = f"last {hours}h"
            return (label, now_ts - float(hours) * 3600.0, hours)
    except Exception:
        pass
    try:
        st = float(_overall_report_start_ts() or 0.0)
    except Exception:
        st = 0.0
    return (f"from {_overall_report_start_txt()} Melbourne", st, 0)


