async def setup_combo_policy_catchup_job(context: ContextTypes.DEFAULT_TYPE):
    """One-shot startup catch-up for missed weekly/daily setup-combo policy reviews."""
    try:
        if not bool(globals().get('SETUP_COMBO_POLICY_CATCHUP_ENABLED', True)):
            return
        uid = int(AUTOTRADE_OWNER_UID or 0)
        if uid <= 0:
            try:
                ids = sorted(list(_admin_ids_all()))
                uid = int(ids[0]) if ids else 0
            except Exception:
                uid = 0
        if uid <= 0:
            return
        now_ts = float(time.time())
        # Weekly catch-up only shortly after the missed Sunday 23:00 window.
        try:
            prev_weekly = _setup_combo_previous_policy_review_dt(now_ts)
            prev_weekly_ts = float(prev_weekly.astimezone(timezone.utc).timestamp())
            age_h = (now_ts - prev_weekly_ts) / 3600.0
            if bool(SETUP_COMBO_REVIEW_ENABLED) and 0.0 <= age_h <= float(SETUP_COMBO_WEEKLY_REVIEW_CATCHUP_MAX_HOURS or 8):
                if not _setup_combo_policy_kind_updated_since(int(uid), 'scheduled', prev_weekly_ts - 300.0):
                    res = await to_thread_heavy(
                        _setup_combo_matrix_build,
                        int(uid),
                        _overall_report_effective_hours(max(int(SETUP_COMBO_REVIEW_WINDOW_HOURS), int(SETUP_COMBO_POLICY_MIN_WINDOW_HOURS))),
                        True,
                        True,
                        'scheduled',
                        _overall_report_start_ts(),
                        timeout=240,
                    )
                    try:
                        db_log_setup_pipeline_event(uid, stage='setup_combo_review_catchup', status='ok', session=str(scan_session_name_utc(datetime.now(timezone.utc)) or ''), mode='optimizer', details={
                            'scheduled_for': _setup_combo_format_policy_ts(prev_weekly_ts),
                            'window_hours': int((res or {}).get('window_hours') or _overall_report_effective_hours(max(int(SETUP_COMBO_REVIEW_WINDOW_HOURS), int(SETUP_COMBO_POLICY_MIN_WINDOW_HOURS)))),
                            'baseline_start': _overall_report_start_txt(),
                            'rows': len(list((res or {}).get('rows') or [])),
                            'policy_updated': bool((res or {}).get('policy_updated')),
                        })
                    except Exception:
                        pass
        except Exception as e:
            try:
                db_log_setup_pipeline_event(uid, stage='setup_combo_review_catchup', status='error', session=str(scan_session_name_utc(datetime.now(timezone.utc)) or ''), mode='optimizer', details={'error': f'{type(e).__name__}: {e}'})
            except Exception:
                pass
        # Daily safety catch-up shortly after 10:00 Melbourne. This is intentionally
        # severe-disable only and expires at the next weekly review.
        try:
            prev_daily = _setup_combo_previous_daily_safety_dt(now_ts)
            prev_daily_ts = float(prev_daily.astimezone(timezone.utc).timestamp())
            age_h = (now_ts - prev_daily_ts) / 3600.0
            if bool(SETUP_COMBO_DAILY_SAFETY_ENABLED) and 0.0 <= age_h <= float(SETUP_COMBO_DAILY_SAFETY_CATCHUP_MAX_HOURS or 2.5):
                if not _setup_combo_policy_kind_updated_since(int(uid), 'daily_safety', prev_daily_ts - 300.0):
                    res = await to_thread_heavy(_setup_combo_run_daily_safety_policy, int(uid), _overall_report_start_ts(), timeout=240)
                    try:
                        db_log_setup_pipeline_event(uid, stage='setup_combo_daily_safety_catchup', status='ok' if (res or {}).get('ok') else 'skip', session=str(scan_session_name_utc(datetime.now(timezone.utc)) or ''), mode='optimizer', details={
                            'scheduled_for': _setup_combo_format_policy_ts(prev_daily_ts),
                            'window_hours': int(SETUP_COMBO_DAILY_SAFETY_WINDOW_HOURS),
                            'rows': int((res or {}).get('rows') or 0),
                            'disabled': list((res or {}).get('disabled') or []),
                            'reason': str((res or {}).get('reason') or ''),
                        })
                    except Exception:
                        pass
        except Exception as e:
            try:
                db_log_setup_pipeline_event(uid, stage='setup_combo_daily_safety_catchup', status='error', session=str(scan_session_name_utc(datetime.now(timezone.utc)) or ''), mode='optimizer', details={'error': f'{type(e).__name__}: {e}'})
            except Exception:
                pass
    except Exception:
        pass



# ================= NON-BLOCKING ADMIN REPORT RUNNER (yver145) =================
_ADMIN_REPORT_BG_RUNNING: dict[str, float] = {}
_ADMIN_REPORT_BG_LOCK = threading.Lock()


def _admin_report_cache_get_with_age(cache_key: str, ttl_sec: float | None = None) -> tuple[str, float | None]:
    """Return cached report text and age seconds. TTL=None returns any cached value."""
    try:
        rec = _CACHE.get(str(cache_key or ''))
        if not rec:
            return '', None
        ts, obj = rec
        age = max(0.0, float(time.time()) - float(ts or 0.0))
        if ttl_sec is not None and float(ttl_sec) > 0 and age > float(ttl_sec):
            return '', age
        txt = str(obj or '')
        return (txt if txt.strip() else ''), age
    except Exception:
        return '', None


def _admin_report_age_text(age: float | None) -> str:
    try:
        if age is None:
            return '-'
        age_f = max(0.0, float(age))
        if age_f < 90:
            return f"{int(age_f)}s"
        if age_f < 7200:
            return f"{age_f/60.0:.0f}m"
        return f"{age_f/3600.0:.1f}h"
    except Exception:
        return '-'


def _admin_report_bg_try_start(cache_key: str) -> bool:
    try:
        key = str(cache_key or '')
        now_ts = float(time.time())
        stale_sec = max(120.0, float(os.getenv('ADMIN_REPORT_RUNNING_STALE_SEC', '900') or 900))
        with _ADMIN_REPORT_BG_LOCK:
            running_ts = float(_ADMIN_REPORT_BG_RUNNING.get(key) or 0.0)
            if running_ts > 0 and (now_ts - running_ts) < stale_sec:
                return False
            # If a previous worker timed out, crashed, or got lost after Render sleep,
            # do not keep saying "already running" forever. Replace stale marker.
            _ADMIN_REPORT_BG_RUNNING[key] = now_ts
            return True
    except Exception:
        return False


def _admin_report_bg_done(cache_key: str) -> None:
    try:
        with _ADMIN_REPORT_BG_LOCK:
            _ADMIN_REPORT_BG_RUNNING.pop(str(cache_key or ''), None)
    except Exception:
        pass


async def _admin_report_background_refresh(
    update: Update,
    title: str,
    cache_key: str,
    fn,
    args: tuple = (),
    kwargs: dict | None = None,
    parse_mode=None,
    background_timeout: int | None = 600,
    post_result: bool = True,
):
    """Build a heavy admin report outside the Telegram command timeout and post it when ready."""
    kwargs = dict(kwargs or {})
    try:
        text = await to_thread_bg(fn, *(args or ()), timeout=background_timeout, **kwargs)
        text = str(text or '').strip() or 'No data found.'
        try:
            cache_set(str(cache_key or ''), text)
        except Exception:
            pass
        if post_result:
            header = f"✅ <b>Fresh result ready:</b> {html.escape(str(title or 'report'))}\n{SEP}\n"
            await send_long_message(update, header + text, parse_mode=(parse_mode or ParseMode.HTML), disable_web_page_preview=True)
    except Exception as e:
        try:
            await update.message.reply_text(
                f"⚠️ {str(title or 'Report')} background refresh failed: {type(e).__name__}: {html.escape(str(e))}",
                parse_mode=ParseMode.HTML,
                disable_web_page_preview=True,
            )
        except Exception:
            pass
    finally:
        _admin_report_bg_done(str(cache_key or ''))


async def _send_cached_or_queue_admin_report(
    update: Update,
    title: str,
    cache_key: str,
    fn,
    args: tuple = (),
    kwargs: dict | None = None,
    parse_mode=None,
    fresh_ttl: int = 60,
    stale_ttl: int = 12 * 3600,
    background_timeout: int | None = 600,
    force_refresh: bool = True,
) -> None:
    """Instant response for heavy admin commands.

    Behaviour:
    - fresh cache -> send immediately, no Telegram timeout;
    - stale cache -> send immediately and queue a background rebuild;
    - no cache -> acknowledge immediately and post the fresh result later.
    """
    cache_key = str(cache_key or '')
    title_s = str(title or 'report').strip() or 'report'
    pm = parse_mode or ParseMode.HTML

    fresh, age = _admin_report_cache_get_with_age(cache_key, fresh_ttl)
    if fresh:
        await send_long_message(update, fresh, parse_mode=pm, disable_web_page_preview=True)
        return

    stale, stale_age = _admin_report_cache_get_with_age(cache_key, stale_ttl)
    started = False
    if force_refresh:
        started = _admin_report_bg_try_start(cache_key)
        if started:
            _safe_create_task(
                _admin_report_background_refresh(
                    update,
                    title_s,
                    cache_key,
                    fn,
                    args=tuple(args or ()),
                    kwargs=dict(kwargs or {}),
                    parse_mode=pm,
                    background_timeout=background_timeout,
                    post_result=True,
                ),
                label=f"admin-report-refresh:{cache_key}",
            )

    if stale:
        note = (
            f"⚡ <b>Latest cached result:</b> {html.escape(title_s)} "
            f"(age {html.escape(_admin_report_age_text(stale_age))}). "
            f"Fresh rebuild {'started in background' if started else 'already running in background'}.\n{SEP}\n"
        )
        await send_long_message(update, note + stale, parse_mode=pm, disable_web_page_preview=True)
        return

    await update.message.reply_text(
        f"⏳ {title_s} is heavy. No cached result yet. Fresh rebuild "
        f"{'started in background' if started else 'is already running in background'}; I will post it here when ready.",
        parse_mode=None,
        disable_web_page_preview=True,
    )

