async def setup_audit_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    uid = int(update.effective_user.id)
    if not is_admin_user(uid):
        await update.message.reply_text("⛔ Admin only.")
        return
    limit = 0
    hours = 24
    try:
        args = [str(a).strip() for a in (context.args or []) if str(a).strip()]
        if args and args[0].lower() in {'h', 'help', '?', 'guide'}:
            await send_long_message(update, _setup_audit_help_text(), parse_mode=ParseMode.HTML, disable_web_page_preview=True)
            return
        if args and args[0].lower() in {'overall', 'alltime', 'all-time'}:
            await _send_cached_or_queue_admin_report(
                update,
                "/setup_audit overall",
                f"admin:bg:v58:setup_audit_overall:{int(AUTOTRADE_OWNER_UID or uid)}",
                _setup_audit_overall_text,
                args=(int(AUTOTRADE_OWNER_UID or uid),),
                parse_mode=ParseMode.HTML,
                fresh_ttl=120,
                stale_ttl=12 * 3600,
                background_timeout=900,
            )
            return
        if args and args[0].lower() in {'compare', 'reconcile', 'traded', 'autotrade'}:
            cmp_hours = 24
            try:
                if len(args) >= 2 and re.fullmatch(r'\d+(\.\d+)?', str(args[1])):
                    cmp_hours = int(float(args[1]))
            except Exception:
                cmp_hours = 24
            await _send_cached_or_queue_admin_report(
                update,
                f"/setup_audit compare {int(cmp_hours)}",
                f"admin:bg:v58:setup_audit_compare:{int(AUTOTRADE_OWNER_UID or uid)}:{int(cmp_hours)}",
                _setup_audit_compare_text,
                args=(int(AUTOTRADE_OWNER_UID or uid), int(cmp_hours)),
                parse_mode=ParseMode.HTML,
                fresh_ttl=60,
                stale_ttl=12 * 3600,
                background_timeout=900,
            )
            return
        # Primary/simple usage: /setup_audit 1 means last 1 hour, not 1 row.
        # Optional advanced usage: /setup_audit rows 20 24 OR /setup_audit limit 20 24.
        if len(args) == 1:
            if args[0].isdigit() or re.fullmatch(r'\d+(\.\d+)?', args[0]):
                hours = int(float(args[0]))
            elif args[0].lower() in {'all', 'unlimited', 'full'}:
                limit = 0
        elif len(args) >= 2:
            if args[0].lower() in {'rows', 'row', 'limit', 'n'}:
                limit = int(float(args[1]))
                if len(args) >= 3:
                    hours = int(float(args[2]))
            else:
                # Backward compatible: /setup_audit <limit> <hours>
                limit = 0 if args[0].lower() in {'all', 'unlimited', 'full', '0'} else int(float(args[0]))
                hours = int(float(args[1]))
    except Exception:
        limit = 0
        hours = 24
    await _send_cached_or_queue_admin_report(
        update,
        f"/setup_audit {int(hours)}",
        f"admin:bg:v58:setup_audit:{int(AUTOTRADE_OWNER_UID or uid)}:{int(limit)}:{int(hours)}",
        _setup_audit_text,
        args=(int(AUTOTRADE_OWNER_UID or uid), int(limit), int(hours)),
        parse_mode=ParseMode.HTML,
        fresh_ttl=45,
        stale_ttl=6 * 3600,
        background_timeout=600,
    )



# yver76: one reporting/policy evidence baseline for the Setup Audit / Reports section.
# Reports and setup-policy evidence use the fixed 1 Jun baseline so /setup_audit_overall,
# /setup_matrix, /setup_matrix policy, /setup_matrix deep, /setup_matrix safety and
# /setup_deep_analysis all read the same historical setup evidence. Trading/live scans
# still use their own normal runtime gates unless a scheduled/manual policy refresh writes policy rows.
OVERALL_REPORT_START_LOCAL_YEAR = 2026
OVERALL_REPORT_START_LOCAL_MONTH = 6
OVERALL_REPORT_START_LOCAL_DAY = 1


def _overall_report_start_local_dt() -> datetime:
    try:
        return datetime(
            int(OVERALL_REPORT_START_LOCAL_YEAR),
            int(OVERALL_REPORT_START_LOCAL_MONTH),
            int(OVERALL_REPORT_START_LOCAL_DAY),
            0,
            0,
            0,
            tzinfo=MEL_TZ,
        )
    except Exception:
        return datetime(2026, 6, 1, 0, 0, 0, tzinfo=timezone.utc).astimezone(MEL_TZ)


def _overall_report_start_ts() -> float:
    try:
        return float(_overall_report_start_local_dt().astimezone(timezone.utc).timestamp())
    except Exception:
        return 0.0


def _overall_report_start_txt() -> str:
    try:
        return _overall_report_start_local_dt().strftime('%Y-%m-%d %H:%M')
    except Exception:
        return '2026-06-01 00:00'


def _overall_report_hours_since_start(now_ts: float | None = None) -> int:
    try:
        end_ts = float(now_ts if now_ts is not None else time.time())
        start_ts = float(_overall_report_start_ts() or 0.0)
        if start_ts <= 0 or end_ts <= start_ts:
            return 24
        return max(1, int(math.ceil((end_ts - start_ts) / 3600.0)))
    except Exception:
        return 24


def _overall_report_effective_hours(requested_hours: int | float | None = None, now_ts: float | None = None) -> int:
    """Return an hour value large enough to cover the fixed 1 Jun baseline.

    Existing matrix/deep/safety code is hours-based. This helper lets those commands
    keep their old signatures while ensuring the practical data start is 2026-06-01
    when a command belongs to the Setup Audit / Reports evidence section.
    """
    try:
        requested = int(float(requested_hours or 0))
    except Exception:
        requested = 0
    try:
        baseline = int(_overall_report_hours_since_start(now_ts))
    except Exception:
        baseline = 24
    return max(1, min(8760, max(requested, baseline)))


def _overall_report_window_label(requested_hours: int | float | None = None) -> str:
    try:
        eff = _overall_report_effective_hours(requested_hours)
        req = int(float(requested_hours or 0))
        suffix = f" | effective {eff}h" if req and eff != req else f" | {eff}h"
        return f"from {_overall_report_start_txt()} Melbourne{suffix}"
    except Exception:
        return f"from {_overall_report_start_txt()} Melbourne"


def _overall_report_source_rows(uid: int, *, start_ts: float | None = None, limit: int = 0, dedup: bool = True) -> tuple[list[dict], str]:
    """Load the same historical setup rows used by /setup_audit_overall.

    First use the executable/actionable table. If that table starts after the fixed
    baseline, fall back to EXECUTABLE+GENERATED so matrix/policy/deep reports do not
    silently look like a last-24h report.
    """
    rows: list[dict] = []
    source_label = str(globals().get('SETUP_AUDIT_SOURCE_MODE', 'EXECUTABLE')).upper()
    try:
        start = float(start_ts if start_ts is not None else (_overall_report_start_ts() or 0.0))
    except Exception:
        start = 0.0
    try:
        rows = _setup_audit_load_rows(int(uid), hours=None, limit=int(limit or 0), dedup=bool(dedup), start_ts=start, apply_final_quality_gate=False)
        row_start = min([_setup_audit_row_ts(r) for r in rows if _setup_audit_row_ts(r) > 0] or [0.0]) if rows else 0.0
        if start > 0 and (row_start <= 0 or row_start > start + 36 * 3600):
            hist_rows = _setup_audit_load_rows(int(uid), hours=None, limit=int(limit or 0), dedup=bool(dedup), start_ts=start, apply_final_quality_gate=False, source_mode_override='ALL')
            if len(hist_rows or []) > len(rows or []):
                rows = list(hist_rows or [])
                source_label = 'EXECUTABLE+GENERATED'
    except Exception:
        rows = []
    return rows, source_label

def _setup_audit_overall_text(uid: int) -> str:
    """Overall family-level setup audit summary from the fixed 1 Jun reporting baseline."""
    _overall_start_ts = float(_overall_report_start_ts() or 0.0)
    _overall_source_label = str(globals().get('SETUP_AUDIT_SOURCE_MODE', 'EXECUTABLE')).upper()
    # Historical overall must not re-apply today's final quality/policy gate to old executable rows.
    # The executable table already represents what was executable at the time.
    rows = _setup_audit_load_rows(int(uid), hours=None, limit=0, dedup=True, start_ts=_overall_start_ts, apply_final_quality_gate=False)
    # If the current executable table does not contain the older baseline period, use the same
    # deduped setup-audit path against the historical generated table so the 1 Jun window is real.
    try:
        if rows:
            _row_start = min([_setup_audit_row_ts(r) for r in rows if _setup_audit_row_ts(r) > 0] or [0.0])
        else:
            _row_start = 0.0
        if _overall_start_ts > 0 and (_row_start <= 0 or _row_start > _overall_start_ts + 36 * 3600):
            _hist_rows = _setup_audit_load_rows(int(uid), hours=None, limit=0, dedup=True, start_ts=_overall_start_ts, apply_final_quality_gate=False, source_mode_override='ALL')
            if len(_hist_rows or []) > len(rows or []):
                rows = list(_hist_rows or [])
                _overall_source_label = 'EXECUTABLE+GENERATED'
    except Exception:
        pass
    min_vol_m = _setup_min_volume_floor_usd() / 1e6
    # yver60: keep reporting the full Family-Session-NOR/REV-BUY/SELL universe
    # even when no setup has fired yet; zeros are useful for clean forward tests.
    result_horizon = _setup_audit_result_horizon_hours()
    audit_tf = str(os.environ.get('SETUP_AUDIT_OVERALL_TIMEFRAME', os.environ.get('SETUP_AUDIT_TIMEFRAME', '15m')) or '15m').strip().lower() or '15m'
    # Overall uses the no-expiry setup audit. Force grouped
    # historical candles by symbol so old setups are checked against their real
    # post-setup path instead of the current ticker only.
    candles_by_symbol = _setup_audit_preload_ohlcv(rows, hours=result_horizon, timeframe=audit_tf)
    fam_stats: dict[tuple[str, str, str, str], dict] = {}
    fam_codes_seen: set[str] = set()
    try:
        for fam_u, sess_u, strat_u, side_u, _combo_u in _setup_combo_full_universe():
            fam_codes_seen.add(fam_u)
            fam_stats.setdefault((fam_u, sess_u, strat_u, side_u), {'family': fam_u, 'session': sess_u, 'strategy': strat_u, 'side': side_u, 'total': 0, 'tp': 0, 'sl': 0, 'nohit': 0, 'open': 0})
    except Exception:
        pass
    for r in rows:
        fam = _setup_audit_family_code(r)
        fam_codes_seen.add(fam)
        sess_row = str(r.get('session') or r.get('source_session') or '-').upper().strip() or '-'
        sid = str(r.get('setup_id') or '').strip()
        ev = _setup_audit_resolve_result(r, horizon_hours=result_horizon, user_id=int(uid), candles_by_symbol=candles_by_symbol, audit_timeframe=audit_tf, actual_pnl_usdt=0.0)
        result = _setup_audit_binary_display_result(r, ev.get('result'), result_horizon)
        strat = _setup_strategy_short_label(r)
        side_row = _setup_side_suffix(value=str(r.get('side') or ''))
        item = fam_stats.setdefault((fam, sess_row, strat, side_row), {'family': fam, 'session': sess_row, 'strategy': strat, 'side': side_row, 'total': 0, 'tp': 0, 'sl': 0, 'nohit': 0, 'open': 0})
        item['total'] += 1
        item['tp'] += 1 if result == 'TP' else 0
        item['sl'] += 1 if result == 'SL' else 0
        item['nohit'] += 1 if result == 'NOHIT' else 0
        item['open'] += 1 if result == 'OPEN' else 0

    table_rows = []
    total_setups = total_tp = total_sl = total_nohit = total_open = 0
    for (_fam_key, _sess_key, _strat_key, _side_key), st in sorted(fam_stats.items(), key=lambda kv: (int(str(kv[1].get('family') or 'F99')[1:]) if re.fullmatch(r'F\d+', str(kv[1].get('family') or '')) else 99, ['ASIA','LON','NY'].index(str(kv[1].get('session') or '').upper()) if str(kv[1].get('session') or '').upper() in ['ASIA','LON','NY'] else 99, 0 if str(kv[1].get('strategy') or 'NOR').upper() == 'NOR' else 1, 0 if str(kv[1].get('side') or 'BUY').upper() == 'BUY' else 1)):
        fam = str(st.get('family') or _fam_key or '-')
        sess_row = str(st.get('session') or _sess_key or '-')
        strat_row = str(st.get('strategy') or _strat_key or '-')
        side_row = str(st.get('side') or _side_key or 'BOTH')
        total = int(st.get('total') or 0)
        tp = int(st.get('tp') or 0)
        sl = int(st.get('sl') or 0)
        nohit = int(st.get('nohit') or 0)
        op = int(st.get('open') or 0)
        decided = tp + sl
        # v56: setup WR excludes OPEN/unresolved rows.
        wr = (tp / decided * 100.0) if decided > 0 else 0.0
        total_setups += total
        total_tp += tp
        total_sl += sl
        total_nohit += nohit
        total_open += op
        combo_key = _setup_combo_strategy_side_key(fam, sess_row, strat_row, side_row)
        table_rows.append([combo_key, total, tp, sl, op, f"{wr:.1f}%"])
    decided_total = total_tp + total_sl
    # yver56: WR is TP/(TP+SL); OPEN/unresolved rows are excluded until TP or SL.
    wr_total = (total_tp / decided_total * 100.0) if decided_total > 0 else 0.0
    win = _setup_audit_window_summary(rows)
    dur_days = float(win.get('duration_days') or 0.0)
    avg_daily = float(win.get('avg_daily') or 0.0)
    try:
        keep_candidates = [r for r in table_rows if str(r[5]).replace('%','') and float(str(r[5]).replace('%','') or 0.0) >= SETUP_COMBO_POLICY_KEEP_WR and int(r[2]) + int(r[3]) >= SETUP_COMBO_POLICY_MIN_DECIDED_DAILY]
        weak_candidates = [r for r in table_rows if str(r[5]).replace('%','') and float(str(r[5]).replace('%','') or 0.0) < SETUP_COMBO_POLICY_DISABLE_WR and int(r[2]) + int(r[3]) >= SETUP_COMBO_POLICY_MIN_DECIDED_DAILY]
        keep_txt = ', '.join([str(r[0]) for r in keep_candidates[:5]]) or '-'
        weak_txt = ', '.join([str(r[0]) for r in weak_candidates[:5]]) or '-'
    except Exception:
        keep_txt, weak_txt = '-', '-'
    try:
        pol_lookup = _setup_combo_enforceable_policy_lookup(int(uid))
        pol_disabled = sorted([k for k, v in pol_lookup.items() if str((v or {}).get('status') or '').upper() in {'DISABLE','BLOCK','PAUSE','OFF'} or int((v or {}).get('enabled') or 0) == 0])
        pol_txt = ', '.join(pol_disabled[:8]) if pol_disabled else '-'
    except Exception:
        pol_txt = '-'
    header = [
        "📊 <b>Setup Audit Overall</b>",
        HDR,
        f"Families: <b>{len(fam_codes_seen or [])}</b> | Family/session/strategy/side rows: <b>{len(fam_stats)}</b> | Unique setups: <b>{total_setups}</b> | TP: <b>{total_tp}</b> | SL: <b>{total_sl}</b> | OPEN: <b>{total_open}</b> | WR: <b>{wr_total:.1f}%</b>",
        f"Window: <b>from {_overall_report_start_txt()} Melbourne</b>",
        f"Data start: <b>{html.escape(str(win.get('start_txt') or '-'))}</b> | Data end: <b>{html.escape(str(win.get('end_txt') or '-'))}</b>",
        f"Duration from 1 Jun: <b>{max(0.0, (float(time.time()) - float(_overall_report_start_ts() or time.time())) / 86400.0):.1f} days</b> | Avg generated: <b>{(float(total_setups) / max(1.0/24.0, (float(time.time()) - float(_overall_report_start_ts() or time.time())) / 86400.0)):.1f}/day</b> | Evaluation: <b>{_setup_audit_result_horizon_label(result_horizon)}</b> | TF: <b>{html.escape(audit_tf)}</b>",
        f"Min vol: <b>${min_vol_m:.0f}M</b> | Source: post-setup path; rows={html.escape(str(_overall_source_label or 'EXECUTABLE'))} lane.",
        f"Quick read: strongest now = <b>{html.escape(keep_txt)}</b> | weakest now = <b>{html.escape(weak_txt)}</b>.",
        f"Current live disabled policy combos: <b>{html.escape(pol_txt)}</b>.",
        html.escape(_setup_edge_guard_snapshot_text(int(uid))),
        "For the weekly DB edge review, use <code>/setup_matrix 168</code>. <code>/setup_matrix 24</code> is diagnostic only. Live policy is officially updated by the scheduled Sunday 23:00 Melbourne review; daily 10:00 safety can add temporary severe-disable rows only.",
        "OPEN = unresolved/not hit yet. Setups have no due date. WR = TP/(TP+SL), excluding OPEN.",
    ]
    table = tabulate(
        table_rows,
        headers=['Combo', 'Set', 'TP', 'SL', 'Open', 'WR'],
        tablefmt='plain',
        colalign=('left', 'right', 'right', 'right', 'right', 'right'),
    )
    return "\n".join(header) + "\n<pre>" + html.escape(table) + "</pre>"



# yver113: /setup_audit_keep_watch must be an instant admin summary, not a
# full historical OHLCV re-evaluation.  The full audit commands remain available
# for deep recalculation; this compact summary uses cached audit decisions and
# cached price moves only, then caches the rendered text for a short TTL.
_SETUP_AUDIT_KEEP_WATCH_SUMMARY_CACHE = {}
SETUP_AUDIT_KEEP_WATCH_SUMMARY_CACHE_SEC = int(os.environ.get("SETUP_AUDIT_KEEP_WATCH_SUMMARY_CACHE_SEC", "300") or 300)

def _setup_audit_keep_watch_fast_result_label(row: dict, horizon_hours: int) -> str:
    try:
        sid = str((row or {}).get('setup_id') or '').strip()
        if sid:
            try:
                cached = _setup_audit_cached_result(sid, int(horizon_hours or 0), allow_open_fresh_sec=900) or {}
                lab = _setup_audit_result_label((cached or {}).get('result'))
                if lab in {'TP', 'SL', 'NOHIT', 'OPEN'}:
                    return _setup_audit_binary_display_result(row or {}, lab, int(horizon_hours or 0))
            except Exception:
                pass
        try:
            fast = str(_setup_audit_result_from_cached_price_moves(row or {}, int(horizon_hours or 0)) or '').upper().strip()
            if fast in {'WIN', 'TP'}:
                lab = 'TP'
            elif fast in {'LOSE', 'LOSS', 'SL'}:
                lab = 'SL'
            else:
                lab = 'OPEN'
            return _setup_audit_binary_display_result(row or {}, lab, int(horizon_hours or 0))
        except Exception:
            pass
    except Exception:
        pass
    return _setup_audit_binary_display_result(row or {}, 'OPEN', int(horizon_hours or 0))


def _setup_audit_keep_watch_summary_text(uid: int) -> str:
    """Multi-window totals for current KEEP + WATCH policy lanes only.

    yver126: render as a readable table with Last 24h / Last 7d / Last 14d /
    Overall-from-database rows.  WR is TP/(TP+SL); OPEN means unresolved/not hit yet and is excluded from WR, matching the setup-audit WR basis used elsewhere.
    """
    try:
        owner_uid = int(globals().get('AUTOTRADE_OWNER_UID', 0) or 0)
        uid_i = int(owner_uid or uid or 0)
    except Exception:
        uid_i = int(uid or 0)

    try:
        cache_key = f"keep_watch_summary:v58::{uid_i}::{int(time.time() // max(60, int(globals().get('SETUP_AUDIT_KEEP_WATCH_SUMMARY_CACHE_SEC', 300) or 300)))}"
        cache = globals().get('_SETUP_AUDIT_KEEP_WATCH_SUMMARY_CACHE', {}) or {}
        cached = cache.get(cache_key) if isinstance(cache, dict) else None
        if cached and (float(time.time()) - float(cached.get('ts') or 0.0)) <= max(30, int(globals().get('SETUP_AUDIT_KEEP_WATCH_SUMMARY_CACHE_SEC', 300) or 300)):
            return str(cached.get('text') or '')
    except Exception:
        cache_key = ''

    allowed_combos: set[str] = set()
    keep_combos: set[str] = set()
    watch_combos: set[str] = set()
    try:
        lane_sets = _setup_matrix_policy_current_lane_sets(uid_i)
        keep_combos = set(lane_sets.get('keep') or set())
        watch_combos = set(lane_sets.get('watch') or set()) | set(lane_sets.get('tighten') or set())
        allowed_combos = set(keep_combos) | set(watch_combos)
    except Exception:
        allowed_combos = set()
        keep_combos = set()
        watch_combos = set()

    try:
        # yver126: multi-window summary must use the full available historical
        # setup database.  _overall_report_source_rows(start_ts=0) can return only
        # the short executable table, which made Last 24h / 7d / 14d / Overall look
        # almost identical.  Use the generated+executable source directly, then
        # filter by the current KEEP/WATCH policy lanes below.
        rows = _setup_audit_load_rows(int(uid_i), hours=None, limit=0, dedup=True, start_ts=0.0, apply_final_quality_gate=False, source_mode_override='ALL')
        source_label = 'EXECUTABLE+GENERATED'
        if not rows:
            rows, source_label = _overall_report_source_rows(uid_i, start_ts=0.0, limit=0, dedup=True)
    except Exception:
        rows, source_label = [], 'EXECUTABLE'

    result_horizon = _setup_audit_result_horizon_hours()
    audit_tf = str(os.environ.get('SETUP_AUDIT_OVERALL_TIMEFRAME', os.environ.get('SETUP_AUDIT_TIMEFRAME', '15m')) or '15m').strip().lower() or '15m'
    now_ts = float(time.time())

    def _row_combo_u(r: dict) -> str:
        try:
            fam = _setup_audit_family_code(r)
            sess_row = str(r.get('session') or r.get('source_session') or '-').upper().strip() or '-'
            strat = _setup_strategy_short_label(r)
            side_row = _setup_side_suffix(value=str(r.get('side') or ''))
            return str(_setup_combo_strategy_side_key(fam, sess_row, strat, side_row) or '').upper().strip()
        except Exception:
            return ''

    # Precompute just once so every window uses exactly the same policy/result logic.
    enriched_rows: list[tuple[float, str, str]] = []
    matched_all_for_dates: list[dict] = []
    for r in list(rows or []):
        try:
            combo_u = _row_combo_u(r)
            if combo_u not in allowed_combos:
                continue
            ts = float(_setup_audit_row_ts(r) or 0.0)
            res = _setup_audit_keep_watch_fast_result_label(r, result_horizon)
            enriched_rows.append((ts, combo_u, res))
            matched_all_for_dates.append(r)
        except Exception:
            continue

    def _stats_for_window(start_ts: float | None = None) -> dict:
        keep_hit: set[str] = set()
        watch_hit: set[str] = set()
        set_n = tp = sl = nh = op = 0
        for ts, combo_u, res in enriched_rows:
            try:
                if start_ts is not None and float(ts or 0.0) > 0 and float(ts) < float(start_ts):
                    continue
                if start_ts is not None and float(ts or 0.0) <= 0:
                    continue
                if combo_u in keep_combos:
                    keep_hit.add(combo_u)
                elif combo_u in watch_combos:
                    watch_hit.add(combo_u)
                set_n += 1
                if res == 'TP':
                    tp += 1
                elif res == 'SL':
                    sl += 1
                elif res == 'NOHIT':
                    nh += 1
                else:
                    op += 1
            except Exception:
                continue
        dec = tp + sl
        wr = (tp / dec * 100.0) if dec > 0 else 0.0
        return {
            # yver142: Keep/Watch are policy-lane totals, not just lanes touched
            # inside this specific result window.  UsedK/UsedW preserves the old
            # "touched in window" count separately, so the policy counts match the
            # header and the setup/result metrics remain window-specific.
            'keep': len(keep_combos),
            'watch': len(watch_combos),
            'used_keep': len(keep_hit),
            'used_watch': len(watch_hit),
            'set': set_n,
            'tp': tp,
            'sl': sl,
            'nh': nh,
            'open': op,
            'wr': wr,
        }

    windows = [
        ('Last 24h', now_ts - 24 * 3600),
        ('Last 7d', now_ts - 7 * 86400),
        ('Last 14d', now_ts - 14 * 86400),
        ('Overall', None),
    ]
    table_rows = []
    for label, start_ts in windows:
        st = _stats_for_window(start_ts)
        table_rows.append([
            label,
            st['keep'],
            st['watch'],
            st['used_keep'],
            st['used_watch'],
            st['set'],
            st['tp'],
            st['sl'],
            st['open'],
            f"{st['wr']:.1f}%",
        ])

    try:
        win = _setup_audit_window_summary(matched_all_for_dates)
        data_start_txt = str(win.get('start_txt') or '-')
        data_end_txt = str(win.get('end_txt') or '-')
    except Exception:
        data_start_txt = data_end_txt = '-'

    table = tabulate(
        table_rows,
        headers=['Window', 'Keep', 'Watch', 'UsedK', 'UsedW', 'Set', 'TP', 'SL', 'Open', 'WR'],
        tablefmt='plain',
        colalign=('left', 'right', 'right', 'right', 'right', 'right', 'right', 'right', 'right', 'right'),
    )
    lines = [
        "📊 <b>Setup KEEP + WATCH Summary</b>",
        HDR,
        "Policy source: <b>/setup_matrix policy KEEP + WATCH lanes</b>",
        f"Current policy combos: <b>{len(allowed_combos)}</b> (KEEP: <b>{len(keep_combos)}</b> | WATCH: <b>{len(watch_combos)}</b>)",
        f"Data start: <b>{html.escape(data_start_txt)}</b> | Data end: <b>{html.escape(data_end_txt)}</b>",
        f"Source: <b>{html.escape(str(source_label or 'EXECUTABLE'))}</b> | Evaluation: <b>{_setup_audit_result_horizon_label(result_horizon)}</b> | TF: <b>{html.escape(audit_tf)}</b>",
        "Keep/Watch columns = <b>current policy lane totals</b>; UsedK/UsedW = policy lanes that actually had setup rows in that window.",
        "WR basis: <b>TP/(TP+SL)</b>; OPEN means not hit yet and is excluded from WR. Setups have <b>no due date</b>.",
        "Overall row: <b>from start of available setup database</b>.",
        HDR,
        "<pre>" + html.escape(table) + "</pre>",
    ]
    if not allowed_combos:
        lines.append("No active KEEP/WATCH policy lanes found. Run <code>/setup_matrix policy</code> to refresh policy first.")
    elif not enriched_rows:
        lines.append("No historical setup rows matched the current KEEP/WATCH lanes yet.")
    txt = "\n".join(lines)
    try:
        if cache_key:
            _SETUP_AUDIT_KEEP_WATCH_SUMMARY_CACHE[cache_key] = {'ts': float(time.time()), 'text': txt}
    except Exception:
        pass
    return txt

