async def setups_log_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/setups_log [n] [screen|email|all] — view recently generated setups."""
    uid = update.effective_user.id
    user = get_user(uid)
    if not has_active_access(uid, user):
        await update.message.reply_text("⛔️ Trial finished. 👉 /billing")
        return

    n = 30
    src = "all"
    if context.args:
        if context.args[0].isdigit():
            n = max(1, min(200, int(context.args[0])))
            if len(context.args) > 1:
                src = str(context.args[1]).strip().lower()
        else:
            src = str(context.args[0]).strip().lower()
            if len(context.args) > 1 and context.args[1].isdigit():
                n = max(1, min(200, int(context.args[1])))

    if src not in ("all", "screen", "email"):
        src = "all"

    try:
        with sqlite3.connect(DB_PATH) as con:
            con.row_factory = sqlite3.Row
            cur = con.cursor()
            if src == "all":
                cur.execute(
                    """SELECT created_ts, source, session, setup_id, symbol, side, conf
                       FROM generated_setups
                       WHERE user_id=?
                       ORDER BY created_ts DESC
                       LIMIT ?""",
                    (int(uid), int(n)),
                )
            else:
                cur.execute(
                    """SELECT created_ts, source, session, setup_id, symbol, side, conf
                       FROM generated_setups
                       WHERE user_id=? AND source=?
                       ORDER BY created_ts DESC
                       LIMIT ?""",
                    (int(uid), str(src), int(n)),
                )
            rows = cur.fetchall() or []
    except Exception as e:
        await update.message.reply_text(f"❌ setups_log error: {e}")
        return

    if not rows:
        await update.message.reply_text("📦 Setups Log\n\nNo rows yet.")
        return

    lines = ["📦 Setups Log", HDR, f"Showing last {len(rows)} ({src})", ""]
    for r in rows:
        try:
            ts = float(r["created_ts"])
            dt = datetime.fromtimestamp(ts, timezone.utc).strftime("%m-%d %H:%MZ")
        except Exception:
            dt = "?"
        lines.append(
            f"{dt} | {str(r['source']).upper():5s} | {str(r['session']):8.8s} | {str(r['setup_id'])} | {str(r['side']).upper():4s} {str(r['symbol']).upper():10s} | {int(r['conf'] or 0)}"
        )

    await send_long_message(update, "\n".join(lines), parse_mode=None, disable_web_page_preview=True)


async def admin_reset_signal_reports_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/admin_reset_signal_reports — hard reset all report-related tables to empty/zero."""
    if not _is_admin(update):
        await update.message.reply_text("⛔️ Admin only.")
        return

    try:
        async with DB_FILE_LOCK:
            with sqlite3.connect(DB_PATH) as con:
                c = con.cursor()

                # Clear live tables used by /signal_report & /signal_report_overall + correlation log
                for t in ("signals", "emailed_setups", "generated_setups"):
                    try:
                        c.execute(f"DELETE FROM {t}")
                    except Exception:
                        pass

                # Outcomes table name can vary across builds
                try:
                    c.execute("SELECT name FROM sqlite_master WHERE type='table' AND name IN ('signal_outcomes','outcomes')")
                    row = c.fetchone()
                    if row and row[0]:
                        try:
                            c.execute(f"DELETE FROM {row[0]}")
                        except Exception:
                            pass
                except Exception:
                    pass

                # Reset daily counters that affect totals
                for t in ("email_daily", "risk_daily", "setup_counter", "emailed_symbols"):
                    try:
                        c.execute(f"DELETE FROM {t}")
                    except Exception:
                        pass

                con.commit()

        await update.message.reply_text("✅ Reports reset: all totals are now 0 and tables cleared.")
    except Exception as e:
        await update.message.reply_text(f"❌ admin_reset_signal_reports failed: {e}")


def _signal_report_overall_text_build(target_uid: int, force_sync: bool = True) -> str:
    target_uid = int(target_uid)
    all_emailed = db_list_emailed_setups_all(target_uid)
    total = len(all_emailed)
    if total == 0:
        return "No emailed setups found yet for this account."
    try:
        _signal_outcome_sync_for_user(target_uid, days=None, limit=max(200, min(2500, total + 100)), force=bool(force_sync))
    except Exception:
        pass
    user = get_user(target_uid) or {}
    rows, hidden_untracked_open = _signal_report_resolve_rows(target_uid, all_emailed, user=user)
    rows = [dict(r, outcome=_display_signal_outcome((r or {}).get('outcome'))) for r in (rows or [])]
    stats = _canonical_wr_stats(rows)
    counts = stats.get('counts') or Counter()
    by_session = stats.get('by_session') or {}
    evaluated = len(rows)
    coverage = (evaluated / total * 100.0) if total > 0 else 0.0
    try:
        life_days = max(7, min(90, int(_autotrade_history_days_available(target_uid) or 30)))
    except Exception:
        life_days = 30
    try:
        lifecycle = _trade_lifecycle_analytics(target_uid, days=life_days, session='ALL', sync=True, force=bool(force_sync))
    except Exception:
        lifecycle = {}
    lines = [
        '📈 Signal Report — Overall',
        HDR,
        f'Total emailed setups: {total}',
        f'Evaluated: {evaluated} ({coverage:.1f}% coverage)',
        SEP,
        f'Completed outcomes: {int(stats.get("decided") or 0)}',
        f'TP wins: {int(stats.get("wins") or 0)} | Losses: {int(stats.get("losses") or 0)} | Signal WR: {float(stats.get("win_rate") or 0.0):.1f}%',
        f'TP: {int(counts.get("TP",0))} | SL: {int(counts.get("SL",0))} | Open: {int(counts.get("OPEN",0))} | None: {int(counts.get("None",0))}',
    ]
    lines.extend([SEP, *_trade_lifecycle_analytics_lines(lifecycle, heading=f'Exchange-backed lifecycle ({life_days}d)', include_sessions=True, include_engines=True, include_buckets=True, include_symbols=True, include_signs=True, max_signs=2)])
    if by_session:
        lines.extend([SEP, 'By session'])
        for sname, c in sorted(by_session.items(), key=lambda kv: kv[0]):
            lines.append(f"• {sname}: total {int(c.get('total') or 0)} | decided {int(c.get('decided') or 0)} | WR {float(c.get('win_rate') or 0.0):.1f}% | TP {int(c.get('tp') or 0)} SL {int(c.get('sl') or 0)} OPEN {int(c.get('open') or 0)} None {int(c.get('untracked') or 0)}")
    hidden_untracked_open = int(hidden_untracked_open or 0)
    if hidden_untracked_open > 0:
        lines.extend([SEP, f'Hidden untracked rows: {hidden_untracked_open} (no current live Bybit/autotrade match)'])
    out = '\n'.join(lines)
    try:
        # Do not keep the old bad all-open snapshot in cache; force the next call to rebuild.
        if not _signal_report_text_is_suspicious_all_open(out):
            cache_set(f"signal_report_overall_text:{target_uid}", out)
    except Exception:
        pass
    return out

def _signal_report_text_is_suspicious_all_open(val: str | None) -> bool:
    """Detect the old bad cached report that showed every emailed setup as OPEN forever."""
    try:
        s = str(val or '')
        if not s:
            return False
        m_total = re.search(r'Total emailed setups:\s*(\d+)', s)
        m_open = re.search(r'TP:\s*0\s*\|\s*SL:\s*0\s*\|\s*Open:\s*(\d+)', s, flags=re.I)
        m_done = re.search(r'Completed outcomes:\s*0\b', s)
        if m_total and m_open and m_done and int(m_total.group(1)) > 0 and int(m_open.group(1)) >= int(m_total.group(1)):
            return True
    except Exception:
        return False
    return False

def _signal_report_overall_cached_text(target_uid: int, ttl_sec: int = 900) -> str | None:
    try:
        key = f"signal_report_overall_text:{int(target_uid)}"
        if cache_valid(key, int(max(1, ttl_sec))):
            val = cache_get(key)
            if _signal_report_text_is_suspicious_all_open(str(val or '')):
                return None
            return str(val) if val else None
    except Exception:
        return None
    return None

def _autotrade_checkbox(flag: bool) -> str:
    return '✅' if bool(flag) else '—'


def _autotrade_sort_targets_for_side(side: str, prices: list[float]) -> list[float]:
    vals = _dedupe_price_targets([float(x or 0.0) for x in (prices or []) if float(x or 0.0) > 0.0])
    vals.sort(reverse=(str(side or '').upper().strip() == 'SELL'))
    return vals


def _autotrade_visible_tp_targets(symbol: str, side: str, open_orders: list[dict] | None = None) -> list[float]:
    sym = _bybit_linear_symbol(symbol)
    orders = open_orders if open_orders is not None else _bybit_get_open_orders_linear(sym)
    close_side = _bybit_exit_close_side_for_position_side(side)
    found = []
    for o in (orders or []):
        try:
            if _bybit_linear_symbol(str((o or {}).get('symbol') or '')) != sym:
                continue
            if not _bybit_order_matches_close_side(o, close_side):
                continue
            if not _bybit_is_tp_exit_order(o):
                continue
            px = float(_bybit_order_tp_price(o) or _bybit_order_working_price(o) or 0.0)
            if px > 0:
                found.append(px)
        except Exception:
            continue
    return _autotrade_sort_targets_for_side(side, found)


def _autotrade_find_open_trade_for_live_position(uid: int, live_pos: dict, journal_open: list[dict] | None = None) -> dict:
    candidates = [dict(r) for r in (journal_open or _autotrade_db_open_trades(int(uid)) or [])]
    sym = str(_pos_symbol(live_pos) or '').upper()
    side = str(_pos_side_text(live_pos) or '').upper()
    matches = [r for r in candidates if str(r.get('symbol') or '').upper() == sym and str(r.get('side') or '').upper() == side]
    if not matches:
        return {}
    if len(matches) == 1:
        return dict(matches[0])
    try:
        info = _autotrade_resolve_live_position_open_info(int(uid), live_pos, journal_open=matches)
    except Exception:
        info = {}
    journal_tid = str(info.get('journal_trade_id') or '').strip()
    if journal_tid:
        for row in matches:
            if str(row.get('trade_id') or '').strip() == journal_tid:
                return dict(row)
    target_opened = float(info.get('opened_ts') or 0.0)
    live_entry = float(_pos_entry(live_pos) or 0.0)
    def _score(row: dict):
        opened = float(row.get('opened_ts') or 0.0)
        entry = float(row.get('entry') or 0.0)
        entry_delta = abs(entry - live_entry) if entry > 0 and live_entry > 0 else 10**18
        if target_opened > 0 and opened > 0:
            open_delta = abs(opened - target_opened)
            return (0, open_delta, entry_delta, -opened)
        # When the exchange open-time cannot be resolved, prefer the latest OPEN
        # journal row for that same symbol/side. This prevents the guardian from
        # repairing a live position using an older setup row with different TP/SL.
        return (1, -opened, entry_delta)
    return dict(sorted(matches, key=_score)[0])


def _autotrade_live_position_owner_trade(uid: int, live_pos: dict, journal_open: list[dict] | None = None) -> dict:
    """Return the matched OPEN bot trade for a live Bybit position, or {} for manual/external positions.

    Recovery mode: if a live position exists but the OPEN journal row is missing because the
    original entry path failed after opening the position, adopt the orphan using setup lifecycle
    evidence so reports and risk accounting stay correct.
    """
    try:
        tr = _autotrade_find_open_trade_for_live_position(int(uid), live_pos, journal_open=journal_open)
    except Exception:
        tr = {}
    if not tr:
        try:
            tr = _autotrade_adopt_orphan_live_position(int(uid), live_pos, journal_open=journal_open)
        except Exception:
            tr = {}
    if not tr:
        return {}
    try:
        trade_id = str((tr or {}).get('trade_id') or '').strip()
        status = str((tr or {}).get('status') or '').upper().strip()
        if trade_id and status in {'', 'OPEN'}:
            return dict(tr)
    except Exception:
        pass
    return {}


def _autotrade_trade_public_ident(trade_row: dict) -> str:
    """Best-effort public identifier for autotrade/manual status lines."""
    try:
        row = dict(trade_row or {})
    except Exception:
        row = {}
    for key in ('setup_id', 'trade_id', 'public_id'):
        try:
            val = str(row.get(key) or '').strip()
        except Exception:
            val = ''
        if not val:
            continue
        if key == 'trade_id' and val.startswith(('exchange::', 'report::', 'prov::', 'manual::', 'AT-LIVE-')):
            continue
        return val
    return '-'


def _autotrade_synthetic_live_trade_row(uid: int, live_pos: dict) -> dict:
    """Synthetic owner row for live Bybit positions when journal linkage is missing.

    This keeps admin AutoTrade views authoritative even if the OPEN journal row was lost
    after the exchange entry succeeded.
    """
    try:
        sym = str(_pos_symbol(live_pos) or '').upper().strip()
        side = str(_pos_side_text(live_pos) or '').upper().strip()
        if not sym or side not in {'BUY', 'SELL'}:
            return {}
        live_entry = float(_pos_entry(live_pos) or 0.0)
        live_qty = abs(float(_pos_size(live_pos) or 0.0))
        current_sl = float(_pos_stop(live_pos) or _bybit_detect_open_sl_price(sym, side=side) or 0.0)
        visible_tps = _autotrade_visible_tp_targets(sym, side)
        current_tp = float((visible_tps[0] if visible_tps else 0.0) or _pos_take_profit(live_pos) or 0.0)
        info = _autotrade_resolve_live_position_open_info(int(uid), live_pos, journal_open=[])
        opened_ts = float(info.get('opened_ts') or _ts_seconds_from_any((live_pos or {}).get('createdTime') or (live_pos or {}).get('created_time')) or time.time())
        payload = {}
        life_trade_id = ''
        life_setup_id = ''
        life_session = ''
        try:
            with sqlite3.connect(DB_PATH) as conn:
                conn.row_factory = sqlite3.Row
                cur = conn.cursor()
                row = cur.execute(
                    """SELECT * FROM admin_setup_lifecycle
                       WHERE uid=? AND UPPER(COALESCE(symbol,''))=? AND UPPER(COALESCE(side,''))=?
                       ORDER BY COALESCE(executed_ts, attempted_ts, executable_ts, emailed_ts, signal_created_ts, generated_logged_ts, 0) DESC
                       LIMIT 1""",
                    (int(uid), sym, side),
                ).fetchone()
                life = dict(row) if row else {}
        except Exception:
            life = {}
        try:
            life_trade_id = str((life or {}).get('trade_id') or '').strip()
            life_setup_id = str((life or {}).get('setup_id') or '').strip()
            life_session = str((life or {}).get('session') or '').strip()
            if life_setup_id:
                payload = _signal_setup_eval_payload(life_setup_id) or {}
        except Exception:
            payload = {}
        payload_sl = float((payload or {}).get('sl') or 0.0)
        payload_tp = float(_resolve_single_tp(float((payload or {}).get('entry') or live_entry or 0.0), payload_sl, (payload or {}).get('tp'), (payload or {}).get('alt_target_a'), (payload or {}).get('alt_target_b'), side) or 0.0)
        row = {
            'trade_id': life_trade_id or f'AT-LIVE-{sym}-{side}',
            'setup_id': life_setup_id,
            'opened_ts': float(opened_ts or 0.0),
            'session': life_session,
            'symbol': sym,
            'side': side,
            'entry': float(live_entry or float((payload or {}).get('entry') or 0.0) or 0.0),
            'sl': float(current_sl or payload_sl or 0.0),
            'tp': float(current_tp or payload_tp or 0.0),
            'alt_target_a': 0.0,
            'alt_target_b': 0.0,
            'qty': float(live_qty or 0.0),
            'conf': int((payload or {}).get('conf') or 0),
            'quality_score': float((payload or {}).get('quality_score') or 0.0),
            'atr_pct': float((payload or {}).get('atr_pct') or 0.0),
            'engine': str((payload or {}).get('engine') or ''),
            'status': 'OPEN',
            'note': 'synthetic_live_position_owner_fallback',
        }
        return row
    except Exception:
        return {}


def _autotrade_collect_live_position_rows(uid: int, positions: list[dict] | None = None, journal_open: list[dict] | None = None, fallback_unmatched_as_owned: bool = True) -> tuple[list[tuple[dict, dict]], list[dict], list[dict]]:
    """Classify live Bybit positions into bot-owned rows plus any unmatched leftovers."""
    try:
        pos_rows = list(positions or _bybit_get_open_positions_linear() or [])
    except Exception:
        pos_rows = []
    try:
        open_rows = [dict(r) for r in (journal_open or _autotrade_db_open_trades(int(uid)) or [])]
    except Exception:
        open_rows = []
    bot_positions: list[tuple[dict, dict]] = []
    external_positions: list[dict] = []
    for p in (pos_rows or []):
        tr = _autotrade_live_position_owner_trade(int(uid), p, journal_open=open_rows)
        if not tr and fallback_unmatched_as_owned:
            tr = _autotrade_synthetic_live_trade_row(int(uid), p)
        if tr:
            bot_positions.append((p, dict(tr)))
        else:
            external_positions.append(p)
    return bot_positions, external_positions, open_rows


def _autotrade_live_position_bucket_rows(uid: int, positions: list[dict] | None = None, journal_open: list[dict] | None = None, fallback_unmatched_as_owned: bool = True) -> dict:
    """Shared live-position bucketing for AutoTrade metrics and admin views."""
    bot_positions, external_positions, open_rows = _autotrade_collect_live_position_rows(
        int(uid), positions=positions, journal_open=journal_open, fallback_unmatched_as_owned=fallback_unmatched_as_owned
    )
    current_total_open_risk = 0.0
    current_day_open_risk = 0.0
    carried_open_risk = 0.0
    inherited_open_positions = 0
    position_classifications = []
    open_pnl = 0.0
    external_open_risk = 0.0
    external_open_pnl = 0.0
    open_positions_now = len(bot_positions)
    user = _autotrade_user_settings(int(uid))
    start_utc, _end_utc = _admin_today_window_utc(uid=int(uid), user=user)
    start_ts = float(start_utc.timestamp())
    for p, matched_trade in (bot_positions or []):
        est = float(_estimate_position_risk_usd(p) or 0.0)
        info = _autotrade_resolve_live_position_open_info(int(uid), p, journal_open=[matched_trade] if matched_trade else open_rows)
        opened_ts = float(info.get('opened_ts') or float((matched_trade or {}).get('opened_ts') or 0.0) or 0.0)
        psym = _pos_symbol(p)
        pside = _pos_side_text(p)
        if est <= 0:
            try:
                est = float(_autotrade_estimated_risk_usd(float((matched_trade or {}).get('entry') or 0.0), float((matched_trade or {}).get('sl') or 0.0), float((matched_trade or {}).get('qty') or 0.0)) or 0.0)
            except Exception:
                pass
        est = max(0.0, float(est or 0.0))
        current_total_open_risk += est
        open_pnl += float(_pos_unreal_pnl(p) or 0.0)
        if opened_ts > 0 and opened_ts < start_ts:
            bucket = 'carried'
            carried_open_risk += est
            inherited_open_positions += 1
        else:
            bucket = 'current_day'
            current_day_open_risk += est
        position_classifications.append({
            'symbol': psym,
            'side': pside,
            'risk': float(est),
            'opened_ts': float(opened_ts or 0.0),
            'bucket': bucket,
            'source': str(info.get('source') or ('synthetic_live_position_owner_fallback' if str((matched_trade or {}).get('note') or '').strip() == 'synthetic_live_position_owner_fallback' else 'autotrade_journal')),
            'journal_ts': float(info.get('journal_ts') or float((matched_trade or {}).get('opened_ts') or 0.0) or 0.0),
            'position_created_ts': float(info.get('position_created_ts') or 0.0),
            'exchange_order_ts': float(info.get('exchange_order_ts') or 0.0),
            'notes': str(info.get('notes') or ''),
        })
    for p in (external_positions or []):
        external_open_pnl += float(_pos_unreal_pnl(p) or 0.0)
        external_open_risk += max(0.0, float(_estimate_position_risk_usd(p) or 0.0))
    return {
        'bot_positions': list(bot_positions or []),
        'external_positions': list(external_positions or []),
        'journal_open': list(open_rows or []),
        'open_positions_now': int(open_positions_now),
        'open_pnl': float(open_pnl),
        'current_total_open_risk': float(current_total_open_risk),
        'current_day_open_risk': float(current_day_open_risk),
        'carried_open_risk': float(carried_open_risk),
        'inherited_open_positions': int(min(int(inherited_open_positions), int(open_positions_now))),
        'position_classifications': list(position_classifications or []),
        'external_open_positions': int(len(external_positions or [])),
        'external_open_risk': float(external_open_risk),
        'external_open_pnl': float(external_open_pnl),
    }


def _autotrade_render_open_position_compact_line(trade_row: dict, live_pos: dict | None = None, index: int | None = None) -> str:
    try:
        row = dict(trade_row or {})
    except Exception:
        row = {}
    prefix = f"{int(index)}) " if index is not None else "• "
    sym = str(row.get('symbol') or (_pos_symbol(live_pos) if live_pos else '') or '?').upper()
    side = str(row.get('side') or (_pos_side_text(live_pos) if live_pos else '') or '?').upper()
    ident = _autotrade_trade_public_ident(row)
    risk_usd = 0.0
    try:
        if live_pos is not None:
            risk_usd = float(_estimate_position_risk_usd(live_pos) or 0.0)
        if risk_usd <= 0:
            risk_usd = float(_autotrade_estimated_risk_usd(float(row.get('entry') or 0.0), float(row.get('sl') or 0.0), float(row.get('qty') or 0.0)) or 0.0)
    except Exception:
        risk_usd = 0.0
    out = f"{prefix}Trade ID {ident} | {sym} {side} | Risk ${float(risk_usd or 0.0):.2f}"
    try:
        if live_pos is not None:
            out += f" | PnL {float(_pos_unreal_pnl(live_pos) or 0.0):+.2f} USDT"
    except Exception:
        pass
    return out


def _manual_open_trade_compact_line(t: dict) -> str:
    public_id = t.get('public_id')
    tid_txt = '-'
    try:
        if public_id is not None and str(public_id).strip() != '':
            tid_txt = str(int(public_id))
    except Exception:
        try:
            tid_txt = str(public_id)
        except Exception:
            tid_txt = '-'
    return f"• Trade ID {tid_txt} | {t.get('symbol')} {t.get('side')} | Risk ${float(t.get('risk_usd') or 0.0):.2f}"

def _autotrade_live_position_status(uid: int, live_pos: dict, trade_row: dict | None = None, lifecycle_row: dict | None = None, open_orders: list[dict] | None = None) -> dict:
    sym = _bybit_linear_symbol(_pos_symbol(live_pos))
    side = str(_pos_side_text(live_pos) or '').upper().strip()
    trade_row = dict(trade_row or {})
    lifecycle_row = dict(lifecycle_row or {})
    if (not lifecycle_row) and trade_row:
        try:
            ident = str(trade_row.get('trade_id') or trade_row.get('setup_id') or '').strip()
            if ident:
                lifecycle_row = _trade_lifecycle_detail_row(int(uid), ident, sync=False) or {}
        except Exception:
            lifecycle_row = {}

    visible_tp_targets = _autotrade_visible_tp_targets(sym, side, open_orders=open_orders)
    # Status reports must reflect native position-level TP/SL only. Standalone
    # Conditional rows are intentionally not counted as valid AutoTrade protection.
    current_sl = float(_pos_native_stop_loss(live_pos) or 0.0)
    current_qty = abs(float(_pos_size(live_pos) or 0.0))
    entry_live = float(_pos_entry(live_pos) or trade_row.get('entry') or 0.0)
    pnl = float(_pos_unreal_pnl(live_pos) or 0.0)
    mark = float(_pos_mark(live_pos) or 0.0)
    risk_est = float(_estimate_position_risk_usd(live_pos) or 0.0)

    expected_sl = float(trade_row.get('sl') or current_sl or 0.0)
    expected_tp = _resolve_single_tp(entry_live, expected_sl, trade_row.get('tp'), trade_row.get('alt_target_a'), trade_row.get('alt_target_b'), side)
    if expected_tp <= 0 and visible_tp_targets:
        expected_tp = float(visible_tp_targets[0] or 0.0)

    tp_hit = bool(float((lifecycle_row or {}).get('tp_hit_ts') or 0.0) > 0.0 or float((lifecycle_row or {}).get('alt_target_a_hit_ts') or 0.0) > 0.0)
    sl_hit = bool(float((lifecycle_row or {}).get('sl_hit_ts') or 0.0) > 0.0)
    native_tp_live = float(_pos_native_take_profit(live_pos) or 0.0)
    tp_order_live = bool(expected_tp > 0 and native_tp_live > 0 and _price_close_enough(native_tp_live, expected_tp, rel_tol=0.0020))
    sl_order_live = bool(expected_sl > 0 and current_sl > 0 and _price_close_enough(current_sl, expected_sl, rel_tol=0.0020))

    missing_sl = bool(expected_sl > 0 and not sl_order_live and not sl_hit)
    missing_tp = bool(expected_tp > 0 and not tp_hit and not tp_order_live)

    opened_ts = 0.0
    open_source = ''
    try:
        info = _autotrade_resolve_live_position_open_info(int(uid), live_pos, journal_open=[trade_row] if trade_row else None)
        opened_ts = float(info.get('opened_ts') or 0.0)
        open_source = str(info.get('source') or '')
    except Exception:
        pass

    return {
        'symbol': sym,
        'side': side,
        'trade_id': str(trade_row.get('trade_id') or ''),
        'setup_id': str(trade_row.get('setup_id') or ''),
        'entry': float(entry_live or 0.0),
        'mark': float(mark or 0.0),
        'pnl': float(pnl or 0.0),
        'qty': float(current_qty or 0.0),
        'risk_est': float(risk_est or 0.0),
        'expected_sl': float(expected_sl or 0.0),
        'expected_tp': float(expected_tp or 0.0),
        'expected_alt_target_a': 0.0,
        'current_sl': float(current_sl or 0.0),
        'visible_tp_targets': list(visible_tp_targets or []),
        'sl_hit': bool(sl_hit),
        'tp_hit': bool(tp_hit),
        'alt_target_a_hit': False,
        'sl_order_live': bool(sl_order_live),
        'tp_order_live': bool(tp_order_live),
        'alt_target_a_order_live': False,
        'missing_sl': bool(missing_sl),
        'missing_tp': bool(missing_tp),
        'missing_alt_target_a': False,
        'be_active': False,
        'risk_free': False,
        'opened_ts': float(opened_ts or 0.0),
        'open_source': open_source,
        'lifecycle_row': dict(lifecycle_row or {}),
    }


def _autotrade_render_live_position_snapshot(snapshot: dict, index: int | None = None) -> list[str]:
    label = f"{int(index)}) " if index is not None else "• "
    header = f"{label}{snapshot.get('side')} {snapshot.get('symbol')}"
    if snapshot.get('trade_id'):
        header += f" | {snapshot.get('trade_id')}"
    elif snapshot.get('setup_id'):
        header += f" | {snapshot.get('setup_id')}"
    lines = [header]
    lines.append(
        f"   • Qty: {float(snapshot.get('qty') or 0.0):g} | Entry: {fmt_price(float(snapshot.get('entry') or 0.0)) if float(snapshot.get('entry') or 0.0) > 0 else '—'} | Mark: {fmt_price(float(snapshot.get('mark') or 0.0)) if float(snapshot.get('mark') or 0.0) > 0 else '—'} | PnL: {float(snapshot.get('pnl') or 0.0):+.2f} USDT"
    )
    lines.append(
        f"   • SL: {fmt_price(float(snapshot.get('expected_sl') or 0.0)) if float(snapshot.get('expected_sl') or 0.0) > 0 else '—'} | Hit: {_autotrade_checkbox(snapshot.get('sl_hit'))} | Live order: {_autotrade_checkbox(snapshot.get('sl_order_live'))}"
    )
    lines.append(
        f"   • TP: {fmt_price(float(snapshot.get('expected_tp') or 0.0)) if float(snapshot.get('expected_tp') or 0.0) > 0 else '—'} | Hit: {_autotrade_checkbox(snapshot.get('tp_hit'))} | Live order: {_autotrade_checkbox(snapshot.get('tp_order_live'))}"
    )
    lines.append(
        f"   • Estimated risk now: {float(snapshot.get('risk_est') or 0.0):.2f} USDT"
    )
    missing = [name for name, flag in (('SL', snapshot.get('missing_sl')), ('TP', snapshot.get('missing_tp'))) if bool(flag)]
    if missing:
        lines.append(f"   • Protection repair pending: {', '.join(missing)}")
    if float(snapshot.get('opened_ts') or 0.0) > 0:
        lines.append(f"   • Opened: {_fmt_dt_local(datetime.fromtimestamp(float(snapshot.get('opened_ts')), tz=timezone.utc))}")
    return lines


def _autotrade_report_friendly_close_reason(row: dict) -> str:
    try:
        reason = str((row or {}).get('close_reason') or '').strip()
        result_path = str((row or {}).get('result_path') or '').upper().strip()
        result_label = str((row or {}).get('result_label') or '').strip()
        generic = {'', 'signal_path_close', 'exchange_closed_pnl_fallback', 'exchange_only_fallback_close'}
        if reason not in generic:
            return reason
        if result_path in {'HIT_TP_WIN', 'TP'}:
            return 'hit TP'
        if result_path in {'HIT_SL_LOSS', 'SL'}:
            return 'hit SL'
        if result_path == 'HIT_TP_THEN_BE_SL':
            return 'hit TP then BE stop'
        if result_path == 'HIT_TP_THEN_SL':
            return 'hit TP then SL'
        if result_path == 'OPEN':
            return 'open'
        return result_label or reason or 'closed'
    except Exception:
        return str((row or {}).get('close_reason') or (row or {}).get('result_label') or 'closed')


def _autotrade_render_closed_lifecycle_row_compact(row: dict, index: int | None = None) -> list[str]:
    sym = str(row.get('symbol') or '?')
    side = str(row.get('side') or '?')
    try:
        pnl = float(row.get('pnl_usdt') if row.get('pnl_usdt') is not None else row.get('pnl') or 0.0)
    except Exception:
        pnl = 0.0
    label = f"{int(index)}) " if index is not None else "• "
    header = f"{label}{side} {sym}"
    lines = [header]
    if float(row.get('opened_ts') or 0.0) > 0:
        lines.append(f"   • Opened: {_trade_lifecycle_time_text(float(row.get('opened_ts') or 0.0))}")
    lines.append(f"   • Close reason: {_autotrade_report_friendly_close_reason(row)}")
    if float(row.get('closed_ts') or 0.0) > 0:
        lines.append(f"   • Closed: {_trade_lifecycle_time_text(float(row.get('closed_ts') or 0.0))}")
    lines.append(f"   • PnL: {pnl:+.2f} USDT")
    return lines

def _autotrade_closed_report_rows(owner_uid: int, start_ts: float, end_ts: float, lookback_h: int = 24, limit: int = 80) -> list[dict]:
    owner_uid = int(owner_uid)
    start_ts = float(start_ts or 0.0)
    end_ts = float(end_ts or 0.0)
    limit = int(limit or 0)
    if limit <= 0:
        limit = 100000
    else:
        limit = int(max(1, min(int(limit), 100000)))

    try:
        sync_days = max(14, int(math.ceil(float(lookback_h or 24) / 24.0)) + 5)
        _autotrade_sync_closed_trades_from_exchange(owner_uid, lookback_days=sync_days)
    except Exception:
        pass

    def _payload_fill(row: dict) -> dict:
        row = dict(row or {})
        sid = str(row.get('setup_id') or '').strip()
        payload = _signal_setup_eval_payload(sid) if sid else {}
        if payload:
            for fld in ('symbol', 'side', 'entry', 'sl', 'tp', 'alt_target_a', 'alt_target_b', 'engine', 'session', 'conf', 'quality_score', 'atr_pct', 'family_id', 'regime_primary', 'allocator_plan_id', 'param_set_id', 'setup_strategy', 'strategy', 'strategy_mode', 'original_setup_id', 'original_side', 'strategy_reason'):
                cur = row.get(fld)
                if fld in {'entry', 'sl', 'tp', 'alt_target_a', 'alt_target_b', 'quality_score', 'atr_pct'}:
                    try:
                        cur_num = float(cur or 0.0)
                    except Exception:
                        cur_num = 0.0
                    try:
                        src_num = float(payload.get(fld) or 0.0)
                    except Exception:
                        src_num = 0.0
                    if cur_num <= 0 and src_num > 0:
                        row[fld] = src_num
                elif fld == 'conf':
                    try:
                        if int(cur or 0) <= 0 and int(payload.get(fld) or 0) > 0:
                            row[fld] = int(payload.get(fld) or 0)
                    except Exception:
                        pass
                else:
                    if not str(cur or '').strip() and str(payload.get(fld) or '').strip():
                        row[fld] = payload.get(fld)
            if float(row.get('opened_ts') or 0.0) <= 0 and float(payload.get('created_ts') or 0.0) > 0:
                row['opened_ts'] = float(payload.get('created_ts') or 0.0)
        return row

    try:
        journal_rows = _autotrade_db_closed_trades_window(owner_uid, start_ts, end_ts) or []
    except Exception:
        journal_rows = []
    journal_rows = [
        _payload_fill(dict(r)) for r in (journal_rows or [])
        if not str((r or {}).get('trade_id') or '').startswith(('exchange::', 'report::', 'prov::', 'manual::'))
        and str((r or {}).get('note') or '').strip() != 'exchange_closed_pnl_fallback'
    ]
    journal_rows = list(journal_rows[:max(limit * 3, 60)])

    prov_days = max(2, int(math.ceil(float(lookback_h or 24) / 24.0)) + 3)
    try:
        provisional_rows = [
            _payload_fill(dict(p)) for p in (_autotrade_reconstruct_provisional_closes(owner_uid, days=prov_days) or [])
            if float((p or {}).get('closed_ts') or 0.0) >= start_ts
            and float((p or {}).get('closed_ts') or 0.0) < end_ts
            and str((p or {}).get('setup_id') or '').strip()
        ]
    except Exception:
        provisional_rows = []

    lifecycle_rows = []
    try:
        lifecycle_rows = [
            _payload_fill(dict(r)) for r in (_trade_lifecycle_query_rows(owner_uid, start_ts=float(start_ts), session='ALL', limit=max(limit * 2, 80)) or [])
            if str((r or {}).get('result_path') or '').upper().strip() != 'OPEN'
            and float((r or {}).get('closed_ts') or 0.0) >= start_ts
            and float((r or {}).get('closed_ts') or 0.0) < end_ts
            and (
                str((r or {}).get('setup_id') or '').strip()
                or (str((r or {}).get('trade_id') or '').strip() and not str((r or {}).get('trade_id') or '').startswith(('exchange::', 'report::', 'prov::', 'manual::')))
            )
        ]
    except Exception:
        lifecycle_rows = []


    exchange_fallback_rows = []
    try:
        exchange_fallback_rows = [
            _payload_fill(dict(r)) for r in (_autotrade_exchange_close_fallback_rows(owner_uid, days=prov_days) or [])
            if float((r or {}).get('closed_ts') or 0.0) >= start_ts
            and float((r or {}).get('closed_ts') or 0.0) < end_ts
        ]
    except Exception:
        exchange_fallback_rows = []

    life_by_ident = {}
    life_by_key = {}
    for r in (lifecycle_rows or []):
        rr = dict(r or {})
        tid = str(rr.get('trade_id') or '').strip()
        sid = str(rr.get('setup_id') or '').strip()
        sym = str(_bybit_linear_symbol(rr.get('symbol') or '')).upper()
        side = str(rr.get('side') or '').upper().strip()
        cts = float(rr.get('closed_ts') or 0.0)
        pnl = float(rr.get('pnl_usdt') or 0.0) if rr.get('pnl_usdt') is not None else float(rr.get('pnl') or 0.0)
        if tid:
            life_by_ident[('trade', tid)] = rr
        if sid:
            life_by_ident[('setup', sid)] = rr
        if sym and side and cts > 0:
            life_by_key[(sym, side, int(cts // 60), round(float(pnl or 0.0), 8))] = rr

    user = _autotrade_user_settings(owner_uid)
    out = []
    seen_out = set()
    enrich_budget = min(max(limit, 10), 20)
    lifecycle_order_cache: dict[str, list[dict]] = {}
    lifecycle_closed_pnl_rows = []
    if str(_autotrade_runtime_mode()).lower() == 'live':
        try:
            lifecycle_closed_pnl_rows = _bybit_get_closed_pnl_linear(max(0.0, float(start_ts) - 86400.0), float(end_ts) + 21600.0, limit=max(200, int(limit) * 30)) or []
        except Exception:
            lifecycle_closed_pnl_rows = []

    def _needs_lifecycle_enrichment(row: dict) -> bool:
        try:
            result_path = str((row or {}).get('result_path') or '').upper().strip()
            close_reason = str((row or {}).get('close_reason') or '').strip()
            if float((row or {}).get('entry') or 0.0) <= 0 or float((row or {}).get('sl') or 0.0) <= 0:
                return True
            if float(_resolve_single_tp(float((row or {}).get('entry') or 0.0), float((row or {}).get('sl') or 0.0), (row or {}).get('tp'), (row or {}).get('alt_target_a'), (row or {}).get('alt_target_b'), str((row or {}).get('side') or '')) or 0.0) <= 0:
                return True
            if result_path in {'TP', 'SL', 'HIT_TP_WIN', 'HIT_SL_LOSS', 'HIT_TP_THEN_BE_SL', 'HIT_TP_THEN_SL'}:
                if float((row or {}).get('tp_hit_ts') or 0.0) <= 0 and float((row or {}).get('sl_hit_ts') or 0.0) <= 0 and float((row or {}).get('alt_target_a_hit_ts') or 0.0) <= 0:
                    return True
            if close_reason in {'', 'signal_path_close', 'exchange_closed_pnl_fallback', 'exchange_only_fallback_close'}:
                return True
            if (row or {}).get('pnl_usdt') is None and (row or {}).get('pnl') is not None:
                return True
            return False
        except Exception:
            return True

    def _out_key(row: dict) -> tuple:
        sid = str((row or {}).get('setup_id') or '').strip()
        if sid:
            return ('setup', sid)
        tid = str((row or {}).get('trade_id') or '').strip()
        if tid and not tid.startswith(('exchange::', 'report::', 'prov::', 'manual::')):
            return ('trade', tid)
        sym = str(_bybit_linear_symbol((row or {}).get('symbol') or '')).upper()
        side = str((row or {}).get('side') or '').upper().strip()
        cts = float((row or {}).get('closed_ts') or 0.0)
        pnl = float((row or {}).get('pnl_usdt') or 0.0) if (row or {}).get('pnl_usdt') is not None else float((row or {}).get('pnl') or 0.0)
        return (sym, side, int(cts // 60), round(float(pnl or 0.0), 8))

    def _canonical_result_label(row: dict) -> tuple[str, str]:
        raw_path = str((row or {}).get('result_path') or '').upper().strip()
        # Ver16: do not turn pnl sign into TP/SL. Only preserve explicit lifecycle
        # labels; final verified TP/SL/OTHER is decided by _autotrade_report_closed_kind().
        if raw_path in {'HIT_TP_WIN', 'TP'}:
            return 'TP', 'TP'
        if raw_path in {'HIT_SL_LOSS', 'SL'}:
            return 'SL', 'SL'
        if raw_path in {'HIT_TP_THEN_BE_SL', 'HIT_TP_THEN_SL'}:
            return raw_path, _trade_lifecycle_result_label(raw_path)
        outcome_txt = str((row or {}).get('outcome') or '').upper().strip()
        if outcome_txt in {'TP', 'WIN_TP', 'TAKE_PROFIT', 'TAKEPROFIT'}:
            return 'TP', 'TP'
        if outcome_txt in {'SL', 'STOP_LOSS', 'STOPLOSS', 'SL_FIRST'}:
            return 'SL', 'SL'
        return 'MANUAL_OR_UNKNOWN_CLOSE', _trade_lifecycle_result_label('MANUAL_OR_UNKNOWN_CLOSE')

    # Ver16: raw exchange-only fallback rows are hidden by default. They often
    # have no setup/trade id and can be manual, legacy, or unmatched exchange
    # closes, which made /autotrade_report show TP/SL rows with tiny/non-target PnL.
    seed_rows = list(lifecycle_rows or []) + list(journal_rows or []) + list(provisional_rows or [])
    if bool(globals().get('AUTOTRADE_REPORT_INCLUDE_EXCHANGE_ONLY_FALLBACK', True)):
        seed_rows += list(exchange_fallback_rows or [])
    for base in seed_rows:
        try:
            b = _payload_fill(dict(base or {}))
            sym = str(_bybit_linear_symbol(b.get('symbol') or '')).upper()
            side = str(b.get('side') or '').upper().strip()
            cts = float(b.get('closed_ts') or 0.0)
            pnl = float(b.get('pnl_usdt') or 0.0) if b.get('pnl_usdt') is not None else float(b.get('pnl') or 0.0)
            event_key = (sym, side, int(cts // 60), round(float(pnl or 0.0), 8))
            tid = str(b.get('trade_id') or '').strip()
            sid = str(b.get('setup_id') or '').strip()

            detail = {}
            if sid:
                detail = dict(life_by_ident.get(('setup', sid)) or {})
            if (not detail) and tid:
                detail = dict(life_by_ident.get(('trade', tid)) or {})
            if (not detail):
                detail = dict(life_by_key.get(event_key) or {})
            row = _payload_fill(dict(detail or b))

            if str(row.get('status') or '').upper().strip() == 'OPEN' or float(row.get('closed_ts') or 0.0) <= 0:
                row['status'] = 'CLOSED'
                row['closed_ts'] = float(cts or row.get('closed_ts') or 0.0)
                row['pnl_usdt'] = float(b.get('pnl_usdt') if b.get('pnl_usdt') is not None else pnl)
            if sid and not str(row.get('setup_id') or '').strip():
                row['setup_id'] = sid
            if enrich_budget > 0 and _needs_lifecycle_enrichment(row) and (sid or tid or sym):
                try:
                    order_rows = lifecycle_order_cache.get(sym)
                    if order_rows is None:
                        try:
                            order_rows = _bybit_get_recent_filled_orders_linear(sym, lookback_hours=max(48, int(lookback_h or 24) + 24), limit=max(120, int(limit) * 12)) or []
                        except Exception:
                            order_rows = []
                        lifecycle_order_cache[sym] = list(order_rows or [])
                    row, _events = _trade_lifecycle_build_trade_row(
                        owner_uid,
                        row,
                        user,
                        next_open_ts=0.0,
                        live_mode=False,
                        live_pos=None,
                        order_rows=order_rows or [],
                        closed_pnl_rows=lifecycle_closed_pnl_rows or [],
                    )
                except Exception:
                    row = dict(row)
                row = _payload_fill(row)
                enrich_budget -= 1
            result_path, result_label = _canonical_result_label(row)
            if not str(row.get('result_path') or '').strip() or str(row.get('result_path') or '').upper().strip() in {'OPEN', 'MANUAL_OR_UNKNOWN_CLOSE'}:
                row['result_path'] = result_path
            if not str(row.get('result_label') or '').strip() or str(row.get('result_label') or '').lower().strip() == 'manual / unknown exchange close':
                row['result_label'] = result_label
            if not str(row.get('close_reason') or '').strip() or str(row.get('close_reason') or '').strip() in {'signal_path_close', 'exchange_closed_pnl_fallback', 'exchange_only_fallback_close'}:
                row['close_reason'] = _autotrade_report_friendly_close_reason({**row, 'result_path': result_path, 'result_label': result_label})
            if row.get('pnl_usdt') is None and row.get('pnl') is not None:
                try:
                    row['pnl_usdt'] = float(row.get('pnl') or 0.0)
                except Exception:
                    pass
            ok = _out_key(row)
            if ok not in seen_out:
                out.append(row)
                seen_out.add(ok)
        except Exception:
            continue

    out.sort(key=lambda r: float((r or {}).get('closed_ts') or 0.0), reverse=True)
    return out if int(limit or 0) >= 100000 else out[:limit]




def _autotrade_report_row_session(row: dict) -> str:
    try:
        sess = str((row or {}).get('session') or (row or {}).get('source_session') or (row or {}).get('open_session') or '').upper().strip()
        if sess in {'ASIA', 'LON', 'NY'}:
            return sess
        ts = float((row or {}).get('opened_ts') or (row or {}).get('closed_ts') or (row or {}).get('ts') or 0.0)
        if ts > 0:
            return _session_label_from_ts(ts)
    except Exception:
        pass
    return 'UNK'




def _autotrade_report_money(v, blank: str = '-') -> str:
    try:
        x = float(v or 0.0)
        if abs(x) < 1e-9:
            return blank
        return f"{x:.2f}"
    except Exception:
        return blank


def _autotrade_report_pct(v, blank: str = '-') -> str:
    try:
        x = float(v or 0.0)
        if abs(x) < 1e-9:
            return blank
        return f"{x:.2f}%"
    except Exception:
        return blank


def _autotrade_report_close_session(row: dict) -> str:
    try:
        ts = float((row or {}).get('closed_ts') or (row or {}).get('last_ts') or (row or {}).get('ts') or 0.0)
        if ts > 0:
            return _session_label_from_ts(ts)
    except Exception:
        pass
    return '-'


def _autotrade_report_is_before_asia_close(row: dict) -> bool:
    """True when a close belongs to the daily pre-ASIA flat/zero-carry process."""
    try:
        note = str((row or {}).get('note') or (row or {}).get('close_reason') or (row or {}).get('source_note') or '').upper()
        if any(k in note for k in ('BEFORE_ASIA', 'SCHEDULED_FLAT', 'FLAT_BEFORE_ASIA', 'ZERO_CARRYOVER', 'COOLDOWN RESET')):
            return True
        ts = float((row or {}).get('closed_ts') or (row or {}).get('last_ts') or (row or {}).get('ts') or 0.0)
        if ts <= 0:
            return False
        dt = datetime.fromtimestamp(ts, tz=timezone.utc).astimezone(MEL_TZ)
        # The scheduled job is 09:55, but Render/catch-up can close a few minutes later.
        return (dt.hour == 9 and 40 <= dt.minute <= 59) or (dt.hour == 10 and 0 <= dt.minute <= 5)
    except Exception:
        return False


AUTOTRADE_REPORT_LOSS_REASON_CHOICES = (
    'SL_HIT',                 # stop price/order was hit or PnL is close to expected risk
    'CLOSE_BEFORE_ASIA_SESSION', # 09:55 daily flat closed before the ASIA trading day
    'MAX_HOLD_LOSS',          # max-hold rule closed the position at a loss
    'WEAK_COMBO',             # family+session currently has negative/disabled edge evidence
    'WEAK_SYMBOL',            # symbol has recent blocklist/poor-edge evidence
    'WEAK_HOUR',              # entry hour is in weak-hour watch/blackout evidence
    'TIGHT_SL',               # stop distance was too small for crypto noise/volatility
    'BAD_ENTRY',              # entry drifted/adverse or candle structure was weak
    'COUNTER_TREND',          # setup side fought the 24h/4h/1h direction
    'LOW_CONFIDENCE',         # confidence was below the stronger live threshold
    'LOW_VOLUME',             # volume was above floor but still thin for AutoTrade quality
    'MISSING_SETUP_DATA',     # legacy/unmatched row lacks setup metadata; do not pretend it was low-confidence
    'LOSS_CLOSE',             # exchange closed at loss but exact failure mode is unknown
)


def _autotrade_report_loss_reason(row: dict) -> str:
    """Best-effort analytical loss reason for continuous improvement.

    Ver29: direct SL proof no longer stops the analysis immediately.  The report
    already has Result=SL; LossReason should explain the likely *cause* so the
    policy engine and weekly review can tighten the right variable.
    """
    try:
        row = dict(row or {})
        note = str(row.get('note') or row.get('close_reason') or row.get('source_note') or row.get('result_label') or '').upper()
        if _autotrade_report_is_before_asia_close(row):
            return 'CLOSE_BEFORE_ASIA_SESSION'
        if 'MAX_POSITION' in note or 'MAX_HOLD' in note or 'MAX-HOLD' in note:
            return 'MAX_HOLD_LOSS'

        sym = str(row.get('symbol') or '').upper().replace('USDT', '')
        side = str(row.get('side') or '').upper().strip()
        fam = _setup_audit_family_display(row, compact=True)
        sess = str(row.get('session') or row.get('open_session') or '').upper().strip()
        combo = f"{fam}-{sess}" if fam and sess else ''
        try:
            conf_val = int(float(row.get('conf') or row.get('confidence') or 0.0))
        except Exception:
            conf_val = 0
        has_setup_id = bool(str(row.get('setup_id') or '').strip())
        has_core_setup_prices = float(row.get('entry') or 0.0) > 0 and float(row.get('sl') or 0.0) > 0

        # Enforced policy / micro-edge evidence first: this is usually the most
        # actionable reason for the next week/day adjustment.
        try:
            disabled = set(_setup_combo_disabled_set(int(row.get('uid') or AUTOTRADE_OWNER_UID or 0)) or set())
            if combo and combo in disabled:
                return 'WEAK_COMBO'
        except Exception:
            pass
        try:
            pol = _setup_combo_policy_cache_rows(force=False) or {}
            strat_row = _setup_strategy_suffix(row)
            side_row = _setup_side_suffix(value=side)
            for key_pol, pr in pol.items():
                try:
                    if len(key_pol) == 5:
                        _uid, pfam, pses, pstrat, pside = key_pol
                    else:
                        _uid, pfam, pses = key_pol[:3]
                        pstrat, pside = 'ALL', 'BOTH'
                    if pfam == str(fam).upper() and pses == str(sess).upper():
                        # Exact-lane policy gets priority; coarse policy is still useful
                        # for scheduled high-level context, but coarse daily safety is ignored.
                        pkind = str((pr or {}).get('policy_kind') or '').lower().strip()
                        exact_or_coarse = (pstrat in {'ALL', strat_row}) and (pside in {'BOTH', side_row})
                        if not exact_or_coarse:
                            continue
                        if pkind == 'daily_safety' and not (pstrat in {'NOR','REV'} and pside in {'BUY','SELL'}):
                            continue
                        if int(pr.get('enabled') if pr.get('enabled') is not None else 1) <= 0 or str(pr.get('status') or '').upper() == 'DISABLE':
                            return 'WEAK_COMBO'
                        if float(pr.get('last_score') or 0.0) < -20 or float(pr.get('last_win_rate') or 0.0) < 35:
                            return 'WEAK_COMBO'
                except Exception:
                    continue
        except Exception:
            pass
        try:
            guard = _setup_edge_guard_build(int(row.get('uid') or AUTOTRADE_OWNER_UID or 0), hours=int(globals().get('SETUP_EDGE_GUARD_WINDOW_HOURS', 168) or 168), force=False)
            bad_symbols = set((guard or {}).get('symbol_block') or {})
            if sym and (sym in bad_symbols or f'{sym}USDT' in bad_symbols):
                return 'WEAK_SYMBOL'
            opened_ts = float(row.get('opened_ts') or row.get('ts') or 0.0)
            if opened_ts > 0:
                hh = datetime.fromtimestamp(opened_ts, tz=timezone.utc).astimezone(MEL_TZ).strftime('%H:00')
                weak_hours = set((guard or {}).get('hour_watch') or {})
                if hh in weak_hours:
                    return 'WEAK_HOUR'
        except Exception:
            pass

        # If an older/exchange fallback row has no setup context, say that honestly.
        # Do not mislabel missing metadata as LOW_CONFIDENCE; that corrupts the
        # continuous-improvement loop by making legacy/unmatched rows look like
        # a confidence-threshold problem.
        if (not has_setup_id) and (fam in {'', '-', 'F0', 'UNK'} or conf_val <= 0) and (not has_core_setup_prices):
            return 'MISSING_SETUP_DATA'

        # Setup mechanics: identify if stop placement or entry quality was the likely problem.
        entry = float(row.get('entry') or 0.0)
        sl = float(row.get('sl') or 0.0)
        if entry > 0 and sl > 0:
            sl_pct = abs(entry - sl) / max(abs(entry), 1e-12) * 100.0
            if sl_pct < 1.20:
                return 'TIGHT_SL'
            try:
                atr_pct = float(row.get('atr_pct') or 0.0)
                if atr_pct > 0 and sl_pct < max(0.65 * atr_pct, 0.8):
                    return 'TIGHT_SL'
            except Exception:
                pass
            # Very wide SL that still loses often means the entry was too late/chased.
            try:
                if sl_pct > 8.0 and abs(float(row.get('ch15') or 0.0)) > 1.5:
                    return 'BAD_ENTRY'
            except Exception:
                pass

        try:
            drift = float(row.get('entry_drift_adverse_pct') or row.get('entry_delta_pct') or 0.0)
            if drift >= 0.35:
                return 'BAD_ENTRY'
        except Exception:
            pass

        # Direction conflict using available move features.
        try:
            moves = [float(row.get('ch24') or 0.0), float(row.get('ch4') or 0.0), float(row.get('ch1') or 0.0)]
            if side == 'BUY' and sum(1 for x in moves if x < -1.0) >= 2:
                return 'COUNTER_TREND'
            if side == 'SELL' and sum(1 for x in moves if x > 1.0) >= 2:
                return 'COUNTER_TREND'
        except Exception:
            pass

        try:
            # LOW_CONFIDENCE is only valid when a real confidence value exists.
            # Missing legacy metadata is reported as MISSING_SETUP_DATA instead.
            if 0 < int(conf_val) < 83:
                return 'LOW_CONFIDENCE'
        except Exception:
            pass
        try:
            volm = float(row.get('fut_vol_usd') or row.get('volume_usd') or 0.0) / 1e6
            if 0 < volm < 25:
                return 'LOW_VOLUME'
        except Exception:
            pass

        # Only keep SL_HIT when no better actionable cause can be inferred.
        if _autotrade_report_has_direct_tpsl_proof(row, 'SL') or _autotrade_report_pnl_close_to_expected(row, 'SL'):
            return 'SL_HIT'
        return 'LOSS_CLOSE'
    except Exception:
        return 'LOSS_CLOSE'


# yver57: /autotrade_report Reason is a close-cause column.  When native/full
# TP/SL or realised-PnL evidence proves an SL close, show SL_HIT instead of an
# analytical weakness label such as LOW_CONFIDENCE/WEAK_COMBO.  The matrix/report
# still carries combo/WR evidence separately.
try:
    _YVER57_ORIG_AUTOTRADE_REPORT_LOSS_REASON = _autotrade_report_loss_reason
except Exception:
    _YVER57_ORIG_AUTOTRADE_REPORT_LOSS_REASON = None

def _autotrade_report_loss_reason(row: dict) -> str:
    try:
        if _autotrade_report_has_direct_tpsl_proof(row, 'SL') or _autotrade_report_pnl_close_to_expected(row, 'SL'):
            return 'SL_HIT'
    except Exception:
        pass
    if _YVER57_ORIG_AUTOTRADE_REPORT_LOSS_REASON is not None:
        return _YVER57_ORIG_AUTOTRADE_REPORT_LOSS_REASON(row)
    return 'LOSS_CLOSE'

def _autotrade_report_exit_reason(row: dict, result: str | None = None) -> str:
    """Short user-facing close reason used by /autotrade_report.

    Result is the trading outcome (TP/SL/FLAT/OPEN). Reason explains how it closed
    (TP hit, SL hit, pre-ASIA flat, max hold, or inferred loss cause).
    """
    try:
        row = dict(row or {})
        res = str(result or row.get('closed_kind') or '').upper().strip()
        if str(row.get('state') or '').upper().strip() == 'OPEN' or res == 'OPEN':
            return 'OPEN'
        note_raw = str(row.get('note') or row.get('close_reason') or row.get('source_note') or row.get('result_label') or '').strip()
        note = note_raw.upper()
        if _autotrade_report_is_before_asia_close(row):
            if res == 'TP':
                return 'CLOSE_BEFORE_ASIA_SESSION'
            if res == 'SL':
                return 'CLOSE_BEFORE_ASIA_SESSION'
            return 'CLOSE_BEFORE_ASIA_SESSION'
        if 'MAX_POSITION' in note or 'MAX_HOLD' in note or 'MAX-HOLD' in note:
            if res == 'TP':
                return 'MAX_HOLD_WIN'
            if res == 'SL':
                return 'MAX_HOLD_LOSS'
            return 'MAX_HOLD'
        if res == 'TP':
            if _autotrade_report_has_direct_tpsl_proof(row, 'TP') or _autotrade_report_pnl_close_to_expected(row, 'TP'):
                return 'TP_HIT'
            return 'PROFIT_CLOSE'
        if res == 'SL':
            return _autotrade_report_loss_reason(row)
        if res == 'FLAT':
            return 'FLAT_CLOSE'
        if note_raw:
            return _setup_audit_short_text(note_raw.replace('exchange_closed_pnl_fallback', 'EXCHANGE_CLOSE'), 22).upper().replace(' ', '_')
        return 'OTHER_CLOSE'
    except Exception:
        return 'OTHER_CLOSE'

def _autotrade_report_infer_dynamic_score(row: dict) -> float:
    """Infer the dynamic-risk score for reporting when the stored score is missing.

    Some live rows persisted only the executed Risk%/Risk$ but not the dynamic score.
    For analysis, infer the score from the configured base risk and risk multiplier
    instead of showing a blank Dyn column.  This is a reporting-only estimate.
    """
    try:
        row = dict(row or {})
        stored = float(row.get('dynamic_risk_score') or row.get('dyn_score') or 0.0)
        if stored > 0:
            return float(stored)
    except Exception:
        pass
    try:
        mult = float(row.get('risk_multiplier') or 0.0)
    except Exception:
        mult = 0.0
    if mult <= 0:
        try:
            base_pct = float(row.get('configured_risk_pct') or _autotrade_risk_per_trade_pct() or 0.0)
            risk_pct = float(row.get('risk_pct') or row.get('allowed_risk_pct') or row.get('risk_actual_pct') or row.get('filled_risk_pct') or 0.0)
            if base_pct > 0 and risk_pct > 0:
                mult = float(risk_pct) / float(base_pct)
        except Exception:
            mult = 0.0
    if mult <= 0:
        return 0.0
    try:
        min_mult, max_mult, low_score, base_score, high_score = _autotrade_dynamic_risk_bounds()
        mult = max(float(min_mult), min(float(max_mult), float(mult)))
        if mult <= 1.0:
            denom = max(1e-9, 1.0 - float(min_mult))
            return float(low_score) + ((float(mult) - float(min_mult)) / denom) * (float(base_score) - float(low_score))
        denom = max(1e-9, float(max_mult) - 1.0)
        return float(base_score) + ((float(mult) - 1.0) / denom) * (float(high_score) - float(base_score))
    except Exception:
        return 0.0

def _autotrade_report_enrich_amounts(row: dict, equity: float = 0.0) -> dict:
    """Add reporting risk/TP amounts without inventing fake legacy values.

    Ver29 rule:
    - show Risk$/TP$ only when they come from stored execution metadata or
      actual position geometry (entry/SL/TP x executed qty x contract size),
    - do NOT convert a generic/default risk percentage into a fake dollar amount
      for old rows, because that corrupts continuous improvement analysis,
    - keep source flags so the Telegram table can hide unknown legacy values
      instead of showing base-config placeholders such as 1.50% / 29.04.
    """
    out = dict(row or {})
    try:
        eq = float(equity or 0.0)
        if eq > 0:
            out['report_equity'] = float(eq)

        def _first_num(keys, absval: bool = False) -> tuple[float, str]:
            for k in keys:
                try:
                    raw = out.get(k)
                    if raw in (None, ''):
                        continue
                    v = float(raw or 0.0)
                    if absval:
                        v = abs(v)
                    if v > 0:
                        return float(v), str(k)
                except Exception:
                    pass
            return 0.0, ''

        amount_keys = ('risk_usd', 'risk_usdt', 'filled_risk_usd', 'risk_actual_usd', 'target_risk_usd', 'estimated_risk_usd', 'risk_est')
        tp_amount_keys = ('tp_usd', 'tp_usdt', 'target_tp_usd', 'expected_tp_usd')
        risk_usd, risk_src_key = _first_num(amount_keys, absval=True)
        tp_usd, tp_src_key = _first_num(tp_amount_keys, absval=True)
        # yver108: preserve live Bybit geometry amounts injected by /autotrade_report.
        # The generic geometry calculation below can be stale if it falls back to old
        # setup metadata, so live_position_geometry must not be overwritten.
        risk_src_existing = str(out.get('risk_usd_source') or '').strip()
        tp_src_existing = str(out.get('tp_usd_source') or '').strip()
        risk_src = risk_src_existing if risk_usd > 0 and risk_src_existing else ('stored_amount' if risk_usd > 0 else '')
        tp_src = tp_src_existing if tp_usd > 0 and tp_src_existing else ('stored_amount' if tp_usd > 0 else '')

        entry = float(out.get('entry') or 0.0)
        sl = float(out.get('sl') or 0.0)
        side = str(out.get('side') or '').upper().strip()
        tp = float(_resolve_single_tp(entry, sl, out.get('tp'), out.get('alt_target_a'), out.get('alt_target_b'), side) or 0.0)
        qty = abs(float(out.get('qty') or out.get('filled_qty') or out.get('closed_qty') or 0.0))
        try:
            cs = float(out.get('contract_size') or out.get('contractSize') or 0.0)
            if cs <= 0:
                cs = float((_bybit_get_instr_filters(str(out.get('symbol') or '')) or {}).get('contractSize') or 1.0)
        except Exception:
            cs = 1.0
        cs = abs(float(cs or 1.0))

        if risk_src != 'live_position_geometry' and entry > 0 and sl > 0 and qty > 0:
            geom_risk = abs(entry - sl) * qty * cs
            if geom_risk > 0:
                risk_usd = float(geom_risk)
                risk_src = 'geometry_qty'
        if tp_src != 'live_position_geometry' and entry > 0 and tp > 0 and qty > 0:
            geom_tp = abs(tp - entry) * qty * cs
            if geom_tp > 0:
                tp_usd = float(geom_tp)
                tp_src = 'geometry_qty'
        elif tp_usd <= 0 and risk_usd > 0 and entry > 0 and sl > 0 and tp > 0:
            try:
                rr = abs(tp - entry) / max(abs(entry - sl), 1e-12)
            except Exception:
                rr = float(out.get('rr_tp') or out.get('rr_tp_target') or 0.0)
            if rr > 0:
                tp_usd = float(risk_usd) * float(rr)
                tp_src = 'rr_from_real_risk'

        pct_keys_actual = ('risk_actual_pct', 'filled_risk_pct')
        pct_actual, pct_actual_key = _first_num(pct_keys_actual, absval=True)
        raw_allowed_pct, raw_allowed_key = _first_num(('allowed_risk_pct',), absval=True)
        raw_risk_pct, raw_risk_key = _first_num(('risk_pct',), absval=True)

        risk_pct = 0.0
        risk_pct_src = ''
        if risk_usd > 0 and eq > 0:
            risk_pct = (risk_usd / eq) * 100.0
            risk_pct_src = 'risk_usd_equity'
        elif pct_actual > 0:
            risk_pct = pct_actual
            risk_pct_src = pct_actual_key
        elif raw_risk_pct > 0 and (float(out.get('dynamic_risk_score') or 0.0) > 0 or float(out.get('risk_multiplier') or 0.0) > 0):
            # Risk percentage persisted with dynamic-risk metadata is useful even if
            # quantity is missing; a plain old/base risk_pct without that context is not.
            risk_pct = raw_risk_pct
            risk_pct_src = raw_risk_key
        elif raw_allowed_pct > 0 and (float(out.get('dynamic_risk_score') or 0.0) > 0 or float(out.get('risk_multiplier') or 0.0) > 0):
            risk_pct = raw_allowed_pct
            risk_pct_src = raw_allowed_key

        # Never create Risk$ from a generic percentage only.  That was the cause of
        # repeated fake legacy values (for example 29.04) in the report.
        out['risk_usd'] = float(risk_usd or 0.0)
        out['risk_pct'] = float(risk_pct or 0.0)
        out['tp_usd'] = float(tp_usd or 0.0)
        out['risk_usd_source'] = str(risk_src or '')
        out['risk_pct_source'] = str(risk_pct_src or '')
        out['tp_usd_source'] = str(tp_src or '')
        out['risk_report_quality'] = 'real' if risk_src in {'stored_amount', 'geometry_qty', 'live_position_geometry'} else ('pct_only' if risk_pct > 0 else 'unknown')
        out['tp_report_quality'] = 'real' if tp_src in {'stored_amount', 'geometry_qty', 'rr_from_real_risk', 'live_position_geometry'} else 'unknown'
        if tp > 0:
            out['tp'] = float(tp)
        if risk_usd > 0 and tp_usd > 0:
            out['rr_tp'] = float(tp_usd / risk_usd)

        # Reporting-only repair: if the executed dynamic risk % is present but
        # the score was not persisted, infer the score/multiplier from config so
        # /autotrade_report remains analyzable instead of showing Dyn='-'.
        try:
            if float(out.get('risk_multiplier') or 0.0) <= 0 and float(out.get('risk_pct') or 0.0) > 0:
                _base_pct = float(out.get('configured_risk_pct') or _autotrade_risk_per_trade_pct() or 0.0)
                if _base_pct > 0:
                    out['risk_multiplier'] = float(out.get('risk_pct') or 0.0) / _base_pct
            if float(out.get('dynamic_risk_score') or 0.0) <= 0:
                _dyn = _autotrade_report_infer_dynamic_score(out)
                if _dyn > 0:
                    out['dynamic_risk_score'] = float(_dyn)
        except Exception:
            pass
    except Exception:
        pass
    return out

def _autotrade_report_expected_pnl_targets(row: dict) -> dict:
    """Expected TP/SL PnL from actual stored execution risk and setup geometry."""
    row = dict(row or {})
    try:
        entry = float(row.get('entry') or 0.0)
        sl = float(row.get('sl') or 0.0)
        side = str(row.get('side') or '').upper().strip()
        tp = float(_resolve_single_tp(entry, sl, row.get('tp'), row.get('alt_target_a'), row.get('alt_target_b'), side) or 0.0)
        qty = abs(float(row.get('qty') or row.get('filled_qty') or row.get('closed_qty') or 0.0))
        try:
            cs = float(row.get('contract_size') or row.get('contractSize') or 0.0)
            if cs <= 0:
                cs = float((_bybit_get_instr_filters(str(row.get('symbol') or '')) or {}).get('contractSize') or 1.0)
        except Exception:
            cs = 1.0
        risk_usd = 0.0
        for key in ('risk_usd', 'risk_usdt', 'risk', 'estimated_risk_usd', 'target_risk_usd', 'filled_risk_usd', 'risk_actual_usd'):
            try:
                v = abs(float(row.get(key) or 0.0))
                if v > risk_usd:
                    risk_usd = v
            except Exception:
                pass
        if entry > 0 and sl > 0 and qty > 0:
            risk_usd = max(risk_usd, abs(entry - sl) * qty * abs(float(cs or 1.0)))
        tp_usd = 0.0
        for key in ('tp_usd', 'tp_usdt', 'target_tp_usd', 'expected_tp_usd'):
            try:
                tp_usd = max(tp_usd, abs(float(row.get(key) or 0.0)))
            except Exception:
                pass
        if entry > 0 and tp > 0 and qty > 0:
            tp_usd = max(tp_usd, abs(tp - entry) * qty * abs(float(cs or 1.0)))
        elif tp_usd <= 0 and entry > 0 and sl > 0 and tp > 0 and risk_usd > 0:
            rr = abs(tp - entry) / max(abs(entry - sl), 1e-12)
            tp_usd = risk_usd * rr
        return {'TP': float(abs(tp_usd or 0.0)), 'SL': -float(abs(risk_usd or 0.0))}
    except Exception:
        return {'TP': 0.0, 'SL': 0.0}


def _autotrade_report_pnl_close_to_expected(row: dict, kind: str) -> bool:
    """True when realised PnL is close enough to expected TP/SL amount."""
    try:
        k = str(kind or '').upper().strip()
        if k not in {'TP', 'SL'}:
            return False
        pnl = float(row.get('pnl') if row.get('pnl') is not None else row.get('pnl_usdt') or 0.0)
        expected = float((_autotrade_report_expected_pnl_targets(row) or {}).get(k) or 0.0)
        if expected == 0:
            return False
        if k == 'TP' and pnl <= 0:
            return False
        if k == 'SL' and pnl >= 0:
            return False
        tol_abs = max(float(globals().get('AUTOTRADE_REPORT_TPSL_PNL_TOLERANCE_USD', 2.0) or 2.0), abs(expected) * float(globals().get('AUTOTRADE_REPORT_TPSL_PNL_TOLERANCE_PCT', 0.35) or 0.35))
        return abs(float(pnl) - float(expected)) <= tol_abs
    except Exception:
        return False


def _autotrade_report_pnl_sign_allows_kind(row: dict, kind: str) -> bool:
    """Prevent impossible report labels: positive PnL must not be shown as SL and negative PnL must not be shown as TP.

    Some exchange/order-history rows can say an SL order closed the position even when
    the realised PnL is positive, e.g. moved stop, breakeven/profit-protect stop, partial
    fragments, or stale lifecycle labels. User-facing reports must not label those as SL.
    They should be TP only if they are close to the configured TP amount, otherwise OTHER.
    """
    try:
        k = str(kind or '').upper().strip()
        pnl = float(row.get('pnl') if row.get('pnl') is not None else row.get('pnl_usdt') or 0.0)
        eps = float(globals().get('AUTOTRADE_REPORT_TPSL_SIGN_EPS_USD', 0.50) or 0.50)
        if k == 'SL' and pnl > eps:
            return False
        if k == 'TP' and pnl < -eps:
            return False
        return True
    except Exception:
        return False


def _autotrade_report_has_direct_tpsl_proof(row: dict, kind: str) -> bool:
    """Direct lifecycle/order proof, not merely PnL sign."""
    try:
        k = str(kind or '').upper().strip()
        row = dict(row or {})
        if not _autotrade_report_pnl_sign_allows_kind(row, k):
            return False
        path = str(row.get('result_path') or row.get('outcome') or '').upper().strip()
        label = str(row.get('result_label') or '').upper().strip()
        close_reason = str(row.get('close_reason') or '').lower().strip()
        source_bits = str(row.get('source') or row.get('source_bits') or row.get('source_note') or row.get('note') or '').lower()
        if k == 'TP':
            if float(row.get('tp_hit_ts') or 0.0) > 0 or float(row.get('alt_target_a_hit_ts') or 0.0) > 0:
                return True
            if 'tp' in close_reason and ('order_history' in source_bits or 'bybit_order_history' in source_bits):
                return True
            if (path in {'TP', 'HIT_TP_WIN'} or label == 'TP') and 'positive_closed_pnl' not in source_bits and 'exchange_closed_pnl_without_path_proof' not in source_bits and 'exchange_only_fallback_close' not in source_bits:
                return True
        if k == 'SL':
            if float(row.get('sl_hit_ts') or 0.0) > 0:
                return True
            if 'sl' in close_reason and ('order_history' in source_bits or 'bybit_order_history' in source_bits):
                return True
            if (path in {'SL', 'HIT_SL_LOSS'} or label == 'SL') and 'exchange_closed_pnl_without_path_proof' not in source_bits and 'exchange_only_fallback_close' not in source_bits:
                return True
        return False
    except Exception:
        return False


def _autotrade_report_closed_kind(row: dict) -> str:
    """Return the realised outcome label for AutoTrade reporting.

    Ver97: TP/SL labels must mean a real/near-target TP or SL close, not just
    positive/negative PnL.  Positive in-between/profit-protect exits are OTHER
    unless they are close to the expected TP amount or have direct TP proof.
    Losses remain SL when negative because Bybit realised loss is the account
    impact, but reporting repairs the displayed Risk$ separately when stored
    risk metadata is incomplete.
    """
    try:
        row = dict(row or {})
        if str(row.get('state') or '').upper().strip() == 'OPEN':
            return 'OPEN'
        path = str(row.get('result_path') or row.get('outcome') or '').upper().strip()
        label = str(row.get('result_label') or '').upper().strip()
        pnl = float(row.get('pnl') if row.get('pnl') is not None else row.get('pnl_usdt') or 0.0)
        eps = float(globals().get('AUTOTRADE_REPORT_TPSL_SIGN_EPS_USD', 0.50) or 0.50)

        exp = _autotrade_report_expected_pnl_targets(row) or {}
        tp_expected = abs(float(exp.get('TP') or 0.0))
        sl_expected = abs(float(exp.get('SL') or 0.0))
        source_txt = ' '.join(str(row.get(k) or '') for k in ('source', 'source_bits', 'source_note', 'note', 'close_reason')).lower()

        # For Bybit-Closed-PnL-authority rows we create result_path from PnL sign
        # during import; do not let that synthetic path become "direct TP proof".
        def _explicit_tpsl_proof(kind: str) -> bool:
            try:
                k = str(kind or '').upper().strip()
                if k == 'TP':
                    if float(row.get('tp_hit_ts') or 0.0) > 0 or float(row.get('alt_target_a_hit_ts') or 0.0) > 0:
                        return True
                    if 'tp' in str(row.get('close_reason') or '').lower() and 'order_history' in source_txt:
                        return True
                if k == 'SL':
                    if float(row.get('sl_hit_ts') or 0.0) > 0:
                        return True
                    if 'sl' in str(row.get('close_reason') or '').lower() and 'order_history' in source_txt:
                        return True
                if 'bybit_closed_pnl_authority' in source_txt or 'bybit_closed_pnl' in source_txt:
                    return False
                return _autotrade_report_has_direct_tpsl_proof(row, k)
            except Exception:
                return False

        if path in {'HIT_TP_THEN_BE_SL', 'HIT_TP_THEN_SL', 'TP', 'HIT_TP_WIN'} or label == 'TP':
            if _autotrade_report_pnl_sign_allows_kind(row, 'TP') and (_explicit_tpsl_proof('TP') or _autotrade_report_pnl_close_to_expected(row, 'TP')):
                return 'TP'
        if path in {'SL', 'HIT_SL_LOSS'} or label == 'SL':
            if _autotrade_report_pnl_sign_allows_kind(row, 'SL') and (_explicit_tpsl_proof('SL') or _autotrade_report_pnl_close_to_expected(row, 'SL') or pnl < -eps):
                return 'SL'

        if pnl > eps:
            # Do not call a small profit-protect / manual / exchange-only close TP
            # when it is far from the expected TP target.  This keeps WR and policy
            # self-improvement based on real target hits.
            if tp_expected > 0 and not _autotrade_report_pnl_close_to_expected(row, 'TP'):
                return 'OTHER'
            return 'TP'
        if pnl < -eps:
            # A realised loss is a risk event.  If stored Risk$ was incomplete or
            # too small, the display layer will backfill Risk$ from realised SL PnL.
            return 'SL'
        return 'FLAT'
    except Exception:
        return 'OTHER'

def _autotrade_report_repair_realized_amounts(row: dict) -> dict:
    """Repair user-facing Risk$/TP$ amounts for realised closes.

    The bot may have older rows where setup risk metadata is per-fragment, stale,
    or missing, while Bybit Closed P&L is authoritative.  For a realised SL, the
    actual account loss is the best available stop-loss dollar amount.  For a
    genuine realised TP, the actual realised profit is the best available TP$
    when stored TP$ is absent or clearly too small.  This is reporting-only and
    prevents misleading rows such as Risk$ $3.67 with PnL -$22.62.
    """
    out = dict(row or {})
    try:
        if str(out.get('state') or '').upper().strip() == 'OPEN':
            return out
        pnl = float(out.get('pnl') if out.get('pnl') is not None else out.get('pnl_usdt') or 0.0)
        kind = str(out.get('closed_kind') or out.get('result_label') or out.get('result_path') or '').upper().strip()
        eps = float(globals().get('AUTOTRADE_REPORT_TPSL_SIGN_EPS_USD', 0.50) or 0.50)
        risk = 0.0
        try:
            risk = abs(float(out.get('risk_usd') or out.get('risk_usdt') or out.get('filled_risk_usd') or out.get('risk_actual_usd') or 0.0))
        except Exception:
            risk = 0.0
        tp_usd = 0.0
        try:
            tp_usd = abs(float(out.get('tp_usd') or out.get('tp_usdt') or out.get('target_tp_usd') or out.get('expected_tp_usd') or 0.0))
        except Exception:
            tp_usd = 0.0
        # For actual SL rows, the realised negative PnL is the realised stop-loss
        # amount.  Backfill only when the existing Risk$ is missing or clearly
        # under-reports the loss by more than normal slippage/fees.
        if pnl < -eps and kind in {'SL', 'HIT_SL_LOSS'}:
            realized = abs(float(pnl))
            # ver99: for a row that is displayed as SL, the user-facing Risk$
            # must reconcile with the realised stop-loss impact.  Old/merged
            # rows can be under-stated (one fragment risk only) or over-stated
            # (summed risk from multiple fragments).  Repair in both directions
            # when the difference is outside normal slippage/fee tolerance.
            if realized > 0 and (
                risk <= 0
                or realized > max(risk * 1.35, risk + 3.0)
                or risk > max(realized * 1.35, realized + 3.0)
            ):
                out['risk_usd'] = float(realized)
                out['risk_usdt'] = float(realized)
                out['risk_usd_source'] = 'realized_sl_pnl'
                out['risk_report_quality'] = 'realized_sl_pnl'
        # For genuine TP rows, repair TP$ when stored target is missing or far
        # from realised TP PnL in either direction.
        if pnl > eps and kind in {'TP', 'HIT_TP_WIN'}:
            realized = abs(float(pnl))
            if realized > 0 and (
                tp_usd <= 0
                or realized > max(tp_usd * 1.35, tp_usd + 3.0)
                or tp_usd > max(realized * 1.35, realized + 3.0)
            ):
                out['tp_usd'] = float(realized)
                out['tp_usdt'] = float(realized)
                out['tp_usd_source'] = 'realized_tp_pnl'
                out['tp_report_quality'] = 'realized_tp_pnl'
        try:
            eq = float(out.get('equity') or out.get('equity_usdt') or out.get('report_equity') or out.get('_report_equity') or 0.0)
            if eq > 0 and float(out.get('risk_usd') or 0.0) > 0:
                out['risk_pct'] = float(out.get('risk_usd') or 0.0) / eq * 100.0
                if str(out.get('risk_report_quality') or '').lower() == 'realized_sl_pnl':
                    out['risk_pct_source'] = 'realized_sl_pnl'
            elif str(out.get('risk_report_quality') or '').lower() == 'realized_sl_pnl':
                # Avoid showing a stale Risk% beside a repaired Risk$.
                out['risk_pct'] = ''
                out['risk_pct_source'] = ''
        except Exception:
            pass
    except Exception:
        return out
    return out

def _autotrade_merge_position_report_rows(rows: list[dict], merge_window_sec: int | None = None) -> list[dict]:
    """Merge raw report fragments into one row per practical position close.

    Bybit may return several closed-PnL records for one position close because of partial
    fills, fees, legacy partial TP/SL children, or force-close fragments. The user-facing
    report should count that as one position. Open rows are already one per live position.
    """
    try:
        window = max(60, int(merge_window_sec if merge_window_sec is not None else AUTOTRADE_REPORT_POSITION_MERGE_WINDOW_SEC))
    except Exception:
        window = 420
    src = [dict(r or {}) for r in (rows or [])]
    open_rows = [r for r in src if str(r.get('state') or '').upper().strip() == 'OPEN']
    closed = [r for r in src if str(r.get('state') or '').upper().strip() != 'OPEN']
    closed.sort(key=lambda r: float(r.get('ts') or r.get('closed_ts') or 0.0))
    groups: list[dict] = []

    def _family(r: dict) -> str:
        return str(r.get('family') or r.get('fam') or r.get('engine') or 'F0').upper().strip() or 'F0'

    for r in closed:
        try:
            sym = str(r.get('symbol') or '').upper().strip()
            side = str(r.get('side') or '').upper().strip()
            fam = _family(r)
            sess = _autotrade_report_row_session(r)
            strat = _setup_strategy_short_label(r)
            ts = float(r.get('ts') or r.get('closed_ts') or 0.0)
            pnl = float(r.get('pnl') if r.get('pnl') is not None else r.get('pnl_usdt') or 0.0)
            matched = None
            # Prefer exact setup/trade id when available. Otherwise cluster same symbol/side/family/session
            # when the closes are only a few minutes apart.
            sid = str(r.get('setup_id') or '').strip()
            tid = str(r.get('trade_id') or '').strip()
            for g in reversed(groups):
                if str(g.get('symbol') or '') != sym or str(g.get('side') or '') != side or str(g.get('family') or '') != fam:
                    continue
                if str(g.get('session') or '') != sess:
                    continue
                if _setup_strategy_short_label(g) != strat:
                    continue
                gsid = str(g.get('setup_id') or '').strip()
                gtid = str(g.get('trade_id') or '').strip()
                if sid and gsid and sid == gsid:
                    matched = g
                    break
                if tid and gtid and tid == gtid:
                    matched = g
                    break
                if abs(ts - float(g.get('last_ts') or g.get('ts') or 0.0)) <= float(window):
                    matched = g
                    break
            if matched is None:
                nr = dict(r)
                nr['state'] = 'CLOSED'
                nr['symbol'] = sym
                nr['side'] = side
                nr['family'] = fam
                nr['session'] = sess
                nr['setup_strategy'] = _setup_strategy_label(r)
                nr['strategy'] = nr['setup_strategy']
                nr['pnl'] = float(pnl)
                nr['parts'] = int(r.get('parts') or 1)
                nr['first_ts'] = float(ts or 0.0)
                nr['last_ts'] = float(ts or 0.0)
                nr['ts'] = float(ts or 0.0)
                # v95: for merged report rows, Close must follow the latest
                # Bybit close event.  Do not leave a stale/first closed_ts on
                # rows that later absorb additional Closed-PnL fragments.
                nr['closed_ts'] = float(ts or nr.get('closed_ts') or 0.0)
                nr['closed_kind_votes'] = [_autotrade_report_closed_kind(r)]
                groups.append(nr)
            else:
                matched['pnl'] = float(matched.get('pnl') or 0.0) + float(pnl)
                matched['pnl_usdt'] = float(matched.get('pnl') or 0.0)
                # Preserve the best available execution/reporting metadata for the merged position.
                # For Risk$/TP$, the merged practical row must represent the whole
                # realised position, not only the first fragment.  Sum real/stored
                # amounts when multiple exchange fragments are absorbed; the later
                # realised-PnL repair below also protects old rows where fragment
                # quantity/risk was missing.
                for _sumk in ('risk_usd', 'risk_usdt', 'filled_risk_usd', 'risk_actual_usd', 'tp_usd', 'tp_usdt'):
                    try:
                        rv = abs(float(r.get(_sumk) or 0.0))
                        if rv > 0:
                            matched[_sumk] = abs(float(matched.get(_sumk) or 0.0)) + rv
                    except Exception:
                        pass
                for _mk in ('risk_pct', 'risk_usd_source', 'risk_pct_source', 'tp_usd_source', 'risk_report_quality', 'tp_report_quality', 'risk_multiplier', 'dynamic_risk_score', 'configured_risk_pct', 'allowed_risk_pct', 'rr_tp', 'entry', 'sl', 'tp', 'qty', 'conf', 'fut_vol_usd', 'ch24', 'ch4', 'ch1', 'setup_strategy', 'strategy', 'strategy_mode', 'original_setup_id', 'original_side', 'strategy_reason', 'policy_at_open', 'policy_combo_at_open', 'policy_execnow_at_open'):
                    try:
                        if float(matched.get(_mk) or 0.0) <= 0 and float(r.get(_mk) or 0.0) > 0:
                            matched[_mk] = r.get(_mk)
                    except Exception:
                        if not str(matched.get(_mk) or '').strip() and str(r.get(_mk) or '').strip():
                            matched[_mk] = r.get(_mk)
                matched['parts'] = int(matched.get('parts') or 1) + int(r.get('parts') or 1)
                matched['first_ts'] = min(float(matched.get('first_ts') or ts), float(ts or 0.0))
                matched['last_ts'] = max(float(matched.get('last_ts') or ts), float(ts or 0.0))
                matched['ts'] = float(matched.get('last_ts') or matched.get('ts') or ts)
                # v95: make the displayed Close column equal the newest
                # exchange close time after merging partial fragments.
                try:
                    matched['closed_ts'] = max(float(matched.get('closed_ts') or 0.0), float(ts or 0.0))
                except Exception:
                    matched['closed_ts'] = float(ts or matched.get('closed_ts') or 0.0)
                votes = list(matched.get('closed_kind_votes') or [])
                votes.append(_autotrade_report_closed_kind(r))
                matched['closed_kind_votes'] = votes
                # Keep latest display time for the merged close.
                matched['time'] = r.get('time') or matched.get('time')
        except Exception:
            groups.append(dict(r))

    # Decide merged realised result after summing PnL. Ver27 uses sign-sane
    # realised outcome classification so profitable exchange/time closes are not
    # reported as OTHER and losing exchange/time closes are not reported as TP.
    for g in groups:
        try:
            kind = _autotrade_report_closed_kind(g)
            g['closed_kind'] = kind
            g['exit_reason'] = _autotrade_report_exit_reason(g, kind)
            if kind == 'TP':
                g['result_path'] = 'HIT_TP_WIN'; g['result_label'] = 'TP'
            elif kind == 'SL':
                g['result_path'] = 'HIT_SL_LOSS'; g['result_label'] = 'SL'
            elif kind == 'FLAT':
                g['result_path'] = 'MANUAL_OR_UNKNOWN_CLOSE'; g['result_label'] = 'FLAT'
            else:
                g['result_path'] = 'MANUAL_OR_UNKNOWN_CLOSE'; g['result_label'] = 'OTHER'
            try:
                repaired = _autotrade_report_repair_realized_amounts(g)
                g.update(repaired)
            except Exception:
                pass
        except Exception:
            pass
    out = list(open_rows) + list(groups)
    out.sort(key=lambda r: float(r.get('ts') or r.get('last_ts') or 0.0), reverse=True)
    return out



def _autotrade_combo_side_from_key(combo: str = '') -> str:
    try:
        parts = [x for x in str(combo or '').upper().strip().split('-') if x]
        if len(parts) >= 4 and parts[-1] in {'BUY', 'SELL'}:
            return parts[-1]
    except Exception:
        pass
    return ''


def _autotrade_combo_parts_from_key(combo: str = '') -> tuple[str, str, str, str]:
    try:
        parts = [x for x in str(combo or '').upper().strip().split('-') if x]
        if len(parts) >= 4:
            fam, sess, strat, side = parts[0], parts[1], parts[2], parts[3]
            if side in {'BUY', 'SELL'}:
                return fam, sess, strat, side
    except Exception:
        pass
    return 'F0', 'UNK', 'NOR', ''


def _autotrade_report_bybit_canonical_closed_rows(owner_uid: int, start_ts: float, end_ts: float, lookback_h: int = 24, report_equity: float = 0.0) -> list[dict]:
    """Return closed rows using Bybit Closed-PnL as the time/PnL authority.

    This keeps /autotrade_report aligned with /autotrade_closed. Bot journal and
    lifecycle rows are used only as metadata enrichment (combo, risk, setup fields),
    never as the source of the exchange close time or realised PnL.
    """
    if str(_autotrade_runtime_mode()).lower() != 'live':
        return []
    owner_uid = int(owner_uid or 0)
    start_ts = float(start_ts or 0.0)
    end_ts = float(end_ts or 0.0)
    try:
        bybit_events = _bybit_get_closed_pnl_linear(float(start_ts), float(end_ts) + 60.0, limit=max(200, min(10000, int(max(1, lookback_h)) * 100))) or []
    except Exception:
        bybit_events = []
    if not bybit_events:
        return []

    def _num(row: dict, keys: tuple[str, ...]) -> float:
        for k in keys:
            try:
                v = (row or {}).get(k)
                if v is None or str(v).strip() == '':
                    continue
                x = float(v)
                if x != 0:
                    return x
            except Exception:
                continue
        return 0.0

    def _closed_ts(ev: dict) -> float:
        try:
            for k in ('updatedTime', 'updated_time', 'closed_ts', 'close_ts', 'exit_ts', 'closeTime', 'closedTime', 'createdTime', 'created_time', 'execTime', 'fillTime', 'last_ts', 'updated_ts', 'ts'):
                try:
                    v = (ev or {}).get(k)
                    ts = float(_ts_seconds_from_any(v) or 0.0)
                    if ts > 0:
                        return ts
                except Exception:
                    pass
        except Exception:
            pass
        try:
            return float(_bybit_closed_pnl_event_ts(ev) or 0.0)
        except Exception:
            return 0.0

    def _position_side(ev: dict) -> str:
        raw = str((ev or {}).get('side') or '').upper().strip()
        if raw not in {'BUY', 'SELL'}:
            raw = ''
        try:
            entry = abs(float(_num(ev, ('avgEntryPrice', 'avg_entry_price', 'entryPrice', 'entry_price')) or 0.0))
            exitp = abs(float(_num(ev, ('avgExitPrice', 'avg_exit_price', 'exitPrice', 'exit_price', 'orderPrice', 'price')) or 0.0))
            pnl = float((ev or {}).get('closedPnl') if (ev or {}).get('closedPnl') is not None else (ev or {}).get('pnl') or 0.0)
            if entry > 0 and exitp > 0 and abs(exitp - entry) > max(entry * 1e-7, 1e-12) and abs(pnl) >= 0.50:
                if pnl > 0:
                    return 'BUY' if exitp > entry else 'SELL'
                if pnl < 0:
                    return 'BUY' if exitp < entry else 'SELL'
        except Exception:
            pass
        return raw or '-'

    def _risk_value(row: dict, ev: dict | None = None) -> float:
        ev = ev or {}
        try:
            v = float((row or {}).get('risk_usd') or (row or {}).get('risk_usdt') or (row or {}).get('filled_risk_usd') or (row or {}).get('risk_actual_usd') or 0.0)
            if v > 0:
                return v
        except Exception:
            pass
        try:
            entry = abs(float((row or {}).get('entry') or ev.get('avgEntryPrice') or ev.get('avg_entry_price') or ev.get('entryPrice') or ev.get('entry_price') or 0.0))
            sl = abs(float((row or {}).get('sl') or (row or {}).get('stopLoss') or (row or {}).get('stop_loss') or 0.0))
            qty = abs(float(_bybit_closed_pnl_event_qty(ev) or (row or {}).get('qty') or (row or {}).get('filled_qty') or (row or {}).get('closed_qty') or 0.0))
            if entry > 0 and sl > 0 and qty > 0:
                try:
                    cs = float((row or {}).get('contract_size') or (row or {}).get('contractSize') or ev.get('contractSize') or 0.0)
                    if cs <= 0:
                        cs = float((_bybit_get_instr_filters(str((row or {}).get('symbol') or ev.get('symbol') or '')) or {}).get('contractSize') or 1.0)
                except Exception:
                    cs = 1.0
                return abs(entry - sl) * qty * abs(float(cs or 1.0))
        except Exception:
            pass
        return 0.0

    def _combo_cell(row: dict) -> str:
        try:
            for k in ('combo', 'combo_key', 'combo_side_key', 'combo_strategy_side'):
                v = str((row or {}).get(k) or '').upper().strip()
                if v and v != '-':
                    return v
            combo = str(_autotrade_setup_exact_combo_key(row) or '').upper().strip()
            if combo and combo not in {'F0-UNK-NOR-BOTH', 'F0-UNK-NOR', 'F0---NOR'}:
                return combo
            fam = _setup_audit_family_code(row) if isinstance(row, dict) else 'F0'
            sess = str((row or {}).get('session') or (row or {}).get('source_session') or '-').upper().strip() or '-'
            strat = _setup_strategy_suffix(row)
            side = str((row or {}).get('side') or '').upper().strip()
            combo = _setup_combo_strategy_side_key(fam, sess, strat, side)
            return combo if combo and 'UNK' not in combo else '-'
        except Exception:
            return '-'

    try:
        enrich_rows = _autotrade_closed_report_rows(owner_uid, float(start_ts) - 30 * 3600.0, float(end_ts) + 6 * 3600.0, lookback_h=max(lookback_h, 48), limit=0) or []
    except Exception:
        enrich_rows = []

    candidates = []
    for er in list(enrich_rows or []):
        try:
            row = _setup_audit_merge_trade_setup_row(dict(er or {}))
            row = _autotrade_report_enrich_amounts(row, float(report_equity or 0.0))
            sym = str(_bybit_linear_symbol(row.get('symbol') or er.get('symbol') or '')).upper().strip()
            if not sym:
                continue
            combo = _combo_cell(row)
            side = str(row.get('side') or er.get('side') or '').upper().strip()
            combo_side = _autotrade_combo_side_from_key(combo)
            if combo_side in {'BUY', 'SELL'}:
                side = combo_side
            cts = 0.0
            for k in ('closed_ts', 'last_ts', 'ts', 'updated_ts'):
                try:
                    cts = float(row.get(k) or er.get(k) or 0.0)
                    if cts > 0:
                        break
                except Exception:
                    pass
            pnl = float(row.get('pnl_usdt') if row.get('pnl_usdt') is not None else row.get('pnl') or er.get('pnl_usdt') or er.get('pnl') or 0.0)
            candidates.append({'symbol': sym, 'side': side, 'combo': combo, 'closed_ts': float(cts or 0.0), 'opened_ts': float(row.get('opened_ts') or er.get('opened_ts') or 0.0), 'pnl': float(pnl), 'risk_usd': _risk_value(row), 'row': dict(row or {})})
        except Exception:
            continue

    def _match(sym: str, side: str, pnl: float, ts: float, ev: dict) -> dict:
        best = None
        best_score = 10**18
        side = str(side or '').upper().strip()
        for cand in candidates:
            try:
                if str(cand.get('symbol') or '') != sym:
                    continue
                cside = str(cand.get('side') or '').upper().strip()
                combo = str(cand.get('combo') or '').upper().strip()
                combo_side = _autotrade_combo_side_from_key(combo)
                # Never attach BUY-lane metadata/risk to a SELL close, or vice versa.
                if side in {'BUY', 'SELL'}:
                    if combo_side in {'BUY', 'SELL'} and combo_side != side:
                        continue
                    if cside in {'BUY', 'SELL'} and cside != side and combo_side not in {'BUY', 'SELL'}:
                        continue
                cts = float(cand.get('closed_ts') or 0.0)
                ots = float(cand.get('opened_ts') or 0.0)
                cpnl = float(cand.get('pnl') or 0.0)
                pnl_diff = abs(cpnl - float(pnl or 0.0))
                # yver146: never enrich an exchange close with a candidate whose
                # recorded/opened time is after the Bybit close. This was causing
                # /autotrade_report to display a future setup combo for an older
                # close while /autotrade_closed showed the correct older lifecycle.
                if ots > 0 and ts > 0 and ots > ts + 300.0:
                    continue
                if cts > 0 and ts > 0:
                    dt = abs(ts - cts)
                elif ots > 0 and ts > 0 and ots <= ts + 300.0:
                    dt = min(abs(ts - ots), 24 * 3600.0)
                else:
                    dt = 999999.0
                # Accept old journal close timestamps only when PnL is effectively
                # the same; otherwise keep the Bybit event unlinked instead of
                # showing wrong combo/risk.
                if dt > 6 * 3600.0 and pnl_diff > 0.25:
                    continue
                if dt > 48 * 3600.0:
                    continue
                exact_bonus = -500000.0 if (cts > 0 and ts > 0 and abs(float(ts) - float(cts)) <= 3.0 and pnl_diff <= 0.05) else 0.0
                score = exact_bonus + dt * 10.0 + min(pnl_diff, 100.0) * 250.0
                if score < best_score:
                    best = cand
                    best_score = score
            except Exception:
                continue
        return dict(best or {})

    seen = set()
    out = []
    for ev in bybit_events:
        try:
            ts = float(_closed_ts(ev) or 0.0)
            if ts <= 0 or ts < start_ts or ts > end_ts + 120.0:
                continue
            sym = str(_bybit_linear_symbol((ev or {}).get('symbol') or '')).upper().strip()
            if not sym:
                continue
            pnl = float((ev or {}).get('closedPnl') if (ev or {}).get('closedPnl') is not None else (ev or {}).get('pnl') or 0.0)
            side = _position_side(ev)
            key = (sym, int(round(ts * 1000)), str((ev or {}).get('orderId') or (ev or {}).get('execId') or (ev or {}).get('createdTime') or ''), round(pnl, 8), round(float(_bybit_closed_pnl_event_qty(ev) or 0.0), 8))
            if key in seen:
                continue
            seen.add(key)
            cand = _match(sym, side, pnl, ts, ev)
            base = dict(cand.get('row') or {}) if cand else {}
            combo = str(cand.get('combo') or '').upper().strip() if cand else '-'
            if combo and combo != '-' and _autotrade_combo_side_from_key(combo) not in {'', side}:
                combo = '-'
                base = {}
            risk = float(cand.get('risk_usd') or 0.0) if cand else 0.0
            if risk <= 0 and base:
                risk = _risk_value(base, ev)
            fam, sess, strat, combo_side = _autotrade_combo_parts_from_key(combo)
            if combo_side in {'BUY', 'SELL'} and side in {'BUY', 'SELL'} and combo_side != side:
                combo = '-'; fam, sess, strat = 'F0', 'UNK', 'NOR'
            kind = 'TP' if pnl > 0.05 else ('SL' if pnl < -0.05 else 'OTHER')
            row = dict(base or {})
            row.update({
                'state': 'CLOSED', 'status': 'CLOSED', 'symbol': sym, 'side': side,
                'closed_ts': float(ts), 'last_ts': float(ts), 'ts': float(ts),
                'pnl': float(pnl), 'pnl_usdt': float(pnl),
                'closed_kind': kind, 'result_path': kind, 'result_label': kind,
                'close_reason': str(row.get('close_reason') or 'BYBIT_CLOSED_PNL'),
                'note': str(row.get('note') or 'bybit_closed_pnl_authority'),
                'exchange_close_time_authority': True,
                'parts': 1,
            })
            if combo and combo != '-':
                row['combo'] = combo
                row['family'] = fam
                row['session'] = sess
                row['setup_strategy'] = strat
                row['strategy'] = strat
            if risk > 0:
                row['risk_usd'] = float(risk)
            # Fill basic exchange quantities/prices for risk/debug display.
            try:
                row.setdefault('qty', abs(float(_bybit_closed_pnl_event_qty(ev) or 0.0)))
                row.setdefault('entry', abs(float(_num(ev, ('avgEntryPrice', 'avg_entry_price', 'entryPrice', 'entry_price')) or 0.0)))
            except Exception:
                pass
            out.append(row)
        except Exception:
            continue
    out.sort(key=lambda r: float((r or {}).get('closed_ts') or 0.0), reverse=True)
    return out

def _autotrade_report_text_cached(owner_uid: int, lookback_h: int) -> str:
    """AutoTrade journal: one row per practical position, sorted by latest time.

    Ver06 merges raw Bybit closed-PnL fragments for the same symbol/side/family/session
    into one position row, so BLEND/ZEREBRO-style dust fragments do not inflate Trades.
    """
    owner_uid = int(owner_uid)
    lookback_h = int(clamp(int(lookback_h or 24), 1, 168))
    cache_key = f"autotrade_report_text:v58_atpol:{owner_uid}:{lookback_h}"
    try:
        if cache_valid(cache_key, int(AUTOTRADE_REPORT_CACHE_TTL_SEC or 20)):
            cached = cache_get(cache_key)
            if isinstance(cached, str) and cached.strip():
                return cached
    except Exception:
        pass

    _autotrade_migrate_tables()
    try:
        _migrate_generated_setups()
    except Exception:
        pass
    now_ts = float(time.time())
    start_ts = now_ts - float(lookback_h) * 3600.0
    try:
        _report_equity = float(_effective_equity_for_risk(_autotrade_user_settings(owner_uid), prefer_live=(str(_autotrade_runtime_mode()).lower() == 'live')) or 0.0)
    except Exception:
        _report_equity = 0.0

    open_positions = _bybit_get_open_positions_linear() if str(_autotrade_runtime_mode()).lower() == 'live' else []
    bot_positions, external_positions, _journal_open = _autotrade_collect_live_position_rows(owner_uid, positions=open_positions, fallback_unmatched_as_owned=True)
    try:
        closed_rows = _autotrade_report_bybit_canonical_closed_rows(owner_uid, float(start_ts), float(now_ts), lookback_h=lookback_h, report_equity=_report_equity) or []
        if not closed_rows:
            closed_rows = _autotrade_closed_report_rows(owner_uid, float(start_ts), float(now_ts), lookback_h=lookback_h, limit=0) or []
    except Exception:
        try:
            closed_rows = _autotrade_closed_report_rows(owner_uid, float(start_ts), float(now_ts), lookback_h=lookback_h, limit=0) or []
        except Exception:
            closed_rows = []

    total_open = 0.0
    total_closed = 0.0
    journal_rows = []

    def _family_for_report(row: dict) -> str:
        try:
            fam = _setup_audit_family_display(row, compact=True)
            if fam and fam != '-':
                return fam
            eng = str((row or {}).get('engine') or '').strip()
            fam2 = _setup_family_id_to_code(_setup_engine_to_family_id(eng, row))
            return fam2 if fam2 and fam2 != '-' else 'F0'
        except Exception:
            return 'F0'

    def _sym_display(row: dict, fallback: str = '') -> str:
        try:
            sym = str((row or {}).get('symbol') or fallback or '').upper().strip()
            if sym.endswith('USDT'):
                sym = sym[:-4]
            return sym or '-'
        except Exception:
            return '-'

    def _ts_value(row: dict, fallback: float = 0.0) -> float:
        for k in ('closed_ts', 'opened_ts', 'created_ts', 'updated_ts', 'email_logged_ts', 'emailed_ts'):
            try:
                v = float((row or {}).get(k) or 0.0)
                if v > 0:
                    return v
            except Exception:
                pass
        return float(fallback or 0.0)

    def _ts_txt(ts: float) -> str:
        try:
            return datetime.fromtimestamp(float(ts or 0.0), tz=timezone.utc).astimezone(MEL_TZ).strftime('%m-%d %H:%M')
        except Exception:
            return '-'

    def _report_display_open_close_ts(r: dict) -> tuple[float, float]:
        """Return sane Melbourne display timestamps for /autotrade_report.

        Exchange-only/merged close fragments can occasionally inherit setup/open
        metadata newer than the realised close record.  Never display an impossible
        Open time later than Close time; fall back to the earliest reliable fragment
        timestamp for that merged row.
        """
        try:
            state = str((r or {}).get('state') or '').upper().strip()
            open_ts = float((r or {}).get('opened_ts') or (r or {}).get('first_ts') or (r or {}).get('ts') or 0.0)
            close_ts = 0.0
            if state != 'OPEN':
                close_ts = float((r or {}).get('closed_ts') or (r or {}).get('last_ts') or (r or {}).get('ts') or 0.0)
                if close_ts > 0 and (open_ts <= 0 or open_ts > close_ts):
                    candidates = []
                    for k in ('first_ts', 'ts', 'created_ts', 'updated_ts', 'opened_ts'):
                        try:
                            v = float((r or {}).get(k) or 0.0)
                            if v > 0 and v <= close_ts:
                                candidates.append(v)
                        except Exception:
                            pass
                    open_ts = min(candidates) if candidates else close_ts
            return float(open_ts or 0.0), float(close_ts or 0.0)
        except Exception:
            return 0.0, 0.0

    for p, tr in (bot_positions or []):
        row = _setup_audit_merge_trade_setup_row(tr)
        # yver106: for OPEN rows, Bybit live position geometry is the authority for
        # displayed Risk$/TP$. Stored setup metadata can be stale after entry slippage or
        # TP RR capping, so override entry/SL/TP/qty from the live position when present.
        try:
            _live_entry = float(_pos_entry(p) or 0.0)
            _live_sl = float(_pos_stop(p) or 0.0)
            _live_tp = float(_pos_take_profit(p) or 0.0)
            _live_qty = abs(float(_pos_size(p) or 0.0))
            if _live_entry > 0:
                row['entry'] = float(_live_entry)
            if _live_sl > 0:
                row['sl'] = float(_live_sl)
            if _live_tp > 0:
                row['tp'] = float(_live_tp)
            if _live_qty > 0:
                row['qty'] = float(_live_qty)
            _live_risk = float(_estimate_position_risk_usd(p) or 0.0)
            _live_tp_usd = float(_estimate_position_tp_usd(p) or 0.0)
            if _live_risk > 0:
                row['risk_usd'] = float(_live_risk)
                row['risk_actual_usd'] = float(_live_risk)
                row['risk_usd_source'] = 'live_position_geometry'
            if _live_tp_usd > 0:
                row['tp_usd'] = float(_live_tp_usd)
                row['tp_usd_source'] = 'live_position_geometry'
        except Exception:
            pass
        row = _autotrade_report_enrich_amounts(row, _report_equity)
        side = str(row.get('side') or _pos_side_text(p) or '').upper().strip() or '-'
        pnl = float(_pos_unreal_pnl(p) or 0.0)
        total_open += pnl
        ts = _ts_value(row, now_ts)
        journal_rows.append({
            'ts': ts,
            'time': _ts_txt(ts),
            'state': 'OPEN',
            'symbol': _sym_display(row, _pos_symbol(p)),
            'side': side,
            'setup_strategy': _setup_strategy_label(row),
            'strategy': _setup_strategy_label(row),
            'family': _family_for_report(row),
            'session': _autotrade_report_row_session(row),
            'setup_id': str(row.get('setup_id') or ''),
            'trade_id': str(row.get('trade_id') or ''),
            'policy_at_open': str(row.get('policy_at_open') or ''),
            'policy_combo_at_open': str(row.get('policy_combo_at_open') or ''),
            'policy_execnow_at_open': str(row.get('policy_execnow_at_open') or ''),
            'opened_ts': float(row.get('opened_ts') or ts or 0.0),
            'entry': float(row.get('entry') or 0.0),
            'sl': float(row.get('sl') or 0.0),
            'tp': float(row.get('tp') or 0.0),
            'qty': float(row.get('qty') or 0.0),
            'conf': int(float(row.get('conf') or row.get('confidence') or 0.0)),
            'fut_vol_usd': float(row.get('fut_vol_usd') or 0.0),
            'ch24': float(row.get('ch24') or 0.0),
            'ch4': float(row.get('ch4') or 0.0),
            'ch1': float(row.get('ch1') or 0.0),
            'pnl': pnl,
            'parts': 1,
            'risk_usd': float(row.get('risk_usd') or 0.0),
            'risk_pct': float(row.get('risk_pct') or 0.0),
            'tp_usd': float(row.get('tp_usd') or 0.0),
            'risk_usd_source': str(row.get('risk_usd_source') or ''),
            'risk_pct_source': str(row.get('risk_pct_source') or ''),
            'tp_usd_source': str(row.get('tp_usd_source') or ''),
            'risk_report_quality': str(row.get('risk_report_quality') or ''),
            'tp_report_quality': str(row.get('tp_report_quality') or ''),
            'dynamic_risk_score': float(row.get('dynamic_risk_score') or 0.0),
            'risk_multiplier': float(row.get('risk_multiplier') or 0.0),
            'close_reason': 'OPEN',
            'note': str(row.get('note') or ''),
            'closed_kind': 'OPEN',
            'exit_reason': 'OPEN',
        })

    for r in (closed_rows or []):
        row = _setup_audit_merge_trade_setup_row(r)
        row = _autotrade_report_enrich_amounts(row, _report_equity)
        side = str(row.get('side') or r.get('side') or '').upper().strip() or '-'
        try:
            pnl = float(row.get('pnl_usdt') if row.get('pnl_usdt') is not None else row.get('pnl') or 0.0)
        except Exception:
            pnl = 0.0
        total_closed += pnl
        ts = _ts_value(row, float((r or {}).get('closed_ts') or (r or {}).get('opened_ts') or 0.0))
        journal_rows.append({
            'ts': ts,
            'time': _ts_txt(ts),
            'state': 'CLOSED',
            'symbol': _sym_display(row, r.get('symbol') or ''),
            'side': side,
            'setup_strategy': _setup_strategy_label(row),
            'strategy': _setup_strategy_label(row),
            'family': _family_for_report(row),
            'session': _autotrade_report_row_session(row),
            'setup_id': str(row.get('setup_id') or r.get('setup_id') or ''),
            'trade_id': str(row.get('trade_id') or r.get('trade_id') or ''),
            'policy_at_open': str(row.get('policy_at_open') or r.get('policy_at_open') or ''),
            'policy_combo_at_open': str(row.get('policy_combo_at_open') or r.get('policy_combo_at_open') or ''),
            'policy_execnow_at_open': str(row.get('policy_execnow_at_open') or r.get('policy_execnow_at_open') or ''),
            'opened_ts': float(row.get('opened_ts') or r.get('opened_ts') or 0.0),
            'closed_ts': float(row.get('closed_ts') or r.get('closed_ts') or ts or 0.0),
            'result_path': str(row.get('result_path') or r.get('result_path') or ''),
            'result_label': str(row.get('result_label') or r.get('result_label') or ''),
            'close_reason': str(row.get('close_reason') or r.get('close_reason') or ''),
            'note': str(row.get('note') or r.get('note') or ''),
            'source_note': str(row.get('source_note') or r.get('source_note') or ''),
            'entry': float(row.get('entry') or r.get('entry') or 0.0),
            'sl': float(row.get('sl') or r.get('sl') or 0.0),
            'tp': float(row.get('tp') or r.get('tp') or 0.0),
            'qty': float(row.get('qty') or r.get('qty') or 0.0),
            'conf': int(float(row.get('conf') or r.get('conf') or row.get('confidence') or 0.0)),
            'fut_vol_usd': float(row.get('fut_vol_usd') or r.get('fut_vol_usd') or 0.0),
            'ch24': float(row.get('ch24') or r.get('ch24') or 0.0),
            'ch4': float(row.get('ch4') or r.get('ch4') or 0.0),
            'ch1': float(row.get('ch1') or r.get('ch1') or 0.0),
            'pnl': pnl,
            'pnl_usdt': pnl,
            'parts': 1,
            'risk_usd': float(row.get('risk_usd') or 0.0),
            'risk_pct': float(row.get('risk_pct') or 0.0),
            'tp_usd': float(row.get('tp_usd') or 0.0),
            'risk_usd_source': str(row.get('risk_usd_source') or ''),
            'risk_pct_source': str(row.get('risk_pct_source') or ''),
            'tp_usd_source': str(row.get('tp_usd_source') or ''),
            'risk_report_quality': str(row.get('risk_report_quality') or ''),
            'tp_report_quality': str(row.get('tp_report_quality') or ''),
            'dynamic_risk_score': float(row.get('dynamic_risk_score') or r.get('dynamic_risk_score') or 0.0),
            'risk_multiplier': float(row.get('risk_multiplier') or r.get('risk_multiplier') or 0.0),
            'closed_kind': _autotrade_report_closed_kind(row),
            'exit_reason': _autotrade_report_exit_reason(row),
        })

    journal_rows = _autotrade_merge_position_report_rows(journal_rows)

    # yver78: /autotrade_report must be ordered by the Open column, not by
    # latest close/update time. Closed rows can otherwise jump ahead of newer
    # opens just because they closed recently. Keep newest opens first.
    def _open_time_sort_key(x: dict) -> tuple[float, float]:
        try:
            open_ts, close_ts = _report_display_open_close_ts(x)
            if float(open_ts or 0.0) <= 0:
                open_ts = float((x or {}).get('opened_ts') or (x or {}).get('first_ts') or (x or {}).get('ts') or 0.0)
            if float(close_ts or 0.0) <= 0:
                close_ts = float((x or {}).get('closed_ts') or (x or {}).get('last_ts') or (x or {}).get('ts') or 0.0)
            return (float(open_ts or 0.0), float(close_ts or 0.0))
        except Exception:
            return (float((x or {}).get('opened_ts') or (x or {}).get('ts') or 0.0), float((x or {}).get('ts') or 0.0))

    journal_rows.sort(key=_open_time_sort_key, reverse=True)
    try:
        now_txt = datetime.fromtimestamp(now_ts, tz=timezone.utc).astimezone(MEL_TZ).strftime('%Y-%m-%d %H:%M')
    except Exception:
        now_txt = ''
    lines = [
        "📒 <b>AutoTrade Journal</b>",
        HDR,
        f"Window: <b>last {lookback_h}h</b> (Melbourne)" + (f" | Now: <b>{html.escape(now_txt)}</b>" if now_txt else ""),
        f"Trades: <b>{len(journal_rows)}</b> | Open PnL: <b>{total_open:+.2f}</b> | Closed PnL: <b>{total_closed:+.2f}</b> | Total PnL: <b>{(total_open + total_closed):+.2f} USDT</b>",
        "Result: TP=win/profitable close, SL=loss, FLAT=near-zero. ATPol shows the stored AutoTrade open-time policy snapshot. Reason shows TP_HIT, SL_HIT, CLOSE_BEFORE_ASIA_SESSION, MAX_HOLD, PROFIT_CLOSE, or the best inferred close cause.",
    ]
    if external_positions:
        lines.append(f"Ignored unmatched manual/external live positions: <b>{len(external_positions)}</b>")
    if not journal_rows:
        lines.append(SEP)
        lines.append("No AutoTrade open/closed rows found in this window.")
        out = "\n".join(lines)
    else:
        # Ver16: show every trade row. Time is explicitly converted to Melbourne
        # in _ts_txt(), and the long <pre> table is chunked safely by send_long_message.
        display = list(journal_rows)
        def _result_display(r: dict) -> str:
            try:
                if str(r.get('state') or '').upper() == 'OPEN':
                    return 'OPEN'
                return str(r.get('closed_kind') or _autotrade_report_closed_kind(r) or '-').upper()
            except Exception:
                return '-'
        def _reason_display(r: dict) -> str:
            try:
                res = _result_display(r)
                # For losing trades this must be the actionable improvement cause,
                # not just a generic "SL_HIT".  TP rows still show hit/profit.
                if str(res).upper() == 'SL':
                    return _autotrade_report_loss_reason(r)
                return str(r.get('exit_reason') or _autotrade_report_exit_reason(r, res) or '-')
            except Exception:
                return '-'
        def _real_money_cell(r: dict, key: str) -> str:
            try:
                qkey = 'risk_report_quality' if key == 'risk_usd' else 'tp_report_quality'
                src = str(r.get(f'{key}_source') or '').strip().lower()
                qual = str(r.get(qkey) or '').strip().lower()
                # ver98: display reporting-repaired realised amounts.  ver97
                # correctly repaired SL/TP values from Bybit realised PnL, but
                # this cell still hid them because the quality was not exactly
                # "real".  For closed rows, realised_sl_pnl / realised_tp_pnl
                # are the safest user-facing amounts when original setup risk
                # metadata was stale, missing, or only one partial fragment.
                allowed_qual = {'real', 'realized_sl_pnl', 'realized_tp_pnl'}
                allowed_src = {'stored_amount', 'geometry_qty', 'rr_from_real_risk', 'realized_sl_pnl', 'realized_tp_pnl', 'live_position_geometry'}
                if qual not in allowed_qual and src not in allowed_src:
                    return '-'
                return _autotrade_report_money(r.get(key))
            except Exception:
                return '-'
        def _real_pct_cell(r: dict) -> str:
            try:
                qual = str(r.get('risk_report_quality') or '').strip().lower()
                src = str(r.get('risk_pct_source') or '').strip().lower()
                if qual not in {'real', 'pct_only', 'realized_sl_pnl'} and src not in {'risk_usd_equity', 'risk_actual_pct', 'filled_risk_pct', 'realized_sl_pnl'}:
                    return '-'
                return _autotrade_report_pct(r.get('risk_pct'))
            except Exception:
                return '-'
        def _dyn_cell(r: dict) -> str:
            try:
                v = float(r.get('dynamic_risk_score') or 0.0)
                if v <= 0:
                    v = float(_autotrade_report_infer_dynamic_score(r) or 0.0)
                return f'{v:.0f}' if v > 0 else '-'
            except Exception:
                return '-'
        def _atpol_cell(r: dict) -> str:
            try:
                pol = str((r or {}).get('policy_at_open') or '').upper().strip()
                if pol == 'OFF':
                    pol = 'DISABLE'
                if pol in {'KEEP','WATCH','TIGHTEN','DISABLE'}:
                    return pol
                fn = globals().get('_setup_audit_compare_policy_at_open')
                if callable(fn):
                    pol2 = str(fn(r, None) or '').upper().strip()
                    return pol2 if pol2 else 'NO_SNAP*'
                return 'NO_SNAP*'
            except Exception:
                return '-'
        table_rows = []
        for r in display:
            open_ts, close_ts = _report_display_open_close_ts(r)
            table_rows.append([
                _ts_txt(open_ts),
                _ts_txt(close_ts) if close_ts > 0 else '-',
                _result_display(r),
                r.get('symbol'),
                r.get('side'),
                _setup_combo_strategy_side_key(str(r.get('family') or 'F0'), str(r.get('session') or '-'), r, str(r.get('side') or '')),
                _atpol_cell(r),
                _autotrade_report_close_session(r),
                int(float(r.get('conf') or 0.0)) if float(r.get('conf') or 0.0) > 0 else '-',
                _dyn_cell(r),
                _real_pct_cell(r),
                _real_money_cell(r, 'risk_usd'),
                _real_money_cell(r, 'tp_usd'),
                int(r.get('parts') or 1),
                f"{float(r.get('pnl') or 0.0):+.2f}",
                _reason_display(r),
            ])
        table = tabulate(
            table_rows,
            headers=['Open', 'Close', 'Result', 'Sym', 'Side', 'Combo', 'ATPol', 'SesC', 'Conf', 'Dyn', 'Risk%', 'Risk$', 'TP$', 'Parts', 'PnL', 'Reason'],
            tablefmt='plain',
            colalign=('left', 'left', 'center', 'left', 'center', 'left', 'center', 'center', 'right', 'right', 'right', 'right', 'right', 'right', 'right', 'left'),
        )
        raw_count = int(len(bot_positions or [])) + int(len(closed_rows or []))
        lines.append(f"Rows shown: <b>{len(display)}</b> / <b>{len(journal_rows)}</b> merged position rows. Raw fragments: <b>{raw_count}</b>. Time: <b>Melbourne</b>.")
        out = "\n".join(lines) + "\n<pre>" + html.escape(table) + "</pre>"
    try:
        cache_set(cache_key, out)
    except Exception:
        pass
    return out

def _autotrade_report_overall_text_cached(owner: int, lookback_h: int = 24) -> str:
    """/autotrade_report_overall — practical AutoTrade overall matrix.

    Ver05: the old lifecycle-weighted summary could show 0 decided / hundreds
    untracked while /autotrade_report had real closed PnL. Delegate to the same
    merged Bybit+journal position logic as /autotrade_report_overall so this
    command is immediately useful for WR/PnL/family-session review.
    """
    try:
        owner = int(owner)
        lookback_h = int(clamp(int(lookback_h or 24), 1, 8760))
        return _autoytrade_report_overall_text_cached(owner, lookback_h)
    except Exception as exc:
        return f"❌ /autotrade_report_overall failed: {type(exc).__name__}: {exc}"

def _performance_report_payload_cached(owner: int, days: int) -> dict:
    owner = int(owner)
    days = int(clamp(int(days or 7), 3, 30))
    cache_key = f"performance_report_payload:{owner}:{days}"
    try:
        if cache_valid(cache_key, int(PERFORMANCE_REPORT_CACHE_TTL_SEC or 30)):
            cached = cache_get(cache_key)
            if isinstance(cached, dict) and cached.get('text'):
                return cached
    except Exception:
        pass

    recent_rows = _autotrade_performance_rows(owner, days=days)
    recent_summary = _autotrade_performance_summary(recent_rows)
    overall_days = _autotrade_history_days_available(owner)
    overall_rows = _autotrade_performance_rows(owner, days=overall_days)
    overall_summary = _autotrade_performance_summary(overall_rows)
    owner_user = _autotrade_user_settings(owner)
    equity_now = _effective_equity_for_risk(owner_user, prefer_live=(str(_autotrade_runtime_mode()).lower() == 'live'))
    weighted_recent = _autotrade_weighted_outcome_summary(owner, days=days)
    weighted_overall = _autotrade_weighted_outcome_summary(owner, days=overall_days)
    try:
        lifecycle_recent = _trade_lifecycle_analytics(owner, days=max(3, int(days)), session='ALL', sync=True, force=False)
    except Exception:
        lifecycle_recent = {}
    try:
        lifecycle_overall_days = max(7, min(90, int(overall_days or 30)))
        lifecycle_overall = _trade_lifecycle_analytics(owner, days=lifecycle_overall_days, session='ALL', sync=True, force=False)
    except Exception:
        lifecycle_overall_days = max(7, min(90, int(overall_days or 30)))
        lifecycle_overall = {}

    def _pf_txt(v):
        return 'INF' if v == float('inf') else f"{float(v or 0.0):.2f}"

    lines = [
        '📈 Performance Report',
        HDR,
        f'Recent window: last {days} anchored trading day(s)',
        f'Overall history: {int(overall_days)} anchored trading day(s)',
        SEP,
        'OVERALL',
        f"Closed trades: {int(overall_summary.get('closed') or 0)} | Wins: {int(overall_summary.get('wins') or 0)} | Losses: {int(overall_summary.get('losses') or 0)}",
        f"Net PnL: ${float(overall_summary.get('net') or 0.0):+.2f} | Profit factor: {_pf_txt(overall_summary.get('profit_factor'))} | Expectancy: ${float(overall_summary.get('expectancy') or 0.0):+.2f}",
        f"Realized WR: {float(overall_summary.get('win_rate') or 0.0):.1f}% | Weighted TP WR: {float(weighted_overall.get('weighted_win_rate') or 0.0):.1f}%",
        f"TP mix: TP {int(weighted_overall.get('tp_only') or 0) + int(weighted_overall.get('alt_target_a_plus') or 0)} | SL {int(weighted_overall.get('losses') or 0)} | OPEN {int(weighted_overall.get('open') or 0)}",
    ]
    bd = overall_summary.get('best_day') or {}
    wd = overall_summary.get('worst_day') or {}
    if bd:
        lines.append(f"Best day: {bd.get('day')} | ${float(bd.get('net_pnl') or 0.0):+.2f}")
    if wd:
        lines.append(f"Worst day: {wd.get('day')} | ${float(wd.get('net_pnl') or 0.0):+.2f}")

    lines.extend([SEP, *_trade_lifecycle_analytics_lines(lifecycle_overall, heading=f'Lifecycle feed (overall, {int(lifecycle_overall_days)}d cap)', include_sessions=True, include_engines=True, include_buckets=True, include_symbols=True, include_signs=True, max_signs=2)])

    lines.extend([
        SEP,
        f'RECENT ({days} day window)',
        f"Closed: {int(recent_summary.get('closed') or 0)} | Net PnL: ${float(recent_summary.get('net') or 0.0):+.2f} | Realized WR: {float(recent_summary.get('win_rate') or 0.0):.1f}%",
        f"Weighted TP WR: {float(weighted_recent.get('weighted_win_rate') or 0.0):.1f}% | TP {int(weighted_recent.get('tp_only') or 0) + int(weighted_recent.get('alt_target_a_plus') or 0)} | SL {int(weighted_recent.get('losses') or 0)} | OPEN {int(weighted_recent.get('open') or 0)}",
    ])
    lines.extend([SEP, *_trade_lifecycle_analytics_lines(lifecycle_recent, heading=f'Lifecycle feed ({days}d)', include_sessions=True, include_engines=True, include_buckets=True, include_symbols=True, include_signs=True, max_signs=2), SEP, 'Daily trend'])
    for r in recent_rows:
        wl_total = int(r.get('wins') or 0) + int(r.get('losses') or 0)
        wr = (float(r.get('wins') or 0) / wl_total * 100.0) if wl_total > 0 else 0.0
        lines.append(f"• {r.get('day')} | PnL ${float(r.get('net_pnl') or 0.0):+.2f} | Realized WR {wr:.1f}%")

    chart_path = _build_performance_chart_png(overall_rows or recent_rows, equity=float(equity_now or 0.0))
    payload = {'text': "\n".join(lines), 'chart_path': chart_path}
    try:
        cache_set(cache_key, payload)
    except Exception:
        pass
    return payload





def _autotrade_closed_positions_text_cached(owner_uid: int, lookback_h: int) -> str:
    """Return compact closed position rows for /autotrade_closed and /autotrade/closed.

    ver82: for this command, Bybit Closed P&L is the authority. The table mirrors
    the exchange closed-PnL rows in the requested window: exact exchange close time
    (shown in Australia/Melbourne), symbol, inferred/open side, risk if a matching
    bot journal row exists, and exact realised PnL. This fixes the old behaviour
    where bot lifecycle/provisional rows could use a different close timestamp from
    Bybit's P&L page.
    """
    owner_uid = int(owner_uid)
    lookback_h = int(clamp(int(lookback_h or 24), 1, 168))
    cache_key = f"autotrade_closed_positions:v146:{owner_uid}:{lookback_h}"
    try:
        if cache_valid(cache_key, int(AUTOTRADE_REPORT_CACHE_TTL_SEC or 20)):
            cached = cache_get(cache_key)
            if isinstance(cached, str) and cached.strip():
                return cached
    except Exception:
        pass

    _autotrade_migrate_tables()
    try:
        _migrate_generated_setups()
    except Exception:
        pass

    now_ts = float(time.time())
    start_ts = now_ts - float(lookback_h) * 3600.0
    try:
        report_equity = float(_effective_equity_for_risk(_autotrade_user_settings(owner_uid), prefer_live=(str(_autotrade_runtime_mode()).lower() == 'live')) or 0.0)
    except Exception:
        report_equity = 0.0

    def _sym_short(value) -> str:
        try:
            s = str(_bybit_linear_symbol(value or '')).upper().strip()
            return s[:-4] if s.endswith('USDT') else (s or '-')
        except Exception:
            return '-'

    def _num_from_keys(row: dict, keys: tuple[str, ...]) -> float:
        for k in keys:
            try:
                v = row.get(k)
                if v is None or str(v).strip() == '':
                    continue
                x = float(v)
                if x != 0:
                    return x
            except Exception:
                continue
        return 0.0

    def _risk_cell(row: dict) -> str:
        try:
            # Risk must mean the real Stop-Loss $ amount for this position, not a
            # placeholder. Prefer stored/executed risk; otherwise use position
            # geometry: abs(entry - SL) * qty * contract_size.
            v = float((row or {}).get('risk_usd') or (row or {}).get('risk_usdt') or (row or {}).get('filled_risk_usd') or (row or {}).get('risk_actual_usd') or 0.0)
            if v > 0:
                return f"${v:.2f}"
        except Exception:
            pass
        try:
            entry = abs(float((row or {}).get('entry') or (row or {}).get('avgEntryPrice') or (row or {}).get('avg_entry_price') or 0.0))
            sl = abs(float((row or {}).get('sl') or (row or {}).get('stop_loss') or (row or {}).get('stopLoss') or 0.0))
            qty = abs(float((row or {}).get('qty') or (row or {}).get('filled_qty') or (row or {}).get('closed_qty') or (row or {}).get('closedSize') or (row or {}).get('closed_size') or 0.0))
            if entry > 0 and sl > 0 and qty > 0:
                try:
                    cs = float((row or {}).get('contract_size') or (row or {}).get('contractSize') or 0.0)
                    if cs <= 0:
                        cs = float((_bybit_get_instr_filters(str((row or {}).get('symbol') or '')) or {}).get('contractSize') or 1.0)
                except Exception:
                    cs = 1.0
                risk = abs(entry - sl) * qty * abs(float(cs or 1.0))
                if risk > 0:
                    return f"${risk:.2f}"
        except Exception:
            pass
        return '-'

    def _combo_cell(row: dict) -> str:
        try:
            for k in ('combo', 'combo_key', 'combo_side_key', 'combo_strategy_side'):
                v = str((row or {}).get(k) or '').upper().strip()
                if v and v != '-':
                    return v
            combo = str(_autotrade_setup_exact_combo_key(row) or '').upper().strip()
            if combo and combo not in {'F0-UNK-NOR-BOTH', 'F0-UNK-NOR', 'F0---NOR'}:
                return combo
            fam = _setup_audit_family_code(row) if isinstance(row, dict) else 'F0'
            sess = str((row or {}).get('session') or (row or {}).get('source_session') or '-').upper().strip() or '-'
            strat = _setup_strategy_suffix(row)
            side = str((row or {}).get('side') or '').upper().strip()
            combo = _setup_combo_strategy_side_key(fam, sess, strat, side)
            return combo if combo and 'UNK' not in combo else '-'
        except Exception:
            return '-'

    def _coerce_ts_utc_seconds(value) -> float:
        try:
            if value in (None, '', 0, '0'):
                return 0.0
            try:
                v = float(value)
                if v <= 0:
                    return 0.0
                try:
                    vv = float(_ts_seconds_from_any(v) or 0.0)
                    if vv > 0:
                        return vv
                except Exception:
                    pass
                return (v / 1000.0) if v > 10_000_000_000 else v
            except Exception:
                pass
            try:
                dt = _parse_iso_utcish(str(value))
                if dt is not None:
                    return float(dt.timestamp())
            except Exception:
                pass
        except Exception:
            pass
        return 0.0

    def _closed_ts_value(row: dict, fallback_row: dict | None = None) -> float:
        try:
            rr = row or {}
            fb = fallback_row or {}
            for src in (rr, fb):
                # For raw Bybit Closed P&L rows, updatedTime is the Trade Time shown
                # on Bybit's P&L / Closed Orders page. Keep it first.
                for k in ('updatedTime', 'updated_time', 'closed_ts', 'close_ts', 'exit_ts', 'closeTime', 'closedTime', 'createdTime', 'created_time', 'execTime', 'fillTime', 'last_ts', 'updated_ts', 'ts'):
                    v = _coerce_ts_utc_seconds((src or {}).get(k))
                    if v > 0:
                        return float(v)
        except Exception:
            pass
        return 0.0

    def _closed_time_text(ts: float) -> str:
        """Render a UTC epoch-second close timestamp in Australia/Melbourne time."""
        try:
            ts_sec = float(_ts_seconds_from_any(ts) or ts or 0.0)
            if ts_sec <= 0:
                return '-'
            return datetime.fromtimestamp(ts_sec, tz=timezone.utc).astimezone(MEL_TZ).strftime('%m-%d %H:%M:%S')
        except Exception:
            return '-'

    def _bybit_position_side(ev: dict) -> str:
        """Infer the original position side for a Bybit Closed-PnL row.

        Bybit Closed-PnL payloads can expose the execution/closing side in some
        environments. If entry/exit prices plus PnL clearly identify the position
        direction, use that; otherwise fall back to the raw exchange side.
        """
        raw = str((ev or {}).get('side') or '').upper().strip()
        if raw not in {'BUY', 'SELL'}:
            raw = ''
        try:
            entry = abs(float(_num_from_keys(ev, ('avgEntryPrice', 'avg_entry_price', 'entryPrice', 'entry_price')) or 0.0))
            exitp = abs(float(_num_from_keys(ev, ('avgExitPrice', 'avg_exit_price', 'exitPrice', 'exit_price', 'orderPrice', 'price')) or 0.0))
            pnl = float((ev or {}).get('closedPnl') if (ev or {}).get('closedPnl') is not None else (ev or {}).get('pnl') or 0.0)
            # Do not infer direction for tiny near-zero outcomes where fees/funding can
            # flip the sign versus the price movement.
            if entry > 0 and exitp > 0 and abs(exitp - entry) > max(entry * 1e-7, 1e-12) and abs(pnl) >= 0.50:
                if pnl > 0:
                    return 'BUY' if exitp > entry else 'SELL'
                if pnl < 0:
                    return 'BUY' if exitp < entry else 'SELL'
        except Exception:
            pass
        return raw or '-'

    def _exchange_event_key(ev: dict) -> tuple:
        try:
            return (
                str(_bybit_linear_symbol((ev or {}).get('symbol') or '')).upper(),
                int(round(float(_closed_ts_value(ev) or 0.0) * 1000)),
                str((ev or {}).get('orderId') or (ev or {}).get('execId') or (ev or {}).get('createdTime') or ''),
                round(float((ev or {}).get('closedPnl') or 0.0), 8),
                round(float(_bybit_closed_pnl_event_qty(ev) or 0.0), 8),
            )
        except Exception:
            return (str(ev),)

    def _pnl_text(value) -> str:
        try:
            x = float(value or 0.0)
            # yver123: keep all PnL display rounded and readable.
            return f"{x:.2f}"
        except Exception:
            return '-'

    def _risk_text_for_closed_event(risk_txt: str, pnl_value: float, kind: str = '') -> str:
        try:
            txt = str(risk_txt or '-').strip() or '-'
            v = 0.0
            if txt != '-':
                try:
                    v = abs(float(txt.replace('$', '').replace(',', '').strip() or 0.0))
                except Exception:
                    v = 0.0
            pnl_f = float(pnl_value or 0.0)
            k = str(kind or '').upper().strip()
            if pnl_f < -float(globals().get('AUTOTRADE_REPORT_TPSL_SIGN_EPS_USD', 0.50) or 0.50) and (k in {'', 'SL'}):
                realised = abs(pnl_f)
                if realised > 0 and (
                    v <= 0
                    or realised > max(v * 1.35, v + 3.0)
                    or v > max(realised * 1.35, realised + 3.0)
                ):
                    return f"${realised:.2f}"
            return txt
        except Exception:
            return str(risk_txt or '-')

    # v95: use the same canonical Bybit Closed-PnL metadata layer as
    # /autotrade_report first, so Combo/Risk in /autotrade_closed cannot drift
    # from the journal report.  Fall back to the older journal/lifecycle source
    # only if canonical enrichment is unavailable.  The displayed rows below
    # still come directly from Bybit Closed P&L.
    enrich_rows = []
    try:
        enrich_rows = _autotrade_report_bybit_canonical_closed_rows(
            owner_uid,
            float(start_ts) - 6 * 3600.0,
            float(now_ts) + 6 * 3600.0,
            lookback_h=max(lookback_h, 48),
            report_equity=report_equity,
        ) or []
    except Exception:
        enrich_rows = []
    if not enrich_rows:
        try:
            enrich_rows = _autotrade_closed_report_rows(owner_uid, float(start_ts) - 6 * 3600.0, float(now_ts) + 6 * 3600.0, lookback_h=lookback_h, limit=0) or []
        except Exception:
            enrich_rows = []

    enrich_candidates = []
    for er in (enrich_rows or []):
        try:
            row = _setup_audit_merge_trade_setup_row(dict(er or {}))
            row = _autotrade_report_enrich_amounts(row, report_equity)
            sym = str(_bybit_linear_symbol(row.get('symbol') or er.get('symbol') or '')).upper().strip()
            if not sym:
                continue
            pnl = float(row.get('pnl_usdt') if row.get('pnl_usdt') is not None else row.get('pnl') or 0.0)
            cts = _closed_ts_value(row, er)
            side = str(row.get('side') or er.get('side') or '').upper().strip()
            enrich_candidates.append({
                'symbol': sym,
                'side': side,
                'pnl': pnl,
                'closed_ts': float(cts or 0.0),
                'opened_ts': float(row.get('opened_ts') or er.get('opened_ts') or 0.0),
                'risk': _risk_cell(row),
                'combo': _combo_cell(row),
                'row': dict(row or {}),
            })
        except Exception:
            continue

    # yver96: when a raw Bybit Closed-PnL fragment cannot be safely enriched
    # from canonical report rows (common for partial/profit-close fragments), use
    # the nearest same-symbol/same-side setup row as a fallback for Combo and SL
    # risk.  This is still display-only: Bybit remains the authority for close
    # time and realised PnL.
    setup_enrich_candidates = []
    try:
        setup_start = max(0.0, float(start_ts) - 36 * 3600.0)
        setup_rows_for_closed = _setup_audit_load_rows(
            owner_uid, hours=None, limit=0, dedup=False, start_ts=setup_start,
            apply_final_quality_gate=False, source_mode_override='ALL'
        ) or []
        for sr in setup_rows_for_closed:
            try:
                row = dict(sr or {})
                sym2 = str(_bybit_linear_symbol(row.get('symbol') or row.get('market_symbol') or '')).upper().strip()
                side2 = str(row.get('side') or '').upper().strip()
                sts2 = float(_setup_audit_row_ts(row) or row.get('created_ts') or row.get('ts') or 0.0)
                if not sym2 or side2 not in {'BUY', 'SELL'} or sts2 <= 0:
                    continue
                fam2 = _setup_audit_family_code(row) if isinstance(row, dict) else 'F0'
                sess2 = str(row.get('session') or row.get('source_session') or '-').upper().strip() or '-'
                combo2 = _setup_combo_strategy_side_key(fam2, sess2, row, side2)
                setup_enrich_candidates.append({
                    'symbol': sym2, 'side': side2, 'setup_ts': float(sts2),
                    'combo': combo2, 'risk': _risk_cell(row), 'row': row,
                })
            except Exception:
                continue
    except Exception:
        setup_enrich_candidates = []

    def _match_setup_enrichment_for_exchange_event(sym: str, side: str, ts: float, ev: dict | None = None) -> dict:
        try:
            side = str(side or '').upper().strip()
            best = None
            best_score = 10**18
            max_age = max(36 * 3600.0, float(_setup_audit_result_horizon_hours() + 6) * 3600.0)
            for cand in setup_enrich_candidates:
                try:
                    if str(cand.get('symbol') or '') != str(sym or ''):
                        continue
                    if side in {'BUY', 'SELL'} and str(cand.get('side') or '').upper().strip() != side:
                        continue
                    sts = float(cand.get('setup_ts') or 0.0)
                    if sts <= 0 or ts <= 0 or sts > float(ts) + 300.0:
                        continue
                    age = float(ts) - sts
                    if age < -300.0 or age > max_age:
                        continue
                    # Prefer the most recent valid setup before the Bybit close.
                    score = age
                    if score < best_score:
                        best = cand
                        best_score = score
                except Exception:
                    continue
            if not best:
                return {'risk': '-', 'combo': '-'}
            risk = str(best.get('risk') or '-')
            if risk.strip() == '-':
                try:
                    row = dict(best.get('row') or {})
                    ev2 = ev or {}
                    entry = abs(float(row.get('entry') or ev2.get('avgEntryPrice') or ev2.get('avg_entry_price') or ev2.get('entryPrice') or ev2.get('entry_price') or 0.0))
                    sl = abs(float(row.get('sl') or row.get('stopLoss') or row.get('stop_loss') or 0.0))
                    qty = abs(float(_bybit_closed_pnl_event_qty(ev2) or row.get('qty') or row.get('filled_qty') or row.get('closed_qty') or 0.0))
                    if entry > 0 and sl > 0 and qty > 0:
                        try:
                            cs = float(row.get('contract_size') or row.get('contractSize') or ev2.get('contractSize') or 0.0)
                            if cs <= 0:
                                cs = float((_bybit_get_instr_filters(str(row.get('symbol') or ev2.get('symbol') or '')) or {}).get('contractSize') or 1.0)
                        except Exception:
                            cs = 1.0
                        v = abs(entry - sl) * qty * abs(float(cs or 1.0))
                        if v > 0:
                            risk = f"${v:.2f}"
                except Exception:
                    pass
            return {'risk': risk or '-', 'combo': str(best.get('combo') or '-').upper().strip() or '-'}
        except Exception:
            return {'risk': '-', 'combo': '-'}

    def _event_risk_from_candidate(cand: dict, ev: dict | None = None) -> str:
        try:
            risk = str((cand or {}).get('risk') or '-').strip()
            if risk and risk != '-':
                return risk
            row = dict((cand or {}).get('row') or {})
            ev = ev or {}
            entry = abs(float(row.get('entry') or ev.get('avgEntryPrice') or ev.get('avg_entry_price') or ev.get('entryPrice') or ev.get('entry_price') or 0.0))
            sl = abs(float(row.get('sl') or row.get('stopLoss') or row.get('stop_loss') or 0.0))
            qty = abs(float(_bybit_closed_pnl_event_qty(ev) or row.get('qty') or row.get('filled_qty') or row.get('closed_qty') or 0.0))
            if entry > 0 and sl > 0 and qty > 0:
                try:
                    cs = float(row.get('contract_size') or row.get('contractSize') or ev.get('contractSize') or 0.0)
                    if cs <= 0:
                        cs = float((_bybit_get_instr_filters(str(row.get('symbol') or ev.get('symbol') or '')) or {}).get('contractSize') or 1.0)
                except Exception:
                    cs = 1.0
                v = abs(entry - sl) * qty * abs(float(cs or 1.0))
                if v > 0:
                    return f"${v:.2f}"
        except Exception:
            pass
        return '-'

    def _match_enrichment_for_exchange_event(sym: str, side: str, pnl: float, ts: float, ev: dict | None = None) -> dict:
        best = None
        best_score = 10**18
        side = str(side or '').upper().strip()
        for cand in enrich_candidates:
            try:
                if str(cand.get('symbol') or '') != str(sym or ''):
                    continue
                cside = str(cand.get('side') or '').upper().strip()
                ccombo = str(cand.get('combo') or '').upper().strip()
                ccombo_side = _autotrade_combo_side_from_key(ccombo)
                if side in {'BUY', 'SELL'}:
                    # Never enrich a SELL exchange close with BUY-lane combo/risk
                    # or a BUY exchange close with SELL-lane combo/risk.  A wrong
                    # metadata match is worse than showing '-' for Combo/Risk.
                    if ccombo_side in {'BUY', 'SELL'} and ccombo_side != side:
                        continue
                    if cside in {'BUY', 'SELL'} and cside != side and ccombo_side not in {'BUY', 'SELL'}:
                        continue
                side_penalty = 0.0
                cpnl = float(cand.get('pnl') or 0.0)
                pnl_diff = abs(cpnl - float(pnl or 0.0))
                cts = float(cand.get('closed_ts') or 0.0)
                ots = float(cand.get('opened_ts') or 0.0)
                if cts > 0 and ts > 0:
                    dt = abs(float(ts or 0.0) - cts)
                elif ots > 0 and ts > 0 and ots <= ts + 300.0:
                    dt = min(abs(float(ts or 0.0) - ots), 12 * 3600.0)
                else:
                    dt = 999999.0
                if dt > 6 * 3600 and pnl_diff > 0.25:
                    continue
                if dt > 48 * 3600:
                    continue
                # Do not attach metadata from a candidate whose open time is clearly
                # after the exchange close.  This prevents stale/future setup matches.
                if ots > 0 and ts > 0 and ots > ts + 300.0:
                    continue
                # First priority is exact/near close-time match; PnL remains a strong
                # tie-breaker but is not a hard filter because Bybit may split or
                # aggregate realised P&L differently from the bot's practical row.
                # v95: exact Bybit-event canonical candidates get a strong priority.
                exact_bonus = -500000.0 if (cts > 0 and ts > 0 and abs(float(ts) - float(cts)) <= 3.0 and pnl_diff <= 0.05) else 0.0
                score = exact_bonus + side_penalty + dt * 10.0 + min(pnl_diff, 100.0) * 250.0
                if score < best_score:
                    best = cand
                    best_score = score
            except Exception:
                continue
        if not best:
            return {'risk': '-', 'combo': '-'}
        return {
            'risk': _event_risk_from_candidate(best, ev),
            'combo': str((best or {}).get('combo') or '-').upper().strip() or '-',
        }

    bybit_events = []
    if str(_autotrade_runtime_mode()).lower() == 'live':
        try:
            bybit_events = _bybit_get_closed_pnl_linear(float(start_ts), float(now_ts) + 60.0, limit=max(200, min(10000, int(lookback_h) * 100))) or []
        except Exception:
            bybit_events = []

    table_rows = []
    source_txt = 'Bybit Closed P&L'
    if bybit_events:
        seen = set()
        for ev in (bybit_events or []):
            try:
                ts = float(_closed_ts_value(ev) or _bybit_closed_pnl_event_ts(ev) or 0.0)
                if ts <= 0 or ts < start_ts or ts > now_ts + 120.0:
                    continue
                key = _exchange_event_key(ev)
                if key in seen:
                    continue
                seen.add(key)
                sym = str(_bybit_linear_symbol((ev or {}).get('symbol') or '')).upper().strip()
                if not sym:
                    continue
                pnl = float((ev or {}).get('closedPnl') if (ev or {}).get('closedPnl') is not None else (ev or {}).get('pnl') or 0.0)
                pos_side = (_bybit_closed_pnl_position_side(ev) or _bybit_position_side(ev))
                enrich = _match_enrichment_for_exchange_event(sym, pos_side, pnl, ts, ev)
                # yver96 fallback: fill missing Combo/Risk from nearest setup evidence.
                try:
                    if str((enrich or {}).get('combo') or '-').strip() == '-' or str((enrich or {}).get('risk') or '-').strip() == '-':
                        setup_enrich = _match_setup_enrichment_for_exchange_event(sym, pos_side, ts, ev)
                        if str((enrich or {}).get('combo') or '-').strip() == '-' and str((setup_enrich or {}).get('combo') or '-').strip() != '-':
                            enrich['combo'] = str(setup_enrich.get('combo') or '-')
                        if str((enrich or {}).get('risk') or '-').strip() == '-' and str((setup_enrich or {}).get('risk') or '-').strip() != '-':
                            enrich['risk'] = str(setup_enrich.get('risk') or '-')
                except Exception:
                    pass
                _kind_for_risk = 'SL' if float(pnl or 0.0) < -float(globals().get('AUTOTRADE_REPORT_TPSL_SIGN_EPS_USD', 0.50) or 0.50) else ''
                table_rows.append({
                    'closed_ts': float(ts),
                    'close': _closed_time_text(ts),
                    'combo': str((enrich or {}).get('combo') or '-').upper().strip() or '-',
                    'symbol': _sym_short(sym),
                    'side': pos_side,
                    'risk': _risk_text_for_closed_event(str((enrich or {}).get('risk') or '-'), float(pnl or 0.0), _kind_for_risk),
                    'pnl': pnl,
                })
            except Exception:
                continue
    else:
        # Fallback for paper mode or temporary Bybit API failure: use the previous
        # journal/lifecycle source, but keep the same display contract.
        source_txt = 'Bot journal/lifecycle fallback'
        for r in (enrich_rows or []):
            try:
                row = _setup_audit_merge_trade_setup_row(dict(r or {}))
                row = _autotrade_report_enrich_amounts(row, report_equity)
                pnl = float(row.get('pnl_usdt') if row.get('pnl_usdt') is not None else row.get('pnl') or 0.0)
                closed_ts = _closed_ts_value(row, r)
                table_rows.append({
                    'closed_ts': float(closed_ts or 0.0),
                    'close': _closed_time_text(closed_ts),
                    'combo': _combo_cell(row),
                    'symbol': _sym_short(row.get('symbol') or r.get('symbol') or ''),
                    'side': str(row.get('side') or r.get('side') or '-').upper().strip() or '-',
                    'risk': _risk_text_for_closed_event(_risk_cell(row), float(pnl or 0.0), 'SL' if float(pnl or 0.0) < -float(globals().get('AUTOTRADE_REPORT_TPSL_SIGN_EPS_USD', 0.50) or 0.50) else ''),
                    'pnl': pnl,
                })
            except Exception:
                continue

    table_rows.sort(key=lambda x: (float(x.get('closed_ts') or 0.0), str(x.get('symbol') or ''), float(x.get('pnl') or 0.0)), reverse=True)
    now_txt = ''
    try:
        now_txt = datetime.fromtimestamp(now_ts, tz=timezone.utc).astimezone(MEL_TZ).strftime('%Y-%m-%d %H:%M')
    except Exception:
        pass

    lines = [
        "📕 <b>AutoTrade Closed Positions</b>",
        HDR,
        f"Window: <b>last {lookback_h}h</b> (Melbourne)" + (f" | Now: <b>{html.escape(now_txt)}</b>" if now_txt else ''),
        f"Source: <b>{html.escape(source_txt)}</b>. Sorted by exact exchange close time newest first. Close time is Australia/Melbourne.",
        "Columns: Close, Combo, Symbol, Side, Risk, PnL. Risk = realised Stop-Loss $ amount for SL rows; TP$/Risk$ are repaired from Bybit realised PnL when stored setup amounts are stale or partial.",
    ]
    if not table_rows:
        lines.append(SEP)
        lines.append("No closed position rows found in this window.")
        out = "\n".join(lines)
    else:
        plain_rows = [[r.get('close') or '-', r.get('combo') or '-', r['symbol'], r['side'], r['risk'], _pnl_text(r['pnl'])] for r in table_rows]
        table = tabulate(
            plain_rows,
            headers=['Close', 'Combo', 'Symbol', 'Side', 'Risk', 'PnL'],
            tablefmt='plain',
            colalign=('left', 'left', 'left', 'center', 'right', 'right'),
        )
        lines.append(f"Rows shown: <b>{len(plain_rows)}</b> closed P&amp;L rows. Time: <b>Melbourne</b>.")
        out = "\n".join(lines) + "\n<pre>" + html.escape(table) + "</pre>"
    try:
        cache_set(cache_key, out)
    except Exception:
        pass
    return out


