def _autotrade_reconciliation_snapshot(uid: int, days: int = 7) -> dict:
    """Journal-first reconciliation stats for performance reporting."""
    days = int(max(2, min(int(days or 7), 60)))
    user = _autotrade_user_settings(int(uid))
    tz = _user_tzinfo(user)
    start_local, _ = _anchored_day_window(datetime.now(tz), _user_day_reset_hhmm(user))
    start_local = start_local - timedelta(days=days - 1)
    start_ts = float(start_local.astimezone(timezone.utc).timestamp())
    end_ts = float((start_local + timedelta(days=days)).astimezone(timezone.utc).timestamp())
    journal_closed = 0
    exchange_reconciled = 0
    with sqlite3.connect(DB_PATH) as conn:
        conn.row_factory = sqlite3.Row
        cur = conn.cursor()
        rows = cur.execute(
            """SELECT trade_id, note, closed_ts FROM autotrade_trades
               WHERE uid=? AND closed_ts IS NOT NULL AND closed_ts>=? AND closed_ts<?""",
            (int(uid), int(start_ts), int(end_ts))
        ).fetchall() or []
        for r in rows:
            journal_closed += 1
            note = str(r['note'] or '')
            if 'exchange_close_sync' in note:
                exchange_reconciled += 1
    provisional_emailed = 0
    provisional_keys = set()
    try:
        for t in (_autotrade_reconstruct_provisional_closes(int(uid), days=days) or []):
            sym = str(t.get('symbol') or '').upper()
            side = str(t.get('side') or '').upper()
            ts = int(float(t.get('closed_ts') or 0.0))
            pnl = round(float(t.get('pnl') or 0.0), 8)
            provisional_keys.add((sym, side, ts, pnl))
        provisional_emailed = len(provisional_keys)
    except Exception:
        provisional_emailed = 0
        provisional_keys = set()

    unmatched = 0
    try:
        seen = set()
        with sqlite3.connect(DB_PATH) as conn:
            conn.row_factory = sqlite3.Row
            cur = conn.cursor()
            rows = cur.execute(
                """SELECT symbol, side, closed_ts, pnl_usdt, note FROM autotrade_trades
                   WHERE uid=? AND closed_ts IS NOT NULL AND closed_ts>=? AND closed_ts<?""",
                (int(uid), int(start_ts), int(end_ts))
            ).fetchall() or []
            for r in rows:
                key = (str(r['symbol'] or '').upper(), str(r['side'] or '').upper(), int(float(r['closed_ts'] or 0.0)), round(float(r['pnl_usdt'] or 0.0), 8))
                seen.add(key)
        seen |= provisional_keys
        for ev in (_bybit_get_closed_pnl_linear(start_ts, end_ts, limit=max(200, days * 80)) or []):
            sym = str(_bybit_linear_symbol((ev or {}).get('symbol') or '')).upper()
            ts = int(float(_bybit_closed_pnl_event_ts(ev) or 0.0))
            pnl = round(float((ev or {}).get('closedPnl') or 0.0), 8)
            matched = False
            for side in _bybit_closed_pnl_event_side_candidates(ev):
                if (sym, side, ts, pnl) in seen:
                    matched = True
                    break
            if not matched:
                unmatched += 1
    except Exception:
        pass
    return {
        'journal_confirmed_closes': int(journal_closed),
        'exchange_reconciled_closes': int(exchange_reconciled),
        'provisional_emailed_setup_closes': int(provisional_emailed),
        'unmatched_exchange_closes': int(unmatched),
    }

async def performance_report_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Admin bot-lifecycle performance report over recent and overall anchored trading days."""
    uid = update.effective_user.id
    if int(uid) != int(AUTOTRADE_OWNER_UID) and (not is_admin_user(uid)):
        await update.message.reply_text("⛔️ Owner/admin only.")
        return
    days = 7
    force = False
    try:
        args = list(context.args or [])
        if args and str(args[0]).strip().lower() in {'force', 'refresh', 'now'}:
            force = True
            args = args[1:]
        if args and str(args[0]).strip():
            days = int(float(args[0]))
    except Exception:
        days = 7
    days = int(clamp(days, 3, 30))
    owner = int(AUTOTRADE_OWNER_UID or uid)
    cache_key = f"performance_report_payload:{owner}:{days}"
    if not force:
        try:
            if cache_valid(cache_key, 900):
                cached = cache_get(cache_key)
                if isinstance(cached, dict) and cached.get('text'):
                    await send_long_message(update, str(cached.get('text') or '') + "\n\n⏳ Refreshing the latest performance data in the background…", parse_mode=None)
                    chart_path = str(cached.get('chart_path') or '')
                    if chart_path:
                        try:
                            with open(chart_path, 'rb') as f:
                                await context.bot.send_photo(chat_id=update.effective_chat.id, photo=f, caption='📉 Equity & daily PnL trend')
                        except Exception:
                            pass
                    try:
                        _safe_create_task(to_thread_bg(_performance_report_payload_cached, owner, days, timeout=300), 'performance_report_refresh')
                    except Exception:
                        pass
                    return
        except Exception:
            pass
    try:
        payload = await to_thread_heavy(_performance_report_payload_cached, owner, days, timeout=min(int(PERFORMANCE_REPORT_TIMEOUT_SEC), 45))
    except asyncio.TimeoutError:
        try:
            stale = cache_get(cache_key)
        except Exception:
            stale = None
        if isinstance(stale, dict) and stale.get('text'):
            await send_long_message(update, str(stale.get('text') or '') + "\n\n⏳ Heavy refresh is still running; showing the latest cached snapshot.", parse_mode=None)
            try:
                _safe_create_task(to_thread_bg(_performance_report_payload_cached, owner, days, timeout=300), 'performance_report_refresh')
            except Exception:
                pass
            return
        await update.message.reply_text(f"⚠️ /performance_report timed out after {min(int(PERFORMANCE_REPORT_TIMEOUT_SEC), 45)}s. Try again in a few seconds.")
        return
    except Exception as e:
        await update.message.reply_text(f"❌ /performance_report failed: {type(e).__name__}: {e}")
        return
    await send_long_message(update, str(payload.get('text') or ''), parse_mode=None)
    chart_path = str(payload.get('chart_path') or '')
    if chart_path:
        try:
            with open(chart_path, 'rb') as f:
                await context.bot.send_photo(chat_id=update.effective_chat.id, photo=f, caption='📉 Equity & daily PnL trend')
        except Exception:
            pass



def _autotrade_reconcile_attempt_rows_for_display(uid: int, hist: list) -> list:
    """Repair /autotrade_last display rows when a timeout row later became a real open trade.

    This is display-only and intentionally conservative: only timeout-like SKIP rows are
    promoted, and only when the same symbol/side or setup_id is currently open in the
    bot journal or live Bybit positions.
    """
    try:
        uid_i = int(uid or 0)
    except Exception:
        uid_i = 0
    rows = [dict(x or {}) for x in list(hist or [])]
    if not rows:
        return rows

    open_keys = set()
    open_setup_ids = set()

    def _norm_sym(x) -> str:
        try:
            return _bybit_linear_symbol(str(x or '').upper())
        except Exception:
            return str(x or '').upper().strip()

    def _add_open(sym, side='', setup_id=''):
        s = _norm_sym(sym)
        sd = str(side or '').upper().strip()
        if s:
            open_keys.add((s, sd))
            if sd:
                open_keys.add((s, ''))
        sid = str(setup_id or '').strip()
        if sid:
            open_setup_ids.add(sid)

    try:
        for t in list(_autotrade_db_open_trades(uid_i) or []):
            _add_open(t.get('symbol'), t.get('side'), t.get('setup_id'))
    except Exception:
        pass

    try:
        cache_delete('bybit_open_positions_linear')
    except Exception:
        pass
    try:
        for pos in list(_bybit_get_open_positions_linear() or []):
            try:
                qty = abs(float(_pos_size(pos) or 0.0))
                if qty <= 0:
                    continue
                _add_open(_pos_symbol(pos), _pos_side_text(pos), '')
            except Exception:
                continue
    except Exception:
        pass

    changed = False
    for r in rows:
        try:
            status = str(r.get('status') or '').upper().strip()
            reason = str(r.get('reason') or '').lower()
            if status != 'SKIP':
                continue
            if 'timeout' not in reason and 'place_trade_timeout' not in reason:
                continue
            sid = str(r.get('setup_id') or r.get('id') or '').strip()
            sym = _norm_sym(r.get('symbol') or r.get('symbol_sent') or r.get('symbol_raw') or '')
            side = str(r.get('side') or '').upper().strip()
            matched = bool(sid and sid in open_setup_ids) or bool(sym and ((sym, side) in open_keys or (sym, '') in open_keys))
            if matched:
                r['status'] = 'PLACED'
                original = str(r.get('reason') or '')
                r['reason'] = 'placed_after_timeout_confirmed_open_position'
                r['timeout_original_reason'] = original
                changed = True
        except Exception:
            continue

    if changed:
        try:
            _LAST_AUTOTRADE_ATTEMPTS[uid_i] = rows[:100]
            dec = dict(_LAST_AUTOTRADE_DECISION.get(uid_i) or {})
            if dec and str(dec.get('status') or '').upper() == 'SKIP':
                dec['status'] = 'PLACED'
                dec['reason'] = 'placed_after_timeout_confirmed_open_position'
                dec['attempted_candidates'] = rows[:8]
                _LAST_AUTOTRADE_DECISION[uid_i] = dec
        except Exception:
            pass
    return rows

async def autotrade_last_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Show recent autotrade attempts as a clean /setup_audit-style table (admin only)."""
    uid = update.effective_user.id
    if not is_admin_user(uid):
        await update.message.reply_text("⛔️ Admin only.")
        return

    owner = int(AUTOTRADE_OWNER_UID or uid)
    dec = _LAST_AUTOTRADE_DECISION.get(owner) or {}
    hist = list(_LAST_AUTOTRADE_ATTEMPTS.get(owner) or [])
    dec_attempts = list(dec.get('attempted_candidates') or []) if isinstance(dec, dict) else []
    if dec_attempts:
        hist = list(hist or []) + list(dec_attempts or [])
    # yver44: include persisted attempt rows so /autotrade_last 30 is not limited
    # to the tiny in-memory slice since the last handler cycle/restart.
    try:
        persisted = _autotrade_load_attempt_rows(owner, limit=60)
    except Exception:
        persisted = []
    if persisted:
        merged = []
        seen = set()
        for rr in list(hist or []) + list(persisted or []):
            try:
                d = dict(rr or {})
                key = (str(d.get('when') or d.get('when_iso') or d.get('when_ts') or ''), str(d.get('setup_id') or ''), str(d.get('symbol') or d.get('symbol_sent') or d.get('symbol_raw') or ''), str(d.get('side') or ''), str(d.get('reason') or ''))
                if key in seen:
                    continue
                seen.add(key)
                merged.append(d)
            except Exception:
                continue
        merged.sort(key=lambda x: _autotrade_attempt_ts(x), reverse=True)
        hist = merged
    try:
        hist = _autotrade_reconcile_attempt_rows_for_display(owner, hist)
        if isinstance(dec, dict) and dec.get('attempted_candidates'):
            dec['attempted_candidates'] = _autotrade_reconcile_attempt_rows_for_display(owner, list(dec.get('attempted_candidates') or []))
    except Exception:
        pass
    # yver46: collapse near-identical diagnostics in the display so a single
    # setup retried by email/immediate/scheduled jobs does not flood the table.
    # This is display-only; persisted raw diagnostics remain available in SQLite.
    try:
        compact_hist = []
        seen_compact = set()
        for _r in list(hist or []):
            try:
                _ts = int(_autotrade_attempt_ts(_r) // 60)  # same local minute bucket
                _sym = str(_r.get('symbol') or _r.get('symbol_sent') or _r.get('symbol_raw') or '').upper()
                if _sym.endswith('USDT'):
                    _sym = _sym[:-4]
                _key = (
                    _ts,
                    str(_r.get('setup_id') or _r.get('id') or ''),
                    _sym,
                    str(_r.get('side') or '').upper(),
                    str(_r.get('status') or '').upper(),
                    _setup_audit_short_autotrade_reason(str(_r.get('reason') or '')),
                    str(_r.get('entry') or ''),
                    str(_r.get('sl') or ''),
                )
                if _key in seen_compact:
                    continue
                seen_compact.add(_key)
                compact_hist.append(_r)
            except Exception:
                compact_hist.append(_r)
        hist = compact_hist
    except Exception:
        pass

    # yver63: remove ghost duplicate rows that have no timestamp when a real
    # timestamped attempt for the same setup/symbol/side/reason/entry/SL exists.
    # This is display-only; the raw persisted diagnostics are left untouched.
    try:
        def _yver63_attempt_sig(_r):
            _sym = str(_r.get('symbol') or _r.get('symbol_sent') or _r.get('symbol_raw') or '').upper()
            if _sym.endswith('USDT'):
                _sym = _sym[:-4]
            return (
                str(_r.get('setup_id') or _r.get('id') or ''),
                _sym,
                str(_r.get('side') or '').upper(),
                str(_r.get('status') or '').upper(),
                _setup_audit_short_autotrade_reason(str(_r.get('reason') or '')),
                _autotrade_price_str(_r.get('entry')),
                _autotrade_price_str(_r.get('sl')),
            )
        _with_time = set()
        for _r in list(hist or []):
            try:
                if str(_r.get('when') or _r.get('when_iso') or _r.get('when_ts') or '').strip():
                    _with_time.add(_yver63_attempt_sig(_r))
            except Exception:
                pass
        _clean_hist = []
        _seen_no_time = set()
        for _r in list(hist or []):
            try:
                _has_time = bool(str(_r.get('when') or _r.get('when_iso') or _r.get('when_ts') or '').strip())
                _sig = _yver63_attempt_sig(_r)
                if not _has_time and _sig in _with_time:
                    continue
                if not _has_time and _sig in _seen_no_time:
                    continue
                if not _has_time:
                    _seen_no_time.add(_sig)
                _clean_hist.append(_r)
            except Exception:
                _clean_hist.append(_r)
        hist = _clean_hist
    except Exception:
        pass

    lines = ["🤖 <b>AutoTrade — Last Attempts</b>", HDR]
    if not hist and not dec:
        lines.append("No attempts recorded yet.")
        await send_long_message(update, "\n".join(lines), parse_mode='HTML')
        return

    if dec:
        when_raw = str(dec.get('when') or '')
        last_status = html.escape(str(dec.get('status') or '—').upper())
        last_reason = html.escape(_setup_audit_short_autotrade_reason(str(dec.get('reason') or '')) if str(dec.get('reason') or '') else '-')
        lines.append(f"Last decision: <b>{last_status}</b> | {last_reason}")
        if when_raw:
            lines.append(f"Decision time: <b>{html.escape(_fmt_iso_to_local(when_raw))}</b>")
        if dec.get('trigger'):
            lines.append(f"Trigger: <code>{html.escape(str(dec.get('trigger') or ''))}</code>")
        try:
            sel = dict(dec.get('selector_top_reasons') or {})
            if sel:
                compact = ', '.join([f"{k}={v}" for k, v in list(sel.items())[:5]])
                lines.append(f"Selector reasons: {html.escape(compact)}")
        except Exception:
            pass
        lines.append(HDR)

    try:
        args = [str(a).strip() for a in (context.args or []) if str(a).strip()]
        max_rows = int(float(args[0])) if args and re.fullmatch(r'\d+(\.\d+)?', args[0]) else 15
    except Exception:
        max_rows = 15
    max_rows = max(1, min(30, int(max_rows or 15)))

    table_rows = []
    for i, a in enumerate(hist[:max_rows], start=1):
        try:
            when_raw = str(a.get('when') or a.get('when_iso') or '')
            if not when_raw and str(a.get('when_ts') or '').strip():
                try:
                    when_raw = datetime.fromtimestamp(float(a.get('when_ts')), tz=timezone.utc).isoformat()
                except Exception:
                    when_raw = ''
            when_txt = _fmt_iso_to_local(when_raw) if when_raw else '—'
            try:
                m = re.search(r'(\d{2}-\d{2}\s+\d{2}:\d{2})', when_txt)
                if m:
                    when_txt = m.group(1)
            except Exception:
                pass
            sym = str(a.get('symbol') or a.get('symbol_sent') or a.get('symbol_raw') or '—')
            if sym.upper().endswith('USDT'):
                sym = sym[:-4]
            side = str(a.get('side') or '—').upper()
            status = str(a.get('status') or '').upper() or '—'
            reason = str(a.get('reason') or '').strip()
            entry = _autotrade_price_str(a.get('entry'))
            sl = _autotrade_price_str(a.get('sl'))
            drift_txt = '-'
            try:
                drift = a.get('entry_drift_pct', '')
                drift_dir = str(a.get('entry_drift_direction') or '').strip().lower()
                adverse = a.get('entry_drift_adverse_pct', '')
                if drift not in ('', None):
                    if drift_dir in {'favourable', 'favorable'}:
                        drift_txt = f"{float(drift):+.2f}% fav"
                    elif drift_dir == 'adverse':
                        try:
                            drift_txt = f"{float(adverse):.2f}% adv"
                        except Exception:
                            drift_txt = f"{float(drift):.2f}% adv"
                    else:
                        drift_txt = f"{float(drift):+.2f}%"
            except Exception:
                pass
            risk_txt = '-'
            try:
                if a.get('allowed_risk_pct') not in ('', None):
                    risk_txt = f"{float(a.get('allowed_risk_pct')):.2f}%"
                elif a.get('risk_actual_pct') not in ('', None):
                    risk_txt = f"{float(a.get('risk_actual_pct')):.2f}%"
            except Exception:
                risk_txt = '-'
            reason_short = _setup_audit_short_autotrade_reason(reason) if reason else '-'
            table_rows.append([i, when_txt, sym, side, status, reason_short, entry, sl, drift_txt, risk_txt])
        except Exception:
            continue

    if table_rows:
        table = tabulate(
            table_rows,
            headers=['#', 'Time', 'Sym', 'Side', 'Status', 'Why', 'Entry', 'SL', 'Drift', 'Risk'],
            tablefmt='plain',
            colalign=('right', 'left', 'left', 'center', 'center', 'left', 'right', 'right', 'right', 'right'),
        )
        lines.append("<pre>" + html.escape(table) + "</pre>")
        lines.append(HDR)
        lines.append("Tip: <code>/autotrade_last 30</code> shows up to 30 recent attempts.")
    else:
        lines.append("No attempt rows found yet for this process/DB window.")

    await send_long_message(update, "\n".join(lines), parse_mode='HTML')

async def autotrade_debug_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """AutoTrade readiness + last decision diagnostics (admin only)."""
    uid = update.effective_user.id
    if not is_admin_user(uid):
        await update.message.reply_text("⛔️ Admin only.")
        return

    owner = int(AUTOTRADE_OWNER_UID or uid)
    user = get_user(owner) or {}
    now_utc = datetime.now(timezone.utc)
    sess = current_session_utc(now_utc)
    ready = _autotrade_ready()
    sess_allowed = (sess != 'NONE') and _autotrade_allowed_session(sess)
    # Ver25: /autotrade_debug also self-heals any carried AutoTrade position
    # that survived past the 10:00 Melbourne reset despite the 09:55 flat rule.
    # After this, carried risk should normally be zero whenever flat-before-ASIA is ON.
    try:
        if bool(_autotrade_flat_before_asia_enabled()) and str(_autotrade_runtime_mode()).lower() == 'live':
            await to_thread_fast(_autotrade_close_carried_live_positions_after_reset, int(owner), 'debug_zero_carryover_after_10_melbourne', timeout=min(20, FAST_ADMIN_COMMAND_TIMEOUT_SEC))
    except Exception:
        pass

    try:
        snap = await to_thread_fast(_accounting_snapshot_cached, owner, user, is_admin=True, ttl=FAST_ADMIN_SNAPSHOT_TTL_SEC, force_refresh=True, timeout=FAST_ADMIN_COMMAND_TIMEOUT_SEC)
    except Exception:
        snap = _accounting_snapshot_cached(owner, user, is_admin=True, ttl=FAST_ADMIN_SNAPSHOT_TTL_SEC, force_refresh=True)
    equity = float(snap.get('equity') or 0.0)
    try:
        mday = await to_thread_fast(_autotrade_day_risk_metrics_cached, int(owner), float(equity), ttl=FAST_ADMIN_METRICS_TTL_SEC, force_refresh=True, timeout=FAST_ADMIN_COMMAND_TIMEOUT_SEC)
    except Exception:
        mday = _autotrade_day_risk_metrics_cached(int(owner), float(equity), ttl=FAST_ADMIN_METRICS_TTL_SEC, force_refresh=True)
    # Ver12: debug closed/PnL should match /autotrade_report. The quick risk snapshot
    # can miss exchange-derived/provisional closes, so reconcile against the same report rows.
    try:
        _start_utc, _end_utc = _admin_today_window_utc(uid=int(owner), user=user)
        _closed_report_rows = _autotrade_closed_report_rows(int(owner), float(_start_utc.timestamp()), float(_end_utc.timestamp()), lookback_h=24, limit=0) or []
        _closed_report_pnl = float(sum(float((r or {}).get('pnl_usdt') if (r or {}).get('pnl_usdt') is not None else (r or {}).get('pnl') or 0.0) for r in _closed_report_rows))
        if len(_closed_report_rows) > int(snap.get('positions_closed_today', 0) or 0) or abs(_closed_report_pnl) > abs(float(snap.get('pnl_today') or 0.0)):
            snap['positions_closed_today'] = int(len(_closed_report_rows))
            snap['closed_today_rows'] = list(_closed_report_rows)
            snap['pnl_today'] = float(_closed_report_pnl)
            mday['closed_today_count'] = int(len(_closed_report_rows))
            mday['closed_today_rows'] = list(_closed_report_rows)
            mday['realized_pnl_today'] = float(_closed_report_pnl)
            mday['realized_loss_today'] = float(sum(abs(float((r or {}).get('pnl_usdt') if (r or {}).get('pnl_usdt') is not None else (r or {}).get('pnl') or 0.0)) for r in _closed_report_rows if float((r or {}).get('pnl_usdt') if (r or {}).get('pnl_usdt') is not None else (r or {}).get('pnl') or 0.0) < 0.0))
            # Recalculate daily used with realised PnL credit/debit.
            # Ver17: use all live open AT risk, including carried positions.
            _raw_used = max(0.0, float(snap.get('current_total_open_risk') or snap.get('live_open_risk_charged_today') or snap.get('current_day_open_risk') or 0.0) - float(_closed_report_pnl))
            _used_eff, _reset_credit = _risk_day_reset_effective_used(int(owner), user, _raw_used)
            snap['used_today'] = float(_used_eff)
            snap['used_today_raw'] = float(_raw_used)
            snap['risk_reset_credit'] = float(_reset_credit)
            _cap = float(snap.get('cap') or 0.0)
            if _cap > 0:
                snap['remaining_today'] = max(0.0, _cap - float(_used_eff))
    except Exception:
        pass

    dec = _LAST_AUTOTRADE_DECISION.get(owner) or {}
    email_gate = _email_runtime_limits_snapshot(int(owner), user)

    reasons = []
    if not AUTOTRADE_ENABLED:
        reasons.append('AUTOTRADE_ENABLED=0')
    if owner <= 0:
        reasons.append('AUTOTRADE_OWNER_UID missing/0')
    if str(_autotrade_runtime_mode()).lower() == 'live' and (not BYBIT_API_KEY or not BYBIT_API_SECRET):
        reasons.append('missing BYBIT_API_KEY/SECRET')
    if not _autotrade_entry_enabled():
        reasons.append('autotrade_entries_off')

    session_cap_txt = '∞' if int(email_gate.get('session_cap', 0) or 0) <= 0 else str(int(email_gate.get('session_cap', 0) or 0))
    day_cap_txt = '∞' if int(email_gate.get('day_cap', 0) or 0) <= 0 else str(int(email_gate.get('day_cap', 0) or 0))
    gap_remaining = int(email_gate.get('gap_remaining_sec', 0) or 0)
    gate_reason = ', '.join([str(r) for r in (email_gate.get('gate_reasons') or [])[:3]])

    exec_recent = 0
    emailed_recent = 0
    sent_email_batches_recent = 0
    since_ts = time.time() - 12 * 3600
    try:
        con = db_connect()
        cur = con.cursor()
        # Count unique live opportunities, not every scanner refresh row.
        # Raw row counts can be huge because equivalent executable opportunities
        # are refreshed repeatedly during background scans.
        min_vol = float(_setup_min_volume_floor_usd())
        try:
            cur.execute("""
                SELECT COUNT(DISTINCT UPPER(COALESCE(NULLIF(symbol,''), setup_id)) || ':' || UPPER(COALESCE(NULLIF(side,''),'?'))) AS n
                FROM executable_setups
                WHERE user_id IN (?,0) AND executable_ts>=? AND COALESCE(fut_vol_usd,0)>=?
            """, (int(owner), float(since_ts), float(min_vol)))
        except Exception:
            cur.execute("""
                SELECT COUNT(DISTINCT UPPER(COALESCE(NULLIF(symbol,''), setup_id)) || ':' || UPPER(COALESCE(NULLIF(side,''),'?'))) AS n
                FROM executable_setups
                WHERE user_id IN (?,0) AND executable_ts>=?
            """, (int(owner), float(since_ts)))
        row = cur.fetchone()
        try:
            exec_recent = int(row['n'] if hasattr(row, 'keys') and 'n' in row.keys() else row[0])
        except Exception:
            exec_recent = 0

        cur.execute("SELECT COUNT(DISTINCT setup_id) AS n FROM emailed_setups WHERE user_id IN (?,0) AND emailed_ts>=?", (int(owner), float(since_ts)))
        row = cur.fetchone()
        try:
            emailed_recent = int(row['n'] if hasattr(row, 'keys') and 'n' in row.keys() else row[0])
        except Exception:
            emailed_recent = 0

        try:
            # Approximate sent setup-email batches; multiple setups in one email
            # share nearly identical timestamps.
            cur.execute("SELECT COUNT(DISTINCT CAST(emailed_ts / 60 AS INTEGER)) AS n FROM emailed_setups WHERE user_id IN (?,0) AND emailed_ts>=?", (int(owner), float(since_ts)))
            row = cur.fetchone()
            sent_email_batches_recent = int(row['n'] if hasattr(row, 'keys') and 'n' in row.keys() else row[0])
        except Exception:
            sent_email_batches_recent = 0
        con.close()
    except Exception:
        try:
            con.close()
        except Exception:
            pass

    # Ver21: make /autotrade_debug accounting explicit and non-ambiguous.
    # "Opened today" is a journal/exchange activity count inside the current
    # Melbourne trading-day window. The open-position split is live-position
    # age/risk bucketing, so carried positions are shown separately instead of
    # making the risk split look inconsistent.
    _open_now_i = int(snap.get('open_positions_now', 0) or 0)
    _carried_open_i = int(snap.get('inherited_open_positions', 0) or 0)
    _current_open_i = max(0, int(_open_now_i) - int(_carried_open_i))
    _opened_today_i = int(snap.get('positions_opened_today', 0) or 0)
    _closed_today_i = int(snap.get('positions_closed_today', 0) or 0)
    _max_trades_day_i = int(_autotrade_runtime_max_trades_per_day() or 0)
    _max_trades_day_txt = '∞' if _max_trades_day_i <= 0 else str(_max_trades_day_i)

    _debug_open_risk_display = float(snap.get('current_total_open_risk', 0.0) or 0.0)
    _debug_realised_display = float(snap.get('pnl_today') or 0.0)
    _debug_risk_credit_display = max(0.0, float(snap.get('risk_reset_credit') or 0.0))
    # Ver30: single sign-safe formula. Positive realised PnL reduces daily
    # risk pressure; realised losses increase it. This prevents the confusing
    # case where Realised net is positive but Daily risk used rises by that
    # same amount.
    _debug_daily_used_raw = max(0.0, float(_debug_open_risk_display) - float(_debug_realised_display))
    _debug_daily_used_display = max(0.0, float(_debug_daily_used_raw) - float(_debug_risk_credit_display))
    _debug_cap_display = float(snap.get('cap') or 0.0)
    _debug_remaining_display = float('inf') if _debug_cap_display <= 0 else max(0.0, _debug_cap_display - _debug_daily_used_display)
    try:
        snap['used_today'] = float(_debug_daily_used_display)
        snap['used_today_raw'] = float(_debug_daily_used_raw)
        snap['remaining_today'] = float(_debug_remaining_display)
    except Exception:
        pass

    lines = [
        '🧪 AutoTrade Debug',
        HDR,
        f"Ready: {'✅' if ready else '❌'} | Mode: {str(_autotrade_runtime_mode()).lower()} | Entries: {'ON' if _autotrade_entry_enabled() else 'OFF'} | Session: {sess} ({'allowed' if sess_allowed else 'blocked'})",
        f"Trading day: {snap.get('today_window_label')}",
        "Configured sessions: ASIA/LON/NY active by default; current Session line only shows the active session/time block right now.",
        (f"Keep-all test: ON | Daily flat: {'ON' if _autotrade_flat_before_asia_enabled() else 'OFF'} {int(_autotrade_flat_before_asia_hour()):02d}:{int(_autotrade_flat_before_asia_minute()):02d} | Max-hold: {'ON' if _autotrade_max_position_hours_enabled() else 'OFF'} | Entry window: {int(_autotrade_entry_window_min())}m" if _autotrade_keep_all_test_mode() else None),
        (f"Count caps: max-open {int(_autotrade_runtime_max_open_trades())} | max/day {_max_trades_day_txt} | Batch/tick cap: ∞ | Entry blackout: {'ON' if _autotrade_entry_blackout_enabled() else 'OFF'} | Setup blackout: {'ON' if _setup_generation_blackout_enabled() else 'OFF'}" if bool(globals().get('AUTOTRADE_KEEP_ALL_TEST_UNLIMITED_MODE', False)) and bool(globals().get('AUTOTRADE_KEEP_ALL_TEST_DISABLE_COUNT_CAPS', True)) else None),
        SEP,
        f"EquityAT: ${equity:.2f}",
        f"Daily cap (AT): {str(_autotrade_daily_cap_settings()[0]).upper()} {float(_autotrade_daily_cap_settings()[1] or 0.0):.2f}{'%' if str(_autotrade_daily_cap_settings()[0]).upper() == 'PCT' else ''} (≈ ${float(snap.get('cap') or 0.0):.2f})",
        f"Opened today (AT): {_opened_today_i}/{_max_trades_day_txt} | Closed today (AT): {_closed_today_i} | Open now (AT): {_open_now_i}",
        (f"Open split (AT): current-day {_current_open_i} | carried {_carried_open_i} ⚠️ carryover guard should close" if _carried_open_i > 0 and bool(_autotrade_flat_before_asia_enabled()) else (f"Open split (AT): current-day {_current_open_i} | carried {_carried_open_i}" if _carried_open_i > 0 else f"Open split (AT): current-day {_current_open_i} | carried 0")),
        f"Open risk now (AT): ${_debug_open_risk_display:.2f}",
        f"Open PnL now (AT): ${float(mday.get('open_pnl') or 0.0):+.2f}",
        f"Risk split (AT): current-day ${float(snap.get('current_day_open_risk', 0.0)):.2f} | carried ${float(snap.get('carried_open_risk', 0.0)):.2f}",
        (f"Ignored unmatched live positions (AT): {int(snap.get('external_open_positions', 0) or 0)} | Risk ${float(snap.get('external_open_risk', 0.0)):.2f}" if int(snap.get('external_open_positions', 0) or 0) > 0 else None),
        f"Realised net today (AT): ${_debug_realised_display:+.2f}",
        f"Daily risk used (AT) (open risk - realised net): ${_debug_daily_used_display:.2f}",
        ('Daily risk remaining (AT): ∞' if not math.isfinite(float(_debug_remaining_display)) else f"Daily risk remaining (AT): ${float(_debug_remaining_display):.2f}"),
        SEP,
        'Email / AutoTrade entry gate',
        f"AutoTrade lane filter: {('KEEP+WATCH policy ON' if _autotrade_allow_watch_policy() else 'KEEP-only policy ON') if _autotrade_require_keep_policy() else 'policy filter OFF'}",
        f"AutoTrade capital guard: daily loss stop {'ON' if _autotrade_daily_realized_loss_stop_enabled() else 'OFF'} {_autotrade_daily_realized_loss_stop_pct():.1f}% | realised-combo {'ON' if _autotrade_require_realized_combo_edge() else 'OFF'} | context feed {'ON' if _autotrade_context_feed_guard_enabled() else 'OFF'}",
        f"AutoTrade capital gate: {'OPEN' if _autotrade_daily_realized_loss_stop_allows(int(owner))[0] else 'BLOCKED'} | {_autotrade_daily_realized_loss_stop_allows(int(owner))[1]}",
        f"Recipient: {str(email_gate.get('recipient_masked') or '(none)')}",
        f"Alerts: {'ON' if bool(email_gate.get('alerts_on')) else 'OFF'} | SMTP: {'READY' if bool(email_gate.get('smtp_ready')) else 'NOT READY'}",
        f"Session email cap: {session_cap_txt} (configured)",
        f"Emails sent in session: {int(email_gate.get('sent_in_session', 0) or 0)}",
        f"Daily email cap: {day_cap_txt} (configured)",
        f"Emails sent today: {int(email_gate.get('sent_today', 0) or 0)}",
        f"Email gap: {int(email_gate.get('gap_min', 0) or 0)}m" + (f" (remaining {_fmt_dur(gap_remaining)})" if gap_remaining > 0 else ''),
        f"Email/AutoTrade gate: {'OPEN' if bool(email_gate.get('gate_open')) else 'BLOCKED'}" + (f" | {gate_reason}" if gate_reason else ''),
        f"Recent emailed setups (unique, 12h): {emailed_recent}",
        f"Recent executable setups (unique sym/side, 12h): {exec_recent}",
    ]
    try:
        lines.append(f"Recent sent setup-email batches (12h): {int(sent_email_batches_recent or 0)}")
    except Exception:
        pass
    try:
        reset_ts = float(_autotrade_cooldown_reset_ts() or 0.0)
        if reset_ts > 0:
            lines.append(f"Cooldown reset marker: {_fmt_dt_local(datetime.fromtimestamp(reset_ts, tz=timezone.utc))}")
    except Exception:
        pass
    if reasons and not ready:
        lines.extend([SEP, 'Blocking reasons'])
        for r in reasons[:6]:
            lines.append(f"• {r}")
    try:
        bot_positions, _external_positions, _journal_open = _autotrade_collect_live_position_rows(owner, fallback_unmatched_as_owned=True)
    except Exception:
        bot_positions, _external_positions, _journal_open = [], [], []
    lines.extend([SEP, f"Open AutoTrade Positions: {len(bot_positions)}"])

    open_pos_table = ''
    if not bot_positions:
        lines.append('• None')
    else:
        table_rows = []
        for p, tr in (bot_positions or []):
            try:
                row = dict(tr or {})
            except Exception:
                row = {}
            sym_txt = _symbol_base(str(row.get('symbol') or (_pos_symbol(p) if p else '') or '')) or '-'
            side_txt = str(row.get('side') or (_pos_side_text(p) if p else '') or '-').upper().strip() or '-'
            try:
                risk_usd = float(_estimate_position_risk_usd(p) or 0.0) if p is not None else 0.0
                if risk_usd <= 0:
                    risk_usd = float(_autotrade_estimated_risk_usd(float(row.get('entry') or 0.0), float(row.get('sl') or 0.0), float(row.get('qty') or 0.0)) or 0.0)
            except Exception:
                risk_usd = 0.0
            try:
                pnl_usd = float(_pos_unreal_pnl(p) or 0.0) if p is not None else 0.0
            except Exception:
                pnl_usd = 0.0
            table_rows.append([sym_txt, side_txt, f"${float(risk_usd or 0.0):.2f}", f"{float(pnl_usd or 0.0):+.2f}"])
        try:
            open_pos_table = tabulate(
                table_rows,
                headers=['Symbol', 'Side', 'Risk', 'PnL'],
                tablefmt='plain',
                colalign=('left', 'center', 'right', 'right'),
            )
        except Exception:
            open_pos_table = '\n'.join([f"{r[0]} {r[1]} {r[2]} {r[3]}" for r in table_rows])

    lines = [str(ln) for ln in lines if ln is not None and str(ln) != '']
    # Ver18: use HTML <pre> for the open-position table and escape all
    # dynamic text so Telegram keeps the table aligned and never exposes
    # internal trade IDs in /autotrade_debug.
    msg = "\n".join(html.escape(str(ln)) for ln in lines)
    if open_pos_table:
        msg += "\n<pre>" + html.escape(open_pos_table) + "</pre>"
    await send_long_message(update, msg, parse_mode=ParseMode.HTML)

async def open_trades_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Show open positions. Admin sees AutoTrade live + manual journal; others see manual only."""
    uid = update.effective_user.id
    is_admin = is_admin_user(uid)

    lines: list[str] = []
    lines.append("📌 Open Positions (Bybit)")
    lines.append(HDR)

    def _fam_for_open_row(tr: dict, p: dict | None = None) -> str:
        try:
            row = _setup_audit_merge_trade_setup_row(dict(tr or {}))
            fam = _setup_audit_family_display(row, compact=True)
            if fam and fam != '-':
                return fam
        except Exception:
            pass
        try:
            fam = _setup_audit_family_display(dict(tr or {}), compact=True)
            if fam and fam != '-':
                return fam
        except Exception:
            pass
        return 'F0'

    if is_admin:
        owner_uid = int(AUTOTRADE_OWNER_UID or uid)
        if str(_autotrade_runtime_mode()).lower() == "live":
            try:
                _autotrade_monitor_live_exit_protection(owner_uid)
            except Exception:
                pass
            try:
                _trade_lifecycle_sync(owner_uid, days=7, force=False)
            except Exception:
                pass
            positions = _bybit_get_open_positions_linear() or []
            bot_positions, external_positions, _journal_open = _autotrade_collect_live_position_rows(owner_uid, positions=positions, fallback_unmatched_as_owned=True)
        else:
            bot_positions, external_positions = [], []

        total_pnl = 0.0
        total_risk = 0.0
        lines.append('AutoTrade-owned positions')
        table_txt = ''
        if not bot_positions:
            lines.append('• None')
        else:
            table_rows = []
            for p, tr in bot_positions:
                sym = str(_pos_symbol(p) or (tr or {}).get('symbol') or '').upper().replace('/USDT:USDT','USDT')
                if sym.endswith('USDT'):
                    sym = sym[:-4]
                side = str(_pos_side_text(p) or (tr or {}).get('side') or '').upper() or '-'
                try:
                    risk = max(0.0, float(_estimate_position_risk_usd(p) or 0.0))
                except Exception:
                    risk = 0.0
                try:
                    pnl = float(_pos_unreal_pnl(p) or 0.0)
                except Exception:
                    pnl = 0.0
                fam = _fam_for_open_row(dict(tr or {}), p)
                total_pnl += pnl
                total_risk += risk
                table_rows.append([sym or '-', side or '-', fam or '-', f"{risk:.2f}", f"{pnl:+.2f}"])
            try:
                table_txt = tabulate(
                    table_rows,
                    headers=['Symbol', 'Side', 'Fam', 'Risk', 'PnL'],
                    tablefmt='plain',
                    colalign=('left', 'center', 'center', 'right', 'right'),
                )
            except Exception:
                table_txt = '\n'.join([' '.join(map(str, r)) for r in table_rows])
            lines.append(f"Rows: {len(table_rows)}")
            lines.append(f"AutoTrade unrealised PnL: {total_pnl:+.2f}")
            lines.append(f"AutoTrade risk est: {total_risk:.2f}")

        manual_opens = db_open_trades(uid)
        lines.extend([SEP, f"Manual positions: {len(manual_opens)}"])
        if not manual_opens:
            lines.append('• None')
        else:
            for t in manual_opens[:12]:
                lines.append(_manual_open_trade_compact_line(t))

        if external_positions:
            lines.extend([SEP, f"Unmatched live positions: {len(external_positions)}"])
            ext_rows = []
            for p in external_positions[:12]:
                sym = str(_pos_symbol(p) or '').upper()
                if sym.endswith('USDT'):
                    sym = sym[:-4]
                ext_rows.append([sym or '-', _pos_side_text(p), f"{float(_pos_unreal_pnl(p) or 0.0):+.2f}"])
            try:
                ext_txt = tabulate(ext_rows, headers=['Symbol', 'Side', 'PnL'], tablefmt='plain', colalign=('left','center','right'))
                lines.append('<pre>' + html.escape(ext_txt) + '</pre>')
            except Exception:
                for r in ext_rows:
                    lines.append(' '.join(map(str, r)))

        msg = "\n".join(html.escape(str(x)) if not str(x).startswith('<pre>') else str(x) for x in lines)
        if table_txt:
            # Ver22: table display, no internal Trade ID, no repeated USDT suffix.
            msg = msg.replace('AutoTrade-owned positions', 'AutoTrade-owned positions\n<pre>' + html.escape(table_txt) + '</pre>')
        await send_long_message(update, msg, parse_mode=ParseMode.HTML)
        return

    manual_opens = db_open_trades(uid)
    lines.append('Manual positions')
    if not manual_opens:
        lines.append('• None')
    else:
        for t in manual_opens[:12]:
            lines.append(_manual_open_trade_compact_line(t))
    await send_long_message(update, "\n".join(lines), parse_mode=None)

