def _autotrade_closed_report_rows_for_fixed_overall(owner_uid: int, start_ts: float, end_ts: float) -> list[dict]:
    """Load closed AutoTrade rows for the fixed 1 Jun overall window.

    The original 24h report works because Bybit/reconstruction calls stay inside a short
    range. A single 8+ day exchange request can return no rows on some Bybit endpoints, so
    this helper keeps the original classifier but splits only the history load into safe
    sub-windows and deduplicates the merged result.
    """
    owner_uid = int(owner_uid)
    start_ts = float(start_ts or 0.0)
    end_ts = float(end_ts or 0.0)
    if start_ts <= 0 or end_ts <= start_ts:
        return []
    collected: list[dict] = []
    try:
        direct_hours = int(math.ceil((end_ts - start_ts) / 3600.0))
        direct = _autotrade_closed_report_rows(owner_uid, float(start_ts), float(end_ts), lookback_h=max(24, direct_hours), limit=0) or []
        collected.extend(list(direct or []))
    except Exception:
        pass
    # If the single wide-window call comes back empty/near-empty, rebuild in <=3-day chunks.
    # This keeps the exact same row classifier but avoids wide Bybit history-window failures.
    if len(collected or []) < 3 and (end_ts - start_ts) > 3 * 86400.0:
        try:
            chunk_sec = 3 * 86400.0
            cur = float(start_ts)
            while cur < end_ts - 1:
                nxt = min(float(end_ts), cur + chunk_sec)
                chunk_hours = max(24, int(math.ceil((nxt - cur) / 3600.0)))
                try:
                    part = _autotrade_closed_report_rows(owner_uid, float(cur), float(nxt), lookback_h=chunk_hours, limit=0) or []
                    collected.extend(list(part or []))
                except Exception:
                    pass
                cur = float(nxt)
        except Exception:
            pass
    out: list[dict] = []
    seen: set[tuple] = set()
    for r in collected or []:
        try:
            rr = dict(r or {})
            sid = str(rr.get('setup_id') or '').strip()
            tid = str(rr.get('trade_id') or '').strip()
            sym = str(_bybit_linear_symbol(rr.get('symbol') or '')).upper().strip()
            side = str(rr.get('side') or '').upper().strip()
            cts = int(float(rr.get('closed_ts') or rr.get('ts') or 0.0) // 60)
            pnl = round(float(rr.get('pnl_usdt') if rr.get('pnl_usdt') is not None else rr.get('pnl') or 0.0), 8)
            if sid:
                key = ('setup', sid)
            elif tid and not tid.startswith(('exchange::', 'report::', 'prov::', 'manual::')):
                key = ('trade', tid)
            else:
                key = ('event', sym, side, cts, pnl)
            if key in seen:
                continue
            seen.add(key)
            out.append(rr)
        except Exception:
            continue
    try:
        out.sort(key=lambda x: float((x or {}).get('closed_ts') or (x or {}).get('ts') or 0.0), reverse=True)
    except Exception:
        pass
    return out

def _autotrade_realised_wr_kind(row: dict) -> str:
    """Return WIN/LOSS/FLAT/OPEN for realised AutoTrade WR.

    yver123: AutoTrade WR should be based on closed practical outcomes, excluding
    open rows. TP is a win and SL is a loss. OTHER rows are classified by realised
    PnL sign so daily flat/profit-close/exchange-authority closes still contribute
    to real trading WR instead of disappearing from the denominator.
    """
    try:
        if str((row or {}).get('state') or '').upper().strip() == 'OPEN':
            return 'OPEN'
        kind = str((row or {}).get('closed_kind') or _autotrade_report_closed_kind(row) or '').upper().strip()
        pnl = float((row or {}).get('pnl_usdt') if (row or {}).get('pnl_usdt') is not None else (row or {}).get('pnl') or 0.0)
        eps = float(globals().get('AUTOTRADE_REPORT_TPSL_SIGN_EPS_USD', 0.50) or 0.50)
        if kind == 'TP' or pnl > eps:
            return 'WIN'
        if kind == 'SL' or pnl < -eps:
            return 'LOSS'
        return 'FLAT'
    except Exception:
        return 'FLAT'

def _autoytrade_report_overall_text_cached(owner_uid: int, lookback_h: int = 24) -> str:
    """Family/session AutoTrade matrix based on actual AutoTrade positions and PnL."""
    owner_uid = int(owner_uid)
    lookback_h = int(clamp(int(lookback_h or 24), 1, 8760))
    _now_for_key = float(time.time())
    _fixed_overall = bool(lookback_h >= max(1, int(_overall_report_hours_since_start(_now_for_key)) - 1))
    _fixed_start_ts = float(_overall_report_start_ts() or 0.0) if _fixed_overall else 0.0
    cache_key = f"autoytrade_report_overall:v123_realised_wr:{owner_uid}:{lookback_h}:{int(_fixed_start_ts or 0)}"
    try:
        if cache_valid(cache_key, int(AUTOTRADE_REPORT_CACHE_TTL_SEC or 20)):
            cached = cache_get(cache_key)
            if isinstance(cached, str) and cached.strip():
                return cached
    except Exception:
        pass
    _autotrade_migrate_tables()
    now_ts = float(time.time())
    start_ts = float(_fixed_start_ts or 0.0) if _fixed_overall and float(_fixed_start_ts or 0.0) > 0 else (now_ts - float(lookback_h) * 3600.0)

    def _family_for_report(row: dict) -> str:
        try:
            fam = _setup_audit_family_display(row, compact=True)
            if fam and fam != '-':
                return fam
            eng = str((row or {}).get('engine') or '').strip()
            fam2 = _setup_family_id_to_code(_setup_engine_to_family_id(eng, row))
            return fam2 if fam2 and fam2 != '-' else 'F0'
        except Exception:
            return 'F0'

    def _sym_display(row: dict, fallback: str = '') -> str:
        try:
            sym = str((row or {}).get('symbol') or fallback or '').upper().strip()
            if sym.endswith('USDT'):
                sym = sym[:-4]
            return sym or '-'
        except Exception:
            return '-'

    rows: list[dict] = []
    open_positions = _bybit_get_open_positions_linear() if str(_autotrade_runtime_mode()).lower() == 'live' else []
    bot_positions, external_positions, _journal_open = _autotrade_collect_live_position_rows(owner_uid, positions=open_positions, fallback_unmatched_as_owned=True)
    try:
        if _fixed_overall:
            closed_rows = _autotrade_closed_report_rows_for_fixed_overall(owner_uid, float(start_ts), float(now_ts)) or []
        else:
            closed_rows = _autotrade_closed_report_rows(owner_uid, float(start_ts), float(now_ts), lookback_h=lookback_h, limit=0) or []
    except Exception:
        closed_rows = []

    for p, tr in (bot_positions or []):
        row = _setup_audit_merge_trade_setup_row(tr)
        ts = float(row.get('opened_ts') or now_ts)
        rows.append({
            'ts': ts,
            'time': datetime.fromtimestamp(ts, tz=timezone.utc).astimezone(MEL_TZ).strftime('%m-%d %H:%M'),
            'state': 'OPEN',
            'symbol': _sym_display(row, _pos_symbol(p)),
            'side': str(row.get('side') or _pos_side_text(p) or '').upper().strip() or '-',
            'setup_strategy': _setup_strategy_label(row),
            'strategy': _setup_strategy_label(row),
            'family': _family_for_report(row),
            'session': _autotrade_report_row_session(row),
            'pnl': float(_pos_unreal_pnl(p) or 0.0),
            'parts': 1,
        })

    for r in (closed_rows or []):
        row = _setup_audit_merge_trade_setup_row(r)
        ts = float(row.get('closed_ts') or r.get('closed_ts') or row.get('opened_ts') or 0.0)
        try:
            pnl = float(row.get('pnl_usdt') if row.get('pnl_usdt') is not None else row.get('pnl') or 0.0)
        except Exception:
            pnl = 0.0
        rows.append({
            'ts': ts,
            'time': datetime.fromtimestamp(ts, tz=timezone.utc).astimezone(MEL_TZ).strftime('%m-%d %H:%M') if ts > 0 else '-',
            'state': 'CLOSED',
            'symbol': _sym_display(row, r.get('symbol') or ''),
            'side': str(row.get('side') or r.get('side') or '').upper().strip() or '-',
            'setup_strategy': _setup_strategy_label(row),
            'strategy': _setup_strategy_label(row),
            'family': _family_for_report(row),
            'session': _autotrade_report_row_session(row),
            'setup_id': str(row.get('setup_id') or r.get('setup_id') or ''),
            'trade_id': str(row.get('trade_id') or r.get('trade_id') or ''),
            'opened_ts': float(row.get('opened_ts') or r.get('opened_ts') or 0.0),
            'closed_ts': ts,
            'result_path': str(row.get('result_path') or r.get('result_path') or ''),
            'result_label': str(row.get('result_label') or r.get('result_label') or ''),
            'close_reason': str(row.get('close_reason') or r.get('close_reason') or ''),
            'note': str(row.get('note') or r.get('note') or ''),
            'source_note': str(row.get('source_note') or r.get('source_note') or ''),
            'entry': float(row.get('entry') or r.get('entry') or 0.0),
            'sl': float(row.get('sl') or r.get('sl') or 0.0),
            'tp': float(row.get('tp') or r.get('tp') or 0.0),
            'qty': float(row.get('qty') or r.get('qty') or 0.0),
            'conf': int(float(row.get('conf') or r.get('conf') or row.get('confidence') or 0.0)),
            'fut_vol_usd': float(row.get('fut_vol_usd') or r.get('fut_vol_usd') or 0.0),
            'ch24': float(row.get('ch24') or r.get('ch24') or 0.0),
            'ch4': float(row.get('ch4') or r.get('ch4') or 0.0),
            'ch1': float(row.get('ch1') or r.get('ch1') or 0.0),
            'pnl': pnl,
            'pnl_usdt': pnl,
            'parts': 1,
        })

    merged = _autotrade_merge_position_report_rows(rows)
    buckets = defaultdict(lambda: {'trades': 0, 'tp': 0, 'sl': 0, 'open': 0, 'other': 0, 'wins': 0, 'losses': 0, 'flat': 0, 'pnl': 0.0, 'parts': 0, 'loss_reasons': defaultdict(int)})
    for r in merged:
        fam = str(r.get('family') or 'F0').upper().strip() or 'F0'
        sess = str(r.get('session') or _autotrade_report_row_session(r) or 'UNK').upper().strip() or 'UNK'
        strat = _setup_strategy_short_label(r)
        side = _setup_side_suffix(value=str(r.get('side') or ''))
        key = (fam, sess, strat, side)
        b = buckets[key]
        b['trades'] += 1
        b['parts'] += int(r.get('parts') or 1)
        b['pnl'] += float(r.get('pnl') or 0.0)
        if str(r.get('state') or '').upper().strip() == 'OPEN':
            b['open'] += 1
        else:
            kind = str(r.get('closed_kind') or _autotrade_report_closed_kind(r)).upper().strip()
            realised_kind = _autotrade_realised_wr_kind(r)
            if kind == 'TP':
                b['tp'] += 1
            elif kind == 'SL':
                b['sl'] += 1
                try:
                    b['loss_reasons'][_autotrade_report_loss_reason(r)] += 1
                except Exception:
                    b['loss_reasons']['LOSS_CLOSE'] += 1
            else:
                b['other'] += 1
            if realised_kind == 'WIN':
                b['wins'] += 1
            elif realised_kind == 'LOSS':
                b['losses'] += 1
                if kind != 'SL':
                    try:
                        b['loss_reasons'][_autotrade_report_loss_reason(r)] += 1
                    except Exception:
                        b['loss_reasons']['LOSS_CLOSE'] += 1
            elif realised_kind == 'FLAT':
                b['flat'] += 1

    total_tp = sum(int(v.get('tp') or 0) for v in buckets.values())
    total_sl = sum(int(v.get('sl') or 0) for v in buckets.values())
    total_other = sum(int(v.get('other') or 0) for v in buckets.values())
    total_open = sum(int(v.get('open') or 0) for v in buckets.values())
    total_pnl = sum(float(v.get('pnl') or 0.0) for v in buckets.values())
    total_trades = sum(int(v.get('trades') or 0) for v in buckets.values())
    total_wins = sum(int(v.get('wins') or 0) for v in buckets.values())
    total_losses = sum(int(v.get('losses') or 0) for v in buckets.values())
    total_flat = sum(int(v.get('flat') or 0) for v in buckets.values())
    raw_fragments = int(len(rows or []))
    decided = total_wins + total_losses
    wr = (total_wins / decided * 100.0) if decided > 0 else 0.0
    try:
        now_txt = datetime.fromtimestamp(now_ts, tz=timezone.utc).astimezone(MEL_TZ).strftime('%Y-%m-%d %H:%M')
    except Exception:
        now_txt = ''
    _report_title = '📊 AutoTrade Report Overall' if _fixed_overall else '📊 AutoTrade Report Matrix'
    lines = [
        _report_title,
        HDR,
        (f'Window: from {_overall_report_start_txt()} Melbourne' if _fixed_overall else f'Window: last {lookback_h}h (Melbourne)') + (f' | Now: {now_txt}' if now_txt else ''),
        f'Position rows: {total_trades} | Raw fragments merged: {raw_fragments} | TP: {total_tp} | SL: {total_sl} | Other: {total_other} | Open: {total_open} | WR: {wr:.1f}% | PnL: {total_pnl:+.2f} USDT',
        f'Realised WR basis: wins={total_wins} / losses={total_losses}; OPEN excluded; near-zero FLAT excluded; OTHER uses PnL sign (positive=win, negative=loss).',
    ]
    if external_positions:
        lines.append(f'Ignored unmatched manual/external live positions: {len(external_positions)}')
    if not buckets:
        lines.append(SEP)
        lines.append('No AutoTrade rows found in this window.')
        out = '\n'.join(lines)
        cache_set(cache_key, out)
        return out

    table_rows = []
    for (fam, sess, strat, side), v in sorted(buckets.items(), key=lambda kv: (float(kv[1].get('pnl') or 0.0), int(kv[1].get('tp') or 0), -int(kv[1].get('sl') or 0)), reverse=True):
        d = int(v.get('wins') or 0) + int(v.get('losses') or 0)
        wr_i = (int(v.get('wins') or 0) / d * 100.0) if d > 0 else 0.0
        try:
            loss_reasons = dict(v.get('loss_reasons') or {})
            top_loss = max(loss_reasons.items(), key=lambda kv: kv[1])[0] if loss_reasons else '-'
        except Exception:
            top_loss = '-'
        table_rows.append([
            _setup_combo_strategy_side_key(fam, sess, strat, side),
            int(v.get('trades') or 0),
            int(v.get('tp') or 0),
            int(v.get('sl') or 0),
            int(v.get('other') or 0),
            int(v.get('open') or 0),
            f'{wr_i:.1f}%',
            f"{float(v.get('pnl') or 0.0):+.2f}",
            top_loss,
        ])
    table = tabulate(
        table_rows,
        headers=['Combo', 'Trades', 'TP', 'SL', 'Other', 'Open', 'WR', 'PnL', 'TopLossReason'],
        tablefmt='plain',
        colalign=('left', 'right', 'right', 'right', 'right', 'right', 'right', 'right', 'left'),
    )
    out = '\n'.join(lines) + '\n<pre>' + html.escape(table) + '</pre>'
    try:
        cache_set(cache_key, out)
    except Exception:
        pass
    return out


async def autoytrade_report_overall_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Rolling matrix command, with typo overall aliases safely redirected to fixed overall."""
    uid = update.effective_user.id
    if int(uid) != int(AUTOTRADE_OWNER_UID) and (not is_admin_user(uid)):
        await update.message.reply_text("⛔️ Owner/admin only.")
        return
    msg_txt = str(getattr(update.message, 'text', '') or '').lower()
    is_matrix_cmd = msg_txt.startswith('/autotrade_report_matrix')
    owner = int(AUTOTRADE_OWNER_UID or uid)
    if not is_matrix_cmd:
        lookback_h = int(_overall_report_hours_since_start())
        await _send_cached_or_queue_admin_report(
            update,
            "/autotrade_report_overall",
            f"admin:bg:v24:autotrade_report_overall:{owner}:{lookback_h}",
            _autotrade_report_overall_text_cached,
            args=(owner, lookback_h),
            parse_mode=ParseMode.HTML,
            fresh_ttl=90,
            stale_ttl=12 * 3600,
            background_timeout=900,
        )
        return

    lookback_h = 24
    try:
        if context.args and str(context.args[0]).strip():
            lookback_h = int(float(context.args[0]))
    except Exception:
        lookback_h = 24
    lookback_h = int(clamp(lookback_h, 1, 168))
    await _send_cached_or_queue_admin_report(
        update,
        f"/autotrade_report_matrix {lookback_h}",
        f"admin:bg:v24:autotrade_report_matrix:{owner}:{lookback_h}",
        _autoytrade_report_overall_text_cached,
        args=(owner, lookback_h),
        parse_mode=ParseMode.HTML,
        fresh_ttl=45,
        stale_ttl=12 * 3600,
        background_timeout=900,
    )

async def autotrade_report_overall_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/autotrade_report_overall — Overall performance summary for bot-opened trades."""
    uid = update.effective_user.id
    if int(uid) != int(AUTOTRADE_OWNER_UID) and (not is_admin_user(uid)):
        await update.message.reply_text("⛔️ Owner/admin only.")
        return

    lookback_h = int(_overall_report_hours_since_start())
    owner = int(AUTOTRADE_OWNER_UID or uid)
    await _send_cached_or_queue_admin_report(
        update,
        "/autotrade_report_overall",
        f"admin:bg:v24:autotrade_report_overall:{owner}:{lookback_h}",
        _autotrade_report_overall_text_cached,
        args=(owner, lookback_h),
        parse_mode=ParseMode.HTML,
        fresh_ttl=90,
        stale_ttl=12 * 3600,
        background_timeout=900,
    )

def _leader_base_override_ok(side: str, ch24: float, ch4: float, ch15: float, fut_vol_usd: float, pullback_ready: bool, pb_dist_pct: float, session_name: str) -> bool:
    """Allow post-expansion continuation entries after a clean 15m base/reclaim.

    This is specifically meant to avoid missing explosive leaders that are already far from the
    1H EMA anchor, but have cooled down and rebuilt around the 15m pullback EMA.
    """
    try:
        if not LEADER_BASE_OVERRIDE_ENABLED:
            return False
        side = str(side or "").upper().strip()
        sess = str(session_name or "").upper().strip() or "NY"
        if abs(float(ch24 or 0.0)) < float(LEADER_BASE_MIN_CH24):
            return False
        if float(fut_vol_usd or 0.0) < float(LEADER_BASE_MIN_FUT_VOL_USD):
            return False
        if not bool(pullback_ready):
            return False
        if float(pb_dist_pct or 999.0) > float(LEADER_BASE_MAX_PB_DIST_PCT):
            return False
        if abs(float(ch15 or 0.0)) > float(LEADER_BASE_MAX_CH15_ABS):
            return False
        if side == "BUY" and float(ch4 or 0.0) < float(LEADER_BASE_MIN_CH4):
            return False
        if side == "SELL" and float(ch4 or 0.0) > -float(LEADER_BASE_MIN_CH4):
            return False
        if sess == "ASIA" and abs(float(ch24 or 0.0)) < float(LEADER_BASE_MIN_CH24) + 5.0:
            return False
        return True
    except Exception:
        return False


def _leader_base_sl_cap_pct(session_name: str) -> float:
    try:
        sess = str(session_name or "").upper().strip() or "NY"
        if sess == "ASIA":
            return float(LEADER_BASE_SL_CAP_PCT_ASIA)
        if sess == "LON":
            return float(LEADER_BASE_SL_CAP_PCT_LON)
        return float(LEADER_BASE_SL_CAP_PCT_NY)
    except Exception:
        return 3.3


def _setup_leader_base_override_ok(setup: "Setup", session_name: str) -> bool:
    try:
        return _leader_base_override_ok(
            side=str(getattr(setup, "side", "") or ""),
            ch24=float(getattr(setup, "ch24", 0.0) or 0.0),
            ch4=float(getattr(setup, "ch4", 0.0) or 0.0),
            ch15=float(getattr(setup, "ch15", 0.0) or 0.0),
            fut_vol_usd=float(getattr(setup, "fut_vol_usd", 0.0) or 0.0),
            pullback_ready=bool(getattr(setup, "pullback_ready", False)),
            pb_dist_pct=float(getattr(setup, "pullback_ema_dist_pct", 999.0) or 999.0),
            session_name=session_name,
        )
    except Exception:
        return False


def _adaptive_ema_anchor_limit_pct(setup: "Setup", session_name: str, fallback_allowed: float) -> float:
    """Adaptive 1H EMA-anchor limit.

    The older static 0.35% anchor was starving valid continuation setups, especially
    on higher-ATR names and momentum breakouts. This keeps the anchor discipline but
    scales the allowance by engine, session, and ATR regime.
    """
    try:
        engine = str(getattr(setup, "engine", "") or "").upper()
        atr_pct = float(getattr(setup, "atr_pct", 0.0) or 0.0)
        sess = str(session_name or "").upper().strip() or "NY"
        base = float(fallback_allowed or EMA_ANCHOR_BASE_MAX_DIST_PCT or 0.80)

        if engine == "B":
            limit = max(base, 0.82 + min(1.18, atr_pct * 0.24))
        elif engine == "A":
            limit = max(base, 0.62 + min(0.85, atr_pct * 0.20))
        elif engine == "C":
            limit = max(base, 0.72 + min(1.02, atr_pct * 0.22))
        else:
            limit = max(base, 0.66 + min(0.92, atr_pct * 0.22))

        fam = str(getattr(setup, "family_id", "") or _family_id_from_engine(engine, setup)).upper().strip()

        if sess == "ASIA":
            # ASIA was still over-tight even after the dynamic anchor migration.
            # Keep it disciplined, but stop shrinking the limit below the adaptive base.
            limit *= 1.06 if fam in {"F1_PULLBACK_CONT", "F3_IMPULSE_BASE_CONT", "F6_VWAP_RECLAIM"} else 1.02
        elif sess == "NY":
            limit *= 1.08
        elif sess == "LON" and fam in {"F1_PULLBACK_CONT", "F3_IMPULSE_BASE_CONT"}:
            limit *= 1.02

        return float(clamp(limit, 0.68, 2.15))
    except Exception:
        return float(fallback_allowed or EMA_ANCHOR_BASE_MAX_DIST_PCT or 0.80)


def _recalibrate_public_confidence(setup: "Setup", session_name: str) -> tuple[int, float, dict]:
    """Blend legacy confidence with quality score so displayed confidence matches real quality better."""
    try:
        score, comps = compute_setup_quality_score(setup, session_name=session_name)
        raw_conf = float(getattr(setup, "conf", 0) or 0.0)
        blended = (0.35 * raw_conf) + (0.65 * float(score))
        if str(getattr(setup, "engine", "") or "").upper() == "B" and abs(float(getattr(setup, "ch15", 0.0) or 0.0)) >= 1.0:
            blended -= 3.0
        blended = float(clamp(blended, 0.0, 99.0))
        return int(round(blended)), float(score), comps
    except Exception:
        raw = int(float(getattr(setup, "conf", 0) or 0.0))
        return raw, float(raw), {}



def _top_volume_allowed_bases(best_fut: dict, limit: int = SCAN_SYMBOL_LIMIT) -> set[str]:
    try:
        lim = max(1, int(limit or SCAN_SYMBOL_LIMIT))
        items = sorted((best_fut or {}).items(), key=lambda kv: float(usd_notional(kv[1]) or 0.0), reverse=True)
        return {str(b or '').upper().strip() for b, _mv in items[:lim] if str(b or '').strip()}
    except Exception:
        return set()


def _limit_bases_to_top_volume(best_fut: dict, bases: list, limit: int = SCAN_SYMBOL_LIMIT) -> list:
    try:
        allowed = _top_volume_allowed_bases(best_fut, limit)
        if not allowed:
            return list(dict.fromkeys([str(b).upper().strip() for b in (bases or []) if str(b).strip()]))[:max(1, int(limit or SCAN_SYMBOL_LIMIT))]
        out = []
        for b in (bases or []):
            bb = str(b or '').upper().strip()
            if bb and bb in allowed and bb not in out:
                out.append(bb)
        if len(out) < int(limit or SCAN_SYMBOL_LIMIT):
            ranked = sorted((best_fut or {}).items(), key=lambda kv: float(usd_notional(kv[1]) or 0.0), reverse=True)
            for b, _mv in ranked:
                bb = str(b or '').upper().strip()
                if bb and bb in allowed and bb not in out:
                    out.append(bb)
                if len(out) >= int(limit or SCAN_SYMBOL_LIMIT):
                    break
        return out[:max(1, int(limit or SCAN_SYMBOL_LIMIT))]
    except Exception:
        return list(dict.fromkeys([str(b).upper().strip() for b in (bases or []) if str(b).strip()]))[:max(1, int(limit or SCAN_SYMBOL_LIMIT))]


def _db_recent_candidate_setup_objects(user_id: int, session_name: str = '', max_age_min: int = 30, limit: int = 5) -> list:
    """Recent generated candidates only; deliberately does not read old email rows."""
    from types import SimpleNamespace
    out = []
    seen = set()
    try:
        uid = int(user_id or 0)
        cutoff = float(time.time()) - float(max(1, int(max_age_min))) * 60.0
        sess_u = str(session_name or '').upper().strip()
        con = db_connect()
        con.row_factory = sqlite3.Row
        cur = con.cursor()
        where_sess = ''
        params = [uid, float(cutoff)]
        if sess_u:
            where_sess = ' AND UPPER(COALESCE(session, "")) = ? '
            params.append(sess_u)
        params.append(int(max(1, limit * 4)))
        cur.execute(f"""
            SELECT *
            FROM generated_setups
            WHERE user_id = ?
              AND LOWER(COALESCE(source, '')) IN ('screen','exec','email','candidate','generated','executable_setups')
              AND created_ts >= ?
              {where_sess}
            ORDER BY created_ts DESC
            LIMIT ?
        """, tuple(params))
        rows = cur.fetchall() or []
        con.close()
        for row in rows:
            try:
                d = dict(row)
                sid = str(d.get('setup_id') or '').strip()
                if not sid or sid in seen:
                    continue
                item = SimpleNamespace(
                    setup_id=sid,
                    id=sid,
                    symbol=str(d.get('symbol') or ''),
                    market_symbol=str(d.get('market_symbol') or ''),
                    side=str(d.get('side') or ''),
                    conf=int(d.get('conf') or 0),
                    entry=float(d.get('entry') or 0.0),
                    sl=float(d.get('sl') or 0.0),
                    tp=float(_setup_target_tp(d, 0.0) or 0.0),
                    alt_target_a=0.0,
                    alt_target_b=0.0,
                    fut_vol_usd=float(d.get('fut_vol_usd') or 0.0),
                    ch24=float(d.get('ch24') or 0.0),
                    ch4=float(d.get('ch4') or 0.0),
                    ch1=float(d.get('ch1') or 0.0),
                    ch15=float(d.get('ch15') or 0.0),
                    quality_score=float(d.get('quality_score') or d.get('conf') or 0.0),
                    atr_pct=float(d.get('atr_pct') or 0.0),
                    engine=str(d.get('engine') or ''),
                    created_ts=float(d.get('created_ts') or 0.0),
                    signal_created_ts=float(d.get('created_ts') or 0.0),
                    executable_ts=float(d.get('created_ts') or 0.0),
                    email_logged_ts=0.0,
                    generated_logged_ts=float(d.get('created_ts') or 0.0),
                    source_kind='recent_candidate',
                    source_session=str(d.get('session') or ''),
                    family_id=str(d.get('family_id') or ''),
                )
                try:
                    item = _research_finalize_setup(item, session_name=sess_u)
                except Exception:
                    pass
                out.append(item)
                seen.add(sid)
                if len(out) >= int(limit):
                    break
            except Exception:
                continue
    except Exception:
        return out[:int(limit)]
    return out[:int(limit)]


async def build_priority_pool(best_fut: dict, session_name: str, mode: str, scan_profile: str = DEFAULT_SCAN_PROFILE, uid: int | None = None) -> dict:
    """
    mode: "screen", "exec", or "email"
    returns: {
        "setups": [Setup...],
        "waiting": [(base, info_dict)...],
        "trend_watch": [dict...],
        "spikes": [dict...],   # NEW
        "spike_warnings": [dict...],  # NEW (Early Warning, non-trade)
    }
    """

    mode = str(mode or '').lower().strip() or 'screen'
    if mode not in {'screen', 'exec', 'email'}:
        mode = 'screen'

    # Setup-count governor should only react to the background email lane.
    # A manual /screen refresh must never silently tighten/loosen live config.
    try:
        if mode == 'email':
            _governor_adjust_quality_floor(session_name=session_name)
    except Exception:
        pass


    # Diagnostics: collect reject reasons for this scan
    # Keep a stable structure so /why is always meaningful.
    _rej_ctx = {
        "__agg__": {},          # aggregate counters per reason
        "__per__": {},          # per-symbol last reason/status
        "__allow__": set(),     # universe allow-list (uppercased bases)
    }

    # Fallback for nested threads that may lose contextvars
    global _GLOBAL_REJECT_CTX
    _GLOBAL_REJECT_CTX = _rej_ctx
    _rej_token = _REJECT_CTX.set(_rej_ctx)

    # Reset near-miss list for this scan (so /screen doesn't show stale symbols)
    try:
        _WAITING_TRIGGER.clear()
    except Exception:
        pass
# knobs
    if mode == "screen":
        n_target = int(SETUPS_N)
        strict_15m = True
        universe_cap = int(min(SCAN_SYMBOL_LIMIT, max(SCREEN_UNIVERSE_N, 35)))
        # Ensure /screen is not stricter than email engine
        trigger_loosen = float(min(SCREEN_TRIGGER_LOOSEN, 1.0))
        waiting_near = float(SCREEN_WAITING_NEAR_PCT)
        allow_no_pullback = True
        scan_multiplier = 10
        directional_take = 12
        market_take = 15
        trend_take = 12
    elif mode == "exec":
        # Authoritative executable pool: broader than email, stricter than screen.
        # This pool feeds /screen, email and autotrade, so it must not inherit the
        # tightest email-generation settings or it self-starves before final gating.
        n_target = int(max(EMAIL_SETUPS_N * 4, 10))
        strict_15m = True
        universe_cap = int(SCAN_SYMBOL_LIMIT)
        trigger_loosen = float(min(0.92, max(SCREEN_TRIGGER_LOOSEN, 0.88)))
        waiting_near = float(SCREEN_WAITING_NEAR_PCT)
        allow_no_pullback = True
        scan_multiplier = 12
        directional_take = 16
        market_take = 20
        trend_take = 10
    else:  # email
        # Build a broader candidate pool for the downstream executable gate.
        # The final email/autotrade lane remains strict; the pool itself should not be starved.
        # FIX5: allow_no_pullback=True here. Email/autotrade still use is_executable_setup_eligible(),
        # but generation must not discard candidates before the authoritative executable lane can score them.
        n_target = int(max(EMAIL_SETUPS_N * 4, 12))
        strict_15m = True
        universe_cap = int(SCAN_SYMBOL_LIMIT)
        trigger_loosen = 0.90
        waiting_near = float(SCREEN_WAITING_NEAR_PCT)
        allow_no_pullback = True
        scan_multiplier = 14
        directional_take = 16
        market_take = 20
        trend_take = 16

    # Aggressive profile overrides
    prof = str(scan_profile or DEFAULT_SCAN_PROFILE).strip().lower()
    if prof not in SCAN_PROFILES:
        prof = DEFAULT_SCAN_PROFILE

    if prof == "aggressive":
        if mode == "screen":
            n_target = int(max(SETUPS_N, 8))
            universe_cap = int(SCAN_SYMBOL_LIMIT)
            trigger_loosen = float(min(0.80, SCREEN_TRIGGER_LOOSEN))
            waiting_near = float(min(0.70, SCREEN_WAITING_NEAR_PCT))
            scan_multiplier = 12
            directional_take = 16
            market_take = 18
            trend_take = 16
            strict_15m = True
            allow_no_pullback = True
        elif mode == "exec":
            n_target = int(max(EMAIL_SETUPS_N * 4, 12))
            universe_cap = int(SCAN_SYMBOL_LIMIT)
            trigger_loosen = 0.88
            waiting_near = float(min(0.75, SCREEN_WAITING_NEAR_PCT))
            strict_15m = True
            allow_no_pullback = True
            scan_multiplier = 13
            directional_take = 18
            market_take = 22
            trend_take = 10
        else:
            # Email pool becomes broader, but final email gates still apply.
            # FIX5: do not require pullback at generation time; executable gate decides.
            n_target = int(max(EMAIL_SETUPS_N * 4, 12))
            universe_cap = int(SCAN_SYMBOL_LIMIT)
            trigger_loosen = 0.88
            waiting_near = float(SCREEN_WAITING_NEAR_PCT)
            strict_15m = True
            allow_no_pullback = True
            scan_multiplier = 14
            directional_take = 16
            market_take = 18
            trend_take = 16

    # 1) Directional leaders / losers (priority #1)
    up_list, dn_list = compute_directional_lists(best_fut)

    directional_table_n = 10
    leaders = [str(t[0]).upper() for t in (up_list or [])[:directional_table_n]]
    losers  = [str(t[0]).upper() for t in (dn_list or [])[:directional_table_n]]

    # Market Leaders (Top by Futures Volume)
    market_bases = _market_leader_bases(best_fut, market_take)

    # Active scan universe:
    # keep the displayed leaders/losers/market leaders first, then widen with extra top-volume names
    # so liquid symbols that are not in the visible top buckets can still be evaluated and explained in /why.
    display_universe_bases = list(dict.fromkeys([b.upper() for b in (leaders + losers + (market_bases or []))]))
    extra_top_volume_bases = []
    try:
        ranked_all = sorted((best_fut or {}).items(), key=lambda kv: usd_notional(kv[1]), reverse=True)
        seen_display = set(display_universe_bases)
        for base, _mv in ranked_all:
            b = str(base or '').upper().strip()
            if not b or b in seen_display:
                continue
            extra_top_volume_bases.append(b)
            if len(display_universe_bases) + len(extra_top_volume_bases) >= int(max(universe_cap, len(display_universe_bases))):
                break
    except Exception:
        extra_top_volume_bases = []

    universe_bases = list(dict.fromkeys(display_universe_bases + extra_top_volume_bases))
    # Production API guard: only scan the top symbols by futures volume.
    universe_bases = _limit_bases_to_top_volume(best_fut, universe_bases, int(SCAN_SYMBOL_LIMIT))
    universe_best = _subset_best(best_fut, universe_bases) if universe_bases else {}

    # Diagnostics: keep /why focused on this scan universe
    try:
        _rej_ctx["__allow__"] = set(str(x).upper() for x in (universe_bases or []) if x)
        _rej_ctx["__per__"] = {b: {"reason": "not_evaluated", "n": 0} for b in (_rej_ctx["__allow__"] or set())}

        try:
            global _LAST_SCAN_UNIVERSE
            _LAST_SCAN_UNIVERSE = list(universe_bases or [])
        except Exception:
            pass
    except Exception:
        pass

    priority_setups = []

    # Rotate active OHLCV timeframe phase so cold refreshes are staggered across scan cycles.
    try:
        global _SCAN_TF_PHASE
        _SCAN_TF_PHASE = (int(_SCAN_TF_PHASE or 0) + 1) % 3
        _scan_health_touch(
            mode=mode,
            session=session_name,
            symbols_processed=len(universe_bases or []),
            tf_phase=_current_scan_tf_phase(),
        )
    except Exception:
        pass

    # Leaders pass
    if leaders:
        sub = _subset_best(best_fut, leaders)
        try:
            tmp = pick_setups(
                sub,
                n_target * scan_multiplier,
                strict_15m,
                session_name,
                min(int(universe_cap), len(sub) if sub else universe_cap),
                trigger_loosen,
                waiting_near,
                allow_no_pullback,
                scan_profile=prof,
            )
        except Exception:
            tmp = []
        for s in (tmp or []):
            if s.side == "BUY":
                priority_setups.append(s)

    # Losers pass
    if losers:
        sub = _subset_best(best_fut, losers)
        try:
            tmp = pick_setups(
                sub,
                n_target * scan_multiplier,
                strict_15m,
                session_name,
                min(int(universe_cap), len(sub) if sub else universe_cap),
                trigger_loosen,
                waiting_near,
                allow_no_pullback,
                scan_profile=prof,
            )
        except Exception:
            tmp = []
        for s in (tmp or []):
            if s.side == "SELL":
                priority_setups.append(s)

    # 1b) Full universe pass (leaders + losers + market leaders)
    try:
        if universe_best:
            tmp = pick_setups(
                universe_best,
                n_target * scan_multiplier,
                strict_15m,
                session_name,
                min(int(universe_cap), len(universe_best) if universe_best else universe_cap),
                trigger_loosen,
                waiting_near,
                allow_no_pullback,
                scan_profile=prof,
            )
        else:
            tmp = []
    except Exception:
        tmp = []
    for s in (tmp or []):
        priority_setups.append(s)

    # ------------------------------------------------
    # Engine B: Momentum Breakout Setups (Balanced)
    # ------------------------------------------------
    breakout_setups = []
    try:
        bases_for_breakout = list(dict.fromkeys([b.upper() for b in (leaders + losers)]))
        if bases_for_breakout:
            sub = _subset_best(best_fut, bases_for_breakout)
            breakout_setups = pick_breakout_setups(
                sub,
                int(max(6, n_target)),   # allow a handful
                session_name,
                min(int(universe_cap), len(sub) if sub else universe_cap),
                scan_profile=prof,
            )
    except Exception:
        breakout_setups = []

    if breakout_setups:
        priority_setups.extend(breakout_setups)

    # 2) Trend continuation watch (priority #2)
    watch_bases = []
    watch_bases.extend([b for b in leaders[:6]])
    watch_bases.extend([b for b in losers[:6]])
    watch_bases = list(dict.fromkeys([b.upper() for b in watch_bases]))

    trend_watch = []
    trend_bases = []
    if mode == 'screen':
        for base in watch_bases:
            mv = (best_fut or {}).get(base)
            if not mv:
                continue
            r = await to_thread_heavy(trend_watch_for_symbol, base, mv, session_name)
            if r:
                trend_watch.append(r)
                trend_bases.append(base)
    else:
        # The trend-watch cards are a /screen UX feature. Rebuilding them during the
        # background email/executable pool path wastes OHLCV budget and is a major source
        # of timeouts without improving the final executable gate.
        trend_bases = list(watch_bases[:max(6, int(trend_take))])

    if trend_bases:
        sub = _subset_best(best_fut, trend_bases[:trend_take])
        try:
            tmp = pick_setups(
                sub,
                n_target * scan_multiplier,
                strict_15m,
                session_name,
                min(int(universe_cap), len(sub) if sub else universe_cap),
                trigger_loosen,
                waiting_near,
                allow_no_pullback,
                scan_profile=prof,
            )
        except Exception:
            tmp = []

        side_map = {str(t.get("symbol")).upper(): str(t.get("side")) for t in (trend_watch or []) if t.get("symbol")}
        for s in (tmp or []):
            want = side_map.get(str(s.symbol).upper())
            if want and s.side == want:
                priority_setups.append(s)

    # 3) Waiting for Trigger (priority #3) is produced by pick_setups via _WAITING_TRIGGER
    waiting_items = []
    try:
        if _WAITING_TRIGGER:
            allow_set = set(str(x).upper() for x in (_LAST_SCAN_UNIVERSE or []))
            waiting_items = [
                (b, o)
                for (b, o) in list(_WAITING_TRIGGER.items())
                if (not allow_set) or (str(b).upper() in allow_set)
            ][:SCREEN_WAITING_N]
    except Exception:
        waiting_items = []

    # 4) Market leaders fallback (priority #4)
    if len(priority_setups) < (n_target * 2):
        if market_bases:
            sub = _subset_best(best_fut, market_bases)
            try:
                tmp = pick_setups(
                    sub,
                    n_target * scan_multiplier,
                    strict_15m,
                    session_name,
                    min(int(universe_cap), len(sub) if sub else universe_cap),
                    trigger_loosen,
                    waiting_near,
                    allow_no_pullback,
                    scan_profile=prof,
                )
            except Exception:
                tmp = []
            priority_setups.extend(tmp or [])

    # 4B) Momentum Breakout setups (Engine B) — Balanced
    try:
        mom_n = max(6, int(n_target) * 2)
        mom = pick_breakout_setups(
            universe_best,  # ✅ restricted universe
            mom_n,
            session_name,
            int(universe_cap),
            scan_profile=prof,
        )
    except Exception:
        mom = []
    if mom:
        priority_setups.extend(mom)

    # ------------------------------------------------
    # Big Move Continuation family (15m/1H/4H aligned expansion)
    # ------------------------------------------------
    try:
        bm_take = max(3, min(int(BIGMOVE_SIGNAL_MAX_ITEMS), int(max(4, n_target))))
        bm_setups = pick_bigmove_family_setups(
            universe_best,
            bm_take,
            session_name,
            int(universe_cap),
            scan_profile=prof,
        )
    except Exception:
        bm_setups = []
    if bm_setups:
        priority_setups.extend(bm_setups)

    # ------------------------------------------------
    # F9: Multi-Day Leader/Loser Continuation (WATCH-first)
    # ------------------------------------------------
    try:
        f9_take = max(2, min(int(F9_MAX_ITEMS or 6), int(max(4, n_target))))
        f9_setups = pick_multiday_mover_family_setups(
            best_fut,
            leaders,
            losers,
            f9_take,
            session_name,
            scan_profile=prof,
        )
    except Exception:
        f9_setups = []
    if f9_setups:
        priority_setups.extend(f9_setups)


    # -----------------------------------------------------
    # BALANCE MODE: If strict_15m produces too few candidates,
    # add a relaxed 15m pass to avoid starving /screen and email pools.
    # This keeps quality-first behavior, but prevents "no signals" sessions.
    # -----------------------------------------------------
    # Allow one controlled relaxed-15m recovery pass for BOTH screen and email
    # when the strict pass produced too few candidates. Final shared eligibility
    # gates still decide what can actually be shown/sent, so this improves fill
    # rate without bypassing quality / RR / liquidity controls.
    if strict_15m and len(priority_setups) < int(max(3, n_target)):
        try:
            if universe_best:
                tmp = pick_setups(
                    universe_best,
                    n_target * scan_multiplier,
                    False,  # relaxed 15m
                    session_name,
                    min(int(universe_cap), len(universe_best) if universe_best else universe_cap),
                    trigger_loosen,
                    waiting_near,
                    allow_no_pullback,
                    scan_profile=prof,
                )
                priority_setups.extend(tmp or [])
        except Exception:
            pass

        # If still low, try market leaders once with relaxed 15m
        try:
            if len(priority_setups) < int(max(3, n_target)) and market_bases:
                sub = _subset_best(best_fut, market_bases)
                tmp = pick_setups(
                    sub,
                    n_target * scan_multiplier,
                    False,  # relaxed 15m
                    session_name,
                    min(int(universe_cap), len(sub) if sub else universe_cap),
                    trigger_loosen,
                    waiting_near,
                    allow_no_pullback,
                    scan_profile=prof,
                )
                priority_setups.extend(tmp or [])
        except Exception:
            pass

        # De-duplicate setups after relaxation
        try:
            seen = set()
            deduped = []
            for s in (priority_setups or []):
                k = (
                    getattr(s, "setup_id", None),
                    getattr(s, "market_symbol", None),
                    getattr(s, "side", None),
                    getattr(s, "entry", None),
                    getattr(s, "sl", None),
                )
                if k in seen:
                    continue
                seen.add(k)
                deduped.append(s)
            priority_setups = deduped
        except Exception:
            pass


# -----------------------------------------------------
    # CRITICAL GATE (DYNAMIC EMA ANCHOR):
    # Require price to be close to the *nearest* 1H EMA among {EMA_ANCHOR_1H_PERIODS}.
    # This preserves your original intent (avoid "stretched" entries),
    # but reduces missed opportunities when EMA7 isn't the active magnet.
    # -----------------------------------------------------
    ema_anchor_cache: Dict[str, Tuple[bool, float, float, float, int, float]] = {}
    gated = []
    for s in (priority_setups or []):
        try:
            mk = str(getattr(s, "market_symbol", "") or "")
            base = str(getattr(s, "symbol", "") or "").upper().strip()
            if not mk:
                mv = (best_fut or {}).get(base)
                _rej("missing_market_symbol", base, mv, "EMA-anchor gate")
                continue

            if mk not in ema_anchor_cache:
                ema_anchor_cache[mk] = ema_anchor_1h_is_close(
                    mk,
                    base_max_dist_pct=EMA_ANCHOR_BASE_MAX_DIST_PCT,
                    periods=EMA_ANCHOR_1H_PERIODS,
                )

            ok, dist_pct, last_close, ema_val, ema_p, allowed = ema_anchor_cache[mk]
            adaptive_allowed = _adaptive_ema_anchor_limit_pct(s, session_name=session_name, fallback_allowed=allowed)
            try:
                fam = str(getattr(s, 'family_id', '') or '').upper().strip()
                if fam == BIGMOVE_FAMILY_ID:
                    bm_floor = 1.12 if str(session_name or '').upper().strip() in {'LON', 'NY'} else 0.98
                    adaptive_allowed = max(float(adaptive_allowed), float(bm_floor))
                if fam == globals().get('F9_FAMILY_ID', 'F9_MULTI_DAY_MOVER_CONT'):
                    f9_floor = float(_f9_ema_entry_limit_pct(session_name))
                    adaptive_allowed = max(float(adaptive_allowed), float(f9_floor))
            except Exception:
                pass
            try:
                if _research_balance_reversal_mode(session_name):
                    mult = 1.45
                    upper = 1.60
                    fam = str(getattr(s, 'family_id', '') or '').upper().strip()
                    if fam == 'F4_SWEEP_RECLAIM':
                        mult = 1.65
                        upper = 1.95
                    adaptive_allowed = float(clamp(float(adaptive_allowed) * mult, float(adaptive_allowed), max(float(allowed) * upper, float(adaptive_allowed))))
            except Exception:
                pass
            leader_base_ok = _setup_leader_base_override_ok(s, session_name=session_name)
            if float(dist_pct) > float(adaptive_allowed) and not leader_base_ok:
                mv = (best_fut or {}).get(base)
                _rej(
                    "far_from_ema_anchor_1h",
                    base,
                    mv,
                    f"ema={ema_p} dist={dist_pct:.2f}% max={adaptive_allowed:.2f}% base={allowed:.2f}% close={last_close:.6g} emaV={ema_val:.6g}",
                )
                continue

            try:
                setattr(s, "ema_anchor_period", int(ema_p or 0))
                setattr(s, "ema_anchor_dist_pct", float(dist_pct or 0.0))
                setattr(s, "ema_anchor_limit_pct", float(adaptive_allowed or 0.0))
                if float(dist_pct) > float(allowed or adaptive_allowed):
                    if leader_base_ok:
                        setattr(s, "leader_base_anchor_override", True)
                    else:
                        s.conf = int(max(0, int(getattr(s, "conf", 0) or 0) - 4))
            except Exception:
                pass

            gated.append(s)
        except Exception:
            try:
                base = str(getattr(s, "symbol", "") or "").upper().strip()
                mv = (best_fut or {}).get(base)
                _rej("ema_anchor_gate_error", base, mv)
            except Exception:
                pass
            continue

    priority_setups = gated


    # de-dupe by (symbol, side, engine) keeping highest conf, preserving priority order
    best = {}
    for s in priority_setups:
        k = (
            str(s.symbol).upper(),
            str(s.side),
            str(getattr(s, "engine", "")),
            str(getattr(s, "family_id", "") or _family_id_from_engine(getattr(s, "engine", ""), s)).upper().strip(),
        )
        if k not in best or int(s.conf) > int(best[k].conf):
            best[k] = s

    ordered = []
    seen = set()
    for s in priority_setups:
        k = (
            str(s.symbol).upper(),
            str(s.side),
            str(getattr(s, "engine", "")),
            str(getattr(s, "family_id", "") or _family_id_from_engine(getattr(s, "engine", ""), s)).upper().strip(),
        )
        if k in seen:
            continue
        if k in best:
            ordered.append(best[k])
            seen.add(k)

    # If still empty, create a small fallback set so /screen isn't blank.
    # Important: this remains SCREEN-ONLY and still goes through the shared gate below.
    # The setup-generation mismatch fixed in this patch is the session floor override,
    # not a quality bypass for fallback rows.
    if not ordered and mode in {"screen", "exec", "email"}:
        try:
            ordered = _fallback_setups_from_universe(best_fut, leaders, losers, market_bases, session_name, max_items=max(4, n_target))
        except Exception:
            pass

    
    # -----------------------------------------------------
    # Shared Top Setup gate (applies to BOTH /screen and email)
    # -----------------------------------------------------
    gate_source = 'screen' if str(mode or '').lower().strip() == 'exec' else mode
    try:
        ordered = [s for s in (ordered or []) if is_top_setup_eligible(s, source=gate_source, session_name=session_name)[0]]
    except Exception:
        pass

    # If the normal engines produced candidates but the shared gate filtered all of them,
    # still activate the current-ticker recovery lane. Previously the recovery lane only
    # ran when the pre-gate list was empty, so one weak/invalid normal candidate could
    # prevent any fallback setup from reaching /screen, email, or autotrade.
    if not ordered and mode in {"screen", "exec", "email"}:
        try:
            fb = _fallback_setups_from_universe(best_fut, leaders, losers, market_bases, session_name, max_items=max(4, n_target))
            gated_fb = [s for s in (fb or []) if is_top_setup_eligible(s, source=gate_source, session_name=session_name)[0]]
            ordered = gated_fb or list(fb or [])[:max(1, int(n_target))]
            if ordered:
                try:
                    db_log_setup_pipeline_event(int(uid or 0), stage='recovery_fallback_pool', status='ok', session=str(session_name or ''), mode=str(mode or ''), details={'fallback': len(fb or []), 'accepted': len(ordered or []), 'gate_source': str(gate_source)})
                except Exception:
                    pass
        except Exception:
            ordered = []
# -----------------------------------------------------
    # NEW: Spike Reversal candidates (10M+ Vol) — for /screen only
    # -----------------------------------------------------
    spike_candidates = []
    if mode == "screen":
        try:
            spike_candidates = await to_thread_heavy(_spike_reversal_candidates,
                universe_best,
                10_000_000.0,  # min_vol_usd
                0.55,          # wick_ratio_min
                1.20,          # atr_mult_min
                6,             # max_items
            )
        except Exception:
            spike_candidates = []

    # -----------------------------------------------------
    # NEW: Early Warning — Possible Reversal Zones (non-trade)
    # -----------------------------------------------------
    spike_warnings = []
    if mode == "screen":
        try:
            spike_warnings = await to_thread_heavy(_spike_reversal_warnings,
                universe_best,
                10_000_000.0,  # min_vol_usd
                1.15,          # atr_mult_min
                0.60,          # body_ratio_min
                8,             # lookback_1h
                0.30,          # retrace_min
                6,             # max_items
            )
        except Exception:
            spike_warnings = []

    # Store diagnostics for /why, then ALWAYS reset context
    try:
        if uid is not None:
            counts = {
                str(k): int(v)
                for k, v in dict(_rej_ctx or {}).items()
                if not str(k).startswith("__")
            }
            payload = {
                "ts": time.time(),
                "mode": str(mode or ''),
                "session": str(session_name or ''),
                "allow": list(_rej_ctx.get("__allow__") or []),
                "counts": counts,
                "per_symbol": dict((_rej_ctx.get("__per__") or {})),
            }
            try:
                shared_bucket = _LAST_REJECTS_SHARED if isinstance(_LAST_REJECTS_SHARED, dict) else {}
                if str(mode or '').strip():
                    shared_bucket[str(mode).strip().lower()] = dict(payload)
                shared_bucket["latest"] = dict(payload)
                _LAST_REJECTS_SHARED.clear()
                _LAST_REJECTS_SHARED.update(shared_bucket)
            except Exception:
                pass
            if uid is not None:
                bucket = _LAST_REJECTS.get(int(uid)) or {}
                if isinstance(bucket, dict) and any(k in bucket for k in ("screen", "email", "latest")):
                    bucket = dict(bucket)
                else:
                    bucket = {}
                if str(mode or '').strip():
                    bucket[str(mode).strip().lower()] = payload
                bucket["latest"] = payload
                _LAST_REJECTS[int(uid)] = bucket
    finally:
        try:
            _REJECT_CTX.reset(_rej_token)
        except Exception:
            pass
        try:
            _GLOBAL_REJECT_CTX = None
        except Exception:
            pass

    try:
        db_log_setup_pipeline_event(
            int(uid or 0),
            stage='build_priority_pool',
            status='ok' if ordered else 'empty',
            session=str(session_name or ''),
            mode=str(mode or ''),
            details={
                'setups': len(ordered or []),
                'waiting': len(waiting_items or []),
                'trend_watch': len(trend_watch or []),
                'spikes': len(spike_candidates or []),
                'spike_warnings': len(spike_warnings or []),
                'top_rejects': _pipeline_top_reasons(dict((_rej_ctx or {}).get('__agg__') or {}), 5),
                'make_setup_exception_count': int(((_rej_ctx or {}).get('__agg__') or {}).get('make_setup_exception', 0) or 0),
                'scan_health': _scan_health_snapshot(),
            },
        )
    except Exception:
        pass

    try:
        ordered = _research_finalize_setups(list(ordered or []), session_name=str(session_name or ""))
    except Exception:
        pass

    return {
        "setups": ordered,
        "waiting": waiting_items,
        "trend_watch": trend_watch,
        "spikes": spike_candidates,
        "spike_warnings": spike_warnings,
    }




# =========================================================
# User location/time helpers
# =========================================================
def user_location_and_time(user: dict):
    """
    Returns: (location_label, time_str) based on user's tz
    """
    tz, tz_name = _zoneinfo_or_default((user or {}).get("tz") or (user or {}).get("timezone"))

    now_local = datetime.now(tz)

    if "/" in tz_name:
        parts = tz_name.split("/")
        region = parts[0].replace("_", " ")
        city = parts[-1].replace("_", " ")
        loc = f"{city} ({region})"
    else:
        loc = tz_name

    return loc, now_local.strftime("%Y-%m-%d %H:%M")


# =========================================================
# /screen fast cache (per-instance)
# =========================================================
SCREEN_CACHE_TTL_SEC = int(os.environ.get("SCREEN_CACHE_TTL_SEC", str(MAX_STALE_SCAN_SEC)) or MAX_STALE_SCAN_SEC)  # seconds
SCREEN_STALE_CACHE_MAX_SEC = int(os.environ.get("SCREEN_STALE_CACHE_MAX_SEC", str(MAX_STALE_SCAN_SEC)) or MAX_STALE_SCAN_SEC)  # force fresh rebuild when stale
SCREEN_CACHE_WARMUP_INTERVAL_SEC = int(os.environ.get("SCREEN_CACHE_WARMUP_INTERVAL_SEC", str(MAX_STALE_SCAN_SEC)) or MAX_STALE_SCAN_SEC)
SCREEN_CACHE_WARMUP_MIN_AGE_SEC = int(os.environ.get("SCREEN_CACHE_WARMUP_MIN_AGE_SEC", str(MAX_STALE_SCAN_SEC)) or MAX_STALE_SCAN_SEC)
SCREEN_MIN_CONF = 72  # do not show setups below this confidence on /screen
_SCREEN_CACHE: dict[str, dict] = {}
_SCREEN_LOCK = asyncio.Lock()

# Background refresh task for /screen (keeps UX instant)
_SCREEN_REFRESH_TASK = None  # asyncio.Task
_SCREEN_REFRESH_TASK_TS = 0.0
SCREEN_REFRESH_STUCK_SEC = int(os.environ.get("SCREEN_REFRESH_STUCK_SEC", "90") or 90)

# Keep recent screen cards in memory for PF- lookup.
# /screen is built from the executable lane, but these cached cards themselves are
# not standalone trade/report records until the normal email/autotrade sync writes them.
RECENT_SCREEN_SIGNAL_TTL_SEC = int(os.environ.get("RECENT_SCREEN_SIGNAL_TTL_SEC", "1800"))
_RECENT_SCREEN_SIGNALS: Dict[str, Tuple[float, Dict[str, Any]]] = {}

def _recent_screen_signal_prune() -> None:
    try:
        ttl = max(60, int(RECENT_SCREEN_SIGNAL_TTL_SEC))
        cutoff = time.time() - float(ttl)
        stale = [sid for sid, (ts, _payload) in list(_RECENT_SCREEN_SIGNALS.items()) if float(ts or 0.0) < cutoff]
        for sid in stale:
            _RECENT_SCREEN_SIGNALS.pop(sid, None)
    except Exception:
        pass

def _remember_recent_screen_signal(s: Setup, session: str = "", user_id: int | None = None) -> None:
    try:
        sid = str(getattr(s, "setup_id", "") or "").strip()
        if not sid:
            return
        payload = {
            "setup_id": sid,
            "created_ts": float(getattr(s, "created_ts", time.time()) or time.time()),
            "session": str(session or ""),
            "user_id": int(user_id or 0),
            "symbol": str(getattr(s, "symbol", "") or ""),
            "market_symbol": getattr(s, "market_symbol", None),
            "side": str(getattr(s, "side", "") or ""),
            "conf": int(getattr(s, "conf", 0) or 0),
            "entry": float(getattr(s, "entry", 0.0) or 0.0),
            "sl": float(getattr(s, "sl", 0.0) or 0.0),
            "tp": getattr(s, "tp", None),
            "alt_target_a": 0.0,
            "alt_target_b": 0.0,
            "fut_vol_usd": float(getattr(s, "fut_vol_usd", 0.0) or 0.0),
            "ch24": float(getattr(s, "ch24", 0.0) or 0.0),
            "ch4": float(getattr(s, "ch4", 0.0) or 0.0),
            "ch1": float(getattr(s, "ch1", 0.0) or 0.0),
            "ch15": float(getattr(s, "ch15", 0.0) or 0.0),
            "setup_strategy": _setup_strategy_label(s),
            "strategy": _setup_strategy_label(s),
            "strategy_mode": _setup_strategy_label(s),
            "strategy_reason": str(getattr(s, "strategy_reason", "") or ""),
            "original_setup_id": str(getattr(s, "original_setup_id", "") or ""),
            "original_side": str(getattr(s, "original_side", "") or ""),
            "delivery_lane_locked": True,
        }
        _RECENT_SCREEN_SIGNALS[sid] = (time.time(), payload)
        _recent_screen_signal_prune()
    except Exception:
        pass

def _recent_screen_signal_lookup(setup_id: str) -> Optional[dict]:
    try:
        sid = str(setup_id or "").strip()
        if not sid:
            return None
        _recent_screen_signal_prune()
        hit = _RECENT_SCREEN_SIGNALS.get(sid)
        return dict(hit[1]) if hit else None
    except Exception:
        return None



def _screen_quick_ticker_snapshot_body(best_fut: Dict[str, MarketVol], session: str = '') -> tuple[str, list, list]:
    """No-OHLCV fallback for /screen when the full executable scan is warming up.

    It gives the user an instant market snapshot instead of the annoying
    "No cached /screen snapshot yet" message. It does not create trade setups.
    """
    try:
        items = list((best_fut or {}).items())
        items = [(str(b).upper(), mv) for b, mv in items if mv]
        # /screen market context should not advertise thin leaders/losers.
        # Keep the same 10M+ floor used by setup generation.
        min_ctx_vol = float(_screen_context_volume_floor_usd())
        items = [(b, mv) for b, mv in items if float(usd_notional(mv) or 0.0) >= min_ctx_vol]
        items.sort(key=lambda kv: abs(float(getattr(kv[1], 'percentage', 0.0) or 0.0)), reverse=True)
        leaders = sorted(items, key=lambda kv: float(getattr(kv[1], 'percentage', 0.0) or 0.0), reverse=True)[:5]
        losers = sorted(items, key=lambda kv: float(getattr(kv[1], 'percentage', 0.0) or 0.0))[:5]

        def _row(kv):
            b, mv = kv
            try:
                pct = float(getattr(mv, 'percentage', 0.0) or 0.0)
            except Exception:
                pct = 0.0
            try:
                vol = float(usd_notional(mv) or 0.0) / 1e6
            except Exception:
                vol = 0.0
            dot = '🟢' if pct >= 0 else '🔴'
            return f"{b} {pct:+.1f}% {dot} ({vol:.1f}M)"

        btc = float(getattr((best_fut or {}).get('BTC') or MarketVol('BTC','BTC','USDT',0,0,0,0,0,0), 'percentage', 0.0) or 0.0)
        eth = float(getattr((best_fut or {}).get('ETH') or MarketVol('ETH','ETH','USDT',0,0,0,0,0,0), 'percentage', 0.0) or 0.0)
        body = []
        body.append("*Top Trade Setups*")
        body.append("━━━━━━━━━━━━━━━━━━━━")
        body.append("_Executable scan is warming up. No confirmed setup shown from the quick ticker snapshot._")
        body.append("")
        market_txt = _screen_market_context_table(best_fut, leaders=leaders, losers=losers)
        if market_txt:
            body.append(market_txt)
        body.append("")
        body.append("_A full executable-family refresh has been queued in the dedicated /screen lane._")
        return "\n".join(body), [], []
    except Exception:
        return "_Screen cache is warming up. A fresh scan has been queued._", [], []

async def _refresh_screen_cache_async():
    """Refreshes _SCREEN_CACHE in the background (best effort)."""
    global _SCREEN_REFRESH_TASK
    try:
        best_fut = await to_thread_screen(fetch_futures_tickers, timeout=20)
        if not best_fut:
            return
        now_utc = datetime.now(timezone.utc)
        session = scan_session_name_utc(now_utc)
        body, kb, _setups = await to_thread_screen(_build_screen_body_and_kb,
            best_fut,
            session,
            0,
            timeout=75,
        )
        cache_key = f"global::{str(session or '').upper()}"
        _screen_cache_put(cache_key, body, list(kb or []), ts=time.time())
    except Exception:
        # never let background refresh crash the bot
        return
    finally:
        _SCREEN_REFRESH_TASK = None


async def _refresh_screen_cache_for_user_async(uid: int, session: str | None = None):
    """Refresh a user/session scoped /screen cache in the background only.

    /screen itself must return instantly with the latest available result. This task can
    take as long as needed without blocking /status, /equity, /trade_close, or /size.
    """
    global _SCREEN_REFRESH_TASK
    try:
        if _SCREEN_LOCK.locked() or SCAN_LOCK.locked():
            return
        async with _SCREEN_LOCK:
            best_fut = await to_thread_screen(_screen_best_fut_fast, timeout=10)
            if not best_fut:
                return
            sess = str(session or scan_session_name_utc(datetime.now(timezone.utc)) or '').upper()
            try:
                body, kb, _setups = await to_thread_screen(_build_screen_body_and_kb, best_fut, sess, int(uid or 0), timeout=75)
            except Exception as e:
                try:
                    db_log_setup_pipeline_event(int(uid or 0), stage='screen_cache_refresh', status='error', session=str(sess or ''), mode='screen', details={'error': f'{type(e).__name__}: {e}'})
                except Exception:
                    pass
                return
            # If a setup email was delivered recently, keep /screen locked to that exact
            # email/autotrade lane instead of overwriting it with a different background scan.
            try:
                if int(uid or 0) > 0 and _screen_user_can_see_email_source(int(uid or 0)) and _latest_recent_delivery_ts(int(uid or 0), sess, max_age_min=_screen_actionable_fallback_max_age_min()) > 0:
                    body_e, kb_e, _shown_e = _screen_recent_db_body_and_kb(int(uid or 0), sess, best_fut or {}, max_age_min=_screen_actionable_fallback_max_age_min(), include_email_source=True)
                    if body_e:
                        body, kb = body_e, list(kb_e or [])
            except Exception:
                pass
            _screen_cache_put(f"uid:{int(uid or 0)}::{sess}", body, list(kb or []), ts=time.time())
            _screen_cache_put(f"global::{sess}", body, list(kb or []), ts=time.time())

            # Ver10: if a user-triggered /screen refresh finds executable setups,
            # immediately route those same setups through the email/autotrade lane.
            # This prevents the user seeing a setup on /screen while /email_decision
            # and /autotrade_last still say no_setups. The sync still respects email
            # caps, cooldowns, duplicate guards, and is_executable_setup_eligible().
            try:
                if MANUAL_SCREEN_SYNC_ENABLED and int(uid or 0) > 0 and _setups:
                    _u = get_user(int(uid or 0)) or {}
                    _live_sess = str(current_session_utc() or '')
                    await _screen_sync_pipeline_async(int(uid or 0), dict(_u or {}), _live_sess, str(sess or ''), best_fut or {}, list(_setups or []))
            except Exception as _sync_e:
                try:
                    logger.warning('screen_cache_refresh_sync failed uid=%s: %s', uid, _sync_e)
                except Exception:
                    pass
    except Exception:
        return
    finally:
        _SCREEN_REFRESH_TASK = None


def _schedule_screen_cache_refresh(uid: int, session: str | None = None) -> None:
    global _SCREEN_REFRESH_TASK, _SCREEN_REFRESH_TASK_TS
    try:
        now_ts = float(time.time())
        if _SCREEN_REFRESH_TASK is not None and not _SCREEN_REFRESH_TASK.done():
            # If a refresh is genuinely stuck, cancel and replace it; otherwise do not pile up tasks.
            if (now_ts - float(_SCREEN_REFRESH_TASK_TS or 0.0)) < float(SCREEN_REFRESH_STUCK_SEC):
                return
            try:
                _SCREEN_REFRESH_TASK.cancel()
            except Exception:
                pass
        _SCREEN_REFRESH_TASK_TS = now_ts
        _SCREEN_REFRESH_TASK = _safe_create_task(_refresh_screen_cache_for_user_async(int(uid or 0), session), 'screen_cache_refresh')
    except Exception:
        _SCREEN_REFRESH_TASK = None


