def _screen_age_text(age_sec: float) -> str:
    try:
        age = max(0, int(float(age_sec or 0.0)))
        if age < 60:
            return f"{age}s"
        if age < 3600:
            return f"{age // 60}m"
        return f"{age // 3600}h{(age % 3600) // 60:02d}m"
    except Exception:
        return "-"


def _screen_when_line(label: str, ts: float) -> str:
    try:
        ts_f = float(ts or 0.0)
        if ts_f <= 0:
            return ""
        when = _fmt_dt_local(datetime.fromtimestamp(ts_f, tz=timezone.utc), "%Y-%m-%d %H:%M:%S")
        return f"*{label}:* `{when}` | *Age:* `{_screen_age_text(time.time() - ts_f)}`\n"
    except Exception:
        return ""


def _screen_user_can_see_email_source(uid: int, user: dict | None = None) -> bool:
    """Only admins and Pro/trial users should see email-source wording on /screen."""
    try:
        if is_admin_user(int(uid)):
            return True
    except Exception:
        pass
    try:
        u = user if user is not None else (get_user(int(uid)) or {})
        return effective_plan(int(uid), u) in {"pro", "trial"}
    except Exception:
        return False


def _screen_ts_label(ts: float, fmt: str = "%Y-%m-%d %H:%M") -> str:
    try:
        ts_f = float(ts or 0.0)
        if ts_f <= 0:
            return ""
        return _fmt_dt_local(datetime.fromtimestamp(ts_f, tz=timezone.utc), fmt)
    except Exception:
        return ""


def _screen_plain_cleanup(txt: str) -> str:
    """Legacy plain-text fallback. /screen now uses HTML rendering instead."""
    try:
        import re as _re
        t = str(txt or '')
        out = []
        for line in t.splitlines():
            if line.strip() == '```':
                continue
            line = line.replace('`', '').replace('*', '')
            st = line.strip()
            if len(st) >= 2 and st.startswith('_') and st.endswith('_'):
                line = line.replace('_', '')
            out.append(line.rstrip())
        return _re.sub(r'\n{3,}', '\n\n', '\n'.join(out)).strip()
    except Exception:
        return str(txt or '')


def _screen_markdown_to_html(txt: str) -> str:
    """Render the old nice /screen Markdown layout as Telegram-safe HTML.

    This keeps the previous readable format (bold headers, italic notes, inline
    code, and copyable table boxes) without risking raw '*', '`' or code fences
    appearing when Telegram Markdown parsing fails.
    """
    try:
        import re as _re
        import html as _html
        text = str(txt or '')
        out = []
        in_code = False
        code_buf = []

        def _flush_code():
            nonlocal code_buf
            if code_buf:
                raw = '\n'.join(code_buf).rstrip('\n')
                out.append('<pre>' + _html.escape(raw, quote=False) + '</pre>')
                code_buf = []

        def _inline(line: str) -> str:
            escaped = _html.escape(str(line or ''), quote=False)
            # inline code first so bold conversion does not touch command text
            escaped = _re.sub(r'`([^`]+)`', lambda m: '<code>' + m.group(1) + '</code>', escaped)
            escaped = _re.sub(r'\*([^*\n]+)\*', lambda m: '<b>' + m.group(1) + '</b>', escaped)
            st = escaped.strip()
            if len(st) >= 2 and st.startswith('_') and st.endswith('_'):
                inner = st[1:-1]
                prefix = escaped[:len(escaped) - len(escaped.lstrip())]
                suffix = escaped[len(escaped.rstrip()):]
                escaped = prefix + '<i>' + inner + '</i>' + suffix
            return escaped

        for line in text.splitlines():
            if line.strip() == '```':
                if in_code:
                    _flush_code()
                    in_code = False
                else:
                    in_code = True
                    code_buf = []
                continue
            if in_code:
                code_buf.append(line)
            else:
                out.append(_inline(line.rstrip()))
        if in_code:
            _flush_code()
        rendered = '\n'.join(out)
        rendered = _re.sub(r'\n{3,}', '\n\n', rendered).strip()
        return rendered
    except Exception:
        return _screen_plain_cleanup(txt)



def _screen_body_has_trade_setups(body: str) -> bool:
    """True only when a /screen body contains real setup cards, not just market context."""
    try:
        t = str(body or '')
        if not t.strip():
            return False
        low = t.lower()
        if 'no high-quality setups right now' in low:
            return False
        if 'executable scan is warming up' in low:
            return False
        if 'no confirmed setup' in low:
            return False
        return ((('PF-' in t) or ('BMAT-' in t) or ('BIGMOVE-' in t)) and 'Entry:' in t and ('BUY' in t or 'SELL' in t))
    except Exception:
        return False


def _screen_cache_put(cache_key: str, body: str, kb: list | None = None, ts: float | None = None, allow_empty_overwrite: bool = False) -> bool:
    """Write /screen cache without letting an empty refresh erase a useful recent setup view.

    This fixes the observed behaviour where /screen showed setups, then one background
    refresh returned an empty scan and the next /screen showed "No high-quality setups".
    """
    try:
        key = str(cache_key or '')
        if not key:
            return False
        body_s = str(body or '')
        now_ts = float(ts or time.time())
        new_has = _screen_body_has_trade_setups(body_s)
        old = _SCREEN_CACHE.get(key) or {}
        old_body = str(old.get('body') or '')
        old_has = _screen_body_has_trade_setups(old_body)
        old_age = now_ts - float(old.get('ts', 0.0) or 0.0)
        try:
            keep_window = max(float(SCREEN_STALE_CACHE_MAX_SEC or 0), float(_setup_delivery_actionable_window_sec()))
        except Exception:
            keep_window = max(float(SCREEN_STALE_CACHE_MAX_SEC or 0), 60.0 * 60.0)

        # Keep the exact setup-email batch visible while it is still actionable.
        # A background /screen rebuild can legitimately find a different pool one
        # minute later, but Pro/Admin /screen must stay synced with email/autotrade.
        old_is_email = ('Showing latest sent setup email' in old_body) or ('Showing recent emailed setup queue' in old_body) or ('Emailed at ' in old_body)
        new_is_email = ('Showing latest sent setup email' in body_s) or ('Showing recent emailed setup queue' in body_s) or ('Emailed at ' in body_s)
        if (not allow_empty_overwrite) and old_is_email and (not new_is_email) and old_has and old_age <= keep_window:
            try:
                db_log_setup_pipeline_event(0, stage='screen_cache_put', status='kept_recent_email_cache', session=str(key).split('::')[-1], mode='screen', details={'old_age_sec': round(old_age, 1)})
            except Exception:
                pass
            return False

        # Ver10: do NOT keep a generic non-empty /screen cache when the fresh
        # executable rebuild is empty. A stale candidate cache made /screen show
        # setups while /email_decision and AutoTrade had no executable pool.
        # Only the exact recent emailed lane is protected above.
        try:
            _keep_generic = str(os.environ.get('SCREEN_KEEP_NONEMPTY_CACHE_WHEN_EMPTY', '0') or '0').strip().lower() in {'1', 'true', 'yes', 'on'}
        except Exception:
            _keep_generic = False
        if _keep_generic and (not allow_empty_overwrite) and (not new_has) and old_has and old_age <= min(300.0, keep_window):
            try:
                db_log_setup_pipeline_event(0, stage='screen_cache_put', status='kept_nonempty_cache', session=str(key).split('::')[-1], mode='screen', details={'old_age_sec': round(old_age, 1)})
            except Exception:
                pass
            return False
        _SCREEN_CACHE[key] = {'ts': now_ts, 'body': body_s, 'kb': list(kb or [])}
        return True
    except Exception:
        try:
            _SCREEN_CACHE[str(cache_key or '')] = {'ts': float(ts or time.time()), 'body': str(body or ''), 'kb': list(kb or [])}
            return True
        except Exception:
            return False


def _screen_choose_best_cache(cache_keys: list[str]) -> tuple[dict, float]:
    """Prefer recent non-empty setup caches over newer empty/market-context-only caches."""
    try:
        candidates = []
        now_ts = time.time()
        for _ck in list(cache_keys or []):
            _ce = _SCREEN_CACHE.get(_ck) or {}
            _body = str(_ce.get('body') or '')
            if not _body:
                continue
            _is_quick = ('Executable scan is warming up' in _body) or ('quick ticker snapshot' in _body) or ('full executable scan warms up' in _body)
            if _is_quick:
                continue
            _age = now_ts - float(_ce.get('ts', 0.0) or 0.0)
            _has = _screen_body_has_trade_setups(_body)
            _is_email = ('Showing latest sent setup email' in _body) or ('Showing recent emailed setup queue' in _body) or ('Emailed at ' in _body)
            candidates.append((_is_email, _has, _age, _ce))
        if not candidates:
            return {}, 999999.0
        try:
            _email_screen_window_sec = max(float(_setup_delivery_actionable_window_sec()), float(SCREEN_STALE_CACHE_MAX_SEC or 0))
        except Exception:
            _email_screen_window_sec = max(60.0 * 60.0, float(SCREEN_STALE_CACHE_MAX_SEC or 0))
        recent_email = [c for c in candidates if c[0] and c[1] and c[2] <= _email_screen_window_sec]
        with_setups = [c for c in candidates if c[1]]
        pool = recent_email if recent_email else (with_setups if with_setups else candidates)
        pool.sort(key=lambda x: x[2])
        return pool[0][3], pool[0][2]
    except Exception:
        return {}, 999999.0

def _screen_display_limit() -> int:
    try:
        return max(1, min(4, int(os.environ.get('SCREEN_MAX_CARDS_DISPLAY', '4') or 4)))
    except Exception:
        return 4


def _screen_requires_emailed_delivery_for_setup() -> bool:
    """User-facing sync rule for /screen.

    /screen is a subscriber-facing surface, so it must not expose a raw executable
    setup that the email lane did not actually deliver/log. AutoTrade may still
    consume the executable queue directly; this helper is only for /screen UX.
    """
    try:
        return str(os.environ.get('SCREEN_REQUIRE_EMAILED_SETUP', '1') or '1').strip().lower() not in {'0', 'false', 'no', 'off'}
    except Exception:
        return True


def _screen_recent_emailed_ts_for_setup(user_id: int, setup, lookback_hours: float | None = None) -> float:
    """Return recent email timestamp for this exact setup/identity, else 0.

    This deliberately uses setup_id and setup identity, not only symbol cooldown,
    because /screen should match the exact email-delivered setup batch.
    """
    try:
        ts0 = float(getattr(setup, 'email_logged_ts', 0.0) or getattr(setup, 'emailed_ts', 0.0) or 0.0)
        if ts0 > 0:
            return ts0
    except Exception:
        pass
    try:
        uid = int(user_id or 0)
    except Exception:
        uid = 0
    if uid <= 0:
        return 0.0
    try:
        hours = float(lookback_hours if lookback_hours is not None else max(1.0, float(_screen_actionable_fallback_max_age_min()) / 60.0))
    except Exception:
        hours = 1.0
    cutoff = float(time.time()) - max(1.0, hours) * 3600.0
    sid = str(getattr(setup, 'setup_id', '') or getattr(setup, 'id', '') or '').strip()
    ident = ''
    try:
        ident = str(_setup_identity_from_obj(setup) or '').strip()
    except Exception:
        ident = ''
    try:
        with sqlite3.connect(DB_PATH) as conn:
            cur = conn.cursor()
            if sid:
                row = cur.execute(
                    "SELECT emailed_ts FROM emailed_setups WHERE user_id=? AND setup_id=? AND emailed_ts>=? ORDER BY emailed_ts DESC LIMIT 1",
                    (uid, sid, float(cutoff)),
                ).fetchone()
                if row and row[0] is not None:
                    return float(row[0] or 0.0)
            if ident:
                cur.execute("""CREATE TABLE IF NOT EXISTS emailed_setup_identities (
                    user_id INTEGER NOT NULL,
                    identity_key TEXT NOT NULL,
                    symbol TEXT NOT NULL DEFAULT '',
                    side TEXT NOT NULL DEFAULT '',
                    setup_id TEXT NOT NULL DEFAULT '',
                    emailed_ts REAL NOT NULL DEFAULT 0,
                    PRIMARY KEY(user_id, identity_key)
                )""")
                row = cur.execute(
                    "SELECT emailed_ts FROM emailed_setup_identities WHERE user_id=? AND identity_key=? AND emailed_ts>=? ORDER BY emailed_ts DESC LIMIT 1",
                    (uid, ident, float(cutoff)),
                ).fetchone()
                if row and row[0] is not None:
                    return float(row[0] or 0.0)
    except Exception:
        return 0.0
    return 0.0


def _screen_attach_email_delivery_or_skip(user_id: int, setup, lookback_hours: float | None = None) -> bool:
    """Attach email timestamp metadata to a setup or reject it for /screen."""
    try:
        if not _screen_requires_emailed_delivery_for_setup():
            return True
        ts = _screen_recent_emailed_ts_for_setup(int(user_id or 0), setup, lookback_hours=lookback_hours)
        if ts <= 0:
            return False
        try:
            setattr(setup, 'email_logged_ts', float(ts))
            setattr(setup, 'emailed_ts', float(ts))
            setattr(setup, 'source_kind', 'emailed_setups')
        except Exception:
            pass
        return True
    except Exception:
        return False


def _screen_format_setup_cards(setups: list, uid: int, session: str) -> str:
    """Return the nice card-style Markdown body used by /screen."""
    if not setups:
        return "_No high-quality setups right now._"

    def _mv_dot(p: float) -> str:
        try:
            p = float(p or 0.0)
        except Exception:
            p = 0.0
        if abs(p) < 2.0:
            return "🟡"
        return "🟢" if p >= 0 else "🔴"

    visible_setups = [s for s in list(setups or []) if _setup_volume_ok(s)]
    visible_setups = _filter_user_visible_keep_setups(visible_setups, session_name=session, user_id=int(uid or 0), lane='screen')
    if not visible_setups:
        if _user_visible_require_keep_policy('screen'):
            return "_No KEEP/WATCH policy setup right now. Background scanner is still collecting DISABLE/probation evidence for learning._"
        return f"_No setup above ${_setup_min_volume_floor_usd()/1e6:.0f}M 24h volume right now._"

    lines2 = []
    for s in visible_setups[:_screen_display_limit()]:
        try:
            sym = str(getattr(s, "symbol", "") or "").upper()
            sid = str(getattr(s, "setup_id", "") or "")
            side = str(getattr(s, "side", "") or "").upper()
            conf = int(getattr(s, "conf", 0) or 0)
            entry = float(getattr(s, "entry", 0.0) or 0.0)
            sl = float(getattr(s, "sl", 0.0) or 0.0)
            tp = float(_setup_target_tp(s, 0.0) or 0.0)
            vol = float(getattr(s, "fut_vol_usd", 0.0) or 0.0)
            ch24 = float(getattr(s, "ch24", 0.0) or 0.0)
            ch4 = float(getattr(s, "ch4", 0.0) or 0.0)
            ch1 = float(getattr(s, "ch1", 0.0) or 0.0)
            ch15 = float(getattr(s, "ch15", 0.0) or 0.0)
            rr_den = abs(entry - sl)
            rr = (abs(float(tp) - entry) / rr_den) if (rr_den > 0 and tp not in (None, 0, 0.0)) else 0.0
            pos_word = "long" if side == "BUY" else "short"
            size_cmd = f"/size {sym} {pos_word} entry {entry:.6g} sl {sl:.6g}"
            emoji = "🟢" if side == "BUY" else "🔴"
            typ = _setup_display_label(s)
            block = []
            fam_code = _setup_audit_family_code(getattr(s, 'family_id', '') or getattr(s, 'engine', '') or '')
            is_bigmove = (fam_code == 'F8') or str(sid).upper().startswith(('BMAT-', 'BIGMOVE-')) or 'BIGMOVE' in str(getattr(s, 'family_id', '') or getattr(s, 'engine', '') or '').upper()
            block.append(f"{emoji} *{side} — {sym}*")
            block.append(f"`{sid}` | Conf: `{conf}` | Family: `{'F8 BigMove' if is_bigmove else fam_code}`")
            try:
                sk = str(getattr(s, 'source_kind', '') or '').lower().strip()
                email_ts = float(getattr(s, 'email_logged_ts', 0.0) or getattr(s, 'emailed_ts', 0.0) or 0.0)
                if sk in {'emailed_setups', 'recent_email_cache', 'recent_email_lane'} or email_ts > 0:
                    when_txt = _screen_ts_label(email_ts) if email_ts > 0 else ''
                    if is_bigmove:
                        block.append(f"📩 *Setup emailed at {when_txt}* (F8 BigMove)" if when_txt else "📩 *Setup emailed* (F8 BigMove)")
                    else:
                        block.append(f"📩 *Setup emailed at {when_txt}*" if when_txt else "📩 *Setup emailed*")
                elif (not is_bigmove) and symbol_recently_emailed(uid, sym, side, session):
                    block.append("📩 *Email cooldown active*")
            except Exception:
                pass
            block.append(f"RR(TP): `{rr:.2f}`")
            block.append(f"Entry: `{fmt_price(entry)}` | SL: `{fmt_price(sl)}`")
            block.append(f"TP: `{fmt_price(float(_resolve_single_tp(entry, sl, tp, 0.0, 0.0, side) or 0.0))}`")
            block.append(
                f"Moves: 24H {ch24:+.0f}% {_mv_dot(ch24)} • 4H {ch4:+.0f}% {_mv_dot(ch4)} • "
                f"1H {ch1:+.0f}% {_mv_dot(ch1)} • 15m {ch15:+.0f}% {_mv_dot(ch15)}"
            )
            block.append(f"Volume: ~{vol/1e6:.1f}M")
            block.append(f"Chart: {tv_chart_url(sym)}")
            block.append(f"`{size_cmd}`")
            lines2.append("\n".join(block))
        except Exception:
            continue

    return ("\n\n".join(lines2)).strip() if lines2 else "_No high-quality setups right now._"


def _screen_recent_db_body_and_kb(uid: int, session: str, best_fut: dict, max_age_min: int | None = None, include_email_source: bool = True):
    """Lightweight no-OHLCV /screen fallback from the latest delivery/executable DB.

    Priority is deliberate:
    1) latest setup email delivered to this user/session;
    2) executable queue;
    3) recent generated candidates.
    This keeps /screen, email and autotrade showing the same setups after a deploy or cache refresh.
    """
    try:
        if max_age_min is None:
            max_age_min = _screen_actionable_fallback_max_age_min()
        max_age_min = max(1, int(max_age_min or _screen_actionable_fallback_max_age_min()))
        sess = str(session or '').upper().strip()
        out = []
        seen = set()

        def _basic_valid(item) -> bool:
            try:
                side = str(getattr(item, 'side', '') or '').upper().strip()
                entry = float(getattr(item, 'entry', 0.0) or 0.0)
                sl = float(getattr(item, 'sl', 0.0) or 0.0)
                tp = float(_setup_target_tp(item, 0.0) or 0.0)
                if side not in {'BUY', 'SELL'} or entry <= 0 or sl <= 0 or tp <= 0:
                    return False
                if side == 'BUY' and not (sl < entry < tp):
                    return False
                if side == 'SELL' and not (tp < entry < sl):
                    return False
                if not _setup_volume_ok(item):
                    return False
                return True
            except Exception:
                return False

        sources = []
        if include_email_source:
            try:
                sources.append(('emailed', _recent_delivery_lane_setup_objects(int(uid), session_name=sess, max_age_min=max_age_min, limit=20) or []))
            except Exception:
                sources.append(('emailed', []))
        try:
            cutoff = float(time.time()) - float(max(2, int(max_age_min))) * 60.0
            rows = db_list_executable_setups(int(uid), session_name=sess, ts_from=cutoff, limit=20)
            sources.append(('executable', _executable_rows_to_setup_objects(rows, session_name=sess) or []))
        except Exception:
            sources.append(('executable', []))
        # Ver10: do not show raw/recent generated candidates as Top Trade Setups.
        # /screen must match the executable/email/autotrade lane. Candidates that
        # are not in executable_setups can still appear in diagnostics/watch lists,
        # but not as actionable setup cards.

        used_source_name = ''
        for source_name, candidates in sources:
            for item in candidates:
                try:
                    sid = str(getattr(item, 'setup_id', '') or getattr(item, 'id', '') or '').strip()
                    sym = str(getattr(item, 'symbol', '') or '').upper().strip()
                    ident = _setup_identity_from_obj(item)
                    dedupe_key = ident or sid
                    if not sid or not sym or dedupe_key in seen:
                        continue
                    src_session_u = str(getattr(item, 'source_session', '') or getattr(item, 'session', '') or '').upper().strip()
                    if sess and src_session_u and src_session_u not in {'', sess}:
                        continue
                    try:
                        if source_name == 'emailed':
                            ok_basic = _basic_valid(item)
                            ok_final, _why_final, _meta_final = _setup_final_quality_gate_allows_setup(item, session_name=sess, user_id=int(uid)) if ok_basic else (False, 'screen_emailed_basic_invalid', {})
                            ok_exec = bool(ok_basic and ok_final)
                        else:
                            ok_exec, _why_exec = is_executable_setup_eligible(item, session_name=sess)
                    except Exception:
                        ok_exec = False
                    if not ok_exec:
                        continue
                    keep_ok, _keep_why, _keep_meta = _setup_user_visible_keep_policy_allows(item, session_name=sess, user_id=int(uid), lane='screen')
                    if not keep_ok:
                        continue
                    if source_name != 'emailed' and not _screen_attach_email_delivery_or_skip(int(uid), item, lookback_hours=max(1.0, float(max_age_min) / 60.0)):
                        continue
                    if not used_source_name:
                        used_source_name = 'emailed' if _screen_requires_emailed_delivery_for_setup() else str(source_name or '')
                    out.append(item)
                    seen.add(dedupe_key)
                    if len(out) >= _screen_display_limit():
                        break
                except Exception:
                    continue
            if out:
                break

        if not out:
            return '', [], []
        try:
            up_list, dn_list = compute_directional_lists(best_fut or {})
        except Exception:
            up_list, dn_list = [], []
        market_txt = _screen_market_context_table(best_fut or {}, leaders=up_list, losers=dn_list)
        source_note = '_Showing recent emailed setup queue while the live scan refreshes._' if _screen_requires_emailed_delivery_for_setup() else ('_Showing latest sent setup email while the live scan refreshes._' if include_email_source and used_source_name == 'emailed' else '_Showing recent executable setup queue while the live scan refreshes._')
        body = "\n".join([
            "",
            "*Top Trade Setups*",
            SEP,
            source_note,
            _screen_format_setup_cards(out, int(uid), sess),
            "",
            market_txt or "",
        ]).strip()
        kb = [(str(getattr(x, 'symbol', '') or '').upper(), str(getattr(x, 'setup_id', '') or getattr(x, 'id', '') or '')) for x in out]
        return body, kb, list(out)
    except Exception:
        return '', [], []

def _build_screen_body_and_kb(best_fut: dict, session: str, uid: int):
    """Heavy /screen builder (runs in a worker thread).

    Top setups must stay in the same lane used by email + autotrade.
    If a setup was just emailed to this user, /screen should reflect that same live setup
    for a short freshness window instead of immediately showing an empty screen because the
    next scan tick no longer rebuilt the same candidate.

    Returns:
        body (str): cached body (header is built in the async handler)
        kb (list[tuple[str,str]]): [(SYMBOL, SETUP_ID), ...] for TradingView buttons
        setups (list[Setup]): synced executable-grade setups shown on /screen
    """
    from types import SimpleNamespace

    def _recent_email_lane_screen_setups(_uid: int, _session: str, max_age_min: int | None = None, limit: int = 3):
        """Return the newest visible setup lane for /screen.

        Priority: latest emailed setups first, then executable DB queue, then recent generated
        candidates. This prevents /screen from showing a different cache than the email that
        just went out.
        """
        try:
            if max_age_min is None:
                max_age_min = _screen_actionable_fallback_max_age_min()
            max_age_min = max(1, int(max_age_min or _screen_actionable_fallback_max_age_min()))
            req_session_u = str(_session or '').upper().strip()
            out = []
            seen = set()

            def _basic_valid(item) -> bool:
                try:
                    side = str(getattr(item, 'side', '') or '').upper().strip()
                    entry = float(getattr(item, 'entry', 0.0) or 0.0)
                    sl = float(getattr(item, 'sl', 0.0) or 0.0)
                    tp = float(_setup_target_tp(item, 0.0) or 0.0)
                    if side not in {'BUY', 'SELL'} or entry <= 0 or sl <= 0 or tp <= 0:
                        return False
                    if side == 'BUY' and not (sl < entry < tp):
                        return False
                    if side == 'SELL' and not (tp < entry < sl):
                        return False
                    if not _setup_volume_ok(item):
                        return False
                    return True
                except Exception:
                    return False

            sources = []
            if _screen_user_can_see_email_source(int(_uid)):
                try:
                    sources.append(('emailed', _recent_delivery_lane_setup_objects(int(_uid), session_name=req_session_u, max_age_min=max_age_min, limit=max(1, int(limit * 3))) or []))
                except Exception:
                    sources.append(('emailed', []))
            try:
                cutoff = float(time.time()) - float(max_age_min) * 60.0
                rows = db_list_executable_setups(int(_uid), session_name=str(_session or ''), ts_from=float(cutoff), limit=max(1, int(limit * 4)))
                sources.append(('executable', _executable_rows_to_setup_objects(rows, session_name=req_session_u) or []))
            except Exception:
                sources.append(('executable', []))
            # Ver10: no raw/recent-candidate fallback for Top Trade Setups.
            # If it is not emailed or in executable_setups, it must not be shown as
            # an actionable setup because email/autotrade will not consume it.

            for source_name, rows in sources:
                for item in rows:
                    try:
                        sid = str(getattr(item, 'setup_id', '') or getattr(item, 'id', '') or '').strip()
                        ident = _setup_identity_from_obj(item)
                        dedupe_key = ident or sid
                        if not sid or dedupe_key in seen:
                            continue
                        src_session_u = str(getattr(item, 'source_session', '') or '').upper().strip()
                        if req_session_u and src_session_u and src_session_u not in {'', req_session_u}:
                            continue
                        if source_name == 'emailed':
                            ok_exec = _basic_valid(item)
                        else:
                            try:
                                ok_exec, _why_exec = is_executable_setup_eligible(item, session_name=req_session_u or src_session_u or _session)
                            except Exception:
                                ok_exec, _why_exec = False, 'screen_lane_exec_gate_exception'
                        if ok_exec:
                            keep_ok, _keep_why, _keep_meta = _setup_user_visible_keep_policy_allows(item, session_name=(req_session_u or src_session_u or _session), user_id=int(_uid), lane='screen')
                            if not keep_ok:
                                continue
                            if source_name != 'emailed' and not _screen_attach_email_delivery_or_skip(int(_uid), item, lookback_hours=max(1.0, float(max_age_min) / 60.0)):
                                continue
                            out.append(item)
                            seen.add(dedupe_key)
                        if len(out) >= int(limit):
                            return out[:int(limit)]
                    except Exception:
                        continue
                if out:
                    break
            return out[:int(limit)]
        except Exception:
            return []


    # Market context inputs (keep /screen informative without becoming a data terminal)
    leaders_txt = build_leaders_table(best_fut)  # fast (top by futures volume)
    up_list, dn_list = compute_directional_lists(best_fut)

    # Build the CURRENT executable pool first, persist it as the authoritative
    # executable queue for this user/session, then read /screen back from that same
    # source of truth so /screen and autotrade are wired to the same lane.
    try:
        pool = _run_coro_in_thread(
            build_priority_pool(
                best_fut,
                session,
                mode="exec",
                scan_profile=str(DEFAULT_SCAN_PROFILE),
                uid=uid,
            )
        )
    except Exception as e:
        db_log_setup_pipeline_event(int(uid), stage='build_priority_pool', status='error', session=str(session or ''), mode='screen', details={'error': f'{type(e).__name__}: {e}'})
        pool = {'setups': [], 'waiting': [], 'trend_watch': [], 'spikes': [], 'spike_warnings': []}
    try:
        _raw_pool_setups = list(pool.get("setups") or [])
        _exec_ready = []
        _exec_rejects = Counter()
        for _s in _raw_pool_setups:
            try:
                _s_eff = _setup_route_candidate_for_executable_lane(_s, session, int(uid))
                _ok_exec, _why_exec = is_executable_setup_eligible(_s_eff, session_name=session)
            except Exception:
                _s_eff = _s
                _ok_exec, _why_exec = False, 'screen_exec_gate_exception'
            if _ok_exec:
                _exec_ready.append(_s_eff)
            else:
                _exec_rejects[str(_why_exec)] += 1
        if _exec_ready:
            _persist_stats = _persist_executable_candidates(int(uid), str(session or ''), _exec_ready, source_kind='executable_setups', mode='screen')
            db_log_setup_pipeline_event(int(uid), stage='screen_executable_pool', status='ok', session=str(session or ''), mode='screen', details={'raw_pool': len(_raw_pool_setups), 'executable_ready': len(_exec_ready), 'persisted': int((_persist_stats or {}).get('persisted') or 0), 'top_exec_rejects': _pipeline_top_reasons(_exec_rejects, 5)})
        else:
            db_log_setup_pipeline_event(int(uid), stage='screen_executable_pool', status='empty', session=str(session or ''), mode='screen', details={'raw_pool': len(_raw_pool_setups), 'top_exec_rejects': _pipeline_top_reasons(_exec_rejects, 5)})
    except Exception as e:
        db_log_setup_pipeline_event(int(uid), stage='screen_executable_pool', status='error', session=str(session or ''), mode='screen', details={'error': f'{type(e).__name__}: {e}'})
        _exec_ready = []

    try:
        setups = list(_recent_email_lane_screen_setups(int(uid), str(session or ''), max_age_min=_screen_actionable_fallback_max_age_min(), limit=max(1, int(SETUPS_N))))
    except Exception:
        setups = []

    if not setups and _exec_ready and not _screen_requires_emailed_delivery_for_setup():
        _screen_keep_ready = _filter_user_visible_keep_setups(list(_exec_ready or []), session_name=str(session or ''), user_id=int(uid), lane='screen')
        setups = list(_screen_keep_ready[:max(1, int(SETUPS_N))])
    elif not setups and _exec_ready and _screen_requires_emailed_delivery_for_setup():
        _screen_keep_ready = _filter_user_visible_keep_setups(list(_exec_ready or []), session_name=str(session or ''), user_id=int(uid), lane='screen')
        _screen_emailed_ready = [s for s in list(_screen_keep_ready or []) if _screen_attach_email_delivery_or_skip(int(uid), s, lookback_hours=max(1.0, float(_screen_actionable_fallback_max_age_min()) / 60.0))]
        setups = list(_screen_emailed_ready[:max(1, int(SETUPS_N))])

    # Keep /screen readable. The executable queue can still hold more for email/autotrade;
    # /screen is an action dashboard, not a dump. Also enforce the production 24h-volume floor.
    try:
        setups = [s for s in list(setups or []) if _setup_volume_ok(s)]
        setups = _filter_user_visible_keep_setups(setups, session_name=str(session or ''), user_id=int(uid), lane='screen')
    except Exception:
        setups = list(setups or [])
    try:
        setups = list(setups or [])[:_screen_display_limit()]
    except Exception:
        setups = list(setups or [])[:5]

    # For UX: do not show the same symbol in Momentum Watch if it's already a Top Setup
    try:
        top_setup_syms = set(str(getattr(s, 'symbol', '') or '').upper() for s in (setups or []) if getattr(s, 'symbol', None))
    except Exception:
        top_setup_syms = set()
    # Keep recent cards in memory for PF- lookup. The screen itself is now built from
    # the executable lane, but these cached cards are not report rows by themselves.
    try:
        for s in (setups or []):
            if not hasattr(s, "conf") or s.conf is None:
                s.conf = 0
            try:
                _remember_recent_screen_signal(s, session=session, user_id=uid)
            except Exception:
                pass
    except Exception:
        pass

    # Setup cards -> combined text (single "Top Trade Setups" section)
    combined_setups_txt = _screen_format_setup_cards(setups, int(uid), str(session or ''))

    # -----------------------------------------------------
    # UX: Keep /screen clean and action-first.
    # - Top Trade Setups = ONLY qualified, email-eligible setups.
    # - Momentum Watch = small "FYI" list (no entry yet).
    # - Market Context = compressed pulse of the market (tone + a few leaders/losers + BTC/ETH).
    # -----------------------------------------------------

    # Momentum Watch (No Entry Yet)
    momentum_lines = []
    try:
        waiting_items = pool.get("waiting") or []
    except Exception:
        waiting_items = []

    try:
        trend_watch = pool.get("trend_watch") or []
    except Exception:
        trend_watch = []

    try:
        seen_syms = set()

        # 1) Waiting-for-trigger items first (near-miss)
        for item in (waiting_items or [])[:max(2, int(SCREEN_WAITING_N or 2))]:
            try:
                if not (isinstance(item, (list, tuple)) and len(item) == 2 and isinstance(item[1], dict)):
                    continue
                base, d = item
                sym = str(base).upper()
                if sym in (top_setup_syms or set()):
                    continue
                raw_side = str(d.get("side", "BUY") or "BUY").strip().upper()
                if raw_side in ("LONG",):
                    side = "BUY"
                elif raw_side in ("SHORT",):
                    side = "SELL"
                elif raw_side in ("BUY", "SELL"):
                    side = raw_side
                else:
                    side = raw_side
                dot = "🟢" if side == "BUY" else ("🔴" if side == "SELL" else "🟡")
                if sym in seen_syms:
                    continue
                seen_syms.add(sym)
                momentum_lines.append(f"• *{sym}* {dot} `{side}` — waiting for entry trigger")
                if len(momentum_lines) >= 2:
                    break
            except Exception:
                continue

        # 2) Trend watch (strong trend but no valid entry) — fill remaining slots
        if len(momentum_lines) < 2:
            trend_watch_sorted = sorted(
                (trend_watch or []),
                key=lambda x: int(x.get("confidence", x.get("conf", 0)) or 0),
                reverse=True
            )
            for t in trend_watch_sorted:
                try:
                    sym = str(t.get("symbol", "")).upper().strip()
                    if sym in (top_setup_syms or set()):
                        continue
                    if not sym or sym in seen_syms:
                        continue
                    side = str(t.get("side", "BUY") or "BUY").strip().upper()
                    dot = "🟢" if side == "BUY" else ("🔴" if side == "SELL" else "🟡")
                    seen_syms.add(sym)
                    momentum_lines.append(f"• *{sym}* {dot} `{side}` — strong trend, no qualified entry yet")
                    if len(momentum_lines) >= 2:
                        break
                except Exception:
                    continue
    except Exception:
        momentum_lines = []

    momentum_txt = ""
    if momentum_lines:
        momentum_txt = "*Momentum Watch (No Entry Yet)*\n" + SEP + "\n" + "\n".join(momentum_lines)

    # Market Context (compressed)
    market_txt = ""
    try:
        # Build Leaders/Losers for Market Context
        # Goal: show up to 5 items each (when available), preferring "directional" movers,
        # but backfilling with high-volume movers so the section is informative.
        vol_min = float(_screen_context_volume_floor_usd())

        movers = []
        for sym, mv in (best_fut or {}).items():
            try:
                v = float(usd_notional(mv) or 0.0)
                c24 = float(getattr(mv, "percentage", 0.0) or 0.0)
                movers.append((sym, v, c24))
            except Exception:
                continue

        movers = [t for t in movers if t[1] >= vol_min]

        # Backfill thresholds: start strict, relax if we don't have enough.
        def _pick_top(movers_list, direction: str):
            out = []
            used = set()
            if direction == "up":
                thresholds = [float(MOVER_UP_24H_MIN), 5.0, 0.0]
                key = lambda x: x[2]
                filt = lambda x, th: x[2] >= th
                sort_rev = True
            else:
                thresholds = [abs(float(MOVER_DN_24H_MAX)), 5.0, 0.0]  # compare on absolute move
                key = lambda x: -x[2]  # more negative first when sorting ascending by c24
                filt = lambda x, th: (-x[2]) >= th
                sort_rev = False

            for th in thresholds:
                if direction == "up":
                    cand = [x for x in movers_list if x[0] not in used and filt(x, th)]
                    cand = sorted(cand, key=lambda x: x[2], reverse=True)
                else:
                    cand = [x for x in movers_list if x[0] not in used and filt(x, th)]
                    cand = sorted(cand, key=lambda x: x[2])  # most negative first

                for x in cand:
                    out.append(x)
                    used.add(x[0])
                    if len(out) >= 5:
                        return out
            return out

        up_picks = _pick_top(movers, "up")
        dn_picks = _pick_top(movers, "dn")

        # Tone heuristic (based on strict directional thresholds)
        upn = sum(1 for _sym, _v, _c24 in movers if _c24 >= float(MOVER_UP_24H_MIN))
        dnn = sum(1 for _sym, _v, _c24 in movers if _c24 <= float(MOVER_DN_24H_MAX))
        if upn >= max(2, int(dnn * 1.5)):
            tone = "\U0001F7E2 Bullish"
        elif dnn >= max(2, int(upn * 1.5)):
            tone = "\U0001F534 Bearish"
        else:
            tone = "\U0001F7E1 Mixed"

        market_txt = _screen_market_context_table(best_fut, leaders=up_picks, losers=dn_picks, tone=tone)
    except Exception:
        market_txt = ""

    # Assemble body (cache THIS, header stays live)
    def _is_empty(txt: str) -> bool:
        t = (txt or "").strip()
        if not t:
            return True
        return t.startswith("_No ") or t.startswith("No ") or t.endswith("right now._")

    screen_lane_note = ""
    try:
        if setups and any(str(getattr(s, 'source_kind', '') or '') not in {'', 'executable_setups'} for s in (setups or [])):
            screen_lane_note = "_Showing only very recent fallback setups while the executable lane rebuilds. Stale duplicates are suppressed._"
    except Exception:
        screen_lane_note = ""

    blocks = []
    blocks.extend(["", "*Top Trade Setups*", SEP])
    if screen_lane_note:
        blocks.append(screen_lane_note)
    blocks.append(combined_setups_txt)

    # Only show momentum section if there are no qualified setups OR to give quick context.
    if momentum_txt and (not _is_empty(momentum_txt)):
        blocks.extend(["", momentum_txt])

    if market_txt and (not _is_empty(market_txt)):
        blocks.extend(["", market_txt])

    body = "\n".join([b for b in blocks if b is not None]).strip()

    kb = []
    try:
        kb = [(s.symbol, s.setup_id) for s in (setups or [])][:_screen_display_limit()]
    except Exception:
        kb = []
    return body, kb, list(setups or [])

async def _screen_sync_pipeline_async(uid: int, user: dict, live_session: str, scan_session: str, best_fut: dict, shown_setups: list["Setup"]):
    """Immediately sync manual /screen top setups into the email -> autotrade lane.

    This keeps manual scans aligned with the live pipeline instead of waiting for the
    background email job to rediscover the same setup later.

    IMPORTANT:
    Manual /screen sync must honor the same email-session caps, daily caps, email gap,
    cooldowns, and executable qualification rules as the background email pipeline.
    """
    try:
        if not shown_setups:
            return {"status": "skip", "reason": "no_shown_setups"}
        live_session = str(live_session or '').upper().strip()
        scan_session = str(scan_session or '').upper().strip()

        user = dict(user or {})
        unlimited_on = int(user.get("sessions_unlimited", 0) or 0) == 1
        try:
            sess = in_session_now(user or {})
        except Exception:
            sess = None
        if not sess:
            return {"status": "skip", "reason": "user_not_in_enabled_session"}

        sess_name = str(sess.get('name') or '').upper().strip()
        if sess_name not in {"ASIA", "LON", "NY"}:
            return {"status": "skip", "reason": f"invalid_target_session ({sess_name or 'NONE'})"}

        # Normal mode: only sync when /screen is inside the real live market session.
        # Sessions UNLIMITED: allow manual /screen outside live session too, but always
        # sync into the real target bucket resolved by in_session_now()/scan-session logic
        # so email logging and autotrade stay on the same session lane.
        if not unlimited_on:
            if live_session not in {"ASIA", "LON", "NY"}:
                return {"status": "skip", "reason": "outside_live_session_window"}
            if scan_session and scan_session != live_session:
                return {"status": "skip", "reason": f"session_mismatch ({scan_session}->{live_session})"}
            if sess_name != live_session:
                return {"status": "skip", "reason": f"user_session_mismatch ({sess_name}!={live_session})"}

        target_session = sess_name

        try:
            st = email_state_get(int(uid))
        except Exception as e:
            return {"status": "error", "reason": f"email_state_get_failed ({type(e).__name__})"}

        try:
            sess_key = str(sess.get('session_key') or '')
            if str(st.get('session_key')) != sess_key:
                email_state_set(int(uid), session_key=sess_key, sent_count=0, last_email_ts=0.0)
                st = email_state_get(int(uid))
        except Exception:
            pass

        email_gate = _email_runtime_limits_snapshot(int(uid), user)
        if not bool(email_gate.get('gate_open')):
            reason = ', '.join([str(r) for r in (email_gate.get('gate_reasons') or [])[:3]]) or 'email_gate_blocked'
            _LAST_EMAIL_DECISION[int(uid)] = {
                'status': 'SKIP',
                'reasons': [reason],
                'when': datetime.now(timezone.utc).isoformat(timespec='seconds'),
            }
            return {"status": "skip", "reason": f"screen_sync_blocked ({reason})"}

        actionable = []
        skipped = []
        seen_keys = set()
        for s in (shown_setups or []):
            sid = str(getattr(s, 'setup_id', '') or '').strip()
            if not sid:
                skipped.append('missing_setup_id')
                continue
            # Manual /screen sync must NOT bypass the executable gate.
            # Only setups that are valid for the background email/autotrade lane
            # may be emailed and queued here.
            try:
                s = _setup_route_unless_delivery_locked(s, target_session, int(uid), source_kind=str(getattr(s, 'source_kind', '') or ''))
                _exec_ok, _exec_why = is_executable_setup_eligible(s, session_name=target_session)
            except Exception:
                _exec_ok, _exec_why = False, 'screen_sync_exec_gate_exception'
            if not _exec_ok:
                skipped.append(f'exec_gate:{_exec_why}')
                continue
            if db_has_emailed_setup(int(uid), sid, lookback_hours=12):
                skipped.append('already_emailed')
                continue
            sym = str(getattr(s, 'symbol', '') or '').upper()
            side = str(getattr(s, 'side', '') or '').upper()
            if symbol_flip_guard_active(int(uid), sym, side, target_session):
                skipped.append('flip_guard_blocked')
                continue
            if _email_setup_identity_recently_sent(int(uid), s):
                skipped.append('duplicate_setup_identity')
                continue
            if _email_symbol_recently_sent(int(uid), sym, side, target_session, setup_id=sid):
                skipped.append('cooldown_blocked')
                continue
            try:
                dedupe_key = (
                    sym,
                    side,
                    round(float(getattr(s, 'entry', 0.0) or 0.0), 8),
                    round(float(getattr(s, 'sl', 0.0) or 0.0), 8),
                    round(float(_setup_target_tp(s, 0.0) or 0.0), 8),
                )
            except Exception:
                dedupe_key = (sym, side, sid)
            if dedupe_key in seen_keys:
                skipped.append('duplicate_candidate')
                continue
            seen_keys.add(dedupe_key)
            actionable.append(s)

        if not actionable:
            return {"status": "skip", "reason": f"no_actionable_screen_setups ({','.join(skipped[:3])})"}

        actionable = list(actionable[:max(1, int(EMAIL_SETUPS_N))])
        sent = await to_thread_heavy(
            send_email_alert_multi,
            dict(user or {}),
            {"name": str(target_session)},
            actionable,
            best_fut,
        )
        if sent:
            try:
                sent_count_now = int(st.get('sent_count', 0) or 0)
            except Exception:
                sent_count_now = 0
            try:
                email_state_set(int(uid), last_email_ts=time.time(), sent_count=sent_count_now + 1)
            except Exception:
                pass
            try:
                _email_daily_inc(int(uid), str(email_gate.get('day_local') or ''))
            except Exception:
                pass
            for s in actionable:
                try:
                    mark_symbol_emailed(int(uid), s.symbol, s.side, target_session)
                except Exception:
                    pass

            # Ver22: /screen-sync and autonomous screen-sync must behave exactly like the
            # normal setup email lane. After the setup email is sent, immediately queue
            # AutoTrade for the exact same setup batch. This prevents email/screen from
            # being ahead of autotrade.
            try:
                owner_uid_for_at = int(AUTOTRADE_OWNER_UID or 0)
                if owner_uid_for_at > 0 and _autotrade_ready() and (int(uid) == owner_uid_for_at or is_admin_user(int(uid))):
                    _LAST_AUTOTRADE_DECISION[owner_uid_for_at] = {
                        "status": "QUEUED",
                        "when": datetime.now(timezone.utc).isoformat(timespec="seconds"),
                        "reason": "screen_sync_email_sent_waiting_for_immediate_autotrade",
                        "session": str(target_session or ""),
                        "mode": str(_autotrade_runtime_mode()).lower(),
                        "trigger": "screen_or_autonomous_sync",
                    }
                    _safe_create_task(
                        _trigger_autotrade_after_email_async(int(uid), str(target_session or ""), list(actionable or [])),
                        "autotrade_after_screen_sync_email",
                    )
            except Exception:
                pass

            return {"status": "sent", "reason": f"synced {len(actionable)} setup(s)", "setup_ids": [str(getattr(s, 'setup_id', '') or '') for s in actionable], "target_session": target_session}

        fail_reason = ''
        try:
            dec = _LAST_EMAIL_DECISION.get(int(uid)) or {}
            fail_reason = ', '.join([str(r) for r in (dec.get('reasons') or [])[:2]]) or str(dec.get('reason') or '')
        except Exception:
            fail_reason = ''
        fail_reason = fail_reason or str(_LAST_SMTP_ERROR.get(int(uid)) or 'screen_sync_email_send_failed')
        return {"status": "skip", "reason": f"screen_sync_email_send_failed ({fail_reason})"}
    except Exception as e:
        return {"status": "error", "reason": f"screen_sync_exception ({type(e).__name__}: {e})"}


async def screen_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    _hb_touch('screen', ok=True, details='screen_cmd_invoked')

    uid = update.effective_user.id
    user = get_user(uid)

    if not has_active_access(uid, user):
        await update.message.reply_text(
            "⛔️ Trial finished.\n\n"
            "Your 7-day trial is over — you need to pay to keep using PulseFutures.\n\n"
            "👉 /billing"
        )
        return

    # ULTRA-LOW-LATENCY /screen:
    # Never wait for OHLCV/Bybit scans inside the user command. Return the latest cached
    # snapshot immediately and refresh the cache in the background.
    try:
        live_session = current_session_utc()
        scan_session = str(scan_session_name_utc() or '').upper()
        loc_label, loc_time = user_location_and_time(user)
        cache_keys = [
            f"uid:{int(uid)}::{scan_session}",
            f"global::{scan_session}",
        ]
        # If this session has no cache after a restart, reuse the freshest cache from any session.
        try:
            for _k, _v in list(_SCREEN_CACHE.items()):
                if str(_k).startswith((f"uid:{int(uid)}::", "global::")) and (_v or {}).get('body'):
                    cache_keys.append(_k)
        except Exception:
            pass
        cache_entry, age = _screen_choose_best_cache(cache_keys)
        _schedule_screen_cache_refresh(int(uid), scan_session)
        can_show_email_source = _screen_user_can_see_email_source(int(uid), user)
        try:
            screen_fallback_min = int(_screen_actionable_fallback_max_age_min())
        except Exception:
            screen_fallback_min = 60
        try:
            latest_delivery_ts = _latest_recent_delivery_ts(int(uid), str(scan_session or '').upper(), max_age_min=screen_fallback_min) if can_show_email_source else 0.0
        except Exception:
            latest_delivery_ts = 0.0
        cache_ts = float((cache_entry or {}).get('ts', 0.0) or 0.0)
        # yver51: /screen setup cards are part of delivery, so blackout hides
        # cached/recent setup queues while raw generation continues in shadow.
        screen_delivery_blackout = False
        try:
            screen_delivery_blackout, _screen_blk_reason = _setup_delivery_blackout_now()
            if screen_delivery_blackout:
                latest_delivery_ts = 0.0
        except Exception:
            screen_delivery_blackout = False

        # Latest setup email wins over a cached scan only for Pro/trial users and admins,
        # because Standard users do not receive setup emails.
        if latest_delivery_ts > 0:
            try:
                quick_best_email = get_cached_futures_tickers() or {}
                if quick_best_email:
                    body_e, kb_e, shown_e = _screen_recent_db_body_and_kb(
                        int(uid), str(scan_session or '').upper(), quick_best_email,
                        max_age_min=screen_fallback_min,
                        include_email_source=True,
                    )
                    if body_e:
                        # Keep the top /screen note consistent with the actual body source.
                        # If the DB fallback had to show the executable queue rather than the exact
                        # latest email batch, do not label the whole screen as a sent-email view.
                        try:
                            _body_is_latest_email = 'Showing latest sent setup email' in str(body_e or '')
                        except Exception:
                            _body_is_latest_email = False
                        _source_note_e = (
                            "_Showing recent emailed setup queue while the live scan refreshes._\n"
                            if _screen_requires_emailed_delivery_for_setup() else
                            ("_Showing latest sent setup email while the live scan refreshes._\n"
                             if _body_is_latest_email else
                             "_Showing recent executable setup queue while the live scan refreshes._\n")
                        )
                        header_e = (
                            f"*PulseFutures — Market Scan*\n"
                            f"{HDR}\n"
                            f"*Session:* `{live_session}` | *{loc_label}:* `{loc_time}`\n"
                            f"{_source_note_e}"
                        )
                        keyboard_e = [
                            [InlineKeyboardButton(text=f"📈 {sym} • {sid}", url=tv_chart_url(sym))]
                            for (sym, sid) in (kb_e or [])
                        ]
                        await send_long_message(
                            update,
                            _screen_markdown_to_html((header_e + "\n" + body_e).strip()),
                            parse_mode=ParseMode.HTML,
                            disable_web_page_preview=True,
                            reply_markup=InlineKeyboardMarkup(keyboard_e) if keyboard_e else None,
                        )
                        return
            except Exception:
                pass

        if (not bool(locals().get('screen_delivery_blackout', False))) and cache_entry.get('body') and age <= float(SCREEN_STALE_CACHE_MAX_SEC):
            note = "_Showing latest cached scan. Fresh scan is refreshing in the background._\n"
            if age <= float(SCREEN_CACHE_TTL_SEC):
                note = "_Showing latest cached scan._\n"
            header = (
                f"*PulseFutures — Market Scan*\n"
                f"{HDR}\n"
                f"*Session:* `{live_session}` | *{loc_label}:* `{loc_time}`\n"
                f"{_screen_when_line('Cached scan built', cache_ts)}"
                f"{note}"
            )
            keyboard = [
                [InlineKeyboardButton(text=f"📈 {sym} • {sid}", url=tv_chart_url(sym))]
                for (sym, sid) in (cache_entry.get('kb') or [])
            ]
            await send_long_message(
                update,
                _screen_markdown_to_html((header + "\n" + str(cache_entry.get('body') or '')).strip()),
                parse_mode=ParseMode.HTML,
                disable_web_page_preview=True,
                reply_markup=InlineKeyboardMarkup(keyboard) if keyboard else None,
            )
            return
        # No usable full cache exists. Do NOT run a cold OHLCV rebuild inside the
        # Telegram command path. That was the source of visible lag and Render warnings.
        # A dedicated background refresh was already queued above; return a ticker
        # snapshot immediately so /equity, /why, /status and /open_trades stay responsive.

        # First try a lightweight SQLite fallback. This is important immediately after
        # deployment: memory cache is empty, but recent executable/email setups may
        # already exist in the DB and should be visible on /screen.
        try:
            quick_best = get_cached_futures_tickers() or {}
            if quick_best:
                body, kb, shown_setups = _screen_recent_db_body_and_kb(
                    int(uid),
                    str(scan_session or '').upper(),
                    quick_best,
                    max_age_min=screen_fallback_min,
                    include_email_source=bool(can_show_email_source),
                )
                if body:
                    try:
                        source_ts = max([float(getattr(x, 'email_logged_ts', 0.0) or getattr(x, 'executable_ts', 0.0) or getattr(x, 'created_ts', 0.0) or 0.0) for x in (shown_setups or [])] or [0.0])
                    except Exception:
                        source_ts = 0.0
                    try:
                        source_ts = max([float(getattr(x, 'email_logged_ts', 0.0) or getattr(x, 'executable_ts', 0.0) or getattr(x, 'created_ts', 0.0) or 0.0) for x in (shown_setups or [])] or [0.0])
                    except Exception:
                        source_ts = 0.0
                    header = (
                        f"*PulseFutures — Market Scan*\n"
                        f"{HDR}\n"
                        f"*Session:* `{live_session}` | *{loc_label}:* `{loc_time}`\n"
                        f"{_screen_when_line('Displayed setup source', source_ts)}"
                        f"{('_Showing recent emailed setup queue while full scan refreshes._' if _screen_requires_emailed_delivery_for_setup() else '_Showing recent executable setup queue while full scan refreshes._')}\n"
                    )
                    keyboard = [
                        [InlineKeyboardButton(text=f"📈 {sym} • {sid}", url=tv_chart_url(sym))]
                        for (sym, sid) in (kb or [])
                    ]
                    await send_long_message(
                        update,
                        _screen_markdown_to_html((header + "\n" + body).strip()),
                        parse_mode=ParseMode.HTML,
                        disable_web_page_preview=True,
                        reply_markup=InlineKeyboardMarkup(keyboard) if keyboard else None,
                    )
                    if MANUAL_SCREEN_SYNC_ENABLED and shown_setups:
                        try:
                            _safe_create_task(
                                _screen_sync_pipeline_async(
                                    int(uid),
                                    dict(user or {}),
                                    str(live_session or ''),
                                    str(scan_session or ''),
                                    quick_best,
                                    list(shown_setups or []),
                                ),
                                'screen_db_sync_once'
                            )
                        except Exception:
                            pass
                    return
        except Exception:
            pass

        # Last-resort instant ticker snapshot from cached tickers. Do NOT cache it as a
        # full scan, otherwise it suppresses the next real rebuild for MAX_STALE_SCAN_SEC.
        try:
            quick_best = get_cached_futures_tickers() or {}
            if quick_best:
                body, kb, _ = _screen_quick_ticker_snapshot_body(quick_best, scan_session)
                header = (
                    f"*PulseFutures — Market Scan*\n"
                    f"{HDR}\n"
                    f"*Session:* `{live_session}` | *{loc_label}:* `{loc_time}`\n"
                    f"{_screen_when_line('Ticker snapshot', time.time())}"
                    f"_Showing instant ticker snapshot while full executable scan warms up._\n"
                )
                await send_long_message(
                    update,
                    _screen_markdown_to_html((header + "\n" + body).strip()),
                    parse_mode=ParseMode.HTML,
                    disable_web_page_preview=True,
                )
                return
        except Exception:
            pass
        await update.message.reply_text("🔎 /screen cache is warming up. Fresh scan is queued in the dedicated screen lane — run /screen again shortly.")
        return
    except Exception as e:
        try:
            logger.warning("screen fast path failed; returning queued refresh message: %s", e)
        except Exception:
            pass
        try:
            _schedule_screen_cache_refresh(int(uid), str(scan_session_name_utc() or '').upper())
        except Exception:
            pass
        try:
            await update.message.reply_text("🔎 /screen snapshot is refreshing in the background. Commands remain responsive — run /screen again shortly.")
        except Exception:
            pass
        return

    # Legacy slow path below is kept only as unreachable fallback for old deployments;
    # current /screen returns above and must never block on OHLCV scans.
    # Avoid long scans blocking other commands on small instances
    if SCAN_LOCK.locked():
        try:
            scan_session = scan_session_name_utc()
            cache_key = f"uid:{int(uid)}::{str(scan_session or '').upper()}"
            cache_entry = _SCREEN_CACHE.get(cache_key) or {}
            age = time.time() - float(cache_entry.get('ts', 0.0) or 0.0)
            if cache_entry.get('body') and age <= float(SCREEN_STALE_CACHE_MAX_SEC):
                loc_label, loc_time = user_location_and_time(user)
                live_session = current_session_utc()
                header = (
                    f"*PulseFutures — Market Scan*\n"
                    f"{HDR}\n"
                    f"*Session:* `{live_session}` | *{loc_label}:* `{loc_time}`\n"
                    f"_Showing recent cached scan while a fresh scan is still running._\n"
                )
                keyboard = [
                    [InlineKeyboardButton(text=f"📈 {sym} • {sid}", url=tv_chart_url(sym))]
                    for (sym, sid) in (cache_entry.get('kb') or [])
                ]
                await send_long_message(
                    update,
                    _screen_markdown_to_html((header + "\n" + str(cache_entry.get('body') or '')).strip()),
                    parse_mode=ParseMode.HTML,
                    disable_web_page_preview=True,
                    reply_markup=InlineKeyboardMarkup(keyboard) if keyboard else None,
                )
                return
        except Exception:
            pass
        await update.message.reply_text("⏳ Scan is running… please try /screen again in a moment.")
        return

    await SCAN_LOCK.acquire()
    try:
        # Send immediate response (fast perceived UX)
        status_msg = await update.message.reply_text("🔎 Scanning market… Please wait")

        # Compute header/session without hitting the exchange first.
        uid = update.effective_user.id
        user = get_user(uid)
        live_session = current_session_utc()
        scan_session = scan_session_name_utc()
        loc_label, loc_time = user_location_and_time(user)
        cache_key = f"uid:{int(uid)}::{str(scan_session or '').upper()}"
        now_ts = time.time()
        cache_entry = _SCREEN_CACHE.get(cache_key) or {}
        if (cache_entry.get("body") and (now_ts - float(cache_entry.get("ts", 0.0)) <= float(SCREEN_CACHE_TTL_SEC))):
            header = (
                f"*PulseFutures — Market Scan*\n"
                f"{HDR}\n"
                f"*Session:* `{live_session}` | *{loc_label}:* `{loc_time}`\n"
                f"_Showing recent cached scan for faster response._\n"
            )
            keyboard = [
                [InlineKeyboardButton(text=f"📈 {sym} • {sid}", url=tv_chart_url(sym))]
                for (sym, sid) in (cache_entry.get("kb") or [])
            ]
            try:
                await status_msg.delete()
            except Exception:
                pass
            await send_long_message(
                update,
                _screen_markdown_to_html((header + "\n" + str(cache_entry.get("body") or "")).strip()),
                parse_mode=ParseMode.HTML,
                disable_web_page_preview=True,
                reply_markup=InlineKeyboardMarkup(keyboard) if keyboard else None,
            )
            return

        reset_reject_tracker()

        best_fut = await to_thread_heavy(_screen_best_fut_fast, timeout=10)
        if not best_fut:
            await status_msg.edit_text("❌ Failed to fetch futures data.")
            return

        # Header (always fresh)
        uid = update.effective_user.id
        user = get_user(uid)
        live_session = current_session_utc()
        scan_session = scan_session_name_utc()
        loc_label, loc_time = user_location_and_time(user)

        header = (
            f"*PulseFutures — Market Scan*\n"
            f"{HDR}\n"
            f"*Session:* `{live_session}` | *{loc_label}:* `{loc_time}`\n"
        )
        if live_session == "NONE":
            header += "_Outside live session window. Manual scan shown for reference only._\n"

        now_ts = time.time()
        cache_key = f"uid:{int(uid)}::{str(scan_session or '').upper()}"
        cache_entry = _SCREEN_CACHE.get(cache_key) or {}

        # ------------- FAST PATH (cache hit) -------------
        cached_body = ""
        cached_kb = []
        if (cache_entry.get("body") and (now_ts - float(cache_entry.get("ts", 0.0)) <= float(SCREEN_CACHE_TTL_SEC))):
            cached_body = str(cache_entry.get("body") or "")
            cached_kb = list(cache_entry.get("kb") or [])

            msg = _screen_markdown_to_html((header + "\n" + cached_body).strip())

            keyboard = [
                [InlineKeyboardButton(text=f"📈 {sym} • {sid}", url=tv_chart_url(sym))]
                for (sym, sid) in (cached_kb or [])
            ]

            try:
                await status_msg.delete()
            except Exception:
                pass

            await send_long_message(
                update,
                msg,
                parse_mode=ParseMode.HTML,
                disable_web_page_preview=True,
                reply_markup=InlineKeyboardMarkup(keyboard) if keyboard else None,
            )
            return

        # ------------- SLOW PATH (build once under lock) -------------
        async with _SCREEN_LOCK:
            # Re-check cache after waiting for lock (another request may have filled it)
            now_ts = time.time()
            cache_entry = _SCREEN_CACHE.get(cache_key) or {}
            if (cache_entry.get("body") and (now_ts - float(cache_entry.get("ts", 0.0)) <= float(SCREEN_CACHE_TTL_SEC))):
                cached_body = str(cache_entry.get("body") or "")
                cached_kb = list(cache_entry.get("kb") or [])

                msg = _screen_markdown_to_html((header + "\n" + cached_body).strip())
                keyboard = [
                    [InlineKeyboardButton(text=f"📈 {sym} • {sid}", url=tv_chart_url(sym))]
                    for (sym, sid) in (cached_kb or [])
                ]

                try:
                    await status_msg.delete()
                except Exception:
                    pass

                await send_long_message(
                    update,
                    msg,
                    parse_mode=ParseMode.HTML,
                    disable_web_page_preview=True,
                    reply_markup=InlineKeyboardMarkup(keyboard) if keyboard else None,
                )
                return


            # Heavy build MUST NOT run on the asyncio event loop.
            # Only /screen is allowed to take longer; everything here runs in a worker thread.
            body, kb, shown_setups = await to_thread_screen(
                _build_screen_body_and_kb,
                best_fut,
                scan_session,
                int(update.effective_user.id),
                timeout=45,
            )

            # /screen now renders from the executable lane. After the message is sent,
            # the same shown setups may be synced into the normal email/autotrade flow
            # subject to the user's runtime email/session/cap configuration.

            # Cache for fast subsequent /screen calls (user + session scoped)
            _screen_cache_put(cache_key, body, list(kb or []), ts=time.time())


        # Send final
        cache_entry = _SCREEN_CACHE.get(cache_key) or {}
        msg = _screen_markdown_to_html((header + "\n" + str(cache_entry.get("body") or "")).strip())
        keyboard = [
            [InlineKeyboardButton(text=f"📈 {sym} • {sid}", url=tv_chart_url(sym))]
            for (sym, sid) in (cache_entry.get("kb") or [])
        ]

        try:
            await status_msg.delete()
        except Exception:
            pass

        await send_long_message(
            update,
            msg,
            parse_mode=ParseMode.HTML,
            disable_web_page_preview=True,
            reply_markup=InlineKeyboardMarkup(keyboard) if keyboard else None,
        )

        if MANUAL_SCREEN_SYNC_ENABLED and shown_setups:
            try:
                async def _run_screen_sync_once():
                    try:
                        res = await _screen_sync_pipeline_async(
                            int(uid),
                            dict(user or {}),
                            str(live_session or ''),
                            str(scan_session or ''),
                            best_fut,
                            list(shown_setups or []),
                        )
                        try:
                            logger.info(
                                "screen_sync uid=%s status=%s reason=%s",
                                uid,
                                str((res or {}).get('status') or ''),
                                str((res or {}).get('reason') or ''),
                            )
                        except Exception:
                            pass
                    except Exception as sync_e:
                        try:
                            logger.warning("screen_sync failed uid=%s: %s", uid, sync_e)
                        except Exception:
                            pass
                _safe_create_task(_run_screen_sync_once(), 'screen_sync_once')
            except Exception:
                pass

    except Exception as e:
        logger.exception("screen_cmd failed")
        try:
            await update.message.reply_text(f"❌ /screen failed: {e}")
        except Exception:
            pass



# =========================================================
# TEXT ROUTER (Signal ID lookup)
# =========================================================
    finally:
        try:
            if SCAN_LOCK.locked():
                SCAN_LOCK.release()
        except Exception:
            pass


async def text_router(update: Update, context: ContextTypes.DEFAULT_TYPE):
    text = (update.message.text or "").strip()
    if text.startswith("PF-"):
        sig = db_get_signal(text) or _recent_screen_signal_lookup(text)
        if not sig:
            await update.message.reply_text("Signal ID not found.")
            return

        tp_val = _resolve_single_tp(float(sig.get('entry') or 0.0), float(sig.get('sl') or 0.0), sig.get('tp'), sig.get('alt_target_a'), sig.get('alt_target_b'), str(sig.get('side') or ''))
        tps = f"TP {fmt_price(float(tp_val or 0.0))}"

        rr3 = rr_to_tp(float(sig["entry"]), float(sig["sl"]), float(tp_val or 0.0))

        await update.message.reply_text(
            f"🔎 Signal {sig['setup_id']}\n"
            f"{sig['side']} {sig['symbol']} — Conf {sig['conf']}/100\n"
            f"Entry {fmt_price(float(sig['entry']))} | SL {fmt_price(float(sig['sl']))}\n"
            f"{tps}\n"
            f"RR(TP): {rr_to_tp(float(sig['entry']), float(sig['sl']), float(tp_val or 0.0)):.2f}\n"
            f"Chart: {tv_chart_url(sig['symbol'])}\n\n"
            f"To journal it:\n"
            f"/trade_open {sig['symbol']} {'long' if sig['side']=='BUY' else 'short'} entry {sig['entry']} sl {sig['sl']} risk usd 40 sig {sig['setup_id']}"
        )
        return

