def _smtp_error_probably_delivered(err: str) -> bool:
    """SMTP can time out/disconnect after DATA is accepted. Treat those as soft-delivered.

    This is deliberately limited to late-SMTP/read/connection-close signatures; config,
    recipient, auth and TLS/login errors are still hard failures.
    """
    try:
        e = str(err or '').lower()
        if not e:
            return False
        hard = ('auth', 'login', 'authentication', 'recipient', 'no_recipient', 'not configured', 'missing smtp', 'invalid email')
        if any(h in e for h in hard):
            return False
        soft = (
            'smtpserverdisconnected', 'connection unexpectedly closed', 'read operation timed out',
            'timed out', 'timeout_after_', 'timeout after', 'network is unreachable',
            'connection reset', 'broken pipe', 'server disconnected'
        )
        return any(x in e for x in soft)
    except Exception:
        return False


def _email_assume_sent_on_soft_smtp() -> bool:
    try:
        return str(os.environ.get('EMAIL_ASSUME_SENT_ON_SOFT_SMTP', '1')).strip().lower() not in {'0','false','no','off'}
    except Exception:
        return True


def _record_setup_email_delivery_side_effects(user_id: int, session_name: str, setups: list, best_fut: dict | None = None, status: str = 'sent') -> int:
    """Mirror a setup-email delivery into DB/cache/executable lane.

    Used both for confirmed SMTP success and for late-SMTP soft timeouts where the
    email is often delivered but the server disconnects before acknowledgement.
    """
    try:
        uid = int(user_id or 0)
        if uid <= 0 or not setups:
            return 0
        sess_u = str(session_name or '').upper().strip()
        now_ts = time.time()
        try:
            owner_uid = int(AUTOTRADE_OWNER_UID or 0)
        except Exception:
            owner_uid = 0
        target_uids = [uid]
        try:
            if owner_uid > 0 and owner_uid not in target_uids and is_admin_user(uid):
                target_uids.append(owner_uid)
        except Exception:
            pass
        n = 0
        for s in list(setups or []):
            try:
                db_insert_signal(s, user_id=uid)
            except Exception:
                pass
            try:
                setattr(s, 'email_logged_ts', float(now_ts))
                setattr(s, 'emailed_ts', float(now_ts))
                setattr(s, 'source_kind', 'emailed_setups')
                setattr(s, 'source_session', sess_u)
                setattr(s, 'delivery_lane_locked', True)
            except Exception:
                pass
            sid = str(getattr(s, 'setup_id', '') or getattr(s, 'id', '') or '').strip()
            if not sid:
                continue
            for tuid in target_uids:
                try:
                    db_mark_emailed_setup(int(tuid), sid, sess_u, now_ts)
                except Exception:
                    pass
                try:
                    db_mark_executable_setup(int(tuid), sid, sess_u, now_ts, s=s, source_kind='emailed_setups', state='executable_pending')
                except Exception:
                    pass
                try:
                    db_log_generated_setup(int(tuid), 'email', sess_u, s)
                except Exception:
                    pass
                try:
                    _cache_recent_emailed_setup(int(tuid), s, session=sess_u, emailed_ts=now_ts, source_kind='recent_email_cache')
                except Exception:
                    pass
                try:
                    _mark_emailed_setup_identity(int(tuid), s, emailed_ts=now_ts)
                except Exception:
                    pass
            n += 1
        # Keep /screen aligned to the exact email batch.
        try:
            up_list, dn_list = compute_directional_lists(best_fut or {})
            market_txt = _screen_market_context_table(best_fut or {}, leaders=up_list, losers=dn_list)
            for tuid in target_uids:
                screen_body = "\n".join([
                    "", "*Top Trade Setups*", SEP,
                    "_Showing latest sent setup email while the live scan refreshes._",
                    _screen_format_setup_cards(list(setups or []), int(tuid), sess_u),
                    "", market_txt or "",
                ]).strip()
                screen_kb = [(str(getattr(_s, 'symbol', '') or '').upper(), str(getattr(_s, 'setup_id', '') or getattr(_s, 'id', '') or '')) for _s in list(setups or [])[:_screen_display_limit()]]
                _screen_cache_put(f"uid:{int(tuid)}::{sess_u}", screen_body, screen_kb, ts=now_ts, allow_empty_overwrite=True)
        except Exception:
            pass
        try:
            db_log_setup_pipeline_event(uid, stage='email_delivery_side_effects', status=str(status or 'sent'), session=sess_u, mode='email', details={'setups': n})
        except Exception:
            pass
        return n
    except Exception:
        return 0


def _setup_email_presend_executable_filter(user_id: int, session_name: str, setups: list, lane: str = 'email') -> tuple[list, Counter]:
    """Return only setup rows that can be both emailed and autotrade-consumed.

    Ver46: the last loop came from BigMove/setup-email delivery accepting rows that
    AutoTrade later rejected with final_* / micro-edge reasons.  This helper is the
    single pre-send guard used by normal setup emails, BigMove/F8 setup emails and the
    immediate after-email AutoTrade trigger.  It routes NORMAL/REVERSE first and then
    runs the exact executable gate that AutoTrade uses.
    """
    reasons = Counter()
    out = []
    try:
        uid = int(user_id or 0)
    except Exception:
        uid = 0
    try:
        owner_uid = int(globals().get('AUTOTRADE_OWNER_UID', 0) or 0)
    except Exception:
        owner_uid = 0
    # Use the owner evidence when the email recipient is the live owner/admin, because
    # AutoTrade consumes the owner lane. This keeps email, /screen and AT decisions synced.
    try:
        gate_uid = owner_uid if owner_uid > 0 and (uid == owner_uid or is_admin_user(uid)) else uid
    except Exception:
        gate_uid = owner_uid or uid
    sess = str(session_name or '').upper().strip()
    if sess not in {'ASIA', 'LON', 'NY'}:
        sess = str(session_name or '').upper().strip()
    seen = set()
    for raw in list(setups or []):
        try:
            eff = _setup_route_candidate_for_executable_lane(raw, sess, int(gate_uid or uid or 0))
            try:
                setattr(eff, 'source_session', sess)
                if not getattr(eff, 'session', None):
                    setattr(eff, 'session', sess)
            except Exception:
                pass
            sym = str(getattr(eff, 'symbol', '') or '').upper().strip()
            side = str(getattr(eff, 'side', '') or '').upper().strip()
            sid = str(getattr(eff, 'setup_id', '') or getattr(eff, 'id', '') or '').strip()
            try:
                key = (sid or sym, side, round(float(getattr(eff, 'entry', 0.0) or 0.0), 8), round(float(getattr(eff, 'sl', 0.0) or 0.0), 8), round(float(_setup_target_tp(eff, 0.0) or 0.0), 8))
            except Exception:
                key = (sid or sym, side)
            if key in seen:
                continue
            seen.add(key)
            ok, why = is_executable_setup_eligible(eff, session_name=sess)
            if not ok:
                reasons[str(why or 'not_executable')] += 1
                try:
                    db_log_setup_pipeline_event(int(uid or 0), stage='setup_email_presend_gate', status='skip', session=sess, mode=str(lane or 'email'), setup_id=sid, symbol=sym, side=side, details={'reason': str(why or 'not_executable'), 'gate_uid': int(gate_uid or 0)})
                except Exception:
                    pass
                continue
            keep_ok, keep_why, keep_meta = _setup_user_visible_keep_policy_allows(eff, session_name=sess, user_id=int(gate_uid or uid or 0), lane=str(lane or 'email'))
            if not keep_ok:
                reasons[str(keep_why or 'email_policy_not_keep')] += 1
                try:
                    db_log_setup_pipeline_event(int(uid or 0), stage='setup_email_keep_policy_gate', status='skip', session=sess, mode=str(lane or 'email'), setup_id=sid, symbol=sym, side=side, details={'reason': str(keep_why or 'email_policy_not_keep'), 'gate_uid': int(gate_uid or 0), 'policy': keep_meta})
                except Exception:
                    pass
                continue
            out.append(eff)
        except Exception as exc:
            reasons[f'presend_gate_exception:{type(exc).__name__}'] += 1
            continue
    try:
        db_log_setup_pipeline_event(int(uid or 0), stage='setup_email_presend_gate', status='ok' if out else 'empty', session=sess, mode=str(lane or 'email'), details={'input': len(list(setups or [])), 'eligible': len(out), 'top_reasons': _pipeline_top_reasons(reasons, 8), 'gate_uid': int(gate_uid or 0)})
    except Exception:
        pass
    return list(out or []), reasons

def send_email_alert_multi(user: dict, sess: dict, setups: List[Setup], best_fut) -> bool:
    """
    One email containing multiple setups.
    Requires _email_body_pretty(...) and send_email(...).
    """
    if not setups:
        return False

    uid = int(user["user_id"])
    try:
        _blk, _blk_reason = _setup_generation_blackout_now()
        if _blk:
            try:
                db_log_setup_pipeline_event(int(uid), stage='setup_email_blackout', status='skip', session=str((sess or {}).get('name') or ''), mode='email', details={'reason': str(_blk_reason or 'setup_generation_blackout'), 'windows': _setup_generation_blackout_windows(), 'setups': len(setups or [])})
            except Exception:
                pass
            try:
                _LAST_EMAIL_DECISION[int(uid)] = {'status': 'SKIP', 'picked': '-', 'when': datetime.now(_zoneinfo_or_default((user or {}).get('tz'))[0]).isoformat(timespec='seconds'), 'reasons': [str(_blk_reason or 'setup_generation_blackout')]}
            except Exception:
                pass
            return False
    except Exception:
        pass
    tz, user_tz = _zoneinfo_or_default(user.get("tz") or user.get("timezone"))

    now_local = datetime.now(tz)

    # Display the *market* session (NY/LON/ASIA) in the email header.
    # 'UNLIMITED' is an access mode, not a market session.
    try:
        live_sess = current_session_utc(datetime.now(timezone.utc))
    except Exception:
        live_sess = "NONE"
    sess_name = str(sess.get("name") or "")
    display_session = (live_sess if live_sess != "NONE" else "NY") if sess_name == "UNLIMITED" else sess_name

    # Ver46: final sync guard.  Do not send a setup email unless the exact routed
    # setup can also enter the executable/AutoTrade lane now.  This prevents
    # /screen from showing an emailed setup that /autotrade_last immediately skips
    # for final_watch_micro_edge_block / weak symbol / policy reasons.
    try:
        _filtered, _filter_reasons = _setup_email_presend_executable_filter(int(uid), str(display_session or sess_name or ''), list(setups or []), lane='setup_email')
        if not _filtered:
            try:
                _LAST_EMAIL_DECISION[int(uid)] = {
                    'status': 'SKIP',
                    'picked': '-',
                    'when': datetime.now(tz).isoformat(timespec='seconds'),
                    'reasons': ['presend_executable_gate_empty', f"top_reasons={dict((_filter_reasons or Counter()).most_common(5))}"],
                }
            except Exception:
                pass
            return False
        setups = list(_filtered or [])
    except Exception as _pre_exc:
        try:
            _LAST_EMAIL_DECISION[int(uid)] = {
                'status': 'ERROR',
                'picked': '-',
                'when': datetime.now(tz).isoformat(timespec='seconds'),
                'reasons': [f'presend_executable_gate_exception:{type(_pre_exc).__name__}: {_pre_exc}'],
            }
        except Exception:
            pass
        return False

    first = setups[0]
    subject = f"PulseFutures • {display_session} • {first.side} {first.symbol}"
    if len(setups) > 1:
        subject += f" (+{len(setups)-1} more)"

    body = _email_body_pretty(
        session_name=str(display_session),
        now_local=now_local,
        user_tz=user_tz,
        setups=setups,
        best_fut=best_fut,
    )

    body_html = _email_body_pretty_html(
        session_name=str(display_session),
        now_local=now_local,
        user_tz=user_tz,
        setups=setups,
        best_fut=best_fut,
    )

    try:
        for s in setups:
            try:
                db_insert_signal(s, user_id=uid)
            except Exception:
                pass
    except Exception:
        pass

    try:
        sent = send_email(subject, body, user_id_for_debug=uid, body_html=body_html)
    except Exception as _smtp_exc:
        sent = False
        try:
            _LAST_SMTP_ERROR[uid] = f"{type(_smtp_exc).__name__}: {_smtp_exc}"
        except Exception:
            pass
        try:
            logger.warning("setup email send raised uid=%s subject=%s error=%s", uid, subject, _LAST_SMTP_ERROR.get(uid, ''))
        except Exception:
            pass
    if (not sent) and _email_assume_sent_on_soft_smtp() and _smtp_error_probably_delivered(str(_LAST_SMTP_ERROR.get(uid, ''))):
        try:
            logger.warning("setup email soft-delivered uid=%s subject=%s smtp_error=%s", uid, subject, _LAST_SMTP_ERROR.get(uid, ''))
        except Exception:
            pass
        try:
            _record_setup_email_delivery_side_effects(int(uid), str(display_session or ''), list(setups or []), best_fut or {}, status='soft_smtp_assumed_sent')
        except Exception:
            pass
        sent = True
    if sent:
        try:
            db_log_setup_pipeline_event(int(uid), stage='email_delivery', status='sent', session=str(display_session or ''), mode='email', details={'setups': len(setups or []), 'subject': str(subject or '')[:180]})
        except Exception:
            pass
        try:
            now_ts = time.time()
            try:
                owner_uid = int(AUTOTRADE_OWNER_UID or 0)
            except Exception:
                owner_uid = 0
            # IMPORTANT:
            # The email recipient uid and the autotrade owner uid can diverge in live admin setups
            # (for example, a current admin tester receives the email while AUTOTRADE_OWNER_UID points
            # to the dedicated owner record). Mirror the confirmed email/executable queue rows to the
            # owner uid so autotrade always consumes the same setup that was actually emailed.
            target_uids = [int(uid)]
            try:
                if owner_uid > 0 and int(owner_uid) not in target_uids and is_admin_user(int(uid)):
                    target_uids.append(int(owner_uid))
            except Exception:
                pass
            for s in setups:
                try:
                    setattr(s, 'email_logged_ts', float(now_ts))
                    setattr(s, 'emailed_ts', float(now_ts))
                    setattr(s, 'source_kind', 'emailed_setups')
                    setattr(s, 'source_session', str(display_session or ''))
                except Exception:
                    pass
                for _target_uid in target_uids:
                    try:
                        db_mark_emailed_setup(_target_uid, getattr(s, "setup_id", ""), str(display_session), now_ts)
                    except Exception:
                        pass
                    try:
                        # Re-assert the exact emailed setup into the executable lane so
                        # /screen and autotrade consume the same authoritative row even if
                        # an earlier pool-write was missed or a cache branch went stale.
                        db_mark_executable_setup(
                            int(_target_uid),
                            getattr(s, "setup_id", ""),
                            str(display_session),
                            float(now_ts),
                            s=s,
                            source_kind='emailed_setups',
                            state='executable_pending',
                        )
                    except Exception:
                        pass
                    try:
                        db_log_generated_setup(_target_uid, "email", str(display_session or ""), s)
                    except Exception:
                        pass
                    try:
                        _cache_recent_emailed_setup(int(_target_uid), s, session=str(display_session or ''), emailed_ts=float(now_ts), source_kind='recent_email_cache')
                    except Exception:
                        pass
                    try:
                        _mark_emailed_setup_identity(int(_target_uid), s, emailed_ts=float(now_ts))
                    except Exception:
                        pass
                try:
                    # Keep /screen immediately aligned with the exact setup email just sent.
                    up_list, dn_list = compute_directional_lists(best_fut or {})
                    market_txt = _screen_market_context_table(best_fut or {}, leaders=up_list, losers=dn_list)
                    screen_body = "\n".join([
                        "",
                        "*Top Trade Setups*",
                        SEP,
                        "_Showing latest sent setup email while the live scan refreshes._",
                        _screen_format_setup_cards(list(setups or []), int(_target_uid), str(display_session or '')),
                        "",
                        market_txt or "",
                    ]).strip()
                    screen_kb = [(str(getattr(_s, 'symbol', '') or '').upper(), str(getattr(_s, 'setup_id', '') or getattr(_s, 'id', '') or '')) for _s in list(setups or [])[:_screen_display_limit()]]
                    _screen_cache_put(f"uid:{int(_target_uid)}::{str(display_session or '').upper()}", screen_body, screen_kb, ts=float(now_ts), allow_empty_overwrite=True)
                except Exception:
                    pass
        except Exception:
            pass
    else:
        try:
            db_log_setup_pipeline_event(int(uid), stage='email_delivery', status='failed', session=str(display_session or ''), mode='email', details={'setups': len(setups or []), 'subject': str(subject or '')[:180], 'smtp_error': str(_LAST_SMTP_ERROR.get(uid, 'smtp_send_failed') or 'smtp_send_failed')})
        except Exception:
            pass
        try:
            for s in setups:
                try:
                    _admin_setup_lifecycle_merge(
                        int(uid),
                        str(getattr(s, 'setup_id', '') or ''),
                        session=str(display_session or ''),
                        symbol=str(getattr(s, 'symbol', '') or ''),
                        side=str(getattr(s, 'side', '') or ''),
                        state='email_failed',
                        last_reason='smtp_send_failed',
                    )
                except Exception:
                    pass
        except Exception:
            pass
    return sent




