async def _to_thread_with_timeout(fn, timeout_sec: int, *args, **kwargs):
    return await to_thread_email(fn, *args, timeout=timeout_sec, **kwargs)

def _run_coro_in_thread(coro):
    """Run an awaitable inside a dedicated event loop in a worker thread.

    Used when synchronous thread offloading needs the *result* of an async
    function (for example build_priority_pool inside /screen or the email loop).
    Keeps the main Telegram event loop non-blocking and avoids relying on any
    ambient loop existing inside the worker thread.
    """
    if not inspect.isawaitable(coro):
        return coro
    try:
        return asyncio.run(coro)
    except RuntimeError:
        loop = asyncio.new_event_loop()
        try:
            asyncio.set_event_loop(loop)
            return loop.run_until_complete(coro)
        finally:
            try:
                loop.run_until_complete(loop.shutdown_asyncgens())
            except Exception:
                pass
            asyncio.set_event_loop(None)
            loop.close()

async def _send_email_async(timeout_sec: int, *args, **kwargs) -> bool:
    """
    Runs send_email() in a worker thread with a hard timeout so SMTP/network stalls
    can't block the Telegram event loop (Render lag fix).
    """
    uid = None
    try:
        raw_uid = kwargs.get('user_id_for_debug', None)
        if raw_uid is not None:
            uid = int(raw_uid)
    except Exception:
        uid = None
    try:
        return bool(await _to_thread_with_timeout(send_email, timeout_sec, *args, **kwargs))
    except asyncio.TimeoutError:
        if uid is not None:
            err = f"async_email_timeout ({int(timeout_sec)}s)"
            try:
                _LAST_SMTP_ERROR[uid] = err
                _LAST_EMAIL_DECISION[uid] = {
                    "status": "FAIL",
                    "reasons": [err],
                    "when": datetime.now(timezone.utc).isoformat(timespec="seconds"),
                }
            except Exception:
                pass
        return False
    except Exception as e:
        if uid is not None:
            err = f"async_email_error ({type(e).__name__}: {e})"
            try:
                _LAST_SMTP_ERROR[uid] = err
                _LAST_EMAIL_DECISION[uid] = {
                    "status": "FAIL",
                    "reasons": [err],
                    "when": datetime.now(timezone.utc).isoformat(timespec="seconds"),
                }
            except Exception:
                pass
        return False


def _alert_job_limit(name: str, default: int) -> int:
    """Safe lookup for alert-job limits and cache windows."""
    try:
        val = globals().get(name, default)
        limit = int(val if val is not None else default)
        if 'BIGMOVE' in str(name or '').upper():
            return max(0, limit)
        return max(1, limit)
    except Exception:
        if 'BIGMOVE' in str(name or '').upper():
            return max(0, int(default))
        return max(1, int(default))

async def _alert_job_async_internal(context: ContextTypes.DEFAULT_TYPE):
    # Ver21: this autonomous pipeline is the source of truth for setup emails and
    # AutoTrade attempts. Manual /screen sync is only a backup/UX accelerator, not a
    # required trigger.
    try:
        db_log_setup_pipeline_event(0, stage='autonomous_setup_pipeline_tick', status='start', session=str(scan_session_name_utc(datetime.now(timezone.utc)) or ''), mode='email', details={'source': 'job_queue', 'screen_required': False})
    except Exception:
        pass
    # Prevent overlapping runs (JobQueue can overlap if a run is slow).
    # Do NOT skip the whole email loop because a user command ran recently or
    # a heavy optimizer/screen task is active. That silently starves emails for
    # a full session. Heavy scans are gated later; DB-lane consumption and
    # Big-Move pending confirmations must still run.
    if ALERT_LOCK.locked():
        return

    async with ALERT_LOCK:
        job_started_ts = time.time()

        def _job_budget_exhausted() -> bool:
            try:
                return (time.time() - job_started_ts) >= float(ALERT_JOB_MAX_RUNTIME_SEC or 55)
            except Exception:
                return False

        def _bigmove_session_reserve_hit() -> bool:
            try:
                if not users_notify:
                    return False
                max_runtime = max(1.0, float(ALERT_JOB_MAX_RUNTIME_SEC or 55))
                reserve_pct = max(0.05, min(0.90, float(ALERT_JOB_RESERVE_FOR_SESSION_POOLS_PCT or 0.45)))
                share_pct = max(0.10, min(0.95, float(ALERT_JOB_BIGMOVE_MAX_RUNTIME_SHARE_WITH_NOTIFY_PCT or 0.55)))
                allowed = min(max_runtime * share_pct, max_runtime * max(0.05, 1.0 - reserve_pct))
                return (time.time() - job_started_ts) >= max(5.0, allowed)
            except Exception:
                return False

        def _bigmove_deferred_budget_exhausted() -> bool:
            try:
                max_runtime = max(1.0, float(ALERT_JOB_MAX_RUNTIME_SEC or 55))
                grace = max(0.0, float(ALERT_JOB_BIGMOVE_DEFERRED_GRACE_SEC or 0))
                return (time.time() - job_started_ts) >= (max_runtime + grace)
            except Exception:
                return _job_budget_exhausted()

        deferred_bigmove_jobs = []

        # Keep it quiet if email is off or not configured
        if not EMAIL_ENABLED:
            return
        if not email_config_ok():
            return

        # Trade-signal emails may be notify_on-gated,
        # but Big-Move Alerts should go to anyone who has an email saved.

        try:
            users_notify = await to_thread_fast(list_users_notify_on, timeout=10)
        except Exception as e:
            logger.exception("list_users_notify_on failed: %s", e)
            users_notify = []

        try:
            users_bigmove = await to_thread_fast(list_users_with_email, timeout=10)
        except Exception as e:
            logger.exception("list_users_with_email failed: %s", e)
            users_bigmove = []

        # yver140: do not let a stale/long notify list silently remove the live owner
        # from the autonomous setup-email pool. Keep AUTOTRADE_OWNER_UID pinned first
        # so ALERT_JOB_NOTIFY_MAX_USERS slicing cannot cut it off.
        try:
            owner_uid_for_email = int(AUTOTRADE_OWNER_UID or 0)
        except Exception:
            owner_uid_for_email = 0
        try:
            if owner_uid_for_email > 0:
                ou = get_user(owner_uid_for_email) or {}
                if ou and str(ou.get('email_to') or ou.get('email') or '').strip():
                    users_notify = [u for u in list(users_notify or []) if int((u or {}).get('user_id') or (u or {}).get('id') or 0) != owner_uid_for_email]
                    users_notify.insert(0, ou)
        except Exception:
            pass

        if not users_notify and not users_bigmove:
            return
        if _job_budget_exhausted():
            return

        # TIMEOUT-PROTECTED fetch (prevents lock being held forever)
        try:
            best_fut = await _to_thread_with_timeout(fetch_futures_tickers, EMAIL_FETCH_TIMEOUT_SEC)
        except asyncio.TimeoutError:
            return
        except Exception:
            return

        if not best_fut:
            return

        try:
            goal_running = bool(_goal_profile_is_running())
        except Exception:
            goal_running = False

        # -----------------------------------------------------
        # Rule 2: Volume relative filter base line (killer rule)
        # -----------------------------------------------------
        _all_vols = []
        for _b, _mv in (best_fut or {}).items():
            try:
                _all_vols.append(float(getattr(_mv, "fut_vol_usd", 0.0) or 0.0))
            except Exception:
                pass
        MARKET_VOL_MEDIAN_USD = _median(_all_vols)

        def _build_bigmove_payload_for_user(uid: int, tz):
            try:
                uu = get_user(int(uid)) or {}
                # yver89: /bigmove_alert controls ONLY the market-event Big-Move alert email.
                # F8 setup generation must remain continuous so /setup_audit, setup email,
                # /screen, and AutoTrade stay synchronized with all other engines.
                on = int(uu.get("bigmove_alert_on", 1) or 0)

                try:
                    p15, p1, p4 = _user_bigmove_thresholds(uu)
                except Exception:
                    p15, p1, p4 = BIGMOVE_DEFAULT_15M_PCT, BIGMOVE_DEFAULT_1H_PCT, BIGMOVE_DEFAULT_4H_PCT

                try:
                    min_vol = _user_bigmove_min_vol_usd(uu, BIGMOVE_DEFAULT_MIN_VOL_USD)
                except Exception:
                    min_vol = BIGMOVE_DEFAULT_MIN_VOL_USD

                raw_candidates = _bigmove_candidates(best_fut, p15=p15, p1=p1, p4=p4, min_vol_usd=min_vol, max_items=12)
                candidates = list(raw_candidates or [])

                def _pick_pct(_mv, _keys) -> float:
                    for _k in _keys:
                        try:
                            _v = getattr(_mv, _k, None)
                            if _v is None:
                                continue
                            return float(_v or 0.0)
                        except Exception:
                            continue
                    return 0.0

                try:
                    bm_any_4h = sum(
                        1 for _sym, _mv in (best_fut or {}).items()
                        if abs(_pick_pct(_mv, ["ch4", "pct_4h", "change_4h", "chg_4h", "percentage_4h", "p4", "h4"])) >= float(p4)
                    )
                except Exception:
                    bm_any_4h = -1

                try:
                    bm_any_1h = sum(
                        1 for _sym, _mv in (best_fut or {}).items()
                        if abs(_pick_pct(_mv, ["ch1", "pct_1h", "change_1h", "chg_1h", "percentage_1h", "p1", "h1"])) >= float(p1)
                    )
                except Exception:
                    bm_any_1h = -1

                try:
                    bm_any_15m = sum(
                        1 for _sym, _mv in (best_fut or {}).items()
                        if abs(_pick_pct(_mv, ["ch15", "pct_15m", "change_15m", "chg_15m", "percentage_15m", "p15", "m15"])) >= float(p15)
                    )
                except Exception:
                    bm_any_15m = -1

                # Confirmation gate requested by admin: first criteria hit only stages the symbol.
                # Email is sent only after the next closed 15m candle closes in the same direction.
                confirm_stats = {}
                try:
                    candidates, confirm_stats = _bigmove_confirm_next_15m_for_user(int(uid), list(raw_candidates or []), p15, p1, p4, min_vol)
                except Exception:
                    candidates = list(raw_candidates or [])
                    confirm_stats = {"error": "confirmation_gate_exception"}

                if not candidates:
                    if BIGMOVE_CONFIRM_NEXT_15M_ENABLED and (raw_candidates or int((confirm_stats or {}).get('pending_checked') or 0) > 0 or int((confirm_stats or {}).get('pending_new') or 0) > 0 or int((confirm_stats or {}).get('pending_wait') or 0) > 0):
                        return {
                            "status": "SKIP",
                            "reasons": [
                                "waiting_for_next_15m_confirmation",
                                f"confirmation_stats={confirm_stats}",
                                f"raw_hits={bm_any_15m}/{bm_any_1h}/{bm_any_4h}",
                            ],
                        }
                    return {
                        "status": "SKIP",
                        "reasons": [
                            f"no_candidates (p15={p15}, p1={p1}, p4={p4})",
                            f"debug_raw_hits:15m={bm_any_15m},1h={bm_any_1h},4h={bm_any_4h}",
                            f"confirmation_stats={confirm_stats}",
                        ],
                    }

                filtered = []
                volume_filtered_out = 0
                cooldown_filtered_out = 0
                for c in candidates:
                    try:
                        vol = float(c.get("vol", 0.0) or 0.0)
                    except Exception:
                        vol = 0.0

                    if vol > 0.0 and vol < float(min_vol):
                        volume_filtered_out += 1
                        continue

                    try:
                        ch15 = float(c.get("ch15", 0.0) or 0.0)
                        ch4 = float(c.get("ch4", 0.0) or 0.0)
                        ch1 = float(c.get("ch1", 0.0) or 0.0)
                        if not ((ch15 > 0 and ch4 > 0 and ch1 > 0) or (ch15 < 0 and ch4 < 0 and ch1 < 0)):
                            c['suppression_reason'] = 'mismatch_direction_15m_1h_4h'
                            continue
                        if bigmove_recently_emailed(int(uid), c["symbol"], c["direction"]):
                            cooldown_filtered_out += 1
                            c['suppression_reason'] = 'bigmove_symbol_cooldown_active'
                            continue
                        filtered.append(c)
                    except Exception:
                        filtered.append(c)

                if not filtered:
                    return {
                        "status": "SKIP",
                        "reasons": [
                            f"no_candidates_after_filters (min_vol={min_vol/1e6:.1f}M)",
                            f"raw_candidates={len(candidates)}",
                            f"volume_filtered={int(volume_filtered_out)}",
                            f"cooldown_filtered={int(cooldown_filtered_out)}",
                            "suppression_reasons:mismatch_direction_15m_1h_4h,bigmove_symbol_cooldown_active",
                        ],
                    }

                lines = []
                lines.append("⚡ PulseFutures — BIG MOVE ALERT")
                lines.append(HDR)
                lines.append(f"Triggers: |15m| ≥ {p15:.1f}% AND |1H| ≥ {p1:.1f}% AND |4H| ≥ {p4:.1f}% (same direction only)")
                if BIGMOVE_CONFIRM_NEXT_15M_ENABLED:
                    lines.append("Confirmation: next closed 15m candle also closed in the same direction")
                lines.append(f"Min Vol (24H): {min_vol/1e6:.1f}M")
                lines.append("")

                top = filtered[0]
                top_sym = top["symbol"]
                top_dir = "UP" if top.get("direction") == "UP" else "DOWN"
                # For confirmed big-move emails, the displayed 15m value must be the
                # confirmation candle move, not the original rolling trigger move.
                top_ch15_trigger = float(top.get("ch15", 0.0) or 0.0)
                top_ch15_display = float(top.get("confirm_15m_pct", top_ch15_trigger) or 0.0)
                top_ch1 = float(top.get("ch1", 0.0) or 0.0)
                top_ch4 = float(top.get("ch4", 0.0) or 0.0)
                # Alert headline must show the confirmation candle move only.
                # 1H/4H remain in the body as trigger context; they are not the
                # post-stage confirmation value.
                top_tf = "Confirm15m"
                top_move = top_ch15_display

                subject = f"⚡ Big Move Alert • {top_sym} {top_dir} • Confirm15m {top_move:+.1f}%"
                if len(filtered) > 1:
                    subject += f" (+{len(filtered)-1} more)"

                for c in filtered[:8]:
                    sym = c["symbol"]
                    ch15_trigger = float(c.get("ch15", 0.0) or 0.0)
                    ch15_display = float(c.get("confirm_15m_pct", ch15_trigger) or 0.0)
                    ch4 = float(c.get("ch4", 0.0) or 0.0)
                    ch1 = float(c.get("ch1", 0.0) or 0.0)
                    vol = float(c.get("vol", 0.0) or 0.0)
                    arrow = "🟢" if c.get("direction") == "UP" else "🔴"
                    confirm_dot = "🟢" if c.get("direction") == "UP" else "🔴"
                    lines.append(f"{arrow} {sym}: 15m confirmation: {confirm_dot} | 15m: {ch15_display:+.1f}% | 1H {ch1:+.1f}% | 4H {ch4:+.1f}% | Vol ~{vol/1e6:.1f}M")
                    lines.append(f"Chart: https://www.tradingview.com/chart/?symbol=BYBIT:{sym}USDT.P")
                    lines.append("")

                body = "\n".join(lines).strip()
                return {
                    "status": "READY",
                    "subject": str(subject or ""),
                    "body": str(body or ""),
                    "filtered": list(filtered or []),
                    "top_sym": str(top_sym or ""),
                    "top_dir": str(top_dir or ""),
                    "top_tf": str(top_tf or ""),
                    "top_move": float(top_move or 0.0),
                    "reasons": [
                        f"candidates={len(filtered)}",
                        f"top={top_sym}:{top_dir}:{top_tf}{top_move:+.2f}%",
                        f"p15={p15}",
                        f"p1={p1}",
                        f"p4={p4}",
                        f"min_vol={min_vol}",
                        f"volume_filtered={int(volume_filtered_out)}",
                        f"cooldown_filtered={int(cooldown_filtered_out)}",
                    ],
                }
            except Exception as e:
                return {"status": "ERROR", "reasons": [f"{type(e).__name__}: {e}"]}


        async def _record_bigmove_email_delivery_side_effects(uid: int, session_name: str, filtered: list, best_fut_snapshot: dict | None = None, tag: str = 'bigmove') -> list:
            """Mirror confirmed Big-Move alert email into setup/executable/screen lanes.

            Big-Move alert emails are independent from the normal setup-email builder, but
            operationally they must still create F8 setup rows so /screen, /setup_audit,
            /autotrade_last, and AutoTrade all see the exact same opportunity.
            """
            try:
                owner_uid = int(AUTOTRADE_OWNER_UID or 0)
            except Exception:
                owner_uid = 0
            sess_u = str(session_name or _bigmove_autotrade_session_name()).upper().strip()
            if sess_u not in {'ASIA', 'LON', 'NY'}:
                sess_u = _bigmove_autotrade_session_name()
            setups = []
            try:
                setups = await to_thread_autotrade(_bigmove_candidates_to_autotrade_setups, list(filtered or []), best_fut_snapshot or {}, sess_u, timeout=8)
            except Exception as exc:
                try:
                    db_log_setup_pipeline_event(int(uid), stage='bigmove_setup_build', status='error', session=sess_u, mode='bigmove', details={'error': f'{type(exc).__name__}: {exc}', 'tag': str(tag or '')})
                except Exception:
                    pass
                setups = []
            if not setups:
                try:
                    db_log_setup_pipeline_event(int(uid), stage='bigmove_setup_build', status='empty', session=sess_u, mode='bigmove', details={'candidates': len(filtered or []), 'tag': str(tag or '')})
                except Exception:
                    pass
                return []
            now_ts = float(time.time())
            target_uids = []
            for tu in (int(uid or 0), owner_uid):
                try:
                    if int(tu) > 0 and int(tu) not in target_uids:
                        target_uids.append(int(tu))
                except Exception:
                    pass
            for stp in list(setups or []):
                try:
                    setattr(stp, 'email_logged_ts', now_ts)
                    setattr(stp, 'emailed_ts', now_ts)
                    setattr(stp, 'source_kind', 'emailed_setups')
                    setattr(stp, 'source_session', sess_u)
                    setattr(stp, 'created_ts', float(getattr(stp, 'created_ts', 0.0) or now_ts))
                except Exception:
                    pass
            for tuid in target_uids:
                try:
                    _persist_executable_candidates(int(tuid), sess_u, list(setups or []), source_kind='emailed_setups', mode='bigmove_email')
                except Exception:
                    pass
                for stp in list(setups or []):
                    sid = str(getattr(stp, 'setup_id', '') or getattr(stp, 'id', '') or '')
                    try:
                        db_mark_emailed_setup(int(tuid), sid, sess_u, now_ts)
                    except Exception:
                        pass
                    try:
                        db_mark_executable_setup(int(tuid), sid, sess_u, now_ts, s=stp, source_kind='emailed_setups', state='executable_pending')
                    except Exception:
                        pass
                    try:
                        db_log_generated_setup(int(tuid), 'bigmove_email', sess_u, stp)
                    except Exception:
                        pass
                    try:
                        _cache_recent_emailed_setup(int(tuid), stp, session=sess_u, emailed_ts=now_ts, source_kind='recent_email_cache')
                    except Exception:
                        pass
                    try:
                        _mark_emailed_setup_identity(int(tuid), stp, emailed_ts=now_ts)
                    except Exception:
                        pass
                try:
                    up_list, dn_list = compute_directional_lists(best_fut_snapshot or {})
                    market_txt = _screen_market_context_table(best_fut_snapshot or {}, leaders=up_list, losers=dn_list)
                    screen_body = "\n".join([
                        "", "*Top Trade Setups*", SEP,
                        "_Showing latest Big-Move/F8 setup email while the live scan refreshes._",
                        _screen_format_setup_cards(list(setups or []), int(tuid), sess_u),
                        "", market_txt or "",
                    ]).strip()
                    screen_kb = [(str(getattr(_s, 'symbol', '') or '').upper(), str(getattr(_s, 'setup_id', '') or getattr(_s, 'id', '') or '')) for _s in list(setups or [])[:_screen_display_limit()]]
                    _screen_cache_put(f"uid:{int(tuid)}::{sess_u}", screen_body, screen_kb, ts=now_ts, allow_empty_overwrite=True)
                except Exception:
                    pass
                try:
                    cache_delete(f"autotrade_db_setups:{int(tuid)}:{sess_u}:12:5")
                except Exception:
                    pass
            try:
                db_log_setup_pipeline_event(int(uid), stage='bigmove_email_delivery_side_effects', status='ok', session=sess_u, mode='bigmove', details={'setups': len(setups or []), 'target_uids': target_uids, 'tag': str(tag or '')})
            except Exception:
                pass
            return list(setups or [])

        async def _send_bigmove_setup_email_after_alert(uid: int, session_name: str, filtered: list, best_fut_snapshot: dict | None = None, tag: str = 'bigmove') -> tuple[list, bool]:
            """Build and send the normal setup email for confirmed BigMove/F8 alerts.

            A Big-Move alert is only the market-event notification. The matching F8 setup
            must also enter the same setup-email/executable/screen lane as normal setups.
            This helper sends that setup email and lets send_email_alert_multi stamp
            emailed_ts/email_logged_ts, so /screen shows the SETUP email time rather than
            the earlier Big-Move alert email time.
            """
            sess_u = str(session_name or _bigmove_autotrade_session_name()).upper().strip()
            if sess_u not in {'ASIA', 'LON', 'NY'}:
                sess_u = _bigmove_autotrade_session_name()
            try:
                setups = await to_thread_autotrade(
                    _bigmove_candidates_to_autotrade_setups,
                    list(filtered or []),
                    best_fut_snapshot or {},
                    sess_u,
                    timeout=12,
                )
            except Exception as exc:
                try:
                    db_log_setup_pipeline_event(int(uid), stage='bigmove_setup_email_build', status='error', session=sess_u, mode='bigmove_setup_email', details={'error': f'{type(exc).__name__}: {exc}', 'tag': str(tag or '')})
                except Exception:
                    pass
                return [], False

            if not setups:
                try:
                    db_log_setup_pipeline_event(int(uid), stage='bigmove_setup_email_build', status='empty', session=sess_u, mode='bigmove_setup_email', details={'candidates': len(filtered or []), 'tag': str(tag or '')})
                except Exception:
                    pass
                return [], False

            # Stabilise metadata before sending. send_email_alert_multi will set the final
            # emailed timestamp after SMTP succeeds/soft-succeeds.
            for stp in list(setups or []):
                try:
                    setattr(stp, 'source_kind', 'emailed_setups')
                    setattr(stp, 'source_session', sess_u)
                    setattr(stp, 'bigmove_alert_tag', str(tag or 'bigmove'))
                    setattr(stp, 'family_id', BIGMOVE_FAMILY_ID)
                    setattr(stp, 'family_name', BIGMOVE_FAMILY_NAME)
                    setattr(stp, 'engine', 'F8')
                except Exception:
                    pass

            # yver89: log every built F8 BigMove candidate into generated_setups BEFORE
            # the setup-email/AutoTrade KEEP gate.  This makes /setup_audit the source
            # of truth for both KEEP and NOT_KEEP/WATCH F8 outcomes, instead of having
            # raw BigMove candidates appear only in /autotrade_last.
            try:
                _owner_uid_for_bm = int(AUTOTRADE_OWNER_UID or 0)
            except Exception:
                _owner_uid_for_bm = 0
            try:
                _raw_targets = []
                for _tu in (int(uid or 0), _owner_uid_for_bm):
                    try:
                        if int(_tu) > 0 and int(_tu) not in _raw_targets:
                            _raw_targets.append(int(_tu))
                    except Exception:
                        pass
                for _tu in list(_raw_targets or []):
                    for _stp in list(setups or []):
                        try:
                            db_log_generated_setup(int(_tu), 'bigmove_f8', sess_u, _stp)
                        except Exception:
                            pass
                try:
                    db_log_setup_pipeline_event(int(uid), stage='bigmove_f8_raw_generation_logged', status='ok', session=sess_u, mode='bigmove_setup_email', details={'setups': len(setups or []), 'target_uids': _raw_targets, 'tag': str(tag or '')})
                except Exception:
                    pass
            except Exception:
                pass

            # Ver46: BigMove/F8 setup emails must obey the same executable gate as
            # normal setup emails and AutoTrade.  The market-event BigMove alert may
            # still be sent independently, but the tradable F8 setup email is blocked
            # if the final gate/micro-edge guard would reject it.
            try:
                setups, _bm_gate_reasons = _setup_email_presend_executable_filter(int(uid), sess_u, list(setups or []), lane='bigmove_setup_email')
            except Exception:
                setups, _bm_gate_reasons = [], Counter({'bigmove_presend_gate_exception': 1})
            if not setups:
                try:
                    db_log_setup_pipeline_event(int(uid), stage='bigmove_setup_email_presend_gate', status='empty', session=sess_u, mode='bigmove_setup_email', details={'tag': str(tag or ''), 'top_reasons': _pipeline_top_reasons(_bm_gate_reasons, 8)})
                except Exception:
                    pass
                return [], False

            try:
                user_for_email = get_user(int(uid)) or {'user_id': int(uid), 'tz': _default_user_tz_name()}
            except Exception:
                user_for_email = {'user_id': int(uid), 'tz': _default_user_tz_name()}
            try:
                user_for_email['user_id'] = int(uid)
            except Exception:
                pass

            sent_setup_email = False
            try:
                sent_setup_email = await to_thread_email(
                    send_email_alert_multi,
                    user_for_email,
                    {'name': sess_u},
                    list(setups or []),
                    best_fut_snapshot or {},
                    timeout=int(EMAIL_SEND_TIMEOUT_SEC) + 8,
                )
            except asyncio.TimeoutError:
                try:
                    _LAST_SMTP_ERROR[int(uid)] = f'bigmove_setup_email_timeout_after_{int(EMAIL_SEND_TIMEOUT_SEC)}s'
                except Exception:
                    pass
                sent_setup_email = False
            except Exception as exc:
                try:
                    _LAST_SMTP_ERROR[int(uid)] = f'bigmove_setup_email_{type(exc).__name__}: {exc}'
                except Exception:
                    pass
                sent_setup_email = False

            try:
                db_log_setup_pipeline_event(
                    int(uid),
                    stage='bigmove_setup_email_delivery',
                    status='sent' if sent_setup_email else 'failed',
                    session=sess_u,
                    mode='bigmove_setup_email',
                    details={'setups': len(setups or []), 'tag': str(tag or ''), 'smtp_error': str(_LAST_SMTP_ERROR.get(int(uid), '') or '')[:240]},
                )
            except Exception:
                pass

            # Keep /email_decision honest: it should show the setup email outcome too.
            try:
                _LAST_EMAIL_DECISION[int(uid)] = {
                    'status': 'SENT' if sent_setup_email else 'ERROR',
                    'picked': ', '.join([f"{getattr(s, 'side', '')} {getattr(s, 'symbol', '')} conf={getattr(s, 'conf', '')} F8" for s in list(setups or [])[:8]]),
                    'when': datetime.now(_zoneinfo_or_default((get_user(int(uid)) or {}).get('tz'))[0]).isoformat(timespec='seconds'),
                    'reasons': ['bigmove_alert_generated_f8_setup_email'] if sent_setup_email else ['bigmove_alert_setup_email_failed', str(_LAST_SMTP_ERROR.get(int(uid), '') or '')[:160]],
                }
                if sent_setup_email:
                    _LAST_EMAIL_SENT[int(uid)] = dict(_LAST_EMAIL_DECISION[int(uid)])
            except Exception:
                pass
            return list(setups or []), bool(sent_setup_email)

        async def _send_bigmove_payload_for_user(uid: int, tz, tag: str = 'pre_session') -> None:
            """Build/process one user's confirmed Big-Move event.

            yver89 contract:
            - /bigmove_alert ON/OFF controls only the market-event alert email.
            - F8 setup generation runs continuously and uses the same setup-email,
              /screen, /setup_audit, and AutoTrade lane as every other engine.
            - AutoTrade may only consume the gated F8 setup-email list, never the raw
              BigMove alert candidate list.  This removes NOT_KEEP-only AutoTrade
              attempts that had no matching /setup_audit/setup-email row.
            """
            try:
                payload_timeout = max(20, int(BIGMOVE_PAYLOAD_TIMEOUT_SEC or 60))
                try:
                    payload = await to_thread_email(_build_bigmove_payload_for_user, int(uid), tz, timeout=payload_timeout)
                except asyncio.TimeoutError:
                    payload = {"status": "SKIP", "reasons": [f"bigmove_payload_timeout>{payload_timeout}s"]}
                pstatus = str((payload or {}).get('status') or '').upper().strip()
                if pstatus != 'READY':
                    _LAST_BIGMOVE_DECISION[int(uid)] = {
                        "status": pstatus or "SKIP",
                        "when": datetime.now(tz).isoformat(timespec="seconds"),
                        "reasons": list((payload or {}).get('reasons') or ["bigmove_payload_not_ready"]),
                    }
                    return

                subject = str(payload.get('subject') or '')
                body = str(payload.get('body') or '')
                filtered = list(payload.get('filtered') or [])
                top_sym = str(payload.get('top_sym') or '')
                top_dir = str(payload.get('top_dir') or '')
                top_tf = str(payload.get('top_tf') or '')
                top_move = float(payload.get('top_move') or 0.0)

                try:
                    _u_now = get_user(int(uid)) or {}
                    alert_email_enabled = int((_u_now or {}).get('bigmove_alert_on', 1) or 0) == 1
                except Exception:
                    alert_email_enabled = True

                alert_sent = False
                alert_error = ''
                if alert_email_enabled:
                    try:
                        alert_sent = bool(await _send_email_async(
                            int(EMAIL_SEND_TIMEOUT_SEC),
                            subject,
                            body,
                            user_id_for_debug=int(uid),
                            bypass_user_email_master=True,
                            enforce_trade_window=False,
                        ))
                    except Exception as e:
                        alert_sent = False
                        alert_error = f"{type(e).__name__}: {e}"
                        try:
                            _LAST_SMTP_ERROR[int(uid)] = alert_error
                        except Exception:
                            pass
                    if (not alert_sent) and not alert_error:
                        alert_error = str(_LAST_SMTP_ERROR.get(int(uid), "send_email_failed") or "send_email_failed")
                else:
                    alert_error = 'bigmove_alert_email_off_setup_generation_continues'

                # Mark the confirmed BigMove event as processed for cooldown whether the
                # market-event email is ON or OFF.  This prevents repeated F8 setup rows
                # every tick while still allowing opposite-direction events.
                for c in filtered[:8]:
                    try:
                        mark_bigmove_emailed(int(uid), c["symbol"], c["direction"])
                    except Exception:
                        pass

                bm_sess = _bigmove_autotrade_session_name()
                setup_email_setups = []
                setup_email_sent = False
                try:
                    setup_email_setups, setup_email_sent = await _send_bigmove_setup_email_after_alert(
                        int(uid),
                        str(bm_sess or ""),
                        list(filtered or []),
                        best_fut or {},
                        tag=str(tag or "pre_session"),
                    )
                except Exception as exc:
                    setup_email_setups, setup_email_sent = [], False
                    try:
                        db_log_setup_pipeline_event(int(uid), stage='bigmove_setup_email_after_alert_exception', status='error', session=str(bm_sess or ''), mode='bigmove_setup_email', details={'error': f'{type(exc).__name__}: {exc}', 'tag': str(tag or '')})
                    except Exception:
                        pass

                reasons = [
                    f"candidates={len(filtered)}",
                    f"top={top_sym}:{top_dir}:{top_tf}{top_move:+.2f}%",
                    f"sent_{tag}" if alert_sent else ("alert_email_off" if not alert_email_enabled else f"alert_email_failed:{str(alert_error)[:120]}"),
                    f"f8_setup_email_sent:{len(setup_email_setups or [])}" if setup_email_sent else "f8_setup_email_failed_or_empty",
                ]
                _LAST_BIGMOVE_DECISION[int(uid)] = {
                    "status": "SENT" if alert_sent else ("SETUP_ONLY" if not alert_email_enabled else "ERROR"),
                    "when": datetime.now(tz).isoformat(timespec="seconds"),
                    "subject": subject,
                    "reasons": reasons,
                }

                # Only the gated F8 setup-email list can trigger AutoTrade.  Raw BigMove
                # candidates that are NOT_KEEP/WATCH remain visible in /setup_audit but
                # are never sent directly to AutoTrade.
                try:
                    owner_uid_for_bm_at = int(AUTOTRADE_OWNER_UID or 0)
                    if owner_uid_for_bm_at > 0 and BIGMOVE_AUTOTRADE_ENABLED and _autotrade_ready() and list(setup_email_setups or []):
                        _LAST_AUTOTRADE_DECISION[owner_uid_for_bm_at] = {
                            "status": "QUEUED",
                            "when": datetime.now(timezone.utc).isoformat(timespec="seconds"),
                            "reason": "bigmove_gated_f8_setup_email_ready_for_immediate_autotrade",
                            "session": str(bm_sess or ""),
                            "mode": str(_autotrade_runtime_mode()).lower(),
                            "trigger": "bigmove_setup_email_immediate",
                        }
                        _safe_create_task(
                            _yver89_trigger_autotrade_for_f8_setups_async(int(uid), str(bm_sess or ""), list(setup_email_setups or []), best_fut or {}, tag=str(tag or "pre_session")),
                            "autotrade_after_gated_bigmove_setup_email",
                        )
                except Exception:
                    pass
            except Exception as e:
                logger.exception("Big-move alert/setup processing failed for uid=%s: %s", uid, e)
                _LAST_BIGMOVE_DECISION[int(uid)] = {
                    "status": "ERROR",
                    "when": datetime.now(tz).isoformat(timespec="seconds"),
                    "reasons": [f"{tag}_{type(e).__name__}: {e}"],
                }

        # -----------------------------------------------------
        # Big-Move Alert Emails (independent of full trade setups)
        # Trigger: |15m| >= user.bigmove_alert_15m AND |1H| >= user.bigmove_alert_1h
        #          AND |4H| >= user.bigmove_alert_4h, all in the same direction.
        # Volume gate: vol24 >= user.bigmove_min_vol_usd (default 10M)
        # Defaults: 15m=1.5%, 1H=3%, 4H=5%
        # -----------------------------------------------------
        try:
            if bool(ALERT_JOB_SKIP_BIGMOVE_WHEN_GOAL_RUNNING) and goal_running:
                users_bigmove = []
            else:
                used_pct = (time.time() - job_started_ts) / max(1.0, float(ALERT_JOB_MAX_RUNTIME_SEC or 1))
                if float(ALERT_JOB_SKIP_BIGMOVE_AFTER_BUDGET_PCT or 0.0) > 0 and used_pct >= float(ALERT_JOB_SKIP_BIGMOVE_AFTER_BUDGET_PCT):
                    users_bigmove = []
        except Exception:
            pass
        users_bigmove = list(users_bigmove or [])
        # yver89: keep the F8/BigMove setup-generation worker running for pro users
        # even when market-event Big-Move alert emails are turned OFF.  The setting
        # bigmove_alert_on is now checked only at SMTP-send time for the alert email;
        # generated F8 setups still flow through the normal setup/audit/screen/AutoTrade lane.
        try:
            users_bigmove = list(users_bigmove or [])
        except Exception:
            users_bigmove = list(users_bigmove or [])
        _bigmove_user_limit = _alert_job_limit('ALERT_JOB_BIGMOVE_MAX_USERS', 0)
        if int(_bigmove_user_limit or 0) > 0:
            users_bigmove = users_bigmove[:int(_bigmove_user_limit)]
        for u in users_bigmove:
            # Ver110: Big-Move is important, but it must not consume the entire
            # alert_job runtime and starve the normal session setup/email/autotrade pool.
            if _bigmove_session_reserve_hit():
                logger.warning("alert_job bigmove queue reserved session budget after %.1fs", time.time() - job_started_ts)
                break
            if _job_budget_exhausted():
                logger.warning("alert_job bigmove queue budget exhausted after %.1fs", time.time() - job_started_ts)
                break
            try:
                uid = int(u.get("user_id") or u.get("id") or 0)
            except Exception:
                uid = 0
            if not uid:
                continue
            if not user_has_pro(uid):
                continue
            try:
                tz_name = str((u or {}).get("tz") or (get_user(uid) or {}).get("tz") or _default_user_tz_name())
                tz, tz_name = _zoneinfo_or_default(tz_name)
            except Exception:
                tz = timezone.utc
            # Big-Move must not wait behind the session setup pool. DELAYFIX4
            # deferred it until after heavy scans; if scans timed out or exhausted
            # the runtime budget, no Big-Move email was ever sent even though
            # /email_test worked. Run it now in the dedicated email executor.
            if _job_budget_exhausted():
                _LAST_BIGMOVE_DECISION[uid] = {
                    "status": "SKIP",
                    "when": datetime.now(tz).isoformat(timespec="seconds"),
                    "reasons": ["pre_session_bigmove_budget_exhausted"],
                }
                continue
            await _send_bigmove_payload_for_user(int(uid), tz, tag='pre_session')


        # -----------------------------------------------------
        # Build only the session pools that are actually needed right now.
        # This is a major Render speed win versus rebuilding ASIA/LON/NY every minute
        # even when no user is currently inside those sessions.
        # -----------------------------------------------------
        if _job_budget_exhausted():
            logger.warning("alert_job runtime budget exhausted before session pools after %.1fs", time.time() - job_started_ts)
            return

        notify_runtime = []
        required_pool_sessions = []
        for user in (users_notify or []):
            try:
                uid = int(user.get("user_id") or user.get("id") or 0)
            except Exception:
                uid = 0
            if not uid:
                continue

            tz, tz_name = _zoneinfo_or_default(user.get("tz") or user.get("timezone"))

            try:
                sess = in_session_now(user)
            except Exception as e:
                _LAST_EMAIL_DECISION[uid] = {
                    "status": "SKIP",
                    "reasons": [f"in_session_now_failed ({type(e).__name__})"],
                    "when": datetime.now(tz).isoformat(timespec="seconds"),
                }
                sess = None

            notify_runtime.append({
                "user": user,
                "uid": uid,
                "tz": tz,
                "sess": sess,
            })

            if sess:
                sess_name = str((sess or {}).get("name") or "").upper().strip()
                if sess_name and sess_name not in required_pool_sessions:
                    required_pool_sessions.append(sess_name)

        setups_by_session: Dict[str, List[Setup]] = {}

        async def _build_email_pool_for_session(sess_name: str) -> tuple[str, list]:
            sess_key = str(sess_name or '').upper().strip()
            cache_entry = _email_pool_cache_entry(sess_key)
            cache_age = float(time.time()) - float(cache_entry.get('ts') or 0.0)
            cached_setups = list(cache_entry.get('setups') or []) if cache_entry else []

            # Authoritative source first: persisted executable queue for this session.
            # This prevents transient rebuild droughts from suppressing email/autotrade when
            # executable setups were already produced in a recent prior cycle.
            try:
                exec_rows_cached = db_list_executable_setups(0, session_name=str(sess_name or ''), ts_from=float(time.time() - _setup_email_actionable_queue_window_sec()), limit=max(int(EMAIL_SETUPS_N) * 12, 36))
            except Exception:
                exec_rows_cached = []
            try:
                persisted_setups = _executable_rows_to_setup_objects(list(exec_rows_cached or []), session_name=str(sess_name or ''))
            except Exception:
                persisted_setups = []
            persisted_setups = [s for s in (persisted_setups or []) if s is not None]
            if persisted_setups:
                try:
                    db_log_setup_pipeline_event(0, stage='email_pool_session_db', status='ok', session=str(sess_name or ''), mode='email', details={'setups': len(persisted_setups or []), 'source': f'exec_db_{int(_setup_email_actionable_queue_window_sec())}s'})
                except Exception:
                    pass
                _email_pool_cache_set(sess_name, persisted_setups)
                return str(sess_name).upper(), list(persisted_setups or [])

            # Cache-first: avoid rebuilding the full email pool every cycle when a recent
            # authoritative session pool already exists. Under runtime pressure, prefer
            # reusing cache over starting another expensive scan.
            busy_runtime = SCAN_LOCK.locked() or _SCREEN_LOCK.locked() or _backtest_runtime_busy()
            cache_ttl_for_email = float(max(20, min(float(MAX_STALE_SCAN_SEC), float(_alert_job_limit('EMAIL_POOL_REBUILD_MIN_SEC', 60)))))
            if cached_setups and cache_age <= cache_ttl_for_email:
                setups = list(cached_setups)
                try:
                    db_log_setup_pipeline_event(0, stage='email_pool_session_cache', status='busy_cache_hit' if busy_runtime else 'ok', session=str(sess_name or ''), mode='email', details={'setups': len(setups or []), 'cache_age_sec': round(cache_age, 1)})
                except Exception:
                    pass
            else:
                tf_cooling = _ohlcv_timeframe_cooling('15m', '1h', '4h')
                if tf_cooling and cached_setups:
                    setups = list(cached_setups)
                    try:
                        db_log_setup_pipeline_event(0, stage='email_pool_session_cache', status='rate_limit_cooldown_hit', session=str(sess_name or ''), mode='email', details={'setups': len(setups or []), 'cache_age_sec': round(cache_age, 1)})
                    except Exception:
                        pass
                elif tf_cooling:
                    setups = []
                    try:
                        db_log_setup_pipeline_event(0, stage='email_pool_session_skip', status='rate_limit_cooldown_no_cache', session=str(sess_name or ''), mode='email', details={'reason': 'ohlcv_global_or_tf_cooling'})
                    except Exception:
                        pass
                else:
                    try:
                        pool = await to_thread_email(
                            _run_async_in_new_loop,
                            build_priority_pool,
                            best_fut,
                            sess_name,
                            mode="exec",
                            scan_profile=str(EMAIL_SETUP_SCAN_PROFILE),
                            uid=None,
                            timeout=EMAIL_BUILD_POOL_TIMEOUT_SEC,
                        )
                    except asyncio.TimeoutError:
                        db_log_setup_pipeline_event(0, stage='build_priority_pool', status='timeout', session=str(sess_name or ''), mode='email', details={'timeout_sec': float(EMAIL_BUILD_POOL_TIMEOUT_SEC)})
                        pool = {"setups": []}
                    except Exception as e:
                        db_log_setup_pipeline_event(0, stage='build_priority_pool', status='error', session=str(sess_name or ''), mode='email', details={'error': f'{type(e).__name__}: {e}'})
                        pool = {"setups": []}

                    setups = list(pool.get("setups", []) or [])
                    if (not setups) and (not busy_runtime) and (not tf_cooling) and ((time.time() - job_started_ts) < max(10.0, float(ALERT_JOB_MAX_RUNTIME_SEC or 70) - 20.0)) and str(sess_name or '').upper() in {'ASIA', 'LON', 'NY'}:
                        try:
                            fallback_pool = await to_thread_email(
                                _run_async_in_new_loop,
                                build_priority_pool,
                                best_fut,
                                sess_name,
                                mode="screen",
                                scan_profile="aggressive",
                                uid=None,
                                timeout=max(15, int(EMAIL_BUILD_POOL_TIMEOUT_SEC)),
                            )
                            setups = list((fallback_pool or {}).get("setups", []) or [])
                            try:
                                db_log_setup_pipeline_event(0, stage='build_priority_pool_fallback', status='ok' if setups else 'empty', session=str(sess_name or ''), mode='email', details={'fallback_mode': 'screen_aggressive', 'setups': len(setups or [])})
                            except Exception:
                                pass
                        except Exception as e:
                            try:
                                db_log_setup_pipeline_event(0, stage='build_priority_pool_fallback', status='error', session=str(sess_name or ''), mode='email', details={'fallback_mode': 'screen_aggressive', 'error': f'{type(e).__name__}: {e}'})
                            except Exception:
                                pass
                if setups:
                    _email_pool_cache_set(sess_name, setups)
                elif cached_setups and cache_age <= float(_setup_email_actionable_queue_window_sec()):
                    setups = list(cached_setups)
                    try:
                        db_log_setup_pipeline_event(0, stage='email_pool_session_cache', status='stale_fallback', session=str(sess_name or ''), mode='email', details={'setups': len(setups or []), 'cache_age_sec': round(cache_age, 1)})
                    except Exception:
                        pass

            # Do not starve the executable lane by clipping the pre-filter pool too early.
            setups = setups[:max(EMAIL_SETUPS_N * 12, 36)]
            if EMAIL_PRIORITY_OVERRIDE_ON:
                pri = _email_priority_bases(best_fut, directional_take=14)
                setups = sorted(
                    setups,
                    key=lambda s: (0 if str(getattr(s, "symbol", "")).upper() in pri else 1)
                )
            try:
                db_log_setup_pipeline_event(0, stage='email_pool_session', status='ok' if setups else 'empty', session=str(sess_name or ''), mode='email', details={'setups': len(setups or [])})
            except Exception:
                pass
            return str(sess_name).upper(), list(setups or [])

        if required_pool_sessions:
            sessions_to_build = list(required_pool_sessions)
            if goal_running:
                # Keep only the live session first while heavy goal-search is running.
                live_sess = current_session_utc(datetime.now(timezone.utc))
                if live_sess in sessions_to_build:
                    sessions_to_build = [live_sess]
            built_sessions = await asyncio.gather(
                *[_build_email_pool_for_session(sess_name) for sess_name in sessions_to_build],
                return_exceptions=True,
            )
            for item in (built_sessions or []):
                if isinstance(item, Exception):
                    continue
                sess_name, setups = item
                setups_by_session[str(sess_name).upper()] = list(setups or [])
                for s in (setups or []):
                    try:
                        db_insert_signal(s)
                    except Exception:
                        pass

        # -----------------------------------------------------
        # Per-user send / skip logic
        # -----------------------------------------------------
        try:
            _notify_max = int(_alert_job_limit('ALERT_JOB_NOTIFY_MAX_USERS', 6) or 6)
        except Exception:
            _notify_max = 6
        notify_runtime = list(notify_runtime or [])
        # yver140: owner must not be lost when the notify list is longer than the
        # runtime cap. This is the setup-email source of truth for AutoTrade.
        try:
            if owner_uid_for_email > 0:
                owner_meta = None
                rest_meta = []
                for _m in notify_runtime:
                    try:
                        if int((_m or {}).get('uid') or 0) == int(owner_uid_for_email):
                            owner_meta = _m
                        else:
                            rest_meta.append(_m)
                    except Exception:
                        rest_meta.append(_m)
                if owner_meta is not None:
                    notify_runtime = [owner_meta] + rest_meta
        except Exception:
            pass
        if _notify_max > 0:
            notify_runtime = notify_runtime[:_notify_max]
        for meta in notify_runtime:
            if _job_budget_exhausted():
                logger.warning("alert_job notify loop budget exhausted after %.1fs", time.time() - job_started_ts)
                return
            user = dict(meta.get("user") or {})
            uid = int(meta.get("uid") or 0)
            tz = meta.get("tz") or timezone.utc
            sess = meta.get("sess")
            if not uid:
                continue

            # If user is NOT in an enabled session right now, skip
            if not sess:
                _LAST_EMAIL_DECISION[uid] = {
                    "status": "SKIP",
                    "reasons": ["not_in_enabled_session (outside live session window / gap)"],
                    "when": datetime.now(tz).isoformat(timespec="seconds"),
                }
                continue

            sess_name = str(sess.get("name") or "").upper()
            display_sess = _email_session_display_label(sess, fallback=sess_name)
            setups_all = setups_by_session.get(sess_name, []) or []

            # state init must not crash job
            try:
                st = email_state_get(uid)
            except Exception as e:
                _tmp_dec = {
                    "status": "ERROR",
                    "reasons": [f"email_state_get_failed ({type(e).__name__})"],
                    "when": datetime.now(tz).isoformat(timespec="seconds"),
                }
                _LAST_EMAIL_DECISION[uid] = _tmp_dec
                _LAST_EMAIL_ERROR[uid] = dict(_tmp_dec)
                continue

            # Reset session state if session_key changed
            try:
                if str(st.get("session_key")) != str(sess.get("session_key")):
                    email_state_set(uid, session_key=str(sess.get("session_key")), sent_count=0, last_email_ts=0.0)
                    st = email_state_get(uid)
            except Exception:
                pass

            # Safe defaults (never KeyError)
            try:
                max_emails = int(user.get("max_emails_per_session", DEFAULT_MAX_EMAILS_PER_SESSION))
            except Exception:
                max_emails = int(DEFAULT_MAX_EMAILS_PER_SESSION)

            try:
                gap_min = int(user.get("email_gap_min", DEFAULT_MIN_EMAIL_GAP_MIN))
            except Exception:
                gap_min = int(DEFAULT_MIN_EMAIL_GAP_MIN)

            gap_sec = max(0, gap_min) * 60

            # Daily cap (anchored trading day via /dayreset, not midnight local day)
            try:
                day_local = _user_day_local(user)
            except Exception:
                day_local = datetime.now(tz).date().isoformat()
            try:
                sent_today = _email_daily_get(uid, day_local)
            except Exception:
                sent_today = 0

            try:
                day_cap = int(user.get("max_emails_per_day", DEFAULT_MAX_EMAILS_PER_DAY))
            except Exception:
                day_cap = int(DEFAULT_MAX_EMAILS_PER_DAY)

            if day_cap > 0 and sent_today >= day_cap:
                _LAST_EMAIL_DECISION[uid] = {
                    "status": "SKIP",
                    "reasons": [f"daily_email_cap_reached ({sent_today}/{day_cap})"],
                    "when": datetime.now(tz).isoformat(timespec="seconds"),
                }
                continue

            # Session cap
            try:
                sent_in_session = int(st.get("sent_count", 0) or 0)
            except Exception:
                sent_in_session = 0

            if max_emails > 0 and sent_in_session >= max_emails:
                _LAST_EMAIL_DECISION[uid] = {
                    "status": "SKIP",
                    "reasons": [f"session_email_cap_reached ({sent_in_session}/{max_emails})"],
                    "when": datetime.now(tz).isoformat(timespec="seconds"),
                }
                continue

            # Gap
            now_ts = time.time()
            try:
                last_ts = float(st.get("last_email_ts", 0.0) or 0.0)
            except Exception:
                last_ts = 0.0

            if gap_sec > 0 and (now_ts - last_ts) < gap_sec:
                remain = int(gap_sec - (now_ts - last_ts))
                _LAST_EMAIL_DECISION[uid] = {
                    "status": "SKIP",
                    "reasons": [f"email_gap_active (remain {remain}s)"],
                    "when": datetime.now(tz).isoformat(timespec="seconds"),
                }
                continue

                        # ---------------------------
            # Unified executable lane consumption
            # ---------------------------
            # The authoritative lane is executable_setups. Email may help populate it,
            # but it must always re-read that persisted queue before selection/sending.

            skip_reasons_counter = Counter()
            eligible: List[Setup] = []
            for s in (setups_all or []):
                try:
                    s_eff = _setup_route_candidate_for_executable_lane(s, sess_name, int(uid))
                    ok, why = is_executable_setup_eligible(s_eff, session_name=sess_name)
                except Exception:
                    s_eff = s
                    ok, why = False, 'email_exec_gate_exception'
                if ok:
                    eligible.append(s_eff)
                else:
                    skip_reasons_counter[str(why)] += 1

            persisted_count = 0
            if eligible:
                try:
                    _persist_stats = _persist_executable_candidates(int(uid), str(sess_name or ''), list(eligible or []), source_kind='executable_setups', mode='email')
                    persisted_count = int((_persist_stats or {}).get('persisted') or 0)
                    db_log_setup_pipeline_event(int(uid), stage='email_executable_pool', status='ok', session=str(sess_name or ''), mode='email', details={'eligible': len(eligible or []), 'persisted': persisted_count, 'top_reasons': _pipeline_top_reasons(skip_reasons_counter, 5)})
                except Exception as e:
                    db_log_setup_pipeline_event(int(uid), stage='email_executable_pool', status='error', session=str(sess_name or ''), mode='email', details={'error': f'{type(e).__name__}: {e}', 'eligible': len(eligible or []), 'top_reasons': _pipeline_top_reasons(skip_reasons_counter, 5)})

            # yver139: keep the in-memory/shared executable candidates as a safety net.
            # A per-user executable_setups fan-out can be skipped by generation cooldown or
            # a transient SQLite write, but the exact candidate can still be emailed and
            # then stamped into emailed_setups/executable_setups by send_email_alert_multi().
            eligible_from_pool = list(eligible or [])
            try:
                exec_rows = db_list_executable_setups(int(uid), session_name=str(sess_name or ''), ts_from=float(time.time() - _setup_email_actionable_queue_window_sec()), limit=max(int(EMAIL_SETUPS_N) * 12, 36))
            except Exception:
                exec_rows = []
            try:
                hydrated = _executable_rows_to_setup_objects(list(exec_rows or []), session_name=str(sess_name or ''))
            except Exception:
                hydrated = []
            eligible_db = [s for s in (hydrated or []) if s is not None]
            if eligible_db:
                eligible = list(eligible_db)
            elif eligible_from_pool:
                eligible = list(eligible_from_pool)
                try:
                    db_log_setup_pipeline_event(int(uid), stage='email_executable_pool_db_fallback', status='using_in_memory_pool', session=str(sess_name or ''), mode='email', details={'eligible_from_pool': len(eligible_from_pool or []), 'db_rows': len(exec_rows or [])})
                except Exception:
                    pass
            else:
                eligible = []

            if (not eligible) and str(sess_name or '').upper() in {'ASIA', 'LON', 'NY'}:
                try:
                    recent_candidates = _db_recent_candidate_setup_objects(
                        int(uid),
                        session_name=str(sess_name or ''),
                        max_age_min=_setup_email_actionable_queue_window_min(),
                        limit=max(int(EMAIL_SETUPS_N) * 4, 12),
                    )
                except Exception:
                    recent_candidates = []
                if recent_candidates:
                    eligible = []
                    for _cand in (recent_candidates or []):
                        if _cand is None:
                            continue
                        try:
                            _cand_eff = _setup_route_candidate_for_executable_lane(_cand, sess_name, int(uid))
                            if is_executable_setup_eligible(_cand_eff, session_name=sess_name)[0]:
                                eligible.append(_cand_eff)
                        except Exception:
                            continue
                    try:
                        db_log_setup_pipeline_event(int(uid), stage='email_executable_pool_fallback', status='ok' if eligible else 'empty', session=str(sess_name or ''), mode='email', details={'eligible': len(eligible or []), 'source': f'recent_candidates_{int(_setup_email_actionable_queue_window_sec())}s'})
                    except Exception:
                        pass

            if not eligible:
                # FIX5: last-chance current-market recovery for email/autotrade lane.
                # This does NOT use old emailed setups. It converts the current generated pool
                # into clean recovery candidates when the executable queue is empty.
                try:
                    recovery_now = []
                    for _s in list(setups_all or []):
                        try:
                            _s_eff = _setup_route_candidate_for_executable_lane(_s, sess_name, int(uid))
                            setattr(_s_eff, 'recovery_fallback', True)
                            ok_now, _why_now = is_executable_setup_eligible(_s_eff, session_name=sess_name)
                            if ok_now:
                                recovery_now.append(_s_eff)
                        except Exception:
                            continue
                    if recovery_now:
                        _persist_stats = _persist_executable_candidates(int(uid), str(sess_name or ''), list(recovery_now or []), source_kind='executable_setups', mode='email_recovery')
                        eligible = list(recovery_now or [])
                        persisted_count = max(int(persisted_count or 0), int((_persist_stats or {}).get('persisted') or 0))
                        db_log_setup_pipeline_event(int(uid), stage='email_executable_pool_recovery', status='ok', session=str(sess_name or ''), mode='email', details={'eligible': len(eligible or []), 'persisted': persisted_count})
                except Exception as _e:
                    try:
                        db_log_setup_pipeline_event(int(uid), stage='email_executable_pool_recovery', status='error', session=str(sess_name or ''), mode='email', details={'error': f'{type(_e).__name__}: {_e}'})
                    except Exception:
                        pass

            if not eligible:
                top_reasons = dict(skip_reasons_counter.most_common(3))
                db_log_setup_pipeline_event(int(uid), stage='email_executable_pool', status='empty', session=str(sess_name or ''), mode='email', details={'eligible': 0, 'persisted': persisted_count, 'top_reasons': _pipeline_top_reasons(skip_reasons_counter, 5)})
                _LAST_EMAIL_DECISION[uid] = {
                    "status": "SKIP",
                    "reasons": ([_email_no_setups_reason(sess, fallback_session=sess_name)] if not setups_all else ["no_setups_after_filters"]) + [f"top_reasons={top_reasons}"],
                    "when": datetime.now(tz).isoformat(timespec="seconds"),
                }
                continue

            # Premium ordering: confidence desc, RR(final TP) desc
            def _rr3(_s: Setup) -> float:
                try:
                    final_tp = float(_setup_target_tp(_s, 0.0) or 0.0)
                    return float(rr_to_tp(float(_s.entry), float(_s.sl), final_tp)) if final_tp > 0 else 0.0
                except Exception:
                    return 0.0

            eligible = sorted(
                eligible,
                key=lambda _s: (
                    float(getattr(_s, "quality_score", 0.0) or 0.0),
                    int(getattr(_s, "conf", 0) or 0),
                    _rr3(_s),
                    float(getattr(_s, "fut_vol_usd", 0.0) or 0.0),
                ),
                reverse=True,
            )

            # Candidate picks for cooldown/flip checks below
            picks: List[Setup] = list(eligible[: max(int(EMAIL_SETUPS_N) * 10, 30)])

            chosen_list: List[Setup] = []
            _seen_setup_keys = set()
            cooldown_blocked = 0
            flip_blocked = 0
            diversify_blocked = Counter()
            owner_manual_same_symbol_blocked = 0
            combo_policy_blocked = 0

            for s in picks:
                if len(chosen_list) >= int(EMAIL_SETUPS_N):
                    break

                sym = str(getattr(s, "symbol", "")).upper()
                side = str(getattr(s, "side", "")).upper()
                try:
                    _k = (
                        sym,
                        side,
                        round(float(getattr(s, 'entry', 0.0) or 0.0), 8),
                        round(float(getattr(s, 'sl', 0.0) or 0.0), 8),
                        round(float(_setup_target_tp(s, 0.0) or 0.0), 8),
                    )
                except Exception:
                    _k = (sym, side, str(getattr(s, 'entry', '')), str(getattr(s, 'sl', '')), str(_setup_target_tp(s, 0.0) or ''))
                if _k in _seen_setup_keys:
                    continue
                _seen_setup_keys.add(_k)
                sess_name = str(sess["name"])

                try:
                    if not _setup_combo_policy_allows_setup(s, sess_name, user_id=int(uid)):
                        combo_policy_blocked += 1
                        continue
                except Exception:
                    combo_policy_blocked += 1
                    continue

                # yver139: apply the same subscriber/email KEEP + context gate before
                # choosing the candidate, not only inside send_email_alert_multi().
                # Otherwise the top candidate can be chosen then removed by presend,
                # causing the whole email batch to fail instead of trying the next valid setup.
                try:
                    _vis_ok, _vis_why, _vis_meta = _setup_user_visible_keep_policy_allows(s, session_name=sess_name, user_id=int(uid), lane='email')
                    if not _vis_ok:
                        combo_policy_blocked += 1
                        try:
                            db_log_setup_pipeline_event(int(uid), stage='email_user_visible_policy_gate', status='skip', session=str(sess_name or ''), mode='email', setup_id=str(getattr(s, 'setup_id', '') or ''), symbol=sym, side=side, details={'reason': str(_vis_why or 'email_policy_not_allowed'), 'policy': dict(_vis_meta or {})})
                        except Exception:
                            pass
                        continue
                except Exception:
                    combo_policy_blocked += 1
                    continue

                if symbol_flip_guard_active(uid, sym, side, sess_name):
                    flip_blocked += 1
                    continue

                ok_div, why_div = _email_diversification_guard(s, chosen_list, best_fut, sess_name)
                if not ok_div:
                    diversify_blocked[str(why_div)] += 1
                    continue

                if _email_setup_identity_recently_sent(uid, s):
                    cooldown_blocked += 1
                    continue
                if _email_symbol_recently_sent(uid, sym, side, sess_name, setup_id=str(getattr(s, 'setup_id', '') or '')):
                    cooldown_blocked += 1
                    continue

                if int(uid) == int(AUTOTRADE_OWNER_UID or 0) and str(_autotrade_runtime_mode()).lower() == 'live':
                    try:
                        _conflict = _autotrade_live_symbol_conflict(int(uid), sym, side=side)
                    except Exception:
                        _conflict = {}
                    if bool((_conflict or {}).get('has_conflict')) and str((_conflict or {}).get('owner_kind') or '') == 'external':
                        owner_manual_same_symbol_blocked += 1
                        continue

                chosen_list.append(s)

            if not chosen_list:
                reasons = []
                if cooldown_blocked:
                    reasons.append(f"cooldown_blocked={cooldown_blocked}")
                if flip_blocked:
                    reasons.append(f"flip_guard_blocked={flip_blocked}")
                if diversify_blocked:
                    reasons.append(f"diversified_blocked={dict(diversify_blocked.most_common(3))}")
                if owner_manual_same_symbol_blocked:
                    reasons.append(f"owner_manual_same_symbol_blocked={owner_manual_same_symbol_blocked}")
                if combo_policy_blocked:
                    reasons.append(f"combo_policy_quality_gate_blocked={combo_policy_blocked}")
                reasons.append("all_candidates_blocked")

                _LAST_EMAIL_DECISION[uid] = {
                    "status": "SKIP",
                    "reasons": reasons,
                    "when": datetime.now(tz).isoformat(timespec="seconds"),
                }
                continue

            # Send ONE email containing MULTIPLE setups (timeout-protected)
            try:
                ok = await asyncio.wait_for(
                    to_thread_heavy(send_email_alert_multi, user, sess, chosen_list, best_fut, timeout=EMAIL_SEND_TIMEOUT_SEC),
                    timeout=EMAIL_SEND_TIMEOUT_SEC + 2,
                )
            except asyncio.TimeoutError:
                try:
                    _LAST_SMTP_ERROR[uid] = f"timeout_after_{int(EMAIL_SEND_TIMEOUT_SEC)}s"
                except Exception:
                    pass
                ok = bool(_email_assume_sent_on_soft_smtp())
                if ok:
                    try:
                        _record_setup_email_delivery_side_effects(int(uid), str(sess.get("name") or sess_name or ''), list(chosen_list or []), best_fut or {}, status='timeout_assumed_sent')
                    except Exception:
                        pass
            except Exception as e:
                ok = False
                logger.exception("send_email_alert_multi failed for uid=%s: %s", uid, e)
                try:
                    _LAST_SMTP_ERROR[uid] = f"{type(e).__name__}: {e}"
                except Exception:
                    pass
                # Defensive: if SMTP raised after DATA was likely accepted, still record the
                # exact email batch and continue into AutoTrade. This prevents delivered
                # Gmail messages from being invisible to /screen and autotrade.
                if _email_assume_sent_on_soft_smtp() and _smtp_error_probably_delivered(str(_LAST_SMTP_ERROR.get(uid, ''))):
                    try:
                        _record_setup_email_delivery_side_effects(int(uid), str(sess.get("name") or sess_name or ''), list(chosen_list or []), best_fut or {}, status='exception_assumed_sent')
                    except Exception:
                        pass
                    ok = True

            if ok:
                try:
                    _LAST_EMAIL_ERROR.pop(uid, None)
                except Exception:
                    pass
                try:
                    email_state_set(uid, last_email_ts=time.time(), sent_count=int(st.get("sent_count", 0) or 0) + 1)
                except Exception:
                    pass

                try:
                    _email_daily_inc(uid, day_local)
                except Exception:
                    pass

                for s in chosen_list:
                    try:
                        mark_symbol_emailed(uid, s.symbol, s.side, sess["name"])
                    except Exception:
                        pass

                # AutoTrade: mirror the emailed setups into the owner executable lane and
                # trigger one immediate execution attempt. The helper uses the same lock and
                # _autotrade_place_trade path as the scheduled autotrade_job, so risk/duplicate
                # controls remain centralized.
                autotrade_note = "queued_for_immediate_autotrade"
                try:
                    owner_uid_for_at = int(AUTOTRADE_OWNER_UID or 0)
                    if owner_uid_for_at > 0 and _autotrade_ready() and (int(uid) == owner_uid_for_at or is_admin_user(int(uid))):
                        _LAST_AUTOTRADE_DECISION[owner_uid_for_at] = {
                            "status": "QUEUED",
                            "when": datetime.now(timezone.utc).isoformat(timespec="seconds"),
                            "reason": "email_sent_waiting_for_immediate_autotrade",
                            "session": str(sess.get("name") or sess_name or ""),
                            "mode": str(_autotrade_runtime_mode()).lower(),
                        }
                        _safe_create_task(
                            _trigger_autotrade_after_email_async(int(uid), str(sess.get("name") or sess_name or ""), list(chosen_list or [])),
                            "autotrade_after_email",
                        )
                except Exception:
                    pass

                try:
                    db_log_setup_pipeline_event(int(uid), stage='email_executable_pool', status='sent', session=str(sess.get("name") or sess_name or ''), mode='email', details={'eligible': len(chosen_list or []), 'persisted': int(persisted_count or 0), 'setups': len(chosen_list or []), 'picked': [f"{getattr(_s, 'side', '')} {getattr(_s, 'symbol', '')}" for _s in list(chosen_list or [])[:8]]})
                except Exception:
                    pass

                _tmp_dec = {
                    "status": "SENT",
                    "picked": ", ".join([f"{s.side} {s.symbol} conf={s.conf}" for s in chosen_list]),
                    "when": datetime.now(tz).isoformat(timespec="seconds"),
                    "autotrade": autotrade_note,
                    "reasons": ["passed_filters_multi"],
                }
                _LAST_EMAIL_DECISION[uid] = _tmp_dec
                _LAST_EMAIL_SENT[uid] = dict(_tmp_dec)
            else:
                _tmp_dec = {
                    "status": "ERROR",
                    "reasons": ["send_email_failed_or_timeout", _LAST_SMTP_ERROR.get(uid, "unknown_error")],
                    "when": datetime.now(tz).isoformat(timespec="seconds"),
                }
                _LAST_EMAIL_DECISION[uid] = _tmp_dec
                _LAST_EMAIL_ERROR[uid] = dict(_tmp_dec)


        # -----------------------------------------------------
        # Post-session-pools retry for Big-Move emails that were deferred
        # to preserve setup-email runtime. This prevents Big-Move from
        # being starved forever whenever session pools are busy.
        # -----------------------------------------------------
        deferred_limit = _alert_job_limit('ALERT_JOB_BIGMOVE_DEFERRED_MAX_USERS', int(ALERT_JOB_BIGMOVE_DEFERRED_MAX_USERS or 0))
        deferred_jobs_to_run = list(deferred_bigmove_jobs or [])
        if int(deferred_limit or 0) > 0:
            deferred_jobs_to_run = deferred_jobs_to_run[:int(deferred_limit)]
        for job in deferred_jobs_to_run:
            try:
                uid = int(job.get('uid') or 0)
            except Exception:
                uid = 0
            tz = job.get('tz') or timezone.utc
            if not uid:
                continue
            if _bigmove_deferred_budget_exhausted():
                _LAST_BIGMOVE_DECISION[uid] = {
                    "status": "SKIP",
                    "when": datetime.now(tz).isoformat(timespec="seconds"),
                    "reasons": ["queued_until_after_session_pools", "retry_budget_exhausted_after_session_pools"],
                }
                continue
            try:
                await _send_bigmove_payload_for_user(uid, tz, tag='deferred')
            except Exception as e:
                logger.exception("Deferred big-move setup processing failed for uid=%s: %s", uid, e)
                _LAST_BIGMOVE_DECISION[uid] = {
                    "status": "ERROR",
                    "when": datetime.now(tz).isoformat(timespec="seconds"),
                    "reasons": [f"deferred_retry_{type(e).__name__}: {e}"],
                }

async def email_decision_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    uid = update.effective_user.id
    user = get_user(uid) or {}

    # User timezone for consistent debug display.
    # Admin request: do not print duplicate UTC in /email_decision; show all times
    # in the user's own timezone (Melbourne for the owner/admin deployment).
    try:
        from zoneinfo import ZoneInfo
        tz_name = str(user.get("tz") or user.get("timezone") or os.environ.get("DEFAULT_USER_TZ") or TIMEZONE or "Australia/Melbourne")
        tz_disp = ZoneInfo(tz_name)
    except Exception:
        tz_name = "Australia/Melbourne"
        try:
            tz_disp = ZoneInfo(tz_name)
        except Exception:
            tz_disp = timezone.utc

    def _fmt_when_local(v) -> str:
        try:
            if v is None:
                return ""
            import datetime as _dt
            dt = None
            if isinstance(v, (int, float)):
                dt = _dt.datetime.fromtimestamp(float(v), tz=_dt.timezone.utc)
            elif isinstance(v, str):
                s = v.strip()
                if not s:
                    return ""
                try:
                    # Python handles offsets like +10:00. If the timestamp is naive,
                    # treat it as UTC because internal DB/runtime timestamps are UTC-ish.
                    dt = _dt.datetime.fromisoformat(s.replace("Z", "+00:00"))
                except Exception:
                    return s
                if dt.tzinfo is None:
                    dt = dt.replace(tzinfo=_dt.timezone.utc)
            else:
                return str(v)
            loc = dt.astimezone(tz_disp)
            return f"{loc.strftime('%Y-%m-%d %H:%M:%S')} {tz_name}"
        except Exception:
            try:
                return str(v)
            except Exception:
                return ""

    scan = _LAST_EMAIL_DECISION.get(uid) or {}
    bigm = _LAST_BIGMOVE_DECISION.get(uid) or {}

    # If nothing recorded
    if not scan and not bigm:
        await update.message.reply_text("No email decision recorded yet.")
        return

    lines = []
    lines.append("📧 Email Decisions")
    # Heartbeat
    try:
        last_tick = float(_EMAIL_LOOP_HEARTBEAT.get("last_tick_ts", 0.0) or 0.0)
        next_tick = float(_EMAIL_LOOP_HEARTBEAT.get("next_tick_ts", 0.0) or 0.0)
        alive = bool(_EMAIL_LOOP_HEARTBEAT.get("alive", False))
        last_err = str(_EMAIL_LOOP_HEARTBEAT.get("last_error", "") or "")
        lines.append("")
        lines.append("🫀 Email Loop")
        lines.append(f"Alive: {'YES' if alive else 'NO'}")
        if last_tick > 0:
            lines.append("Last tick: " + _fmt_when_local(last_tick))
        if next_tick > 0:
            lines.append("Next tick: " + _fmt_when_local(next_tick))
        if last_err:
            lines.append("Last error: " + last_err)
    except Exception:
        pass

    # Last successful SENT email (not overwritten by later SKIPs)
    sent = _LAST_EMAIL_SENT.get(uid) or {}
    if sent:
        lines.append("")
        lines.append("✅ Last SENT Email")
        lines.append(f"When: {_fmt_when_local(sent.get('when') or sent.get('ts'))}")
        if sent.get('picked'):
            lines.append("Picked: " + str(sent.get('picked')))
        rs = sent.get('reasons') or []
        if rs:
            lines.append("Reasons:\n- " + "\n- ".join([str(x) for x in rs]))

    err = _LAST_EMAIL_ERROR.get(uid) or {}
    if err:
        lines.append("")
        lines.append("❌ Last Email ERROR")
        lines.append(f"When: {_fmt_when_local(err.get('when') or err.get('ts'))}")
        rs = err.get('reasons') or []
        if rs:
            lines.append("Reasons:\n- " + "\n- ".join([str(x) for x in rs]))


    # Mirror the current /bigmove_alert settings here so /email_decision shows
    # both the live pipeline outcome and the user's active big-move alert config.
    try:
        bigm_on = int(user.get("bigmove_alert_on", 1) or 0)
    except Exception:
        bigm_on = 1
    try:
        bigm_p15, bigm_p1, bigm_p4 = _user_bigmove_thresholds(user)
    except Exception:
        bigm_p15, bigm_p1, bigm_p4 = BIGMOVE_DEFAULT_15M_PCT, BIGMOVE_DEFAULT_1H_PCT, BIGMOVE_DEFAULT_4H_PCT
    try:
        bigm_min_vol = _user_bigmove_min_vol_usd(user, BIGMOVE_DEFAULT_MIN_VOL_USD)
    except Exception:
        bigm_min_vol = BIGMOVE_DEFAULT_MIN_VOL_USD
    try:
        bigm_updated_ts = float(user.get("bigmove_alert_updated_ts", 0.0) or 0.0)
    except Exception:
        bigm_updated_ts = 0.0
    bigm_updated_reason = str(user.get("bigmove_alert_update_reason", "") or "").strip()

    lines.append("")
    lines.append("⚡ Big-Move Alert Settings")
    lines.append(f"Status: {'ON' if bigm_on else 'OFF'}")
    lines.append(f"Thresholds: |15m| ≥ {bigm_p15:g}% AND |1H| ≥ {bigm_p1:g}% AND |4H| ≥ {bigm_p4:g}% (same direction only)")
    lines.append(f"Min Vol (24H): {bigm_min_vol/1e6:.1f}M")
    lines.append(f"Payload timeout: {int(BIGMOVE_PAYLOAD_TIMEOUT_SEC or 60)}s")
    if bigm_updated_ts > 0:
        lines.append("Updated: " + _fmt_when_local(bigm_updated_ts))
    if bigm_updated_reason:
        lines.append(f"Reason: {bigm_updated_reason}")

    if bigm:
        lines.append("")
        lines.append("⚡ Big-Move Alert Decision")
        lines.append(f"Status: {bigm.get('status')}")
        lines.append("When: " + _fmt_when_local(bigm.get("when") or bigm.get("ts")))
        rs = bigm.get("reasons") or []
        if rs:
            lines.append("Reasons:\n- " + "\n- ".join(rs))

    try:
        ctx_now = _session_gap_context(datetime.now(timezone.utc))
        sess_now = str(ctx_now.get('live_session') or current_session_name() or 'NONE').upper().strip()
        scan_bucket_now = str(ctx_now.get('scan_session') or scan_session_name_utc(datetime.now(timezone.utc)) or '').upper().strip()
        pipe_lookup_sess = scan_bucket_now if sess_now == 'NONE' else sess_now
        pipe_build = _latest_setup_pipeline_event(0, stage='build_priority_pool', session=pipe_lookup_sess, mode='email') or {}
        if not pipe_build:
            pipe_build = _latest_setup_pipeline_event(0, stage='build_priority_pool', mode='email') or {}
        pipe_exec = _latest_setup_pipeline_event(uid, stage='email_executable_pool', session=pipe_lookup_sess, mode='email') or {}
        if not pipe_exec:
            pipe_exec = _latest_setup_pipeline_event(uid, stage='email_executable_pool', mode='email') or {}
        if pipe_build or pipe_exec:
            def _pipe_summary(row: dict) -> str:
                if not row:
                    return '-'
                try:
                    details = json.loads(str(row.get('details_json') or '{}')) if row.get('details_json') else {}
                except Exception:
                    details = {}
                status = str(row.get('status') or '-')
                row_sess = str(row.get('session') or '-').upper()
                parts = [status, f"session={row_sess}"]
                try:
                    evt = float(row.get('event_ts') or 0.0)
                    if evt > 0:
                        parts.append(_fmt_when_local(evt))
                except Exception:
                    pass
                try:
                    if details.get('timeout_sec'):
                        parts.append(f"timeout={details.get('timeout_sec')}s")
                except Exception:
                    pass
                try:
                    if details.get('setups') is not None:
                        parts.append(f"setups={int(details.get('setups') or 0)}")
                except Exception:
                    pass
                try:
                    if details.get('eligible') is not None:
                        parts.append(f"eligible={int(details.get('eligible') or 0)}")
                except Exception:
                    pass
                try:
                    top = details.get('top_reasons') or []
                    if top:
                        parts.append('top=' + ', '.join([str(x) for x in top[:3]]))
                except Exception:
                    pass
                try:
                    err = str(details.get('error') or '').strip()
                    if err:
                        parts.append(err[:160])
                except Exception:
                    pass
                return ' | '.join(parts)
            lines.append("")
            lines.append("🛠️ Setup Email Pipeline")
            if sess_now == 'NONE':
                lines.append(f"Current session: NONE (outside live session window / gap)")
                lines.append(f"Fallback scan bucket: {scan_bucket_now or '-'}")
            else:
                lines.append(f"Current session: {sess_now or '-'}")
            lines.append(f"Configured build timeout: {float(EMAIL_BUILD_POOL_TIMEOUT_SEC):.1f}s")
            if pipe_build:
                lines.append("Build pool: " + _pipe_summary(pipe_build))
            if pipe_exec:
                lines.append("Executable pool: " + _pipe_summary(pipe_exec))
    except Exception:
        pass

    try:
        h = _scan_health_snapshot()
        last_ts = float(h.get('last_scan_ts') or 0.0)
        lines.append("")
        lines.append("🩺 Scan Health")
        lines.append("Last scan: " + (_fmt_when_local(last_ts) if last_ts > 0 else "-"))
        lines.append(f"Mode/session: {str(h.get('last_scan_mode') or '-')}/{str(h.get('last_scan_session') or '-')}")
        lines.append(f"TF phase: {str(h.get('last_tf_phase') or '-')} | Symbols processed: {int(h.get('symbols_processed') or 0)}")
        lines.append(f"Rate-limit hits: {int(h.get('rate_limit_hits') or 0)} | Stale uses: {int(h.get('stale_usage') or 0)} | OHLCV limit: {int(h.get('ohlcv_limit') or MAX_OHLCV_LIMIT)}")
    except Exception:
        pass

    lines.append("")
    lines.append("🧠 Market Scan Decision")
    if scan:
        lines.append(f"Status: {scan.get('status')}")
        lines.append("When: " + _fmt_when_local(scan.get("when") or scan.get("ts")))
        rs = scan.get("reasons") or scan.get("reason")
        if isinstance(rs, list) and rs:
            lines.append("Reasons:\n- " + "\n- ".join([str(x) for x in rs]))
        elif rs:
            lines.append(f"Reason: {rs}")
        else:
            lines.append("Reason: -")
    else:
        lines.append("Status: -")
        lines.append("When: -")
        lines.append("Reason: no_market_scan_decision_recorded_yet")

    await update.message.reply_text("\n".join(lines).strip())



