def _autotrade_monitor_live_exit_protection(uid: int) -> list[dict]:
    """Lean live SL/TP guardian.

    This must never monopolise the background executor. The previous version could call
    Bybit open-order endpoints repeatedly per position and then time out after 15s,
    leaving a noisy asyncio task exception in Render. This version is budget-aware,
    limits work per tick, reuses the position snapshot, and avoids extra diagnostic
    status calls inside the guardian loop.
    """
    repaired = []
    started = time.time()
    try:
        budget = float(os.getenv('AUTOTRADE_GUARDIAN_BUDGET_SEC', str(max(4, int(AUTOTRADE_GUARDIAN_TIMEOUT_SEC or 12) - 2))) or 10)
    except Exception:
        budget = 10.0
    try:
        max_items = int(os.getenv('AUTOTRADE_GUARDIAN_MAX_ITEMS', '10') or 10)
    except Exception:
        max_items = 10

    def _budget_left() -> bool:
        try:
            return (time.time() - started) < max(2.0, float(budget))
        except Exception:
            return False

    try:
        # First remove legacy standalone Conditional exit rows left by older builds.
        # This also clears orphan pf_tp/pf_cond orders for symbols that no longer have a position.
        try:
            cancelled_orphans = _autotrade_cancel_all_legacy_conditional_exit_orders(max_cancel=50)
            if int(cancelled_orphans or 0) > 0:
                repaired.append({'checked': True, 'placement': 'legacy_conditional_cleanup', 'legacy_conditional_cancelled': int(cancelled_orphans or 0)})
        except Exception:
            pass

        live_positions = list(_bybit_get_open_positions_linear() or [])
        journal_open = list(_autotrade_db_open_trades(int(uid)) or [])
        if not live_positions or not journal_open:
            return repaired

        pos_map = {}
        for p in live_positions:
            try:
                pos_map[(str(_pos_symbol(p) or '').upper(), str(_pos_side_text(p) or '').upper())] = p
            except Exception:
                continue

        work = []
        used_trade_ids = set()
        for p in live_positions:
            if not _budget_left() or len(work) >= max_items:
                break
            tr = _autotrade_find_open_trade_for_live_position(int(uid), p, journal_open=journal_open)
            if not tr:
                continue
            tid = str(tr.get('trade_id') or '').strip()
            if tid:
                used_trade_ids.add(tid)
            work.append((tr, p))

        for tr in journal_open:
            if not _budget_left() or len(work) >= max_items:
                break
            tid = str(tr.get('trade_id') or '').strip()
            if tid and tid in used_trade_ids:
                continue
            sym = _bybit_linear_symbol(str(tr.get('symbol') or ''))
            side = str(tr.get('side') or '').upper().strip()
            p = pos_map.get((sym, side))
            if not p:
                continue
            work.append((tr, p))

        for tr, p in work:
            if not _budget_left():
                break
            try:
                rr = _autotrade_repair_live_exit_protection(int(uid), tr, live_pos=p)
                if any(bool(rr.get(k)) for k in ('sl_fixed', 'tp_fixed', 'tp_order_fixed', 'be_applied', 'legacy_conditional_cancelled')):
                    repaired.append(rr)
                # Ver06 emergency risk guardian: if an existing live position's
                # detected SL risk is far above the configured dynamic-risk cap,
                # reduce/close it. This catches stale/wrong exchange stops or any
                # position that slipped past post-fill verification.
                try:
                    eq = _live_equity_usdt_cached(ttl=FAST_ADMIN_SNAPSHOT_TTL_SEC) or _effective_equity_for_risk(get_user(int(uid)) or {}, prefer_live=True)
                    emerg_cap = _autotrade_hard_risk_cap_usd(float(eq or 0.0), multiplier=_autotrade_emergency_risk_max_mult())
                    if emerg_cap > 0:
                        rd = _autotrade_live_position_risk_detail(p)
                        if float((rd or {}).get('risk_usd') or 0.0) > emerg_cap * 1.0005:
                            if bool(globals().get('AUTOTRADE_STRICT_TPSL_ONLY', True)) and not bool(globals().get('AUTOTRADE_MARKET_REDUCE_ON_RISK_BREACH', False)):
                                repaired.append({'checked': True, 'placement': 'guardian_emergency_risk_cap', 'action': 'no_market_reduce_strict_tpsl_only', 'risk_detail': rd, 'cap_usd': float(emerg_cap)})
                            else:
                                rg = _autotrade_reduce_live_position_to_risk_cap(_pos_symbol(p), _pos_side_text(p), emerg_cap, reason='guardian_emergency_risk_cap', live_pos=p)
                                rg['checked'] = True
                                rg['placement'] = 'guardian_emergency_risk_cap'
                                repaired.append(rg)
                except Exception:
                    pass
            except Exception:
                continue

        # Final account-level cleanup for old bot-created Conditional TP rows,
        # including orphan rows left behind after a position closed. Native TP/SL
        # rows are not cancelled by this helper.
        if _budget_left():
            try:
                cancelled = _autotrade_cancel_all_legacy_conditional_exit_orders(max_items=80)
                if cancelled:
                    repaired.append({'checked': True, 'placement': 'cleanup_only', 'legacy_conditional_cancelled': int(cancelled)})
            except Exception:
                pass
    except Exception:
        return repaired
    return repaired


async def autotrade_exit_guardian_job(context: ContextTypes.DEFAULT_TYPE):
    try:
        if _live_trade_runtime_busy():
            _hb_touch('autotrade_guardian', ok=True, details='live_trade_runtime_busy')
            return
        if not _autotrade_ready():
            return
        if str(_autotrade_runtime_mode()).lower() != 'live':
            return
        uid = int(AUTOTRADE_OWNER_UID or 0)
        if uid <= 0:
            return
        if AUTOTRADE_GUARDIAN_LOCK.locked():
            _hb_touch('autotrade_guardian', ok=True, details='busy_skip')
            return
        if _autotrade_guardian_recent():
            _hb_touch('autotrade_guardian', ok=True, details='cooldown_skip')
            return

        async with AUTOTRADE_GUARDIAN_LOCK:
            try:
                repaired = await to_thread_bg(
                    _autotrade_monitor_live_exit_protection,
                    int(uid),
                    timeout=AUTOTRADE_GUARDIAN_TIMEOUT_SEC,
                )
            except asyncio.TimeoutError:
                _hb_touch('autotrade_guardian', ok=False, error=f'timeout>{AUTOTRADE_GUARDIAN_TIMEOUT_SEC}s', details='guardian_timeout')
                try:
                    _key = 'autotrade_guardian_timeout'
                    _now = float(time.time())
                    if _LOG_WARN_THROTTLE_UNTIL.get(_key, 0.0) <= _now:
                        _LOG_WARN_THROTTLE_UNTIL[_key] = _now + max(60, int(LOG_WARN_THROTTLE_SEC or 120))
                        logger.info('autotrade_exit_guardian_job skipped: timed out after %ss (will retry later)', AUTOTRADE_GUARDIAN_TIMEOUT_SEC)
                except Exception:
                    pass
                _autotrade_guardian_touch(0)
                return

        repaired = list(repaired or [])
        _autotrade_guardian_touch(len(repaired))
        if repaired:
            _LAST_AUTOTRADE_DECISION[int(uid)] = {
                'status': 'MANAGED',
                'when': datetime.now(timezone.utc).isoformat(timespec='seconds'),
                'reason': f"managed_live_exits ({len(repaired)})",
                'session': current_session_utc(datetime.now(timezone.utc)),
                'mode': AUTOTRADE_MODE,
            }
        _hb_touch('autotrade_guardian', ok=True, details=f'repairs={len(repaired)}')
    except Exception as e:
        _hb_touch('autotrade_guardian', ok=False, error=f"{type(e).__name__}: {e}", details='guardian_error')
        logger.exception('autotrade_exit_guardian_job crashed: %s', e)




async def autotrade_fix_exits_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Force-clean AutoTrade exits: native Full TP/SL only, no legacy Conditional orders."""
    try:
        uid = int(update.effective_user.id)
        if not is_admin_user(uid):
            await update.message.reply_text("⛔ Admin only.")
            return
        owner = int(AUTOTRADE_OWNER_UID or uid or 0)
        if owner <= 0:
            await update.message.reply_text("❌ AUTOTRADE_OWNER_UID is not configured.")
            return
        if str(_autotrade_runtime_mode()).lower() != 'live':
            await update.message.reply_text("ℹ️ AutoTrade is not in live mode; no Bybit exit cleanup required.")
            return
        await update.message.reply_text("🔧 Fixing live exits now: Full TP/SL only, cancelling legacy Conditional and old Partial TP/SL exit orders...")
        try:
            repaired = await to_thread_autotrade(_autotrade_monitor_live_exit_protection, owner, timeout=max(20, int(AUTOTRADE_GUARDIAN_TIMEOUT_SEC or 15) + 10))
        except asyncio.TimeoutError:
            await update.message.reply_text("⚠️ Exit cleanup timed out. The guardian will continue cleaning on the next cycle.")
            return
        repaired = list(repaired or [])
        cancelled = sum(int((r or {}).get('legacy_conditional_cancelled') or 0) for r in repaired if isinstance(r, dict))
        partial_cancelled = sum(int((r or {}).get('partial_tpsl_cancelled') or int(((r or {}).get('attach_res') or {}).get('partial_tpsl_cancelled') or 0)) for r in repaired if isinstance(r, dict))
        fixed = sum(1 for r in repaired if isinstance(r, dict) and (bool(r.get('sl_fixed')) or bool(r.get('tp_fixed')) or bool(r.get('ok'))))
        lines = [
            "✅ AutoTrade exit cleanup finished",
            "━━━━━━━━━━━━━━━━━━━━",
            f"Positions checked/fixed: {fixed}",
            f"Legacy Conditional orders cancelled: {cancelled}",
            f"Old Partial TP/SL children cancelled: {partial_cancelled}",
            "Policy: native position-level Full TP/SL only",
            "Expected Bybit view: TP/SL rows, not Conditional rows.",
        ]
        await update.message.reply_text("\n".join(lines))
    except Exception as e:
        try:
            await update.message.reply_text(f"❌ /autotrade_fix_exits failed: {type(e).__name__}: {e}")
        except Exception:
            pass



async def screen_cache_warmup_job(context: ContextTypes.DEFAULT_TYPE):
    """Periodic global /screen cache warmer.

    Throttled by design: a full executable scan is expensive and can starve Telegram
    polling on small Render instances. This job only queues a refresh when the existing
    global cache is old/missing and the runtime is quiet. User /screen still replies
    instantly from stale cache or quick ticker context.
    """
    try:
        if _ohlcv_boot_grace_active():
            return
        if _recent_user_activity(20):
            return
        if _SCREEN_REFRESH_TASK is not None and not _SCREEN_REFRESH_TASK.done():
            return
        if _interactive_runtime_busy(30):
            return
        sess = str(scan_session_name_utc(datetime.now(timezone.utc)) or '').upper()
        cache_key = f"global::{sess}"
        ce = _SCREEN_CACHE.get(cache_key) or {}
        age = time.time() - float(ce.get('ts', 0.0) or 0.0) if ce.get('body') else 1e9
        if age < float(SCREEN_CACHE_WARMUP_MIN_AGE_SEC):
            return
        if _ohlcv_timeframe_cooling('15m', '1h', '4h'):
            return
        _schedule_screen_cache_refresh(0, sess)
    except Exception:
        return

async def autotrade_job(context: ContextTypes.DEFAULT_TYPE):
    """Background AutoTrade loop.

    Important runtime rule:
    - entry execution must stay lean and bounded
    - live SL/TP repair belongs to the dedicated guardian job, not inline here
    This prevents lock contention and long-running autotrade ticks that cause missed scheduler runs.
    """
    try:
        _hb_touch('autotrade', ok=True, details='job_tick')
        if _live_trade_runtime_busy():
            _hb_touch('autotrade', ok=True, details='live_trade_runtime_busy')
            return
        if not _autotrade_ready():
            return
        if not _autotrade_entry_enabled():
            try:
                uid0 = int(AUTOTRADE_OWNER_UID or 0)
                if uid0:
                    _LAST_AUTOTRADE_DECISION[uid0] = {
                        "status": "SKIP",
                        "when": datetime.now(timezone.utc).isoformat(timespec="seconds"),
                        "reason": "autotrade_entries_off",
                        "session": str(scan_session_name_utc(datetime.now(timezone.utc)) or "NONE"),
                        "mode": str(_autotrade_runtime_mode()).lower(),
                    }
            except Exception:
                pass
            _hb_touch('autotrade', ok=True, details='entries_off')
            return

        uid = int(AUTOTRADE_OWNER_UID)
        try:
            user = await to_thread_fast(get_user, uid, timeout=2)
        except Exception:
            user = get_user(uid) or {}
        if not user:
            return

        now_utc = datetime.now(timezone.utc)
        job_started_ts = time.time()

        def _job_budget_exhausted() -> bool:
            try:
                return (time.time() - job_started_ts) >= float(AUTOTRADE_JOB_MAX_RUNTIME_SEC or 40)
            except Exception:
                return False

        owner_unlimited = int(user.get("sessions_unlimited", 0) or 0) == 1
        autotrade_allowed_sessions = [str(s).upper().strip() for s in (_autotrade_get_sessions() or []) if str(s).strip()]
        live_sess = _current_session_for_allowed(now_utc, autotrade_allowed_sessions)
        sess = _current_session_for_allowed(now_utc, autotrade_allowed_sessions)
        if owner_unlimited and sess == "NONE":
            sess = scan_session_name_utc(now_utc)

        if AUTOTRADE_EXEC_LOCK.locked():
            _LAST_AUTOTRADE_DECISION[uid] = {
                "status": "SKIP",
                "when": now_utc.isoformat(timespec="seconds"),
                "reason": "autotrade_exec_lock_busy",
                "session": str(sess or "NONE"),
                "mode": AUTOTRADE_MODE,
            }
            _hb_touch('autotrade', ok=True, details='busy_skip')
            return

        async with AUTOTRADE_EXEC_LOCK:
            if not owner_unlimited and not live_sess:
                _LAST_AUTOTRADE_DECISION[uid] = {
                    "status": "SKIP",
                    "when": now_utc.isoformat(timespec="seconds"),
                    "reason": "outside_live_session_window",
                    "session": "NONE",
                    "mode": AUTOTRADE_MODE,
                }
                return
            if sess not in {"ASIA", "LON", "NY"}:
                _LAST_AUTOTRADE_DECISION[uid] = {
                    "status": "SKIP",
                    "when": now_utc.isoformat(timespec="seconds"),
                    "reason": f"invalid_target_session ({sess or 'NONE'})",
                    "session": str(sess or "NONE"),
                    "mode": AUTOTRADE_MODE,
                }
                return
            if not _autotrade_allowed_session(sess):
                _LAST_AUTOTRADE_DECISION[uid] = {
                    "status": "SKIP",
                    "when": now_utc.isoformat(timespec="seconds"),
                    "reason": f"session_not_allowed ({sess})",
                }
                return

            try:
                if not trade_window_allows_now(user):
                    _LAST_AUTOTRADE_DECISION[uid] = {
                        "status": "SKIP",
                        "when": now_utc.isoformat(timespec="seconds"),
                        "reason": "trade_window_block",
                    }
                    return
            except Exception:
                pass


            try:
                db_setups = await to_thread_autotrade(_autotrade_select_db_setups_cached, uid, sess, lookback_hours=24, limit=30, timeout=8)
            except asyncio.TimeoutError:
                db_setups = []
                try:
                    db_log_setup_pipeline_event(uid, stage='autotrade_exec_select', status='timeout', session=str(sess or ''), mode='autotrade', details={'timeout_sec': 8})
                except Exception:
                    pass
            except Exception as e:
                db_setups = []
                try:
                    db_log_setup_pipeline_event(uid, stage='autotrade_exec_select', status='error', session=str(sess or ''), mode='autotrade', details={'error': f'{type(e).__name__}: {e}'})
                except Exception:
                    pass
            # yver120: put fresh current-session executable rows ahead of the broad 24h queue.
            # This is what makes AutoTrade coverage match /setup_audit for the current session.
            try:
                fresh_db_setups = await to_thread_autotrade(
                    _autotrade_select_fresh_session_executable_setups,
                    uid,
                    sess,
                    int(globals().get('AUTOTRADE_FRESH_SESSION_QUEUE_WINDOW_MIN', 150) or 150),
                    int(globals().get('AUTOTRADE_FRESH_SESSION_QUEUE_LIMIT', 60) or 60),
                    timeout=8,
                )
            except Exception:
                fresh_db_setups = []
            if fresh_db_setups:
                db_setups = _autotrade_merge_candidate_lists_fresh_first(fresh_db_setups, db_setups, limit=60)

            tf_cooling = _ohlcv_timeframe_cooling('15m', '1h', '4h')
            if not db_setups and tf_cooling:
                reason = 'autotrade_refresh_deferred_rate_limit_cooldown'
            if (
                not db_setups
                and not tf_cooling
                and not _job_budget_exhausted()
                and bool(AUTOTRADE_REFRESH_EXECUTABLE_WHEN_EMPTY)
                and not _live_trade_runtime_busy(240)
                and _heavy_background_window_ok()
            ):
                remaining_budget = max(4.0, float(AUTOTRADE_JOB_MAX_RUNTIME_SEC or 22) - (time.time() - job_started_ts))
                refresh_timeout = min(8.0, remaining_budget)
                try:
                    refreshed = await to_thread_bg(_autotrade_refresh_owner_executable_pool, uid, sess, 12, timeout=refresh_timeout)
                except asyncio.TimeoutError:
                    refreshed = []
                    try:
                        db_log_setup_pipeline_event(uid, stage='autotrade_exec_refresh', status='timeout', session=str(sess or ''), mode='autotrade', details={'timeout_sec': float(refresh_timeout)})
                    except Exception:
                        pass
                except Exception as e:
                    refreshed = []
                    try:
                        db_log_setup_pipeline_event(uid, stage='autotrade_exec_refresh', status='error', session=str(sess or ''), mode='autotrade', details={'error': f'{type(e).__name__}: {e}'})
                    except Exception:
                        pass
                if refreshed:
                    db_setups = list(refreshed or [])

            attempt_summaries = [{
                'setup_id': str(getattr(x, 'setup_id', '') or getattr(x, 'id', '') or ''),
                'symbol': str(getattr(x, 'symbol', '') or ''),
                'side': str(getattr(x, 'side', '') or ''),
                'created_ts': float(getattr(x, 'created_ts', 0.0) or 0.0),
                'executable_ts': float(getattr(x, 'executable_ts', 0.0) or 0.0),
                'source_kind': str(getattr(x, 'source_kind', '') or ''),
                'source_session': str(getattr(x, 'source_session', '') or ''),
            } for x in (db_setups or [])]
            if not db_setups:
                selector_diag = dict(_LAST_AUTOTRADE_SELECTOR_REJECTS.get(uid) or {})
                selector_reasons = dict(selector_diag.get('top_reasons') or {})
                selector_samples = list(selector_diag.get('samples') or [])
                if tf_cooling:
                    skip_reason = 'autotrade_refresh_deferred_rate_limit_cooldown'
                elif selector_reasons:
                    if any(str(k).startswith(('autotrade_policy_not_keep', 'autotrade_policy_not_allowed')) for k in selector_reasons):
                        skip_reason = 'no_keep_or_watch_executable_setup'
                    else:
                        skip_reason = 'no_tradable_setup_after_selector_filters'
                else:
                    skip_reason = 'no_setups'
                _LAST_AUTOTRADE_DECISION[uid] = {
                    "status": "SKIP",
                    "when": now_utc.isoformat(timespec="seconds"),
                    "reason": skip_reason,
                    "session": sess,
                    "mode": AUTOTRADE_MODE,
                    "attempted_candidates": selector_samples or attempt_summaries,
                    "selector_top_reasons": selector_reasons,
                    "selector_scanned": selector_diag.get('scanned'),
                    "selector_selected": selector_diag.get('selected'),
                }
                _hb_touch('autotrade', ok=True, details=f'{skip_reason} sess={sess}')
                return

            ok = False
            reason = 'no_tradable_setup'
            attempted = 0
            placed_count = 0
            max_tick_places = max(0, int(globals().get('AUTOTRADE_JOB_MAX_PLACEMENTS_PER_TICK', 0) or 0))  # 0 = unlimited/all eligible
            for cand in db_setups:
                if _job_budget_exhausted():
                    reason = f'autotrade_job_budget_exhausted>{int(AUTOTRADE_JOB_MAX_RUNTIME_SEC or 40)}s'
                    break
                attempted += 1
                remaining_budget = max(3.0, float(AUTOTRADE_JOB_MAX_RUNTIME_SEC or 40) - (time.time() - job_started_ts))
                per_candidate_timeout = min(float(AUTOTRADE_JOB_TIMEOUT_SEC or 25), remaining_budget)
                try:
                    ok, reason = await to_thread_autotrade(
                        _autotrade_place_trade,
                        uid,
                        sess,
                        [cand],
                        timeout=per_candidate_timeout,
                    )
                except asyncio.TimeoutError:
                    _timeout_reason = f'autotrade_place_trade_timeout>{int(per_candidate_timeout)}s'
                    try:
                        ok, reason = await to_thread_autotrade(_autotrade_timeout_reconcile, uid, sess, cand, _timeout_reason, timeout=8)
                    except Exception:
                        ok, reason = False, _timeout_reason
                try:
                    detail_snapshot = dict(_LAST_AUTOTRADE_DETAIL.get(uid) or {})
                    if 0 <= attempted - 1 < len(attempt_summaries):
                        attempt_summaries[attempted - 1].update({
                            'status': 'PLACED' if ok else 'SKIP',
                            'reason': '' if ok else str(reason or ''),
                            'entry': detail_snapshot.get('entry') or getattr(cand, 'entry', ''),
                            'sl': detail_snapshot.get('sl') or getattr(cand, 'sl', ''),
                            'entry_drift_pct': detail_snapshot.get('entry_drift_pct', ''),
                            'entry_drift_direction': detail_snapshot.get('entry_drift_direction', ''),
                            'entry_drift_adverse_pct': detail_snapshot.get('entry_drift_adverse_pct', ''),
                        })
                        _autotrade_record_attempt(uid, attempt_summaries[attempted - 1], detail_snapshot, 'PLACED' if ok else 'SKIP', '' if ok else str(reason or ''))
                except Exception:
                    pass
                if ok:
                    placed_count += 1
                    if max_tick_places > 0 and placed_count >= max_tick_places:
                        break
                    # Ver54: keep opening eligible queued setups in this tick so the
                    # NORMAL/REVERSE forward test can observe all positions until TP/SL.
                    continue
                if not _autotrade_should_try_next_after_skip(reason):
                    break

            final_ok = placed_count > 0
            final_reason = (f'placed_{placed_count}_from_queue' if final_ok else reason)
            _LAST_AUTOTRADE_DECISION[uid] = {
                "status": "PLACED" if final_ok else "SKIP",
                "when": now_utc.isoformat(timespec="seconds"),
                "reason": final_reason,
                "attempted": attempted,
                "placed": placed_count,
                "session": sess,
                "mode": AUTOTRADE_MODE,
                "attempted_candidates": attempt_summaries,
                "latest_candidate": attempt_summaries[0] if attempt_summaries else {},
            }
            _hb_touch('autotrade', ok=True, details=f"status={'PLACED' if final_ok else 'SKIP'} reason={final_reason} placed={placed_count}")

    except Exception as e:
        try:
            uid = int(AUTOTRADE_OWNER_UID or 0)
        except Exception:
            uid = 0
        if uid:
            _LAST_AUTOTRADE_DECISION[uid] = {
                "status": "ERROR",
                "when": datetime.now(timezone.utc).isoformat(timespec="seconds"),
                "reason": f"{type(e).__name__}: {e}",
            }
        _hb_touch('autotrade', ok=False, error=f"{type(e).__name__}: {e}", details='job_error')
        logger.exception("autotrade_job crashed: %s", e)


async def _trigger_autotrade_after_email_async(uid: int, session_name: str, chosen_list: list):
    """Run one immediate autotrade attempt after a setup email is sent.

    The previous build waited only for the scheduled autotrade_job (default 5 min),
    so /autotrade_last could show "No attempts recorded yet" right after an email.
    This helper uses the same AUTOTRADE_EXEC_LOCK and _autotrade_place_trade path, so
    it does not create a second execution engine or bypass risk controls.
    """
    try:
        owner_uid = int(AUTOTRADE_OWNER_UID or 0)
        caller_uid = int(uid or 0)
        sess = str(session_name or '').upper().strip()
        now_utc = datetime.now(timezone.utc)
        if owner_uid <= 0 or sess not in {'ASIA', 'LON', 'NY'}:
            return
        if not _autotrade_ready():
            _LAST_AUTOTRADE_DECISION[owner_uid] = {
                'status': 'SKIP',
                'when': now_utc.isoformat(timespec='seconds'),
                'reason': 'autotrade_not_ready_or_disabled',
                'session': sess,
                'mode': str(_autotrade_runtime_mode()).lower(),
            }
            return
        if not _autotrade_entry_enabled():
            _LAST_AUTOTRADE_DECISION[owner_uid] = {
                'status': 'SKIP',
                'when': now_utc.isoformat(timespec='seconds'),
                'reason': 'autotrade_entries_off',
                'session': sess,
                'mode': str(_autotrade_runtime_mode()).lower(),
                'trigger': 'email_sent_immediate',
            }
            return
        # The email itself is already an authorized bot action.  Always route the
        # exact emailed setup batch into AUTOTRADE_OWNER_UID so email, /screen and
        # AutoTrade cannot diverge when the recipient uid differs from the owner uid.
        if not _autotrade_allowed_session(sess):
            _LAST_AUTOTRADE_DECISION[owner_uid] = {
                'status': 'SKIP', 'when': now_utc.isoformat(timespec='seconds'),
                'reason': f'session_not_allowed ({sess})', 'session': sess,
                'mode': str(_autotrade_runtime_mode()).lower(),
            }
            return
        try:
            user_owner = get_user(owner_uid) or {}
            if not trade_window_allows_now(user_owner):
                _LAST_AUTOTRADE_DECISION[owner_uid] = {
                    'status': 'SKIP', 'when': now_utc.isoformat(timespec='seconds'),
                    'reason': 'trade_window_block', 'session': sess,
                    'mode': str(_autotrade_runtime_mode()).lower(),
                }
                return
        except Exception:
            pass
        # Do not silently skip a just-emailed setup because the scheduled
        # AutoTrade job is briefly running. Queue by waiting for the shared lock.
        async with AUTOTRADE_EXEC_LOCK:
            # Force selected emailed setups into the owner's executable lane and clear stale empty cache.
            try:
                if chosen_list:
                    for _s in list(chosen_list or []):
                        try:
                            setattr(_s, 'source_kind', 'emailed_setups')
                            setattr(_s, 'source_session', sess)
                            setattr(_s, 'delivery_lane_locked', True)
                            if not float(getattr(_s, 'created_ts', 0.0) or 0.0):
                                setattr(_s, 'created_ts', time.time())
                        except Exception:
                            pass
                    try:
                        _valid_for_at, _at_gate_reasons = _setup_email_presend_executable_filter(owner_uid, sess, list(chosen_list or []), lane='autotrade_after_email')
                    except Exception:
                        _valid_for_at, _at_gate_reasons = [], Counter({'autotrade_after_email_presend_exception': 1})
                    if not _valid_for_at:
                        try:
                            _LAST_AUTOTRADE_DECISION[owner_uid] = {
                                'status': 'SKIP',
                                'when': datetime.now(timezone.utc).isoformat(timespec='seconds'),
                                'reason': 'emailed_setups_failed_final_gate_before_autotrade_trying_keep_queue',
                                'session': sess,
                                'mode': str(_autotrade_runtime_mode()).lower(),
                                'top_reasons': dict((_at_gate_reasons or Counter()).most_common(5)),
                                'trigger': 'email_sent_immediate',
                            }
                        except Exception:
                            pass
                        try:
                            db_log_setup_pipeline_event(owner_uid, stage='autotrade_after_email_presend_gate', status='empty', session=sess, mode='autotrade', details={'top_reasons': _pipeline_top_reasons(_at_gate_reasons, 8), 'input': len(list(chosen_list or []))})
                        except Exception:
                            pass
                        chosen_list = []
                    else:
                        chosen_list = list(_valid_for_at or [])
                    await to_thread_autotrade(_persist_executable_candidates, owner_uid, sess, list(chosen_list or []), 'emailed_setups', 'email_autotrade_immediate', timeout=5)
                    try:
                        cache_delete(f"autotrade_db_setups_v129:{owner_uid}:{sess}:24:30")
                    except Exception:
                        pass
            except Exception as e:
                try:
                    db_log_setup_pipeline_event(owner_uid, stage='autotrade_after_email_persist', status='error', session=sess, mode='autotrade', details={'error': f'{type(e).__name__}: {e}'})
                except Exception:
                    pass
            # Ver57: email_sent_immediate must execute only the exact just-emailed batch.
            # Do not pull the latest generic executable queue here; otherwise AutoTrade can
            # open rows that were not in the email, then the emailed rows show as duplicates.
            db_setups = []
            for _s in list(chosen_list or []):
                try:
                    _s_eff = _setup_route_unless_delivery_locked(_s, sess, owner_uid, source_kind=str(getattr(_s, 'source_kind', '') or 'emailed_setups'))
                    ok_s, _why_s = is_executable_setup_eligible(_s_eff, session_name=sess)
                    if ok_s:
                        db_setups.append(_s_eff)
                except Exception:
                    continue
            attempted = 0
            placed_count = 0
            attempts_meta = []
            ok = False
            reason = 'no_setups_after_email'
            max_batch_places = max(0, int(globals().get('AUTOTRADE_AFTER_EMAIL_MAX_PLACEMENTS_PER_BATCH', 0) or 0))  # 0 = unlimited/all eligible
            _email_batch_candidates = list(db_setups or [])
            # yver129: do NOT append generic fresh-session or fallback executable
            # queues here. Immediate AutoTrade after email must attempt only the
            # exact just-emailed batch, otherwise AutoTrade can open PLAYSOUT/TAO/NEAR
            # style rows that were never emailed to the subscriber/admin.
            if max_batch_places > 0:
                _email_batch_candidates = _email_batch_candidates[:max_batch_places]
            for cand in _email_batch_candidates:
                attempted += 1
                try:
                    attempts_meta.append({
                        'setup_id': str(getattr(cand, 'setup_id', '') or getattr(cand, 'id', '') or ''),
                        'symbol': str(getattr(cand, 'symbol', '') or ''),
                        'side': str(getattr(cand, 'side', '') or ''),
                        'source_kind': str(getattr(cand, 'source_kind', '') or ''),
                    })
                except Exception:
                    pass
                try:
                    ok, reason = await to_thread_autotrade(_autotrade_place_trade, owner_uid, sess, [cand], timeout=min(int(AUTOTRADE_JOB_TIMEOUT_SEC or 55), max(10, int(AUTOTRADE_JOB_TIMEOUT_SEC or 55))))
                except asyncio.TimeoutError:
                    _timeout_reason = 'autotrade_place_trade_timeout_after_email'
                    try:
                        ok, reason = await to_thread_autotrade(_autotrade_timeout_reconcile, owner_uid, sess, cand, _timeout_reason, timeout=8)
                    except Exception:
                        ok, reason = False, _timeout_reason
                except Exception as e:
                    ok, reason = False, f'{type(e).__name__}: {e}'
                try:
                    detail_snapshot = dict(_LAST_AUTOTRADE_DETAIL.get(owner_uid) or {})
                    attempts_meta[-1].update({
                        'status': 'PLACED' if ok else 'SKIP',
                        'reason': '' if ok else str(reason or ''),
                        'entry': detail_snapshot.get('entry') or getattr(cand, 'entry', ''),
                        'sl': detail_snapshot.get('sl') or getattr(cand, 'sl', ''),
                        'entry_drift_pct': detail_snapshot.get('entry_drift_pct', ''),
                            'entry_drift_direction': detail_snapshot.get('entry_drift_direction', ''),
                            'entry_drift_adverse_pct': detail_snapshot.get('entry_drift_adverse_pct', ''),
                    })
                    _autotrade_record_attempt(owner_uid, attempts_meta[-1], detail_snapshot, 'PLACED' if ok else 'SKIP', '' if ok else str(reason or ''))
                except Exception:
                    pass
                if ok:
                    placed_count += 1
                    if max_batch_places > 0 and placed_count >= max_batch_places:
                        break
                    # Continue through the just-emailed batch while normal risk/open-trade
                    # caps still allow it, so AutoTrade does not fall behind emails.
                    continue
                if not _autotrade_should_try_next_after_skip(reason):
                    break
            _LAST_AUTOTRADE_DECISION[owner_uid] = {
                'status': 'PLACED' if placed_count > 0 else 'SKIP',
                'when': datetime.now(timezone.utc).isoformat(timespec='seconds'),
                'reason': (f'placed_{placed_count}_from_email_batch' if placed_count > 0 else str(reason or 'no_tradable_setup')),
                'attempted': int(attempted),
                'session': sess,
                'mode': str(_autotrade_runtime_mode()).lower(),
                'attempted_candidates': attempts_meta,
                'latest_candidate': attempts_meta[0] if attempts_meta else {},
                'trigger': 'email_sent_immediate',
            }
            try:
                db_log_setup_pipeline_event(owner_uid, stage='autotrade_after_email', status='placed' if placed_count > 0 else 'skip', session=sess, mode='autotrade', details={'reason': reason, 'attempted': attempted, 'placed': int(placed_count), 'candidates': attempts_meta[:5]})
            except Exception:
                pass
    except Exception as e:
        try:
            owner_uid = int(AUTOTRADE_OWNER_UID or 0)
            if owner_uid:
                _LAST_AUTOTRADE_DECISION[owner_uid] = {
                    'status': 'ERROR', 'when': datetime.now(timezone.utc).isoformat(timespec='seconds'),
                    'reason': f'{type(e).__name__}: {e}', 'trigger': 'email_sent_immediate',
                }
        except Exception:
            pass



async def autonomous_screen_sync_job(context: ContextTypes.DEFAULT_TYPE):
    """Autonomous /screen-equivalent setup/email/autotrade lane (Ver22).

    This job intentionally uses the dedicated screen executor and the exact same
    _build_screen_body_and_kb + _screen_sync_pipeline_async path that manual /screen
    uses. Therefore setup generation, setup emails, /screen cache, and autotrade are
    produced without waiting for the admin/user to press /screen.
    """
    job_started_ts = float(time.time())

    def _budget_left() -> float:
        try:
            return float(AUTONOMOUS_SCREEN_SYNC_MAX_RUNTIME_SEC or 120) - (float(time.time()) - job_started_ts)
        except Exception:
            return 0.0

    try:
        _hb_touch('email', ok=True, details='autonomous_screen_sync_tick')
        try:
            db_log_setup_pipeline_event(0, stage='autonomous_screen_sync_tick', status='start', session=str(scan_session_name_utc(datetime.now(timezone.utc)) or ''), mode='screen_email', details={'screen_required': False, 'source': 'job_queue_ver23'})
        except Exception:
            pass
        if _AUTONOMOUS_SCREEN_SYNC_LOCK.locked():
            try:
                db_log_setup_pipeline_event(0, stage='autonomous_screen_sync_tick', status='skip_locked', session=str(scan_session_name_utc(datetime.now(timezone.utc)) or ''), mode='screen_email', details={'screen_required': False})
            except Exception:
                pass
            return
        async with _AUTONOMOUS_SCREEN_SYNC_LOCK:
            if not EMAIL_ENABLED or not email_config_ok():
                return
            try:
                users = await to_thread_fast(list_users_notify_on, timeout=10)
            except Exception:
                users = []
            users = list(users or [])

            # yver141: keep the AutoTrade owner/admin pinned first in the autonomous
            # /screen-sync email queue as well. ver140 fixed alert_job, but this
            # separate autonomous path could still append the owner at the end and then
            # cut it off with AUTONOMOUS_SCREEN_SYNC_MAX_USERS slicing.
            try:
                owner_uid = int(AUTOTRADE_OWNER_UID or 0)
            except Exception:
                owner_uid = 0
            try:
                if owner_uid > 0:
                    owner_user = None
                    rest_users = []
                    for _u in list(users or []):
                        try:
                            if int((_u or {}).get('user_id') or (_u or {}).get('id') or 0) == int(owner_uid):
                                owner_user = _u
                            else:
                                rest_users.append(_u)
                        except Exception:
                            rest_users.append(_u)
                    if owner_user is None:
                        ou = get_user(owner_uid) or {}
                        if ou and str(ou.get('email_to') or ou.get('email') or '').strip():
                            owner_user = ou
                    users = ([owner_user] if owner_user is not None else []) + rest_users
            except Exception:
                pass
            if not users:
                return

            try:
                best_fut = await to_thread_screen(_screen_best_fut_fast, timeout=12)
            except Exception:
                best_fut = {}
            if not best_fut:
                try:
                    best_fut = await to_thread_screen(fetch_futures_tickers, timeout=18)
                except Exception:
                    best_fut = {}
            if not best_fut:
                return

            processed = 0
            sent_count = 0
            skipped = []
            for u in users[:max(1, int(AUTONOMOUS_SCREEN_SYNC_MAX_USERS or 1))]:
                if _budget_left() < 20:
                    skipped.append('budget_exhausted')
                    break
                try:
                    uid = int((u or {}).get('user_id') or (u or {}).get('id') or 0)
                except Exception:
                    uid = 0
                if uid <= 0:
                    continue
                try:
                    if not (is_admin_user(uid) or user_has_pro(uid, u)):
                        continue
                except Exception:
                    continue
                try:
                    sess = in_session_now(u or {})
                except Exception:
                    sess = None
                if not sess:
                    skipped.append(f'{uid}:no_live_session')
                    continue
                sess_name = str((sess or {}).get('name') or scan_session_name_utc(datetime.now(timezone.utc)) or '').upper().strip()
                if sess_name not in {'ASIA', 'LON', 'NY'}:
                    skipped.append(f'{uid}:invalid_session:{sess_name}')
                    continue
                processed += 1
                try:
                    screen_timeout = max(20, min(55, int(_budget_left() - 10)))
                    body, kb, setups = await to_thread_screen(_build_screen_body_and_kb, best_fut, sess_name, uid, timeout=screen_timeout)
                except asyncio.TimeoutError:
                    skipped.append(f'{uid}:screen_build_timeout')
                    continue
                except Exception as e:
                    skipped.append(f'{uid}:screen_build_{type(e).__name__}')
                    continue
                try:
                    _screen_cache_put(f"uid:{uid}::{sess_name}", body, list(kb or []), ts=time.time(), allow_empty_overwrite=True)
                    _screen_cache_put(f"global::{sess_name}", body, list(kb or []), ts=time.time(), allow_empty_overwrite=True)
                except Exception:
                    pass
                if not setups:
                    skipped.append(f'{uid}:no_screen_setups')
                    continue
                try:
                    res = await _screen_sync_pipeline_async(uid, dict(u or {}), sess_name, sess_name, best_fut or {}, list(setups or []))
                    if str((res or {}).get('status') or '').lower() == 'sent':
                        sent_count += 1
                    else:
                        skipped.append(f"{uid}:{str((res or {}).get('reason') or 'not_sent')[:80]}")
                except Exception as e:
                    skipped.append(f'{uid}:sync_{type(e).__name__}')
            try:
                db_log_setup_pipeline_event(0, stage='autonomous_screen_sync_tick', status='ok', session=str(scan_session_name_utc(datetime.now(timezone.utc)) or ''), mode='screen_email', details={'processed': processed, 'sent_batches': sent_count, 'skipped': skipped[:8], 'screen_required': False})
            except Exception:
                pass
    except Exception as e:
        try:
            db_log_setup_pipeline_event(0, stage='autonomous_screen_sync_tick', status='error', session=str(scan_session_name_utc(datetime.now(timezone.utc)) or ''), mode='screen_email', details={'error': f'{type(e).__name__}: {e}', 'screen_required': False})
        except Exception:
            pass
        try:
            logger.exception('autonomous_screen_sync_job failed: %s', e)
        except Exception:
            pass

async def alert_job(context: ContextTypes.DEFAULT_TYPE):
    """Background email engine (trade setups + big-move alerts).

    IMPORTANT:
    - Do NOT take ALERT_LOCK here.
    - _alert_job_async_internal() already owns ALERT_LOCK to prevent overlap.

    The previous version double-locked (wrapper + internal), which caused the
    internal job to exit immediately every time, so no emails were ever sent
    (while /email_test still worked).
    """

    # Heartbeat (so /email_decision can prove the loop is alive)
    try:
        _EMAIL_LOOP_HEARTBEAT["alive"] = True
        now_ts = time.time()
        _EMAIL_LOOP_HEARTBEAT["last_tick_ts"] = now_ts
        job = getattr(context, "job", None)
        interval = float(getattr(job, "interval", 0) or 0)
        if interval > 0:
            _EMAIL_LOOP_HEARTBEAT["next_tick_ts"] = now_ts + interval
    except Exception:
        pass

    try:
        await _alert_job_async_internal(context)
        _hb_touch('email', ok=True, details='alert_job_ok')
        try:
            _EMAIL_LOOP_HEARTBEAT["last_error"] = ""
        except Exception:
            pass
    except Exception as e:
        try:
            _EMAIL_LOOP_HEARTBEAT["last_error"] = f"{type(e).__name__}: {e}"
        except Exception:
            pass
        _hb_touch('email', ok=False, error=f"{type(e).__name__}: {e}", details='alert_job_error')
        logger.exception("Alert job failure: %s", e)



async def autotrade_sessions_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if not _is_admin(update):
        await update.message.reply_text("❌ Admin only.")
        return

    if not context.args:
        current = ",".join(_autotrade_get_sessions())
        await update.message.reply_text(f"🤖 Current AutoTrade Sessions: {current}")
        return

    raw = context.args[0].upper()
    parts = [p.strip() for p in raw.split(",") if p.strip()]

    valid = {"NY", "LON", "ASIA"}
    if any(p not in valid for p in parts):
        await update.message.reply_text("❌ Invalid session. Use NY,LON,ASIA")
        return

    _autotrade_set_sessions(",".join(parts))
    await update.message.reply_text(f"✅ AutoTrade sessions updated: {','.join(parts)}")


def main():
    # Render note: if deployed as a Web Service, bind to $PORT so Render keeps the service alive.
    if os.environ.get("RENDER_SERVICE_TYPE") == "web":
        start_keepalive_http_server()
        logger.warning("Running in Render Web Service mode: keepalive HTTP server enabled; polling will still run.")

    # Single instance guard (Render overlap protection)
    render_primary_only()

    if not TOKEN:
        raise RuntimeError("TELEGRAM_TOKEN missing")

    db_init()
    ensure_email_column()
    _evolution_migrate_tables()
    try:
        _research_seed_family_registry()
        _research_activate_all_families_runtime()
        _ver14_all_family_profile_bootstrap()
    except Exception:
        pass
    try:
        _setup_combo_seed_interim_disable_policy()
    except Exception:
        pass
    
    builder = (
        Application.builder()
        .token(TOKEN)
        .post_init(_post_init)
        .concurrent_updates(int(os.getenv('TELEGRAM_CONCURRENT_UPDATES', '64') or 64))
        .connection_pool_size(int(os.getenv('TELEGRAM_CONNECTION_POOL_SIZE', '256') or 256))
        .pool_timeout(float(os.getenv('TELEGRAM_POOL_TIMEOUT_SEC', '1.0') or 1.0))
        .connect_timeout(float(os.getenv('TELEGRAM_CONNECT_TIMEOUT_SEC', '3.0') or 3.0))
        .read_timeout(float(os.getenv('TELEGRAM_READ_TIMEOUT_SEC', '30.0') or 30.0))
        .write_timeout(float(os.getenv('TELEGRAM_WRITE_TIMEOUT_SEC', '10.0') or 10.0))
    )
    # PTB >=20.6 deprecates passing getUpdates timeouts to run_polling().
    # Configure them on ApplicationBuilder to remove the warning and keep polling stable.
    for _method, _value in (
        ('get_updates_connect_timeout', float(os.getenv('TELEGRAM_POLL_CONNECT_TIMEOUT_SEC', '10') or 10)),
        ('get_updates_read_timeout', float(os.getenv('TELEGRAM_POLL_READ_TIMEOUT_SEC', '35') or 35)),
        ('get_updates_write_timeout', float(os.getenv('TELEGRAM_POLL_WRITE_TIMEOUT_SEC', '20') or 20)),
        ('get_updates_pool_timeout', float(os.getenv('TELEGRAM_POOL_TIMEOUT_SEC', '1.0') or 1.0)),
    ):
        try:
            builder = getattr(builder, _method)(_value)
        except Exception:
            pass
    app = builder.build()

    # Fast-lane for ultra-light commands that must feel instant (/help, /size, etc.)
