def _yver101_screen_plain_text(text: str) -> str:
    """Convert Telegram HTML/markdown screen text to parser-friendly plain text."""
    try:
        import html as _html
        t = str(text or '')
        t = re.sub(r'(?i)<br\s*/?>', '\n', t)
        t = re.sub(r'(?i)</p\s*>', '\n', t)
        t = re.sub(r'(?i)</div\s*>', '\n', t)
        t = re.sub(r'<[^>]+>', '', t)
        t = _html.unescape(t)
        t = t.replace('\r', '\n')
        t = t.replace('`', '')
        # Keep bold markers harmless for the existing parser.
        t = re.sub(r'[ \t]+', ' ', t)
        return t
    except Exception:
        return str(text or '')


def _yver101_setup_is_f9(s) -> bool:
    try:
        sid = str(getattr(s, 'setup_id', '') or getattr(s, 'id', '') or '').upper().strip()
        fam = str(getattr(s, 'family_id', '') or getattr(s, 'engine', '') or '').upper().strip()
        if sid.startswith('F9-') or fam == 'F9' or 'F9' in fam:
            return True
        return _setup_audit_family_code(fam) == 'F9'
    except Exception:
        return False


def _yver101_visible_f9_setups(uid: int, session: str, best_fut: dict | None = None, body: str = '', shown_setups: list | None = None) -> list:
    """Return F9 setup objects from visible /screen objects and/or visible text."""
    out = []
    seen = set()
    sess = str(session or '').upper().strip()
    try:
        for s in list(shown_setups or []):
            try:
                if not _yver101_setup_is_f9(s):
                    continue
                sid = str(getattr(s, 'setup_id', '') or getattr(s, 'id', '') or '').strip()
                if not sid:
                    continue
                try:
                    setattr(s, 'source_session', sess or str(getattr(s, 'source_session', '') or getattr(s, 'session', '') or '').upper().strip())
                    setattr(s, 'session', str(getattr(s, 'source_session', '') or sess or '').upper().strip() or sess or 'ASIA')
                    setattr(s, 'source_kind', str(getattr(s, 'source_kind', '') or 'yver101_screen_f9_visible'))
                    setattr(s, 'delivery_lane_locked', True)
                    setattr(s, 'yver101_screen_f9_visible', True)
                except Exception:
                    pass
                if sid not in seen:
                    seen.add(sid)
                    out.append(s)
            except Exception:
                continue
    except Exception:
        pass
    try:
        txt = _yver101_screen_plain_text(body)
        if 'F9-' in txt:
            parsed = _yver100_f9_screen_parse_cards(txt, best_fut=best_fut or {}, default_session=sess or '')
            for s in list(parsed or []):
                try:
                    sid = str(getattr(s, 'setup_id', '') or getattr(s, 'id', '') or '').strip()
                    if not sid or sid in seen:
                        continue
                    try:
                        setattr(s, 'source_session', sess or str(getattr(s, 'source_session', '') or getattr(s, 'session', '') or '').upper().strip())
                        setattr(s, 'session', str(getattr(s, 'source_session', '') or sess or '').upper().strip() or sess or 'ASIA')
                        setattr(s, 'source_kind', 'yver101_screen_text_f9_visible')
                        setattr(s, 'delivery_lane_locked', True)
                        setattr(s, 'yver101_screen_f9_visible', True)
                    except Exception:
                        pass
                    seen.add(sid)
                    out.append(s)
                except Exception:
                    continue
    except Exception:
        pass
    return list(out or [])


def _yver101_policy_keep_f9(s, uid: int, session: str) -> tuple[bool, str, dict]:
    try:
        sess = str(session or getattr(s, 'source_session', '') or getattr(s, 'session', '') or '').upper().strip()
        if sess not in {'ASIA', 'LON', 'NY'}:
            sess = str(scan_session_name_utc() or 'ASIA').upper().strip()
        pol = _setup_combo_policy_lookup_for_setup(s, session_name=sess, user_id=int(uid or 0)) or {}
        st = str(pol.get('status') or '').upper().strip()
        en = int(pol.get('enabled') if pol.get('enabled') is not None else 1)
        if st == 'KEEP' and en == 1:
            return True, 'KEEP', dict(pol or {})
        return False, st or 'NOT_KEEP', dict(pol or {})
    except Exception as exc:
        return False, f'policy_exception:{type(exc).__name__}', {}


def _yver101_is_fresh_unresolved_setup(s, uid: int = 0) -> tuple[bool, str]:
    try:
        sid = str(getattr(s, 'setup_id', '') or getattr(s, 'id', '') or '').strip()
        side = str(getattr(s, 'side', '') or '').upper().strip()
        entry = float(getattr(s, 'entry', 0.0) or 0.0)
        sl = float(getattr(s, 'sl', 0.0) or 0.0)
        tp = float(_setup_target_tp(s, 0.0) or getattr(s, 'tp', 0.0) or 0.0)
        if not sid:
            return False, 'missing_setup_id'
        if side == 'BUY' and not (sl < entry < tp):
            return False, 'bad_price_order'
        if side == 'SELL' and not (tp < entry < sl):
            return False, 'bad_price_order'
        if entry <= 0 or sl <= 0 or tp <= 0:
            return False, 'missing_prices'
        created = float(getattr(s, 'created_ts', 0.0) or 0.0)
        if created <= 0:
            m = re.match(r'F9-(\d{9,12})-', sid)
            if m:
                created = float(int(m.group(1)))
        if created > 0:
            max_age = max(5, int(_autotrade_entry_window_min() or 60)) * 60 + 90
            if time.time() - created > max_age:
                return False, 'ENTRY_OLD'
        try:
            out = db_get_outcome(sid) or {}
            oc = str(out.get('outcome') or '').upper().strip()
            hl = str(out.get('hit_level') or '').upper().strip()
            if oc in {'TP', 'SL'} or hl in {'TP', 'SL'}:
                return False, f'{hl or oc}_ALREADY_HIT'
        except Exception:
            pass
        return True, 'fresh_open'
    except Exception as exc:
        return False, f'fresh_check_exception:{type(exc).__name__}'


def _yver101_persist_visible_f9(uid: int, session: str, setups: list) -> int:
    n = 0
    try:
        uid_i = int(uid or 0)
        sess = str(session or '').upper().strip() or str(scan_session_name_utc() or 'ASIA').upper().strip()
        for s in list(setups or []):
            try:
                if not _yver101_setup_is_f9(s):
                    continue
                sid = str(getattr(s, 'setup_id', '') or getattr(s, 'id', '') or '').strip()
                if not sid:
                    continue
                try:
                    setattr(s, 'source_session', sess)
                    setattr(s, 'session', sess)
                    setattr(s, 'delivery_lane_locked', True)
                except Exception:
                    pass
                if not _yver97_setup_db_exists(uid_i, sid):
                    db_log_generated_setup(uid_i, 'yver101_visible_f9', sess, s)
                    n += 1
                try:
                    db_insert_signal(s, user_id=uid_i)
                except Exception:
                    pass
                try:
                    db_log_setup_pipeline_event(uid_i, stage='yver101_f9_visible_persist', status='ok', session=sess, mode='engine_f9', setup_id=sid, symbol=str(getattr(s, 'symbol', '') or ''), side=str(getattr(s, 'side', '') or ''), details={'source_kind': str(getattr(s, 'source_kind', '') or '')})
                except Exception:
                    pass
            except Exception:
                continue
    except Exception:
        pass
    return int(n or 0)


async def _yver101_force_email_autotrade_visible_f9(uid: int, session: str = '', best_fut: dict | None = None, body: str = '', shown_setups: list | None = None, source: str = 'screen') -> dict:
    """Hard bridge: visible fresh F9 KEEP rows -> setup email -> AutoTrade."""
    try:
        uid_i = int(uid or 0)
    except Exception:
        uid_i = 0
    if uid_i <= 0:
        try:
            uid_i = int(globals().get('AUTOTRADE_OWNER_UID', 0) or 0)
        except Exception:
            uid_i = 0
    if uid_i <= 0:
        return {'status': 'skip', 'reason': 'bad_uid'}
    try:
        user = dict(get_user(uid_i) or {})
    except Exception:
        user = {'user_id': uid_i}
    if not user.get('user_id'):
        user['user_id'] = uid_i
    sess = str(session or '').upper().strip()
    if sess not in {'ASIA', 'LON', 'NY'}:
        try:
            sess = str(scan_session_name_utc() or 'ASIA').upper().strip()
        except Exception:
            sess = 'ASIA'
    try:
        best_fut = best_fut or get_cached_futures_tickers() or {}
    except Exception:
        best_fut = best_fut or {}
    setups = _yver101_visible_f9_setups(uid_i, sess, best_fut=best_fut or {}, body=body or '', shown_setups=shown_setups or [])
    _yver101_persist_visible_f9(uid_i, sess, setups)
    if not setups:
        return {'status': 'skip', 'reason': 'no_visible_f9'}

    actionable = []
    skipped = Counter()
    seen = set()
    for s in list(setups or []):
        try:
            sid = str(getattr(s, 'setup_id', '') or getattr(s, 'id', '') or '').strip()
            if not sid or sid in seen:
                continue
            seen.add(sid)
            ok_fresh, why_fresh = _yver101_is_fresh_unresolved_setup(s, uid_i)
            if not ok_fresh:
                skipped[str(why_fresh or 'not_fresh')] += 1
                continue
            keep, why_keep, pol = _yver101_policy_keep_f9(s, uid_i, sess)
            if not keep:
                skipped[f'policy_{why_keep}'] += 1
                continue
            try:
                db_mark_executable_setup(uid_i, sid, sess, time.time(), s=s, source_kind='yver101_visible_f9_keep', state='executable_pending')
            except Exception:
                pass
            if db_has_emailed_setup(uid_i, sid, lookback_hours=12):
                skipped['already_emailed'] += 1
                continue
            if _email_setup_identity_recently_sent(uid_i, s):
                skipped['duplicate_identity'] += 1
                continue
            actionable.append(s)
        except Exception as exc:
            skipped[f'candidate_exception:{type(exc).__name__}'] += 1
    if not actionable:
        try:
            db_log_setup_pipeline_event(uid_i, stage='yver101_f9_visible_email_autotrade', status='skip', session=sess, mode='engine_f9', details={'reason': 'no_actionable', 'skipped': dict(skipped)})
        except Exception:
            pass
        return {'status': 'skip', 'reason': 'no_actionable', 'skipped': dict(skipped)}

    # Do not arbitrarily drop screen-visible KEEP F9 rows.  Keep a sane upper bound.
    actionable = list(actionable[:8])
    kept = list(actionable)
    skipped_locks = []
    try:
        kept, skipped_locks = _yver92_acquire_setup_email_item_locks(uid_i, sess, kept)
    except Exception:
        skipped_locks = []
    if not kept:
        return {'status': 'skip', 'reason': 'duplicate_lock', 'skipped': skipped_locks[:5]}

    sent = False
    try:
        tz, user_tz = _zoneinfo_or_default((user or {}).get('tz') or (user or {}).get('timezone'))
        now_local = datetime.now(tz)
        first = kept[0]
        subject = f"PulseFutures • {sess} • {str(getattr(first, 'side', '') or '').upper()} {str(getattr(first, 'symbol', '') or '').upper()}"
        if len(kept) > 1:
            subject += f" (+{len(kept)-1} more)"
        body_txt = _email_body_pretty(session_name=sess, now_local=now_local, user_tz=user_tz, setups=list(kept), best_fut=best_fut or {})
        body_html = _email_body_pretty_html(session_name=sess, now_local=now_local, user_tz=user_tz, setups=list(kept), best_fut=best_fut or {})
        try:
            sent = bool(send_email(subject, body_txt, user_id_for_debug=uid_i, body_html=body_html))
        except Exception as smtp_exc:
            sent = False
            try:
                _LAST_SMTP_ERROR[uid_i] = f'{type(smtp_exc).__name__}: {smtp_exc}'
            except Exception:
                pass
        if (not sent) and _email_assume_sent_on_soft_smtp() and _smtp_error_probably_delivered(str(_LAST_SMTP_ERROR.get(uid_i, '') or '')):
            sent = True
        if sent:
            try:
                _record_setup_email_delivery_side_effects(uid_i, sess, list(kept), best_fut or {}, status='yver101_f9_visible_direct_sent')
            except Exception:
                pass
            try:
                st = email_state_get(uid_i)
                email_state_set(uid_i, last_email_ts=time.time(), sent_count=int(st.get('sent_count', 0) or 0) + 1)
            except Exception:
                pass
            try:
                _email_daily_inc(uid_i, local_trading_day_str())
            except Exception:
                pass
            try:
                for s in kept:
                    mark_symbol_emailed(uid_i, str(getattr(s, 'symbol', '') or ''), str(getattr(s, 'side', '') or ''), sess)
            except Exception:
                pass
            try:
                if _autotrade_ready() and (uid_i == int(AUTOTRADE_OWNER_UID or 0) or is_admin_user(uid_i)):
                    _safe_create_task(_trigger_autotrade_after_email_async(uid_i, sess, list(kept)), 'yver101_f9_visible_autotrade_after_direct_email')
            except Exception:
                pass
            try:
                _LAST_EMAIL_DECISION[uid_i] = {'status': 'SENT', 'picked': ','.join([str(getattr(x, 'symbol', '') or '') for x in kept[:5]]), 'when': datetime.now(tz).isoformat(timespec='seconds'), 'reasons': [f'yver101_f9_visible_direct_email source={source}', f'setups={len(kept)}']}
            except Exception:
                pass
            try:
                db_log_setup_pipeline_event(uid_i, stage='yver101_f9_visible_email_autotrade', status='sent', session=sess, mode='engine_f9', details={'source': source, 'sent': len(kept), 'setup_ids': [str(getattr(x, 'setup_id', '') or '') for x in kept], 'skipped': dict(skipped)})
            except Exception:
                pass
            return {'status': 'sent', 'reason': f'yver101_f9_visible_sent_{len(kept)}', 'setup_ids': [str(getattr(x, 'setup_id', '') or '') for x in kept]}
        else:
            try:
                _LAST_EMAIL_DECISION[uid_i] = {'status': 'ERROR', 'picked': '-', 'when': datetime.now(tz).isoformat(timespec='seconds'), 'reasons': ['yver101_direct_f9_email_failed', str(_LAST_SMTP_ERROR.get(uid_i, 'smtp_send_failed') or 'smtp_send_failed')]}
            except Exception:
                pass
            try:
                db_log_setup_pipeline_event(uid_i, stage='yver101_f9_visible_email_autotrade', status='email_failed', session=sess, mode='engine_f9', details={'source': source, 'actionable': len(kept), 'smtp_error': str(_LAST_SMTP_ERROR.get(uid_i, '') or '')})
            except Exception:
                pass
            return {'status': 'error', 'reason': 'email_failed'}
    finally:
        try:
            _yver92_release_setup_email_item_locks(uid_i, sess, kept, bool(sent))
        except Exception:
            pass


async def _screen_sync_pipeline_async(uid: int, user: dict, live_session: str, scan_session: str, best_fut: dict, shown_setups: list["Setup"]):
    # Run the existing sync first, then hard-bridge any visible F9 KEEP rows if the
    # normal path skipped them.
    res = None
    if callable(_YVER101_ORIG_SCREEN_SYNC_PIPELINE_ASYNC):
        try:
            res = await _YVER101_ORIG_SCREEN_SYNC_PIPELINE_ASYNC(uid, user, live_session, scan_session, best_fut, shown_setups)
        except Exception as exc:
            res = {'status': 'error', 'reason': f'orig_screen_sync_exception:{type(exc).__name__}: {exc}'}
    try:
        f9s = _yver101_visible_f9_setups(int(uid or 0), str(scan_session or live_session or ''), best_fut=best_fut or {}, shown_setups=shown_setups or [])
        if f9s:
            hard = await _yver101_force_email_autotrade_visible_f9(int(uid or 0), str(scan_session or live_session or ''), best_fut=best_fut or {}, shown_setups=f9s, source='screen_sync_pipeline')
            try:
                if isinstance(res, dict):
                    res['yver101_f9_hard_bridge'] = hard
            except Exception:
                pass
            if (not isinstance(res, dict)) or str((res or {}).get('status') or '').lower() in {'skip', 'error', ''}:
                return hard
    except Exception:
        pass
    return res or {'status': 'skip', 'reason': 'screen_sync_unavailable'}


