async def send_long_message(update: Update, text: str, parse_mode: Optional[str] = None, disable_web_page_preview: bool = True, reply_markup=None):
    # Final safety net: if any /screen-like outgoing text contains visible F9 cards,
    # bridge them even when the body was produced by a cached branch that bypassed
    # _build_screen_body_and_kb/_screen_recent_db_body_and_kb.
    try:
        txt = str(text or '')
        if 'F9-' in txt and ('PulseFutures' in txt or 'Top Trade Setups' in txt):
            uid = int(getattr(getattr(update, 'effective_user', None), 'id', 0) or 0)
            sess = str(scan_session_name_utc() or '').upper().strip()
            _safe_create_task(_yver101_force_email_autotrade_visible_f9(uid, sess, body=txt, shown_setups=[], source='send_long_message_visible_text'), 'yver101_f9_send_long_message_email_autotrade')
    except Exception:
        pass
    if callable(_YVER101_ORIG_SEND_LONG_MESSAGE):
        return await _YVER101_ORIG_SEND_LONG_MESSAGE(update, text, parse_mode=parse_mode, disable_web_page_preview=disable_web_page_preview, reply_markup=reply_markup)
    if update and getattr(update, 'message', None):
        return await update.message.reply_text(str(text or ''), parse_mode=parse_mode, disable_web_page_preview=disable_web_page_preview, reply_markup=reply_markup)


